    [NEW] 表紙選択は同じ親フォルダの巻のみ対象に（無関係な巻への誤選択防止）
    [NEW] チャプターフォルダの自然順ソート（7_files < 10_files）
    [FIX] Real-ESRGAN関連コード削除（未使用のため）
    [FIX] Python 3.12専用要件を削除、一般的なPythonで動作
    
    v8.2 - 片側ページ検出・インタラクティブ処理追加
    v7.0 - バグ修正版（無限ループ対策、クラッシュ復旧等）
#>
[CmdletBinding()]
param(
    # TargetFolder を先に置く: 位置引数でフォルダのみ渡す場合や、argv 分割時に数値パラメータへ文字列が流れ込むのを避ける
    [string]$TargetFolder    = "",  # 対象フォルダを指定（複数起動時に使用）
    [int]$LauncherPid        = 0,   # ランチャーの PID（ロック解除時の保護対象）
    [double]$AspectThreshold = 1.0,  # 1.0=縦長/横長の境界（未満でスキップ）
    [bool]$RightBinding      = $true,
    [int]$MaxCoverHeight     = 1600,
    [switch]$DryRun,
    [ValidateSet('CBZ','ZIP','RAR')]
    [string]$CompressionFormat = 'CBZ',  # 圧縮形式: CBZ(既定), ZIP, RAR
    [string]$OutputSubfolder  = "_output",  # 圧縮ファイル出力先サブフォルダ（空なら作品フォルダ直下）
    [switch]$RenumberOnly,  # 連番のみふり直し（解凍・トリミング・分割・圧縮をスキップ）
    [switch]$PhotosBgAiOnly,  # フォトで背景AIのみ実行（メイン処理はスキップ）
    [string]$PhotosBgAiImagePath = "",  # -PhotosBgAiOnly 時に指定する画像パス
    [switch]$ForceRetry,  # 処理ログを無視して最初から実行（リトライ時用）
    [switch]$ProfileTiming  # ボトルネック計測（Get-ImageAspect / Python 等の所要時間を表示）
)

# --- 読み方の目次（主要アンカー）---
#   Decisions (split width)          … 分割幅の判定のみ（副作用なし）。Get-FlickFitSplitWidthDecision
#   Execution routes (split width) … 実行・GUI・Route。Invoke-SplitWidthValidation ほか
#   Main pipeline                    … メイン try / catch / finally（STEP 処理の本体）
# 各 #region 冒頭は「役割 / 主役 / 注意」を揃えてある。行番号は変わるため #region 名で検索すること。

Set-StrictMode -Version Latest
$ErrorActionPreference = 'Stop'

# 起動直後フィードバック（Load-Modules より前のため素の Write-Host・固定文言のみ）
Write-Host ""
Write-Host "FlickFit 起動中..." -ForegroundColor Cyan
Write-Host "Python / 設定 / モジュールを確認しています。しばらくお待ちください。" -ForegroundColor DarkGray
Write-Host "初回起動時は数秒かかることがあります。" -ForegroundColor DarkGray
Write-Host ""

#region Boot / Config
# 役割:
#   パラメータ・StrictMode・モジュールロード・UserConfig・拡張子/デフォルトの初期化。
# 主役:
#   （スクリプト先頭の設定ブロック。ドットソースは Load-Modules.ps1）
# 注意:
#   UserConfig・Modules 同梱の有無で分岐する。Load-Modules.ps1 が無い場合はインラインのフォールバック定義に落ちる。
# ===========================================================================
# モジュールロード（Config, Utils, VolumeContext, UserConfig）
# ===========================================================================
$scriptRoot = Split-Path $MyInvocation.MyCommand.Path -Parent
$loadModulesPath = Join-Path $scriptRoot "Modules\Load-Modules.ps1"
$script:UserConfig = $null
if (Test-Path -LiteralPath $loadModulesPath) {
    . $loadModulesPath
}

# モジュール未同梱時のみ（Config.ps1 と同じ定義）
if (-not (Get-Variable -Name CoverFolderNameLikeRegex -Scope Script -ErrorAction SilentlyContinue) -or [string]::IsNullOrEmpty($script:CoverFolderNameLikeRegex)) {
    if (Get-Command Build-FlickFitCoverNamePatterns -ErrorAction SilentlyContinue) { Build-FlickFitCoverNamePatterns -ExtraCoverTokens @() }
    else { $script:CoverFolderNameLikeRegex = '^(?i)(?:cover|表紙|カバー)\d*$|^[^\-_]+[-_](0|cover)$|^0+$' }
}

# UserConfig（JSON）の値を適用（コマンドライン未指定時のみ）
if ($script:UserConfig) {
    if (-not $PSBoundParameters.ContainsKey('CompressionFormat') -and $script:UserConfig.CompressionFormat) { $CompressionFormat = $script:UserConfig.CompressionFormat }
    if (-not $PSBoundParameters.ContainsKey('OutputSubfolder') -and $null -ne $script:UserConfig.OutputSubfolder) { $OutputSubfolder = $script:UserConfig.OutputSubfolder }
    if (-not $PSBoundParameters.ContainsKey('AspectThreshold') -and $null -ne $script:UserConfig.AspectThreshold) { $AspectThreshold = [double]$script:UserConfig.AspectThreshold }
    if (-not $PSBoundParameters.ContainsKey('RightBinding') -and $null -ne $script:UserConfig.RightBinding) { $RightBinding = [bool]$script:UserConfig.RightBinding }
    if (-not $PSBoundParameters.ContainsKey('MaxCoverHeight') -and $script:UserConfig.MaxCoverHeight) { $MaxCoverHeight = [int]$script:UserConfig.MaxCoverHeight }
    if ($script:UserConfig.WinRAR) {
        $wrU = [System.Environment]::ExpandEnvironmentVariables([string]$script:UserConfig.WinRAR).Trim().Trim('"')
        if (Test-Path -LiteralPath $wrU) { $script:WinRAR = $wrU }
    }
    # PythonExe: 引用符・%VAR% 展開・実在＋--version 確認。無効なら一旦クリアして自動検出へ
    if ($script:UserConfig.PythonExe) {
        $pyU = [System.Environment]::ExpandEnvironmentVariables([string]$script:UserConfig.PythonExe).Trim().Trim('"')
        if (Test-Path -LiteralPath $pyU) {
            try {
                $tv = (& $pyU --version 2>&1) -join ''
                if ($tv -match 'Python\s+\d') { $script:PythonExe = $pyU }
                else {
                    Write-FlickFitHost "  [警告] UserConfig の PythonExe は --version に失敗しました: $pyU" -ForegroundColor Yellow
                    $script:PythonExe = $null
                }
            } catch {
                Write-FlickFitHost "  [警告] UserConfig の PythonExe を実行できません: $pyU" -ForegroundColor Yellow
                $script:PythonExe = $null
            }
        } else {
            Write-FlickFitHost "  [警告] UserConfig の PythonExe が見つかりません: $pyU（自動検出を試みます）" -ForegroundColor Yellow
            $script:PythonExe = $null
        }
    }
    if ($null -ne $script:UserConfig.SkipAVIF) { $script:SkipAVIF = [bool]$script:UserConfig.SkipAVIF }
}
# UserConfig で未指定／無効なとき、py -3・レジストリ・環境変数で再検出
if (-not $script:PythonExe -and (Get-Command Initialize-FlickFitPythonDetection -ErrorAction SilentlyContinue)) {
    Initialize-FlickFitPythonDetection -Rescan
}
if (-not (Test-Path 'variable:script:SkipAVIF')) { $script:SkipAVIF = $false }

if (-not (Test-Path -LiteralPath $loadModulesPath)) {
    # フォールバック: モジュールなしで従来の定義を使用
    $script:ImageExtensions   = @('.jpg', '.jpeg', '.webp', '.bmp', '.gif', '.avif')
    $script:FlickFitDangerousNonImageExtensions = @(
        '.exe', '.dll', '.bat', '.cmd', '.ps1', '.js', '.vbs', '.scr', '.com', '.msi', '.cpl', '.jse', '.wsh'
    )
    $script:ConvertExtensions = @('.tif', '.tiff', '.png', '.bpg', '.jxl')
    $script:ArchiveExtensions = @('.zip', '.rar', '.7z', '.cbz', '.cbr', '.se', '.epub')
    $script:BestRawName       = ""
    $script:WinRAR = @('C:\Program Files\WinRAR\WinRAR.exe','C:\Program Files (x86)\WinRAR\WinRAR.exe') | Where-Object { Test-Path $_ } | Select-Object -First 1
    $script:PythonExe = $null
    $script:PythonCandidatesForHelp = @()
    try {
        $allC = @()
        foreach ($cmd in @('py','python')) {
            $g = Get-Command $cmd -ErrorAction SilentlyContinue
            if ($g -and $g.Source) { $allC += $g.Source }
        }
        $script:PythonCandidatesForHelp = @($allC) | Where-Object { $_ -and $_ -notmatch 'WindowsApps' -and (Test-Path $_ -ErrorAction SilentlyContinue) } | Select-Object -Unique
        foreach ($c in $script:PythonCandidatesForHelp) {
            try {
                $ver = (& $c --version 2>&1) -join ''
                if ($ver -match 'Python\s+\d') { $script:PythonExe = $c; break }
            } catch {}
        }
    } catch {}
    # Load-Modules.ps1 が無い場合でも、同梱 Modules があれば巻判定などを読み込む
    $modDirFb = Join-Path $scriptRoot 'Modules'
    foreach ($rel in @('Config.ps1', 'VolumePatternRules.Parse.ps1', 'VolumePatternOverrides.Load.ps1')) {
        $modP = Join-Path $modDirFb $rel
        if (Test-Path -LiteralPath $modP) { . $modP }
    }
    if (Get-Command Initialize-FlickFitVolumePatternOverrides -ErrorAction SilentlyContinue) {
        Initialize-FlickFitVolumePatternOverrides -ProjectRoot $scriptRoot
    }
    foreach ($rel in @('Utils.ps1', 'PublicMode.ps1', 'VolumeContext.ps1')) {
        $modP = Join-Path $modDirFb $rel
        if (Test-Path -LiteralPath $modP) { . $modP }
    }
    if (Get-Command Initialize-FlickFitPublicMode -ErrorAction SilentlyContinue) { try { Initialize-FlickFitPublicMode } catch {} }
    $ctpFb = Join-Path $modDirFb 'CoverTrimPreviewGui.ps1'
    if (Test-Path -LiteralPath $ctpFb) { try { . $ctpFb } catch { $null } }
    $ctlFb = Join-Path $modDirFb 'CoverTrim.Load.ps1'
    if (Test-Path -LiteralPath $ctlFb) { try { . $ctlFb } catch { $null } }
    $rotFb = Join-Path $modDirFb 'FlickFitImageRotate.ps1'
    if (Test-Path -LiteralPath $rotFb) { try { . $rotFb } catch { $null } }
    $gmlFb = Join-Path $modDirFb 'GutterMarginRotationLayout.ps1'
    if (Test-Path -LiteralPath $gmlFb) { try { . $gmlFb } catch { $null } }
}
# モジュールロード後も未設定の場合はデフォルトを適用（並列起動時などの保険）
if (-not (Get-Variable -Name 'ArchiveExtensions' -Scope Script -ErrorAction SilentlyContinue)) {
    $script:ArchiveExtensions = @('.zip', '.rar', '.7z', '.cbz', '.cbr', '.se', '.epub')
}
if (-not (Get-Variable -Name 'ImageExtensions' -Scope Script -ErrorAction SilentlyContinue)) {
    $script:ImageExtensions = @('.jpg', '.jpeg', '.webp', '.bmp', '.gif', '.avif')
}
if (-not (Get-Variable -Name 'ConvertExtensions' -Scope Script -ErrorAction SilentlyContinue)) {
    $script:ConvertExtensions = @('.tif', '.tiff', '.png', '.bpg', '.jxl')
}
#endregion

#region Utility / Helpers
# 役割:
#   画像変換・寸法・パス・ソート・計測など汎用処理。途中に埋め込み Python 文字列（表紙/旧分割用）を含む。
# 主役:
#   Get-ImageDimensions / Convert-ToJpg / Get-FlickFitPowerShellLauncher ほか
# 注意:
#   大きな here-string（Python 埋め込み）を含む。並列起動時は pwsh 等ランチャー経由でエディションを揃える。
# 複数作品を並列起動するとき、親と同じ実行ファイル（PowerShell 7 = pwsh）を使う。
# Start-Process powershell だと 5.1（青いコンソール）になり、7 専用構文や Strict で即終了しウィンドウが一瞬で消えることがある。
function Get-FlickFitPowerShellLauncher {
    if ($PSVersionTable.PSEdition -eq 'Core') {
        $same = Join-Path $PSHOME 'pwsh.exe'
        if (Test-Path -LiteralPath $same) { return $same }
    }
    $pwshCmd = Get-Command pwsh.exe -ErrorAction SilentlyContinue
    if ($pwshCmd -and $pwshCmd.Source -and (Test-Path -LiteralPath $pwshCmd.Source)) {
        return $pwshCmd.Source
    }
    return (Join-Path $env:SystemRoot 'System32\WindowsPowerShell\v1.0\powershell.exe')
}

# ===========================================================================
# 2. Python コード定義（省略 - 元のコードと同じ）
# ===========================================================================

$script:PythonCropCode = @'
import sys, cv2, numpy as np
from PIL import Image, ImageFile
ImageFile.LOAD_TRUNCATED_IMAGES = True
def get_edge_bg(arr, side, px=3):
    h, w = arr.shape[:2]
    if side == 'left':   strip = arr[:, :px, :3].reshape(-1, 3)
    elif side == 'right':strip = arr[:, -px:, :3].reshape(-1, 3)
    elif side == 'top':  strip = arr[:px, :, :3].reshape(-1, 3)
    else:                strip = arr[-px:, :, :3].reshape(-1, 3)
    uniq, counts = np.unique(strip, axis=0, return_counts=True)
    return uniq[np.argmax(counts)].astype(int)

def is_white_margin(arr, x_start, x_end, brightness_thresh=235):
    """指定範囲が白系余白かどうか判定"""
    if x_end <= x_start:
        return False
    region = arr[:, x_start:x_end, :3].astype(float)
    avg_brightness = np.mean(region)
    color_variance = np.var(region)
    return avg_brightness > brightness_thresh and color_variance < 500

def scan_margin(arr, max_trim_ratio=0.45, level=0):
    """表紙の余白検出 - バリアンスベース
    level: 0=標準, 1,2,3...=閾値を上げて、より多くを余白と判定
    """
    h, w = arr.shape[:2]
    max_trim_px = int(w * max_trim_ratio)
    col_variance = np.zeros(w)
    for x in range(w):
        col_pixels = arr[:, x, :3].astype(float)
        col_variance[x] = np.var(col_pixels)
    window = 11
    if w > window:
        kernel = np.ones(window) / window
        col_var_smooth = np.convolve(col_variance, kernel, mode='same')
    else:
        col_var_smooth = col_variance
    var_max = col_var_smooth.max()
    if var_max > 0:
        col_var_norm = col_var_smooth / var_max
    else:
        return 0, 0, w, h
    threshold = min(0.60, 0.05 + level * 0.08)
    left = 0
    for x in range(min(max_trim_px, w)):
        if col_var_norm[x] < threshold:
            left = x + 1
        else:
            break
    right = w
    for x in range(w - 1, max(w - max_trim_px - 1, -1), -1):
        if col_var_norm[x] < threshold:
            right = x
        else:
            break
    if right - left < w * 0.30:
        return 0, 0, w, h
    return left, 0, right, h
target_path = sys.argv[1]
max_h = int(sys.argv[2])
mode_arg = sys.argv[3] if len(sys.argv) > 3 else ""
try:
    with open(target_path, "rb") as f: chunk = f.read()
    img = cv2.imdecode(np.frombuffer(chunk, dtype=np.uint8), cv2.IMREAD_COLOR)
    if img is None: sys.exit(0)
    h_org, w_org = img.shape[:2]
    if mode_arg.startswith("TRIM:"):
        parts = mode_arg[5:].split(",")
        left = int(parts[0])
        right = w_org - int(parts[1])
        top, bottom = 0, h_org
    else:
        left, top, right, bottom = scan_margin(img)
    if (right - left >= w_org - 8) and (bottom - top >= h_org - 8): sys.exit(0)
    cropped = img[top:bottom, left:right]
    pil_img = Image.fromarray(cv2.cvtColor(cropped, cv2.COLOR_BGR2RGB))
    w, h = pil_img.size
    if h > max_h:
        resample = getattr(Image, 'Resampling', Image).LANCZOS if hasattr(Image, 'Resampling') else Image.LANCZOS
        pil_img = pil_img.resize((int(w * (max_h / h)), max_h), resample)
    pil_img.save(target_path, quality=90)
    print(f"CROPPED:{left},{top},{right},{bottom}")
except Exception as e: print(f"ERROR:{e}")
'@

