        Write-FlickFitHost "  [エラー] -PhotosBgAiOnly を使用する場合は -PhotosBgAiImagePath で画像パスを指定してください。" -ForegroundColor Red
        exit 1
    }
    Invoke-PhotosOpen -ImagePath $PhotosBgAiImagePath.Trim()
    exit 0
}

$script:PythonSplitCode = @'
import sys, os, cv2, numpy as np
from PIL import Image, ImageFile
ImageFile.LOAD_TRUNCATED_IMAGES = True

def get_edge_bg(arr, side, px=3):
    h, w = arr.shape[:2]
    if side == 'left':   strip = arr[:, :px, :3].reshape(-1, 3)
    elif side == 'right':strip = arr[:, -px:, :3].reshape(-1, 3)
    elif side == 'top':  strip = arr[:px, :, :3].reshape(-1, 3)
    else:                strip = arr[-px:, :, :3].reshape(-1, 3)
    uniq, counts = np.unique(strip, axis=0, return_counts=True)
    return uniq[np.argmax(counts)].astype(int)

def crop_margins(img):
    """余白トリミング - 無効化（過剰トリミング防止）"""
    # 見開き分割前のトリミングを無効化 - そのまま返す
    return img

def analyze_spread(img, aspect_threshold=1.4):
    """見開き判定（シンプル版）"""
    w, h = img.size
    if w / h < aspect_threshold:
        return 'SKIP'
    return 'SPLIT'

def trim_split_page(pil_img):
    """分割後の1ページの余白をトリミング（白・グレー対応版、上下左右）"""
    w, h = pil_img.size
    if w < 100 or h < 100:
        return pil_img
    
    # 片側最大12%まで
    max_trim_x = w // 8
    max_trim_y = h // 10
    
    def get_gray(p):
        if isinstance(p, tuple):
            return (p[0] + p[1] + p[2]) // 3
        return p
    
    # 明るい均一な色の余白を検出（白・グレー両対応）
    def is_margin_column(x):
        pixels = []
        for y in range(0, h, max(1, h // 30)):
            pixels.append(get_gray(pil_img.getpixel((x, y))))
        if len(pixels) < 2:
            return False
        avg = sum(pixels) / len(pixels)
        if avg < 180:
            return False
        variance = sum((p - avg) ** 2 for p in pixels) / len(pixels)
        return variance < 400
    
    def is_margin_row(y):
        pixels = []
        for x in range(0, w, max(1, w // 30)):
            pixels.append(get_gray(pil_img.getpixel((x, y))))
        if len(pixels) < 2:
            return False
        avg = sum(pixels) / len(pixels)
        if avg < 180:
            return False
        variance = sum((p - avg) ** 2 for p in pixels) / len(pixels)
        return variance < 400
    
    # 左端の余白を検出
    left = 0
    for x in range(min(max_trim_x, w // 4)):
        if is_margin_column(x):
            left = x + 1
        else:
            break
    
    # 右端の余白を検出
    right = w
    for x in range(w - 1, max(w - max_trim_x, 3 * w // 4), -1):
        if is_margin_column(x):
            right = x
        else:
            break
    
    # 上端の余白を検出
    top = 0
    for y in range(min(max_trim_y, h // 4)):
        if is_margin_row(y):
            top = y + 1
        else:
            break
    
    # 下端の余白を検出
    bottom = h
    for y in range(h - 1, max(h - max_trim_y, 3 * h // 4), -1):
        if is_margin_row(y):
            bottom = y
        else:
            break
    
    # 安全チェック: 最低80%のサイズを維持
    if (right - left) < w * 0.80 or (bottom - top) < h * 0.80:
        return pil_img
    
    if left == 0 and right == w and top == 0 and bottom == h:
        return pil_img
    
    return pil_img.crop((left, top, right, bottom))

def split_image(src_path, rb, dr):
    try:
        fname = os.path.basename(src_path)
        print(f"CHECK:{fname}", flush=True)
        img = Image.open(src_path)
        img = crop_margins(img)
        action = analyze_spread(img)
        print(f"ACTION:{action}", flush=True)
        if action == 'SKIP':
            return ('SKIP', [])
        w, h = img.size
        half = w // 2
        ext = os.path.splitext(src_path)[1].lower()
        save_kwargs = {'quality': 92} if ext in ('.jpg', '.jpeg') else {}
        parts = ([('1', img.crop((half, 0, w, h))), ('2', img.crop((0, 0, half, h)))] if rb else
                 [('1', img.crop((0, 0, half, h))), ('2', img.crop((half, 0, w, h)))])
        base, out_ext = os.path.splitext(src_path)
        out_paths = []
        for sfx, cropped in parts:
            # 分割後の各ページの余白もトリミング
            cropped = trim_split_page(cropped.convert('RGB'))
            p = f"{base}_{sfx}{out_ext}"
            if not dr:
                cropped.save(p, **save_kwargs)
            out_paths.append(p)
        if not dr:
            os.remove(src_path)
        return ('OK', out_paths)
    except Exception as e:
        return ('ERROR', [str(e)])

if __name__ == '__main__':
    rb    = sys.argv[2].lower() == 'true'
    dr    = sys.argv[3].lower() == 'true' if len(sys.argv) > 3 else False
    res, pths = split_image(sys.argv[1], rb, dr)
    print(f"{res}:{'|'.join(pths) if pths else ''}", flush=True)
'@

# ===========================================================================
# 3. 共通関数の正: Modules\Utils.ps1・VolumeContext.ps1（メインでは再定義しない）
#    表紙トリム確認: Modules\CoverTrim.Load.ps1（本体 + 失敗時 CoverTrim.Fallback.ps1）
# ===========================================================================
if (-not (Get-Command Write-Step -ErrorAction SilentlyContinue)) {
    $modEssential = Join-Path $scriptRoot 'Modules'
    foreach ($rel in @('Config.ps1', 'VolumePatternRules.Parse.ps1', 'VolumePatternOverrides.Load.ps1')) {
        $essPath = Join-Path $modEssential $rel
        if (Test-Path -LiteralPath $essPath) { . $essPath }
    }
    if (Get-Command Initialize-FlickFitVolumePatternOverrides -ErrorAction SilentlyContinue) {
        Initialize-FlickFitVolumePatternOverrides -ProjectRoot $scriptRoot
    }
    foreach ($rel in @('Utils.ps1', 'VolumeContext.ps1')) {
        $essPath = Join-Path $modEssential $rel
        if (Test-Path -LiteralPath $essPath) { . $essPath }
    }
    $ctpEss = Join-Path $modEssential 'CoverTrimPreviewGui.ps1'
    if (Test-Path -LiteralPath $ctpEss) { try { . $ctpEss } catch { $null } }
    $ctlEss = Join-Path $modEssential 'CoverTrim.Load.ps1'
    if (Test-Path -LiteralPath $ctlEss) { try { . $ctlEss } catch { $null } }
}
if (-not (Get-Command Write-Step -ErrorAction SilentlyContinue)) {
    throw '必須: Modules\Load-Modules.ps1 または Modules 内の Config.ps1 + Utils.ps1 を配置してください。'
}

# 表紙確認GUI（Load-Modules 未使用時でもフォールバック経路で利用）
$ctpPrevGui = Join-Path $scriptRoot "Modules\CoverTrimPreviewGui.ps1"
if (-not (Get-Command Show-CoverTrimPreviewGui -ErrorAction SilentlyContinue) -and (Test-Path -LiteralPath $ctpPrevGui)) {
    try { . $ctpPrevGui } catch { $null }
}

# CoverTrim 未ロード時のみ Modules\CoverTrim.Load.ps1 を再試行（Load-Modules と同一経路）
if (-not (Get-Command Invoke-CoverTrimConfirm -ErrorAction SilentlyContinue)) {
    $coverTrimLoadPath = Join-Path $scriptRoot "Modules\CoverTrim.Load.ps1"
    if (Test-Path -LiteralPath $coverTrimLoadPath) {
        try { . $coverTrimLoadPath } catch { $null }
    }
}

function Remove-NonImageFiles {
    param([string]$Path)
    $deleted = @(Get-ChildItem -LiteralPath $Path -File -ErrorAction SilentlyContinue | Where-Object { $script:ImageExtensions -notcontains $_.Extension.ToLower() -and $script:ConvertExtensions -notcontains $_.Extension.ToLower() } | ForEach-Object { Remove-Item -LiteralPath $_.FullName -Force; $_.Name })
    if ($deleted.Count -gt 0) { Write-FlickFitHost "    [削除]: 不要ファイル $($deleted.Count) 個" -ForegroundColor Yellow }
}

# BPGデコーダーの検出（Get-Command が複数返す場合は先頭のみ使用）
$script:BpgDec = @(
    'C:\Program Files\libbpg\bpgdec.exe',
    'C:\Program Files (x86)\libbpg\bpgdec.exe',
    (Join-Path $env:USERPROFILE 'bpgdec.exe'),
    (Join-Path (Split-Path $MyInvocation.MyCommand.Path -Parent) 'bpgdec.exe'),
    'bpgdec.exe'
) | Where-Object { 
    if ($_ -eq 'bpgdec.exe') { 
        $found = $null
        try {
            $c = Get-Command bpgdec.exe -ErrorAction SilentlyContinue | Select-Object -First 1
            if ($c -and $c.Source) { $found = $c.Source }
        } catch {}
        return $found -and (Test-Path -LiteralPath $found)
    }
    Test-Path -LiteralPath $_ 
} | Select-Object -First 1

# PNG/TIF 等→JPG 時、同一ベース名の .jpg が既にあると保存に失敗することがあるため先に削除を試みる
function Remove-ExistingJpgForOverwrite {
    param([string]$JpgPath)
    if (-not $JpgPath -or -not (Test-Path -LiteralPath $JpgPath)) { return $true }
    for ($r = 0; $r -lt 6; $r++) {
        try {
            [System.GC]::Collect()
            [System.GC]::WaitForPendingFinalizers()
            Start-Sleep -Milliseconds 40
            Remove-Item -LiteralPath $JpgPath -Force -ErrorAction Stop
            return $true
        } catch { Start-Sleep -Milliseconds 120 }
    }
    Write-FlickFitHost "      [警告]: 既存の同名JPGを削除できません（開きっぱなし等）: $([System.IO.Path]::GetFileName($JpgPath))" -ForegroundColor Yellow
    return $false
}

# 画像形式→JPG変換関数（TIF/TIFF/PNG/BPG対応）
function Convert-ToJpg {
    param([string]$Path)
    if (-not $script:PythonExe) { return }
    # 自然順ソートでファイルを取得（0, 1, 2, 10, 11の順になるように）
    $convertFiles = @(Get-ChildItem -LiteralPath $Path -File -ErrorAction SilentlyContinue | 
        Where-Object { $script:ConvertExtensions -contains $_.Extension.ToLower() } |
        Sort-Object { [regex]::Replace($_.Name, '\d+', { $args[0].Value.PadLeft(10,'0') }) })
    if ($convertFiles.Count -eq 0) { return }
    
    # BPGファイルと通常ファイルを分離（ソート順を維持）
    $bpgFiles = @($convertFiles | Where-Object { $_.Extension.ToLower() -eq '.bpg' })
    $otherFiles = @($convertFiles | Where-Object { $_.Extension.ToLower() -ne '.bpg' })
    
    $totalConverted = 0
    
    # BPGファイルの変換（bpgdec使用）
    if ($bpgFiles.Count -gt 0) {
        if (-not $script:BpgDec) {
            Write-FlickFitHost "    [BPG変換]: bpgdec.exeが見つかりません" -ForegroundColor Yellow
            Write-FlickFitHost "      → https://bellard.org/bpg/ からダウンロードしてください" -ForegroundColor DarkGray
            Write-FlickFitHost "      → bpgdec.exeをスクリプトと同じフォルダか、PATHの通った場所に配置" -ForegroundColor DarkGray
        } else {
            Write-FlickFitHost "    [BPG変換]: $($bpgFiles.Count) 個のBPGファイルをJPGに変換中..." -ForegroundColor Cyan
            $bpgIdx = 0
            foreach ($bpg in $bpgFiles) {
                $bpgIdx++
                Write-FlickFitHost "      エンコード中: $($bpg.Name)" -ForegroundColor DarkGray
                $tmpPng = Join-Path (Get-FlickFitScratchTempDir) ("bpg_tmp_" + [Guid]::NewGuid().ToString('N') + ".png")
                $dstJpg = [System.IO.Path]::ChangeExtension($bpg.FullName, '.jpg')
                $null = Remove-ExistingJpgForOverwrite -JpgPath $dstJpg
                try {
                    # bpgdecでPNGに変換（引数は配列で渡し、日本語パスでも壊れにくくする）
                    $decResult = & $script:BpgDec @('-o', $tmpPng, $bpg.FullName) 2>&1
                    if (-not (Test-Path -LiteralPath $tmpPng)) {
                        Write-FlickFitHost "      [警告]: $($bpg.Name) のデコードに失敗 (bpgdec exit=$LASTEXITCODE)" -ForegroundColor Yellow
                        $decStr = ($decResult | ForEach-Object { "$_" }) -join " "
                        if ($decStr) { Write-FlickFitHost "        -> $decStr" -ForegroundColor DarkYellow }
                        continue
                    }
                    # PNG→JPG（他形式と同様に一時 .py + UTF-8 でパスを安全に渡す）
                    $bpgJpgPy = @"
import sys
try:
    if sys.stdout and hasattr(sys.stdout, 'reconfigure'):
        sys.stdout.reconfigure(encoding='utf-8', errors='replace')
    if sys.stderr and hasattr(sys.stderr, 'reconfigure'):
        sys.stderr.reconfigure(encoding='utf-8', errors='replace')
except Exception:
    pass
from PIL import Image
src, dst = sys.argv[1], sys.argv[2]
img = Image.open(src)
if img.mode != 'RGB':
    img = img.convert('RGB')
img.save(dst, 'JPEG', quality=95)
print('OK')
"@
                    $tmpBpgPy = Join-Path (Get-FlickFitScratchTempDir) ("bpg_to_jpg_" + [Guid]::NewGuid().ToString('N') + ".py")
                    $utf8NoBom = New-Object System.Text.UTF8Encoding $false
                    [System.IO.File]::WriteAllText($tmpBpgPy, $bpgJpgPy, $utf8NoBom)
                    try {
                        $result = (& $script:PythonExe $tmpBpgPy $tmpPng $dstJpg 2>&1) -join ""
                        if ($result -match 'OK' -and (Test-Path -LiteralPath $dstJpg)) {
                            Remove-Item -LiteralPath $bpg.FullName -Force -ErrorAction SilentlyContinue
                            $totalConverted++
                        } else {
                            Write-FlickFitHost "      [警告]: $($bpg.Name) のJPG変換に失敗" -ForegroundColor Yellow
                            if ($result) { Write-FlickFitHost "        -> $result" -ForegroundColor DarkYellow }
                        }
                    } finally {
                        Remove-Item -LiteralPath $tmpBpgPy -Force -ErrorAction SilentlyContinue
                    }
                } finally {
                    Remove-Item -LiteralPath $tmpPng -Force -ErrorAction SilentlyContinue
                }
            }
        }
    }
    
    # その他のファイル（TIF/PNG等）の変換
    if ($otherFiles.Count -gt 0) {
        # 拡張子ごとにカウント
        $extCounts = @{}
        foreach ($f in $otherFiles) {
            $ext = $f.Extension.ToUpper()
            if (-not $extCounts.ContainsKey($ext)) { $extCounts[$ext] = 0 }
            $extCounts[$ext]++
        }
        $extSummary = ($extCounts.Keys | ForEach-Object { "$($extCounts[$_])個の$_" }) -join ", "
        Write-FlickFitHost "    [JPG変換]: $extSummary を変換中..." -ForegroundColor Cyan
        
        $convertPy = @"
import sys, os
# Windows: コンソールが cp932 のとき、print(CONVERTED+フルパス) が 丸数字 等で UnicodeEncodeError になる
try:
    if sys.stdout and hasattr(sys.stdout, 'reconfigure'):
        sys.stdout.reconfigure(encoding='utf-8', errors='replace')
    if sys.stderr and hasattr(sys.stderr, 'reconfigure'):
        sys.stderr.reconfigure(encoding='utf-8', errors='replace')
except Exception:
    pass
from PIL import Image
src = sys.argv[1]
try:
    img = Image.open(src)
    if img.mode in ('RGBA', 'LA'):
        background = Image.new('RGB', img.size, (255, 255, 255))
        if img.mode == 'LA':
            img = img.convert('RGBA')
        background.paste(img, mask=img.split()[-1])
        img = background
    elif img.mode == 'P':
        img = img.convert('RGBA')
        background = Image.new('RGB', img.size, (255, 255, 255))
        background.paste(img, mask=img.split()[-1] if len(img.split()) == 4 else None)
        img = background
    elif img.mode != 'RGB':
        img = img.convert('RGB')
    dst = os.path.splitext(src)[0] + '.jpg'
    if os.path.isfile(dst):
        try:
            os.remove(dst)
        except OSError:
            pass
    img.save(dst, 'JPEG', quality=95, optimize=False)
    print('CONVERTED:OK')
except Exception as e:
    try:
        print('ERROR:' + str(e))
    except Exception:
        print('ERROR:encode')
"@
        $tmpPy = Join-Path (Get-FlickFitScratchTempDir) ("img_convert_" + [Guid]::NewGuid().ToString('N') + ".py")
        try {
            $utf8NoBom = New-Object System.Text.UTF8Encoding $false
            [System.IO.File]::WriteAllText($tmpPy, $convertPy, $utf8NoBom)
            $fileCount = $otherFiles.Count
            $currentFile = 0
            $pyIoPrev = $env:PYTHONIOENCODING
            $env:PYTHONIOENCODING = 'utf-8'
            try {
            foreach ($file in $otherFiles) {
                $currentFile++
                Write-FlickFitHost "      エンコード中: $($file.Name) ..." -ForegroundColor DarkGray -NoNewline
                $dstJpgOther = [System.IO.Path]::ChangeExtension($file.FullName, '.jpg')
                $null = Remove-ExistingJpgForOverwrite -JpgPath $dstJpgOther
                $result = (& $script:PythonExe $tmpPy $file.FullName 2>&1) -join ""
                if ($result -match 'CONVERTED:OK') {
                    $totalConverted++
                    $deleted = $false
                    for ($retry = 0; $retry -lt 3; $retry++) {
                        try {
                            [System.GC]::Collect()
                            [System.GC]::WaitForPendingFinalizers()
                            Start-Sleep -Milliseconds 50
                            Remove-Item -LiteralPath $file.FullName -Force -ErrorAction Stop
                            $deleted = $true
                            break
                        } catch { Start-Sleep -Milliseconds 100 }
                    }
                    Write-FlickFitHost $(if ($deleted) { " OK" } else { " OK (元ファイル削除失敗)" })
                } else {
                    Write-FlickFitHost " 失敗"
                    if ($result) { Write-FlickFitHost "        -> $result" -ForegroundColor DarkYellow }
                }
            }
            } finally {
                if ($null -ne $pyIoPrev) { $env:PYTHONIOENCODING = $pyIoPrev }
                else { Remove-Item 'Env:PYTHONIOENCODING' -ErrorAction SilentlyContinue }
            }
        } finally {
            Remove-Item -LiteralPath $tmpPy -Force -ErrorAction SilentlyContinue
        }
    }
    
    if ($totalConverted -gt 0) {
        Write-FlickFitHost "      ✓ 合計 $totalConverted 個のファイルを変換しました" -ForegroundColor Green
    }
}

# 互換性のためのエイリアス
function Convert-TifToJpg { param([string]$Path); Convert-ToJpg -Path $Path }

function Get-ImageDimensions {
    [CmdletBinding()]
    param(
        [string]$Path,
        # Get-ImageAspect 等からフォールバック試行するとき、上位でまとめて警告するため観測ログを抑止
        [switch]$SuppressObsWarn
    )
    if (-not $Path -or -not (Test-Path -LiteralPath $Path)) { return @{ Width = 0; Height = 0 } }
    if ($script:PythonExe) {
        try {
            $safe = $Path.Replace("'", "''")
            $py = "from PIL import Image, ImageOps; img=Image.open(r'$safe'); img=ImageOps.exif_transpose(img); print(img.width, img.height)"
            $out = & $script:PythonExe -c $py 2>$null
            if ($out -match '(\d+)\s+(\d+)') { return @{ Width = [int]$Matches[1]; Height = [int]$Matches[2] } }
        } catch {}
    }
    if (-not $SuppressObsWarn) {
        Write-FlickFitObsImgDimWarn -Func 'Get-ImageDimensions' -Path $Path -W 0 -H 0 -Extra '(PIL/exif read failed or no match)'
    }
    return @{ Width = 0; Height = 0 }
}

# 幅・高さが必要で、かつ連続で複数枚触るとき用（Python 1回起動/枚は重い）。JPG/PNG 等は .NET、webp/avif のみ従来の Python
function Get-ImageDimensionsFast {
    param([string]$Path)
    if (-not $Path -or -not (Test-Path -LiteralPath $Path)) { return @{ Width = 0; Height = 0 } }
    $ext = [System.IO.Path]::GetExtension($Path).ToLower()
    if ($ext -in @('.webp', '.avif')) {
        return Get-ImageDimensions -Path $Path
    }
    $bmp = $null
    try {
        Add-Type -AssemblyName System.Drawing -ErrorAction Stop
        $bmp = [System.Drawing.Bitmap]::new($Path)
        $w = $bmp.Width
        $h = $bmp.Height
        try {
            foreach ($pi in $bmp.PropertyItems) {
                if ($pi.Id -eq 274 -and $pi.Value.Length -ge 2) {
                    $ori = [BitConverter]::ToUInt16($pi.Value, 0)
                    if ($ori -in @(5, 6, 7, 8)) { $tmp = $w; $w = $h; $h = $tmp }
                    break
                }
            }
        } catch { }
        return @{ Width = [int]$w; Height = [int]$h }
    } catch {
        if ($script:PythonExe) { return Get-ImageDimensions -Path $Path }
        Write-FlickFitObsImgDimWarn -Func 'Get-ImageDimensionsFast' -Path $Path -W 0 -H 0 -Extra '(dotnet+python fallback failed)'
        return @{ Width = 0; Height = 0 }
    }
    finally {
        if ($bmp) { $bmp.Dispose() }
    }
}

# STEP5 の処理順・再開一覧用。フォルダ名から巻番号を取れないものは末尾（99999）、同順はフルパスで安定化
function Get-FlickFitStep5VolumeSortKey {
    param([Parameter(Mandatory = $false)][string]$SourcePath)
    if ([string]::IsNullOrWhiteSpace($SourcePath)) { return 99999 }
    # Split-Path -LiteralPath -Leaf は環境によって Parameter set エラーになるため .NET で取得（[] を含むパスも可）
    $trimmed = $SourcePath.TrimEnd([char]'\', [char]'/')
    $leaf = [System.IO.Path]::GetFileName($trimmed)
    if ([string]::IsNullOrWhiteSpace($leaf)) { $leaf = $trimmed }
    $pv = Get-VolFromParentName $leaf
    if (-not $pv) { return 99999 }
    if ($null -ne $pv.Vol) { return [int]$pv.Vol }
    if ($null -ne $pv.Start) { return [int]$pv.Start }
    return 99999
}

# [ ] を含むパスで Split-Path -Path / Test-Path がワイルドカード解釈しエラーになるのを避ける（.NET はリテラル扱い）
function Get-LiteralPathLeaf {
    param([string]$Path)
    if ([string]::IsNullOrWhiteSpace($Path)) { return '' }
    return [System.IO.Path]::GetFileName($Path.TrimEnd([char]'\', [char]'/'))
}
function Get-LiteralPathParent {
    param([string]$Path)
    if ([string]::IsNullOrWhiteSpace($Path)) { return '' }
    return [System.IO.Path]::GetDirectoryName($Path)
}

# 巻番号順ソート（Sort-Object の scriptblock/ハッシュ複数指定は環境によって Parameter set エラーになるためオブジェクト経由）
function Sort-FlickFitStringPathsByVolume {
    param([string[]]$InputPaths)
    $arr = @($InputPaths | Where-Object { -not [string]::IsNullOrWhiteSpace($_) })
    if ($arr.Count -lt 2) { return $arr }
    $rows = foreach ($p in $arr) {
        [PSCustomObject]@{ VolKey = (Get-FlickFitStep5VolumeSortKey -SourcePath $p); Path = $p }
    }
    @($rows | Sort-Object -Property VolKey, Path | ForEach-Object { $_.Path })
}

function Get-ShortPathForPython {
    param([string]$Path)
    if (-not $Path) { return $Path }
    try {
        $resolved = (Resolve-Path -LiteralPath $Path -ErrorAction Stop).Path
        $fso = New-Object -ComObject Scripting.FileSystemObject
        $item = if (Test-Path -LiteralPath $resolved -PathType Container) { $fso.GetFolder($resolved) } else { $fso.GetFile($resolved) }
        $short = $item.ShortPath
        [System.Runtime.InteropServices.Marshal]::ReleaseComObject($fso) | Out-Null
        return $short
    } catch { return $Path }
}

# ボトルネック計測用
function Add-ProfileTiming { param([string]$Category, [long]$Ms)
    if (-not $script:ProfileTiming -or -not $script:ProfileTimingData) { return }
    if (-not $script:ProfileTimingData.ContainsKey($Category)) { $script:ProfileTimingData[$Category] = 0 }
    $script:ProfileTimingData[$Category] += $Ms
}
#endregion

#region Python bridge & observability
# 役割:
#   Python 起動ラッパー・[PyRoute]/[FileOp] 等の観測ログ・縦横比・ノド幾何の補正。
# 主役:
#   Invoke-PythonTimed / Invoke-PythonWithProcess / Write-FlickFitObs* / Repair-GutterMarginGeometry
# 注意:
#   $script:FlickFitObsDisable 等でログ抑制。既存の & Python 直叩きは徐々にラッパーへ寄せる方針。
# 観測ログ: $script:FlickFitObsDisable = $true で [PyRoute] / [ImgDimFail] / [FileOp] を抑制。[PyRoute] の通常表示は $script:FlickFitDebugPythonRoute=$true（UserConfig: DebugPythonRoute / env FLICK_FIT_DEBUG_PYTHON_ROUTE）のときのみ（既定 OFF）
# STEP5 先頭の contentAspects 行: $script:FlickFitDebugAnalyze=$true または FlickFitDebugStep5Verbose（UserConfig: DebugAnalyze / env FLICK_FIT_DEBUG_ANALYZE）
# $script:FlickFitObsVerboseFileOp = $true で削除成功など「期待どおり」の [FileOp] を DarkGray で出す（既定は抑止）
# $script:FlickFitDebugPythonGeometry = $true で Python の幾何デバッグ（埋め込み trim_split 内の DEBUG_* / TRIM_DEBUG / _dbg_geom）を出す（既定は抑止。埋め込み Python は通常時は _dbg_geom で黙らせる）
# 方針（フェーズ1）: 新規の Python 起動は Invoke-PythonWithProcess / Invoke-PythonTimed 等のラッパー経由に限定。既存の & $script:PythonExe 直叩きは触った経路から順に寄せる。
# batch_split_at_gutter: 1 プロセスで複数の split_at_gutter / split_at_gutter_with_margins を実行（Invoke-FlickFitBatchSplitAtGutterJson）。JSON 例は関数コメント参照。
# FlickFitEnableCachedBalBatch: BALANCED + ノドキャッシュ時に batch_split_at_gutter で連続枚を束ねる（既定 $false）
#   有効化: Modules\UserConfig.json の EnableCachedBalBatch / 環境変数 FLICK_FIT_ENABLE_CACHED_BAL_BATCH=1|true|yes|on
# FlickFitDebugCachedBalBatch: [BATCH-DBG] 詳細（forward 列挙・resultMap・scanCtx・生 stdout 等）。Enable のみのときはこれらは出さず「まとめます: N件」＋キュー反映の1行サマリ程度（UserConfig: DebugCachedBalBatch / env）
# batch_analyze_seq: 1 プロセスで is_one_sided を複数パス分順に実行（Invoke-FlickFitBatchAnalyzeSeq）。
if (-not (Get-Variable -Name FlickFitEnableCachedBalBatch -Scope Script -ErrorAction SilentlyContinue)) { $script:FlickFitEnableCachedBalBatch = $false }
if (-not (Get-Variable -Name FlickFitDebugCachedBalBatch -Scope Script -ErrorAction SilentlyContinue)) { $script:FlickFitDebugCachedBalBatch = $false }
if (-not (Get-Variable -Name FlickFitDebugPythonRoute -Scope Script -ErrorAction SilentlyContinue)) { $script:FlickFitDebugPythonRoute = $false }
if (-not (Get-Variable -Name FlickFitDebugAnalyze -Scope Script -ErrorAction SilentlyContinue)) { $script:FlickFitDebugAnalyze = $false }
if (-not (Get-Variable -Name FlickFitDebugVolumeContext -Scope Script -ErrorAction SilentlyContinue)) { $script:FlickFitDebugVolumeContext = $false }
if ($script:UserConfig) {
    $ucCb = $script:UserConfig
    if ($ucCb.PSObject.Properties.Name -contains 'EnableCachedBalBatch' -and $null -ne $ucCb.EnableCachedBalBatch) {
        $script:FlickFitEnableCachedBalBatch = [bool]$ucCb.EnableCachedBalBatch
    }
    if ($ucCb.PSObject.Properties.Name -contains 'DebugCachedBalBatch' -and $null -ne $ucCb.DebugCachedBalBatch) {
        $script:FlickFitDebugCachedBalBatch = [bool]$ucCb.DebugCachedBalBatch
    }
    if ($ucCb.PSObject.Properties.Name -contains 'DebugPythonRoute' -and $null -ne $ucCb.DebugPythonRoute) {
        $script:FlickFitDebugPythonRoute = [bool]$ucCb.DebugPythonRoute
    }
    if ($ucCb.PSObject.Properties.Name -contains 'DebugAnalyze' -and $null -ne $ucCb.DebugAnalyze) {
        $script:FlickFitDebugAnalyze = [bool]$ucCb.DebugAnalyze
    }
    if ($ucCb.PSObject.Properties.Name -contains 'DebugVolumeContext' -and $null -ne $ucCb.DebugVolumeContext) {
        $script:FlickFitDebugVolumeContext = [bool]$ucCb.DebugVolumeContext
    }
    if ($ucCb.PSObject.Properties.Name -contains 'DebugStep5Verbose' -and $null -ne $ucCb.DebugStep5Verbose) {
        $script:FlickFitDebugStep5Verbose = [bool]$ucCb.DebugStep5Verbose
    }
}
$envEnCb = [Environment]::GetEnvironmentVariable('FLICK_FIT_ENABLE_CACHED_BAL_BATCH')
if (-not [string]::IsNullOrWhiteSpace($envEnCb)) {
    $evCb = $envEnCb.Trim().ToLowerInvariant()
    $script:FlickFitEnableCachedBalBatch = $evCb -in @('1', 'true', 'yes', 'on', 'y')
}
$envDbgCb = [Environment]::GetEnvironmentVariable('FLICK_FIT_DEBUG_CACHED_BAL_BATCH')
if (-not [string]::IsNullOrWhiteSpace($envDbgCb)) {
    $dvCb = $envDbgCb.Trim().ToLowerInvariant()
    $script:FlickFitDebugCachedBalBatch = $dvCb -in @('1', 'true', 'yes', 'on', 'y')
}
$envDbgPyRt = [Environment]::GetEnvironmentVariable('FLICK_FIT_DEBUG_PYTHON_ROUTE')
if (-not [string]::IsNullOrWhiteSpace($envDbgPyRt)) {
    $script:FlickFitDebugPythonRoute = $envDbgPyRt.Trim().ToLowerInvariant() -in @('1', 'true', 'yes', 'on', 'y')
}
$envDbgAnz = [Environment]::GetEnvironmentVariable('FLICK_FIT_DEBUG_ANALYZE')
if (-not [string]::IsNullOrWhiteSpace($envDbgAnz)) {
    $script:FlickFitDebugAnalyze = $envDbgAnz.Trim().ToLowerInvariant() -in @('1', 'true', 'yes', 'on', 'y')
}
$envDbgVolCtx = [Environment]::GetEnvironmentVariable('FLICK_FIT_DEBUG_VOLUME_CONTEXT')
if (-not [string]::IsNullOrWhiteSpace($envDbgVolCtx)) {
    $script:FlickFitDebugVolumeContext = $envDbgVolCtx.Trim().ToLowerInvariant() -in @('1', 'true', 'yes', 'on', 'y')
}
if (-not (Get-Variable -Name FlickFitDisableStep5BatchAnalyze -Scope Script -ErrorAction SilentlyContinue)) { $script:FlickFitDisableStep5BatchAnalyze = $false }
# STEP5 見開き is_one_sided: batch 前の軽い寸法フィルタ（縦長・単ページ幅相当・小画像を BALANCED 確定で Python 省略）無効: $FlickFitStep5AnalyzePrefilter = $false
if (-not (Get-Variable -Name FlickFitStep5AnalyzePrefilter -Scope Script -ErrorAction SilentlyContinue)) { $script:FlickFitStep5AnalyzePrefilter = $true }
# TypicalSingleWidth × 此れ以下の幅なら「単ページ相当」とみなし BALANCED 確定（TypicalSingleWidth=0 なら此の判定は行わない）
if (-not (Get-Variable -Name FlickFitStep5AnalyzeNarrowWidthFactor -Scope Script -ErrorAction SilentlyContinue)) { $script:FlickFitStep5AnalyzeNarrowWidthFactor = 1.45 }
# 縦長でも短辺 ≧ 基準幅×此れ なら 90 度納品の横見開き疑い（is_one_sided 省略しない。Python 回転閾値）
if (-not (Get-Variable -Name FlickFitStep5RotatedSpreadWidthFactor -Scope Script -ErrorAction SilentlyContinue)) { $script:FlickFitStep5RotatedSpreadWidthFactor = 1.25 }
# 基準幅不明: 短辺が此れ未満の縦長のみ従来どおり BALANCED ショートカット
if (-not (Get-Variable -Name FlickFitStep5PortraitSpreadMinAbsWidth -Scope Script -ErrorAction SilentlyContinue)) { $script:FlickFitStep5PortraitSpreadMinAbsWidth = 1280 }
# 表紙: 縦向き格納だが短辺が本体単ページ幅×此れ超なら採点減点（回転横見開き疑い）
if (-not (Get-Variable -Name FlickFitCoverWideWidthFactor -Scope Script -ErrorAction SilentlyContinue)) { $script:FlickFitCoverWideWidthFactor = 1.3 }
if (-not (Get-Variable -Name FlickFitCoverWidePortraitPenalty -Scope Script -ErrorAction SilentlyContinue)) { $script:FlickFitCoverWidePortraitPenalty = 30 }
# BALANCED 見開き: 中央にノドが取れない等で中央2枚割りを避け trim_only する事前チェックを無効化: $FlickFitDisableCenterSplitRisk = $true または env FLICK_FIT_DISABLE_CENTER_SPLIT_RISK=1
if (-not (Get-Variable -Name FlickFitDisableCenterSplitRisk -Scope Script -ErrorAction SilentlyContinue)) { $script:FlickFitDisableCenterSplitRisk = $false }
# 中央1枚型（RISK_SKIP）の四辺プロファイル: 同フォルダ×同W×H で初回GUI後の値を使い回し（無効: $FlickFitDisableCenteredSingleTrimProfile = $true）
if (-not (Get-Variable -Name FlickFitDisableCenteredSingleTrimProfile -Scope Script -ErrorAction SilentlyContinue)) { $script:FlickFitDisableCenteredSingleTrimProfile = $false }
# UserConfig.AutoJudge / ランチャー「自動判定の設定」— 上の既定の上書き（center_split_risk を緩くする等）
if ($script:UserConfig -and $script:UserConfig.PSObject.Properties.Name -contains 'AutoJudge' -and $null -ne $script:UserConfig.AutoJudge) {
    $aj = $script:UserConfig.AutoJudge
    $pre = 'standard'
    if ($aj.PSObject.Properties.Name -contains 'Preset' -and -not [string]::IsNullOrWhiteSpace([string]$aj.Preset)) { $pre = [string]$aj.Preset.Trim() }
    switch -Regex ($pre) {
        '^(?i)lenient' { $script:FlickFitDisableCenterSplitRisk = $true; break }
        '^(?i)custom' { break }  # 以下の個別キー（Disable* / AnalyzeMaxLong）のみ有効
    }
    if ($aj.PSObject.Properties.Name -contains 'DisableCenterSplitRisk' -and $null -ne $aj.DisableCenterSplitRisk) { $script:FlickFitDisableCenterSplitRisk = [bool]$aj.DisableCenterSplitRisk }
    if ($aj.PSObject.Properties.Name -contains 'DisableCenteredSingleTrimProfile' -and $null -ne $aj.DisableCenteredSingleTrimProfile) { $script:FlickFitDisableCenteredSingleTrimProfile = [bool]$aj.DisableCenteredSingleTrimProfile }
    if ($aj.PSObject.Properties.Name -contains 'AnalyzeMaxLong' -and $null -ne $aj.AnalyzeMaxLong) {
        try { $al = [int]$aj.AnalyzeMaxLong; if ($al -ge 0) { $env:FLICK_FIT_ANALYZE_MAX_LONG = [string]$al } } catch { }
    }
}
if (-not (Get-Variable -Name FolderCenteredSingleTrimCache -Scope Script -ErrorAction SilentlyContinue)) { $script:FolderCenteredSingleTrimCache = @{} }
# 構造解析サマリ一覧: 特別編・おまけ等を巻内の最後（話数フォルダの後）へ—無効で従来の数値キーのみ
if (-not (Get-Variable -Name FlickFitDisableOmakeEndOfVolSort -Scope Script -ErrorAction SilentlyContinue)) { $script:FlickFitDisableOmakeEndOfVolSort = $false }
if (-not (Get-Variable -Name FlickFitObsDisable -Scope Script -ErrorAction SilentlyContinue)) { $script:FlickFitObsDisable = $false }
if (-not (Get-Variable -Name FlickFitObsVerboseFileOp -Scope Script -ErrorAction SilentlyContinue)) { $script:FlickFitObsVerboseFileOp = $false }
if (-not (Get-Variable -Name FlickFitDebugPythonGeometry -Scope Script -ErrorAction SilentlyContinue)) { $script:FlickFitDebugPythonGeometry = $false }
# STEP5: entry / preview(Apply) / apply 整合のデバッグ（$script:FlickFitDebugStep5Entry = $true のときのみ）
if (-not (Get-Variable -Name FlickFitDebugStep5Entry -Scope Script -ErrorAction SilentlyContinue)) { $script:FlickFitDebugStep5Entry = $false }
# STEP5: 表紙幅[DEBUG] / [AutoGutter] / [PixelLoss] / [SplitWidthVal] / 分割幅の警告行 / キャッシュ行 / ノド→Python 詳細 等（既定: 出さない。$script:FlickFitDebugStep5Verbose = $true）
if (-not (Get-Variable -Name FlickFitDebugStep5Verbose -Scope Script -ErrorAction SilentlyContinue)) { $script:FlickFitDebugStep5Verbose = $false }
if (-not (Get-Variable -Name FlickFitDebugSourceArchiveDelete -Scope Script -ErrorAction SilentlyContinue)) { $script:FlickFitDebugSourceArchiveDelete = $false }
if (-not (Get-Variable -Name SourceArchivePathsForStep7Delete -Scope Script -ErrorAction SilentlyContinue)) { $script:SourceArchivePathsForStep7Delete = @() }

function Write-FlickFitDebugStep5VerboseHost {
    param(
        [Parameter(Mandatory)][string]$Text,
        [string]$ForegroundColor = 'DarkGray',
        [string]$Prefix = '         '
    )
    if ($true -ne $script:FlickFitDebugStep5Verbose) { return }
    Write-FlickFitHost ($Prefix + $Text) -ForegroundColor $ForegroundColor
}

function Write-FlickFitObsPyRoute {
    param([string]$Caller, [object[]]$PythonArgs, [string]$Note = '')
    if ($true -eq $script:FlickFitObsDisable) { return }
    if (-not ($true -eq $script:FlickFitDebugPythonRoute)) { return }
    $pa = @($PythonArgs)
    $scriptLeaf = ''
    $mode = 'other'
    if ($pa.Count -gt 0) {
        $scriptLeaf = [System.IO.Path]::GetFileName([string]$pa[0])
        if ($scriptLeaf -match 'trim_split') { $mode = 'trim_split_embedded' }
        elseif ($scriptLeaf -match 'vsplit') { $mode = '_vsplit_work' }
    }
    $arg1 = if ($pa.Count -gt 1) { [string]$pa[1] } else { '' }
    Write-FlickFitHost "[PyRoute] caller=$Caller mode=$mode script=$scriptLeaf input=$arg1 $Note" -ForegroundColor DarkCyan
}

function Register-FlickFitCorruptImageForStep5 {
    param([string]$Path)
    if ([string]::IsNullOrWhiteSpace($Path)) { return }
    if (-not (Get-Variable -Name FlickFitCorruptPathsThisFolder -Scope Script -ErrorAction SilentlyContinue) -or $null -eq $script:FlickFitCorruptPathsThisFolder) { return }
    try { $fn = [System.IO.Path]::GetFullPath($Path) } catch { $fn = $Path }
    if ($null -eq $fn) { return }
    # HashSet: 同一路径（Aspect / Dimensions 等の重複登録、大小文字差）を1件にまとめる
    [void]$script:FlickFitCorruptPathsThisFolder.Add($fn)
}

function Show-FlickFitCorruptImageNotifyForStep5Folder {
    param([string]$FolderLabel = '')
    if ((Test-Path variable:DryRun) -and $DryRun) {
        if ((Get-Variable -Name FlickFitCorruptPathsThisFolder -Scope Script -ErrorAction SilentlyContinue) -and $null -ne $script:FlickFitCorruptPathsThisFolder) {
            $script:FlickFitCorruptPathsThisFolder.Clear()
        }
        return
    }
    if (-not (Get-Variable -Name FlickFitCorruptPathsThisFolder -Scope Script -ErrorAction SilentlyContinue) -or $null -eq $script:FlickFitCorruptPathsThisFolder) { return }
    if ($script:FlickFitCorruptPathsThisFolder.Count -eq 0) { return }
    $list = [string[]]@($script:FlickFitCorruptPathsThisFolder | Sort-Object { $_ })
    $script:FlickFitCorruptPathsThisFolder.Clear()
    $n = $list.Count
    $maxDlg = 5
    $buf = [System.Text.StringBuilder]::new()
    if ($FolderLabel) {
        [void]$buf.AppendLine("【$FolderLabel】")
        [void]$buf.AppendLine('')
    }
    [void]$buf.AppendLine("処理は完了しましたが、読み込めなかった画像が $n 件ありました。")
    [void]$buf.AppendLine('')
    for ($i = 0; $i -lt [Math]::Min($n, $maxDlg); $i++) {
        [void]$buf.AppendLine('- ' + (Get-LiteralPathLeaf $list[$i]))
    }
    if ($n -gt $maxDlg) { [void]$buf.AppendLine("- 他 $($n - $maxDlg) 件") }
    [void]$buf.AppendLine('')
    [void]$buf.AppendLine('詳しくはコンソールの一覧を確認してください。')
    $bodyDlg = $buf.ToString().TrimEnd()
    Write-FlickFitHost "     [画像読み込み失敗] $n 件（全件 / フルパス）" -ForegroundColor Yellow
    foreach ($p in $list) {
        Write-FlickFitHost "       - $p" -ForegroundColor Yellow
    }
    try {
        Add-Type -AssemblyName System.Windows.Forms -ErrorAction Stop
        [void][System.Windows.Forms.MessageBox]::Show(
            $bodyDlg,
            'FlickFit — 画像の読み込み失敗',
            [System.Windows.Forms.MessageBoxButtons]::OK,
            [System.Windows.Forms.MessageBoxIcon]::Warning
        )
    } catch {
        Write-FlickFitHost "     (MessageBox 非表示) コンソールの一覧をご確認ください。" -ForegroundColor DarkYellow
    }
}

function Write-FlickFitObsImgDimWarn {
    param([string]$Func, [string]$Path, [int]$W = 0, [int]$H = 0, [string]$Extra = '')
    if ([string]::IsNullOrWhiteSpace($Path)) { return }
    if (-not (Test-Path -LiteralPath $Path)) { return }
    Register-FlickFitCorruptImageForStep5 -Path $Path
    if ($true -eq $script:FlickFitObsDisable) { return }
    Write-FlickFitWarning "[ImgDimFail] func=$Func path=$Path w=$W h=$H $Extra"
}

function Write-FlickFitObsFileOp {
    param([string]$Op, [string]$Path)
    if ($true -eq $script:FlickFitObsDisable) { return }
    if ([string]::IsNullOrWhiteSpace($Path)) { return }
    $ex = Test-Path -LiteralPath $Path
    $msg = "[FileOp] op=$Op path=$Path existsAfter=$ex"
    $quietOk = (
        ($Op -match 'Remove_so[12]' -and -not $ex) -or
        ($Op -match 'CopyBackupToOrig' -and $ex) -or
        ($Op -match 'tempBackup' -and $ex)
    )
    if ($quietOk) {
        if ($true -eq $script:FlickFitObsVerboseFileOp) { Write-FlickFitHost $msg -ForegroundColor DarkGray }
        return
    }
    $bad = (
        ($Op -match 'Remove_so' -and $ex) -or
        ($Op -match 'CopyBackupToOrig' -and -not $ex) -or
        ($Op -match 'tempBackup' -and -not $ex)
    )
    if ($bad) { Write-FlickFitWarning $msg }
    else { Write-FlickFitHost $msg -ForegroundColor DarkCyan }
}

function Write-FlickFitPythonDebugLines {
    param([object[]]$Lines)
    if ($true -eq $script:FlickFitObsDisable) { return }
    if (-not ($true -eq $script:FlickFitDebugPythonGeometry)) { return }
    if ($null -eq $Lines) { return }
    foreach ($ln in $Lines) {
        $line = "$ln"
        if ($line -match '^(DEBUG|TRIM_DEBUG)') { Write-FlickFitHost "         $line" -ForegroundColor DarkGray }
    }
}

function Invoke-PythonTimed {
    param([string]$Category, [object[]]$PythonArgs)
    Write-FlickFitObsPyRoute -Caller 'Invoke-PythonTimed' -PythonArgs $PythonArgs
    if (-not $script:ProfileTiming) {
        try {
            $out = & $script:PythonExe @PythonArgs 2>&1
            $ec = $LASTEXITCODE
            if ($null -ne $ec -and $ec -ne 0) { Write-FlickFitWarning "[PyRoute] Invoke-PythonTimed exitCode=$ec category=$Category" }
            return $out
        } catch {
            Write-FlickFitWarning "[PyRoute] Invoke-PythonTimed exception: $($_.Exception.Message)"
            throw
        }
    }
    $sw = [System.Diagnostics.Stopwatch]::StartNew()
    try {
        $out = & $script:PythonExe @PythonArgs 2>&1
        $ec = $LASTEXITCODE
        if ($null -ne $ec -and $ec -ne 0) { Write-FlickFitWarning "[PyRoute] Invoke-PythonTimed exitCode=$ec category=$Category" }
        return $out
    } finally { Add-ProfileTiming -Category $Category -Ms $sw.ElapsedMilliseconds }
}

# 1 回の Python で is_one_sided を複数ファイル順に実行（リストファイル経由）
function Invoke-FlickFitBatchAnalyzeSeq {
    param(
        [string]$Category = "PythonAnalyze",
        [Parameter(Mandatory)][string]$WorkTrimSplitPy,
        [Parameter(Mandatory)][bool]$RightBinding,
        [string[]]$Paths
    )
    if (-not $script:PythonExe -or [string]::IsNullOrWhiteSpace($WorkTrimSplitPy) -or -not (Test-Path -LiteralPath $WorkTrimSplitPy)) { return @() }
    $valid = @($Paths | Where-Object { $_ -and (Test-Path -LiteralPath $_) })
    if ($valid.Count -eq 0) { return @() }
    $listPath = Join-Path (Get-FlickFitScratchTempDir) ("ff_batch_anseq_" + [Guid]::NewGuid().ToString('N').Substring(0, 8) + ".txt")
    try {
        $u8 = New-Object System.Text.UTF8Encoding($false)
        [System.IO.File]::WriteAllLines($listPath, [string[]]@($valid), $u8)
        return @(Invoke-PythonTimed -Category $Category -PythonArgs $WorkTrimSplitPy, $listPath, $RightBinding.ToString(), "batch_analyze_seq")
    } catch {
        return @()
    } finally {
        if (Test-Path -LiteralPath $listPath) { Remove-Item -LiteralPath $listPath -Force -ErrorAction SilentlyContinue }
    }
}

# trim_split_embedded.py に JSON を渡し batch_split_at_gutter を 1 回だけ実行。stdout はジョブごと 1 行の JSON。
# 例: @{ right_binding = $true; jobs = @(
#   @{ op = "split_at_gutter"; input = "C:\a.jpg"; gutter_x = 1920; no_trim = $false; aspect_min = 0.7; cover_width = 1520; no_vertical_trim = $true; gui_exact = $false }
# ) } | ConvertTo-Json -Depth 10 | Set-Content ...
function Invoke-FlickFitBatchSplitAtGutterJson {
    param(
        [string]$Category = "PythonSplit",
        [Parameter(Mandatory)][string]$WorkTrimSplitPy,
        [Parameter(Mandatory)][bool]$RightBinding,
        [Parameter(Mandatory)][string]$JsonPath
    )
    if (-not $script:PythonExe -or -not (Test-Path -LiteralPath $JsonPath) -or -not (Test-Path -LiteralPath $WorkTrimSplitPy)) { return @() }
    return @(Invoke-PythonTimed -Category $Category -PythonArgs $WorkTrimSplitPy, $JsonPath, $RightBinding.ToString(), "batch_split_at_gutter")
}

# 先読み列挙: メモリ上の $imgs/$imgIdx が分割・再取得でズレるため、ディスク上の一覧から現在ファイル位置を解決する
function Get-FlickFitCachedBalBatchScanContext {
    param(
        [Parameter(Mandatory)][string]$DirPath,
        [Parameter(Mandatory)][string]$CurrentFileFullPath,
        $LoopImgs,
        [int]$LoopImgIdx
    )
    $scan = @(Get-ProcessableFolderImages -FolderPath $DirPath)
    $normCur = $null
    try { $normCur = [System.IO.Path]::GetFullPath($CurrentFileFullPath.Trim().TrimStart([char]0xFEFF)) } catch { $normCur = [string]$CurrentFileFullPath }
    $found = -1
    for ($i = 0; $i -lt $scan.Count; $i++) {
        $nk = $null
        try { $nk = [System.IO.Path]::GetFullPath($scan[$i].FullName.Trim().TrimStart([char]0xFEFF)) } catch { $nk = $scan[$i].FullName }
        if ($normCur -and $nk -and [string]::Equals($normCur, $nk, [StringComparison]::OrdinalIgnoreCase)) {
            $found = $i
            break
        }
    }
    if ($found -ge 0) {
        return @{ Imgs = $scan; StartIdx = $found; Source = 'rescan' }
    }
    $li = @($LoopImgs)
    if ($li.Count -gt 0 -and $LoopImgIdx -ge 0 -and $LoopImgIdx -lt $li.Count) {
        return @{ Imgs = $li; StartIdx = $LoopImgIdx; Source = 'loop_idx' }
    }
    $sx = 0
    if ($scan.Count -gt 0) { $sx = [Math]::Max(0, [Math]::Min($LoopImgIdx, $scan.Count - 1)) }
    return @{ Imgs = $scan; StartIdx = $sx; Source = 'rescan_path_miss_clamped' }
}

function Get-FlickFitStep5PathKey {
    param([string]$FullPath)
    if ([string]::IsNullOrWhiteSpace($FullPath)) { return $null }
    try {
        return [System.IO.Path]::GetFullPath($FullPath.Trim().TrimStart([char]0xFEFF))
    } catch {
        return $FullPath.Trim().TrimStart([char]0xFEFF)
    }
}

# バッチJSON・リスト・プレビュー等のスクラッチ。既定: FlickFit 本体\_temp（セキュリティソフト除外しやすい）。不可→作品\_flickfit_temp→ユーザーTemp
$script:FlickFitScratchTempDirCache = $null
$script:FlickFitScratchTempDirLogged = $false

function Get-FlickFitAppRootForScratch {
    if ($PSScriptRoot) { return $PSScriptRoot }
    if ($PSCommandPath) {
        try { return [System.IO.Path]::GetDirectoryName($PSCommandPath) } catch {}
    }
    return $null
}

function Test-FlickFitScratchDirWritable {
    param([string]$DirPath)
    if ([string]::IsNullOrWhiteSpace($DirPath)) { return $false }
    try {
        if (-not (Test-Path -LiteralPath $DirPath)) {
            $null = New-Item -ItemType Directory -Path $DirPath -Force -ErrorAction Stop
        }
        $probe = Join-Path $DirPath ('.ff_write_probe_' + [Guid]::NewGuid().ToString('N'))
        $encProbe = [System.Text.UTF8Encoding]::new($false)
        [System.IO.File]::WriteAllText($probe, '1', $encProbe)
        Remove-Item -LiteralPath $probe -Force -ErrorAction SilentlyContinue
        return $true
    } catch {
        return $false
    }
}

function Get-FlickFitScratchTempDir {
    if ($script:FlickFitScratchTempDirCache) { return $script:FlickFitScratchTempDirCache }
    $cands = [System.Collections.Generic.List[hashtable]]::new()
    $appRoot = Get-FlickFitAppRootForScratch
    if ($appRoot) {
        [void]$cands.Add(@{ Path = (Join-Path $appRoot '_temp'); Desc = 'FlickFit本体\_temp' })
    }
    if ($script:TitleFolder -and $script:TitleFolder.FullName) {
        [void]$cands.Add(@{ Path = (Join-Path $script:TitleFolder.FullName '_flickfit_temp'); Desc = '作品フォルダ\_flickfit_temp' })
    }
    $sysTemp = $null
    try { $sysTemp = [System.IO.Path]::GetTempPath().TrimEnd('\') } catch { $sysTemp = $env:TEMP }
    if (-not [string]::IsNullOrWhiteSpace($sysTemp)) {
        [void]$cands.Add(@{ Path = $sysTemp; Desc = 'ユーザーTemp' })
    }
    $chosen = $env:TEMP
    $chosenDesc = 'ユーザーTemp'
    foreach ($c in $cands) {
        if ($c.Path -and (Test-FlickFitScratchDirWritable $c.Path)) {
            try { $chosen = [System.IO.Path]::GetFullPath($c.Path) } catch { $chosen = $c.Path }
            $chosenDesc = $c.Desc
            break
        }
    }
    $script:FlickFitScratchTempDirCache = $chosen
    if (-not $script:FlickFitScratchTempDirLogged) {
        $script:FlickFitScratchTempDirLogged = $true
        Write-FlickFitHost ("[一時フォルダ] {0} （{1}）" -f $chosen, $chosenDesc) -ForegroundColor DarkGray
    }
    return $chosen
}

# 書き込み直後のロック対策のあと、関連付けで開く（Invoke-Item）→ explorer の順
function Open-FlickFitPreviewImage {
    param(
        [Parameter(Mandatory = $true)]
        [string]$Path
    )
    try {
        $full = [System.IO.Path]::GetFullPath($Path)
        for ($i = 0; $i -lt 10; $i++) {
            if ((Test-Path -LiteralPath $full) -and ((Get-Item -LiteralPath $full).Length -gt 0)) {
                break
            }
            Start-Sleep -Milliseconds 100
        }
        if (-not (Test-Path -LiteralPath $full)) {
            Write-FlickFitHost "  [警告] 表紙プレビューが見つかりません: $full" -ForegroundColor Yellow
            return $false
        }
        if ((Get-Item -LiteralPath $full).Length -le 0) {
            Write-FlickFitHost "  [警告] 表紙プレビューが空ファイルです: $full" -ForegroundColor Yellow
            return $false
        }
        try {
            Invoke-Item -LiteralPath $full
            return $true
        } catch {
            try {
                Start-Process -FilePath 'explorer.exe' -ArgumentList "`"$full`""
                return $true
            } catch {
                Write-FlickFitHost "  [警告] 表紙を開けませんでした: $($_.Exception.Message)" -ForegroundColor Yellow
                return $false
            }
        }
    } catch {
        Write-FlickFitHost "  [警告] 表紙を開けませんでした: $($_.Exception.Message)" -ForegroundColor Yellow
        return $false
    }
}

# FlickFit スクラッチ（Get-FlickFitScratchTempDir が選んだフォルダ）内の一時のみ掃除。成功時のみ ff_batch_split_raw_*.log も削除（不具合調査用に失敗時は残す）。
function Clear-FlickFitScratchTempFiles {
    param(
        [Parameter()]
        [bool]$SuccessRun = $false
    )
    $dir = $script:FlickFitScratchTempDirCache
    if ([string]::IsNullOrWhiteSpace($dir) -or -not (Test-Path -LiteralPath $dir)) { return }

    $patterns = @(
        'aspect_*.txt',
        'ff_batch_anseq_*.txt',
        'ff_batch_split_*.json',
        'preview_crop_*',
        'preview_title_*',
        'bpg_*.png',
        'bpg_*.py',
        'img_convert_*.py'
    )
    if ($SuccessRun) {
        $patterns = $patterns + @('ff_batch_split_raw_*.log')
    }
    foreach ($pat in $patterns) {
        Get-ChildItem -LiteralPath $dir -Filter $pat -File -ErrorAction SilentlyContinue |
            Remove-Item -Force -ErrorAction SilentlyContinue
    }
    $coverPrev = Join-Path $dir 'cover_preview.jpg'
    if (Test-Path -LiteralPath $coverPrev) {
        Remove-Item -LiteralPath $coverPrev -Force -ErrorAction SilentlyContinue
    }
}

# Sync 時の GetFullPath のみと forward 先読みの Trim+FEFF 付きを両方試し、欠けていたら null
function Resolve-FlickFitStep5AnalyzeForPath {
    param(
        [System.Collections.IDictionary]$ByPath,
        [string]$FullPath
    )
    if (-not $ByPath -or [string]::IsNullOrWhiteSpace($FullPath)) { return $null }
    $kTrim = Get-FlickFitStep5PathKey $FullPath
    if ($kTrim -and $ByPath.ContainsKey($kTrim)) {
        return @{ Key = $kTrim; Text = [string]$ByPath[$kTrim] }
    }
    try {
        $kRaw = [System.IO.Path]::GetFullPath($FullPath)
        if ($kRaw -and $ByPath.ContainsKey($kRaw)) {
            return @{ Key = $kRaw; Text = [string]$ByPath[$kRaw] }
        }
    } catch { }
    return $null
}

# STEP5: BALANCED + ノドキャッシュで連続する同一解像度・BALANCED 画像を batch_split_at_gutter 用に列挙（片側・目次・解像度違いで打ち切り）
# 寸法は Get-ImageDimensionsFast（JPG は .NET）で先読み負荷を抑える
function Get-FlickFitCachedBalBatchForwardPaths {
    param(
        [int]$StartIdx,
        [Parameter(Mandatory)] $Imgs,
        [Parameter(Mandatory)] [int]$ExpectW,
        [Parameter(Mandatory)] [int]$ExpectH,
        $CacheB,
        [Parameter(Mandatory)] $Step5OneSidedByPath,
        $FolderTocPaths,
        [bool]$SkipAvif
    )
    # 列挙パスは Debug のみ。Enable のみのときは STEP5 側の「まとめます: N 件」だけ残す（配布で静かに）
    $wantBatchDbg = ($true -eq $script:FlickFitDebugCachedBalBatch)
    $script:FlickFitCachedBalBatchLastBreak = $null
    if ($wantBatchDbg) {
        $sn = if ($StartIdx -ge 0 -and $StartIdx -lt $Imgs.Count) { [string]$Imgs[$StartIdx].Name } else { '?idx_oob' }
        Write-FlickFitHost ("         [BATCH-DBG] forward-fn enter imgsCount={0} startIdx={1} startName={2}" -f @($Imgs).Count, $StartIdx, $sn) -ForegroundColor DarkGray
        $nx = $StartIdx + 1
        if ($nx -lt @($Imgs).Count) {
            Write-FlickFitHost ("         [BATCH-DBG] forward-fn next idx={0} name={1}" -f $nx, $Imgs[$nx].Name) -ForegroundColor DarkGray
        } else {
            Write-FlickFitHost "         [BATCH-DBG] forward-fn no-next (startIdx+1 >= imgsCount)" -ForegroundColor DarkGray
        }
    }
    $acc = [System.Collections.Generic.List[string]]::new()
    $imgArr = @($Imgs)
    for ($j = $StartIdx; $j -lt $imgArr.Count; $j++) {
        $c = $imgArr[$j]
        $leaf = if ($c -and $c.Name) { [string]$c.Name } else { '?' }
        if (-not $c -or -not $c.FullName) {
            $script:FlickFitCachedBalBatchLastBreak = "invalid_entry idx=$j"
            break
        }
        if ($c.Name -like 'cvr_*') {
            $script:FlickFitCachedBalBatchLastBreak = "cvr_temp file=$leaf"
            break
        }
        if ($SkipAvif -and $c.Extension.ToLower() -eq '.avif') {
            $script:FlickFitCachedBalBatchLastBreak = "avif file=$leaf"
            break
        }
        if (-not (Test-Path -LiteralPath $c.FullName)) {
            $script:FlickFitCachedBalBatchLastBreak = "missing_file file=$leaf"
            break
        }
        $d = Get-ImageDimensionsFast -Path $c.FullName
        if ($d.Width -ne $ExpectW -or $d.Height -ne $ExpectH) {
            $script:FlickFitCachedBalBatchLastBreak = "dim_mismatch file=$leaf got=$($d.Width)x$($d.Height) expect=${ExpectW}x${ExpectH}"
            break
        }
        $nk = Get-FlickFitStep5PathKey $c.FullName
        if ($FolderTocPaths -and $nk -and $FolderTocPaths.ContainsKey($nk)) {
            $script:FlickFitCachedBalBatchLastBreak = "toc file=$leaf"
            break
        }
        $rs5 = if ($Step5OneSidedByPath) { Resolve-FlickFitStep5AnalyzeForPath -ByPath $Step5OneSidedByPath -FullPath $c.FullName } else { $null }
        if (-not $rs5) {
            $script:FlickFitCachedBalBatchLastBreak = "no_step5_analyze_key file=$leaf"
            break
        }
        $ar = [string]$rs5.Text
        if ($ar -match 'ONE_SIDED') {
            $arSnippet = if ($ar.Length -gt 48) { $ar.Substring(0, 45) + '...' } else { $ar }
            $script:FlickFitCachedBalBatchLastBreak = "one_sided file=$leaf analyze=$arSnippet"
            break
        }
        if ($CacheB -and ([int]$CacheB.ImgW -ne $d.Width -or [int]$CacheB.ImgH -ne $d.Height)) {
            $script:FlickFitCachedBalBatchLastBreak = "cache_wh_mismatch file=$leaf img=$($d.Width)x$($d.Height) cache=$([int]$CacheB.ImgW)x$([int]$CacheB.ImgH)"
            break
        }
        [void]$acc.Add($c.FullName)
        if ($wantBatchDbg) {
            Write-FlickFitHost ("         [BATCH-DBG] forward-add idx={0} file={1} accCount={2}" -f $j, $leaf, $acc.Count) -ForegroundColor DarkGray
        }
    }
    if ($acc.Count -eq 1 -and [string]::IsNullOrWhiteSpace($script:FlickFitCachedBalBatchLastBreak)) {
        $script:FlickFitCachedBalBatchLastBreak = "list_end_after_one startIdx=$StartIdx totalImgs=$($imgArr.Count)"
    }
    $outForward = @($acc.ToArray())
    if ($wantBatchDbg) {
        $rc = @($outForward).Count
        $rt = if ($rc -gt 0) { $outForward[0].GetType().FullName } else { 'n/a' }
        Write-FlickFitHost ("         [BATCH-DBG] forward-return count={0} elem0Type={1}" -f $rc, $rt) -ForegroundColor DarkGray
    }
    return $outForward
}

# STEP5: is_one_sided（mode=analyze）を batch_analyze_seq で一括。$ByPath キーは GetFullPath 正規化
function Sync-FlickFitStep5OneSidedAnalyzeMap {
    param(
        [Parameter(Mandatory)] [System.Collections.IDictionary] $ByPath,
        [Parameter(Mandatory)] $Imgs,
        [Parameter(Mandatory)] [string] $WorkTrimSplitPy,
        [Parameter(Mandatory)] [bool] $RightBinding,
        [int] $TypicalSingleWidth = 0
    )
    if ($true -eq $script:FlickFitDisableStep5BatchAnalyze) { return }
    if (-not $WorkTrimSplitPy -or -not (Test-Path -LiteralPath $WorkTrimSplitPy)) { return }
    if (-not $Imgs) { return }
    # AVIF は Get-ImageDimensionsFast が毎回 Python/枚。SkipAVIF かつ cvr_ 除く全件が .avif なら寸法プレ枠不要で全件 BALANCED（上と同等の扱い）
    if ($true -eq $script:SkipAVIF) {
        $hasContent = $false
        $allContentAvif = $true
        foreach ($im in $Imgs) {
            if (-not $im -or -not $im.FullName) { continue }
            if ($im.Name -like 'cvr_*') { continue }
            if (-not (Test-Path -LiteralPath $im.FullName)) { continue }
            $hasContent = $true
            if ([System.IO.Path]::GetExtension($im.FullName).ToLower() -ne '.avif') { $allContentAvif = $false; break }
        }
        if ($hasContent -and $allContentAvif) {
            foreach ($im in $Imgs) {
                if (-not $im -or -not $im.FullName) { continue }
                if ($im.Name -like 'cvr_*') { continue }
                $p = $im.FullName
                if (-not (Test-Path -LiteralPath $p)) { continue }
                $normK = Get-FlickFitStep5PathKey $p
                if ($normK -and -not $ByPath.ContainsKey($normK)) { $ByPath[$normK] = 'BALANCED' }
            }
            Write-FlickFitHost "         [STEP5] 全枚 AVIF・SkipAVIF: is_one_sided 寸法プレ枠/一括分析を省略（BALANCED 一括）" -ForegroundColor DarkGray
            return
        }
    }
    $toFetch = [System.Collections.Generic.List[string]]::new()
    $prefillDim = 0
    $narrowLimit = 0
    if ($TypicalSingleWidth -gt 0 -and $script:FlickFitStep5AnalyzeNarrowWidthFactor -gt 0) {
        $narrowLimit = [int]([double]$TypicalSingleWidth * [double]$script:FlickFitStep5AnalyzeNarrowWidthFactor)
    }
    $rotSpreadMinW = 0
    if ($TypicalSingleWidth -gt 0 -and $script:FlickFitStep5RotatedSpreadWidthFactor -gt 0) {
        $rotSpreadMinW = [int]([double]$TypicalSingleWidth * [double]$script:FlickFitStep5RotatedSpreadWidthFactor)
    }
    foreach ($im in $Imgs) {
        if (-not $im -or -not $im.FullName) { continue }
        if ($im.Name -like 'cvr_*') { continue }
        $p = $im.FullName
        if (-not (Test-Path -LiteralPath $p)) { continue }
        $normK = Get-FlickFitStep5PathKey $p
        if (-not $normK -or $ByPath.ContainsKey($normK)) { continue }
        if ($true -eq $script:FlickFitStep5AnalyzePrefilter) {
            $dims = Get-ImageDimensionsFast -Path $p
            $iw = $dims.Width
            $ih = $dims.Height
            if ($iw -gt 0 -and $ih -gt 0) {
                $skipBalanced = $false
                $widePortraitMaybeRotatedSpread = $false
                if ($iw -le $ih) {
                    if ($rotSpreadMinW -gt 0 -and $iw -ge $rotSpreadMinW) { $widePortraitMaybeRotatedSpread = $true }
                    elseif ($rotSpreadMinW -le 0 -and $iw -ge $script:FlickFitStep5PortraitSpreadMinAbsWidth) { $widePortraitMaybeRotatedSpread = $true }
                }
                if ($iw -le $ih -and -not $widePortraitMaybeRotatedSpread) { $skipBalanced = $true }
                elseif ($iw -lt 280 -or $ih -lt 280) { $skipBalanced = $true }
                elseif ($narrowLimit -gt 0 -and $iw -gt $ih -and $iw -le $narrowLimit) { $skipBalanced = $true }
                if ($skipBalanced) {
                    $ByPath[$normK] = "BALANCED"
                    $prefillDim++
                    continue
                }
            }
        }
        [void]$toFetch.Add($p)
    }
    if ($prefillDim -ge 1) {
        Write-FlickFitHost "         [STEP5] 見開き解析: 寸法フィルタで $prefillDim 件を BALANCED 確定（原寸分析スキップ）" -ForegroundColor DarkGray
    }
    if ($toFetch.Count -gt 0) {
        try {
            $lines = Invoke-FlickFitBatchAnalyzeSeq -Category "PythonAnalyze" -WorkTrimSplitPy $WorkTrimSplitPy -RightBinding $RightBinding -Paths @($toFetch)
            if ($toFetch.Count -ge 2) {
                Write-FlickFitHost "         [STEP5] 見開き解析 is_one_sided を 1 プロセスにまとめました ($($toFetch.Count) 件)" -ForegroundColor DarkGray
            }
            foreach ($line in $lines) {
                if ([string]::IsNullOrWhiteSpace($line)) { continue }
                if ($line -match '^(BATCH_EMPTY|Traceback|ERROR:batch)') { continue }
                $tabI = $line.IndexOf([char]9)
                if ($tabI -lt 1) { continue }
                $pPart = $line.Substring(0, $tabI).Trim().TrimStart([char]0xFEFF)
                if (-not $pPart) { continue }
                $rPart = if ($tabI -lt $line.Length - 1) { $line.Substring($tabI + 1) } else { "" }
                $k = Get-FlickFitStep5PathKey $pPart
                if ($k -and -not $ByPath.ContainsKey($k)) { $ByPath[$k] = $rPart }
            }
        } catch { }
    }
    # リスト行取りこぼし・未解析のままだと CachedBal 束ねの forward scan が 2 枚目で途切れる → フォルダ内の全画像にキーを保証
    foreach ($im2 in $Imgs) {
        if (-not $im2 -or -not $im2.FullName) { continue }
        if ($im2.Name -like 'cvr_*') { continue }
        if (-not (Test-Path -LiteralPath $im2.FullName)) { continue }
        $mk2 = Get-FlickFitStep5PathKey $im2.FullName
        if ([string]::IsNullOrWhiteSpace($mk2)) { continue }
        if (-not $ByPath.ContainsKey($mk2)) { $ByPath[$mk2] = 'BALANCED' }
    }
    try {
        $rekey = @{}
        foreach ($ek in @($ByPath.Keys)) {
            $ev0 = $ByPath[$ek]
            $nk0 = Get-FlickFitStep5PathKey ([string]$ek)
            if ([string]::IsNullOrWhiteSpace($nk0)) { continue }
            $rekey[$nk0] = $ev0
        }
        foreach ($ok in @($ByPath.Keys)) { [void]$ByPath.Remove($ok) }
        foreach ($rk in $rekey.Keys) { $ByPath[$rk] = $rekey[$rk] }
    } catch { }
}

function Invoke-PythonWithProcess {
    param([string]$Category, [object[]]$PythonArgs)
    $escaped = foreach ($a in $PythonArgs) {
        $s = [string]$a
        $s = $s.Replace('\', '\\').Replace('"', '\"')
        "`"$s`""
    }
    $argStr = $escaped -join " "
    $psi = New-Object System.Diagnostics.ProcessStartInfo
    $psi.FileName = $script:PythonExe
    $psi.Arguments = $argStr
    $psi.UseShellExecute = $false
    $psi.RedirectStandardOutput = $true
    $psi.RedirectStandardError = $true
    $psi.StandardOutputEncoding = [System.Text.Encoding]::UTF8
    $psi.StandardErrorEncoding = [System.Text.Encoding]::UTF8
    $psi.CreateNoWindow = $true
    Write-FlickFitObsPyRoute -Caller 'Invoke-PythonWithProcess' -PythonArgs $PythonArgs
    $sw = if ($script:ProfileTiming) { [System.Diagnostics.Stopwatch]::StartNew() } else { $null }
    try {
        $proc = [System.Diagnostics.Process]::Start($psi)
        $out = $proc.StandardOutput.ReadToEnd()
        $err = $proc.StandardError.ReadToEnd()
        $proc.WaitForExit()
        $exitC = $proc.ExitCode
        if ($exitC -ne 0) { Write-FlickFitWarning "[PyRoute] Invoke-PythonWithProcess exitCode=$exitC category=$Category" }
        $combined = if ($err) { $out + "`n" + $err } else { $out }
        return $combined -split "`r?`n"
    } finally {
        if ($sw) { Add-ProfileTiming -Category $Category -Ms $sw.ElapsedMilliseconds }
    }
}

function Get-ImageAspect {
    param($Path)
    $sw = if ($script:ProfileTiming) { [System.Diagnostics.Stopwatch]::StartNew() } else { $null }
    $ext = [System.IO.Path]::GetExtension($Path).ToLower()
    
    # webp/avif はPythonで処理（.NETがサポートしていないため）
    if ($ext -in @('.webp', '.avif') -and $script:PythonExe) {
        try {
            $pyCode = "from PIL import Image; img=Image.open(r'$Path'); print(img.width/img.height if img.height>0 else 0)"
            $result = & $script:PythonExe -c $pyCode 2>$null
            if ($result -match '^[\d\.]+$') { return [double]$result }
        } catch {}
        finally { if ($sw) { Add-ProfileTiming -Category "GetImageAspect" -Ms $sw.ElapsedMilliseconds } }
    }
    
    # 通常の画像は.NETで処理（EXIF Orientation 5–8 は表示向きが90°回転＝縦横を入れ替えてから比を取る）
    $bmp = $null
    try {
        Add-Type -AssemblyName System.Drawing -ErrorAction Stop
        $bmp = [System.Drawing.Bitmap]::new($Path)
        $w = $bmp.Width
        $h = $bmp.Height
        try {
            $oriItem = $null
            foreach ($pi in $bmp.PropertyItems) {
                if ($pi.Id -eq 274) { $oriItem = $pi; break }
            }
            if ($null -ne $oriItem -and $oriItem.Value.Length -ge 2) {
                $ori = [BitConverter]::ToUInt16($oriItem.Value, 0)
                if ($ori -in @(5, 6, 7, 8)) { $tmp = $w; $w = $h; $h = $tmp }
            }
        } catch { }
        $r = if ($h -gt 0) { $w / $h } else { 0 }
        return $r
    } catch {
        if (Test-Path -LiteralPath $Path) {
            if ($script:PythonExe) {
                $dimFb = Get-ImageDimensions -Path $Path -SuppressObsWarn
                if ($dimFb.Width -gt 0 -and $dimFb.Height -gt 0) {
                    return [double]$dimFb.Width / [double]$dimFb.Height
                }
            }
            Write-FlickFitObsImgDimWarn -Func 'Get-ImageAspect' -Path $Path -W 0 -H 0 -Extra 'aspect=-1 (dotnet Bitmap と PIL の両方で寸法取得できず)'
        }
        return -1
    }
    finally {
        if ($bmp) { $bmp.Dispose() }
        if ($sw) { Add-ProfileTiming -Category "GetImageAspect" -Ms $sw.ElapsedMilliseconds }
    }
}

# AspectThreshold が 1.0 超（例: 1.4）のとき「わずかに横長」(1.0〜閾値未満) が縦扱いになるのを防ぐ（幅>=高さなら見開き候補）
function Test-IsLandscapeAspectForSpread {
    param(
        [double]$Aspect,
        [double]$Threshold
    )
    if ($Threshold -gt 1.0) {
        if ($Aspect -ge $Threshold) { return $true }
        if ($Aspect -ge 1.0) { return $true }
        return $false
    }
    return ($Aspect -ge $Threshold)
}

# 左トリム境界がノドより右だと Python 側で raw_gutter<0 となり分割が破綻するため、呼び出し前に幾何を整合
function Repair-GutterMarginGeometry {
    param(
        [int]$ImgW,
        [int]$GutterX,
        [int]$LeftTrim,
        [int]$RightTrim,
        [int]$MinPagePx = 5
    )
    $adjusted = $false
    if ($ImgW -le ($MinPagePx * 2 + 3)) {
        $gx = [Math]::Max(1, [Math]::Floor($ImgW / 2))
        return @{ GutterX = $gx; LeftTrimPx = 0; RightTrimPx = 0 }
    }
    $gx = [Math]::Max($MinPagePx + 1, [Math]::Min($ImgW - $MinPagePx - 1, $GutterX))
    if ($gx -ne $GutterX) { $adjusted = $true }
    $lt = [Math]::Max(0, $LeftTrim)
    $rt = [Math]::Max(0, $RightTrim)
    # クロップ後の左ページ幅 = gx - lt >= MinPagePx
    if (($gx - $lt) -lt $MinPagePx) {
        $lt = [Math]::Max(0, $gx - $MinPagePx)
        $adjusted = $true
    }
    # クロップ後の右ページ幅 = (ImgW - rt) - gx >= MinPagePx
    if ((($ImgW - $rt) - $gx) -lt $MinPagePx) {
        $rt = [Math]::Max(0, $ImgW - $gx - $MinPagePx)
        $adjusted = $true
    }
    if (($gx - $lt) -lt $MinPagePx) { $lt = [Math]::Max(0, $gx - $MinPagePx); $adjusted = $true }
    if ((($ImgW - $rt) - $gx) -lt $MinPagePx) { $rt = [Math]::Max(0, $ImgW - $gx - $MinPagePx); $adjusted = $true }
    if ($lt + $rt -ge $ImgW - 1) {
        $lt = [Math]::Max(0, $gx - $MinPagePx)
        $rt = [Math]::Max(0, $ImgW - $gx - $MinPagePx)
        $adjusted = $true
    }
    if ($adjusted) {
        Write-FlickFitHost "         [整合] 左余白・のど・右余白の関係を自動調整しました（左=${lt}px のど=$gx 右=${rt}px／画像幅${ImgW}px）" -ForegroundColor Yellow
    }
    return @{ GutterX = $gx; LeftTrimPx = $lt; RightTrimPx = $rt }
}

# 上下トリムが画像高さを食いつぶさないようクランプ（GUI確定・Python前）
function Repair-GutterVerticalMargins {
    param([int]$ImgH, [int]$TopTrim, [int]$BottomTrim, [int]$MinBandPx = 8)
    if ($ImgH -le ($MinBandPx + 2)) { return @{ TopTrimPx = 0; BottomTrimPx = 0 } }
    $t = [Math]::Max(0, $TopTrim)
    $b = [Math]::Max(0, $BottomTrim)
    $maxSum = [Math]::Max(0, $ImgH - $MinBandPx)
    while (($t + $b) -gt $maxSum -and ($t -gt 0 -or $b -gt 0)) {
        if ($t -ge $b) { $t-- } else { $b-- }
    }
    if (($t + $b) -gt $maxSum) { $t = 0; $b = 0 }
    return @{ TopTrimPx = $t; BottomTrimPx = $b }
}
#endregion

#region GUI normalization & hashtable helpers
# 役割:
#   Hashtable の型安全な取得・GUI フラグ・余白テキストのパース。
# 主役:
#   Get-HashtableInt / Test-GuiMarginFlagTrue / Parse-MarginPxFromText
# 注意:
#   キー照合は OrdinalIgnoreCase。GUI 戻りは型が混在しやすい（文字列の "true" 等に注意）。
# 余白(px)欄の全角数字・混入文字を吸収（右だけ０になる不具合対策）
function ConvertTo-HalfWidthDigitsInString {
    param([string]$s)
    if ([string]::IsNullOrEmpty($s)) { return '' }
    $b = New-Object System.Text.StringBuilder ($s.Length)
    foreach ($ch in $s.ToCharArray()) {
        $u = [int][char]$ch
        if ($u -ge 0xFF10 -and $u -le 0xFF19) { [void]$b.Append([char]($u - 0xFF10 + 48)) }
        elseif ($u -eq 0xFF0E) { [void]$b.Append('.') }
        else { [void]$b.Append($ch) }
    }
    return $b.ToString()
}
function Parse-MarginPxFromText {
    param([string]$Text, [int]$WhenEmptyOrInvalidUse, [switch]$EmptyMeansZero)
    $t = if ($null -eq $Text) { '' } else { $Text.Trim() }
    if ($t -eq '') {
        if ($EmptyMeansZero) { return 0 }
        return [int]$WhenEmptyOrInvalidUse
    }
    $hw = ConvertTo-HalfWidthDigitsInString $t
    if ([string]::IsNullOrWhiteSpace($hw)) {
        if ($EmptyMeansZero) { return 0 }
        return [int]$WhenEmptyOrInvalidUse
    }
    $v = 0
    if (-not [int]::TryParse($hw.Trim(), [ref]$v)) {
        return [int]$WhenEmptyOrInvalidUse
    }
    return [Math]::Max(0, $v)
}
function Get-HashtableInt {
    param($Tbl, [string]$Key, [int]$Default = 0)
    if ($null -eq $Tbl) { return $Default }
    try {
        if ($Tbl -isnot [System.Collections.IDictionary]) { return $Default }
        $raw = $null
        foreach ($k in @($Tbl.Keys)) {
            if ([string]::Equals([string]$k, $Key, [StringComparison]::OrdinalIgnoreCase)) {
                $raw = $Tbl[$k]
                break
            }
        }
        if ($null -eq $raw -or $raw -eq '') { return $Default }
        return [int]$raw
    } catch {
        return $Default
    }
}
function Get-HashtableBool {
    param($Tbl, [string]$Key, [bool]$Default = $false)
    if ($null -eq $Tbl) { return $Default }
    try {
        if ($Tbl -isnot [System.Collections.IDictionary]) { return $Default }
        foreach ($k in @($Tbl.Keys)) {
            if ([string]::Equals([string]$k, $Key, [StringComparison]::OrdinalIgnoreCase)) {
                $raw = $Tbl[$k]
                if ($null -eq $raw -or $raw -eq '') { return $Default }
                if ($raw -is [bool]) { return $raw }
                $s = [string]$raw
                if ($s -match '^(?i)true$|^1$|^(?i)yes$') { return $true }
                if ($s -match '^(?i)false$|^0$|^(?i)no$') { return $false }
                return [bool]$raw
            }
        }
    } catch { return $Default }
    return $Default
}

# GUI 戻り IDictionary 用: キー無し / $null / 空文字 / 空白のみ を $null に正規化（ApplyImagePath 等）。キー照合は Get-HashtableInt と同じ OrdinalIgnoreCase
function Get-HashtableTrimmedString {
    param($Tbl, [string]$Key)
    if ($null -eq $Tbl -or $Tbl -isnot [System.Collections.IDictionary]) { return $null }
    try {
        $raw = $null
        foreach ($k in @($Tbl.Keys)) {
            if ([string]::Equals([string]$k, $Key, [StringComparison]::OrdinalIgnoreCase)) {
                $raw = $Tbl[$k]
                break
            }
        }
        if ($null -eq $raw) { return $null }
        $s = [string]$raw
        $s = $s.Trim()
        if ($s.Length -eq 0) { return $null }
        return $s
    } catch {
        return $null
    }
}

# キーが存在するかだけ（値の truthy は見ない）。ContainsKey と Keys 走査の混在を避ける用途
function Test-HashtableKeyPresent {
    param($Tbl, [string]$Key)
    if ($null -eq $Tbl -or $Tbl -isnot [System.Collections.IDictionary]) { return $false }
    foreach ($k in @($Tbl.Keys)) {
        if ([string]::Equals([string]$k, $Key, [StringComparison]::OrdinalIgnoreCase)) { return $true }
    }
    return $false
}

# ノドGUI戻り: キーが存在し、値が厳密に $true のときだけ真（未設定・$false・$null・1 文字列等は偽）。PhotosEdit / DeleteImage 用
function Test-GuiMarginFlagTrue {
    param($Tbl, [string]$Key)
    if ($null -eq $Tbl) { return $false }
    if ($Tbl -isnot [System.Collections.IDictionary]) { return $false }
    if (-not (Test-HashtableKeyPresent -Tbl $Tbl -Key $Key)) { return $false }
    $raw = $null
    foreach ($k in @($Tbl.Keys)) {
        if ([string]::Equals([string]$k, $Key, [StringComparison]::OrdinalIgnoreCase)) {
            $raw = $Tbl[$k]
            break
        }
    }
    return ($raw -eq $true)
}
#endregion

#region Effective input path
# 役割:
#   GUI 適用後の実入力パス・サイズ・参照ページ幅の解決。
# 主役:
#   Resolve-FlickFitEffectiveInputPath / Get-FlickFitEffectiveInputSizePx / Get-FlickFitReferencePageWidthFromGutter
# 注意:
#   ApplyImagePath は cvr_* 一時ファイルと元画像の切替に関わる。存在確認に失敗したら OrigPath に戻る。
# ノドGUI等で ApplyImagePath が有効ならそのパス、なければ OrigPath（片側/バランス共通の「実処理入力」入口）
function Resolve-FlickFitEffectiveInputPath {
    param(
        [Parameter(Mandatory)][string]$OrigPath,
        [System.Collections.IDictionary]$GuiResult = $null,
        [string]$ApplyImagePathKey = 'ApplyImagePath'
    )
    $p = [string]$OrigPath
    if ($null -eq $GuiResult) { return $p }
    $ap = Get-HashtableTrimmedString -Tbl $GuiResult -Key $ApplyImagePathKey
    if ($ap -and (Test-Path -LiteralPath $ap)) { return $ap }
    return $p
}

# ノドGUIで「次/前に画像切替のあと OK」→ Apply が別パスになっても、**このイテレーションで割る1枚(EntryPath)** へ固定。数値pxは表示画像幅に合わせてスケール。
function Get-FlickFitGutterGuiSplitPathLockedToEntry {
    param(
        [Parameter(Mandatory)][string]$EntryPath,
        [System.Collections.IDictionary]$GuiResult
    )
    $r = [PSCustomObject]@{ Path = $EntryPath; GuiTweak = $GuiResult; Scaled = $false }
    if ($null -eq $GuiResult) { return $r }
    $nEnt = $null; try { $nEnt = [System.IO.Path]::GetFullPath($EntryPath).TrimEnd('\') } catch { $nEnt = $EntryPath.TrimEnd('\') }
    $ap = Get-HashtableTrimmedString -Tbl $GuiResult -Key 'ApplyImagePath'
    if (-not $ap -or -not (Test-Path -LiteralPath $ap)) { return $r }
    $nAp = $null; try { $nAp = [System.IO.Path]::GetFullPath($ap).TrimEnd('\') } catch { $nAp = $ap.TrimEnd('\') }
    if ($nEnt -ieq $nAp) { return $r }
    $dAp = Get-ImageDimensions -Path $ap
    $dEn = Get-ImageDimensions -Path $EntryPath
    if ($dAp.Width -le 0 -or $dEn.Width -le 0) { return $r }
    $hT = [hashtable]@{}; foreach ($k in $GuiResult.Keys) { $hT[$k] = $GuiResult[$k] }
    $hT['ApplyImagePath'] = $EntryPath
    $s = $dEn.Width / [double]$dAp.Width
    $sH = $dEn.Height / [double][Math]::Max(1, $dAp.Height)
    $gx = Get-HashtableInt -Tbl $GuiResult -Key 'GutterX' -Default (-1)
    if ($gx -ge 0) {
        $gx2 = [int][Math]::Round($gx * $s)
        $gx2 = [Math]::Max(1, [Math]::Min($dEn.Width - 2, $gx2))
        $hT['GutterX'] = $gx2
    }
    $hT['LeftTrimPx'] = [int][Math]::Round((Get-HashtableInt -Tbl $GuiResult -Key 'LeftTrimPx') * $s)
    $hT['RightTrimPx'] = [int][Math]::Round((Get-HashtableInt -Tbl $GuiResult -Key 'RightTrimPx') * $s)
    $hT['TopTrimPx'] = [int][Math]::Round((Get-HashtableInt -Tbl $GuiResult -Key 'TopTrimPx') * $sH)
    $hT['BottomTrimPx'] = [int][Math]::Round((Get-HashtableInt -Tbl $GuiResult -Key 'BottomTrimPx') * $sH)
    if ($dEn.Width -gt 0 -and (Get-HashtableInt -Tbl $hT -Key 'GutterX' -Default (-1)) -ge 0) {
        $hT['GutterPct'] = [Math]::Max(1, [Math]::Min(99, [Math]::Round(100.0 * (Get-HashtableInt -Tbl $hT -Key 'GutterX') / [double]$dEn.Width, 2)))
    }
    $entLeafLock = Get-LiteralPathLeaf -Path $EntryPath
    $pvLeafLock = Get-LiteralPathLeaf -Path $ap
    if ($true -eq $script:FlickFitDebugStep5Verbose) {
        Write-FlickFitHost "         [注意] 別画像を表示したまま OK したため、分割はここで進めている1枚（$entLeafLock）に固定。のど・余白px を幅 $([int]$dAp.Width)→$([int]$dEn.Width) px に合わせて再スケールしました。" -ForegroundColor DarkGray
    } else {
        Write-FlickFitHost "         [参考表示] $pvLeafLock を見て設定確認 → 分割は $entLeafLock に適用" -ForegroundColor DarkCyan
    }
    return [PSCustomObject]@{ Path = $EntryPath; GuiTweak = $hT; Scaled = $true }
}

# 中央1枚型トリム: 同フォルダ内で同一 幅×高さ（px）のキー
function Get-FlickFitCenteredSingleTrimCacheKey {
    param(
        [Parameter(Mandatory)][string]$DirPath,
        [int]$W,
        [int]$H
    )
    $dn = $DirPath
    try { $dn = [System.IO.Path]::GetFullPath($DirPath) } catch { $dn = $DirPath }
    return "${dn}|${W}x${H}"
}

# 実入力パスから幅・高さ（px）。欠損時は 0。
function Get-FlickFitEffectiveInputSizePx {
    param(
        [Parameter(Mandatory)][string]$LiteralPath
    )
    $d = Get-ImageDimensions -Path $LiteralPath -ErrorAction SilentlyContinue
    $w = if ($d -and $d.Width -gt 0) { [int]$d.Width } else { 0 }
    $h = if ($d -and $d.Height -gt 0) { [int]$d.Height } else { 0 }
    return [PSCustomObject]@{ Width = $w; Height = $h }
}

# のど・左右トリムから min(左ページ幅, 右ページ幅) を RefWidthFromGutter 用に（純粋。ImgW または GutterX が不正なら 0）
function Get-FlickFitReferencePageWidthFromGutter {
    param(
        [int]$ImgW,
        [int]$GutterX,
        [int]$LeftTrimPx = 0,
        [int]$RightTrimPx = 0
    )
    if ($ImgW -le 0 -or $GutterX -le 0) { return 0 }
    $expLeft = $GutterX - $LeftTrimPx
    $expRight = $ImgW - $GutterX - $RightTrimPx
    if ($expLeft -lt 1 -or $expRight -lt 1) { return 0 }
    return [Math]::Max(1, [Math]::Min($expLeft, $expRight))
}
#endregion

#region Cache (folder gutter snapshot)
# 役割:
#   FolderGutterCache へ格納するエントリの単一形。
# 主役:
#   New-FlickFitFolderGutterCacheEntry
# 注意:
#   プロセス内キャッシュの形を固定する。ImgW/ImgH・キー名のずれは分割幅・自動ノドに波及する。
# FolderGutterCache へ入れるスナップを1形にまとめる（キー名の散在・コピペ差を減らす）
function New-FlickFitFolderGutterCacheEntry {
    param(
        [int]$GutterX,
        [double]$GutterPct,
        [int]$LeftTrimPx,
        [int]$RightTrimPx,
        [int]$TopTrimPx,
        [int]$BottomTrimPx,
        [int]$ImgW,
        [int]$ImgH,
        [double]$RefAspect = 0,
        [double]$RefWidth = 0,
        [bool]$MarginTrimWithoutSplit = $false
    )
    return @{
        GutterX      = $GutterX
        GutterPct    = [Math]::Max(1, [Math]::Min(99, [double]$GutterPct))
        LeftTrimPx   = $LeftTrimPx
        RightTrimPx  = $RightTrimPx
        TopTrimPx    = $TopTrimPx
        BottomTrimPx = $BottomTrimPx
        ImgW         = $ImgW
        ImgH         = $ImgH
        RefAspect    = $RefAspect
        RefWidth     = $RefWidth
        MarginTrimWithoutSplit = [bool]$MarginTrimWithoutSplit
    }
}
#endregion

#region Auto gutter (balanced)
# 役割:
#   連続見開きでキャッシュから自動ノドを試みる可否と理由。
# 主役:
#   Get-FlickFitBalancedAutoGutterDecision / Get-FlickFitBalancedAutoGutterReasonJa / New-FlickFitAutoGutterGuiResult
# 注意:
#   閾値・Reason 文字列はここに集約。解像度不一致・余白非0・中心ずれで GUI へ落とす。
# バランス型・split: FolderGutterCache が「余白0・中央付近ノド」のとき、ImgW/H が近い次見開きでは初回ノドGUIを開かずキャッシュから比例スケールする
function Get-FlickFitBalancedAutoGutterDecision {
    param(
        [System.Collections.IDictionary]$FolderCacheSnap,
        [int]$EffectiveW,
        [int]$EffectiveH
    )
    # 連続見開きの自動ノド許容（閾値の微調整はここだけ）
    $balAutoMaxImgWDiffPx = 24
    $balAutoMaxImgHDiffPx = 8
    $balAutoMaxGutterFromCenterPx = 8
    $balAutoMaxScaledGutterFromCenterPx = 16
    $out = [PSCustomObject]@{
        ShouldSkipGui          = $false
        Reason                 = 'no_cache'
        SuggestedGutterX       = -1
        SuggestedLeftTrimPx    = 0
        SuggestedRightTrimPx   = 0
        SuggestedTopTrimPx     = 0
        SuggestedBottomTrimPx  = 0
    }
    if ($null -eq $FolderCacheSnap -or $FolderCacheSnap -isnot [System.Collections.IDictionary]) {
        return $out
    }
    $cImgW = Get-HashtableInt -Tbl $FolderCacheSnap -Key 'ImgW' -Default 0
    $cImgH = Get-HashtableInt -Tbl $FolderCacheSnap -Key 'ImgH' -Default 0
    if ($cImgW -le 0 -or $cImgH -le 0) {
        $out.Reason = 'cache_no_dimensions'
        return $out
    }
    if ($EffectiveW -le 0 -or $EffectiveH -le 0) {
        $out.Reason = 'bad_effective_size'
        return $out
    }
    if ([Math]::Abs($EffectiveW - $cImgW) -gt $balAutoMaxImgWDiffPx -or [Math]::Abs($EffectiveH - $cImgH) -gt $balAutoMaxImgHDiffPx) {
        $out.Reason = 'img_size_mismatch'
        return $out
    }
    $lt = Get-HashtableInt -Tbl $FolderCacheSnap -Key 'LeftTrimPx' -Default 0
    $rt = Get-HashtableInt -Tbl $FolderCacheSnap -Key 'RightTrimPx' -Default 0
    $tt = Get-HashtableInt -Tbl $FolderCacheSnap -Key 'TopTrimPx' -Default 0
    $bt = Get-HashtableInt -Tbl $FolderCacheSnap -Key 'BottomTrimPx' -Default 0
    if ($lt -ne 0 -or $rt -ne 0 -or $tt -ne 0 -or $bt -ne 0) {
        $out.Reason = 'nonzero_trims'
        return $out
    }
    if (Get-HashtableBool -Tbl $FolderCacheSnap -Key 'MarginTrimWithoutSplit') {
        $out.Reason = 'margin_trim_only_cache'
        return $out
    }
    $gx = Get-HashtableInt -Tbl $FolderCacheSnap -Key 'GutterX' -Default -1
    if ($gx -lt 0) {
        $out.Reason = 'no_gutterx'
        return $out
    }
    $midC = [int][Math]::Floor($cImgW / 2.0)
    if ([Math]::Abs($gx - $midC) -gt $balAutoMaxGutterFromCenterPx) {
        $out.Reason = 'gutter_not_center'
        return $out
    }
    $gxScaled = [int]([Math]::Round($EffectiveW * [double]$gx / [double]$cImgW))
    $gxClamped = [Math]::Max(7, [Math]::Min($EffectiveW - 8, $gxScaled))
    $midE = [int][Math]::Floor($EffectiveW / 2.0)
    if ([Math]::Abs($gxClamped - $midE) -gt $balAutoMaxScaledGutterFromCenterPx) {
        $out.Reason = 'scaled_off_center'
        return $out
    }
    $out.ShouldSkipGui = $true
    $out.Reason = 'near_center_same_folder'
    $out.SuggestedGutterX = $gxClamped
    return $out
}

function Get-FlickFitBalancedAutoGutterReasonJa {
    param([string]$Reason)
    switch ($Reason) {
        'img_size_mismatch'        { return '前回見開きと解像度が異なるため確認が必要です' }
        'gutter_not_center'        { return '中心ずれの可能性があります' }
        'scaled_off_center'        { return '中心ずれの可能性があります' }
        'nonzero_trims'            { return '余白トリムの履歴があるため確認が必要です' }
        'margin_trim_only_cache'   { return '余白のみの履歴のため確認が必要です' }
        'no_gutterx'               { return 'ノド位置が未確定のため確認が必要です' }
        'bad_effective_size'       { return '有効サイズが不正なため確認が必要です' }
        'cache_no_dimensions'      { return 'キャッシュに寸法がないため確認が必要です' }
        default                    { return '' }
    }
}

function New-FlickFitAutoGutterGuiResult {
    param(
        [Parameter(Mandatory)][int]$GutterX,
        [int]$LeftTrimPx = 0,
        [int]$RightTrimPx = 0,
        [int]$TopTrimPx = 0,
        [int]$BottomTrimPx = 0,
        [bool]$MarginTrimWithoutSplit = $false
    )
    return @{
        GutterX                = $GutterX
        LeftTrimPx             = $LeftTrimPx
        RightTrimPx            = $RightTrimPx
        TopTrimPx              = $TopTrimPx
        BottomTrimPx           = $BottomTrimPx
        MarginTrimWithoutSplit = $MarginTrimWithoutSplit
        __AutoGutterBalanced   = $true
    }
}
#endregion

#region Split width param comparison
# 役割:
#   前回 OK スナップとの完全一致・±Tol 再利用のテスト。
# 主役:
#   Test-FlickFitSplitWidthParamsReuse / Test-FlickFitSplitWidthParamsIdentical
# 注意:
#   ImgW 一致と MarginTrimWithoutSplit 一致が前提。±Tol は Gutter/Trim の数値のみに適用。
# 分割幅GUI: 現在のキャッシュが「前回 OK したノド・余白」と±Tol 以内だが完全一致でないときだけ、GUI を出さず同設定で再分割（完全一致は Invoke-SplitWidthValidation 側でそのまま採用）
# ±Tol 再利用は FolderGutterCache / LastConfirmed の ImgW が同一かつ正のときのみ（別解像度・別画像への誤適用を防ぐ）
function Test-FlickFitSplitWidthParamsReuse {
    param(
        [int]$TolerancePx = 3,
        [System.Collections.IDictionary]$Current,
        [System.Collections.IDictionary]$LastConfirmed
    )
    $out = [PSCustomObject]@{ ShouldReuseLastConfirmed = $false }
    if ($null -eq $Current -or $null -eq $LastConfirmed) { return $out }
    $wi = Get-HashtableInt -Tbl $Current -Key 'ImgW' -Default 0
    $wl = Get-HashtableInt -Tbl $LastConfirmed -Key 'ImgW' -Default 0
    if ($wi -le 0 -or $wl -le 0 -or $wi -ne $wl) { return $out }
    $mc = Get-HashtableBool -Tbl $Current -Key 'MarginTrimWithoutSplit'
    $ml = Get-HashtableBool -Tbl $LastConfirmed -Key 'MarginTrimWithoutSplit'
    if ($mc -ne $ml) { return $out }
    $identical = $true
    foreach ($k in @('GutterX', 'LeftTrimPx', 'RightTrimPx', 'TopTrimPx', 'BottomTrimPx')) {
        $vc = Get-HashtableInt -Tbl $Current -Key $k -Default 0
        $vl = Get-HashtableInt -Tbl $LastConfirmed -Key $k -Default 0
        if ($vc -ne $vl) { $identical = $false }
        if ([Math]::Abs($vc - $vl) -gt $TolerancePx) { return $out }
    }
    if ($identical) { return $out }
    $out.ShouldReuseLastConfirmed = $true
    return $out
}

# 分割幅「完全一致 adopt」: ノド・余白に加え ImgW も同一必須（Test-FlickFitSplitWidthParamsReuse と同趣旨。ImgW 欠損時は false）
function Test-FlickFitSplitWidthParamsIdentical {
    param(
        [System.Collections.IDictionary]$A,
        [System.Collections.IDictionary]$B
    )
    if ($null -eq $A -or $null -eq $B) { return $false }
    $wa = Get-HashtableInt -Tbl $A -Key 'ImgW' -Default 0
    $wb = Get-HashtableInt -Tbl $B -Key 'ImgW' -Default 0
    if ($wa -le 0 -or $wb -le 0 -or $wa -ne $wb) { return $false }
    $ma = Get-HashtableBool -Tbl $A -Key 'MarginTrimWithoutSplit'
    $mb = Get-HashtableBool -Tbl $B -Key 'MarginTrimWithoutSplit'
    if ($ma -ne $mb) { return $false }
    foreach ($k in @('GutterX', 'LeftTrimPx', 'RightTrimPx', 'TopTrimPx', 'BottomTrimPx')) {
        $va = Get-HashtableInt -Tbl $A -Key $k -Default 0
        $vb = Get-HashtableInt -Tbl $B -Key $k -Default 0
        if ($va -ne $vb) { return $false }
    }
    return $true
}
#endregion

#region Gutter GUI result normalize
# 役割:
#   ノド・余白 GUI 戻り IDictionary を 1 回だけ正規化。
# 主役:
#   Normalize-GutterGuiResult
# 注意:
#   呼び出し側で二重にかけないこと。キーは OrdinalIgnoreCase で揃える。
# ノド・余白GUI戻り IDictionary を1回だけ正規化（キーがある項目のみ上書き。CoverAction のみ等は増殖しない）
function Normalize-GutterGuiResult {
    param([object]$GuiResult)
    if ($null -eq $GuiResult -or $GuiResult -isnot [System.Collections.IDictionary]) { return $null }
    $out = @{}
    foreach ($k in @($GuiResult.Keys)) {
        try { $out[[string]$k] = $GuiResult[$k] } catch {}
    }
    if (Test-HashtableKeyPresent -Tbl $GuiResult -Key 'ApplyImagePath') {
        $ap = Get-HashtableTrimmedString -Tbl $GuiResult -Key 'ApplyImagePath'
        if ($null -ne $ap) { $out['ApplyImagePath'] = $ap }
        else {
            foreach ($rk in @($out.Keys)) {
                if ([string]::Equals([string]$rk, 'ApplyImagePath', [StringComparison]::OrdinalIgnoreCase)) { [void]$out.Remove($rk); break }
            }
        }
    }
    foreach ($boolKey in @('DeleteImage', 'PhotosEdit', 'ApplyOnlyThisSpread')) {
        if (Test-HashtableKeyPresent -Tbl $GuiResult -Key $boolKey) {
            $out[$boolKey] = (Test-GuiMarginFlagTrue -Tbl $GuiResult -Key $boolKey)
        }
    }
    if (Test-HashtableKeyPresent -Tbl $GuiResult -Key 'MarginTrimWithoutSplit') {
        $out['MarginTrimWithoutSplit'] = Get-HashtableBool -Tbl $GuiResult -Key 'MarginTrimWithoutSplit'
    }
    if (Test-HashtableKeyPresent -Tbl $GuiResult -Key 'GutterX') {
        $out['GutterX'] = Get-HashtableInt -Tbl $GuiResult -Key 'GutterX' -Default (-1)
    }
    foreach ($tk in @('LeftTrimPx', 'RightTrimPx', 'TopTrimPx', 'BottomTrimPx')) {
        if (Test-HashtableKeyPresent -Tbl $GuiResult -Key $tk) {
            $out[$tk] = Get-HashtableInt -Tbl $GuiResult -Key $tk -Default 0
        }
    }
    return $out
}
#endregion

#region Decisions (split width)
# 役割:
#   分割幅・縦横比・再利用・ピクセル費の判定を集約する。
# 主役:
#   Get-FlickFitReuseDecision / Get-FlickFitSplitWidthDecision
# 注意:
#   GUI・ファイル・$script: の更新はしない。実行ルートは Invoke-SplitWidthValidation / Invoke-FlickFitSplitWidthDecision 側。
# Get-FlickFitReuseDecision の Kind（比較は常に $script:FlickFitReuseKind* 経由で typo 防止）
$script:FlickFitReuseKindUnavailable = 'Unavailable'
$script:FlickFitReuseKindExactAdopt  = 'ExactAdopt'
$script:FlickFitReuseKindTolPreset   = 'TolPreset'

# 分割幅検証: フォルダキャッシュ vs 前回OKスナップの再利用判定（Test-FlickFitSplitWidthParams* をここに集約）
function Get-FlickFitReuseDecision {
    param(
        [System.Collections.IDictionary]$CurrentCacheSnap,
        [System.Collections.IDictionary]$LastConfirmedSnap,
        [int]$ReuseConfirmedTolPx = 3
    )
    $out = [PSCustomObject]@{
        Kind           = $script:FlickFitReuseKindUnavailable
        PresetFromLast = $null
    }
    if ($null -eq $CurrentCacheSnap -or $null -eq $LastConfirmedSnap) { return $out }
    if (Test-FlickFitSplitWidthParamsIdentical -A $CurrentCacheSnap -B $LastConfirmedSnap) {
        $out.Kind = $script:FlickFitReuseKindExactAdopt
        return $out
    }
    if ($ReuseConfirmedTolPx -lt 0) { return $out }
    $reuseChk = Test-FlickFitSplitWidthParamsReuse -TolerancePx $ReuseConfirmedTolPx -Current $CurrentCacheSnap -LastConfirmed $LastConfirmedSnap
    if ($reuseChk.ShouldReuseLastConfirmed) {
        $out.Kind = $script:FlickFitReuseKindTolPreset
        $out.PresetFromLast = @{
            GutterX                = (Get-HashtableInt -Tbl $LastConfirmedSnap -Key 'GutterX')
            LeftTrimPx             = (Get-HashtableInt -Tbl $LastConfirmedSnap -Key 'LeftTrimPx')
            RightTrimPx            = (Get-HashtableInt -Tbl $LastConfirmedSnap -Key 'RightTrimPx')
            TopTrimPx              = (Get-HashtableInt -Tbl $LastConfirmedSnap -Key 'TopTrimPx')
            BottomTrimPx           = (Get-HashtableInt -Tbl $LastConfirmedSnap -Key 'BottomTrimPx')
            MarginTrimWithoutSplit = (Get-HashtableBool -Tbl $LastConfirmedSnap -Key 'MarginTrimWithoutSplit')
        }
    }
    return $out
}

# 分割幅検証の「判定のみ」（GUI・ファイル・$script: プリセット更新なし）。Invoke-SplitWidthValidation が実行を担う。
# Kind: BypassNoTarget | DimensionsPass | NeedsFollowUp
# SkipRepeatShouldAdopt / AssumeInitialGuiShouldAdopt: ゴミ幅でないときの「省略して adopt」可否（Invoke 側はこれを参照し二重計算しない）
# PixelLossSeverity: pass | warn_adopt | gui_required — 幅不足だけなら warn_adopt（GUI省略寄り）、表紙天井/目標の92%未満＋複合異常で gui_required 等
# 方針: 幅・縦横比・再利用・ピクセル費・adopt スキップの分岐は検証関数側でローカル再計算を増やさず、原則ここへ集約する。
function Get-FlickFitSplitWidthDecision {
    param(
        [string]$SplitPath1,
        [string]$SplitPath2,
        [int]$CoverWidth,
        [int]$RefWidthFromGutter,
        [int]$TolerancePx,
        [double]$RefAspect,
        [string]$GutterCacheFolderKey,
        [int]$ReuseConfirmedTolPx,
        [switch]$AssumeInitialGutterGuiPrecedesSplit,
        [bool]$SkipRepeatGuiApplyOnly,
        [string]$BackupPath,
        [string]$OrigPath
    )
    $suppressCoverBaselinePrompts = [bool]$AssumeInitialGutterGuiPrecedesSplit
    $targetMin = if ($RefWidthFromGutter -gt 0) {
        [Math]::Max(100, $RefWidthFromGutter - $TolerancePx)
    } elseif ($CoverWidth -gt 0) {
        [int][Math]::Ceiling($CoverWidth * 1.01)
    } else { 0 }

    $r = [PSCustomObject]@{
        Kind                   = 'NeedsFollowUp'
        TargetMin              = $targetMin
        W1                     = 0
        W2                     = 0
        H1                     = 0
        H2                     = 0
        WidthOk                = $false
        AspectRatioOk          = $true
        AspectReason           = ''
        ThresholdDesc          = ''
        ReuseKind              = $script:FlickFitReuseKindUnavailable
        ReusePresetFromLast    = $null
        MaxW                   = 0
        TrashCandidate         = $false
        SkipSetNewCover        = $false
        CanShowMarginGuiEarly  = $false
        DeferNewCoverPrompt     = $false
        DeferNewCoverMaxW      = 0
        NeedsGui               = $false
        CanAdopt               = $false
        CanSetNewCover         = $false
        SkipRepeatShouldAdopt  = $false
        AssumeInitialGuiShouldAdopt = $false
        PixelLossSeverity      = 'pass'
        WidthShortagePx      = 0
        WidthShortageRatio   = 1.0
        HasAspectAnomaly      = $false
        HasLargeWidthGap      = $false
        Reasons                = [string[]]@()
        GuiPromptReasonJa      = ''
    }

    if ($targetMin -le 0) {
        $r.Kind = 'BypassNoTarget'
        $r.WidthOk = $true
        $r.AspectRatioOk = $true
        $r.NeedsGui = $false
        $r.CanAdopt = $false
        $r.CanSetNewCover = $false
        return $r
    }

    $d1 = Get-ImageDimensions -Path $SplitPath1 -ErrorAction SilentlyContinue
    $d2 = Get-ImageDimensions -Path $SplitPath2 -ErrorAction SilentlyContinue
    $r.W1 = if ($d1) { $d1.Width } else { 0 }
    $r.W2 = if ($d2) { $d2.Width } else { 0 }
    $r.H1 = if ($d1) { $d1.Height } else { 0 }
    $r.H2 = if ($d2) { $d2.Height } else { 0 }
    $r.ThresholdDesc = if ($RefWidthFromGutter -gt 0) { "参照幅-${TolerancePx}px" } else { "表紙+1%" }
    $r.WidthOk = ($r.W1 -ge $targetMin -and $r.W2 -ge $targetMin)

    if ($r.H1 -gt 0 -and $r.H2 -gt 0) {
        $asp1 = [double]$r.W1 / $r.H1
        $asp2 = [double]$r.W2 / $r.H2
        $avgAsp = ($asp1 + $asp2) / 2
        if ($avgAsp -gt 0.001 -and [Math]::Abs($asp1 - $asp2) / $avgAsp -gt 0.05) {
            $r.AspectRatioOk = $false
            $r.AspectReason = "左右ページの縦横比が不一致（左=${asp1:N3} 右=${asp2:N3}）"
        } elseif ($RefAspect -gt 0.001) {
            $diff1 = [Math]::Abs($asp1 - $RefAspect) / $RefAspect
            $diff2 = [Math]::Abs($asp2 - $RefAspect) / $RefAspect
            if ($diff1 -gt 0.05 -or $diff2 -gt 0.05) {
                $r.AspectRatioOk = $false
                $r.AspectReason = "フォルダ基準の縦横比とずれ（参照=${RefAspect:N3} 左=${asp1:N3} 右=${asp2:N3}）"
            }
        }
    }

    if ($GutterCacheFolderKey -and (-not $r.WidthOk -or -not $r.AspectRatioOk)) {
        $lastSnap = $null
        if ((Get-Variable -Name 'SplitWidthLastConfirmedByFolder' -Scope Script -ErrorAction SilentlyContinue) -and $script:SplitWidthLastConfirmedByFolder) {
            $lastSnap = $script:SplitWidthLastConfirmedByFolder[$GutterCacheFolderKey]
        }
        $curSnap = $null
        if ($script:FolderGutterCache -and $script:FolderGutterCache.ContainsKey($GutterCacheFolderKey)) {
            $curSnap = $script:FolderGutterCache[$GutterCacheFolderKey]
        }
        if ($lastSnap -and $curSnap) {
            $reuseDec = Get-FlickFitReuseDecision -CurrentCacheSnap $curSnap -LastConfirmedSnap $lastSnap -ReuseConfirmedTolPx $ReuseConfirmedTolPx
            $r.ReuseKind = $reuseDec.Kind
            $r.ReusePresetFromLast = $reuseDec.PresetFromLast
        }
    }

    $r.MaxW = [Math]::Max($r.W1, $r.W2)
    $r.CanShowMarginGuiEarly = ($BackupPath -and (Test-Path -LiteralPath $BackupPath)) -or ($OrigPath -and (Test-Path -LiteralPath $OrigPath))
    if (-not $r.WidthOk) {
        $trashAbsPx = 40
        $trashRatio = 0.12
        $r.TrashCandidate = ($r.MaxW -gt 0 -and ($r.MaxW -le $trashAbsPx -or $r.MaxW -lt ($targetMin * $trashRatio)))
        if ($r.TrashCandidate) { $r.SkipSetNewCover = $true }
        if ($CoverWidth -gt 0 -and -not $r.SkipSetNewCover -and -not $suppressCoverBaselinePrompts) {
            if ($r.MaxW -gt 0 -and $r.MaxW -lt $CoverWidth) {
                if ($r.CanShowMarginGuiEarly) {
                    $r.DeferNewCoverPrompt = $true
                    $r.DeferNewCoverMaxW = $r.MaxW
                } else {
                    $r.CanSetNewCover = $true
                }
            }
        }
    }

    $skipRepeatAdopt = $false
    if ($SkipRepeatGuiApplyOnly -and (-not $r.WidthOk -or -not $r.AspectRatioOk) -and $targetMin -gt 0) {
        $maxWChk = $r.MaxW
        $trashSkipRepeat = ($maxWChk -gt 0 -and ($maxWChk -le 40 -or $maxWChk -lt ($targetMin * 0.12)))
        if (-not $trashSkipRepeat) { $skipRepeatAdopt = $true }
    }
    $reuseExactAdopt = ($r.ReuseKind -eq $script:FlickFitReuseKindExactAdopt)
    $autoAdopt = $false
    if ((Get-Variable -Name OneSidedSplitWidthAutoAdopt -Scope Script -ErrorAction SilentlyContinue) -and $script:OneSidedSplitWidthAutoAdopt) { $autoAdopt = $true }
    $assumeAdopt = $false
    if ($AssumeInitialGutterGuiPrecedesSplit -and (-not $r.WidthOk -or -not $r.AspectRatioOk) -and $targetMin -gt 0) {
        $maxWGuiSkip = $r.MaxW
        $trashGuiSkip = ($maxWGuiSkip -gt 0 -and ($maxWGuiSkip -le 40 -or $maxWGuiSkip -lt ($targetMin * 0.12)))
        if (-not $trashGuiSkip) { $assumeAdopt = $true }
    }
    $r.CanAdopt = ($skipRepeatAdopt -or $reuseExactAdopt -or $autoAdopt -or $assumeAdopt)
    $r.SkipRepeatShouldAdopt = $skipRepeatAdopt
    $r.AssumeInitialGuiShouldAdopt = $assumeAdopt

    $hasAspectAnomaly = -not $r.AspectRatioOk
    $wgap = [Math]::Abs($r.W1 - $r.W2)
    $r.HasLargeWidthGap = ($wgap -gt 24)
    $r.HasAspectAnomaly = $hasAspectAnomaly
    $r.WidthShortagePx = if ($targetMin -gt 0) { [Math]::Max(0, $targetMin - $r.MaxW) } else { 0 }
    $r.WidthShortageRatio = if ($targetMin -gt 0) { [Math]::Round([double]$r.MaxW / [double]$targetMin, 4) } else { 1.0 }
    $coverThresholdPx = if ($CoverWidth -gt 0) { [int][Math]::Ceiling($CoverWidth * 1.01) } else { 0 }
    $belowCoverCeiling = ($coverThresholdPx -gt 0 -and $r.MaxW -gt 0 -and $r.MaxW -lt $coverThresholdPx)
    $physicalVsTarget = ($targetMin -gt 0 -and $r.MaxW -gt 0 -and $r.MaxW -lt [Math]::Floor($targetMin * 0.92))
    if ($r.WidthOk -and $r.AspectRatioOk) {
        $r.PixelLossSeverity = 'pass'
        $r.Kind = 'DimensionsPass'
        $r.NeedsGui = $false
    } elseif ($r.WidthOk -and -not $r.AspectRatioOk) {
        $r.PixelLossSeverity = 'gui_required'
        $r.Kind = 'NeedsFollowUp'
        $pixelNeedsGui = $true
        $r.NeedsGui = $pixelNeedsGui -and -not ($r.CanAdopt -or ($r.ReuseKind -eq $script:FlickFitReuseKindTolPreset))
    } elseif ($physicalVsTarget -or $belowCoverCeiling) {
        if ($hasAspectAnomaly -or $r.HasLargeWidthGap) {
            $r.PixelLossSeverity = 'gui_required'
        } else {
            $r.PixelLossSeverity = 'warn_adopt'
        }
        $r.Kind = 'NeedsFollowUp'
        $pixelNeedsGui = ($r.PixelLossSeverity -eq 'gui_required')
        $r.NeedsGui = $pixelNeedsGui -and -not ($r.CanAdopt -or ($r.ReuseKind -eq $script:FlickFitReuseKindTolPreset))
    } elseif (-not $hasAspectAnomaly -and -not $r.HasLargeWidthGap) {
        $r.PixelLossSeverity = 'warn_adopt'
        $r.Kind = 'NeedsFollowUp'
        $r.NeedsGui = $false
    } else {
        $r.PixelLossSeverity = 'gui_required'
        $r.Kind = 'NeedsFollowUp'
        $pixelNeedsGui = $true
        $r.NeedsGui = $pixelNeedsGui -and -not ($r.CanAdopt -or ($r.ReuseKind -eq $script:FlickFitReuseKindTolPreset))
    }

    $reasonList = [System.Collections.Generic.List[string]]::new()
    if (-not $r.WidthOk) { [void]$reasonList.Add('width_below_threshold') }
    if (-not $r.AspectRatioOk -and $r.AspectReason) { [void]$reasonList.Add(('aspect:' + $r.AspectReason)) }
    if ($r.ReuseKind -ne $script:FlickFitReuseKindUnavailable) { [void]$reasonList.Add(('reuse:' + [string]$r.ReuseKind)) }
    if ($r.DeferNewCoverPrompt) { [void]$reasonList.Add('defer_set_new_cover_prompt') }
    if ($r.CanSetNewCover) { [void]$reasonList.Add('can_set_new_cover_immediate') }
    if ($r.PixelLossSeverity -ne 'pass') { [void]$reasonList.Add(('pixel_loss:' + $r.PixelLossSeverity)) }
    $r.Reasons = @($reasonList.ToArray())
    if ($r.NeedsGui) {
        $lsR = $null
        $csR = $null
        if ($GutterCacheFolderKey) {
            if ((Get-Variable -Name 'SplitWidthLastConfirmedByFolder' -Scope Script -ErrorAction SilentlyContinue) -and $script:SplitWidthLastConfirmedByFolder -and $script:SplitWidthLastConfirmedByFolder.ContainsKey($GutterCacheFolderKey)) {
                $lsR = $script:SplitWidthLastConfirmedByFolder[$GutterCacheFolderKey]
            }
            if ($script:FolderGutterCache -and $script:FolderGutterCache.ContainsKey($GutterCacheFolderKey)) { $csR = $script:FolderGutterCache[$GutterCacheFolderKey] }
        }
        if (-not $r.WidthOk -and -not $r.AspectRatioOk) {
            $r.GuiPromptReasonJa = '幅不足と縦横比ずれのため確認が必要です'
        } elseif (-not $r.WidthOk) {
            $r.GuiPromptReasonJa = '横サイズが基準未満のため確認が必要です'
        } elseif (-not $r.AspectRatioOk) {
            $r.GuiPromptReasonJa = '縦横比のずれのため確認が必要です'
        } elseif ($r.PixelLossSeverity -eq 'gui_required') {
            $r.GuiPromptReasonJa = 'ピクセル不足や複合条件のため確認が必要です'
        } elseif ($r.ReuseKind -eq $script:FlickFitReuseKindUnavailable -and $lsR -and $csR) {
            $r.GuiPromptReasonJa = '前回設定を安全に流用できません'
        } else {
            $r.GuiPromptReasonJa = '分割結果の確認が必要です'
        }
    }
    return $r
}
#endregion

#region Python bridge (crop GUI margins)
# 役割:
#   ノド・余白GUIで確定したトリムを Python の crop_gui_margins で適用する。
# 主役:
#   Invoke-PythonCropGuiMargins
# 注意:
#   WorkTrimSplitPy と入力画像が実在すること。戻りは連結文字列（ERROR: を grep する呼び出し元あり）。
function Invoke-PythonCropGuiMargins {
    param(
        [Parameter(Mandatory)][string]$WorkTrimSplitPy,
        [Parameter(Mandatory)][string]$ImagePath,
        [bool]$RightBinding,
        [int]$LeftTrim,
        [int]$TopTrim,
        [int]$RightTrim,
        [int]$BottomTrim
    )
    if (-not $WorkTrimSplitPy -or -not (Test-Path -LiteralPath $WorkTrimSplitPy) -or -not $ImagePath -or -not (Test-Path -LiteralPath $ImagePath)) { return "ERROR:bad_args" }
    if (($true -eq $script:FlickFitDebugPythonRoute) -and -not ($true -eq $script:FlickFitObsDisable)) {
        $ts = [System.IO.Path]::GetFileName($WorkTrimSplitPy)
        Write-FlickFitHost "[PyRoute] caller=Invoke-PythonCropGuiMargins mode=crop_gui_margins script=$ts input=$ImagePath lt=$LeftTrim tt=$TopTrim rt=$RightTrim bt=$BottomTrim" -ForegroundColor DarkCyan
    }
    $rb = $RightBinding.ToString()
    $rawPy = & $script:PythonExe $WorkTrimSplitPy $ImagePath $rb "crop_gui_margins" "-" $LeftTrim $TopTrim $RightTrim $BottomTrim 2>&1
    $joined = ($rawPy | ForEach-Object { "$_" }) -join ""
    if (($joined -match '(?i)ERROR:') -and -not ($true -eq $script:FlickFitObsDisable)) {
        Write-FlickFitWarning "[PyRoute] Invoke-PythonCropGuiMargins output indicates ERROR: input=$ImagePath"
    }
    return $joined
}
#endregion

#region GUI helpers (margin GUI)
# 役割:
#   余白GUIで削除された画像パスを処理リストから除外する。
# 主役:
#   Update-ImgsAfterMarginGui
# 注意:
#   DeletedImagePaths のみ見る。無ければ Imgs をそのまま返す（副作用なし）。
# ノド・余白GUIで削除されたパスを $imgs リストから除く（複数枚GUI内削除対応）
function Update-ImgsAfterMarginGui {
    param(
        [AllowEmptyCollection()][array]$Imgs,
        [object]$GuiResult
    )
    if ($null -eq $GuiResult -or $GuiResult -isnot [System.Collections.IDictionary]) { return $Imgs }
    if (-not $GuiResult.ContainsKey('DeletedImagePaths')) { return $Imgs }
    $raw = $GuiResult['DeletedImagePaths']
    if ($null -eq $raw) { return $Imgs }
    $paths = @($raw | ForEach-Object { [string]$_ } | Where-Object { $_ })
    if ($paths.Count -eq 0) { return $Imgs }
    $set = [System.Collections.Generic.HashSet[string]]::new([StringComparer]::OrdinalIgnoreCase)
    foreach ($p in $paths) { [void]$set.Add($p) }
    return @($Imgs | Where-Object { -not $set.Contains($_.FullName) })
}

# 次/前でプレビューした画像と混ざらないよう、当イテレーションの $EntryPath へ戻す（$imgs[$imgIdx] 再同期は上より削除で index がズレると別ファイルを指す）
function Get-FlickFitGutterEntryAfterNavGui {
    param(
        [Parameter(Mandatory)][string]$EntryPath,
        [string]$EntryName = '',
        [object]$GuiResult
    )
    if (-not $EntryPath) { return $null }
    if ($null -ne $GuiResult -and $GuiResult -is [System.Collections.IDictionary] -and $GuiResult.ContainsKey('DeletedImagePaths')) {
        $raw = $GuiResult['DeletedImagePaths']
        if ($raw) {
            $ne = $null; try { $ne = [System.IO.Path]::GetFullPath($EntryPath) } catch { $ne = $EntryPath }
            foreach ($d in @($raw)) {
                if (-not $d) { continue }
                $nd = $null; try { $nd = [System.IO.Path]::GetFullPath([string]$d) } catch { $nd = [string]$d }
                if ($nd -ieq $ne) { return $null }
            }
        }
    }
    if (-not (Test-Path -LiteralPath $EntryPath)) { return $null }
    $fn = if ($EntryName) { $EntryName } else { [System.IO.Path]::GetFileName($EntryPath) }
    $ex = [System.IO.Path]::GetExtension($EntryPath)
    if ($ex) { $ex = $ex.ToLower() } else { $ex = '' }
    return [PSCustomObject]@{ OrigPath = $EntryPath; ImgName = $fn; Ext = $ex }
}

# STEP5: GUI 直後 ERROR の再試行カウンタ。Set-StrictMode 下でも、未定義 $script: を参照しない。
function Ensure-FlickFitStep5ErrorRetryCount {
    if (-not (Get-Variable -Scope Script -Name Step5ErrorRetryCount -ErrorAction SilentlyContinue)) {
        $script:Step5ErrorRetryCount = @{}
    }
}
# 同一エントリの表記揺れ（\ vs /、末尾\）で別キーにならないよう正規化
function Get-FlickFitStep5ErrorRetryKey {
    param([string]$Path)
    if ([string]::IsNullOrWhiteSpace($Path)) { return '' }
    try {
        if (Test-Path -LiteralPath $Path) {
            return [string]([System.IO.Path]::GetFullPath($Path)).TrimEnd('\')
        }
        return [string]([System.IO.Path]::GetFullPath($Path)).TrimEnd('\')
    } catch {
        return ([string]$Path).TrimEnd('\')
    }
}
# 先頭英字・コロン正規化の違いでも拾う（"ERROR:..." 以外のプレフィックス混線対策に -cmatch 併用）
function Test-FlickFitStep5StringLooksLikeResultError {
    param([string]$S)
    if ($null -eq $S) { return $false }
    $s = $S.Trim()
    if ($s -like 'ERROR:*') { return $true }
    if ($s -cmatch '^(?i)ERROR:') { return $true }
    # 先頭が改行・stderr 混在でも ERROR: を含めば再試行扱い（外側 $result 経路と揃える）
    if ($s -match '(?i)\bERROR\s*:') { return $true }
    return $false
}
# 1〜2 回目 retry、3 回目 fallback（MaxRetryBeforeFallback=2 → n=3 のとき n -gt 2）
# 抑止: $script:FlickFitDebugStep5Retry = $false
function Get-FlickFitStep5RetryAction {
    param(
        [string]$Path,
        [int]$MaxRetryBeforeFallback = 2
    )
    Ensure-FlickFitStep5ErrorRetryCount
    $key = Get-FlickFitStep5ErrorRetryKey -Path $Path
    if ([string]::IsNullOrWhiteSpace($key) -and -not [string]::IsNullOrWhiteSpace($Path)) {
        $key = ([string]$Path).Trim().TrimEnd('\')
    }
    if ([string]::IsNullOrWhiteSpace($key)) {
        $key = 'STEP5_RETRY_KEY_EMPTY'
        if (-not ($true -eq $script:FlickFitObsDisable)) { Write-FlickFitWarning "[STEP5RetryDbg] キー空のため仮キーで加算（Path 不整合の可能性）" }
    }
    $n = 0
    if ($script:Step5ErrorRetryCount.ContainsKey($key)) { try { $n = [int]$script:Step5ErrorRetryCount[$key] } catch { $n = 0 } }
    $n++
    $script:Step5ErrorRetryCount[$key] = $n
    $act = if ($n -gt $MaxRetryBeforeFallback) { 'fallback' } else { 'retry' }
    $showStep5RetryDbg = $true
    if (Get-Variable -Name FlickFitDebugStep5Retry -Scope Script -ErrorAction SilentlyContinue) { if ($false -eq $script:FlickFitDebugStep5Retry) { $showStep5RetryDbg = $false } }
    if ($showStep5RetryDbg) {
        Write-FlickFitHost ("[STEP5RetryDbg] key={0}" -f $key) -ForegroundColor DarkYellow
        Write-FlickFitHost ("[STEP5RetryDbg] count={0}" -f $n) -ForegroundColor DarkYellow
        Write-FlickFitHost ("[STEP5RetryDbg] action={0}" -f $act) -ForegroundColor DarkYellow
    }
    if ($n -gt $MaxRetryBeforeFallback) {
        [void]$script:Step5ErrorRetryCount.Remove($key)
        return 'fallback'
    }
    return 'retry'
}

# ラベル例: horiz-iter / pc-before / pc-after / os-before / cst-after / bal-after / idx-before-main-inc
function Write-FlickFitStep5EntryDebug {
    param(
        [Parameter(Mandatory)][string]$Label,
        [string]$EntryPath = '',
        [string]$PreviewPath = '',
        [string]$ApplyPath = '',
        [int]$ImgIdx = -1,
        [object]$GuiResult = $null,
        [int]$ImgsCount = -1
    )
    if (-not ($true -eq $script:FlickFitDebugStep5Entry)) { return }
    $pv = $PreviewPath
    if ((-not $pv) -and $null -ne $GuiResult -and $GuiResult -is [System.Collections.IDictionary]) {
        $ap0 = Get-HashtableTrimmedString -Tbl $GuiResult -Key 'ApplyImagePath'
        if ($ap0) { $pv = $ap0 }
    }
    if (-not $pv) { $pv = '-' }
    $ent = if ($EntryPath) { $EntryPath } else { '-' }
    $aply = if ($ApplyPath) { $ApplyPath } else { '-' }
    $ni = if ($ImgsCount -ge 0) { [string]$ImgsCount } else { '-' }
    Write-FlickFitHost ("[STEP5EntryDbg] {0} entry={1} preview={2} apply={3} imgIdx={4} imgs={5}" -f $Label, $ent, $pv, $aply, $ImgIdx, $ni) -ForegroundColor Magenta
}
#endregion

#region GUI: Gutter & margin (WinForms)
# 役割:
#   ノド・左右余白・回転・表紙確認などを WinForms で編集し、後続処理へ渡す。
# 主役:
#   Show-GutterMarginSetGui
# 注意:
#   単一の大型関数。GDI+/WinForms 状態・$script: スコープ変数に依存（UI スレッド前提）。
# ノド＋左右余白をGUIで指定（結果を基準ページとして後続に適用）
# AllImagePaths指定時: 次画像/前画像ボタンで他画像でも余白を検証可能。OK時は基準画像の設定で処理（基準は削除に応じて更新可）
function Show-GutterMarginSetGui {
    param(
        [string]$ImagePath,
        [string]$Title = "ノドと余白の設定 - 基準ページとして後続に適用",
        [string[]]$AllImagePaths = $null,  # 同フォルダの画像一覧（ナビゲーション用）。省略時は次/前ボタンなし
        [switch]$CoverConfirmMode,        # 表紙確認: 追加ボタンと CoverAction を戻り値に付与
        [switch]$OkAppliesToCurrentView,  # OK 時の Apply 対象を「現在表示中の画像」にする（表紙プレビューとナビの整合用）
        [string]$OriginalImagePath = "",  # トリミング前の元画像パス（CoverConfirmMode 時: プレビュー切替・フォト起動用）
        [switch]$SplitWidthReviewMode,    # 互換用（未使用。分割幅確認は通常ノドGUI＋ValidationSummaryTextに統一）
        [ValidateSet('Main', 'Detail')]
        [string]$SplitWidthReviewKind = 'Main',
        [string]$ValidationSummaryText = '',  # 分割幅警告など（複数行）
        [switch]$ShowApplyThisPageOnlyButton  # OK 以外に「このページのみで採用」（フォルダキャッシュを更新しないフラグを付与）
    )
    if (-not $ImagePath -or -not (Test-Path -LiteralPath $ImagePath)) { return $null }
    if ($SplitWidthReviewMode -and $CoverConfirmMode) { $SplitWidthReviewMode = $false }
    $script:guiMarginSplitWidthReviewResult = $null
    $script:guiMarginApplyOnlyThisPage = $false
    $script:guiMarginRotationMode = $false
    # Paint/マウスイベントは関数ローカルの $nudRot が見えないことがある → 角度は script スコープで保持
    $script:guiMarginRotDeg = 0.0
    # 回転枠幾何は Modules\GutterMarginRotationLayout.ps1（Load-Modules 漏れ時の保険）。見つからなくても gmRotFrameGeom 内蔵フォールバックで動作する。
    if (-not (Get-Command Get-GmRotFrameGeometry -ErrorAction SilentlyContinue)) {
        $gmlPath = $null
        if ($PSScriptRoot) { $gmlPath = Join-Path $PSScriptRoot 'Modules\GutterMarginRotationLayout.ps1' }
        if ((-not $gmlPath) -or -not (Test-Path -LiteralPath $gmlPath)) {
            try {
                $sf = $MyInvocation.MyCommand.ScriptBlock.File
                if ($sf) { $gmlPath = Join-Path (Split-Path -Parent $sf) 'Modules\GutterMarginRotationLayout.ps1' }
            } catch { }
        }
        if ($gmlPath -and (Test-Path -LiteralPath $gmlPath)) { try { . $gmlPath } catch { } }
    }
    $dims = Get-ImageDimensions -Path $ImagePath
    $imgW = $dims.Width
    $imgH = $dims.Height
    if ($imgW -le 0 -or $imgH -le 0) { return $null }
    $baseImagePath = $ImagePath
    $baseImgW = $imgW
    $baseImgH = $imgH
    $navList = [System.Collections.Generic.List[string]]::new()
    $baseIdx = 0
    if ($AllImagePaths -and $AllImagePaths.Count -gt 0) {
        foreach ($ap in $AllImagePaths) {
            if (-not $ap -or -not (Test-Path -LiteralPath $ap)) { continue }
            $rp = (Resolve-Path -LiteralPath $ap -ErrorAction SilentlyContinue).Path
            if ($rp) { [void]$navList.Add($rp) }
        }
        $imgPathNorm = (Resolve-Path -LiteralPath $ImagePath -ErrorAction SilentlyContinue).Path
        for ($i = 0; $i -lt $navList.Count; $i++) {
            if ($imgPathNorm -and [string]::Equals($navList[$i], $imgPathNorm, [StringComparison]::OrdinalIgnoreCase)) { $baseIdx = $i; break }
        }
    }
    $deletedInSession = [System.Collections.Generic.List[string]]::new()
    Add-Type -AssemblyName System.Windows.Forms -ErrorAction Stop
    Add-Type -AssemblyName System.Drawing -ErrorAction Stop
    try {
        if (-not ('GmMarginRotOrangeOverlayPanelV2' -as [type])) {
            Add-Type -ReferencedAssemblies System.Windows.Forms, System.Drawing -ErrorAction Stop -TypeDefinition @'
using System;
using System.Drawing;
using System.Windows.Forms;
public class GmMarginRotOrangeOverlayPanelV2 : Panel {
    public GmMarginRotOrangeOverlayPanelV2() {
        SetStyle(ControlStyles.AllPaintingInWmPaint | ControlStyles.OptimizedDoubleBuffer | ControlStyles.ResizeRedraw | ControlStyles.SupportsTransparentBackColor, true);
        DoubleBuffered = true;
        TabStop = false;
        BackColor = Color.Transparent;
    }
}
'@
        }
    } catch { }
    $form = New-Object System.Windows.Forms.Form
    $form.Text = $Title
    $form.Size = New-Object System.Drawing.Size(1140, 840)
    $form.StartPosition = "CenterScreen"
    $form.FormBorderStyle = "Sizable"
    $form.MinimumSize = New-Object System.Drawing.Size(860, 620)
    $imgPanel = New-Object System.Windows.Forms.TableLayoutPanel
    $imgPanel.Dock = "Fill"
    $imgPanel.ColumnCount = 1
    $imgPanel.RowCount = 1
    $imgPanel.BackColor = [System.Drawing.SystemColors]::Control
    $imgPanel.Padding = New-Object System.Windows.Forms.Padding(4, 6, 4, 6)
    $pbHost = New-Object System.Windows.Forms.Panel
    $pbHost.Dock = "Fill"
    # 「黒い枠線の内側」に上下の余裕を作るため、枠線は pbHost に持たせる（PictureBox は枠なし）
    $pbHost.BorderStyle = "FixedSingle"
    # 横は控えめ・縦は緑線ドラッグの余白も確保（ただし画像が小さく見えすぎないよう控えめに）
    $pbHost.Padding = New-Object System.Windows.Forms.Padding(4, 24, 4, 24)
    $pbHost.BackColor = [System.Drawing.SystemColors]::Control
    $scrollGm = New-Object System.Windows.Forms.Panel
    $scrollGm.Dock = "Fill"
    $scrollGm.AutoScroll = $true
    $scrollGm.TabStop = $true
    $scrollGm.BackColor = $pbHost.BackColor
    # pb を直接 scrollGm に置くと、レイアウトが子 Bounds と AutoScrollMinSize を不整合に足し合わせバー範囲が異常になる環境がある → 文書サイズ＝この Panel の Size のみでスクロールさせる
    $gmCanvas = New-Object System.Windows.Forms.Panel
    $gmCanvas.Location = New-Object System.Drawing.Point(0, 0)
    $gmCanvas.Margin = New-Object System.Windows.Forms.Padding(0)
    $gmCanvas.Padding = New-Object System.Windows.Forms.Padding(0)
    $gmCanvas.TabStop = $false
    $gmCanvas.BackColor = $scrollGm.BackColor
    $gmRotOrangeOverlay = $null
    $pb = New-Object System.Windows.Forms.PictureBox
    $pb.Location = New-Object System.Drawing.Point(0, 0)
    $pb.Size = New-Object System.Drawing.Size(400, 300)
    $pb.SizeMode = [System.Windows.Forms.PictureBoxSizeMode]::StretchImage
    $pb.BorderStyle = "None"
    $pb.BackColor = [System.Drawing.Color]::FromArgb(176, 190, 197)
    $script:guiMarginImgW = $imgW
    $script:guiMarginImgH = $imgH
    $script:guiMarginCurrentIdx = $baseIdx
    $script:guiMarginZoom = 1.0
    $imgMs = $null
    try {
        $imgMs = New-Object System.IO.MemoryStream(,([System.IO.File]::ReadAllBytes((Resolve-Path -LiteralPath $ImagePath).Path)))
        $img = [System.Drawing.Image]::FromStream($imgMs)
        $pb.Image = $img
        try {
            $bf = [System.Reflection.BindingFlags]::NonPublic -bor [System.Reflection.BindingFlags]::Instance
            $setStyleMethod = [System.Windows.Forms.Control].GetMethod("SetStyle", $bf, $null, [type[]]@([System.Windows.Forms.ControlStyles], [bool]), $null)
            if ($null -ne $setStyleMethod) {
                [void]$setStyleMethod.Invoke($pb, @([System.Windows.Forms.ControlStyles]::AllPaintingInWmPaint, $true))
                [void]$setStyleMethod.Invoke($pb, @([System.Windows.Forms.ControlStyles]::OptimizedDoubleBuffer, $true))
            }
            $dblProp = [System.Windows.Forms.Control].GetProperty("DoubleBuffered", [System.Reflection.BindingFlags]::NonPublic -bor [System.Reflection.BindingFlags]::Instance)
            if ($null -ne $dblProp) {
                $dblProp.SetValue($pb, $true, $null)
                $dblProp.SetValue($gmCanvas, $true, $null)
                $dblProp.SetValue($scrollGm, $true, $null)
            }
        } catch { }
    } catch {
        if ($imgMs) { try { $imgMs.Dispose() } catch {}; $imgMs = $null }
        $form.Dispose()
        return $null
    }
    # イベントハンドラは別スコープのため、プレビュー状態は参照型で保持しないと Active/Bmp が更新されない
    $rotPrev = @{ Active = $false; Bmp = $null; Snap0 = $null }
    # トリミング前の元画像を事前ロード（CoverConfirmMode 時のプレビュー切替・フォト起動用）
    $guiOriginalPath = ""
    $guiOriginalMs   = $null
    $guiOriginalImg  = $null
    $guiOriginalImgW = 0
    $guiOriginalImgH = 0
    $script:guiViewingOriginal = $false
    if ($CoverConfirmMode -and $OriginalImagePath -and (Test-Path -LiteralPath $OriginalImagePath)) {
        try {
            $absOrig  = (Resolve-Path -LiteralPath $OriginalImagePath -ErrorAction Stop).Path
            $absImage = (Resolve-Path -LiteralPath $ImagePath -ErrorAction SilentlyContinue).Path
            if (-not [string]::Equals($absOrig, $absImage, [StringComparison]::OrdinalIgnoreCase)) {
                $guiOriginalMs  = New-Object System.IO.MemoryStream(,([System.IO.File]::ReadAllBytes($absOrig)))
                $guiOriginalImg = [System.Drawing.Image]::FromStream($guiOriginalMs)
                $guiOriginalPath = $absOrig
                $guiOriginalImgW = $guiOriginalImg.Width
                $guiOriginalImgH = $guiOriginalImg.Height
            }
        } catch {
            $guiOriginalMs  = $null
            $guiOriginalImg = $null
            $guiOriginalPath = ""
            $guiOriginalImgW = 0
            $guiOriginalImgH = 0
        }
    }
    $barWidth = 3
    # 緑の余白枠は Paint で 2px（上下と左右で同じ太さ）。ノド・左右バーは3px表示＋広い当たり判定で掴みやすくする
    $gmHitHalfW = 52
    $gmHitHalfH = {
        param([double]$scale)
        $h = [Math]::Max(64, [int][Math]::Ceiling(52 * $scale))
        if ($h -gt 130) { $h = 130 }
        return $h
    }
    # StretchImage: 横は pbW/iw、縦は pbH/ih（アスペクトと ceil 差で ScaleX≠ScaleY になり得る）。Y 座標・緑線は必ず ScaleY を使う
    $calcGmLayout = {
        param($pbCtrl, [int]$iw0, [int]$ih0)
        $pbW = [double]$pbCtrl.ClientSize.Width
        $pbH = [double]$pbCtrl.ClientSize.Height
        if ($pbW -lt 4 -or $pbH -lt 4 -or $iw0 -le 0 -or $ih0 -le 0) {
            return @{ Scale = 0.001; ScaleX = 0.001; ScaleY = 0.001; OffX = 0.0; OffY = 0.0; DispW = 1.0; DispH = 1.0 }
        }
        $scX = $pbW / [double]$iw0
        $scY = $pbH / [double]$ih0
        return @{ Scale = $scX; ScaleX = $scX; ScaleY = $scY; OffX = 0.0; OffY = 0.0; DispW = $pbW; DispH = $pbH }
    }
    $bar = New-Object System.Windows.Forms.Panel
    $bar.Width = $barWidth
    $bar.BackColor = [System.Drawing.Color]::FromArgb(255, 0, 0)
    $bar.Cursor = [System.Windows.Forms.Cursors]::SizeWE
    $pb.Controls.Add($bar)
    $barLeft = New-Object System.Windows.Forms.Panel
    $barLeft.Width = $barWidth
    $barLeft.BackColor = [System.Drawing.Color]::FromArgb(0, 120, 215)
    $barLeft.Cursor = [System.Windows.Forms.Cursors]::SizeWE
    $pb.Controls.Add($barLeft)
    $barRight = New-Object System.Windows.Forms.Panel
    $barRight.Width = $barWidth
    $barRight.BackColor = [System.Drawing.Color]::FromArgb(0, 120, 215)
    $barRight.Cursor = [System.Windows.Forms.Cursors]::SizeWE
    $pb.Controls.Add($barRight)
    $barTop = New-Object System.Windows.Forms.Panel
    $barTop.Height = 1
    $barTop.Width = 1
    $barTop.Visible = $false
    $barTop.TabStop = $false
    $pb.Controls.Add($barTop)
    $barBottom = New-Object System.Windows.Forms.Panel
    $barBottom.Height = 1
    $barBottom.Width = 1
    $barBottom.Visible = $false
    $barBottom.TabStop = $false
    $pb.Controls.Add($barBottom)
    # 上下ヒットは PictureBox＋青バー経由。緑は PictureBox.Paint。オレンジ枠は gmCanvas 上の透過オーバーレイ（画像外の線も描ける）
    $halfOrig = [int]($imgW / 2)
    $script:gutterImgX = $halfOrig
    $script:gutterDragging = $false
    $script:leftTrimPx = 0
    $script:rightTrimPx = 0
    $script:topTrimPx = 0
    $script:bottomTrimPx = 0
    $script:leftBarDragging = $false
    $script:rightBarDragging = $false
    $script:topBarDragging = $false
    $script:bottomBarDragging = $false
    $script:gmUiSpecifyGutter = $true
    $reviewTopPad = 0
    if (-not [string]::IsNullOrWhiteSpace($ValidationSummaryText) -and -not $CoverConfirmMode) { $reviewTopPad = 90 }
    $yRS = $reviewTopPad
    # 下パネル内の縦位置（サイズ3行・チェック2行・ヒント折り返し・余白・ノド1行・表紙用2段ボタンが重ならないよう間隔を確保。横幅はフォーム幅内で折り返し）
    $gmPadL = 20
    $gmLblMaxW = 640
    $gmRotX = 700
    $gmYSize = 6 + $yRS
    $gmYChk = 58 + $yRS
    $gmYHint = 106 + $yRS
    $gmYRow1 = 174 + $yRS
    # 余白4項目＋回転モード＋注記は同一行のため、旧2段目を廃止してボタン行を詰める
    $gmYBtn = 204 + $yRS
    # 表紙2段目ボタン: 主行ボタン列の直下
    $gmYCov2 = 240 + $yRS
    $lblSizeInfo = New-Object System.Windows.Forms.Label
    $lblSizeInfo.AutoSize = $true
    $lblSizeInfo.MaximumSize = New-Object System.Drawing.Size($gmLblMaxW, 0)
    $lblSizeInfo.Location = New-Object System.Drawing.Point($gmPadL, $gmYSize)
    $lblSizeInfo.Text = "左サイズ 0 px  右サイズ 0 px"
    $lblRotDeg = New-Object System.Windows.Forms.Label
    $lblRotDeg.Text = "角度°"
    $lblRotDeg.AutoSize = $true
    $lblRotDeg.Location = New-Object System.Drawing.Point($gmRotX, ($gmYSize + 2))
    $lblRotDeg.Visible = $false
    $nudRot = New-Object System.Windows.Forms.NumericUpDown
    $nudRot.Location = New-Object System.Drawing.Point(($gmRotX + 48), $gmYSize)
    $nudRot.Size = New-Object System.Drawing.Size(76, 24)
    $nudRot.DecimalPlaces = 2
    $nudRot.Minimum = -45
    $nudRot.Maximum = 45
    $nudRot.Increment = 0.5
    $nudRot.Value = 0
    $script:guiMarginRotDeg = 0.0
    $nudRot.Visible = $false
    $ttRotNud = New-Object System.Windows.Forms.ToolTip
    $ttRotNud.AutoPopDelay = 15000
    [void]$ttRotNud.SetToolTip($nudRot, "回転モードON時のみ有効。角度はこの数値で変更。「回転プレビュー」で実ピクセル確認。OKで cvr_rot_* 保存。")
    $btnRotPreview = New-Object System.Windows.Forms.Button
    $btnRotPreview.Text = "回転プレビュー"
    $btnRotPreview.Location = New-Object System.Drawing.Point(($gmRotX + 130), ($gmYSize - 2))
    $btnRotPreview.Size = New-Object System.Drawing.Size(112, 26)
    $btnRotPreview.Visible = $false
    $btnRotPreview.UseVisualStyleBackColor = $true
    $btnRotPreview.TabStop = $true
    $ttRotPrevBtn = New-Object System.Windows.Forms.ToolTip
    $ttRotPrevBtn.AutoPopDelay = 16000
    [void]$ttRotPrevBtn.SetToolTip($btnRotPreview, "ON で現在の角度の回転結果を表示。もう一度押すと元に戻ります。プレビュー中のノド・余白は OK 確定時と同じ座標系です。")
    $btnRotAdoptAngle = New-Object System.Windows.Forms.Button
    $btnRotAdoptAngle.Text = "回転角度採用"
    $btnRotAdoptAngle.Location = New-Object System.Drawing.Point(950, ($gmYSize - 2))
    $btnRotAdoptAngle.Size = New-Object System.Drawing.Size(118, 26)
    $btnRotAdoptAngle.Visible = $false
    $btnRotAdoptAngle.UseVisualStyleBackColor = $true
    $btnRotAdoptAngle.TabStop = $true
    $ttRotAdopt = New-Object System.Windows.Forms.ToolTip
    $ttRotAdopt.AutoPopDelay = 18000
    [void]$ttRotAdopt.SetToolTip($btnRotAdoptAngle, "現在の角度で画像を回転保存（cvr_rot_*）し、回転モードをオフにします。続けて余白・ノドを調整してから OK してください。プレビュー未表示でも同じ角度で保存します。")
    $updateSizeInfo = {
        $leftPx = $script:gutterImgX - $script:leftTrimPx
        $rightPx = ($script:guiMarginImgW - $script:gutterImgX) - $script:rightTrimPx
        $ratioStr = if ($rightPx -gt 0) {
            $r = [Math]::Round($leftPx / $rightPx, 3)
            "左対右 $r : 1.00"
        } else { "左対右 - : 1.00" }
        $vh = [Math]::Max(0, $script:guiMarginImgH - $script:topTrimPx - $script:bottomTrimPx)
        $zDisp = [Math]::Round([double]$script:guiMarginZoom, 3)
        $pbW0 = 0; $pbH0 = 0
        try { $pbW0 = [int]$pb.Width; $pbH0 = [int]$pb.Height } catch { }
        $effPct = if ($script:guiMarginImgW -gt 0 -and $pbW0 -gt 0) {
            [Math]::Round(100.0 * $pbW0 / [double]$script:guiMarginImgW, 1)
        } else { 0.0 }
        $prevNote = if ($rotPrev.Active) { "`n※ 回転プレビュー中（拡張キャンバス上のノド・余白）" } else { "" }
        $lblSizeInfo.Text = "左サイズ $leftPx px  右サイズ $rightPx px  ／  有効高さ $vh px`n$ratioStr`nプレビュー倍率: 操作 $zDisp× ／ 実効幅 ${effPct}%（画像に対する表示幅）$prevNote"
    }
    $updateBarPos = {
        $pb = $args[0]; $bar = $args[1]; $bL = $args[2]; $bR = $args[3]; $bT = $args[4]; $bB = $args[5]; $imgW = $args[6]; $imgH = $args[7]
        if ($pb.Width -le 0 -or $pb.Height -le 0) { return }
        $L = & $calcGmLayout $pb $imgW $imgH
        $scaleX = $L.ScaleX; $offX = $L.OffX; $offY = $L.OffY; $dispW = $L.DispW; $dispH = $L.DispH
        $barX = [int]([Math]::Round($offX + $script:gutterImgX * $scaleX - $bar.Width / 2))
        $barX = [Math]::Max([int]$offX, [Math]::Min([int]($offX + $dispW - $bar.Width), $barX))
        $bar.Location = New-Object System.Drawing.Point($barX, [int]$offY)
        $bar.Height = [Math]::Max($barWidth, [int][Math]::Ceiling($dispH))
        $leftX = [int]([Math]::Round($offX + $script:leftTrimPx * $scaleX - $bL.Width / 2))
        if ($script:gmUiSpecifyGutter) {
            $leftX = [Math]::Max([int]$offX, [Math]::Min($barX - 2, $leftX))
        } else {
            $leftX = [Math]::Max([int]$offX, [Math]::Min([int]($offX + $dispW - $bL.Width), $leftX))
        }
        $bL.Location = New-Object System.Drawing.Point($leftX, [int]$offY)
        $bL.Height = $bar.Height
        $rightX = [int]([Math]::Round($offX + ($imgW - $script:rightTrimPx) * $scaleX - $bR.Width / 2))
        if ($script:gmUiSpecifyGutter) {
            $rightX = [Math]::Max($barX + 2, [Math]::Min([int]($offX + $dispW - $bR.Width), $rightX))
        } else {
            $rightX = [Math]::Max([int]$offX, [Math]::Min([int]($offX + $dispW - $bR.Width), $rightX))
        }
        $bR.Location = New-Object System.Drawing.Point($rightX, [int]$offY)
        $bR.Height = $bar.Height
    }
    $updateGmRotChrome = { }
    $updateBarPosWrapper = {
        & $updateBarPos $pb $bar $barLeft $barRight $barTop $barBottom $script:guiMarginImgW $script:guiMarginImgH
        & $updateSizeInfo
        try { $pb.Invalidate($false) } catch {}
        try { if ($null -ne $gmRotOrangeOverlay -and $gmRotOrangeOverlay.Visible) { $gmRotOrangeOverlay.Invalidate($false) } } catch {}
        try { & $updateGmRotChrome } catch {}
    }
    # applyGmZoomLayout 実行中に scrollGm.Resize が走ると、スクロール未リセットの再レイアウトで表示が右下等にずれる → Resize 側は再入時スキップ
    $script:gmInsideApplyZoomLayout = $false
    $setGmScrollToImageCenter = {
        try {
            $hs = $scrollGm.HorizontalScroll
            $vs = $scrollGm.VerticalScroll
            # 古い横・縦オフセットが残ると、バー非表示時も表示が右下に寄ったままになる → いったん Minimum に戻してから中央を計算
            try {
                if ($null -ne $hs) { $hs.Value = $hs.Minimum; $hs.Value = $hs.Minimum }
                if ($null -ne $vs) { $vs.Value = $vs.Minimum; $vs.Value = $vs.Minimum }
            } catch { }
            try {
                $scrollGm.AutoScrollPosition = New-Object System.Drawing.Point(0, 0)
            } catch { }
            [void]$scrollGm.PerformLayout()
            $vw3 = [Math]::Max(1, $scrollGm.ClientSize.Width)
            $vh3 = [Math]::Max(1, $scrollGm.ClientSize.Height)
            $pl = [int]$pb.Left; $pt = [int]$pb.Top; $pw = [int]$pb.Width; $ph = [int]$pb.Height
            $cx = $pl + $pw / 2.0
            $cy = $pt + $ph / 2.0
            $wantHX = [int][Math]::Round($cx - $vw3 / 2.0)
            $wantVY = [int][Math]::Round($cy - $vh3 / 2.0)
            if ($null -ne $hs -and $hs.Maximum -gt $hs.Minimum) {
                $wantHX = [Math]::Max($hs.Minimum, [Math]::Min($hs.Maximum, $wantHX))
                $hs.Value = $wantHX
                try { $hs.Value = $wantHX } catch { }
            } else {
                try { $hs.Value = $hs.Minimum; $hs.Value = $hs.Minimum } catch { }
            }
            if ($null -ne $vs -and $vs.Maximum -gt $vs.Minimum) {
                $wantVY = [Math]::Max($vs.Minimum, [Math]::Min($vs.Maximum, $wantVY))
                $vs.Value = $wantVY
                try { $vs.Value = $wantVY } catch { }
            } else {
                try { $vs.Value = $vs.Minimum; $vs.Value = $vs.Minimum } catch { }
            }
        } catch { }
    }
    $applyGmZoomLayout = {
        param([switch]$PreserveScroll)
        $script:gmInsideApplyZoomLayout = $true
        try {
        $ratioH = 0.5
        $ratioV = 0.5
        if ($PreserveScroll) {
            $hs0 = $scrollGm.HorizontalScroll
            $vs0 = $scrollGm.VerticalScroll
            if ($null -ne $hs0 -and $hs0.Maximum -gt $hs0.Minimum) {
                $ratioH = ($hs0.Value - $hs0.Minimum) / [double]($hs0.Maximum - $hs0.Minimum)
            }
            if ($null -ne $vs0 -and $vs0.Maximum -gt $vs0.Minimum) {
                $ratioV = ($vs0.Value - $vs0.Minimum) / [double]($vs0.Maximum - $vs0.Minimum)
            }
        }
        $iw = [double]$script:guiMarginImgW
        $ih = [double]$script:guiMarginImgH
        if ($iw -le 0 -or $ih -le 0) { return }
        $vw = [Math]::Max(8, $scrollGm.ClientSize.Width)
        $vh = [Math]::Max(8, $scrollGm.ClientSize.Height)
        $fit = [Math]::Min($vw / $iw, $vh / $ih)
        $z = [double]$script:guiMarginZoom
        if ($z -lt 0.2) { $z = 0.2; $script:guiMarginZoom = $z }
        if ($z -gt 8.0) { $z = 8.0; $script:guiMarginZoom = $z }
        $sc = $fit * $z
        $nw = [Math]::Max(4, [int][Math]::Ceiling($iw * $sc))
        $nh = [Math]::Max(4, [int][Math]::Ceiling($ih * $sc))
        $padU = 0
        if ($script:guiMarginRotationMode -and (Get-Command Get-GmRotFrameDisplayPaddingPx -ErrorAction SilentlyContinue)) {
            try {
                $pp = Get-GmRotFrameDisplayPaddingPx -DispW ([double]$nw) -DispH ([double]$nh) -AngleDeg ([double]$script:guiMarginRotDeg)
                $padU = [int][Math]::Max(0, $pp.PadUniform)
            } catch { $padU = 0 }
        }
        # 文書を常に「ビューと画像の大きい方」に合わせる。回転モード時はオレンジ枠が画像外にはみ出す分 padU を足す
        $docW = [Math]::Max($vw, $nw + 2 * $padU)
        $docH = [Math]::Max($vh, $nh + 2 * $padU)
        $pbX = [int](($docW - $nw) / 2)
        $pbY = [int](($docH - $nh) / 2)
        try {
            $scrollGm.SuspendLayout()
            $gmCanvas.SuspendLayout()
            $pb.SuspendLayout()
            $gmCanvas.Size = New-Object System.Drawing.Size([Math]::Max($docW, 1), [Math]::Max($docH, 1))
            $pb.Location = New-Object System.Drawing.Point($pbX, $pbY)
            $pb.Size = New-Object System.Drawing.Size($nw, $nh)
            # MinSize を 0 にし、スクロール可能領域を gmCanvas の外接矩形だけに限定（従来の二重指定による巨大レンジを避ける）
            $scrollGm.AutoScrollMinSize = New-Object System.Drawing.Size(0, 0)
            $pb.ResumeLayout($true)
            $gmCanvas.ResumeLayout($true)
            $scrollGm.ResumeLayout($true)
        } catch {
            try { $pb.ResumeLayout($true); $gmCanvas.ResumeLayout($true); $scrollGm.ResumeLayout($true) } catch { }
        }
        if ($PreserveScroll) {
            try {
                [void]$scrollGm.PerformLayout()
                $hs = $scrollGm.HorizontalScroll
                $vs = $scrollGm.VerticalScroll
                if ($null -ne $hs) {
                    if ($hs.Maximum -gt $hs.Minimum) {
                        $nhv = [int][Math]::Round($hs.Minimum + $ratioH * ($hs.Maximum - $hs.Minimum))
                        $nhv = [Math]::Max($hs.Minimum, [Math]::Min($hs.Maximum, $nhv))
                        $hs.Value = $nhv
                        try { $hs.Value = $nhv } catch { }
                    } else {
                        try { $hs.Value = $hs.Minimum; $hs.Value = $hs.Minimum } catch { }
                    }
                }
                if ($null -ne $vs) {
                    if ($vs.Maximum -gt $vs.Minimum) {
                        $nvv = [int][Math]::Round($vs.Minimum + $ratioV * ($vs.Maximum - $vs.Minimum))
                        $nvv = [Math]::Max($vs.Minimum, [Math]::Min($vs.Maximum, $nvv))
                        $vs.Value = $nvv
                        try { $vs.Value = $nvv } catch { }
                    } else {
                        try { $vs.Value = $vs.Minimum; $vs.Value = $vs.Minimum } catch { }
                    }
                }
            } catch { }
        } else {
            # Ctrl+ズーム・初回表示・ウィンドウリサイズ: スクロールをリセットして画像中心に合わせる
            & $setGmScrollToImageCenter
            & $setGmScrollToImageCenter
        }
        & $updateBarPosWrapper
        } finally {
            $script:gmInsideApplyZoomLayout = $false
        }
    }
    $onGmPreviewWheel = {
        param($sender, $e)
        if ([System.Windows.Forms.Control]::ModifierKeys -band [System.Windows.Forms.Keys]::Control) {
            if ($e.Delta -gt 0) { $script:guiMarginZoom *= 1.12 } else { $script:guiMarginZoom /= 1.12 }
            if ($script:guiMarginZoom -lt 0.2) { $script:guiMarginZoom = 0.2 }
            if ($script:guiMarginZoom -gt 8.0) { $script:guiMarginZoom = 8.0 }
            & $applyGmZoomLayout
            return
        }
        try {
            if ([System.Windows.Forms.Control]::ModifierKeys -band [System.Windows.Forms.Keys]::Shift) {
                $hsW = $scrollGm.HorizontalScroll
                if ($null -ne $hsW -and $hsW.Maximum -gt $hsW.Minimum) {
                    $stepH = [int](-$e.Delta / 4)
                    $nvH = $hsW.Value + $stepH
                    if ($nvH -lt $hsW.Minimum) { $nvH = $hsW.Minimum }
                    if ($nvH -gt $hsW.Maximum) { $nvH = $hsW.Maximum }
                    $hsW.Value = $nvH
                }
                return
            }
            $vs = $scrollGm.VerticalScroll
            if ($null -ne $vs -and $vs.Maximum -gt $vs.Minimum) {
                $step = [int](-$e.Delta / 4)
                $nv = $vs.Value + $step
                if ($nv -lt $vs.Minimum) { $nv = $vs.Minimum }
                if ($nv -gt $vs.Maximum) { $nv = $vs.Maximum }
                $vs.Value = $nv
            }
        } catch { }
    }
    [void]$pb.add_MouseWheel($onGmPreviewWheel)
    [void]$gmCanvas.add_MouseWheel($onGmPreviewWheel)
    [void]$scrollGm.add_MouseWheel($onGmPreviewWheel)
    # pbHost の枠・余白上でもホイールを拾う
    [void]$pbHost.add_MouseWheel($onGmPreviewWheel)
    $scrollGm.add_Resize({
        if ($script:gmInsideApplyZoomLayout) { return }
        try { & $applyGmZoomLayout } catch { }
    })
    $forceCenterGutter = {
        $iw = $script:guiMarginImgW
        if ($iw -le 1) { return }
        $script:gutterImgX = [Math]::Max(1, [Math]::Min($iw - 1, [int]($iw / 2)))
        if ($null -ne $txtGutter) {
            $txtGutter.Text = [Math]::Round(100.0 * $script:gutterImgX / $iw, 1).ToString([System.Globalization.CultureInfo]::InvariantCulture)
        }
        # ノドオン時のみ左右トリムをノド位置で制限（ノドオフ＝表紙確認等は安全マージン不要）
        if ($script:gmUiSpecifyGutter) {
            $maxL = [int]($script:gutterImgX - 1)
            if ($maxL -lt 0) { $maxL = 0 }
            if ($script:leftTrimPx -gt $maxL) { $script:leftTrimPx = $maxL; if ($null -ne $txtLeft) { $txtLeft.Text = [string]$script:leftTrimPx } }
            $maxR = [int]($iw - $script:gutterImgX - 1)
            if ($maxR -lt 0) { $maxR = 0 }
            if ($script:rightTrimPx -gt $maxR) { $script:rightTrimPx = $maxR; if ($null -ne $txtRight) { $txtRight.Text = [string]$script:rightTrimPx } }
        }
        & $updateBarPosWrapper
    }
    # 回転枠の幾何（正本は Modules\GutterMarginRotationLayout.ps1 と同一式。cmdlet 未登録時は内蔵計算で null を返さない）
    $gmRotFrameGeom = {
        param($pbCtrl, [double]$angleDeg)
        $iw0 = [double]$script:guiMarginImgW; $ih0 = [double]$script:guiMarginImgH
        if ($iw0 -le 1 -or $ih0 -le 1) { return $null }
        $iwI = [int][Math]::Round($iw0); $ihI = [int][Math]::Round($ih0)
        if ($iwI -le 0 -or $ihI -le 0) { return $null }
        $L = & $calcGmLayout $pbCtrl $iwI $ihI
        $sc = [double]$L.Scale; $ox = [double]$L.OffX; $oy = [double]$L.OffY
        if (Get-Command Get-GmRotFrameGeometry -ErrorAction SilentlyContinue) {
            try {
                return Get-GmRotFrameGeometry -Iw0 $iw0 -Ih0 $ih0 -Scale $sc -OffX $ox -OffY $oy -AngleDegrees $angleDeg
            } catch { }
        }
        $cx = $ox + $iw0 * $sc / 2.0
        $cy = $oy + $ih0 * $sc / 2.0
        $rad = $angleDeg * [Math]::PI / 180.0
        $cos = [Math]::Cos($rad); $sin = [Math]::Sin($rad)
        $hx = $cx + ($ih0 / 2.0) * $sin * $sc
        $hy = $cy - ($ih0 / 2.0) * $cos * $sc
        $corners = [System.Collections.Generic.List[object]]::new()
        foreach ($pair in @(@(-$iw0 / 2.0, -$ih0 / 2.0), @($iw0 / 2.0, -$ih0 / 2.0), @($iw0 / 2.0, $ih0 / 2.0), @(-$iw0 / 2.0, $ih0 / 2.0))) {
            $dx = [double]$pair[0]; $dy = [double]$pair[1]
            $rx = $dx * $cos - $dy * $sin
            $ry = $dx * $sin + $dy * $cos
            [void]$corners.Add([pscustomobject]@{ X = ($cx + $rx * $sc); Y = ($cy + $ry * $sc) })
        }
        return [pscustomobject]@{
            Cx = $cx; Cy = $cy; Hx = $hx; Hy = $hy; Sc = $sc; Iw = $iw0; Ih = $ih0; Cos = $cos; Sin = $sin; Corners = $corners
        }
    }
    $drawGmHorizontalMargins = {
        param($s, $e)
        if ($s.Width -le 4 -or $s.Height -le 4) { return }
        $iw0 = $script:guiMarginImgW; $ih0 = $script:guiMarginImgH
        if ($iw0 -le 0 -or $ih0 -le 0) { return }
        $L = & $calcGmLayout $s $iw0 $ih0
        $offX = [float]$L.OffX; $offY = [float]$L.OffY; $dispW = [float]$L.DispW; $dispH = [float]$L.DispH
        $scaleX = [float]$L.ScaleX; $scaleY = [float]$L.ScaleY
        # 回転モードは余白線（緑）を描かない。オレンジは通常 gmCanvas オーバーレイ。オーバーレイ未生成時のみ pb に直接描く
        if ($script:guiMarginRotationMode) {
            if ($null -eq $gmRotOrangeOverlay) {
                try {
                    $e.Graphics.ResetClip()
                    $ltPx = 0.0; $rtPx = 0.0
                    $xo0 = $offX + $ltPx * $scaleX
                    $xo1 = $offX + ([double]$iw0 - $rtPx) * $scaleX
                    $xo0 = [Math]::Max($offX, [Math]::Min($offX + $dispW, $xo0))
                    $xo1 = [Math]::Max($offX, [Math]::Min($offX + $dispW, $xo1))
                    if ($xo1 -lt $xo0) { $tx = $xo0; $xo0 = $xo1; $xo1 = $tx }
                    $yoT = $offY + 0.0 * $scaleY
                    $yoB = $offY + ([float]$ih0) * $scaleY
                    $yoT = [Math]::Max($offY, [Math]::Min($offY + $dispH, $yoT))
                    $yoB = [Math]::Max($offY, [Math]::Min($offY + $dispH, $yoB))
                    $cx = ($xo0 + $xo1) / 2.0; $cy = ($yoT + $yoB) / 2.0
                    $rad = [double]$script:guiMarginRotDeg * [Math]::PI / 180.0
                    $c = [Math]::Cos($rad); $si = [Math]::Sin($rad)
                    $penF = New-Object System.Drawing.Pen ([System.Drawing.Color]::FromArgb(255, 95, 0)), 1.75
                    $penF.DashStyle = [System.Drawing.Drawing2D.DashStyle]::Dash
                    $penF.Alignment = [System.Drawing.Drawing2D.PenAlignment]::Center
                    $pf = New-Object System.Drawing.PointF[] 4
                    $ci = 0
                    foreach ($corner in @(@($xo0, $yoT), @($xo1, $yoT), @($xo1, $yoB), @($xo0, $yoB))) {
                        $px = [double]$corner[0]; $py = [double]$corner[1]
                        $dx = $px - $cx; $dy = $py - $cy
                        $rx = $dx * $c - $dy * $si
                        $ry = $dx * $si + $dy * $c
                        $pf[$ci] = New-Object System.Drawing.PointF ([float]($cx + $rx), [float]($cy + $ry))
                        $ci++
                    }
                    $e.Graphics.SmoothingMode = [System.Drawing.Drawing2D.SmoothingMode]::None
                    $e.Graphics.PixelOffsetMode = [System.Drawing.Drawing2D.PixelOffsetMode]::Half
                    $e.Graphics.DrawPolygon($penF, $pf)
                    $penF.Dispose()
                } catch { }
            }
            return
        }
        $pen = $null
        try {
            $e.Graphics.ResetClip()
            $gmLineW = 2.0
            $pen = New-Object System.Drawing.Pen ([System.Drawing.Color]::FromArgb(0, 150, 85)), $gmLineW
            $pen.Alignment = [System.Drawing.Drawing2D.PenAlignment]::Center
            $e.Graphics.SmoothingMode = [System.Drawing.Drawing2D.SmoothingMode]::None
            $e.Graphics.PixelOffsetMode = [System.Drawing.Drawing2D.PixelOffsetMode]::Half
            $topY = $offY + [float]$script:topTrimPx * $scaleY
            $botY = $offY + ([float]$ih0 - [float]$script:bottomTrimPx) * $scaleY
            $topY = [Math]::Max($offY, [Math]::Min($offY + $dispH, $topY))
            $botY = [Math]::Max($offY, [Math]::Min($offY + $dispH, $botY))
            # 左右トリム境界（青バーの位置）と同じ X 範囲で描く（画像全幅だと角で白隙間が出る）
            $ltPx = [double]$script:leftTrimPx
            $rtPx = [double]$script:rightTrimPx
            $x0 = $offX + $ltPx * $scaleX
            $x1 = $offX + ([double]$iw0 - $rtPx) * $scaleX
            $x0 = [Math]::Max($offX, [Math]::Min($offX + $dispW, $x0))
            $x1 = [Math]::Max($offX, [Math]::Min($offX + $dispW, $x1))
            if ($x1 -lt $x0) { $t = $x0; $x0 = $x1; $x1 = $t }
            # 上下の水平線のみ（左右境界は青バーで表示。緑の縦線は「全部緑」に見えるため描かない）
            $e.Graphics.DrawLine($pen, $x0, $topY, $x1, $topY)
            $e.Graphics.DrawLine($pen, $x0, $botY, $x1, $botY)
        } finally {
            if ($null -ne $pen) { $pen.Dispose() }
        }
    }
    $drawGmRotOrangeOverlay = {
        param($s, $e)
        if (-not $script:guiMarginRotationMode) { return }
        if ($null -eq $pb -or $pb.Width -le 4 -or $pb.Height -le 4) { return }
        $iw0 = $script:guiMarginImgW; $ih0 = $script:guiMarginImgH
        if ($iw0 -le 0 -or $ih0 -le 0) { return }
        try {
            $L = & $calcGmLayout $pb $iw0 $ih0
            $offX = [float]$L.OffX; $offY = [float]$L.OffY; $dispW = [float]$L.DispW; $dispH = [float]$L.DispH
            $scaleX = [float]$L.ScaleX; $scaleY = [float]$L.ScaleY
            $ltPx = 0.0; $rtPx = 0.0
            $xo0 = $offX + $ltPx * $scaleX
            $xo1 = $offX + ([double]$iw0 - $rtPx) * $scaleX
            $xo0 = [Math]::Max($offX, [Math]::Min($offX + $dispW, $xo0))
            $xo1 = [Math]::Max($offX, [Math]::Min($offX + $dispW, $xo1))
            if ($xo1 -lt $xo0) { $tx = $xo0; $xo0 = $xo1; $xo1 = $tx }
            $yoT = $offY + 0.0 * $scaleY
            $yoB = $offY + ([float]$ih0 - 0.0) * $scaleY
            $yoT = [Math]::Max($offY, [Math]::Min($offY + $dispH, $yoT))
            $yoB = [Math]::Max($offY, [Math]::Min($offY + $dispH, $yoB))
            $cx = ($xo0 + $xo1) / 2.0
            $cy = ($yoT + $yoB) / 2.0
            $rad = [double]$script:guiMarginRotDeg * [Math]::PI / 180.0
            $c = [Math]::Cos($rad); $si = [Math]::Sin($rad)
            $ox = [float]$pb.Left; $oy = [float]$pb.Top
            $penF = New-Object System.Drawing.Pen ([System.Drawing.Color]::FromArgb(255, 95, 0)), 1.75
            $penF.DashStyle = [System.Drawing.Drawing2D.DashStyle]::Dash
            $penF.Alignment = [System.Drawing.Drawing2D.PenAlignment]::Center
            $pf = New-Object System.Drawing.PointF[] 4
            $ci = 0
            foreach ($corner in @(@($xo0, $yoT), @($xo1, $yoT), @($xo1, $yoB), @($xo0, $yoB))) {
                $px = [double]$corner[0]; $py = [double]$corner[1]
                $dx = $px - $cx; $dy = $py - $cy
                $rx = $dx * $c - $dy * $si
                $ry = $dx * $si + $dy * $c
                $pf[$ci] = New-Object System.Drawing.PointF ([float]($ox + $cx + $rx), [float]($oy + $cy + $ry))
                $ci++
            }
            $e.Graphics.ResetClip()
            $e.Graphics.SmoothingMode = [System.Drawing.Drawing2D.SmoothingMode]::None
            $e.Graphics.PixelOffsetMode = [System.Drawing.Drawing2D.PixelOffsetMode]::Half
            $e.Graphics.DrawPolygon($penF, $pf)
            $penF.Dispose()
        } catch { }
    }
    try {
        if ('GmMarginRotOrangeOverlayPanelV2' -as [type]) {
            $gmRotOrangeOverlay = New-Object GmMarginRotOrangeOverlayPanelV2
            $gmRotOrangeOverlay.Dock = [System.Windows.Forms.DockStyle]::Fill
            $gmRotOrangeOverlay.TabStop = $false
            $gmRotOrangeOverlay.Visible = $false
            # マウス角度操作は廃止: オーバーレイは描画のみ。Enabled=false で下の PictureBox にクリックが届く（Ctrl+ホイールは pb/scrollGm 側）
            $gmRotOrangeOverlay.Enabled = $false
            $gmRotOrangeOverlay.Add_Paint($drawGmRotOrangeOverlay)
        }
    } catch { $gmRotOrangeOverlay = $null }
    $ensureGmRotZOrder = {
        if ($null -eq $gmCanvas -or $null -eq $pb) { return }
        try {
            if ($gmCanvas.Controls.Contains($pb)) { $pb.BringToFront() }
            if ($null -ne $gmRotOrangeOverlay -and $gmCanvas.Controls.Contains($gmRotOrangeOverlay)) {
                $gmRotOrangeOverlay.BringToFront()
            }
        } catch { }
    }
    $updateGmRotChrome = {
        if ($null -eq $pb) { return }
        $want = $script:guiMarginRotationMode
        if (-not $want) {
            if ($null -ne $gmRotOrangeOverlay) { $gmRotOrangeOverlay.Visible = $false }
            return
        }
        try {
            $gR = & $gmRotFrameGeom $pb [double]$script:guiMarginRotDeg
            if ($null -eq $gR) {
                if ($null -ne $gmRotOrangeOverlay) { $gmRotOrangeOverlay.Visible = $false }
                return
            }
            & $ensureGmRotZOrder
            if ($null -ne $gmRotOrangeOverlay) {
                $gmRotOrangeOverlay.Visible = $true
                try { $gmRotOrangeOverlay.Invalidate($false) } catch {}
            }
            try { $pb.Invalidate($true) } catch {}
        } catch {
            if ($null -ne $gmRotOrangeOverlay) { $gmRotOrangeOverlay.Visible = $false }
        }
    }
    # Paint 内で子コントロール位置＋Invalidate を回すと再入りでフォーム全体の描画が壊れる（下パネルが真っ白等）
    $pb.Add_Resize($updateBarPosWrapper)
    $pb.Add_Paint($drawGmHorizontalMargins)
    $pb.Add_MouseDown({
        param($s, $e)
        $L = & $calcGmLayout $s $script:guiMarginImgW $script:guiMarginImgH
        $scaleX = $L.ScaleX; $scaleY = $L.ScaleY; $offX = $L.OffX; $offY = $L.OffY; $dispW = $L.DispW; $dispH = $L.DispH
        $barCenterX = $offX + $script:gutterImgX * $scaleX
        $leftBarDispX = $offX + $script:leftTrimPx * $scaleX
        $rightBarDispX = $offX + ($script:guiMarginImgW - $script:rightTrimPx) * $scaleX
        $topBarDispY = $offY + $script:topTrimPx * $scaleY
        $botBarDispY = $offY + ($script:guiMarginImgH - $script:bottomTrimPx) * $scaleY
        $topBarDispY = [Math]::Max($offY, [Math]::Min($offY + $dispH, $topBarDispY))
        $botBarDispY = [Math]::Max($offY, [Math]::Min($offY + $dispH, $botBarDispY))
        $hitW = $gmHitHalfW
        $hitH = & $gmHitHalfH $scaleY
        $bandL = $offX + $script:leftTrimPx * $scaleX
        $bandR = $offX + ($script:guiMarginImgW - $script:rightTrimPx) * $scaleX
        $inBandX = ($e.X -ge ($bandL - 28) -and $e.X -le ($bandR + 28))
        $inImg = ($e.X -ge $offX -and $e.X -le $offX + $dispW -and $e.Y -ge $offY -and $e.Y -le $offY + $dispH)
        # ノド・左右（赤・青）は緑の上下帯と重なる位置でも優先して掴めるように先に判定
        if ($inImg -and $e.Y -ge $offY -and $e.Y -le $offY + $dispH -and $script:gmUiSpecifyGutter -and [Math]::Abs($e.X - $barCenterX) -le $hitW) {
            $script:gutterDragging = $true
            try { $pb.Capture = $true } catch {}
        } elseif ($inImg -and $e.Y -ge $offY -and $e.Y -le $offY + $dispH -and [Math]::Abs($e.X - $leftBarDispX) -le $hitW) {
            $script:leftBarDragging = $true
            try { $pb.Capture = $true } catch {}
        } elseif ($inImg -and $e.Y -ge $offY -and $e.Y -le $offY + $dispH -and [Math]::Abs($e.X - $rightBarDispX) -le $hitW) {
            $script:rightBarDragging = $true
            try { $pb.Capture = $true } catch {}
        } elseif ($inBandX -and [Math]::Abs($e.Y - $topBarDispY) -le $hitH) {
            $script:topBarDragging = $true
            try { $pb.Capture = $true } catch {}
        } elseif ($inBandX -and [Math]::Abs($e.Y - $botBarDispY) -le $hitH) {
            $script:bottomBarDragging = $true
            try { $pb.Capture = $true } catch {}
        } elseif ($inImg) {
            $newX = [Math]::Max(0, [Math]::Min($script:guiMarginImgW - 1, [int]([Math]::Round(($e.X - $offX) / $scaleX))))
            $newY = [Math]::Max(0, [Math]::Min($script:guiMarginImgH - 1, [int]([Math]::Round(($e.Y - $offY) / $scaleY))))
            if ($newX -lt $script:gutterImgX - 10) {
                $mbClick = 12
                $maxLeftClick = if ($script:gmUiSpecifyGutter) {
                    [Math]::Max(0, $script:gutterImgX - 1)
                } else {
                    [Math]::Max(0, $script:guiMarginImgW - $script:rightTrimPx - $mbClick)
                }
                $script:leftTrimPx = [Math]::Max(0, [Math]::Min($maxLeftClick, $newX))
                $txtLeft.Text = [string]$script:leftTrimPx
            } elseif ($newX -gt $script:gutterImgX + 10) {
                $mbRc = 12
                $script:rightTrimPx = [Math]::Max(0, $script:guiMarginImgW - $newX)
                if (-not $script:gmUiSpecifyGutter) {
                    $capR = [Math]::Max(0, $script:guiMarginImgW - $script:leftTrimPx - $mbRc)
                    if ($script:rightTrimPx -gt $capR) { $script:rightTrimPx = $capR }
                }
                $txtRight.Text = [string]$script:rightTrimPx
            } elseif ($newY -lt $script:guiMarginImgH / 2 - 8) {
                $script:topTrimPx = [Math]::Max(0, [Math]::Min($newY, $script:guiMarginImgH - $script:bottomTrimPx - 8))
                if ($null -ne $txtTop) { $txtTop.Text = [string]$script:topTrimPx }
            } elseif ($newY -gt $script:guiMarginImgH / 2 + 8) {
                $script:bottomTrimPx = [Math]::Max(0, [Math]::Min($script:guiMarginImgH - $newY, $script:guiMarginImgH - $script:topTrimPx - 8))
                if ($null -ne $txtBottom) { $txtBottom.Text = [string]$script:bottomTrimPx }
            } elseif ($script:gmUiSpecifyGutter) {
                $script:gutterImgX = $newX
                $txtGutter.Text = [Math]::Round(100.0 * $script:gutterImgX / $script:guiMarginImgW, 1).ToString([System.Globalization.CultureInfo]::InvariantCulture)
            }
            & $updateBarPosWrapper
        }
    })
    $pb.Add_MouseMove({
        param($s, $e)
        # ホバー時カーソル: ノド・左右（青）を上下（緑）より優先（同一帯内で SizeNS に化けるのを防ぐ）。座標は PictureBox クライアントで統一
        if (-not ($script:gutterDragging -or $script:leftBarDragging -or $script:rightBarDragging -or $script:topBarDragging -or $script:bottomBarDragging)) {
            try {
                $Lh = & $calcGmLayout $pb $script:guiMarginImgW $script:guiMarginImgH
                $scXh = $Lh.ScaleX; $scYh = $Lh.ScaleY; $oxH = $Lh.OffX; $oyH = $Lh.OffY; $dwH = $Lh.DispW; $dhH = $Lh.DispH
                $hitWw = $gmHitHalfW
                $inImgH = ($e.X -ge $oxH -and $e.X -le ($oxH + $dwH) -and $e.Y -ge $oyH -and $e.Y -le ($oyH + $dhH))
                $barCX = $oxH + $script:gutterImgX * $scXh
                $leftBX = $oxH + $script:leftTrimPx * $scXh
                $rightBX = $oxH + ($script:guiMarginImgW - $script:rightTrimPx) * $scXh
                if ($inImgH -and $script:gmUiSpecifyGutter -and [Math]::Abs($e.X - $barCX) -le $hitWw) {
                    $pb.Cursor = [System.Windows.Forms.Cursors]::SizeWE
                } elseif ($inImgH -and [Math]::Abs($e.X - $leftBX) -le $hitWw) {
                    $pb.Cursor = [System.Windows.Forms.Cursors]::SizeWE
                } elseif ($inImgH -and [Math]::Abs($e.X - $rightBX) -le $hitWw) {
                    $pb.Cursor = [System.Windows.Forms.Cursors]::SizeWE
                } else {
                    $topYh = $oyH + $script:topTrimPx * $scYh
                    $botYh = $oyH + ($script:guiMarginImgH - $script:bottomTrimPx) * $scYh
                    $topYh = [Math]::Max($oyH, [Math]::Min($oyH + $dhH, $topYh))
                    $botYh = [Math]::Max($oyH, [Math]::Min($oyH + $dhH, $botYh))
                    $hitHh = & $gmHitHalfH $scYh
                    $bandLL = $oxH + $script:leftTrimPx * $scXh
                    $bandRR = $oxH + ($script:guiMarginImgW - $script:rightTrimPx) * $scXh
                    $inBandX2 = ($e.X -ge ($bandLL - 28) -and $e.X -le ($bandRR + 28))
                    if ($inBandX2 -and ([Math]::Abs($e.Y - $topYh) -le $hitHh -or [Math]::Abs($e.Y - $botYh) -le $hitHh)) {
                        $pb.Cursor = [System.Windows.Forms.Cursors]::SizeNS
                    } else {
                        $pb.Cursor = [System.Windows.Forms.Cursors]::Default
                    }
                }
            } catch { }
        }
        $L = & $calcGmLayout $s $script:guiMarginImgW $script:guiMarginImgH
        $scaleX = $L.ScaleX; $scaleY = $L.ScaleY; $offX = $L.OffX; $offY = $L.OffY
        if ($script:gutterDragging -and $script:gmUiSpecifyGutter) {
            $script:gutterImgX = [Math]::Max(0, [Math]::Min($script:guiMarginImgW - 1, [int]([Math]::Round(($e.X - $offX) / $scaleX))))
            $txtGutter.Text = [Math]::Round(100.0 * $script:gutterImgX / $script:guiMarginImgW, 1).ToString([System.Globalization.CultureInfo]::InvariantCulture)
            $maxLeftByGutter = [int]($script:gutterImgX - 1)
            if ($maxLeftByGutter -lt 0) { $maxLeftByGutter = 0 }
            if ($script:leftTrimPx -gt $maxLeftByGutter) {
                $script:leftTrimPx = $maxLeftByGutter
                if ($null -ne $txtLeft) { $txtLeft.Text = [string]$script:leftTrimPx }
            }
            $maxRightByGutter = [int]($script:guiMarginImgW - $script:gutterImgX - 1)
            if ($maxRightByGutter -lt 0) { $maxRightByGutter = 0 }
            if ($script:rightTrimPx -gt $maxRightByGutter) {
                $script:rightTrimPx = $maxRightByGutter
                if ($null -ne $txtRight) { $txtRight.Text = [string]$script:rightTrimPx }
            }
            & $updateBarPosWrapper
        } elseif ($script:leftBarDragging) {
            $iwL = $script:guiMarginImgW
            $mbL = 12
            if ($script:gmUiSpecifyGutter) {
                $maxLeftDrag = [Math]::Max(0, $script:gutterImgX - 1)
            } else {
                $maxLeftDrag = [Math]::Max(0, $iwL - $script:rightTrimPx - $mbL)
            }
            $script:leftTrimPx = [Math]::Max(0, [Math]::Min($maxLeftDrag, [int]([Math]::Round(($e.X - $offX) / $scaleX))))
            $txtLeft.Text = [string]$script:leftTrimPx
            & $updateBarPosWrapper
        } elseif ($script:rightBarDragging) {
            $iwR = $script:guiMarginImgW
            $mbR = 12
            if ($script:gmUiSpecifyGutter) {
                $minRightBarX = $script:gutterImgX + 1
            } else {
                $minRightBarX = [Math]::Min($iwR, $script:leftTrimPx + $mbR)
                if ($minRightBarX -lt 0) { $minRightBarX = 0 }
            }
            $barImgX = [Math]::Max($minRightBarX, [Math]::Min($iwR, [int]([Math]::Round(($e.X - $offX) / $scaleX))))
            $script:rightTrimPx = [Math]::Max(0, $script:guiMarginImgW - $barImgX)
            $txtRight.Text = [string]$script:rightTrimPx
            & $updateBarPosWrapper
        } elseif ($script:topBarDragging) {
            $ny = [int]([Math]::Round(($e.Y - $offY) / $scaleY))
            $ny = [Math]::Max(0, [Math]::Min($script:guiMarginImgH - $script:bottomTrimPx - 8, $ny))
            $script:topTrimPx = [Math]::Max(0, $ny)
            if ($null -ne $txtTop) { $txtTop.Text = [string]$script:topTrimPx }
            & $updateBarPosWrapper
        } elseif ($script:bottomBarDragging) {
            $ny = [int]([Math]::Round(($e.Y - $offY) / $scaleY))
            $ny = [Math]::Max($script:topTrimPx + 8, [Math]::Min($script:guiMarginImgH - 1, $ny))
            $script:bottomTrimPx = [Math]::Max(0, $script:guiMarginImgH - $ny)
            if ($null -ne $txtBottom) { $txtBottom.Text = [string]$script:bottomTrimPx }
            & $updateBarPosWrapper
        }
    })
    $pb.Add_MouseUp({
        $script:gutterDragging = $false; $script:leftBarDragging = $false; $script:rightBarDragging = $false
        $script:topBarDragging = $false; $script:bottomBarDragging = $false
        try { $pb.Capture = $false } catch {}
