    # pbHost の上下パディング領域（黒枠の内側の余白）でも緑線ドラッグできるようにする
    $script:gmHostCapture = $false
    $pbHost.Add_MouseDown({
        param($sHost, $eHost)
        $L = & $calcGmLayout $pb $script:guiMarginImgW $script:guiMarginImgH
        $scaleX = $L.ScaleX; $scaleY = $L.ScaleY; $offX = $L.OffX; $offY = $L.OffY; $dispW = $L.DispW; $dispH = $L.DispH
        # host 座標（pbHost 内）で緑線の表示位置を求める（padding 領域でも判定が効くように）
        $topBarDispY = $offY + $script:topTrimPx * $scaleY
        $botBarDispY = $offY + ($script:guiMarginImgH - $script:bottomTrimPx) * $scaleY
        $topBarDispY = [Math]::Max($offY, [Math]::Min($offY + $dispH, $topBarDispY))
        $botBarDispY = [Math]::Max($offY, [Math]::Min($offY + $dispH, $botBarDispY))
        $topBarHostY = $pb.Top + $topBarDispY
        $botBarHostY = $pb.Top + $botBarDispY
        $hitH = & $gmHitHalfH $scaleY
        $bandL = $pb.Left + ($offX + $script:leftTrimPx * $scaleX)
        $bandR = $pb.Left + ($offX + ($script:guiMarginImgW - $script:rightTrimPx) * $scaleX)
        $inBandX = ($eHost.X -ge ($bandL - 28) -and $eHost.X -le ($bandR + 28))
        if ($inBandX -and [Math]::Abs($eHost.Y - $topBarHostY) -le $hitH) {
            $script:topBarDragging = $true
            $script:gmHostCapture = $true
            try { $pbHost.Capture = $true } catch {}
        } elseif ($inBandX -and [Math]::Abs($eHost.Y - $botBarHostY) -le $hitH) {
            $script:bottomBarDragging = $true
            $script:gmHostCapture = $true
            try { $pbHost.Capture = $true } catch {}
        }
    })
    $pbHost.Add_MouseMove({
        # pbHost 余白でも pb と同じ優先度でカーソル（pb 座標に変換して判定）
        if (-not $script:gmHostCapture) {
            try {
                $ptPb = $pb.PointToClient([System.Windows.Forms.Cursor]::Position)
                $Lh = & $calcGmLayout $pb $script:guiMarginImgW $script:guiMarginImgH
                $scXh = $Lh.ScaleX; $scYh = $Lh.ScaleY; $oxH = $Lh.OffX; $oyH = $Lh.OffY; $dwH = $Lh.DispW; $dhH = $Lh.DispH
                $hitWw = $gmHitHalfW
                $ex = $ptPb.X; $ey = $ptPb.Y
                $inImgH = ($ex -ge $oxH -and $ex -le ($oxH + $dwH) -and $ey -ge $oyH -and $ey -le ($oyH + $dhH))
                $barCX = $oxH + $script:gutterImgX * $scXh
                $leftBX = $oxH + $script:leftTrimPx * $scXh
                $rightBX = $oxH + ($script:guiMarginImgW - $script:rightTrimPx) * $scXh
                $cur = [System.Windows.Forms.Cursors]::Default
                if ($inImgH -and $script:gmUiSpecifyGutter -and [Math]::Abs($ex - $barCX) -le $hitWw) {
                    $cur = [System.Windows.Forms.Cursors]::SizeWE
                } elseif ($inImgH -and [Math]::Abs($ex - $leftBX) -le $hitWw) {
                    $cur = [System.Windows.Forms.Cursors]::SizeWE
                } elseif ($inImgH -and [Math]::Abs($ex - $rightBX) -le $hitWw) {
                    $cur = [System.Windows.Forms.Cursors]::SizeWE
                } else {
                    $topYh = $oyH + $script:topTrimPx * $scYh
                    $botYh = $oyH + ($script:guiMarginImgH - $script:bottomTrimPx) * $scYh
                    $topYh = [Math]::Max($oyH, [Math]::Min($oyH + $dhH, $topYh))
                    $botYh = [Math]::Max($oyH, [Math]::Min($oyH + $dhH, $botYh))
                    $hitHh = & $gmHitHalfH $scYh
                    $bandLL = $oxH + $script:leftTrimPx * $scXh
                    $bandRR = $oxH + ($script:guiMarginImgW - $script:rightTrimPx) * $scXh
                    if (($ex -ge ($bandLL - 28) -and $ex -le ($bandRR + 28)) -and ([Math]::Abs($ey - $topYh) -le $hitHh -or [Math]::Abs($ey - $botYh) -le $hitHh)) {
                        $cur = [System.Windows.Forms.Cursors]::SizeNS
                    }
                }
                $pbHost.Cursor = $cur
                $pb.Cursor = $cur
            } catch { }
            return
        }
        if (-not ($script:topBarDragging -or $script:bottomBarDragging)) { return }
        $ptNow = $pbHost.PointToClient([System.Windows.Forms.Cursor]::Position)
        $clientY = $ptNow.Y - $pb.Top
        $L = & $calcGmLayout $pb $script:guiMarginImgW $script:guiMarginImgH
        $scaleY = $L.ScaleY; $offY = $L.OffY
        if ($script:topBarDragging) {
            $ny = [int]([Math]::Round(($clientY - $offY) / $scaleY))
            $ny = [Math]::Max(0, [Math]::Min($script:guiMarginImgH - $script:bottomTrimPx - 8, $ny))
            $script:topTrimPx = [Math]::Max(0, $ny)
            if ($null -ne $txtTop) { $txtTop.Text = [string]$script:topTrimPx }
            & $updateBarPosWrapper
            return
        }
        if ($script:bottomBarDragging) {
            $ny = [int]([Math]::Round(($clientY - $offY) / $scaleY))
            $ny = [Math]::Max($script:topTrimPx + 8, [Math]::Min($script:guiMarginImgH - 1, $ny))
            $script:bottomTrimPx = [Math]::Max(0, $script:guiMarginImgH - $ny)
            if ($null -ne $txtBottom) { $txtBottom.Text = [string]$script:bottomTrimPx }
            & $updateBarPosWrapper
            return
        }
    })
    $pbHost.Add_MouseUp({
