    })
    $getMouseXInPb = { $mp = $pb.PointToClient([System.Windows.Forms.Cursor]::Position); $mp.X }
    $getMouseYInPb = { $mp = $pb.PointToClient([System.Windows.Forms.Cursor]::Position); $mp.Y }
    $bar.Add_MouseDown({
