            $ny = [Math]::Max(0, [Math]::Min($script:guiMarginImgH - $script:bottomTrimPx - 8, $ny))
            $script:topTrimPx = [Math]::Max(0, $ny)
            if ($null -ne $txtTop) { $txtTop.Text = [string]$script:topTrimPx }
            & $updateBarPosWrapper
            return
        }
        if ($script:bottomBarDragging) {
            $clientY = & $getMouseYInPb
            $L = & $calcGmLayout $pb $script:guiMarginImgW $script:guiMarginImgH
            $scaleY = $L.ScaleY; $offY = $L.OffY
            $ny = [int]([Math]::Round(($clientY - $offY) / $scaleY))
            $ny = [Math]::Max($script:topTrimPx + 8, [Math]::Min($script:guiMarginImgH - 1, $ny))
            $script:bottomTrimPx = [Math]::Max(0, $script:guiMarginImgH - $ny)
            if ($null -ne $txtBottom) { $txtBottom.Text = [string]$script:bottomTrimPx }
