        $scaleX = $L.ScaleX; $offX = $L.OffX
        $script:gutterImgX = [Math]::Max(0, [Math]::Min($script:guiMarginImgW - 1, [int]([Math]::Round(($clientX - $offX) / $scaleX))))
        $txtGutter.Text = [Math]::Round(100.0 * $script:gutterImgX / $script:guiMarginImgW, 1).ToString([System.Globalization.CultureInfo]::InvariantCulture)
        $maxLeftByGutter = [int]($script:gutterImgX - 1)
        if ($maxLeftByGutter -lt 0) { $maxLeftByGutter = 0 }
        if ($script:leftTrimPx -gt $maxLeftByGutter) {
            $script:leftTrimPx = $maxLeftByGutter
