    $txtBottom.Add_Leave({
        $v = Parse-MarginPxFromText -Text $txtBottom.Text -WhenEmptyOrInvalidUse $script:bottomTrimPx -EmptyMeansZero
        $script:bottomTrimPx = [Math]::Max(0, $v)
        $maxBot = [Math]::Max(0, $script:guiMarginImgH - $script:topTrimPx - 8)
        if ($script:bottomTrimPx -gt $maxBot) { $script:bottomTrimPx = $maxBot }
        $txtBottom.Text = [string]$script:bottomTrimPx
        & $updateBarPosWrapper
    })
    # NumericUpDown はフォーカス中の未確定テキストが .Value に入らないまま別ボタンが押されることがある → 角度を確定してから script に反映
    $syncGmRotDegFromNud = {
        try {
            if ($null -eq $nudRot) { return }
            try {
                if ($null -ne $form -and $form.ActiveControl -eq $nudRot) {
                    $form.ActiveControl = $null
                }
            } catch { }
            try { [void]$form.ValidateChildren() } catch { }
            $script:guiMarginRotDeg = [double]$nudRot.Value
        } catch { }
    }
    $clearRotPreview = {
        if (-not $rotPrev.Active) { return }
        $snap = $rotPrev.Snap0
        if ($null -eq $snap) {
            if ($null -ne $rotPrev.Bmp) { try { $rotPrev.Bmp.Dispose() } catch {}; $rotPrev.Bmp = $null }
            $rotPrev.Active = $false
            if ($CoverConfirmMode -and $script:guiViewingOriginal -and $null -ne $guiOriginalImg) { $pb.Image = $guiOriginalImg } else { $pb.Image = $img }
            return
        }
        $nw = [int]$script:guiMarginImgW
        $nh = [int]$script:guiMarginImgH
        $ow = [int]$snap.W
        $oh = [int]$snap.H
        if ($nw -gt 0 -and $nh -gt 0 -and $ow -gt 0 -and $oh -gt 0) {
            $invx = $ow / [double]$nw
            $invy = $oh / [double]$nh
            $script:gutterImgX = [Math]::Max(1, [Math]::Min($ow - 1, [int][Math]::Round($script:gutterImgX * $invx)))
            $script:leftTrimPx = [Math]::Max(0, [int][Math]::Round($script:leftTrimPx * $invx))
            $script:rightTrimPx = [Math]::Max(0, [int][Math]::Round($script:rightTrimPx * $invx))
            $script:topTrimPx = [Math]::Max(0, [int][Math]::Round($script:topTrimPx * $invy))
            $script:bottomTrimPx = [Math]::Max(0, [int][Math]::Round($script:bottomTrimPx * $invy))
            $vertInv = Repair-GutterVerticalMargins -ImgH $oh -TopTrim $script:topTrimPx -BottomTrim $script:bottomTrimPx
            $script:topTrimPx = $vertInv.TopTrimPx
            $script:bottomTrimPx = $vertInv.BottomTrimPx
            $script:guiMarginImgW = $ow
            $script:guiMarginImgH = $oh
        }
        if ($null -ne $txtLeft)  { $txtLeft.Text  = [string]$script:leftTrimPx }
        if ($null -ne $txtRight) { $txtRight.Text = [string]$script:rightTrimPx }
        if ($null -ne $txtTop)    { $txtTop.Text    = [string]$script:topTrimPx }
        if ($null -ne $txtBottom) { $txtBottom.Text = [string]$script:bottomTrimPx }
        if ($null -ne $txtGutter -and $script:guiMarginImgW -gt 0) {
            $txtGutter.Text = [Math]::Round(100.0 * $script:gutterImgX / $script:guiMarginImgW, 1).ToString([System.Globalization.CultureInfo]::InvariantCulture)
        }
        if ($null -ne $rotPrev.Bmp) { try { $rotPrev.Bmp.Dispose() } catch {}; $rotPrev.Bmp = $null }
        $rotPrev.Snap0 = $null
        $rotPrev.Active = $false
        if ($CoverConfirmMode -and $script:guiViewingOriginal -and $null -ne $guiOriginalImg) { $pb.Image = $guiOriginalImg } else { $pb.Image = $img }
        if ($null -ne $btnRotPreview) { $btnRotPreview.Text = "回転プレビュー" }
        try { & $applyGmZoomLayout -PreserveScroll } catch { try { & $applyGmZoomLayout } catch {} }
        try { & $updateBarPosWrapper } catch {}
        try { & $updateSizeInfo } catch {}
    }
    $applyRotPreview = {
        if (-not $script:guiMarginRotationMode) { return }
        & $syncGmRotDegFromNud
        if (-not (Get-Command Get-FlickFitRotatedBitmap -ErrorAction SilentlyContinue)) {
            throw "Get-FlickFitRotatedBitmap が読み込まれていません（FlickFitImageRotate モジュールを確認してください）。"
        }
        $anglePr = [double]$script:guiMarginRotDeg
        $srcImg = if ($CoverConfirmMode -and $script:guiViewingOriginal -and $null -ne $guiOriginalImg) { $guiOriginalImg } else { $img }
        if ($null -eq $srcImg) { return }
        $srcW = [int]$srcImg.Width
        $srcH = [int]$srcImg.Height
        if ($srcW -le 0 -or $srcH -le 0) { return }
        # 既にプレビュー適用中なら、回転後キャンバス寸法のまま再スケールすると累積で横に伸びる → いったんスナップのソース寸法へ戻す
        if ($rotPrev.Active -and $null -ne $rotPrev.Snap0) {
            $snapR = $rotPrev.Snap0
            $nwCur = [int]$script:guiMarginImgW
            $nhCur = [int]$script:guiMarginImgH
            $ow = [int]$snapR.W
            $oh = [int]$snapR.H
            if ($nwCur -gt 0 -and $nhCur -gt 0 -and $ow -gt 0 -and $oh -gt 0) {
                $invx = $ow / [double]$nwCur
                $invy = $oh / [double]$nhCur
                $script:gutterImgX = [Math]::Max(1, [Math]::Min($ow - 1, [int][Math]::Round($script:gutterImgX * $invx)))
                $script:leftTrimPx = [Math]::Max(0, [int][Math]::Round($script:leftTrimPx * $invx))
                $script:rightTrimPx = [Math]::Max(0, [int][Math]::Round($script:rightTrimPx * $invx))
                $script:topTrimPx = [Math]::Max(0, [int][Math]::Round($script:topTrimPx * $invy))
                $script:bottomTrimPx = [Math]::Max(0, [int][Math]::Round($script:bottomTrimPx * $invy))
                $vertRs = Repair-GutterVerticalMargins -ImgH $oh -TopTrim $script:topTrimPx -BottomTrim $script:bottomTrimPx
                $script:topTrimPx = $vertRs.TopTrimPx
                $script:bottomTrimPx = $vertRs.BottomTrimPx
                $script:guiMarginImgW = $ow
                $script:guiMarginImgH = $oh
            }
        }
        if ((-not $rotPrev.Active) -or ($null -eq $rotPrev.Snap0)) {
            $rotPrev.Snap0 = @{
                W  = $srcW
                H  = $srcH
                GX = [int]$script:gutterImgX
                L  = [int]$script:leftTrimPx
                R  = [int]$script:rightTrimPx
                T  = [int]$script:topTrimPx
                B  = [int]$script:bottomTrimPx
            }
        }
        $snap = $rotPrev.Snap0
        if ($null -eq $snap) { return }
        $szPr = Get-FlickFitRotatedCanvasSize -Width ([int]$snap.W) -Height ([int]$snap.H) -AngleDegrees $anglePr
        $nw = [int]$szPr.Width
        $nh = [int]$szPr.Height
        if ($nw -le 0 -or $nh -le 0) { return }
        $sx = $nw / [double][Math]::Max(1, [int]$snap.W)
        $sy = $nh / [double][Math]::Max(1, [int]$snap.H)
        $script:guiMarginImgW = $nw
        $script:guiMarginImgH = $nh
        $script:gutterImgX = [Math]::Max(1, [Math]::Min($nw - 1, [int][Math]::Round($snap.GX * $sx)))
        $script:leftTrimPx = [Math]::Max(0, [int][Math]::Round($snap.L * $sx))
        $script:rightTrimPx = [Math]::Max(0, [int][Math]::Round($snap.R * $sx))
        $script:topTrimPx = [Math]::Max(0, [int][Math]::Round($snap.T * $sy))
        $script:bottomTrimPx = [Math]::Max(0, [int][Math]::Round($snap.B * $sy))
        $vertPr = Repair-GutterVerticalMargins -ImgH $nh -TopTrim $script:topTrimPx -BottomTrim $script:bottomTrimPx
        $script:topTrimPx = $vertPr.TopTrimPx
        $script:bottomTrimPx = $vertPr.BottomTrimPx
        if ($null -ne $txtLeft)  { $txtLeft.Text  = [string]$script:leftTrimPx }
        if ($null -ne $txtRight) { $txtRight.Text = [string]$script:rightTrimPx }
        if ($null -ne $txtTop)    { $txtTop.Text    = [string]$script:topTrimPx }
        if ($null -ne $txtBottom) { $txtBottom.Text = [string]$script:bottomTrimPx }
        if ($null -ne $txtGutter -and $nw -gt 0) {
            $txtGutter.Text = [Math]::Round(100.0 * $script:gutterImgX / $nw, 1).ToString([System.Globalization.CultureInfo]::InvariantCulture)
        }
        $newBmp = $null
        try {
            $newBmp = Get-FlickFitRotatedBitmap -SourceImage $srcImg -AngleDegrees $anglePr -FillColor White -ErrorAction Stop
        } catch {
            throw
        }
        if ($null -ne $rotPrev.Bmp) { try { $rotPrev.Bmp.Dispose() } catch {} }
        $rotPrev.Bmp = $newBmp
        $pb.Image = $rotPrev.Bmp
        try { $pb.Refresh() } catch {}
        $rotPrev.Active = $true
        if ($null -ne $btnRotPreview) { $btnRotPreview.Text = "プレビュー解除" }
        try { & $applyGmZoomLayout -PreserveScroll } catch { try { & $applyGmZoomLayout } catch {} }
        try { & $updateBarPosWrapper } catch {}
        try { & $updateSizeInfo } catch {}
    }
    $btnRotPreview.Add_Click({
        if (-not $script:guiMarginRotationMode) {
            [void][System.Windows.Forms.MessageBox]::Show(
                "「回転モード」をオンにしてから「回転プレビュー」を押してください。",
                "回転プレビュー",
                [System.Windows.Forms.MessageBoxButtons]::OK,
                [System.Windows.Forms.MessageBoxIcon]::Information)
            return
        }
        & $syncGmRotDegFromNud
        if ($rotPrev.Active) {
            try { . $clearRotPreview } catch {}
        } else {
            try {
                . $applyRotPreview
            } catch {
                [void][System.Windows.Forms.MessageBox]::Show(
                    "回転プレビューを表示できませんでした: $($_.Exception.Message)",
                    "回転プレビュー",
                    [System.Windows.Forms.MessageBoxButtons]::OK,
                    [System.Windows.Forms.MessageBoxIcon]::Warning)
            }
        }
    })
    $btnRotAdoptAngle.Add_Click({
        if (-not $script:guiMarginRotationMode) {
            [void][System.Windows.Forms.MessageBox]::Show(
                "「回転モード」をオンにしてから「回転角度採用」を押してください。",
                "回転角度採用",
                [System.Windows.Forms.MessageBoxButtons]::OK,
                [System.Windows.Forms.MessageBoxIcon]::Information)
            return
        }
        & $syncGmRotDegFromNud
        $angleAd = [double]$script:guiMarginRotDeg
        if ([Math]::Abs($angleAd) -le 0.01) {
            [void][System.Windows.Forms.MessageBox]::Show(
                "角度が 0° に近いです。数値を変えてから採用するか、そのまま回転モードをオフにしてください。",
                "回転角度採用",
                [System.Windows.Forms.MessageBoxButtons]::OK,
                [System.Windows.Forms.MessageBoxIcon]::Information)
            return
        }
        if (-not (Get-Command Invoke-FlickFitImageRotateToFile -ErrorAction SilentlyContinue)) {
            [void][System.Windows.Forms.MessageBox]::Show(
                "回転の保存モジュールが読み込まれていません（FlickFitImageRotate を確認してください）。",
                "回転角度採用",
                [System.Windows.Forms.MessageBoxButtons]::OK,
                [System.Windows.Forms.MessageBoxIcon]::Warning)
            return
        }
        $apAd = if ($CoverConfirmMode -and $script:guiViewingOriginal -and -not [string]::IsNullOrWhiteSpace($guiOriginalPath) -and (Test-Path -LiteralPath $guiOriginalPath)) {
            try { (Resolve-Path -LiteralPath $guiOriginalPath -ErrorAction Stop).Path } catch { $guiOriginalPath }
        } elseif ($navList.Count -gt 0) {
            $pNavAd = $navList[$script:guiMarginCurrentIdx]
            try { (Resolve-Path -LiteralPath $pNavAd -ErrorAction Stop).Path } catch { $pNavAd }
        } elseif ($OkAppliesToCurrentView) {
            try { (Resolve-Path -LiteralPath $ImagePath -ErrorAction Stop).Path } catch { $ImagePath }
        } else {
            try { (Resolve-Path -LiteralPath $baseImagePath -ErrorAction Stop).Path } catch { $baseImagePath }
        }
        if (-not $apAd -or -not (Test-Path -LiteralPath $apAd)) {
            [void][System.Windows.Forms.MessageBox]::Show("回転元の画像パスが無効です。", "回転角度採用", [System.Windows.Forms.MessageBoxButtons]::OK, [System.Windows.Forms.MessageBoxIcon]::Warning)
            return
        }
        $hadRotPreview = $rotPrev.Active
        $ow0 = [int]$script:guiMarginImgW
        $oh0 = [int]$script:guiMarginImgH
        try {
            $parAd = [System.IO.Path]::GetDirectoryName($apAd)
            $stemAd = [System.IO.Path]::GetFileNameWithoutExtension($apAd)
            $extAd = [System.IO.Path]::GetExtension($apAd)
            if ([string]::IsNullOrWhiteSpace($extAd)) { $extAd = '.jpg' }
            $outAd = Join-Path $parAd ("cvr_rot_" + $stemAd + $extAd)
            [void](Invoke-FlickFitImageRotateToFile -SourcePath $apAd -OutputPath $outAd -AngleDegrees $angleAd -FillColor White -ErrorAction Stop)
            $ndAd = Get-ImageDimensions -Path $outAd
            if ($ndAd.Width -le 0 -or $ndAd.Height -le 0) { throw "回転後の画像サイズが取得できませんでした" }
            if ($hadRotPreview) {
                $script:guiMarginImgW = [int]$ndAd.Width
                $script:guiMarginImgH = [int]$ndAd.Height
            } else {
                $sx = $ndAd.Width / [double][Math]::Max(1, $ow0)
                $sy = $ndAd.Height / [double][Math]::Max(1, $oh0)
                $script:guiMarginImgW = [int]$ndAd.Width
                $script:guiMarginImgH = [int]$ndAd.Height
                $script:gutterImgX = [Math]::Max(1, [Math]::Min($script:guiMarginImgW - 1, [int][Math]::Round($script:gutterImgX * $sx)))
                $script:leftTrimPx = [Math]::Max(0, [int][Math]::Round($script:leftTrimPx * $sx))
                $script:rightTrimPx = [Math]::Max(0, [int][Math]::Round($script:rightTrimPx * $sx))
                $script:topTrimPx = [Math]::Max(0, [int][Math]::Round($script:topTrimPx * $sy))
                $script:bottomTrimPx = [Math]::Max(0, [int][Math]::Round($script:bottomTrimPx * $sy))
                $vertAd = Repair-GutterVerticalMargins -ImgH $script:guiMarginImgH -TopTrim $script:topTrimPx -BottomTrim $script:bottomTrimPx
                $script:topTrimPx = $vertAd.TopTrimPx
                $script:bottomTrimPx = $vertAd.BottomTrimPx
            }
            if ($null -ne $rotPrev.Bmp) { try { $rotPrev.Bmp.Dispose() } catch {}; $rotPrev.Bmp = $null }
            $rotPrev.Snap0 = $null
            $rotPrev.Active = $false
            $pb.Image = $null
            if ($null -ne $img -and $img -is [System.IDisposable]) { try { $img.Dispose() } catch {}; $img = $null }
            if ($null -ne $imgMs) { try { $imgMs.Dispose() } catch {}; $imgMs = $null }
            $imgMs = New-Object System.IO.MemoryStream(,([System.IO.File]::ReadAllBytes((Resolve-Path -LiteralPath $outAd).Path)))
            $img = [System.Drawing.Image]::FromStream($imgMs)
            $pb.Image = $img
            if ($null -ne $txtLeft)  { $txtLeft.Text  = [string]$script:leftTrimPx }
            if ($null -ne $txtRight) { $txtRight.Text = [string]$script:rightTrimPx }
            if ($null -ne $txtTop)    { $txtTop.Text    = [string]$script:topTrimPx }
            if ($null -ne $txtBottom) { $txtBottom.Text = [string]$script:bottomTrimPx }
            if ($null -ne $txtGutter -and $script:guiMarginImgW -gt 0) {
                $txtGutter.Text = [Math]::Round(100.0 * $script:gutterImgX / $script:guiMarginImgW, 1).ToString([System.Globalization.CultureInfo]::InvariantCulture)
            }
            $outResolved = try { (Resolve-Path -LiteralPath $outAd -ErrorAction Stop).Path } catch { $outAd }
            if ($navList.Count -gt 0) { $navList[$script:guiMarginCurrentIdx] = $outResolved }
            try { $baseImagePath = $outResolved } catch { }
            if ($CoverConfirmMode -and $script:guiViewingOriginal) {
                $script:guiViewingOriginal = $false
                if ($null -ne $btnViewOrig) { $btnViewOrig.Text = "トリミング前を表示" }
                $ncTi = $navList.Count
                $form.Text = if ($ncTi -gt 1) { "$Title  (表示: $($script:guiMarginCurrentIdx + 1)/$ncTi)" } else { $Title }
            }
            $nudRot.Value = 0
            $script:guiMarginRotDeg = 0.0
            $script:guiMarginRotationMode = $false
            $btnRotationMode.Text = "回転モード: OFF"
            $lblRotDeg.Visible = $false
            $nudRot.Visible = $false
            $btnRotPreview.Visible = $false
            $btnRotAdoptAngle.Visible = $false
            if ($null -ne $btnRotPreview) { $btnRotPreview.Text = "回転プレビュー" }
            Write-FlickFitHost "         [回転角度採用] ${angleAd}° → $outResolved（回転モードOFF・続けて余白調整可）" -ForegroundColor DarkCyan
            try { & $applyGmMarginBarsVisibility } catch {}
            try { & $applyGmZoomLayout -PreserveScroll } catch { try { & $applyGmZoomLayout } catch {} }
            try { & $updateBarPosWrapper } catch {}
            try { & $updateGmRotChrome } catch {}
        } catch {
            [void][System.Windows.Forms.MessageBox]::Show(
                "回転の保存に失敗しました: $($_.Exception.Message)",
                "回転角度採用",
                [System.Windows.Forms.MessageBoxButtons]::OK,
                [System.Windows.Forms.MessageBoxIcon]::Warning)
        }
    })
    $nudRot.Add_ValueChanged({
        try { $script:guiMarginRotDeg = [double]$nudRot.Value } catch { }
        if (-not $rotPrev.Active) {
            if ($script:guiMarginRotationMode) {
                try { & $applyGmZoomLayout -PreserveScroll } catch { try { & $applyGmZoomLayout } catch {} }
                try { $pb.Invalidate($false) } catch {}
                try { if ($null -ne $gmRotOrangeOverlay) { $gmRotOrangeOverlay.Invalidate($false) } } catch {}
                try { & $updateGmRotChrome } catch {}
            }
            return
        }
        if (-not $script:guiMarginRotationMode) { return }
        & $syncGmRotDegFromNud
        try {
            . $applyRotPreview
        } catch {
            try { . $clearRotPreview } catch {}
            [void][System.Windows.Forms.MessageBox]::Show(
                "角度変更後のプレビュー更新に失敗しました: $($_.Exception.Message)",
                "回転プレビュー",
                [System.Windows.Forms.MessageBoxButtons]::OK,
                [System.Windows.Forms.MessageBoxIcon]::Warning)
        }
    })
    $loadPathIntoPreview = {
        param([string]$newPath, [bool]$keepMargin = $false)
        try { . $clearRotPreview } catch {}
        if (-not (Test-Path -LiteralPath $newPath)) { return $false }
        if (-not $keepMargin) { $script:guiMarginZoom = 1.0 }
        $newDims = Get-ImageDimensions -Path $newPath
        if ($newDims.Width -le 0 -or $newDims.Height -le 0) {
            # サイズ取得失敗（破損・非対応形式）→ PictureBox をクリアして警告表示
            $pb.Image = $null
            Write-FlickFitHost "         [警告] 画像サイズ取得失敗（破損・非対応形式の可能性）: $(Split-Path $newPath -Leaf)" -ForegroundColor Yellow
            return $false
        }
        # 先に PictureBox をクリアしてから旧画像を破棄（破棄済みオブジェクト参照を防ぐ）
        $pb.Image = $null
        if ($null -ne $img -and $img -is [System.IDisposable]) { $img.Dispose(); $img = $null }
        if ($null -ne $imgMs) { try { $imgMs.Dispose() } catch {}; $imgMs = $null }
        try {
            $imgMs = New-Object System.IO.MemoryStream(,([System.IO.File]::ReadAllBytes((Resolve-Path -LiteralPath $newPath).Path)))
            $img = [System.Drawing.Image]::FromStream($imgMs)
            $pb.Image = $img
            if ($keepMargin -and $script:guiMarginImgW -gt 0) {
                # ノド位置を旧画像の%比率で新画像幅にスケール
                $gutterPct = $script:gutterImgX / $script:guiMarginImgW
                $script:guiMarginImgW = $newDims.Width
                $script:guiMarginImgH = $newDims.Height
                $script:gutterImgX = [Math]::Max(1, [Math]::Min($newDims.Width - 1, [int]($newDims.Width * $gutterPct)))
                # トリム値はそのまま維持（テキストボックスも更新）
                $txtLeft.Text  = [string]$script:leftTrimPx
                $txtRight.Text = [string]$script:rightTrimPx
                if ($null -ne $txtTop)    { $txtTop.Text    = [string]$script:topTrimPx }
                if ($null -ne $txtBottom) { $txtBottom.Text = [string]$script:bottomTrimPx }
            } else {
                $script:guiMarginImgW = $newDims.Width
                $script:guiMarginImgH = $newDims.Height
                $halfNew = [int]($newDims.Width / 2)
                $script:gutterImgX = [Math]::Max(1, [Math]::Min($newDims.Width - 1, $halfNew))
                $script:leftTrimPx = 0; $script:rightTrimPx = 0
                $script:topTrimPx = 0; $script:bottomTrimPx = 0
                $txtLeft.Text = "0"; $txtRight.Text = "0"
                if ($null -ne $txtTop)    { $txtTop.Text    = "0" }
                if ($null -ne $txtBottom) { $txtBottom.Text = "0" }
            }
            $txtGutter.Text = [Math]::Round(100.0 * $script:gutterImgX / $script:guiMarginImgW, 1).ToString([System.Globalization.CultureInfo]::InvariantCulture)
            if (-not $chkSpecifyGutter.Checked) { & $forceCenterGutter } else { & $updateBarPosWrapper }
            try { & $applyGmMarginBarsVisibility } catch {}
            if ($keepMargin) { & $applyGmZoomLayout -PreserveScroll } else { & $applyGmZoomLayout }
            if ($script:guiMarginRotationMode) {
                try { & $ensureGmRotZOrder } catch {}
                try { & $updateGmRotChrome } catch {}
            }
            return $true
        } catch {
            $pb.Image = $null
            Write-FlickFitHost "         [警告] 画像読み込み失敗（破損・非対応形式の可能性）: $(Split-Path $newPath -Leaf)" -ForegroundColor Yellow
            return $false
        }
    }
    $switchImage = {
        param($delta)
        if ($navList.Count -le 0) { return }
        $skipped = [System.Collections.Generic.List[string]]::new()
        $newIdx = $script:guiMarginCurrentIdx + $delta
        while ($newIdx -ge 0 -and $newIdx -lt $navList.Count) {
            $newPath = $navList[$newIdx]
            if (& $loadPathIntoPreview $newPath $true) {
                $script:guiMarginCurrentIdx = $newIdx
                $form.Text = "$Title  (表示: $($newIdx + 1)/$($navList.Count))"
                if ($script:guiViewingOriginal) {
                    $script:guiViewingOriginal = $false
                    try { & $applyGmMarginBarsVisibility } catch {}
                    if ($null -ne $btnViewOrig) { $btnViewOrig.Text = "トリミング前を表示" }
                }
                if ($skipped.Count -gt 0) {
                    $skippedMsg = ($skipped.ToArray() | ForEach-Object { "  ・$_" }) -join "`n"
                    [void][System.Windows.Forms.MessageBox]::Show(
                        "以下の画像は読み込めなかったためスキップしました：`n$skippedMsg",
                        "スキップ通知",
                        [System.Windows.Forms.MessageBoxButtons]::OK,
                        [System.Windows.Forms.MessageBoxIcon]::Information)
                }
                return
            }
            # 読み込み失敗 → 同方向に自動スキップ
            [void]$skipped.Add((Split-Path $newPath -Leaf))
            Write-FlickFitHost "         [スキップ] 読み込み失敗: $(Split-Path $newPath -Leaf)" -ForegroundColor Yellow
            $newIdx += $delta
        }
        # 有効な画像が方向の端まで見つからなかった
        if ($skipped.Count -gt 0) {
            $skippedMsg = ($skipped.ToArray() | ForEach-Object { "  ・$_" }) -join "`n"
            [void][System.Windows.Forms.MessageBox]::Show(
                "有効な画像が見つかりませんでした。以下はすべて読み込み失敗です：`n$skippedMsg",
                "スキップ通知",
                [System.Windows.Forms.MessageBoxButtons]::OK,
                [System.Windows.Forms.MessageBoxIcon]::Warning)
        }
    }
    $btnOk = New-Object System.Windows.Forms.Button
    $btnOk.Text = if ($CoverConfirmMode) { "採用（表紙として確定）" } else { "OK（この設定で分割）" }
    if ($CoverConfirmMode) {
        $btnOk.DialogResult = [System.Windows.Forms.DialogResult]::None
    } else {
        $btnOk.DialogResult = [System.Windows.Forms.DialogResult]::OK
    }
    $btnRowY = $gmYBtn
    $btnOkWidth = if ($CoverConfirmMode) { 200 } else { 180 }
    $btnOk.Size = New-Object System.Drawing.Size($btnOkWidth, 28)
    $btnRowGap = 8
    $btnOk.UseVisualStyleBackColor = $true
    if ($CoverConfirmMode) {
        $btnOk.Add_Click({
            if ($chkSpecifyGutter.Checked) {
                [void][System.Windows.Forms.MessageBox]::Show(
                    "表紙では「ノド（見開き分割）」がオンのまま採用できません。`r`n余白だけ確定する場合はチェックをオフにしてください。`r`n元の見開きをそのまま分割する場合は「見開きで通常分割 (S)」を押してください。",
                    "表紙確認",
                    [System.Windows.Forms.MessageBoxButtons]::OK,
                    [System.Windows.Forms.MessageBoxIcon]::Information)
                return
            }
            # 表紙確認は -OkAppliesToCurrentView で「いま表示中のファイル」を常に採用。削除・前後画像で候補が変わってもブロックしない（旧・別ファイル警告は廃止）
            $form.DialogResult = [System.Windows.Forms.DialogResult]::OK
            $form.Close()
        })
    }
    $btnCancel = New-Object System.Windows.Forms.Button
    $btnCancel.Text = "キャンセル"
    $btnCancel.DialogResult = [System.Windows.Forms.DialogResult]::Cancel
    $btnCancel.Location = New-Object System.Drawing.Point(20, $btnRowY)
    $btnCancel.Size = New-Object System.Drawing.Size(100, 28)
    $btnCancel.UseVisualStyleBackColor = $true
    $btnPrev = $null
    $btnNext = $null
    if ($navList.Count -gt 1) {
        $btnPrev = New-Object System.Windows.Forms.Button
        $btnPrev.Text = "前画像に戻る"
        $btnPrev.Location = New-Object System.Drawing.Point(20, $btnRowY)
        $btnPrev.Size = New-Object System.Drawing.Size(100, 28)
        $btnPrev.UseVisualStyleBackColor = $true
        $btnPrev.Add_Click({ $switchImage.Invoke(-1) })
        $btnNext = New-Object System.Windows.Forms.Button
        $btnNext.Text = "次画像"
        $btnNext.Location = New-Object System.Drawing.Point(20, $btnRowY)
        $btnNext.Size = New-Object System.Drawing.Size(100, 28)
        $btnNext.UseVisualStyleBackColor = $true
        $btnNext.Add_Click({ $switchImage.Invoke(1) })
        $form.Text = "$Title  (表示: $($baseIdx + 1)/$($navList.Count))"
    }
    $btnPhotos = New-Object System.Windows.Forms.Button
    $btnPhotos.Text = "Windowsフォトで編集"
    $btnPhotos.Location = New-Object System.Drawing.Point(20, $btnRowY)
    $btnPhotos.Size = New-Object System.Drawing.Size(140, 28)
    $btnPhotos.UseVisualStyleBackColor = $true
    $btnPhotos.Add_Click({
        # CoverConfirmMode ではトリミング前の元画像を開く（トリム後プレビューではなく元データを編集するため）
        $pathToOpen = if ($CoverConfirmMode -and $guiOriginalPath -and (Test-Path -LiteralPath $guiOriginalPath)) {
            $guiOriginalPath
        } elseif ($navList.Count -gt 0) {
            $navList[$script:guiMarginCurrentIdx]
        } else {
            $ImagePath
        }
        if ($pathToOpen -and (Test-Path -LiteralPath $pathToOpen)) {
            $script:guiMarginPhotosEditPath = $pathToOpen
            $form.DialogResult = [System.Windows.Forms.DialogResult]::Yes
        }
    })
    $btnApplyOne = $null
    if ($ShowApplyThisPageOnlyButton -and -not $CoverConfirmMode) {
        $btnApplyOne = New-Object System.Windows.Forms.Button
        $btnApplyOne.Text = "このページのみで採用"
        $btnApplyOne.Size = New-Object System.Drawing.Size(200, 28)
        $btnApplyOne.Location = New-Object System.Drawing.Point(20, $btnRowY)
        $btnApplyOne.UseVisualStyleBackColor = $true
        $btnApplyOne.TabStop = $true
        $btnApplyOne.Add_Click({
            $script:guiMarginApplyOnlyThisPage = $true
            $form.DialogResult = [System.Windows.Forms.DialogResult]::OK
            $form.Close()
        })
    }
    # 1行目: OK →（任意）このページのみ → キャンセル → フォト → 前後画像 → 削除
    $xRow1 = $gmPadL
    $btnOk.Location = New-Object System.Drawing.Point($xRow1, $btnRowY)
    $xRow1 += $btnOk.Width + $btnRowGap
    if ($null -ne $btnApplyOne) {
        $btnApplyOne.Location = New-Object System.Drawing.Point($xRow1, $btnRowY)
        $xRow1 += $btnApplyOne.Width + $btnRowGap
    }
    $btnCancel.Location = New-Object System.Drawing.Point($xRow1, $btnRowY)
    $xRow1 += $btnCancel.Width + $btnRowGap
    $btnPhotos.Location = New-Object System.Drawing.Point($xRow1, $btnRowY)
    $xRow1 += $btnPhotos.Width + $btnRowGap
    if ($null -ne $btnPrev) {
        $btnPrev.Location = New-Object System.Drawing.Point($xRow1, $btnRowY)
        $xRow1 += $btnPrev.Width + $btnRowGap
    }
    if ($null -ne $btnNext) {
        $btnNext.Location = New-Object System.Drawing.Point($xRow1, $btnRowY)
        $xRow1 += $btnNext.Width + $btnRowGap
    }
    $btnCovSplit = $null
    $btnCovSkip = $null
    $btnViewOrig = $null
    if ($CoverConfirmMode) {
        $row2Y = $gmYCov2
        $btnCovSplit = New-Object System.Windows.Forms.Button
        $btnCovSplit.Text = "見開きで通常分割 (S)"
        $btnCovSplit.Location = New-Object System.Drawing.Point($gmPadL, $row2Y)
        $btnCovSplit.Size = New-Object System.Drawing.Size(200, 26)
        $btnCovSplit.UseVisualStyleBackColor = $true
        $btnCovSplit.Add_Click({ $script:guiMarginCoverAction = 'S'; $form.Close() })
        $btnCovSkip = New-Object System.Windows.Forms.Button
        $btnCovSkip.Text = "この候補をスキップ (2)"
        $btnCovSkip.Location = New-Object System.Drawing.Point(230, $row2Y)
        $btnCovSkip.Size = New-Object System.Drawing.Size(200, 26)
        $btnCovSkip.UseVisualStyleBackColor = $true
        $btnCovSkip.Add_Click({ $script:guiMarginCoverAction = '2'; $form.Close() })
        if ($guiOriginalPath) {
            $btnViewOrig = New-Object System.Windows.Forms.Button
            $btnViewOrig.Text = "トリミング前を表示"
            $btnViewOrig.Location = New-Object System.Drawing.Point(440, $row2Y)
            $btnViewOrig.Size = New-Object System.Drawing.Size(160, 26)
            $btnViewOrig.UseVisualStyleBackColor = $true
            $btnViewOrig.Add_Click({
                try { . $clearRotPreview } catch {}
                $script:guiViewingOriginal = -not $script:guiViewingOriginal
                if ($script:guiViewingOriginal) {
                    if ($null -ne $guiOriginalImg) {
                        $pb.Image = $guiOriginalImg
                        try { & $applyGmMarginBarsVisibility } catch {}
                        $btnViewOrig.Text = "トリム後を表示"
                        $form.Text = "$Title  ※ トリミング前の画像を表示中"
                        # 画像だけ差し替えると PictureBox サイズがトリム後のまま Stretch で潰れる → 元画像のピクセル寸法で再レイアウト
                        if ($guiOriginalImgW -gt 0 -and $guiOriginalImgH -gt 0) {
                            $script:guiMarginImgW = $guiOriginalImgW
                            $script:guiMarginImgH = $guiOriginalImgH
                            $script:gutterImgX = [Math]::Max(1, [Math]::Min($guiOriginalImgW - 1, $script:gutterImgX))
                            $script:leftTrimPx = [Math]::Max(0, [Math]::Min($guiOriginalImgW - 1, $script:leftTrimPx))
                            $script:rightTrimPx = [Math]::Max(0, [Math]::Min($guiOriginalImgW - 1, $script:rightTrimPx))
                            $script:topTrimPx = [Math]::Max(0, [Math]::Min($guiOriginalImgH - 1, $script:topTrimPx))
                            $script:bottomTrimPx = [Math]::Max(0, [Math]::Min($guiOriginalImgH - 1, $script:bottomTrimPx))
                            if ($null -ne $txtGutter) {
                                $txtGutter.Text = [Math]::Round(100.0 * $script:gutterImgX / [Math]::Max(1, $script:guiMarginImgW), 1).ToString([System.Globalization.CultureInfo]::InvariantCulture)
                            }
                            if ($null -ne $txtLeft)  { $txtLeft.Text  = [string]$script:leftTrimPx }
                            if ($null -ne $txtRight) { $txtRight.Text = [string]$script:rightTrimPx }
                            if ($null -ne $txtTop)    { $txtTop.Text    = [string]$script:topTrimPx }
                            if ($null -ne $txtBottom) { $txtBottom.Text = [string]$script:bottomTrimPx }
                            try { & $applyGmZoomLayout -PreserveScroll } catch { }
                            try {
                                $barLeft.BringToFront()
                                $barRight.BringToFront()
                                if ($bar.Visible) { $bar.BringToFront() }
                            } catch { }
                        }
                    } else {
                        $script:guiViewingOriginal = $false
                    }
                } else {
                    $restorePath = if ($navList.Count -gt 0) { $navList[$script:guiMarginCurrentIdx] } else { $ImagePath }
                    [void](& $loadPathIntoPreview $restorePath $true)
                    try { & $applyGmMarginBarsVisibility } catch {}
                    try {
                        $barLeft.BringToFront()
                        $barRight.BringToFront()
                        if ($bar.Visible) { $bar.BringToFront() }
                    } catch { }
                    $btnViewOrig.Text = "トリミング前を表示"
                    $nc = $navList.Count
                    $form.Text = if ($nc -gt 1) { "$Title  (表示: $($script:guiMarginCurrentIdx + 1)/$nc)" } else { $Title }
                }
            })
        }
    }
    $btnDeleteMargin = New-Object System.Windows.Forms.Button
    $btnDeleteMargin.Text = "この画像を削除"
    $deleteBtnY = $btnRowY
    $deleteAfterNextGap = 16
    if ($null -ne $btnNext) {
        $btnDeleteMargin.Location = New-Object System.Drawing.Point(($btnNext.Location.X + $btnNext.Width + $deleteAfterNextGap), $deleteBtnY)
    } else {
        $btnDeleteMargin.Location = New-Object System.Drawing.Point(($xRow1 + $deleteAfterNextGap), $deleteBtnY)
    }
    $btnDeleteMargin.Size = New-Object System.Drawing.Size(160, 28)
    $btnDeleteMargin.UseVisualStyleBackColor = $true
    $btnDeleteMargin.Add_Click({
        # WinForms イベント内で Split-Path 等の cmdlet を呼ぶと PS7 で ParameterBindingException になることがあるため .NET のみ使用
        # 表紙確認で「トリミング前を表示」中は、画面上の元画像（例: 001.jpg）を削除。未切替時は nav 上のファイル（多くは cvr_*）を削除。
        $targetDel = $null
        if ($CoverConfirmMode -and $script:guiViewingOriginal -and -not [string]::IsNullOrWhiteSpace($guiOriginalPath) -and (Test-Path -LiteralPath $guiOriginalPath)) {
            try { $targetDel = (Resolve-Path -LiteralPath $guiOriginalPath -ErrorAction Stop).Path } catch { $targetDel = $guiOriginalPath }
        }
        if ([string]::IsNullOrWhiteSpace($targetDel)) {
            $targetDel = if ($navList.Count -gt 0) { $navList[$script:guiMarginCurrentIdx] } else { $baseImagePath }
        }
        if ([string]::IsNullOrWhiteSpace($targetDel)) { $targetDel = $ImagePath }
        $leaf = [System.IO.Path]::GetFileName($targetDel)
        if ([string]::IsNullOrWhiteSpace($leaf)) { $leaf = $targetDel }
        $msgDel = "次のファイルを削除しますか？`r`n" + $leaf
        $capDel = "画像の削除"
        $mbYesNo = [System.Windows.Forms.MessageBoxButtons]::YesNo
        $mbWarn = [System.Windows.Forms.MessageBoxIcon]::Warning
        $mbDef2 = [System.Windows.Forms.MessageBoxDefaultButton]::Button2
        $confirm = [System.Windows.Forms.MessageBox]::Show($msgDel, $capDel, $mbYesNo, $mbWarn, $mbDef2)
        if ($confirm -ne [System.Windows.Forms.DialogResult]::Yes) { return }
        try { . $clearRotPreview } catch {}
        try {
            if ($null -ne $pb.Image) { $pb.Image.Dispose(); $pb.Image = $null }
        } catch {}
        if ($null -ne $img) { try { $img.Dispose() } catch {}; $img = $null }
        $delOkLocal = $false
        for ($riDel = 0; $riDel -lt 8; $riDel++) {
            [System.GC]::Collect(); [System.GC]::WaitForPendingFinalizers()
            Start-Sleep -Milliseconds (200 + $riDel * 100)
            try {
                if (Test-Path -LiteralPath $targetDel) { Remove-Item -LiteralPath $targetDel -Force -ErrorAction Stop }
                if (-not (Test-Path -LiteralPath $targetDel)) { $delOkLocal = $true; break }
            } catch {}
        }
        if (-not $delOkLocal) {
            [void][System.Windows.Forms.MessageBox]::Show("削除できませんでした（ファイル使用中の可能性があります）。", $capDel, [System.Windows.Forms.MessageBoxButtons]::OK, [System.Windows.Forms.MessageBoxIcon]::Warning)
            if (Test-Path -LiteralPath $targetDel) {
                try {
                    if ($null -ne $imgMs) { try { $imgMs.Dispose() } catch {}; $imgMs = $null }
                    $imgMs = New-Object System.IO.MemoryStream(,([System.IO.File]::ReadAllBytes((Resolve-Path -LiteralPath $targetDel).Path)))
                    $img = [System.Drawing.Image]::FromStream($imgMs)
                    $pb.Image = $img
                } catch { Write-FlickFitHost "         [警告] 画像の再表示に失敗しました" -ForegroundColor Yellow }
            }
            return
        }
        Write-FlickFitHost "         🗑 GUIから削除: $leaf" -ForegroundColor Yellow
        [void]$deletedInSession.Add($targetDel)
        $targetNorm = try { (Resolve-Path -LiteralPath $targetDel -ErrorAction Stop).Path } catch { $targetDel }
        $baseNorm = try { (Resolve-Path -LiteralPath $baseImagePath -ErrorAction Stop).Path } catch { $baseImagePath }
        $baseWasDeleted = ($baseNorm -and $targetNorm -and [string]::Equals($baseNorm, $targetNorm, [StringComparison]::OrdinalIgnoreCase))
        $removedNavIdx = -1
        for ($nvi = 0; $nvi -lt $navList.Count; $nvi++) {
            $nvNorm = try { (Resolve-Path -LiteralPath $navList[$nvi] -ErrorAction Stop).Path } catch { $navList[$nvi] }
            if ($nvNorm -and $targetNorm -and [string]::Equals($nvNorm, $targetNorm, [StringComparison]::OrdinalIgnoreCase)) {
                $removedNavIdx = $nvi
                break
            }
        }
        if ($removedNavIdx -ge 0) {
            $navList.RemoveAt($removedNavIdx)
            if ($script:guiMarginCurrentIdx -gt $removedNavIdx) { $script:guiMarginCurrentIdx-- }
            elseif ($script:guiMarginCurrentIdx -eq $removedNavIdx -and $script:guiMarginCurrentIdx -ge $navList.Count) {
                $script:guiMarginCurrentIdx = [Math]::Max(0, $navList.Count - 1)
            }
        } else {
            # ナビに無いパスを消した（表紙で元画像のみ nav 外のとき）→ トリム後ビューへ戻す
            if ($CoverConfirmMode -and $script:guiViewingOriginal) {
                $script:guiViewingOriginal = $false
                if ($null -ne $guiOriginalImg) { try { $guiOriginalImg.Dispose() } catch {}; $guiOriginalImg = $null }
                if ($null -ne $guiOriginalMs) { try { $guiOriginalMs.Dispose() } catch {}; $guiOriginalMs = $null }
                if ($null -ne $btnViewOrig) { $btnViewOrig.Text = "トリミング前を表示" }
            }
        }
        if ($navList.Count -eq 0) {
            $script:guiMarginDeleteResult = @{ DeleteImage = $true; ImagePath = $targetDel; DeletedImagePaths = @($deletedInSession.ToArray()) }
            $form.DialogResult = [System.Windows.Forms.DialogResult]::Abort
            return
        }
        if ($script:guiMarginCurrentIdx -ge $navList.Count) { $script:guiMarginCurrentIdx = $navList.Count - 1 }
        if ($baseWasDeleted) {
            $baseImagePath = $navList[$script:guiMarginCurrentIdx]
            $bdBase = Get-ImageDimensions -Path $baseImagePath
            if ($bdBase.Width -gt 0) { $baseImgW = $bdBase.Width; $baseImgH = $bdBase.Height }
        }
        $showPath = $navList[$script:guiMarginCurrentIdx]
        try { & $applyGmMarginBarsVisibility } catch {}
        if (-not (& $loadPathIntoPreview $showPath)) {
            $script:guiMarginDeleteResult = @{ DeleteImage = $true; ImagePath = $targetDel; DeletedImagePaths = @($deletedInSession.ToArray()) }
            $form.DialogResult = [System.Windows.Forms.DialogResult]::Abort
            return
        }
        $form.Text = "$Title  (表示: $($script:guiMarginCurrentIdx + 1)/$($navList.Count))"
        return
    })
    $btnRotationMode = New-Object System.Windows.Forms.Button
    $btnRotationMode.Text = "回転モード: OFF"
    $btnRotationMode.Location = New-Object System.Drawing.Point(710, ($gmMarginRowY - 3))
    $btnRotationMode.Size = New-Object System.Drawing.Size(178, 26)
    $btnRotationMode.UseVisualStyleBackColor = $true
    $btnRotationMode.TabStop = $true
    $lblRotTestIntro = New-Object System.Windows.Forms.Label
    $lblRotTestIntro.Text = "※テスト導入機能"
    $lblRotTestIntro.AutoSize = $true
    $lblRotTestIntro.Location = New-Object System.Drawing.Point(896, ($gmMarginRowY + 2))
    $ttRotation = New-Object System.Windows.Forms.ToolTip
    $ttRotation.AutoPopDelay = 20000
    $ttRotation.InitialDelay = 200
    $tipRotMode = "ON: 角度・オレンジ枠・回転プレビュー。「回転角度採用」で cvr_rot_* に保存して回転モードOFF→続けて余白調整可。または OK で保存して以降の処理へ。表紙は「ノド」オフの余白のみ確定時に反映されます。"
    if ($navList.Count -gt 1) {
        $tipRotMode += " 前後画像で表示を切り替えた場合も、OK・回転の適用先は「いま表示中の画像」です。"
    }
    [void]$ttRotation.SetToolTip($btnRotationMode, $tipRotMode)
    $btnRotationMode.Add_Click({
        $script:guiMarginRotationMode = -not [bool]$script:guiMarginRotationMode
        if ($script:guiMarginRotationMode) {
            $btnRotationMode.Text = "回転モード: ON"
            $lblRotDeg.Visible = $true
            $nudRot.Visible = $true
            $btnRotPreview.Visible = $true
            $btnRotAdoptAngle.Visible = $true
        } else {
            try { . $clearRotPreview } catch {}
            $btnRotationMode.Text = "回転モード: OFF"
            $lblRotDeg.Visible = $false
            $nudRot.Visible = $false
            $btnRotPreview.Visible = $false
            $btnRotAdoptAngle.Visible = $false
        }
        try { $script:guiMarginRotDeg = [double]$nudRot.Value } catch { }
        try { & $applyGmMarginBarsVisibility } catch {}
        try { & $applyGmZoomLayout -PreserveScroll } catch { try { & $applyGmZoomLayout } catch {} }
        try { $pb.Invalidate($false) } catch {}
        try { & $updateGmRotChrome } catch {}
    })
    $pnlCtrls = [System.Collections.Generic.List[object]]::new()
    if ($null -ne $tbReviewSum) { [void]$pnlCtrls.Add($tbReviewSum) }
    foreach ($x in @($lblSizeInfo, $lblRotDeg, $nudRot, $btnRotPreview, $btnRotAdoptAngle, $chkSpecifyGutter, $lblHint, $lblGutter, $txtGutter, $lblL, $txtLeft, $lblR, $txtRight, $lblTopM, $txtTop, $lblBotM, $txtBottom, $btnRotationMode, $lblRotTestIntro, $btnOk, $btnCancel, $btnPhotos)) { [void]$pnlCtrls.Add($x) }
    if ($null -ne $btnApplyOne) { [void]$pnlCtrls.Add($btnApplyOne) }
    if ($btnCovSplit) { [void]$pnlCtrls.Add($btnCovSplit); [void]$pnlCtrls.Add($btnCovSkip) }
    if ($null -ne $btnViewOrig) { [void]$pnlCtrls.Add($btnViewOrig) }
    if ($btnPrev) { [void]$pnlCtrls.Add($btnPrev) }
    if ($btnNext) { [void]$pnlCtrls.Add($btnNext) }
    [void]$pnlCtrls.Add($btnDeleteMargin)
    $pnl.Controls.AddRange($pnlCtrls.ToArray())
    $imgPanel.Controls.Add($pbHost, 0, 0)
    [void]$gmCanvas.Controls.Add($pb)
    if ($null -ne $gmRotOrangeOverlay) { [void]$gmCanvas.Controls.Add($gmRotOrangeOverlay) }
    try { & $ensureGmRotZOrder } catch {}
    [void]$scrollGm.Controls.Add($gmCanvas)
    [void]$pbHost.Controls.Add($scrollGm)
    # Dock: Fill を先に追加 → Bottom を後から（下パネルが正しく確保され、Fill に隠れない）
    $form.Controls.Add($imgPanel)
    $form.Controls.Add($pnl)
    $form.Add_Shown({
        param($snd, $ev)
        try { & $applyGmZoomLayout } catch { }
        # Resize イベント等で上書きされる場合があるため、表示後に bar の可視状態を確実に反映
        try { & $applyGmMarginBarsVisibility } catch {}
        try { & $ensureGmRotZOrder } catch {}
    })
    $form.Add_FormClosing({
        param($snd, $ev)
        try { & $syncGmRotDegFromNud } catch { }
    })
    $form.AcceptButton = $btnOk
    $form.CancelButton = $btnCancel
    $disposeGmRotPreviewBmp = {
        if ($null -ne $rotPrev.Bmp) { try { $rotPrev.Bmp.Dispose() } catch {}; $rotPrev.Bmp = $null }
    }
    $result = $form.ShowDialog()
    if ($null -ne $script:guiMarginSplitWidthReviewResult) {
        $sr = $script:guiMarginSplitWidthReviewResult
        $script:guiMarginSplitWidthReviewResult = $null
        . $disposeGmRotPreviewBmp
        if ($img) { try { $img.Dispose() } catch {} }
        if ($imgMs) { try { $imgMs.Dispose() } catch {}; $imgMs = $null }
        if ($null -ne $guiOriginalImg) { try { $guiOriginalImg.Dispose() } catch {} }
        if ($null -ne $guiOriginalMs)  { try { $guiOriginalMs.Dispose()  } catch {} }
        $form.Dispose()
        if ($deletedInSession.Count -gt 0) {
            if ($sr -is [System.Collections.IDictionary] -and -not $sr.ContainsKey('DeletedImagePaths')) { $sr['DeletedImagePaths'] = @($deletedInSession.ToArray()) }
        }
        return $sr
    }
    $ret = $null
    if ($CoverConfirmMode -and $script:guiMarginCoverAction) {
        $caEarly = $script:guiMarginCoverAction
        $script:guiMarginCoverAction = $null
        . $disposeGmRotPreviewBmp
        if ($img) { try { $img.Dispose() } catch {} }
        if ($imgMs) { try { $imgMs.Dispose() } catch {}; $imgMs = $null }
        if ($null -ne $guiOriginalImg) { try { $guiOriginalImg.Dispose() } catch {} }
        if ($null -ne $guiOriginalMs)  { try { $guiOriginalMs.Dispose()  } catch {} }
        $form.Dispose()
        return @{ CoverAction = [string]$caEarly }
    }
    if ($result -eq [System.Windows.Forms.DialogResult]::Abort) {
        . $disposeGmRotPreviewBmp
        if ($img) { $img.Dispose() }
        if ($imgMs) { try { $imgMs.Dispose() } catch {}; $imgMs = $null }
        if ($null -ne $guiOriginalImg) { try { $guiOriginalImg.Dispose() } catch {} }
        if ($null -ne $guiOriginalMs)  { try { $guiOriginalMs.Dispose()  } catch {} }
        $form.Dispose()
        $dr = $script:guiMarginDeleteResult
        $script:guiMarginDeleteResult = $null
        if ($null -ne $dr -and $dr -is [System.Collections.IDictionary] -and $deletedInSession.Count -gt 0) {
            $dr['DeletedImagePaths'] = @($deletedInSession.ToArray())
        }
        if ($CoverConfirmMode -and $null -ne $dr -and $dr -is [System.Collections.IDictionary]) { $dr['CoverAction'] = 'D' }
        return $dr
    }
    if ($result -eq [System.Windows.Forms.DialogResult]::Yes) {
        . $disposeGmRotPreviewBmp
        if ($img) { $img.Dispose() }
        if ($imgMs) { try { $imgMs.Dispose() } catch {}; $imgMs = $null }
        if ($null -ne $guiOriginalImg) { try { $guiOriginalImg.Dispose() } catch {} }
        if ($null -ne $guiOriginalMs)  { try { $guiOriginalMs.Dispose()  } catch {} }
        $form.Dispose()
        $pathForPhotos = if (Get-Variable -Name guiMarginPhotosEditPath -Scope Script -ErrorAction SilentlyContinue) { $script:guiMarginPhotosEditPath } else { $null }
        if ($pathForPhotos -and (Test-Path -LiteralPath $pathForPhotos)) {
            if ($CoverConfirmMode) {
                # 表紙ループの [m] 分岐で1回だけフォトを開き Read-Host する（二重表示・二重待ちを防ぐ）
                $dimsAfter = Get-ImageDimensions -Path $pathForPhotos
                $ret = @{ PhotosEdit = $true; ImagePath = $pathForPhotos; Width = if ($dimsAfter.Width -gt 0) { $dimsAfter.Width } else { $null }; Height = if ($dimsAfter.Height -gt 0) { $dimsAfter.Height } else { $null } }
                if ($deletedInSession.Count -gt 0) { $ret['DeletedImagePaths'] = @($deletedInSession.ToArray()) }
            } else {
                try { Invoke-PhotosOpen -ImagePath $pathForPhotos } catch { try { Start-Process -FilePath $pathForPhotos } catch { Write-FlickFitHost "         [警告] 画像を開けませんでした" -ForegroundColor Yellow } }
                Write-FlickFitHost "         ※ フォトで編集・保存したら Enter で続行（フォトで保存した画像を基準として以降のトリミングに採用）" -ForegroundColor Yellow
                Read-HostWithEsc "         [確認]"
                $dimsAfter = Get-ImageDimensions -Path $pathForPhotos
                $ret = @{ PhotosEdit = $true; ImagePath = $pathForPhotos; Width = if ($dimsAfter.Width -gt 0) { $dimsAfter.Width } else { $null }; Height = if ($dimsAfter.Height -gt 0) { $dimsAfter.Height } else { $null } }
                if ($deletedInSession.Count -gt 0) { $ret['DeletedImagePaths'] = @($deletedInSession.ToArray()) }
            }
        }
        Remove-Variable -Name guiMarginPhotosEditPath -Scope Script -ErrorAction SilentlyContinue
        return $ret
    }
    if ($result -eq [System.Windows.Forms.DialogResult]::OK) {
        try {
            # 表紙確認で「トリミング前を表示」中に採用したときは、画面上の元画像を採用（nav は一時トリム済みのままなので従来は誤ってトリム後ファイルが使われていた）
            $dimsOkOrig = $null
            $forceOriginalAdopt = $false
            if ($CoverConfirmMode -and $script:guiViewingOriginal -and -not [string]::IsNullOrWhiteSpace($guiOriginalPath) -and (Test-Path -LiteralPath $guiOriginalPath)) {
                $dimsOkOrig = Get-ImageDimensions -Path $guiOriginalPath
                if ($dimsOkOrig.Width -gt 0 -and $dimsOkOrig.Height -gt 0) { $forceOriginalAdopt = $true }
            }
            if ($forceOriginalAdopt -and $rotPrev.Active) {
                try { . $clearRotPreview } catch {}
            }
            # OkAppliesToCurrentView: 現在プレビュー中の画像サイズ・パスで確定（表紙の自動トリムプレビューとナビの整合）
            # 回転プレビュー中は gui の寸法が既に拡張キャンバス基準のため OkApplies と同様に扱う
            # navList あり（前後画像ナビ）: 画面上の表示＝guiMarginImgW/H と一致させるため、常に「表示中インデックス」のパス・寸法で確定（回転・余白の取り違え防止）
            $rotPrevWasActive = $rotPrev.Active
            . $disposeGmRotPreviewBmp
            $rotPrev.Active = $false
            $rotPrev.Snap0 = $null
            $useNavView = ($navList.Count -gt 0)
            $useW = if ($forceOriginalAdopt) { $dimsOkOrig.Width } elseif ($useNavView -or $OkAppliesToCurrentView -or $rotPrevWasActive) { $script:guiMarginImgW } else { $baseImgW }
            $useH = if ($forceOriginalAdopt) { $dimsOkOrig.Height } elseif ($useNavView -or $OkAppliesToCurrentView -or $rotPrevWasActive) { $script:guiMarginImgH } else { $baseImgH }
            $apPath = if ($forceOriginalAdopt) {
                try { (Resolve-Path -LiteralPath $guiOriginalPath -ErrorAction Stop).Path } catch { $guiOriginalPath }
            } elseif ($useNavView) {
                $pNav = $navList[$script:guiMarginCurrentIdx]
                try { (Resolve-Path -LiteralPath $pNav -ErrorAction Stop).Path } catch { $pNav }
            } elseif ($OkAppliesToCurrentView) {
                try { (Resolve-Path -LiteralPath $ImagePath -ErrorAction Stop).Path } catch { $ImagePath }
            } else {
                try { (Resolve-Path -LiteralPath $baseImagePath -ErrorAction Stop).Path } catch { $baseImagePath }
            }
            # forceOriginalAdopt: ApplyImagePath と寸法だけ元画像に合わせる。余白数値は GUI のまま Python へ渡す（以前はここで全0にしてトリムが無効化されていた）
            if ($forceOriginalAdopt) {
                Write-FlickFitHost "         [表紙・トリミング前を表示中に確定] 元画像 ${useW}x${useH}px に対して GUI の余白を適用します" -ForegroundColor DarkCyan
            }
            $lvOk = Parse-MarginPxFromText -Text $txtLeft.Text -WhenEmptyOrInvalidUse $script:leftTrimPx
            $rvOk = Parse-MarginPxFromText -Text $txtRight.Text -WhenEmptyOrInvalidUse $script:rightTrimPx
            $leftVal  = [Math]::Max(0, $lvOk)
            $rightVal = [Math]::Max(0, $rvOk)
            $tvOk = Parse-MarginPxFromText -Text $txtTop.Text -WhenEmptyOrInvalidUse $script:topTrimPx -EmptyMeansZero
            $bvOk = Parse-MarginPxFromText -Text $txtBottom.Text -WhenEmptyOrInvalidUse $script:bottomTrimPx -EmptyMeansZero
            $topVal = [Math]::Max(0, $tvOk)
            $botVal = [Math]::Max(0, $bvOk)
            $vertCoh = Repair-GutterVerticalMargins -ImgH $useH -TopTrim $topVal -BottomTrim $botVal
            $topVal = $vertCoh.TopTrimPx
            $botVal = $vertCoh.BottomTrimPx
            $rotDegApplied = $null
            $rotPathApplied = $null
            if ($script:guiMarginRotationMode) {
                $angleRot = [double]$script:guiMarginRotDeg
                if ([Math]::Abs($angleRot) -gt 0.01 -and (Get-Command Invoke-FlickFitImageRotateToFile -ErrorAction SilentlyContinue)) {
                    try {
                        $parAp = [System.IO.Path]::GetDirectoryName($apPath)
                        $stemAp = [System.IO.Path]::GetFileNameWithoutExtension($apPath)
                        $extAp = [System.IO.Path]::GetExtension($apPath)
                        if ([string]::IsNullOrWhiteSpace($extAp)) { $extAp = '.jpg' }
                        $outRot = Join-Path $parAp ("cvr_rot_" + $stemAp + $extAp)
                        [void](Invoke-FlickFitImageRotateToFile -SourcePath $apPath -OutputPath $outRot -AngleDegrees $angleRot -FillColor White -ErrorAction Stop)
                        $nd = Get-ImageDimensions -Path $outRot
                        if ($nd.Width -gt 0 -and $nd.Height -gt 0 -and $useW -gt 0 -and $useH -gt 0) {
                            $apPath = try { (Resolve-Path -LiteralPath $outRot -ErrorAction Stop).Path } catch { $outRot }
                            if ($rotPrevWasActive) {
                                $useW = $nd.Width
                                $useH = $nd.Height
                                $rotDegApplied = $angleRot
                                $rotPathApplied = $apPath
                                Write-FlickFitHost "         [回転] ${angleRot}° → $apPath (${useW}x${useH}px)（プレビュー済み・数値はそのまま採用）" -ForegroundColor DarkCyan
                            } else {
                                $sx = $nd.Width / [double]$useW
                                $sy = $nd.Height / [double]$useH
                                $useW = $nd.Width
                                $useH = $nd.Height
                                $script:gutterImgX = [Math]::Max(1, [Math]::Min($useW - 1, [int][Math]::Round($script:gutterImgX * $sx)))
                                $leftVal = [Math]::Max(0, [int][Math]::Round($leftVal * $sx))
                                $rightVal = [Math]::Max(0, [int][Math]::Round($rightVal * $sx))
                                $topVal = [Math]::Max(0, [int][Math]::Round($topVal * $sy))
                                $botVal = [Math]::Max(0, [int][Math]::Round($botVal * $sy))
                                $vertCoh2 = Repair-GutterVerticalMargins -ImgH $useH -TopTrim $topVal -BottomTrim $botVal
                                $topVal = $vertCoh2.TopTrimPx
                                $botVal = $vertCoh2.BottomTrimPx
                                if ($null -ne $txtGutter -and $useW -gt 0) {
                                    $txtGutter.Text = [Math]::Round(100.0 * $script:gutterImgX / $useW, 1).ToString([System.Globalization.CultureInfo]::InvariantCulture)
                                }
                                $rotDegApplied = $angleRot
                                $rotPathApplied = $apPath
                                Write-FlickFitHost "         [回転] ${angleRot}° → $apPath (${useW}x${useH}px) ノド・余白を比例換算しました" -ForegroundColor DarkCyan
                            }
                        }
                    } catch {
                        Write-FlickFitHost "         [警告] 回転の適用に失敗: $($_.Exception.Message)" -ForegroundColor Yellow
                    }
                }
            }
            if (-not $chkSpecifyGutter.Checked) {
                $minBandX = 12
                while (($leftVal + $rightVal) -gt ($useW - $minBandX) -and ($leftVal -gt 0 -or $rightVal -gt 0)) {
                    if ($leftVal -ge $rightVal) { $leftVal-- } else { $rightVal-- }
                }
                $gxPx = [Math]::Max(1, [Math]::Min($useW - 1, [int]($useW / 2)))
                if ($deletedInSession.Count -eq 0) {
                    Write-FlickFitHost "         [余白のみ・分割なし] 元 ${useW}x${useH}px 左=${leftVal}px 右=${rightVal}px / 上=${topVal}px 下=${botVal}px → Python" -ForegroundColor DarkCyan
                }
                $script:leftTrimPx = $leftVal
                $script:rightTrimPx = $rightVal
                $script:topTrimPx = $topVal
                $script:bottomTrimPx = $botVal
                try { $logDir = if ($PSScriptRoot) { $PSScriptRoot } else { Get-Location }; $logPath = Join-Path $logDir 'debug-68e06a.log'; $logObj = @{sessionId='68e06a';location='Show-GutterMarginSetGui:ps1';message='gui_margin_ok';data=@{marginTrimOnly=$true;leftVal=$leftVal;rightVal=$rightVal;topVal=$topVal;botVal=$botVal;imgW=$useW;imgH=$useH;rotPreviewAtOk=$rotPrevWasActive;rotationDeg=$rotDegApplied}}; Add-Content -LiteralPath $logPath -Value ($logObj | ConvertTo-Json -Compress) -Encoding UTF8 -ErrorAction SilentlyContinue } catch {}
                $ret = @{ MarginTrimWithoutSplit = $true; GutterX = $gxPx; LeftTrimPx = $leftVal; RightTrimPx = $rightVal; TopTrimPx = $topVal; BottomTrimPx = $botVal; GutterPct = 50.0; ApplyImagePath = $apPath }
            } else {
                $gTxt = ConvertTo-HalfWidthDigitsInString $txtGutter.Text
                $gPct = 50.0
                if (-not [double]::TryParse($gTxt, [System.Globalization.NumberStyles]::Float, [System.Globalization.CultureInfo]::InvariantCulture, [ref]$gPct)) {
                    $gPct = [Math]::Round(100.0 * $script:gutterImgX / $useW, 2)
                }
                $gPct = [Math]::Max(1, [Math]::Min(99, $gPct))
                $script:gutterImgX = [Math]::Max(1, [Math]::Min($useW - 1, [int]($useW * $gPct / 100)))
                $gxPx = $script:gutterImgX
                $leftVal = [Math]::Min($leftVal, [Math]::Max(0, $gxPx - 1))
                $rightVal = [Math]::Min($rightVal, [Math]::Max(0, $useW - $gxPx - 1))
                if ($true -eq $script:FlickFitDebugStep5Verbose -and $deletedInSession.Count -eq 0) {
                    Write-FlickFitHost "         [余白・ノド] 元 ${useW}x${useH}px のど=${gxPx}px / 左=${leftVal}px 右=${rightVal}px / 上=${topVal}px 下=${botVal}px → Python" -ForegroundColor DarkCyan
                }
                $script:leftTrimPx = $leftVal
                $script:rightTrimPx = $rightVal
                $script:topTrimPx = $topVal
                $script:bottomTrimPx = $botVal
                try { $logDir = if ($PSScriptRoot) { $PSScriptRoot } else { Get-Location }; $logPath = Join-Path $logDir 'debug-68e06a.log'; $logObj = @{sessionId='68e06a';location='Show-GutterMarginSetGui:ps1';message='gui_margin_ok';data=@{gutterX=$script:gutterImgX;leftVal=$leftVal;rightVal=$rightVal;topVal=$topVal;botVal=$botVal;imgW=$useW;imgH=$useH;rotPreviewAtOk=$rotPrevWasActive;rotationDeg=$rotDegApplied}}; Add-Content -LiteralPath $logPath -Value ($logObj | ConvertTo-Json -Compress) -Encoding UTF8 -ErrorAction SilentlyContinue } catch {}
                $coh = Repair-GutterMarginGeometry -ImgW $useW -GutterX $script:gutterImgX -LeftTrim $leftVal -RightTrim $rightVal
                $ret = @{ GutterX = $coh.GutterX; LeftTrimPx = $coh.LeftTrimPx; RightTrimPx = $coh.RightTrimPx; TopTrimPx = $topVal; BottomTrimPx = $botVal; GutterPct = [Math]::Round([double]$gPct, 2); ApplyImagePath = $apPath; MarginTrimWithoutSplit = $false }
            }
            if ((Get-Variable -Name guiMarginApplyOnlyThisPage -Scope Script -ErrorAction SilentlyContinue) -and $script:guiMarginApplyOnlyThisPage -and $null -ne $ret) {
                $ret['ApplyOnlyThisSpread'] = $true
                $script:guiMarginApplyOnlyThisPage = $false
            }
            if ($CoverConfirmMode) { $ret['CoverAction'] = '1' }
            if ($deletedInSession.Count -gt 0) { $ret['DeletedImagePaths'] = @($deletedInSession.ToArray()) }
            if ($null -ne $ret -and $ret -is [System.Collections.IDictionary]) {
                $ret['RotationModeActive'] = [bool]$script:guiMarginRotationMode
                if ($rotPrevWasActive) { $ret['RotationPreviewUsedAtOk'] = $true }
                if ($null -ne $rotDegApplied) {
                    $ret['RotationDegrees'] = [double]$rotDegApplied
                    $ret['RotatedOutputPath'] = [string]$rotPathApplied
                }
            }
        } catch {
            Write-FlickFitHost "         [警告] ノド・余白GUIのOK確定でエラー: $($_.Exception.Message)（中央ノド・余白0で続行）" -ForegroundColor Yellow
            $wSafe = if ($CoverConfirmMode -and $script:guiViewingOriginal -and -not [string]::IsNullOrWhiteSpace($guiOriginalPath) -and (Test-Path -LiteralPath $guiOriginalPath)) {
                $dF = Get-ImageDimensions -Path $guiOriginalPath
                if ($dF.Width -gt 2) { $dF.Width } else { 100 }
            } elseif ($OkAppliesToCurrentView -and [int]$script:guiMarginImgW -gt 2) { [int]$script:guiMarginImgW } elseif ($baseImgW -gt 2) { $baseImgW } else { 100 }
            $gxF = [Math]::Max(1, [Math]::Min($wSafe - 2, [int]($wSafe / 2)))
            $apF = if ($CoverConfirmMode -and $script:guiViewingOriginal -and -not [string]::IsNullOrWhiteSpace($guiOriginalPath) -and (Test-Path -LiteralPath $guiOriginalPath)) {
                try { (Resolve-Path -LiteralPath $guiOriginalPath -ErrorAction Stop).Path } catch { $guiOriginalPath }
            } elseif ($OkAppliesToCurrentView -and $navList.Count -gt 0) { $navList[$script:guiMarginCurrentIdx] } else { $baseImagePath }
            $ret = @{ GutterX = $gxF; LeftTrimPx = 0; RightTrimPx = 0; TopTrimPx = 0; BottomTrimPx = 0; GutterPct = 50.0; ApplyImagePath = $apF; MarginTrimWithoutSplit = $false }
            if ((Get-Variable -Name guiMarginApplyOnlyThisPage -Scope Script -ErrorAction SilentlyContinue) -and $script:guiMarginApplyOnlyThisPage) {
                $ret['ApplyOnlyThisSpread'] = $true
                $script:guiMarginApplyOnlyThisPage = $false
            }
            if ($CoverConfirmMode) { $ret['CoverAction'] = '1' }
            if ($deletedInSession.Count -gt 0) { $ret['DeletedImagePaths'] = @($deletedInSession.ToArray()) }
            if ($null -ne $ret -and $ret -is [System.Collections.IDictionary]) {
                $ret['RotationModeActive'] = [bool]$script:guiMarginRotationMode
            }
        }
    }
    if ($CoverConfirmMode -and $result -eq [System.Windows.Forms.DialogResult]::Cancel) {
        . $disposeGmRotPreviewBmp
        if ($img) { $img.Dispose() }
        if ($imgMs) { try { $imgMs.Dispose() } catch {}; $imgMs = $null }
        if ($null -ne $guiOriginalImg) { try { $guiOriginalImg.Dispose() } catch {} }
        if ($null -ne $guiOriginalMs)  { try { $guiOriginalMs.Dispose()  } catch {} }
        $form.Dispose()
        return @{ CoverAction = 'N' }
    }
    if ($null -eq $ret -and $deletedInSession.Count -gt 0) {
        $ret = @{ DeletedImagePaths = @($deletedInSession.ToArray()) }
    }
    . $disposeGmRotPreviewBmp
    if ($img) { $img.Dispose() }
    if ($imgMs) { try { $imgMs.Dispose() } catch {}; $imgMs = $null }
    if ($null -ne $guiOriginalImg) { try { $guiOriginalImg.Dispose() } catch {} }
    if ($null -ne $guiOriginalMs)  { try { $guiOriginalMs.Dispose()  } catch {} }
    $form.Dispose()
    return $ret
}
#endregion

#region I/O, file lock & cover helpers
# 役割:
#   画像列挙・ファイルロック・リネーム・Step2 構造・表紙クロップなど入出力周り。
# 主役:
#   Get-ProcessableFolderImages / Invoke-CoverCrop
# 注意:
#   Restart Manager の Add-Type、Step2 長大フロー、表紙処理が同居。巻コンテキストは VolumeContext モジュール側と連携。
# Get-RealRoot / Get-LeafFolders → Modules\VolumeContext.ps1

# フォルダ内の画像をそのまま取得（Windowsエクスプローラーと同様の自然順）
# cvr_* のみ除外（一時ファイル）。その他の特別な除外・判定は行わない
function Get-ProcessableFolderImages {
    param([string]$FolderPath)
    $items = Get-ChildItem -LiteralPath $FolderPath -File -ErrorAction SilentlyContinue | Where-Object {
        $script:ImageExtensions -contains $_.Extension.ToLower() -and $_.Name -notlike "cvr_*"
    }
    $items | Sort-Object { [regex]::Replace($_.Name, '\d+', { $args[0].Value.PadLeft(10,'0') }) }
}

# 表紙〜2ページ目GUI後: 実際に Python が処理したソースファイルと結果文字列から、再取得した $imgs 内の「次に進むべき」添字を求める。
# （GUI で別ページを表示したあと OK した場合、nextIdx+2 など固定加算だと実処理ファイルとズレる）
function Get-FlickFitNextCoverLoopIndexAfterSpreadOp {
    param(
        [array]$Images,
        [string]$ProcessedSourcePath,
        [string]$PythonResult
    )
    $pyText = if ($null -eq $PythonResult) { '' } else { "$PythonResult" }
    if (-not $Images -or @($Images).Count -eq 0) { return $null }
    if ([string]::IsNullOrWhiteSpace($ProcessedSourcePath)) { return $null }
    try {
        $leafSrc = [System.IO.Path]::GetFileName($ProcessedSourcePath)
        $stemSrc = [System.IO.Path]::GetFileNameWithoutExtension($ProcessedSourcePath)
        $extSrc = [System.IO.Path]::GetExtension($ProcessedSourcePath)
    } catch {
        return $null
    }

    if ($pyText -match 'SPLIT:2') {
        $want2 = ($stemSrc + '_2' + $extSrc)
        $arr = @($Images)
        for ($j = 0; $j -lt $arr.Count; $j++) {
            if ([string]::Equals($arr[$j].Name, $want2, [System.StringComparison]::OrdinalIgnoreCase)) {
                return [Math]::Min($j + 1, $arr.Count)
            }
        }
        return $null
    }

    if ($pyText -match 'SPLIT:1') {
        $want1 = ($stemSrc + '_1' + $extSrc)
        $arr = @($Images)
        for ($j = 0; $j -lt $arr.Count; $j++) {
            if ([string]::Equals($arr[$j].Name, $want1, [System.StringComparison]::OrdinalIgnoreCase)) {
                return [Math]::Min($j + 1, $arr.Count)
            }
        }
        for ($j = 0; $j -lt $arr.Count; $j++) {
            if ([string]::Equals($arr[$j].Name, $leafSrc, [System.StringComparison]::OrdinalIgnoreCase)) {
                return [Math]::Min($j + 1, $arr.Count)
            }
        }
        return $null
    }

    if ($pyText -match 'TRIMMED:1') {
        $arr = @($Images)
        for ($j = 0; $j -lt $arr.Count; $j++) {
            if ([string]::Equals($arr[$j].Name, $leafSrc, [System.StringComparison]::OrdinalIgnoreCase)) {
                return [Math]::Min($j + 1, $arr.Count)
            }
        }
        return $null
    }

    return $null
}

# 再取得した $imgs の中でフルパスキーが一致する行を返す（GUI開始ページを一覧で逆引きする用）
function Get-FlickFitCoverLoopIndexForPath {
    param(
        [array]$Images,
        [string]$FullPath
    )
    if (-not $Images -or @($Images).Count -eq 0) { return -1 }
    if ([string]::IsNullOrWhiteSpace($FullPath)) { return -1 }
    $want = $null
    try { $want = Get-FlickFitStep5PathKey $FullPath } catch { }
    if ([string]::IsNullOrWhiteSpace($want)) { return -1 }
    $arr = @($Images)
    for ($i = 0; $i -lt $arr.Count; $i++) {
        try {
            $pk = Get-FlickFitStep5PathKey $arr[$i].FullName
            if ($pk -and ($pk -eq $want)) { return $i }
        } catch { }
    }
    return -1
}

# Restart Manager API を使ってファイルをロックしているプロセスを取得する
if (-not ([System.Management.Automation.PSTypeName]'FlickFit.FileLocker').Type) {
    Add-Type @'
using System;
using System.Collections.Generic;
using System.Diagnostics;
using System.Runtime.InteropServices;

namespace FlickFit {
    public static class FileLocker {
        [DllImport("rstrtmgr.dll", CharSet = CharSet.Unicode)]
        static extern int RmStartSession(out uint pSessionHandle, int dwSessionFlags, string strSessionKey);
        [DllImport("rstrtmgr.dll")]
        static extern int RmEndSession(uint pSessionHandle);
        [DllImport("rstrtmgr.dll", CharSet = CharSet.Unicode)]
        static extern int RmRegisterResources(uint pSessionHandle, uint nFiles, string[] rgsFilenames,
            uint nApplications, [In] RM_UNIQUE_PROCESS[] rgApplications, uint nServices, string[] rgsServiceNames);
        [DllImport("rstrtmgr.dll")]
        static extern int RmGetList(uint dwSessionHandle, out uint pnProcInfoNeeded, ref uint pnProcInfo,
            [In, Out] RM_PROCESS_INFO[] rgAffectedApps, ref uint lpdwRebootReasons);

        [StructLayout(LayoutKind.Sequential)]
        struct RM_UNIQUE_PROCESS { public int dwProcessId; public System.Runtime.InteropServices.ComTypes.FILETIME ProcessStartTime; }

        [StructLayout(LayoutKind.Sequential, CharSet = CharSet.Unicode)]
        struct RM_PROCESS_INFO {
            public RM_UNIQUE_PROCESS Process;
            [MarshalAs(UnmanagedType.ByValTStr, SizeConst = 256)] public string strAppName;
            [MarshalAs(UnmanagedType.ByValTStr, SizeConst = 64)]  public string strServiceShortName;
            public int ApplicationType; public uint AppStatus; public int TSSessionId;
            [MarshalAs(UnmanagedType.Bool)] public bool bRestartable;
        }

        public static List<Process> GetLockingProcesses(string path) {
            var result = new List<Process>();
            uint handle; string key = Guid.NewGuid().ToString();
            if (RmStartSession(out handle, 0, key) != 0) return result;
            try {
                if (RmRegisterResources(handle, 1, new[] { path }, 0, null, 0, null) != 0) return result;
                uint needed = 0, count = 0, reasons = 0;
                RmGetList(handle, out needed, ref count, null, ref reasons);
                if (needed == 0) return result;
                count = needed;
                var infos = new RM_PROCESS_INFO[needed];
                if (RmGetList(handle, out needed, ref count, infos, ref reasons) != 0) return result;
                foreach (var info in infos) {
                    try { result.Add(Process.GetProcessById(info.Process.dwProcessId)); } catch {}
                }
            } finally { RmEndSession(handle); }
            return result;
        }
    }
}
'@ -ErrorAction SilentlyContinue
}

# COM Surrogate など即終了して安全なプロセス名リスト
$script:SafeToKillLockers = @('dllhost', 'SearchIndexer', 'SearchProtocolHost', 'SearchFilterHost')
$script:ProtectedLockerNames = @('powershell', 'pwsh', 'conhost', 'WindowsTerminal')

# ロックしているプロセスを強制開放する内部ヘルパー
function Resolve-FileLock {
    param([string]$Path, [int]$Retry, [int]$MaxRetry)
    $lockers = @()
    try {
        if (([System.Management.Automation.PSTypeName]'FlickFit.FileLocker').Type) {
            $lockers = @([FlickFit.FileLocker]::GetLockingProcesses($Path))
        }
    } catch {}
    if ($lockers.Count -eq 0) { return $false }
    # 自スクリプト・ランチャー・対話シェル系は絶対に終了しない
    $selfPid = $PID
    $protectedPidSet = [System.Collections.Generic.HashSet[int]]::new()
    [void]$protectedPidSet.Add([int]$selfPid)
    if ($LauncherPid -gt 0) {
        [void]$protectedPidSet.Add([int]$LauncherPid)
    }
    $killable = @($lockers | Where-Object {
        $procName = [string]$_.ProcessName
        $isProtectedName = $script:ProtectedLockerNames -contains $procName
        $isProtectedPid = $protectedPidSet.Contains([int]$_.Id)
        (-not $isProtectedName) -and (-not $isProtectedPid)
    })
    $selfLocked = $lockers.Count -gt $killable.Count
    if ($selfLocked) {
        Write-FlickFitHost "      [スクリプト自身がファイルを掴んでいます。GCで解放を試みます...]" -ForegroundColor DarkYellow
        [System.GC]::Collect()
        [System.GC]::WaitForPendingFinalizers()
        Start-Sleep -Milliseconds 300
    }
    if ($killable.Count -eq 0) { return $selfLocked }
    $names = ($killable | ForEach-Object { "$($_.ProcessName)(PID:$($_.Id))" }) -join ', '
    Write-FlickFitHost "      [占有検出] $names がファイルを掴んでいます" -ForegroundColor Yellow
    # dllhost(COM Surrogate)等は即強制終了。それ以外は3回目以降に強制終了
    $safeKill = @($killable | Where-Object { $script:SafeToKillLockers -contains $_.ProcessName })
    $forceKill = $safeKill.Count -gt 0 -or $Retry -ge 3
    if ($forceKill) {
        foreach ($proc in $killable) {
            Write-FlickFitHost "      [強制開放] $($proc.ProcessName) (PID:$($proc.Id)) を終了します..." -ForegroundColor DarkRed
            try { $proc.CloseMainWindow() | Out-Null } catch {}
            try { Stop-Process -Id $proc.Id -Force -ErrorAction SilentlyContinue } catch {}
        }
        Start-Sleep -Milliseconds 500
        return $true
    }
    return $false
}

# ファイルロックを解放して Rename する共通ヘルパー（スクリプト全体で利用）
function Invoke-RenameForceUnlock {
    param([string]$Src, [string]$Dst, [int]$MaxRetry = 6, [int]$WaitMs = 800)
    for ($r = 1; $r -le $MaxRetry; $r++) {
        try {
            Rename-Item -LiteralPath $Src -NewName $Dst -ErrorAction Stop
            return
        } catch [System.IO.IOException] {
            if ($r -ge $MaxRetry) { throw }
            $killed = Resolve-FileLock -Path $Src -Retry $r -MaxRetry $MaxRetry
            if (-not $killed) {
                Write-FlickFitHost "      [リトライ $r/$MaxRetry] ファイル占有中（名前変更）。${WaitMs}ms 待機..." -ForegroundColor DarkYellow
                Start-Sleep -Milliseconds $WaitMs
            }
        }
    }
}

# Remove-Item のロック強制開放版
function Invoke-RemoveForceUnlock {
    param([string]$Path, [int]$MaxRetry = 6, [int]$WaitMs = 800)
    for ($r = 1; $r -le $MaxRetry; $r++) {
        try {
            Remove-Item -LiteralPath $Path -Force -ErrorAction Stop
            return
        } catch [System.IO.IOException] {
            if ($r -ge $MaxRetry) { throw }
            $killed = Resolve-FileLock -Path $Path -Retry $r -MaxRetry $MaxRetry
            if (-not $killed) {
                Write-FlickFitHost "      [リトライ $r/$MaxRetry] ファイル占有中（削除）。${WaitMs}ms 待機..." -ForegroundColor DarkYellow
                Start-Sleep -Milliseconds $WaitMs
            }
        }
    }
}

# STEP1 で選ばれた解凍元アーカイブのフルパス（正規化済み）だけを保持。STEP7 は再解決せず -LiteralPath でこの配列を使う（同名フォルダ・新規CBZとの衝突回避）。
function Set-FlickFitSourceArchivePathsForDeletion {
    param(
        $FromArchives,
        $FromSubfolder
    )
    $set = [System.Collections.Generic.HashSet[string]]::new([StringComparer]::OrdinalIgnoreCase)
    foreach ($coll in @($FromArchives, $FromSubfolder)) {
        if (-not $coll) { continue }
        foreach ($arc in @($coll)) {
            if ($null -eq $arc) { continue }
            $raw = if ($arc -is [string]) { $arc } elseif ($arc -is [System.IO.FileInfo]) { $arc.FullName } else { try { $arc.FullName } catch { try { "$arc" } catch { $null } } }
            if ([string]::IsNullOrWhiteSpace($raw)) { continue }
            $norm = $null
            try { $norm = [System.IO.Path]::GetFullPath($raw).TrimEnd('\') } catch { $norm = $raw.TrimEnd('\') }
            if ($norm) { [void]$set.Add($norm) }
        }
    }
    $script:SourceArchivePathsForStep7Delete = @($set)
}

# STEP7「元ファイル削除」: 解凍元アーカイブ（単一ファイル）のみ。作業フォルダと同名のパスを誤って消さない。通常時は1行要約、詳細は FlickFitDebugSourceArchiveDelete。
function Test-FlickFitPathIsDeletableSourceArchive {
    param([string]$LiteralPath)
    if ([string]::IsNullOrWhiteSpace($LiteralPath)) { return $false }
    if (-not (Test-Path -LiteralPath $LiteralPath)) { return $false }
    if (-not (Test-Path -LiteralPath $LiteralPath -PathType Leaf)) {
        if ($true -eq $script:FlickFitDebugSourceArchiveDelete) {
            Write-FlickFitWarning "[元ファイル削除] パスがファイルではないためスキップ: $LiteralPath"
        }
        return $false
    }
    $ext = [System.IO.Path]::GetExtension($LiteralPath).ToLower()
    if ($script:ArchiveExtensions -notcontains $ext) {
        if ($true -eq $script:FlickFitDebugSourceArchiveDelete) {
            Write-FlickFitWarning "[元ファイル削除] アーカイブ拡張子以外のためスキップ: $LiteralPath (ext=$ext)"
        }
        return $false
    }
    return $true
}

# 追加調整用: 再トリミング候補（本線では出さない。完了後の任意レーン用）
function Add-FlickFitRetrimCandidate {
    param(
        [string]$VolFolder,
        [string]$FilePath,
        [string]$Reason,
        [string]$PageLabel = ''
    )
    if ([string]::IsNullOrWhiteSpace($FilePath)) { return }
    if (-not (Get-Variable -Name FlickFitRetrimCandidates -Scope Script -ErrorAction SilentlyContinue)) { $script:FlickFitRetrimCandidates = [System.Collections.Generic.List[hashtable]]::new() }
    $full = $null; try { $full = [System.IO.Path]::GetFullPath($FilePath).TrimEnd('\') } catch { $full = $FilePath.TrimEnd('\') }
    if (-not $full) { return }
    foreach ($e in $script:FlickFitRetrimCandidates) {
        if ($e['filePath'] -and [string]::Equals([string]$e['filePath'], $full, [StringComparison]::OrdinalIgnoreCase)) { return }
    }
    $h = [ordered]@{
        volFolder = $VolFolder
        filePath  = $full
        fileName  = [System.IO.Path]::GetFileName($full)
        pageLabel = $PageLabel
        reason    = $Reason
        recordedAt = (Get-Date).ToString('s')
    }
    [void]$script:FlickFitRetrimCandidates.Add([hashtable]$h)
}

function Save-FlickFitRetrimCandidatesJson {
    if (-not (Get-Variable -Name FlickFitRetrimCandidates -Scope Script -ErrorAction SilentlyContinue) -or $script:FlickFitRetrimCandidates.Count -eq 0) { return $null }
    $outPath = Join-Path (Get-Location).Path '_retrim_candidates.json'
    $tn = if ((Get-Variable -Name TitleName -Scope Script -ErrorAction SilentlyContinue) -and $script:TitleName) { $script:TitleName } else { '' }
    $obj = [ordered]@{
        version     = 1
        title       = $tn
        createdAt   = (Get-Date).ToString('s')
        candidates  = @($script:FlickFitRetrimCandidates | ForEach-Object { [PSCustomObject]$_ })
    }
    try {
        $obj | ConvertTo-Json -Depth 6 | Set-Content -LiteralPath $outPath -Encoding UTF8
        return $outPath
    } catch { return $null }
}

# 1枚: ノドGUIの結果を balanced 系と同じ Python へ（追加調整専用）
function Invoke-FlickFitRetrimSingleImage {
    param(
        [Parameter(Mandatory)][string]$ImagePath,
        [Parameter(Mandatory)][string]$WorkTrimSplitPy,
        [bool]$RightBinding = $true,
        [double]$AspectMin = 0.0
    )
    if (-not (Test-Path -LiteralPath $ImagePath -PathType Leaf)) { Write-FlickFitWarning "追加調整: ファイルが見つかりません: $ImagePath"; return }
    $dir = [System.IO.Path]::GetDirectoryName($ImagePath)
    if (-not (Get-Command Get-ProcessableFolderImages -ErrorAction SilentlyContinue)) { return }
    $imgs = @(Get-ProcessableFolderImages -FolderPath $dir)
    if ($imgs.Count -eq 0) { return }
    $allPaths = @($imgs | ForEach-Object { $_.FullName })
    $gui = Show-GutterMarginSetGui -ImagePath $ImagePath -Title "追加調整: ノドと余白" -AllImagePaths $allPaths -OkAppliesToCurrentView -ShowApplyThisPageOnlyButton
    if ($null -eq $gui) { Write-FlickFitHost "  （追加調整をキャンセルしました）" -ForegroundColor DarkGray; return }
    if ($gui -is [System.Collections.IDictionary]) { $gui = Normalize-GutterGuiResult -GuiResult $gui }
    $lockBal = Get-FlickFitGutterGuiSplitPathLockedToEntry -EntryPath $ImagePath -GuiResult $gui
    if ($lockBal.Scaled) { $gui = $lockBal.GuiTweak }
    $splitPathB = $lockBal.Path
    $gxBal = Get-HashtableInt -Tbl $gui -Key 'GutterX' -Default (-1)
    if ($gxBal -lt 0) { Write-FlickFitWarning "追加調整: のど位置が取れませんでした"; return }
    $iszBalGui = Get-FlickFitEffectiveInputSizePx -LiteralPath $splitPathB
    $ltB = Get-HashtableInt -Tbl $gui -Key 'LeftTrimPx'
    $rtB = Get-HashtableInt -Tbl $gui -Key 'RightTrimPx'
    $ttB = Get-HashtableInt -Tbl $gui -Key 'TopTrimPx'
    $btB = Get-HashtableInt -Tbl $gui -Key 'BottomTrimPx'
    $gutterXB = $gxBal
    $cwBal = 0; if ($iszBalGui.Width -gt 0) { $cwBal = [Math]::Floor($iszBalGui.Width / 2) }
    $mtOnlyB = Get-HashtableBool -Tbl $gui -Key 'MarginTrimWithoutSplit'
    $effectiveInputPathBal = [string]$splitPathB
    $effectiveInputWidthBal = $iszBalGui.Width
    $effectiveInputHeightBal = $iszBalGui.Height
    try {
        if ($mtOnlyB) {
            $vertBal = Repair-GutterVerticalMargins -ImgH $effectiveInputHeightBal -TopTrim $ttB -BottomTrim $btB
            $null = Invoke-PythonCropGuiMargins -WorkTrimSplitPy $WorkTrimSplitPy -ImagePath $effectiveInputPathBal -RightBinding $RightBinding -LeftTrim $ltB -TopTrim $vertBal.TopTrimPx -RightTrim $rtB -BottomTrim $vertBal.BottomTrimPx
        } elseif ($ltB -gt 0 -or $rtB -gt 0 -or $ttB -gt 0 -or $btB -gt 0) {
            $cohBal = Repair-GutterMarginGeometry -ImgW $effectiveInputWidthBal -GutterX $gutterXB -LeftTrim $ltB -RightTrim $rtB
            $gutterXB = $cohBal.GutterX; $ltB = $cohBal.LeftTrimPx; $rtB = $cohBal.RightTrimPx
            $vertBal2 = Repair-GutterVerticalMargins -ImgH $effectiveInputHeightBal -TopTrim $ttB -BottomTrim $btB
            $ttB = $vertBal2.TopTrimPx; $btB = $vertBal2.BottomTrimPx
            $null = & $script:PythonExe $WorkTrimSplitPy $effectiveInputPathBal $RightBinding.ToString() "split_at_gutter_with_margins" "-" $gutterXB $ltB $rtB $AspectMin $cwBal $ttB $btB 2>&1
        } else {
            $null = & $script:PythonExe $WorkTrimSplitPy $effectiveInputPathBal $RightBinding.ToString() "split_at_gutter" "false" $gutterXB $AspectMin $cwBal "false" "true" 2>&1
        }
    } catch { Write-FlickFitWarning "追加調整: 適用に失敗: $($_.Exception.Message)"; return }
    try { Renumber-Images $dir } catch { }
    Write-FlickFitHost "  ✓ 追加調整を反映しました: $([System.IO.Path]::GetFileName($ImagePath))" -ForegroundColor Green
}

function Invoke-FlickFitOptionalPostRetrimMenu {
    param(
        [Parameter(Mandatory)][string]$WorkTrimSplitPy,
        [bool]$RightBinding = $true,
        [double]$AspectMin = 0.0
    )
    if (-not (Test-Path -LiteralPath $WorkTrimSplitPy)) { Write-FlickFitWarning "追加調整: 作業用 Python が再作成できませんでした"; return }
    if (-not $script:FlickFitRetrimCandidates -or $script:FlickFitRetrimCandidates.Count -eq 0) { return }
    $n = $script:FlickFitRetrimCandidates.Count
    $jsonPath = Save-FlickFitRetrimCandidatesJson
    if ($jsonPath) { Write-FlickFitHost "  候補を記録: _retrim_candidates.json" -ForegroundColor DarkGray }
    Write-FlickFitHost ""
    Write-FlickFitHost "=== 追加調整 ===" -ForegroundColor Cyan
    Write-FlickFitHost "再トリミング候補が $n 枚あります。気になるページだけ仕上げを調整できます。" -ForegroundColor Gray
    $list = [System.Collections.Generic.List[string]]::new()
    # 番号入力で候補からパスを $list へ追加
    $addPathsFromCandidateAnswer = {
        param([string]$Answer)
        foreach ($part in ($Answer -split '[,\s]+' | Where-Object { $_ })) {
            $idx = 0
            if (-not [int]::TryParse($part, [ref]$idx)) { continue }
            if ($idx -ge 0 -and $idx -lt $script:FlickFitRetrimCandidates.Count) {
                $p = [string]$script:FlickFitRetrimCandidates[$idx]['filePath']
                if ($p) { [void]$list.Add($p) }
            }
        }
    }
    $writeCandidateList = {
        for ($i = 0; $i -lt $script:FlickFitRetrimCandidates.Count; $i++) {
            $it = $script:FlickFitRetrimCandidates[$i]
            Write-FlickFitHost "  [$i] $($it['fileName'])  reason=$($it['reason'])" -ForegroundColor White
        }
    }
    # 複数枚: パス入力ループ（A で候補一覧へ切替）
    $readPathsWithOptionalCandidateSwitch = {
        param([string]$BackHint)
        Write-FlickFitHost "  画像のフルパスを1行ずつ入力してください。空行で確定します。" -ForegroundColor DarkGray
        Write-FlickFitHost "  $BackHint" -ForegroundColor DarkGray
        while ($true) {
            $ln = [string](Read-Host "path").Trim()
            if ([string]::IsNullOrWhiteSpace($ln)) { break }
            if ($ln.ToUpperInvariant() -eq 'A' -and $n -gt 1) {
                Write-FlickFitHost "  候補一覧から番号を選びます。" -ForegroundColor Cyan
                & $writeCandidateList
                $ansPick = [string](Read-Host "番号（カンマ区切り、例 0,2。空ならパス入力に戻る）").Trim()
                if (-not [string]::IsNullOrWhiteSpace($ansPick)) {
                    & $addPathsFromCandidateAnswer $ansPick
                    break
                }
                Write-FlickFitHost "  パス入力に戻ります（空行で確定して終了できます）。" -ForegroundColor DarkGray
                continue
            }
            if ($ln.ToUpperInvariant() -eq 'A' -and $n -eq 1) {
                Write-FlickFitHost "  候補が1件のときは、空行で戻って [R]（この候補を再トリミング）を選んでください。" -ForegroundColor DarkYellow
                continue
            }
            if (Test-Path -LiteralPath $ln -PathType Leaf) { [void]$list.Add($ln) } else { Write-FlickFitWarning "  見つかりません: $ln" }
        }
    }
    if ($n -eq 1) {
        Write-FlickFitHost "  [Enter] 終了" -ForegroundColor DarkGray
        Write-FlickFitHost "  [R]     この候補を再トリミング" -ForegroundColor DarkGray
        Write-FlickFitHost "  [P]     別の画像パスを指定" -ForegroundColor DarkGray
        $c = [string](Read-Host "選択 (Enter / R / P)").Trim()
        if ([string]::IsNullOrWhiteSpace($c) -or $c -eq 'Enter') { return }
        if ($c -ieq 'R') {
            $p0 = [string]$script:FlickFitRetrimCandidates[0]['filePath']
            if ($p0) { [void]$list.Add($p0) }
        } elseif ($c -ieq 'P') {
            & $readPathsWithOptionalCandidateSwitch "記録済みの候補で再トリミングする場合は、空行で戻って [R] を選んでください。"
        } else { return }
    } else {
        Write-FlickFitHost "  [Enter] 終了" -ForegroundColor DarkGray
        Write-FlickFitHost "  [A]     候補一覧から選んで再トリミング" -ForegroundColor DarkGray
        Write-FlickFitHost "  [P]     画像パスを直接入力して再トリミング" -ForegroundColor DarkGray
        $c = [string](Read-Host "選択 (Enter / A / P)").Trim()
        if ([string]::IsNullOrWhiteSpace($c) -or $c -eq 'Enter') { return }
        if ($c -ieq 'A') {
            & $writeCandidateList
            $ans = [string](Read-Host "番号（カンマ区切り、例 0,2）").Trim()
            if ([string]::IsNullOrWhiteSpace($ans)) { return }
            & $addPathsFromCandidateAnswer $ans
        } elseif ($c -ieq 'P') {
            & $readPathsWithOptionalCandidateSwitch "候補一覧から選ぶ場合は、一度空行で戻ってメニューで [A] を選ぶか、パス入力中に A と入力してください。"
        } else { return }
    }
    if ($list.Count -eq 0) { return }
    foreach ($p in $list) { Invoke-FlickFitRetrimSingleImage -ImagePath $p -WorkTrimSplitPy $WorkTrimSplitPy -RightBinding $RightBinding -AspectMin $AspectMin }
    Write-FlickFitHost "  ※ 必要ならアーカイブ（CBZ 等）の作り直しを手元で行ってください。" -ForegroundColor DarkGray
}

# [BUG FIX #3] Renumber-Images: クラッシュ復旧機能
function Renumber-Images {
    param([string]$FolderPath)
    $imgs = @(Get-ChildItem -LiteralPath $FolderPath -File -ErrorAction SilentlyContinue | Where-Object { $script:ImageExtensions -contains $_.Extension.ToLower() } | Sort-Object { [regex]::Replace($_.Name, '\d+', { $args[0].Value.PadLeft(10,'0') }) })
    if ($imgs.Count -eq 0) { return }
    # dllhost（エクスプローラーのサムネイル用）がファイルを掴んでいる場合は先に終了してからリネームする
    $dllhosts = @(Get-Process -Name 'dllhost' -ErrorAction SilentlyContinue)
    if ($dllhosts.Count -gt 0) {
        $n = $dllhosts.Count
        Write-FlickFitHost "      画像の並べ替えのため、サムネイル表示用の補助プロセスを $n 件終了します（ファイルのロックを外します）..." -ForegroundColor DarkYellow
        $dllhosts | ForEach-Object { try { Stop-Process -Id $_.Id -Force -ErrorAction SilentlyContinue } catch {} }
        Start-Sleep -Milliseconds 600
    }
    $pad = [math]::Max(3, $imgs.Count.ToString().Length)
    $guid = [Guid]::NewGuid().ToString('N')
    $tmp = "__tmp_${guid}_"
    try {
        if (-not $DryRun) {
            foreach ($img in $imgs) { Invoke-RenameForceUnlock -Src $img.FullName -Dst ($tmp + $img.Name) }
            # 1パス目完了後にGCで残留ハンドルを解放してから2パス目へ
            [System.GC]::Collect()
            [System.GC]::WaitForPendingFinalizers()
            Start-Sleep -Milliseconds 200
            $index = 1
            Get-ChildItem -LiteralPath $FolderPath -File -ErrorAction SilentlyContinue | Where-Object { $_.Name.StartsWith($tmp) } | Sort-Object { [regex]::Replace($_.Name.Substring($tmp.Length), '\d+', { $args[0].Value.PadLeft(10,'0') }) } | ForEach-Object { Invoke-RenameForceUnlock -Src $_.FullName -Dst ("{0:D$pad}{1}" -f $index++, $_.Extension.ToLower()) }
            
            # 最初と最後の画像が重複（同一表紙）かチェックして削除
            $renamedImgs = @(Get-ChildItem -LiteralPath $FolderPath -File -ErrorAction SilentlyContinue | 
                Where-Object { $script:ImageExtensions -contains $_.Extension.ToLower() } | 
                Sort-Object Name)
            if ($renamedImgs.Count -ge 3) {
                $firstImg = $renamedImgs[0]
                $lastImg = $renamedImgs[-1]
                # ファイルサイズが同じ場合、ハッシュで比較
                if ($firstImg.Length -eq $lastImg.Length) {
                    $hash1 = (Get-FileHash -LiteralPath $firstImg.FullName -Algorithm MD5).Hash
                    $hash2 = (Get-FileHash -LiteralPath $lastImg.FullName -Algorithm MD5).Hash
                    if ($hash1 -eq $hash2) {
                        Write-FlickFitHost "      [重複検出]: 最後のファイル '$($lastImg.Name)' は表紙と同一のため削除" -ForegroundColor Yellow
                        Invoke-RemoveForceUnlock -Path $lastImg.FullName
                    }
                }
            }
        }
    } catch {
        Write-FlickFitHost "      [警告]: エラーが発生。復旧中..." -ForegroundColor Yellow
        Get-ChildItem -LiteralPath $FolderPath -File -ErrorAction SilentlyContinue | Where-Object { $_.Name.StartsWith($tmp) } | ForEach-Object { try { Rename-Item -LiteralPath $_.FullName -NewName $_.Name.Substring($tmp.Length) -ErrorAction SilentlyContinue } catch {} }
        throw
    }
}

# Convert-FullWidthToHalfWidth / Get-ChapterNumber / Parse-RangeInput / Parse-ChapterInput → Modules\Utils.ps1・VolumeContext.ps1

# 話数振り分け一覧用（構造解析サマリと同様の注意文言）
function Get-Step2ChapterLeafHint {
    param([string]$Leaf)
    if ([string]::IsNullOrWhiteSpace($Leaf)) { return '' }
    $name = Convert-ZenToHan $Leaf
    if ($name -match '^\s*0*(\d{1,4})\s*(?:\-|~|\u301C|\uFF5E)\s*0*(\d{1,4})\s*$') {
        $ra = [int]$Matches[1]; $rb = [int]$Matches[2]
        if ($ra -gt $rb) { return ' (範囲逆順・要確認)' }
    }
    return ''
}

# coverMap のキーが int / string で混在しても判定（CLIXML 復元や Hashtable の揺れ対策）
function Test-FlickFitCoverMapHasVol {
    param($CoverMap, [int]$Vol)
    if ($null -eq $CoverMap) { return $false }
    if ($CoverMap.ContainsKey($Vol)) {
        $arr = $CoverMap[$Vol]
        return ($null -ne $arr -and @($arr).Count -gt 0)
    }
    $sk = "$Vol"
    if ($CoverMap.ContainsKey($sk)) {
        $arr = $CoverMap[$sk]
        return ($null -ne $arr -and @($arr).Count -gt 0)
    }
    return $false
}

# 親フォルダ名から取れる巻範囲について、表紙と volMap の割り当てがすべて揃っているか（defer→volsNeedingCover 済みなどの二重UI抑止）
function Test-FlickFitChapterParentFullyAssigned {
    param(
        [string]$ParentNameLeaf,
        [hashtable]$VolMap,
        $CoverMap = $null
    )
    if ([string]::IsNullOrWhiteSpace($ParentNameLeaf)) { return $false }
    $cm = if ($null -eq $CoverMap) { $script:coverMap } else { $CoverMap }
    if ($null -eq $VolMap) { return $false }
    $pv = Get-VolFromParentName $ParentNameLeaf
    if (-not ($pv -is [hashtable])) { return $false }
    $pvVol = if ($pv.ContainsKey('Vol')) { $pv['Vol'] } else { $null }
    $pvStart = if ($pv.ContainsKey('Start')) { $pv['Start'] } else { $null }
    $pvEnd = if ($pv.ContainsKey('End')) { $pv['End'] } else { $null }
    if ($null -ne $pvVol -and ($null -eq $pvStart -or $null -eq $pvEnd)) { $pvStart = $pvVol; $pvEnd = $pvVol }
    if ($null -eq $pvStart -or $null -eq $pvEnd) { return $false }
    foreach ($vv in ([int]$pvStart..[int]$pvEnd)) {
        if (-not (Test-FlickFitCoverMapHasVol $cm $vv)) { return $false }
        if (-not $VolMap.ContainsKey($vv) -or $VolMap[$vv].Count -eq 0) { return $false }
    }
    return $true
}

function Test-FlickFitLeafNameChapterLike {
    param([string]$Name)
    if ([string]::IsNullOrWhiteSpace($Name)) { return $false }
    if (Get-Command Ensure-FlickFitVolumePatternRegexes -ErrorAction SilentlyContinue) { Ensure-FlickFitVolumePatternRegexes }
    if ($Name -match $script:FlickFitRegexCoverLeafOrZero -or $Name -match '(?i)^[^\-_]+[-_](#?cover|0)$') { return $false }
    if ($Name -match '(?i)chapter\s*0*\d+(?:\.\d+)?') { return $true }
    if ($Name -match '(?i)chap\s*0*\d+(?:\.\d+)?\s*話?') { return $true }
    if ($Name -match '第\s*0*\d+(?:\.\d+)?\s*話') { return $true }
    if ($Name -match '0*\d+(?:\.\d+)?\s*話') { return $true }
    if ($Name -match '^(\d+(?:\.\d+)?)_files$' -or $Name -match '[-_](\d+(?:\.\d+)?)_files$') { return $true }
    if ($Name -match '^(\d+)$') { return $true }
    return $false
}

# 親フォルダ単位: 表紙候補の表示→（任意で巻範囲入力）→巻ごとに表紙画像→話数フォルダ割当
function Invoke-FlickFitCoverChapterFlowForParent {
    param(
        [string]$NormParent,
        [string]$ParentPath,
        [string]$ParentName,
        [object[]]$Uks,
        [hashtable]$VolMap,
        [Nullable[int]]$PresetVolStart = $null,
        [Nullable[int]]$PresetVolEnd = $null
    )
    if (-not $Uks -or $Uks.Count -eq 0) { return $false }
    if (Get-Command Ensure-FlickFitVolumePatternRegexes -ErrorAction SilentlyContinue) { Ensure-FlickFitVolumePatternRegexes }
    $coverCandidates = @(Get-ChildItem -LiteralPath $ParentPath -Directory -ErrorAction SilentlyContinue | Where-Object {
        $_.Name -match $script:FlickFitRegexCoverUnionOrPad -or $_.Name -notmatch '\d'
    })
    if ($coverCandidates.Count -eq 0 -and $script:detectedCoverFolders.Count -gt 0) {
        $coverCandidates = @($script:detectedCoverFolders | Where-Object { [System.IO.Path]::GetFullPath((Split-Path $_.Path -Parent)) -eq $NormParent } | ForEach-Object { Get-Item -LiteralPath $_.Path -ErrorAction SilentlyContinue })
    }
    $coverVolMap = @{}; $genericCovers = @()
    foreach ($cDir in $coverCandidates) {
        if ($cDir.Name -match '(?i)(?:cover|表紙|カバー)(\d+)') {
            $coverVolMap[[int]$Matches[1]] = $cDir
        } else { $genericCovers += $cDir }
    }
    $firstCoverDir = if ($genericCovers.Count -gt 0) { $genericCovers[0] } elseif ($coverVolMap.Keys.Count -gt 0) { $coverVolMap[($coverVolMap.Keys | Sort-Object)[0]] } else { $null }
    Write-FlickFitHost "`n  [表紙フォルダ] $ParentName" -ForegroundColor Cyan
    if ($coverVolMap.Count -gt 0) {
        foreach ($cv in ($coverVolMap.Keys | Sort-Object)) {
            $cvImgCnt = @(Get-ChildItem -LiteralPath $coverVolMap[$cv].FullName -File -ErrorAction SilentlyContinue | Where-Object { $script:ImageExtensions -contains $_.Extension.ToLower() }).Count
            Write-FlickFitHost "    - $($coverVolMap[$cv].Name) -> 第${cv}巻 ($cvImgCnt 枚)" -ForegroundColor DarkCyan
        }
    }
    if ($genericCovers.Count -gt 0) {
        foreach ($gcDir in $genericCovers) {
            $gcImgCnt = @(Get-ChildItem -LiteralPath $gcDir.FullName -File -ErrorAction SilentlyContinue | Where-Object { $script:ImageExtensions -contains $_.Extension.ToLower() }).Count
            Write-FlickFitHost "    - $($gcDir.Name) -> 全巻共通 ($gcImgCnt 枚)" -ForegroundColor DarkCyan
        }
    }
    if ($firstCoverDir) {
        Write-FlickFitHost "  [表紙フォルダを開いています: $($firstCoverDir.Name)]" -ForegroundColor Gray
        try { Start-Process "explorer.exe" -ArgumentList $firstCoverDir.FullName } catch {}
    } else {
        Write-FlickFitHost "  [表紙フォルダが無いため親フォルダを開きます。表紙画像があれば選択してください]" -ForegroundColor Yellow
        try { Start-Process "explorer.exe" -ArgumentList $ParentPath } catch {}
    }
    if ($null -ne $PresetVolStart -and $null -ne $PresetVolEnd) {
        $pvStart = [int]$PresetVolStart
        $pvEnd = [int]$PresetVolEnd
        if ($pvStart -gt $pvEnd) { $t = $pvStart; $pvStart = $pvEnd; $pvEnd = $t }
        Write-FlickFitHost "`n  巻の範囲: 第 $pvStart 巻 ～ 第 $pvEnd 巻（親フォルダから確定済み）" -ForegroundColor Green
    } else {
        Write-FlickFitHost "`n  振り分けする巻数を設定します（例：3 または 1-5 ※第01巻から第05巻分）" -ForegroundColor Cyan
        $volAns = (Read-HostWithEsc "  巻数").Trim()
        if (-not $volAns -or $volAns -notmatch '^(\d+)(?:\s*[-~]\s*(\d+))?$') { return $false }
        $pvStart = [int]$Matches[1]
        $pvEnd = if ($Matches[2]) { [int]$Matches[2] } else { $pvStart }
        if ($pvStart -gt $pvEnd) { $t = $pvStart; $pvStart = $pvEnd; $pvEnd = $t }
    }
    $chNumToPath = @{}; $chNumDisplay = @{}
    foreach ($uk in $Uks) {
        $nm = Split-Path $uk.Path -Leaf
        $path = $uk.Path
        if ($nm -match '第\s*0*(\d+(?:\.\d+)?)\s*[-~]\s*0*(\d+(?:\.\d+)?)\s*話') {
            $chKey = $Matches[1]; $chNumToPath[$chKey] = $path; $chNumDisplay[$chKey] = "$($Matches[1])-$($Matches[2])"
        } elseif ($nm -match '(?i)chapter\s*0*(\d+(?:\.\d+)?)\s*[-~]\s*0*(\d+(?:\.\d+)?)') {
            $chKey = $Matches[1]; $chNumToPath[$chKey] = $path; $chNumDisplay[$chKey] = "$($Matches[1])-$($Matches[2])"
        } elseif ($nm -match '(?i)chapter\s*0*(\d+(?:\.\d+)?)') {
            $chNumToPath[$Matches[1]] = $path; $chNumDisplay[$Matches[1]] = $Matches[1]
        } elseif ($nm -match '(?i)chap\s*0*(\d+(?:\.\d+)?)\s*話?') {
            $chNumToPath[$Matches[1]] = $path; $chNumDisplay[$Matches[1]] = $Matches[1]
        } elseif ($nm -match '第\s*0*(\d+(?:\.\d+)?)\s*話') {
            $chNumToPath[$Matches[1]] = $path; $chNumDisplay[$Matches[1]] = $Matches[1]
        } elseif ($nm -match '^(\d+(?:\.\d+)?)_files$' -or $nm -match '[-_](\d+(?:\.\d+)?)_files$') {
            $chNumToPath[$Matches[1]] = $path; $chNumDisplay[$Matches[1]] = $Matches[1]
        } elseif ($nm -match '^(\d+)$') {
            $chKey = [string]([double]$nm)
            $chNumToPath[$chKey] = $path
            $chNumDisplay[$chKey] = $nm
        }
    }
    $chNums = @($chNumToPath.Keys | Sort-Object { [double]$_ })
    if ($chNums.Count -eq 0) {
        Write-FlickFitHost "  [スキップ] 話数として解釈できるフォルダ名がありません" -ForegroundColor Yellow
        return $false
    }
    $coverVolMap = @{}; $genericCovers = @()
    foreach ($cDir in $coverCandidates) {
        if ($cDir.Name -match '(?i)(?:cover|表紙|カバー)(\d+)') {
            $coverVolMap[[int]$Matches[1]] = $cDir
        } else { $genericCovers += $cDir }
    }
    $chNumToIndex = @{}; for ($i = 0; $i -lt $chNums.Count; $i++) { $chNumToIndex[$chNums[$i].ToString()] = $i; if ($chNums[$i] -notmatch '\.') { $chNumToIndex[[int]$chNums[$i]] = $i } }
    Write-FlickFitHost "`n  [表紙フォルダ] $ParentName" -ForegroundColor Cyan
    if ($coverVolMap.Count -gt 0) {
        foreach ($cv in ($coverVolMap.Keys | Sort-Object)) {
            $cvImgCnt = @(Get-ChildItem -LiteralPath $coverVolMap[$cv].FullName -File -ErrorAction SilentlyContinue | Where-Object { $script:ImageExtensions -contains $_.Extension.ToLower() }).Count
            Write-FlickFitHost "    - $($coverVolMap[$cv].Name) -> 第${cv}巻 ($cvImgCnt 枚)" -ForegroundColor Gray
        }
    }
    if ($genericCovers.Count -gt 0) {
        foreach ($gcDir in $genericCovers) {
            $gcImgCnt = @(Get-ChildItem -LiteralPath $gcDir.FullName -File -ErrorAction SilentlyContinue | Where-Object { $script:ImageExtensions -contains $_.Extension.ToLower() }).Count
            Write-FlickFitHost "    - $($gcDir.Name) -> 全巻共通 ($gcImgCnt 枚)" -ForegroundColor Gray
        }
    }
    $volIdx = 0
    $volList = @($pvStart..$pvEnd)
    $usedCoverPaths = [System.Collections.Generic.HashSet[string]]::new()
    $usedChapterIndices = [System.Collections.Generic.HashSet[int]]::new()
    $doneDistributing = $false
    while ($volIdx -lt $volList.Count -and -not $doneDistributing) {
        $v = $volList[$volIdx]
        Write-FlickFitHost "`n  -------- 第 $v 巻 --------" -ForegroundColor Cyan
        $currentCoverDir = if ($coverVolMap.ContainsKey($v)) { $coverVolMap[$v] } elseif ($genericCovers.Count -gt 0) { $genericCovers[0] } else { $null }
        if ($currentCoverDir) {
            Write-FlickFitHost "  第 $v 巻の表紙画像を選択してください:" -ForegroundColor Cyan
        } else {
            Write-FlickFitHost "  表紙画像があれば表紙画像を選択してください:" -ForegroundColor Cyan
        }
        $imgSourcePath = if ($currentCoverDir) { $currentCoverDir.FullName } else { $chNumToPath[$chNums[0].ToString()] }
        $allCoverImgs = @(Get-ChildItem -LiteralPath $imgSourcePath -File -ErrorAction SilentlyContinue | Where-Object { $script:ImageExtensions -contains $_.Extension.ToLower() } | Sort-Object { [regex]::Replace($_.Name, '\d+', { $args[0].Value.PadLeft(10,'0') }) })
        $availableCount = @($allCoverImgs | Where-Object { -not $usedCoverPaths.Contains($_.FullName) }).Count
        if ($availableCount -gt 0) {
            for ($i = 0; $i -lt $allCoverImgs.Count; $i++) {
                if (-not $usedCoverPaths.Contains($allCoverImgs[$i].FullName)) { Write-FlickFitHost "    [$($i+1)] $($allCoverImgs[$i].Name)" -ForegroundColor White }
            }
            Write-FlickFitHost "  番号を入力 (例: 1-3)  R:前巻に戻る  空Enter:スキップ" -ForegroundColor DarkGray
            $idxAns = (Read-HostWithEsc "  表紙画像").Trim().ToUpper()
            if ($idxAns -eq 'R' -and $volIdx -gt 0) {
                $prevV = $volList[$volIdx - 1]
                if ($script:coverMap.ContainsKey($prevV)) { foreach ($cp in $script:coverMap[$prevV]) { $usedCoverPaths.Remove($cp) | Out-Null }; $script:coverMap.Remove($prevV) }
                if ($VolMap.ContainsKey($prevV)) {
                    foreach ($chPath in $VolMap[$prevV]) {
                        foreach ($k in $chNumToPath.Keys) { if ($chNumToPath[$k] -eq $chPath) { [void]$usedChapterIndices.Remove($chNumToIndex[$k]); break } }
                    }
                    $VolMap.Remove($prevV)
                    if ($script:volMapFilledByChapterSplit.ContainsKey($prevV)) { $script:volMapFilledByChapterSplit.Remove($prevV) }
                    if ($script:volMapPreserveChapterOrder -and $script:volMapPreserveChapterOrder.Contains($prevV)) { [void]$script:volMapPreserveChapterOrder.Remove($prevV) }
                }
                $volIdx--; continue
            }
            if ($idxAns) {
                $parsedIndices = @(Parse-RangeInput $idxAns $allCoverImgs.Count)
                $validIndices = @($parsedIndices | Where-Object { -not $usedCoverPaths.Contains($allCoverImgs[$_].FullName) })
                if ($validIndices.Count -gt 0) {
                    $covPaths = @($validIndices | ForEach-Object { $allCoverImgs[$_].FullName })
                    foreach ($idx in $validIndices) { $usedCoverPaths.Add($allCoverImgs[$idx].FullName) | Out-Null }
                    $script:coverMap[$v] = $covPaths
                    Write-FlickFitHost "    -> 第 $v 巻: 表紙 $($covPaths.Count) 枚選択" -ForegroundColor Green
                }
            }
        }
        $remainingChNums = @($chNums | Where-Object { -not $usedChapterIndices.Contains($chNumToIndex[$_.ToString()]) })
        if ($remainingChNums.Count -eq 0) { Write-FlickFitHost "  第 $v 巻: 振り分け可能な話数がありません" -ForegroundColor Yellow; $volIdx++; continue }
        Write-FlickFitHost "`n  第 $v 巻に含める話数フォルダを選択してください:" -ForegroundColor Cyan
        foreach ($chNum in $remainingChNums) {
            $dispNum = if ($chNumDisplay.ContainsKey($chNum)) { $chNumDisplay[$chNum] } else { $chNum }
            Write-FlickFitHost "    [$dispNum] $(Split-Path $chNumToPath[$chNum] -Leaf)" -ForegroundColor White
        }
        Write-FlickFitHost "  入力例: 17-25 または 17,18,19  (空:スキップ)  E:振り分け終了" -ForegroundColor DarkGray
        $rangeAns = (Read-HostWithEsc "  入力").Trim().ToUpper()
        if ($rangeAns -eq 'E') { Write-FlickFitHost "  -> 振り分け終了" -ForegroundColor Yellow; $doneDistributing = $true; break }
        if (-not [string]::IsNullOrWhiteSpace($rangeAns)) {
            $indices = Parse-ChapterInput $rangeAns $chNumToIndex
            if ($indices.Count -gt 0) {
                $VolMap[$v] = [System.Collections.Generic.List[string]]::new()
                foreach ($idx in $indices) {
                    if (-not $usedChapterIndices.Contains($idx)) {
                        $VolMap[$v].Add($chNumToPath[$chNums[$idx].ToString()])
                        [void]$usedChapterIndices.Add($idx)
                    }
                }
                $script:volMapFilledByChapterSplit[$v] = $true
                [void]$script:volMapPreserveChapterOrder.Add([int]$v)
                Write-FlickFitHost "    -> 第 $v 巻: $($VolMap[$v].Count) 話を採用" -ForegroundColor Green
            }
        }
        $volIdx++
    }
    if (-not (Get-Variable -Name 'processedChapterParentPaths' -Scope Script -ErrorAction SilentlyContinue)) { $script:processedChapterParentPaths = @{} }
    $script:processedChapterParentPaths[$NormParent] = $true
    return $true
}

# Get-VolContext は Modules\VolumeContext.ps1 のみで定義（Load-Modules または先頭の Modules フォールバックで読込）

function Get-Step2VolLabelPrefix {
    param([psobject]$Ctx)
    if ($Ctx.PSObject.Properties['Vol'] -and $null -ne $Ctx.Vol) {
        return "第 $($Ctx.Vol) 巻 "
    }
    if ($Ctx.PSObject.Properties['VolStart'] -and $Ctx.PSObject.Properties['VolEnd'] -and $null -ne $Ctx.VolStart -and $null -ne $Ctx.VolEnd) {
        if ([int]$Ctx.VolStart -eq [int]$Ctx.VolEnd) { return "第 $($Ctx.VolStart) 巻 " }
        return "第 $($Ctx.VolStart)-$($Ctx.VolEnd) 巻 "
    }
    return ''
}

function Get-Step2StructureLabel {
    param([psobject]$Lc)
    if ($Lc.PSObject.Properties['Step2ManualExclude'] -and $Lc.Step2ManualExclude) {
        return '（この後の処理から除外）'
    }
    $leafName = $Lc.Leaf.Name
    $ctx = $Lc.Ctx
    switch ($ctx.Type) {
        'Single' {
            if ($leafName -match '(?i)chapter\s*0*(\d+(?:\.\d+)?)') { return "第 $($Matches[1]) 話" }
            if ($leafName -match '第\s*0*(\d+(?:\.\d+)?)\s*話') { return "第 $($Matches[1]) 話" }
            if ($leafName -match '(?i)\bv0*(\d{1,3})[sSwWbB]?\s*$') { return "第 $([int]$Matches[1]) 巻" }
            return "第 $($ctx.Vol) 巻"
        }
        'Chapter' {
            $vp = Get-Step2VolLabelPrefix $ctx
            if ($vp) { return "${vp}第 $($ctx.ChNum) 話" }
            return "第 $($ctx.ChNum) 話"
        }
        'ChapterRange' {
            $vp = Get-Step2VolLabelPrefix $ctx
            $s = if ($vp) { "${vp}第 $($ctx.ChStart)-$($ctx.ChEnd) 話" } else { "第 $($ctx.ChStart)-$($ctx.ChEnd) 話" }
            if ($ctx.PSObject.Properties['RangeOrderInvalid'] -and $ctx.RangeOrderInvalid) { $s += " (範囲逆順・要確認)" }
            if ($ctx.PSObject.Properties['OutsideAncestorSpan'] -and $ctx.OutsideAncestorSpan) { $s += " (祖先スパン外・要確認)" }
            return $s
        }
        'Cover' {
            if ($leafName -match '(?i)(cover|表紙|カバー)(\d+)') { return "表紙フォルダ (第$($Matches[2])巻)" }
            return '表紙フォルダ'
        }
        'Range' { return "範囲: $($ctx.Name)" }
        'Special' { return "特別: $($ctx.Suffix)" }
        'Unknown' { return '判定不明' }
        default {
            if ($ctx.Type) { return "($($ctx.Type))" }
            return '判定不明'
        }
    }
}

function Apply-Step2ManualOverride {
    param([psobject]$Lc, [string]$Rhs)
    $leafName = $Lc.Leaf.Name
    $t = Convert-ZenToHan ($Rhs.Trim())
    if ($t -match '^(?i)(x|exclude|除外)$') {
        if ($Lc.PSObject.Properties['Step2ManualExclude']) { $Lc.Step2ManualExclude = $true }
        else { $Lc | Add-Member -NotePropertyName 'Step2ManualExclude' -NotePropertyValue $true -Force }
        return $null
    }
    if ($Lc.PSObject.Properties['Step2ManualExclude']) { $Lc.Step2ManualExclude = $false }
    if ($t -match '^(?i)(cover|表紙)$') {
        $Lc.Ctx = [PSCustomObject]@{ Type='Cover'; Name=$leafName }
        return $null
    }
    if ($t -match '^(?i)(unknown|不明)$') {
        $Lc.Ctx = [PSCustomObject]@{ Type='Unknown'; Name=$leafName }
        return $null
    }
    if ($t -match '^(?i)s\s*[:：]\s*(.+)$') {
        $suf = $Matches[1].Trim()
        if (-not $suf) { return '特別題名が空です' }
        $Lc.Ctx = [PSCustomObject]@{ Type='Special'; Suffix=$suf; Name=$leafName }
        return $null
    }
    if ($t -match '^(\d+)\s*(?i)cr([\d.]+)-([\d.]+)$') {
        $Lc.Ctx = [PSCustomObject]@{ Type='ChapterRange'; ChStart=$Matches[2]; ChEnd=$Matches[3]; Name=$leafName; Vol=[int]$Matches[1] }
        return $null
    }
    if ($t -match '^(?i)cr([\d.]+)-([\d.]+)$') {
        $Lc.Ctx = [PSCustomObject]@{ Type='ChapterRange'; ChStart=$Matches[1]; ChEnd=$Matches[2]; Name=$leafName }
        return $null
    }
    if ($t -match '^(\d+)(?i)c([\d.]+)$') {
        $Lc.Ctx = [PSCustomObject]@{ Type='Chapter'; ChNum=$Matches[2]; Name=$leafName; Vol=[int]$Matches[1] }
        return $null
    }
    if ($t -match '^(?i)c([\d.]+)$') {
        $Lc.Ctx = [PSCustomObject]@{ Type='Chapter'; ChNum=$Matches[1]; Name=$leafName }
        return $null
    }
    if ($t -match '^r(\d+)-(\d+)$') {
        $Lc.Ctx = [PSCustomObject]@{ Type='Range'; Start=[int]$Matches[1]; End=[int]$Matches[2]; Name=$leafName }
        return $null
    }
    if ($t -match '^\d+$') {
        $Lc.Ctx = [PSCustomObject]@{ Type='Single'; Vol=[int]$t; Name=$leafName }
        return $null
    }
    return "解釈できません: $Rhs"
}

# 修正一覧の巻見出し用（Single/Chapter/Range 等から主たる巻番号を取る。無ければ $null）
function Get-Step2ManualReviewPrimaryVol {
    param([psobject]$Lc)
    if (-not $Lc -or -not $Lc.Ctx) { return $null }
    $c = $Lc.Ctx
    if ($c.PSObject.Properties['Vol'] -and $null -ne $c.Vol) {
        try { return [int]$c.Vol } catch { return $null }
    }
    if ($c.Type -eq 'Range' -and $c.PSObject.Properties['VolStart'] -and $null -ne $c.VolStart) {
        try { return [int]$c.VolStart } catch { return $null }
    }
    return $null
}

# 修正一覧: 中間省略。末尾差分（前編/後編等）を見やすくするため、省略時は右側（末尾）の文字数多め
function Invoke-Step2EllipsizeMiddle {
    param([string]$Text, [int]$MaxLen)
    if ([string]::IsNullOrEmpty($Text) -or $Text.Length -le $MaxLen) { return $Text }
    if ($MaxLen -le 3) { return '...' }
    $left = $MaxLen - 3
    $h = [int][Math]::Floor($left * 0.35)
    if ($h -lt 1) { $h = 1 }
    $t = $left - $h
    if ($t -lt 1) { $t = 1; $h = $left - 1; if ($h -lt 1) { $h = 1 } }
    if ($h + $t -ne $left) { $t = $left - $h }
    return $Text.Substring(0, $h) + '...' + $Text.Substring($Text.Length - $t, $t)
}

# 親表示を短く（作品フル名ではなく 第N巻 を優先。マッチしなければ短く中略）
function Get-Step2ManualReviewShortParentDisplay {
    param([string]$ParentName, [int]$MaxFallback = 20)
    if ([string]::IsNullOrWhiteSpace($ParentName)) { return '?' }
    if ($ParentName -match '第[0-9０-９]+巻') { return $Matches[0] }
    if ($ParentName.Length -le $MaxFallback) { return $ParentName }
    return (Invoke-Step2EllipsizeMiddle -Text $ParentName -MaxLen $MaxFallback)
}

# 巻+リーフ1行。全体幅 $MaxChars を超えたら主にリーフを中略（親は 第N巻 等で既に短い想定）
function Get-Step2ManualReviewListMidDisplay {
    param([string]$ParentDisp, [string]$LeafName, [int]$MaxChars = 78)
    $sp = Get-Step2ManualReviewShortParentDisplay -ParentName $ParentDisp
    $lf = if ([string]::IsNullOrWhiteSpace($LeafName)) { '（無名）' } else { $LeafName }
    $sep = ' / '
    $s = $sp + $sep + $lf
    if ($s.Length -le $MaxChars) { return $s }
    $forLeaf = $MaxChars - $sp.Length - $sep.Length
    if ($forLeaf -lt 12) { $sp = (Invoke-Step2EllipsizeMiddle -Text $sp -MaxLen 12); $forLeaf = $MaxChars - $sp.Length - $sep.Length; if ($forLeaf -lt 8) { $forLeaf = 8 } }
    $lf2 = if ($lf.Length -le $forLeaf) { $lf } else { (Invoke-Step2EllipsizeMiddle -Text $lf -MaxLen $forLeaf) }
    return $sp + $sep + $lf2
}

# 一覧・STEP2 処理と同じ並び用の第2キー（前編/後編の入替など）。小さい方が前。
function Get-Step2ManualReviewDisplayTie {
    param($Lc)
    if (-not $Lc) { return 0.0 }
    if ($Lc.PSObject.Properties['Step2DisplayTie']) {
        try { return [double]$Lc.Step2DisplayTie } catch { return 0.0 }
    }
    return 0.0
}

# 行番号<>行番号 の入替: Ctx は触らず Step2DisplayTie だけ。主キーが同一でないと順が意図通りにならない場合あり
function Set-Step2ManualReviewDisplayTie {
    param([psobject]$Lc, [double]$Value)
    if (-not $Lc) { return }
    if ($Lc.PSObject.Properties['Step2DisplayTie']) { $Lc.Step2DisplayTie = $Value }
    else { $Lc | Add-Member -NotePropertyName Step2DisplayTie -NotePropertyValue $Value -Force }
}

function Invoke-Step2ManualSwapDisplayOrder {
    param([psobject]$La, [psobject]$Lb)
    if ($null -eq $La -or $null -eq $Lb) { return '対象が無効です' }
    if ($La -eq $Lb) { return '同じ行同士は指定できません' }
    $ta = Get-Step2ManualReviewDisplayTie -Lc $La
    $tb = Get-Step2ManualReviewDisplayTie -Lc $Lb
    if ([math]::Abs($ta - $tb) -lt 1e-8) { Set-Step2ManualReviewDisplayTie -Lc $Lb -Value ($ta + 0.5); $tb = $ta + 0.5; $ta = Get-Step2ManualReviewDisplayTie -Lc $La }
    $tmpT = (Get-Step2ManualReviewDisplayTie -Lc $La)
    Set-Step2ManualReviewDisplayTie -Lc $La -Value (Get-Step2ManualReviewDisplayTie -Lc $Lb)
    Set-Step2ManualReviewDisplayTie -Lc $Lb -Value $tmpT
    return $null
}

# 巻内ソート用: 特別編・おまけ・番外 等を話数より後ろへ。判定 (Ctx) は変えず表示順のみ。
function Test-Step2LeafNameIsOmakeOrSpecialForSort {
    param($Leaf)
    if (-not $Leaf) { return $false }
    $n = if ($Leaf.PSObject.Properties['Name'] -and $null -ne $Leaf.Name) { [string]$Leaf.Name } else { '' }
    if ([string]::IsNullOrEmpty($n)) { return $false }
    if ($n -match '(?i)特別編|特別[：:２2]|^特別[編篇巻]|[/／\s]特別[編篇]|特別$|特別[２2]|^おまけ|[/／\s]おまけ|番外[編篇話巻]|エクストラ|エキストラ') { return $true }
    if ($n -match '(?i)(?<![A-Za-z0-9_])extra(?![A-Za-z0-9_])|(?<![A-Za-z0-9_])bonus(?![A-Za-z0-9_])') { return $true }
    return $false
}

function Get-Step2ManualReviewSortKey {
    param([psobject]$Lc)
    if (-not $Lc -or -not $Lc.Ctx) { return [double](99999 * 100000.0) }
    $ctx = $Lc.Ctx
    $k = [double]0.0
    switch ($ctx.Type) {
        'Single'  { $k = [double]$ctx.Vol * 100000.0; break }
        'Chapter' {
            $v = if ($ctx.PSObject.Properties['Vol'] -and $null -ne $ctx.Vol) { [double]$ctx.Vol } else { 0.0 }
            $k = $v * 100000.0 + [double]$ctx.ChNum
            break
        }
        'ChapterRange' {
            $v = if ($ctx.PSObject.Properties['Vol'] -and $null -ne $ctx.Vol) { [double]$ctx.Vol } else { 0.0 }
            $k = $v * 100000.0 + [double]$ctx.ChStart
            break
        }
        'Range' {
            $v = if ($ctx.PSObject.Properties['VolStart'] -and $null -ne $ctx.VolStart) { [double]$ctx.VolStart } else { 99990.0 }
            $k = $v * 100000.0
            break
        }
        'Cover'   { $k = 99992.0 * 100000.0; break }
        'Special' { $k = 99993.0 * 100000.0; break }
        default   { $k = 99999.0 * 100000.0; break }
    }
    if ($script:FlickFitDisableOmakeEndOfVolSort) { return $k }
    if ($ctx.Type -eq 'Cover' -or $ctx.Type -eq 'Special') { return $k }
    $pv = Get-Step2ManualReviewPrimaryVol $Lc
    if ($null -eq $pv) { return $k }
    if (-not (Test-Step2LeafNameIsOmakeOrSpecialForSort -Leaf $Lc.Leaf)) { return $k }
    $base = [double]$pv * 100000.0
    if ($k -le ($base + 49999.0)) { $k = $base + 50000.0 }
    $nm = if ($Lc.Leaf -and $Lc.Leaf.PSObject.Properties['Name']) { [string]$Lc.Leaf.Name } else { '' }
    if (-not [string]::IsNullOrEmpty($nm)) {
        $h = 0
        $bytes = [System.Text.Encoding]::UTF8.GetBytes($nm)
        foreach ($b in $bytes) { $h = ($h * 31 + $b) -band 0x7FFFFFFF }
        $k += [double]($h % 8000) / 10000000.0
    }
    return $k
}

# 一覧の並び（主キー＋Step2DisplayTie＋リーフ名）を $LeafContexts の要素順に反映（STEP2 本処理の iterate 順と一致させる）
function Sync-Step2LeafContextsToManualDisplayOrder {
    param(
        [System.Collections.Generic.List[PSObject]]$LeafContexts,
        [hashtable]$ByParent,
        [string[]]$ParentNames,
        $NaturalSort
    )
    if (-not $LeafContexts -or $LeafContexts.Count -eq 0) { return }
    $allLcs = [System.Collections.Generic.List[PSObject]]::new()
    foreach ($pp in $ParentNames) {
        if (-not $ByParent.ContainsKey($pp)) { continue }
        foreach ($lc in (@($ByParent[$pp] | Sort-Object $NaturalSort))) { [void]$allLcs.Add($lc) }
    }
    $leafTie = { [regex]::Replace($_.Leaf.Name, '\d+', { $args[0].Value.PadLeft(10,'0') }) }
    $sorted = $allLcs | Sort-Object { Get-Step2ManualReviewSortKey $_ }, { Get-Step2ManualReviewDisplayTie $_ }, $leafTie
    $LeafContexts.Clear()
    foreach ($x in $sorted) { [void]$LeafContexts.Add($x) }
}

# フルパス -> leafContexts 上の序（Step2 巻候補・話数候補の並びに使用。手動<>の前後入替を継承）
function Get-Step2LeafPathOrderRank {
    param([string]$Path)
    if ([string]::IsNullOrEmpty($Path)) { return [int]::MaxValue }
    $p = $null
    try { $p = [System.IO.Path]::GetFullPath($Path).TrimEnd('\') } catch { $p = $Path.TrimEnd('\') }
    if ($script:Step2LeafPathOrder -and $script:Step2LeafPathOrder.ContainsKey($p)) { return [int]$script:Step2LeafPathOrder[$p] }
    return [int]::MaxValue
}

function Invoke-Step2StructureManualReview {
    param([System.Collections.Generic.List[PSObject]]$LeafContexts)
    if (-not $LeafContexts -or $LeafContexts.Count -eq 0) { return }
    $naturalSort = { [regex]::Replace($_.Leaf.Name, '\d+', { $args[0].Value.PadLeft(10,'0') }) }
    $byParentLocal = @{}
    foreach ($lc in $LeafContexts) {
        $parentPath = Split-Path $lc.Leaf.Path -Parent
        if (-not $byParentLocal.ContainsKey($parentPath)) { $byParentLocal[$parentPath] = [System.Collections.ArrayList]::new() }
        [void]$byParentLocal[$parentPath].Add($lc)
    }
    $parentNamesLocal = @(
        $byParentLocal.Keys | ForEach-Object { [PSCustomObject]@{ Path=$_; Name=(Split-Path $_ -Leaf) } } |
            Sort-Object { [regex]::Replace($_.Name, '\d+', { $args[0].Value.PadLeft(10,'0') }) } |
            ForEach-Object { $_.Path }
    )
    while ($true) {
        $flat = [System.Collections.Generic.List[PSObject]]::new()
        $allLcsUnsorted = [System.Collections.Generic.List[PSObject]]::new()
        foreach ($pp in $parentNamesLocal) {
            foreach ($lc in (@($byParentLocal[$pp] | Sort-Object $naturalSort))) { [void]$allLcsUnsorted.Add($lc) }
        }
        # 巻番号昇順＋前編/後編などの行入替(Step2DisplayTie)＋リーフ名（不明・手動特別・表紙は末尾。特別層は Get-Step2ManualReviewSortKey）
        $leafTieSort = { [regex]::Replace($_.Leaf.Name, '\d+', { $args[0].Value.PadLeft(10,'0') }) }
        $sortedLcs = $allLcsUnsorted | Sort-Object { Get-Step2ManualReviewSortKey $_ }, { Get-Step2ManualReviewDisplayTie $_ }, $leafTieSort
        foreach ($lc in $sortedLcs) { [void]$flat.Add($lc) }
        Write-FlickFitHost "`n  [構造解析サマリ・修正用一覧] 左の番号を修正入力で指定します（巻番号昇順）" -ForegroundColor Cyan
        Write-FlickFitHost "    形式: 第N巻 / リーフ名  (画像枚数)  ->  自動判定  ※作品名は短縮・極端に長いリーフは中略" -ForegroundColor DarkGray
        $nr = 1
        $prevGroupKey = [string]$null
        foreach ($lc in $flat) {
            $pv = Get-Step2ManualReviewPrimaryVol $lc
            $gk = if ($null -ne $pv) { "v$pv" } else { 'other' }
            if ($gk -ne $prevGroupKey) {
                if ($null -ne $pv) {
                    Write-FlickFitHost ("  -- 第 {0} 巻 --" -f $pv) -ForegroundColor DarkCyan
                } else {
                    Write-FlickFitHost "  -- （巻番号なし・表紙・特別・不明など） --" -ForegroundColor DarkCyan
                }
                $prevGroupKey = $gk
            }
            $bookParent = Split-Path $lc.Leaf.Path -Parent
            $parentDisp = Split-Path $bookParent -Leaf
            if ([string]::IsNullOrWhiteSpace($parentDisp)) { $parentDisp = $bookParent }
            $leafOnly = $lc.Leaf.Name
            $imgCnt = 0
            try {
                $imgCnt = @(Get-ChildItem -LiteralPath $lc.Leaf.Path -File -ErrorAction SilentlyContinue |
                    Where-Object { $script:ImageExtensions -contains $_.Extension.ToLower() }).Count
            } catch {}
            $mid = Get-Step2ManualReviewListMidDisplay -ParentDisp $parentDisp -LeafName $leafOnly
            $label = Get-Step2StructureLabel $lc
            $lineColor = if ($lc.PSObject.Properties['Step2ManualExclude'] -and $lc.Step2ManualExclude) { 'DarkGray' }
                elseif ($lc.Ctx.Type -eq 'Cover') { 'DarkCyan' } elseif ($lc.Ctx.Type -eq 'Special') { 'Magenta' }
                elseif ($lc.Ctx.Type -eq 'Unknown') { 'Yellow' } else { 'White' }
            Write-FlickFitHost ("  {0,3}  {1,-78}  ({2,4}枚)  ->  {3}" -f $nr, $mid, $imgCnt, $label) -ForegroundColor $lineColor
            $nr++
        }
        Write-FlickFitHost "  ※ Enter のあと、巻番号が取れないフォルダでは「親フォルダ名から一括[P]」や親名自動判定で振り分けできます" -ForegroundColor DarkGray
        Write-FlickFitHost "  ※ 誤検知が多い場合にはフォルダ名の食い違いや、曖昧な表記が多い為、解凍後のファイルを手動で整理することをお勧めします" -ForegroundColor DarkGray
        $ans = Read-HostWithEsc "  この一覧の巻番号割り当てを修正しますか？ [Enter=そのまま次へ / y=番号を指定して修正]"
        if ($ans -notmatch '^[yY]') {
            Sync-Step2LeafContextsToManualDisplayOrder -LeafContexts $LeafContexts -ByParent $byParentLocal -ParentNames $parentNamesLocal -NaturalSort $naturalSort
            return
        }
        Write-FlickFitHost "  入力例:  3=5 →第5巻  |  4=c12 →第12話  |  5=01c1 →1巻1話  |  6=cover  |  7=x 除外  |  8=unknown  |  9=s:おまけ  |  10=cr1-5 話範囲  |  11=2cr1-5 2巻で1-5話" -ForegroundColor DarkGray
        Write-FlickFitHost "  12<>13 →同じ巻・話分類内で行の前後を入替（巻・話 Ctx は変えない）" -ForegroundColor DarkGray
        Write-FlickFitHost "  複数は ; で区切り（例 1=2; 3=cover; 2<>3）  空Enterで一覧を更新" -ForegroundColor DarkGray
        while ($true) {
            $line = Read-HostWithEsc "  修正（空Enterで一覧に戻る）"
            if ([string]::IsNullOrWhiteSpace($line)) { break }
            $segments = @($line -split '\s*;\s*' | Where-Object { -not [string]::IsNullOrWhiteSpace($_) })
            foreach ($seg in $segments) {
                $st = $seg.Trim()
                if ($st -match '^\s*(\d+)\s*<>\s*(\d+)\s*$') {
                    $iA = [int]$Matches[1]
                    $iB = [int]$Matches[2]
                    if ($iA -lt 1 -or $iA -gt $flat.Count -or $iB -lt 1 -or $iB -gt $flat.Count) {
                        Write-FlickFitHost "  行番号が範囲外: $iA<>$iB （1～$($flat.Count)）" -ForegroundColor Yellow
                        continue
                    }
                    $la = $flat[$iA - 1]
                    $lb = $flat[$iB - 1]
                    $errSw = Invoke-Step2ManualSwapDisplayOrder -La $la -Lb $lb
                    if ($errSw) { Write-FlickFitHost "  [$iA<>$iB] $errSw" -ForegroundColor Yellow; continue }
                    try {
                        $ka = [double](Get-Step2ManualReviewSortKey $la)
                        $kb = [double](Get-Step2ManualReviewSortKey $lb)
                        if ([math]::Abs($ka - $kb) -gt 0.1) { Write-FlickFitHost "  [注意] 主キー（巻・話）が大きく異なります。違う話の行を入替えた可能性があります。空Enterで一覧を更新し確認してください。" -ForegroundColor DarkYellow }
                    } catch {}
                    Write-FlickFitHost "  [${iA}<>${iB}] 表示順（および以降のSTEP2の処理順）を入れ替えました" -ForegroundColor Green
                    continue
                }
                if ($st -notmatch '^\s*(\d+)\s*=\s*(.+)$') {
                    if ($st -match '[,，]') {
                        Write-FlickFitHost "  入力形式が正しくありません。複数の指定は セミコロン `;` だけ区切りにしてください（カンマ `,` は使えません）" -ForegroundColor Yellow
                        Write-FlickFitHost "  例: 2<>3;4<>5" -ForegroundColor DarkGray
                    } else {
                        Write-FlickFitHost "  スキップ（番号=値 または 行<>行 ではありません）: $st" -ForegroundColor Yellow
                    }
                    continue
                }
                $idx = [int]$Matches[1]
                $rhs = $Matches[2].Trim()
                if ($idx -lt 1 -or $idx -gt $flat.Count) {
                    Write-FlickFitHost "  行番号が範囲外: $idx （1～$($flat.Count)）" -ForegroundColor Yellow
                    continue
                }
                $targetLc = $flat[$idx - 1]
                $err = Apply-Step2ManualOverride -Lc $targetLc -Rhs $rhs
                if ($err) { Write-FlickFitHost "  [$idx] $err" -ForegroundColor Yellow }
                else { Write-FlickFitHost "  [$idx] 更新しました ($rhs)" -ForegroundColor Green }
            }
        }
    }
}

# [BUG FIX #7] 表紙トリミング: シンプル版
function Invoke-CoverCrop {
    param([string]$ImagePath, [string]$TmpCropPy)
    if (-not $script:PythonExe) { return }
    $aspect = Get-ImageAspect $ImagePath
    if ($aspect -le 0) { Write-FlickFitHost "    [スキップ]: 無効な画像 ($(Split-Path $ImagePath -Leaf))" -ForegroundColor Yellow; return }
    Write-FlickFitHost "    [表紙加工]: トリミング判定中... ($(Split-Path $ImagePath -Leaf))" -ForegroundColor Gray
    $previewImg = Join-Path (Get-FlickFitScratchTempDir) ("preview_crop_" + [Guid]::NewGuid().ToString('N') + [System.IO.Path]::GetExtension($ImagePath))
    try {
        Copy-Item -LiteralPath $ImagePath -Destination $previewImg -Force
        $res = (& $script:PythonExe $TmpCropPy $previewImg $MaxCoverHeight 2>&1) -join ""
        if ($res -match 'CROPPED:') {
            Write-FlickFitHost "      -> 自動トリミング完了" -ForegroundColor DarkGray
            # トリミングされた場合は確認が必要
            Invoke-Item -LiteralPath $previewImg
            Write-FlickFitHost "    [Y/Enter] 採用  [N] キャンセル  ※編集する場合はフォトで編集→保存後にY" -ForegroundColor DarkGray
            $ans = Read-HostWithEsc "    [確認]"
            if ($ans -match '^[nN]$') {
                Write-FlickFitHost "      -> キャンセル。" -ForegroundColor DarkGray
            } else {
                Copy-Item -LiteralPath $previewImg -Destination $ImagePath -Force
                Write-FlickFitHost "      -> 採用しました。" -ForegroundColor Green
            }
        } else {
            Write-FlickFitHost "      -> トリミング不要（自動採用）" -ForegroundColor DarkGray
            # トリミング不要の場合は確認スキップ（元のままなので何もしない）
        }
    }
    catch {
        Write-FlickFitHost "      -> [エラー]: $($_.Exception.Message)" -ForegroundColor Red
    }
    finally {
        try { Remove-Item -LiteralPath $previewImg -Force -ErrorAction SilentlyContinue } catch {}
    }
}
#endregion

#region Execution routes (split width)
# 役割:
#   分割幅確認の実行フローと Route 呼び出しをまとめる。
# 主役:
#   Invoke-SplitWidthValidation
# 注意:
#   判定は Get-FlickFitSplitWidthDecision 側に寄せる。ここは GUI・ファイル・Complete-*・Invoke-FlickFitSplitWidthDecision。
# 分割幅チェック時: コンソールログ相当の説明＋画像（見開き・左右）を同一画面で確認して選択
function Show-SplitWidthValidationDialog {
    param(
        [string]$Caption = "分割幅の確認",
        [string]$SummaryText = '',
        [string]$BackupPath = '',
        [string]$SplitPath1 = '',
        [string]$SplitPath2 = '',
        [string]$OrigPath = '',
        [Parameter(Mandatory)][ValidateSet('YesNoTrash', 'YesNoBase', 'Main', 'Detail')]
        [string]$Kind
    )
    if ($script:FolderAutoTimer -and $script:FolderAutoTimer.Enabled -and $script:FolderAutoTimer.Stopwatch.IsRunning) {
        $script:FolderAutoTimer.Stopwatch.Stop()
        $prevMs = $script:FolderAutoTimer.ElapsedMs; if ($null -eq $prevMs) { $prevMs = 0 }
        $script:FolderAutoTimer.ElapsedMs = $prevMs + $script:FolderAutoTimer.Stopwatch.ElapsedMilliseconds
    }
    try {
        Add-Type -AssemblyName System.Windows.Forms -ErrorAction Stop | Out-Null
        Add-Type -AssemblyName System.Drawing -ErrorAction Stop | Out-Null
    } catch { return $null }

    $heldStreams = [System.Collections.Generic.List[System.IDisposable]]::new()
    $mkPbTab = {
        param([string]$TabLabel, [string]$ImgPath)
        $tp = New-Object System.Windows.Forms.TabPage
        $tp.Text = $TabLabel
        $tp.UseVisualStyleBackColor = $true
        $pbx = New-Object System.Windows.Forms.PictureBox
        $pbx.Dock = [System.Windows.Forms.DockStyle]::Fill
        $pbx.SizeMode = [System.Windows.Forms.PictureBoxSizeMode]::Zoom
        $pbx.BackColor = [System.Drawing.Color]::FromArgb(220, 220, 220)
        if ($ImgPath -and (Test-Path -LiteralPath $ImgPath)) {
            try {
                $bytes = [System.IO.File]::ReadAllBytes((Resolve-Path -LiteralPath $ImgPath).Path)
                $ms = New-Object System.IO.MemoryStream(,$bytes)
                [void]$heldStreams.Add($ms)
                $pbx.Image = [System.Drawing.Image]::FromStream($ms)
            } catch {
                $lbl = New-Object System.Windows.Forms.Label
                $lbl.Text = "画像を読み込めませんでした`r`n$ImgPath"
                $lbl.Dock = "Fill"
                $lbl.TextAlign = [System.Drawing.ContentAlignment]::MiddleCenter
                [void]$tp.Controls.Add($lbl)
                return $tp
            }
        } else {
            $lbl = New-Object System.Windows.Forms.Label
            $lbl.Text = if ($ImgPath) { "ファイルがありません`r`n$ImgPath" } else { "（画像パスなし）" }
            $lbl.Dock = "Fill"
            $lbl.TextAlign = [System.Drawing.ContentAlignment]::MiddleCenter
            [void]$tp.Controls.Add($lbl)
            return $tp
        }
        [void]$tp.Controls.Add($pbx)
        return $tp
    }

    $out = @{ Value = '' }
    $form = New-Object System.Windows.Forms.Form
    $form.Text = $Caption
    $form.Size = New-Object System.Drawing.Size(920, 720)
    $form.StartPosition = [System.Windows.Forms.FormStartPosition]::CenterScreen
    $form.MinimizeBox = $false
    $form.KeyPreview = $true

    # TableLayoutPanel で行高を固定（SplitContainer+FixedPanel だと Panel2 が潰れてボタンが見えない環境がある）
    $rootTlp = New-Object System.Windows.Forms.TableLayoutPanel
    $rootTlp.Dock = [System.Windows.Forms.DockStyle]::Fill
    $rootTlp.ColumnCount = 1
    $rootTlp.RowCount = 3
    [void]$rootTlp.ColumnStyles.Add((New-Object System.Windows.Forms.ColumnStyle([System.Windows.Forms.SizeType]::Percent, 100)))
    [void]$rootTlp.RowStyles.Add((New-Object System.Windows.Forms.RowStyle([System.Windows.Forms.SizeType]::Percent, 50)))
    [void]$rootTlp.RowStyles.Add((New-Object System.Windows.Forms.RowStyle([System.Windows.Forms.SizeType]::Percent, 28)))
    [void]$rootTlp.RowStyles.Add((New-Object System.Windows.Forms.RowStyle([System.Windows.Forms.SizeType]::Absolute, 172)))

    $tabs = New-Object System.Windows.Forms.TabControl
    $tabs.Dock = [System.Windows.Forms.DockStyle]::Fill
    $bpUse = if ($BackupPath -and (Test-Path -LiteralPath $BackupPath)) { $BackupPath } elseif ($OrigPath -and (Test-Path -LiteralPath $OrigPath)) { $OrigPath } else { '' }
    [void]$tabs.TabPages.Add((& $mkPbTab "見開き・バックアップ" $bpUse))
    [void]$tabs.TabPages.Add((& $mkPbTab "左ページ (_1等)" $SplitPath1))
    [void]$tabs.TabPages.Add((& $mkPbTab "右ページ (_2等)" $SplitPath2))

    $btnPanel = New-Object System.Windows.Forms.Panel
    $btnPanel.Dock = [System.Windows.Forms.DockStyle]::Fill
    $btnPanel.Padding = New-Object System.Windows.Forms.Padding(4, 2, 4, 6)
    $btnPanel.BackColor = [System.Drawing.SystemColors]::Control

    $flow = New-Object System.Windows.Forms.FlowLayoutPanel
    $flow.Dock = [System.Windows.Forms.DockStyle]::Fill
    $flow.Padding = New-Object System.Windows.Forms.Padding(4, 4, 4, 4)
    $flow.AutoScroll = $true
    $flow.WrapContents = $true
    $flow.FlowDirection = [System.Windows.Forms.FlowDirection]::LeftToRight
    $mkBtn = {
        param([string]$Label, [string]$Val)
        $b = New-Object System.Windows.Forms.Button
        $b.Text = $Label
        $b.AutoSize = $true
        $b.MinimumSize = New-Object System.Drawing.Size(120, 32)
        $b.Margin = New-Object System.Windows.Forms.Padding(6, 6, 6, 6)
        $b.UseVisualStyleBackColor = $true
        $b.TabStop = $true
        $vLoc = $Val
        $b.Add_Click({
            $out.Value = $vLoc
            $form.Close()
        })
        return $b
    }
    $btnAccept = $null
    if ($Kind -eq 'YesNoTrash') {
        $btnAccept = & $mkBtn "はい — 削除して次へ (Y / Enter)" "Y"
        [void]$flow.Controls.Add($btnAccept)
        [void]$flow.Controls.Add((& $mkBtn "いいえ (n)" "n"))
    } elseif ($Kind -eq 'YesNoBase') {
        $btnAccept = & $mkBtn "はい — この幅を基準に採用 (Y / Enter)" "Y"
        [void]$flow.Controls.Add($btnAccept)
        [void]$flow.Controls.Add((& $mkBtn "いいえ (n)" "n"))
    } elseif ($Kind -eq 'Main') {
        $btnAccept = & $mkBtn "[1] 採用 (Enter)" "1"
        [void]$flow.Controls.Add($btnAccept)
        [void]$flow.Controls.Add((& $mkBtn "[2] ノド位置をGUIで調整" "2"))
        [void]$flow.Controls.Add((& $mkBtn "[3] 詳細メニュー" "3"))
        [void]$flow.Controls.Add((& $mkBtn "[4] 以降同じ処理を自動選択（採用）" "4"))
        [void]$flow.Controls.Add((& $mkBtn "[D] この画像を削除" "D"))
    } else {
        $btnAccept = & $mkBtn "[1] 採用 (Enter)" "1"
        [void]$flow.Controls.Add($btnAccept)
        [void]$flow.Controls.Add((& $mkBtn "[2] 手動で左右をトリミング（フォト）" "2"))
        [void]$flow.Controls.Add((& $mkBtn "[3] ノド位置の再選択（GUI）" "3"))
        [void]$flow.Controls.Add((& $mkBtn "[4] 余白のみトリミング（分割なし）" "4"))
        [void]$flow.Controls.Add((& $mkBtn "[5] 削除" "5"))
    }
    if ($null -ne $btnAccept) { $form.AcceptButton = $btnAccept }
    [void]$btnPanel.Controls.Add($flow)

    $txt = New-Object System.Windows.Forms.TextBox
    $txt.Multiline = $true
    $txt.ReadOnly = $true
    $txt.ScrollBars = [System.Windows.Forms.ScrollBars]::Vertical
    $txt.Dock = [System.Windows.Forms.DockStyle]::Fill
    $txt.Font = New-Object System.Drawing.Font("Consolas", 9)
    $txt.Text = if ($SummaryText) { $SummaryText } else { "（説明テキストなし）" }
    $txt.TabStop = $false
    [void]$rootTlp.Controls.Add($tabs, 0, 0)
    [void]$rootTlp.Controls.Add($txt, 0, 1)
    [void]$rootTlp.Controls.Add($btnPanel, 0, 2)

    $form.Add_KeyDown({
        param($_, $ke)
        if ($ke.KeyCode -eq [System.Windows.Forms.Keys]::Escape) {
            $ke.Handled = $true
            $ke.SuppressKeyPress = $true
            $out.Value = '__ESC__'
            $form.Close()
            return
        }
        if ($ke.Alt -or $ke.Control) { return }
        $kc = $ke.KeyCode
        $set = {
            param([string]$v)
            $out.Value = $v
            $ke.Handled = $true
            $ke.SuppressKeyPress = $true
            $form.Close()
        }
        if ($Kind -eq 'YesNoTrash' -or $Kind -eq 'YesNoBase') {
            if ($kc -eq [System.Windows.Forms.Keys]::Y) { & $set 'Y' }
            elseif ($kc -eq [System.Windows.Forms.Keys]::N) { & $set 'n' }
            return
        }
        if ($Kind -eq 'Main') {
            if ($kc -eq [System.Windows.Forms.Keys]::D1 -or $kc -eq [System.Windows.Forms.Keys]::NumPad1) { & $set '1' }
            elseif ($kc -eq [System.Windows.Forms.Keys]::D2 -or $kc -eq [System.Windows.Forms.Keys]::NumPad2) { & $set '2' }
            elseif ($kc -eq [System.Windows.Forms.Keys]::D3 -or $kc -eq [System.Windows.Forms.Keys]::NumPad3) { & $set '3' }
            elseif ($kc -eq [System.Windows.Forms.Keys]::D4 -or $kc -eq [System.Windows.Forms.Keys]::NumPad4) { & $set '4' }
            elseif ($kc -eq [System.Windows.Forms.Keys]::D) { & $set 'D' }
            return
        }
        if ($Kind -eq 'Detail') {
            if ($kc -eq [System.Windows.Forms.Keys]::D1 -or $kc -eq [System.Windows.Forms.Keys]::NumPad1) { & $set '1' }
            elseif ($kc -eq [System.Windows.Forms.Keys]::D2 -or $kc -eq [System.Windows.Forms.Keys]::NumPad2) { & $set '2' }
            elseif ($kc -eq [System.Windows.Forms.Keys]::D3 -or $kc -eq [System.Windows.Forms.Keys]::NumPad3) { & $set '3' }
            elseif ($kc -eq [System.Windows.Forms.Keys]::D4 -or $kc -eq [System.Windows.Forms.Keys]::NumPad4) { & $set '4' }
            elseif ($kc -eq [System.Windows.Forms.Keys]::D5 -or $kc -eq [System.Windows.Forms.Keys]::NumPad5) { & $set '5' }
        }
    })
    $form.Add_FormClosed({
        if ([string]::IsNullOrWhiteSpace($out.Value)) { $out.Value = '__ESC__' }
        if ($script:FolderAutoTimer -and $script:FolderAutoTimer.Enabled) { $script:FolderAutoTimer.Stopwatch.Restart() }
        foreach ($tp in $tabs.TabPages) {
            foreach ($c in $tp.Controls) {
                if ($c -is [System.Windows.Forms.PictureBox] -and $null -ne $c.Image) {
                    try { $c.Image.Dispose(); $c.Image = $null } catch {}
                }
            }
        }
        foreach ($d in $heldStreams) { try { $d.Dispose() } catch {} }
        $heldStreams.Clear()
    })

    [void]$form.Controls.Add($rootTlp)
    try {
        [void]$form.ShowDialog()
    } catch { }
    if ($out.Value -eq '__ESC__') { throw "中断: ESCキーが押されました" }
    return [string]$out.Value
}

<#
  分割幅検証の戻り文字列（Invoke-SplitWidthValidation → 呼び出し側の -eq 分岐）。typo 防止のため一覧のみここに固定。
  値: ok | delete | set_new_cover | adopt | gutter_reselect | trim_only | retry
  将来: 分岐を $script:FlickFitSplitWidthOutcomeCode のプロパティ参照に寄せる、または enum 相当の閉じた集合にする。
  関連 $script: 状態（GUI直後だけでなく次画像に残り得る）: SplitWidthGuiPresetResult, SplitWidthLastConfirmedByFolder,
  SplitWidthNewCoverCandidate, SplitWidthApplyGutterOnlyThisPage, SplitWidthSkipRepeatGuiApplyOnlyThisPage 等。経路ごとにクリア方針を決めると安全。
  フォルダキャッシュ vs 前回OKの再利用分岐: Get-FlickFitReuseDecision（Kind は $script:FlickFitReuseKind*。内部で Test-FlickFitSplitWidthParamsIdentical / Test-FlickFitSplitWidthParamsReuse）。
  実行寄りの早期終了・削除・set_new_cover・gutter_reselect 準備（PrepareGutter*）・trim/retry 等: Invoke-FlickFitSplitWidthDecision（Complete-* 直前の寄せ先。段階的に拡張）。
#>
# Invoke-SplitWidthValidation の終了を1か所に記録（呼び出し側は従来どおり文字列）。$script:SplitWidthValidationLastOutcome で直近の code / preset 有無を参照可能
function Complete-FlickFitSplitWidthValidation {
    param(
        [Parameter(Mandatory)][string]$Code,
        [string]$ImgName = '',
        [string]$GutterCacheFolderKey = ''
    )
    $presetNonNull = $false
    if ((Get-Variable -Name SplitWidthGuiPresetResult -Scope Script -ErrorAction SilentlyContinue) -and $null -ne $script:SplitWidthGuiPresetResult) {
        $presetNonNull = $true
    }
    $script:SplitWidthValidationLastOutcome = [PSCustomObject]@{
        Code = $Code
        At = (Get-Date).ToString('s')
        ImgName = $ImgName
        GutterCacheFolderKey = $GutterCacheFolderKey
        SplitWidthGuiPresetResultNonNull = $presetNonNull
    }
    if (-not ($true -eq $script:FlickFitObsDisable) -and ($true -eq $script:FlickFitDebugStep5Verbose)) {
        Write-FlickFitHost "[SplitWidthVal] code=$Code img=$ImgName folderKey=$GutterCacheFolderKey presetNonNull=$presetNonNull" -ForegroundColor DarkGray
    }
    return $Code
}

# 分割幅: $swDec 等を受け Complete-* 直前の「実行だけ」を寄せる（判定は Get-FlickFitSplitWidthDecision）。
# gutter_reselect: Prepare*＝プリセット・LastConfirmed・メッセージ等の直前準備〜Complete。メインのノドGUI本体は Invoke-SplitWidthValidation。
function Invoke-FlickFitSplitWidthDecision {
    param(
        [Parameter(Mandatory)]
        [ValidateSet(
            'DeletePaths',
            'OutcomeDelete',
            'SetNewCoverImmediate',
            'AdoptSkipRepeat',
            'AdoptReuseExact',
            'PrepareGutterReselectFromPreset',
            'PrepareGutterReselectFromGui',
            'PrepareGutterReselectFromMenu',
            'AdoptAutoOnesided',
            'AdoptAutoBalance',
            'AdoptAssumeInitialGutterGuiPrecedes',
            'OutcomeTrimOnly',
            'OutcomeRetry'
        )]
        [string]$Route,
        [string]$ImgName = '',
        [string]$GutterCacheFolderKey = '',
        [string[]]$PathsForDelete = @(),
        [int]$SetNewCoverWidthPx = 0,
        [object]$ReusePresetFromLast = $null,
        [int]$ReuseConfirmedTolPx = 3,
        [System.Collections.IDictionary]$GutterGuiResult = $null,
        [string]$ReviewImgPath = '',
        [string]$OrigPath = ''
    )
    switch ($Route) {
        'DeletePaths' {
            foreach ($p in $PathsForDelete) {
                if ($p -and (Test-Path -LiteralPath $p)) {
                    Remove-Item -LiteralPath $p -Force -ErrorAction SilentlyContinue
                }
            }
            return (Complete-FlickFitSplitWidthValidation -Code 'delete' -ImgName $ImgName -GutterCacheFolderKey $GutterCacheFolderKey)
        }
        'OutcomeDelete' {
            return (Complete-FlickFitSplitWidthValidation -Code 'delete' -ImgName $ImgName -GutterCacheFolderKey $GutterCacheFolderKey)
        }
        'SetNewCoverImmediate' {
            $script:SplitWidthNewCoverCandidate = $SetNewCoverWidthPx
            return (Complete-FlickFitSplitWidthValidation -Code 'set_new_cover' -ImgName $ImgName -GutterCacheFolderKey $GutterCacheFolderKey)
        }
        'AdoptSkipRepeat' {
            Write-FlickFitHost "         （このページのみ採用のため分割幅の再GUIを省略し、この分割をそのまま採用。フォルダの表紙基準は自動では下げません）" -ForegroundColor DarkCyan
            return (Complete-FlickFitSplitWidthValidation -Code 'adopt' -ImgName $ImgName -GutterCacheFolderKey $GutterCacheFolderKey)
        }
        'AdoptReuseExact' {
            Write-FlickFitHost "         （前回OKと同じノド・余白のまま → 再分割では幅が改善しないためそのまま採用）" -ForegroundColor DarkCyan
            return (Complete-FlickFitSplitWidthValidation -Code 'adopt' -ImgName $ImgName -GutterCacheFolderKey $GutterCacheFolderKey)
        }
        'PrepareGutterReselectFromPreset' {
            Write-FlickFitHost "         （前回OKのノド・余白と±${ReuseConfirmedTolPx}px以内 → GUIを出さず同設定で再分割）" -ForegroundColor DarkCyan
            $script:SplitWidthGuiPresetResult = $ReusePresetFromLast
            return (Complete-FlickFitSplitWidthValidation -Code 'gutter_reselect' -ImgName $ImgName -GutterCacheFolderKey $GutterCacheFolderKey)
        }
        'PrepareGutterReselectFromGui' {
            $d = Normalize-GutterGuiResult -GuiResult $GutterGuiResult
            if ($null -eq $d) {
                return (Complete-FlickFitSplitWidthValidation -Code 'gutter_reselect' -ImgName $ImgName -GutterCacheFolderKey $GutterCacheFolderKey)
            }
            $gxP = Get-HashtableInt -Tbl $d -Key 'GutterX' -Default (-1)
            if ($gxP -lt 0) {
                return (Complete-FlickFitSplitWidthValidation -Code 'gutter_reselect' -ImgName $ImgName -GutterCacheFolderKey $GutterCacheFolderKey)
            }
            $script:SplitWidthGuiPresetResult = @{
                GutterX      = $gxP
                LeftTrimPx   = (Get-HashtableInt -Tbl $d -Key 'LeftTrimPx')
                RightTrimPx  = (Get-HashtableInt -Tbl $d -Key 'RightTrimPx')
                TopTrimPx    = (Get-HashtableInt -Tbl $d -Key 'TopTrimPx')
                BottomTrimPx = (Get-HashtableInt -Tbl $d -Key 'BottomTrimPx')
                MarginTrimWithoutSplit = (Get-HashtableBool -Tbl $d -Key 'MarginTrimWithoutSplit')
            }
            if (Test-GuiMarginFlagTrue -Tbl $d -Key 'ApplyOnlyThisSpread') { $script:SplitWidthApplyGutterOnlyThisPage = $true }
            if ($d.ContainsKey('RotatedOutputPath')) {
                try {
                    $rpLog = [string]$d['RotatedOutputPath']
                    if (-not [string]::IsNullOrWhiteSpace($rpLog)) {
                        Write-FlickFitHost "         （分割へ回す画像: 回転済み $rpLog）" -ForegroundColor DarkCyan
                    }
                } catch {}
            }
            if ($GutterCacheFolderKey) {
                if (-not (Get-Variable -Name 'SplitWidthLastConfirmedByFolder' -Scope Script -ErrorAction SilentlyContinue)) { $script:SplitWidthLastConfirmedByFolder = @{} }
                $imgWLastConf = 0
                if ($ReviewImgPath -and (Test-Path -LiteralPath $ReviewImgPath)) {
                    $dLcf = Get-ImageDimensions -Path $ReviewImgPath -ErrorAction SilentlyContinue
                    if ($dLcf) { $imgWLastConf = $dLcf.Width }
                }
                if ($imgWLastConf -le 0 -and $OrigPath -and (Test-Path -LiteralPath $OrigPath)) {
                    $dLcf2 = Get-ImageDimensions -Path $OrigPath -ErrorAction SilentlyContinue
                    if ($dLcf2) { $imgWLastConf = $dLcf2.Width }
                }
                $script:SplitWidthLastConfirmedByFolder[$GutterCacheFolderKey] = @{
                    GutterX      = (Get-HashtableInt -Tbl $d -Key 'GutterX')
                    LeftTrimPx   = (Get-HashtableInt -Tbl $d -Key 'LeftTrimPx')
                    RightTrimPx  = (Get-HashtableInt -Tbl $d -Key 'RightTrimPx')
                    TopTrimPx    = (Get-HashtableInt -Tbl $d -Key 'TopTrimPx')
                    BottomTrimPx = (Get-HashtableInt -Tbl $d -Key 'BottomTrimPx')
                    MarginTrimWithoutSplit = (Get-HashtableBool -Tbl $d -Key 'MarginTrimWithoutSplit')
                    ImgW         = $imgWLastConf
                }
            }
            return (Complete-FlickFitSplitWidthValidation -Code 'gutter_reselect' -ImgName $ImgName -GutterCacheFolderKey $GutterCacheFolderKey)
        }
        'PrepareGutterReselectFromMenu' {
            return (Complete-FlickFitSplitWidthValidation -Code 'gutter_reselect' -ImgName $ImgName -GutterCacheFolderKey $GutterCacheFolderKey)
        }
        'AdoptAutoOnesided' {
            Write-FlickFitHost "         ⚠ 片側コンテンツ → 自動適用: 採用" -ForegroundColor Yellow
            return (Complete-FlickFitSplitWidthValidation -Code 'adopt' -ImgName $ImgName -GutterCacheFolderKey $GutterCacheFolderKey)
        }
        'AdoptAutoBalance' {
            Write-FlickFitHost "         ⚠ 横サイズ確認 → 自動適用: 採用" -ForegroundColor Yellow
            return (Complete-FlickFitSplitWidthValidation -Code 'adopt' -ImgName $ImgName -GutterCacheFolderKey $GutterCacheFolderKey)
        }
        'AdoptAssumeInitialGutterGuiPrecedes' {
            Write-FlickFitDebugStep5VerboseHost -Text '（初回のノド・余白GUIで確定済み → 分割幅の再GUIを省略しこの分割を採用。フォルダの表紙基準は自動では下げません）' -ForegroundColor DarkCyan
            return (Complete-FlickFitSplitWidthValidation -Code 'adopt' -ImgName $ImgName -GutterCacheFolderKey $GutterCacheFolderKey)
        }
        'OutcomeTrimOnly' {
            return (Complete-FlickFitSplitWidthValidation -Code 'trim_only' -ImgName $ImgName -GutterCacheFolderKey $GutterCacheFolderKey)
        }
        'OutcomeRetry' {
            return (Complete-FlickFitSplitWidthValidation -Code 'retry' -ImgName $ImgName -GutterCacheFolderKey $GutterCacheFolderKey)
        }
    }
}

# 分割幅チェック（表紙+1% 等）→ 通常のノド・余白GUIで調整（キャンセル＝現分割採用）
# 寸法・縦横比・再利用・表紙defer候補の判定は Get-FlickFitSplitWidthDecision（副作用なし）。早期終了の一部は Invoke-FlickFitSplitWidthDecision。本関数は残りの実行・GUI・Complete-*。
# 戻り値: ok（合格） | delete | set_new_cover（SplitWidthNewCoverCandidate） | adopt | gutter_reselect（SplitWidthGuiPresetResult 設定あり得る） | trim_only | retry
# 終了のたびに Complete-FlickFitSplitWidthValidation が $script:SplitWidthValidationLastOutcome を更新し、[SplitWidthVal] を1行出す（戻りは従来どおり文字列）
function Invoke-SplitWidthValidation {
    param(
        [string]$SplitPath1,
        [string]$SplitPath2,
        [int]$CoverWidth,
        [string]$BackupPath,
        [string]$OrigPath,
        [string]$WorkTrimSplitPy,
        [bool]$RightBinding,
        [double]$AspectMin,
        [string]$ImgName,
        [int]$RefWidthFromGutter = 0,
        [int]$TolerancePx = 10,
        [bool]$AllowGutterReselect = $false,
        [double]$RefAspect = 0,
        [switch]$OneSidedContent,
        [string[]]$AllImagePaths = $null,
        [string]$GutterCacheFolderKey = '',
        [int]$ReuseConfirmedTolPx = 3,
        [switch]$AssumeInitialGutterGuiPrecedesSplit
    )
    $skipRepeatGuiApplyOnly = $false
    if ((Get-Variable -Name SplitWidthSkipRepeatGuiApplyOnlyThisPage -Scope Script -ErrorAction SilentlyContinue) -and $script:SplitWidthSkipRepeatGuiApplyOnlyThisPage) {
        $skipRepeatGuiApplyOnly = $true
        $script:SplitWidthSkipRepeatGuiApplyOnlyThisPage = $false
    }
    $script:SplitWidthApplyGutterOnlyThisPage = $false
    $backupOpenedAlready = $false
    $deferNewCoverPrompt = $false
    $deferNewCoverMaxW = 0
    $suppressCoverBaselinePrompts = $AssumeInitialGutterGuiPrecedesSplit
    # 判定のみ Get-FlickFitSplitWidthDecision（副作用なし）。実行・GUI・ファイル操作はこの関数側。
    $swDec = Get-FlickFitSplitWidthDecision -SplitPath1 $SplitPath1 -SplitPath2 $SplitPath2 -CoverWidth $CoverWidth -RefWidthFromGutter $RefWidthFromGutter -TolerancePx $TolerancePx -RefAspect $RefAspect -GutterCacheFolderKey $GutterCacheFolderKey -ReuseConfirmedTolPx $ReuseConfirmedTolPx -AssumeInitialGutterGuiPrecedesSplit:$AssumeInitialGutterGuiPrecedesSplit -SkipRepeatGuiApplyOnly:$skipRepeatGuiApplyOnly -BackupPath $BackupPath -OrigPath $OrigPath
    if ($swDec.TargetMin -le 0) { return (Complete-FlickFitSplitWidthValidation -Code 'ok' -ImgName $ImgName -GutterCacheFolderKey $GutterCacheFolderKey) }
    $targetMin = $swDec.TargetMin
    $w1 = $swDec.W1; $w2 = $swDec.W2; $h1 = $swDec.H1; $h2 = $swDec.H2
    $widthOk = $swDec.WidthOk
    $aspectRatioOk = $swDec.AspectRatioOk
    $aspectReason = $swDec.AspectReason
    $thresholdDesc = $swDec.ThresholdDesc
    $deferNewCoverPrompt = $swDec.DeferNewCoverPrompt
    $deferNewCoverMaxW = $swDec.DeferNewCoverMaxW
    if ($widthOk -and $aspectRatioOk) { return (Complete-FlickFitSplitWidthValidation -Code 'ok' -ImgName $ImgName -GutterCacheFolderKey $GutterCacheFolderKey) }
    if (-not $widthOk) {
        Write-FlickFitDebugStep5VerboseHost -Text "⚠ 横サイズが${thresholdDesc}未満: 左=$w1 右=$w2 px (必要: $targetMin px)" -ForegroundColor Yellow
        # 表紙より小さいページを新しい基準値にするオプション（数値は Get-FlickFitSplitWidthDecision と一致）
        $maxW = $swDec.MaxW
        $skipSetNewCover = $swDec.SkipSetNewCover
        $canShowMarginGuiEarly = $swDec.CanShowMarginGuiEarly
        # ゴミ混入対策: 分割後の幅が極端に小さい場合（例: 24px など）は基準値採用を避け、先に削除確認する
        if ($swDec.TrashCandidate) {
            Write-FlickFitHost "         ⚠ ゴミ候補（幅が極端に小さい）: 最大=$maxW px / 必要=$targetMin px" -ForegroundColor Yellow
            $sumTrash = @(
                "画像: $ImgName",
                "⚠ ゴミ候補（幅が極端に小さい）: 最大=$maxW px / 必要=$targetMin px",
                "",
                "削除して次へ？ (Y/n)"
            ) -join "`r`n"
            $ansTrash = $null
            try {
                Add-Type -AssemblyName System.Windows.Forms -ErrorAction SilentlyContinue | Out-Null
                $mbTrash = [System.Windows.Forms.MessageBox]::Show(
                    ($sumTrash -replace "`r`n", [Environment]::NewLine),
                    "分割幅 — 削除確認 ($ImgName)",
                    [System.Windows.Forms.MessageBoxButtons]::YesNo,
                    [System.Windows.Forms.MessageBoxIcon]::Warning,
                    [System.Windows.Forms.MessageBoxDefaultButton]::Button1)
                $ansTrash = if ($mbTrash -eq [System.Windows.Forms.DialogResult]::Yes) { 'Y' } else { 'n' }
            } catch { $ansTrash = $null }
            if ($null -eq $ansTrash) {
                if (Test-Path -LiteralPath $BackupPath) {
                    try { Invoke-PhotosOpen -ImagePath $BackupPath } catch { try { Start-Process $BackupPath } catch {} }
                    Start-Sleep -Milliseconds 300
                    $backupOpenedAlready = $true
                }
                $ansTrash = Read-HostWithEsc "         削除して次へ？ (Y/n)"
            }
            if ($ansTrash -match '^[Yy]$' -or [string]::IsNullOrWhiteSpace($ansTrash)) {
                return (Invoke-FlickFitSplitWidthDecision -Route DeletePaths -ImgName $ImgName -GutterCacheFolderKey $GutterCacheFolderKey -PathsForDelete @($SplitPath1, $SplitPath2, $OrigPath))
            }
        }
        if ($CoverWidth -gt 0 -and -not $skipSetNewCover -and -not $suppressCoverBaselinePrompts) {
            if ($maxW -gt 0 -and $maxW -lt $CoverWidth) {
                Write-FlickFitDebugStep5VerboseHost -Text "※ このページの最大幅は表紙 (${CoverWidth}px) より小さい $maxW px です。" -ForegroundColor DarkYellow
                if (-not $canShowMarginGuiEarly) {
                    $sumBase = @(
                        "画像: $ImgName",
                        "⚠ 横サイズが${thresholdDesc}未満: 左=$w1 右=$w2 px (必要: $targetMin px)",
                        "※ このページの最大幅は表紙 (${CoverWidth}px) より小さい $maxW px です。",
                        "",
                        "この幅 ($maxW px) を以降の基準値として採用しますか？ (Y/n)"
                    ) -join "`r`n"
                    $ansBase = $null
                    try {
                        Add-Type -AssemblyName System.Windows.Forms -ErrorAction SilentlyContinue | Out-Null
                        $mbBase = [System.Windows.Forms.MessageBox]::Show(
                            ($sumBase -replace "`r`n", [Environment]::NewLine),
                            "分割幅 — 基準幅の採用 ($ImgName)",
                            [System.Windows.Forms.MessageBoxButtons]::YesNo,
                            [System.Windows.Forms.MessageBoxIcon]::Question,
                            [System.Windows.Forms.MessageBoxDefaultButton]::Button1)
                        $ansBase = if ($mbBase -eq [System.Windows.Forms.DialogResult]::Yes) { 'Y' } else { 'n' }
                    } catch { $ansBase = $null }
                    if ($null -eq $ansBase) { $ansBase = Read-HostWithEsc "         この幅 ($maxW px) を以降の基準値として採用しますか？ (Y/n)" }
                    if ($ansBase -match '^[Yy]$' -or [string]::IsNullOrWhiteSpace($ansBase)) {
                        return (Invoke-FlickFitSplitWidthDecision -Route SetNewCoverImmediate -ImgName $ImgName -GutterCacheFolderKey $GutterCacheFolderKey -SetNewCoverWidthPx $maxW)
                    }
                }
            }
        }
    }
    # 縦横比は GUI 要約・[PixelLoss] に集約（ここでは重複行を出さない）
    # バランス型で「このページのみで採用」→ ゴミ幅でなければ再GUI省略 adopt（判定は Get-FlickFitSplitWidthDecision の SkipRepeatShouldAdopt）
    if ($swDec.SkipRepeatShouldAdopt) {
        return (Invoke-FlickFitSplitWidthDecision -Route AdoptSkipRepeat -ImgName $ImgName -GutterCacheFolderKey $GutterCacheFolderKey)
    }
    # 前回分割幅GUIで OK したノド・余白とフォルダキャッシュの関係で GUI を省略（判定は Get-FlickFitSplitWidthDecision 内の ReuseKind）
    if ($GutterCacheFolderKey -and (-not $widthOk -or -not $aspectRatioOk)) {
        if (-not (Get-Variable -Name 'SplitWidthLastConfirmedByFolder' -Scope Script -ErrorAction SilentlyContinue)) { $script:SplitWidthLastConfirmedByFolder = @{} }
        if ($swDec.ReuseKind -eq $script:FlickFitReuseKindExactAdopt) {
            return (Invoke-FlickFitSplitWidthDecision -Route AdoptReuseExact -ImgName $ImgName -GutterCacheFolderKey $GutterCacheFolderKey)
        }
        if ($swDec.ReuseKind -eq $script:FlickFitReuseKindTolPreset) {
            return (Invoke-FlickFitSplitWidthDecision -Route PrepareGutterReselectFromPreset -ImgName $ImgName -GutterCacheFolderKey $GutterCacheFolderKey -ReusePresetFromLast $swDec.ReusePresetFromLast -ReuseConfirmedTolPx $ReuseConfirmedTolPx)
        }
    }
    # 「以降同じ処理を自動選択」が有効なら確認なしで採用（片側・通常どちらでも）
    if ($script:OneSidedSplitWidthAutoAdopt) {
        if ($OneSidedContent) {
            return (Invoke-FlickFitSplitWidthDecision -Route AdoptAutoOnesided -ImgName $ImgName -GutterCacheFolderKey $GutterCacheFolderKey)
        }
        return (Invoke-FlickFitSplitWidthDecision -Route AdoptAutoBalance -ImgName $ImgName -GutterCacheFolderKey $GutterCacheFolderKey)
    }
    # 初回ノド・余白GUI確定済みスイッチ時の adopt 省略（ゴミ幅でない場合のみ。判定は AssumeInitialGuiShouldAdopt）
    if ($swDec.AssumeInitialGuiShouldAdopt) {
        return (Invoke-FlickFitSplitWidthDecision -Route AdoptAssumeInitialGutterGuiPrecedes -ImgName $ImgName -GutterCacheFolderKey $GutterCacheFolderKey)
    }
    # 幅不足のみ等は警告＋自動採用（PixelLossSeverity）。複合異常は gui_required のまま通常 GUI へ
    if ($swDec.PixelLossSeverity -eq 'warn_adopt') {
        $plAsp = if ($swDec.HasAspectAnomaly) { 'True' } else { 'False' }
        $plGap = if ($swDec.HasLargeWidthGap) { 'True' } else { 'False' }
        if ($true -eq $script:FlickFitDebugStep5Verbose) {
            Write-FlickFitHost "[PixelLoss] severity=warn_adopt max=$($swDec.MaxW) target=$targetMin shortagePx=$($swDec.WidthShortagePx) ratio=$($swDec.WidthShortageRatio) w1=$w1 w2=$w2 aspect=$plAsp gap=$plGap img=$ImgName folderKey=$GutterCacheFolderKey" -ForegroundColor DarkGray
            Write-FlickFitHost "         （ピクセル不足は許容レベルのためこの分割を採用。再GUIは省略）" -ForegroundColor DarkGray
        }
        return (Complete-FlickFitSplitWidthValidation -Code 'adopt' -ImgName $ImgName -GutterCacheFolderKey $GutterCacheFolderKey)
    }
    $linesMain = [System.Collections.Generic.List[string]]::new()
    [void]$linesMain.Add("画像: $ImgName")
    if (-not $widthOk) { [void]$linesMain.Add("⚠ 横サイズが${thresholdDesc}未満: 左=$w1 右=$w2 px (必要: $targetMin px)") }
    if (-not $aspectRatioOk -and $aspectReason) { [void]$linesMain.Add("⚠ 縦横比が異常: $aspectReason") }
    if ($deferNewCoverPrompt -and $deferNewCoverMaxW -gt 0 -and $CoverWidth -gt 0) {
        [void]$linesMain.Add("※ このページの最大幅は表紙 (${CoverWidth}px) より小さい $deferNewCoverMaxW px です。")
        [void]$linesMain.Add("（キャンセルで今の分割を採用したあと、表紙基準をこの幅に下げるかコンソールで聞きます）")
    }
    [void]$linesMain.Add("")
    [void]$linesMain.Add("▼ 見開き・表紙と同じノド・余白GUIです。画像上で調整してください。")
    [void]$linesMain.Add("  OK＝この設定で再分割 ／ キャンセル＝いまの2枚分割をそのまま採用 ／ 「このページのみで採用」＝フォルダキャッシュは変えずこの見開きだけ反映")
    $sumMain = [string]::Join("`r`n", $linesMain)
    $script:SplitWidthGuiPresetResult = $null
    $reviewImgPath = $null
    if ($BackupPath -and (Test-Path -LiteralPath $BackupPath)) { $reviewImgPath = $BackupPath }
    elseif ($OrigPath -and (Test-Path -LiteralPath $OrigPath)) { $reviewImgPath = $OrigPath }
    if ($swDec.PixelLossSeverity -eq 'gui_required' -and ($true -eq $script:FlickFitDebugStep5Verbose)) {
        $plAspG = if ($swDec.HasAspectAnomaly) { 'True' } else { 'False' }
        $plGapG = if ($swDec.HasLargeWidthGap) { 'True' } else { 'False' }
        Write-FlickFitHost "[PixelLoss] severity=gui_required max=$($swDec.MaxW) target=$targetMin shortagePx=$($swDec.WidthShortagePx) ratio=$($swDec.WidthShortageRatio) w1=$w1 w2=$w2 aspect=$plAspG gap=$plGapG img=$ImgName folderKey=$GutterCacheFolderKey" -ForegroundColor Yellow
    }
    if ($swDec.GuiPromptReasonJa) {
        Write-FlickFitHost "         $($swDec.GuiPromptReasonJa)" -ForegroundColor Yellow
    }
    Write-FlickFitHost "         （分割幅確認: 通常のノド・余白GUIを表示します）" -ForegroundColor Cyan
    $guiFirst = $null
    $marginGuiWasShown = $false
    if ($reviewImgPath) {
        try {
            $swTitle = "ノドと左右余白の設定 — $ImgName（分割幅の見直し）"
            if ($AllImagePaths -and $AllImagePaths.Count -gt 0) {
                $guiFirst = Show-GutterMarginSetGui -ImagePath $reviewImgPath -Title $swTitle -AllImagePaths $AllImagePaths -ValidationSummaryText $sumMain -OkAppliesToCurrentView -ShowApplyThisPageOnlyButton
            } else {
                $guiFirst = Show-GutterMarginSetGui -ImagePath $reviewImgPath -Title $swTitle -ValidationSummaryText $sumMain -OkAppliesToCurrentView -ShowApplyThisPageOnlyButton
            }
            $marginGuiWasShown = $true
            if ($guiFirst -is [System.Collections.IDictionary]) { $guiFirst = Normalize-GutterGuiResult -GuiResult $guiFirst }
        } catch {
            $guiFirst = $null
            $marginGuiWasShown = $false
        }
    }
    if ($marginGuiWasShown -and $null -eq $guiFirst) {
        Write-FlickFitHost "         （キャンセル）分割結果をそのまま採用します" -ForegroundColor DarkGray
        if ($deferNewCoverPrompt -and $deferNewCoverMaxW -gt 0 -and $CoverWidth -gt 0 -and $deferNewCoverMaxW -lt $CoverWidth) {
            $ansNc = Read-HostWithEsc "         この幅 ($deferNewCoverMaxW px) を以降の表紙基準に下げますか？ (Y/n)"
            if ($ansNc -match '^[Yy]$' -or [string]::IsNullOrWhiteSpace($ansNc)) {
                return (Invoke-FlickFitSplitWidthDecision -Route SetNewCoverImmediate -ImgName $ImgName -GutterCacheFolderKey $GutterCacheFolderKey -SetNewCoverWidthPx $deferNewCoverMaxW)
            }
        }
        return (Complete-FlickFitSplitWidthValidation -Code 'adopt' -ImgName $ImgName -GutterCacheFolderKey $GutterCacheFolderKey)
    }
    if ($null -eq $guiFirst) {
        if (-not $backupOpenedAlready -and (Test-Path -LiteralPath $BackupPath)) {
            try { Invoke-PhotosOpen -ImagePath $BackupPath } catch { try { Start-Process $BackupPath } catch {} }
            Start-Sleep -Milliseconds 300
        }
        if (Test-Path -LiteralPath $SplitPath1) { try { Start-Process $SplitPath1 } catch {} }
        if (Test-Path -LiteralPath $SplitPath2) { try { Start-Process $SplitPath2 } catch {} }
        $guiFirst = Read-HostWithEsc "         [1]採用 [2]ノド再設定 [3]詳細 [4]自動採用 [D]削除"
    }
    if ($guiFirst -is [System.Collections.IDictionary]) {
        if (Test-GuiMarginFlagTrue -Tbl $guiFirst -Key 'DeleteImage') {
            return (Invoke-FlickFitSplitWidthDecision -Route DeletePaths -ImgName $ImgName -GutterCacheFolderKey $GutterCacheFolderKey -PathsForDelete @($SplitPath1, $SplitPath2, $OrigPath))
        }
        if (Test-GuiMarginFlagTrue -Tbl $guiFirst -Key 'PhotosEdit') {
            foreach ($p in @($SplitPath1, $SplitPath2)) {
                if (Test-Path -LiteralPath $p) { Remove-Item -LiteralPath $p -Force -ErrorAction SilentlyContinue }
            }
            return (Invoke-FlickFitSplitWidthDecision -Route PrepareGutterReselectFromMenu -ImgName $ImgName -GutterCacheFolderKey $GutterCacheFolderKey)
        }
        $gxOk = Get-HashtableInt -Tbl $guiFirst -Key 'GutterX' -Default (-1)
        if ($gxOk -ge 0) {
            return (Invoke-FlickFitSplitWidthDecision -Route PrepareGutterReselectFromGui -ImgName $ImgName -GutterCacheFolderKey $GutterCacheFolderKey -GutterGuiResult $guiFirst -ReviewImgPath $reviewImgPath -OrigPath $OrigPath)
        }
    }
    if ($guiFirst -is [string]) {
        if ($guiFirst -match '^[dD]$') {
            return (Invoke-FlickFitSplitWidthDecision -Route DeletePaths -ImgName $ImgName -GutterCacheFolderKey $GutterCacheFolderKey -PathsForDelete @($SplitPath1, $SplitPath2, $OrigPath))
        }
        if ($guiFirst -match '^[1]|^$') { return (Complete-FlickFitSplitWidthValidation -Code 'adopt' -ImgName $ImgName -GutterCacheFolderKey $GutterCacheFolderKey) }
        if ($guiFirst -match '^[4]$') {
            $script:OneSidedSplitWidthAutoAdopt = $true
            Write-FlickFitHost "         → このフォルダ内では、同様の場合は「採用」で自動処理します" -ForegroundColor DarkCyan
            return (Complete-FlickFitSplitWidthValidation -Code 'adopt' -ImgName $ImgName -GutterCacheFolderKey $GutterCacheFolderKey)
        }
        if ($guiFirst -match '^[2]$' -and (Test-Path -LiteralPath $BackupPath)) { return (Invoke-FlickFitSplitWidthDecision -Route PrepareGutterReselectFromMenu -ImgName $ImgName -GutterCacheFolderKey $GutterCacheFolderKey) }
        if ($guiFirst -match '^[3]$') {
            $sumDet = @(
                "画像: $ImgName",
                "[詳細メニュー]",
                "▼ [1]採用 [2]手動 [3]ノド [4]余白のみ [5]削除"
            ) -join "`r`n"
            $ans = $null
            try { $ans = Show-SplitWidthValidationDialog -Caption "分割幅 — 詳細 ($ImgName)" -SummaryText $sumDet -BackupPath $BackupPath -SplitPath1 $SplitPath1 -SplitPath2 $SplitPath2 -OrigPath $OrigPath -Kind Detail } catch { $ans = $null }
            if ($null -eq $ans) { $ans = Read-HostWithEsc "         [選択]" }
            if ($ans -match '^[1]|^$') { return (Complete-FlickFitSplitWidthValidation -Code 'adopt' -ImgName $ImgName -GutterCacheFolderKey $GutterCacheFolderKey) }
            if ($ans -match '^[5]|^[dD]$') {
                return (Invoke-FlickFitSplitWidthDecision -Route DeletePaths -ImgName $ImgName -GutterCacheFolderKey $GutterCacheFolderKey -PathsForDelete @($SplitPath1, $SplitPath2, $OrigPath))
            }
            if ($ans -match '^[3]$' -and (Test-Path -LiteralPath $BackupPath)) { return (Invoke-FlickFitSplitWidthDecision -Route PrepareGutterReselectFromMenu -ImgName $ImgName -GutterCacheFolderKey $GutterCacheFolderKey) }
            if ($ans -match '^[4]$' -and (Test-Path -LiteralPath $BackupPath)) { return (Invoke-FlickFitSplitWidthDecision -Route OutcomeTrimOnly -ImgName $ImgName -GutterCacheFolderKey $GutterCacheFolderKey) }
            if ($ans -match '^[2]$') { $guiFirst = '2' } else { return (Complete-FlickFitSplitWidthValidation -Code 'adopt' -ImgName $ImgName -GutterCacheFolderKey $GutterCacheFolderKey) }
        }
    }
    $manualTrimRedo = $false
    do {
        if (-not $manualTrimRedo) {
            if ($guiFirst -is [string] -and $guiFirst -match '^[2]$') {
                $ans = '2'
                $guiFirst = $null
            } elseif ($null -eq $ans) {
                Write-FlickFitHost "         [1] 採用  [2] 手動で左右画像をトリミング（フォト）  [3] ノド位置の再選択（GUI）  [4] 分割しないで余白のみトリミング  [5] 削除" -ForegroundColor Cyan
                $sumDet = @(
                    "画像: $ImgName",
                    "[詳細メニュー]",
                    "▼ 画面下のボタンで選択（Enter＝[1]採用、キー 1～5 でも可）。"
                ) -join "`r`n"
                $ans = $null
                try { $ans = Show-SplitWidthValidationDialog -Caption "分割幅 — 詳細 ($ImgName)" -SummaryText $sumDet -BackupPath $BackupPath -SplitPath1 $SplitPath1 -SplitPath2 $SplitPath2 -OrigPath $OrigPath -Kind Detail } catch { $ans = $null }
                if ($null -eq $ans) { $ans = Read-HostWithEsc "         [選択]" }
            }
        } else {
            $ans = "2"
        }
        if ($ans -match '^[1]|^$') { return (Complete-FlickFitSplitWidthValidation -Code 'adopt' -ImgName $ImgName -GutterCacheFolderKey $GutterCacheFolderKey) }
        if ($ans -match '^[5]|^[dD]$') {
            return (Invoke-FlickFitSplitWidthDecision -Route DeletePaths -ImgName $ImgName -GutterCacheFolderKey $GutterCacheFolderKey -PathsForDelete @($SplitPath1, $SplitPath2, $OrigPath))
        }
        if ($ans -match '^[3]$' -and (Test-Path -LiteralPath $BackupPath)) {
            return (Invoke-FlickFitSplitWidthDecision -Route PrepareGutterReselectFromMenu -ImgName $ImgName -GutterCacheFolderKey $GutterCacheFolderKey)
        }
        if ($ans -match '^[4]$' -and (Test-Path -LiteralPath $BackupPath)) {
            return (Invoke-FlickFitSplitWidthDecision -Route OutcomeTrimOnly -ImgName $ImgName -GutterCacheFolderKey $GutterCacheFolderKey)
        }
        if ($ans -match '^[2]$') {
            foreach ($p in @($SplitPath1, $SplitPath2)) {
                if (Test-Path -LiteralPath $p) { Remove-Item -LiteralPath $p -Force -ErrorAction SilentlyContinue }
            }
            if (-not (Test-Path -LiteralPath $BackupPath)) {
                Write-FlickFitHost "         [エラー] バックアップが見つかりません" -ForegroundColor Red
                return (Invoke-FlickFitSplitWidthDecision -Route OutcomeDelete -ImgName $ImgName -GutterCacheFolderKey $GutterCacheFolderKey)
            }
            $parentDir = Split-Path $OrigPath -Parent
            $ext = [System.IO.Path]::GetExtension($OrigPath)
            $baseName = [System.IO.Path]::GetFileNameWithoutExtension($OrigPath)
            # 右綴じ（日本コミック）: 右ページ=奇数=_1、左ページ=偶数=_2
            $tempRight = Join-Path $parentDir ("cvr_right_" + [Guid]::NewGuid().ToString('N').Substring(0,8) + $ext)
            $tempLeft = Join-Path $parentDir ("cvr_left_" + [Guid]::NewGuid().ToString('N').Substring(0,8) + $ext)
            $dest1 = Join-Path $parentDir ($baseName + "_1" + $ext)
            $dest2 = Join-Path $parentDir ($baseName + "_2" + $ext)
            try {
                Copy-Item -LiteralPath $BackupPath -Destination $tempRight -Force
                Write-FlickFitHost "         [1/2] 右ページ: フォトで見開きを開きます" -ForegroundColor Cyan
                Invoke-PhotosOpen -ImagePath $tempRight
                Write-FlickFitHost "         右ページ（見開きの右側）としてトリミングし、保存したら Enter で次へ" -ForegroundColor Gray
                $null = Read-HostWithEsc "         [フォトで保存後 Enter]"
                Copy-Item -LiteralPath $BackupPath -Destination $tempLeft -Force
                Write-FlickFitHost "         [2/2] 左ページ: フォトで見開きを開きます" -ForegroundColor Cyan
                Invoke-PhotosOpen -ImagePath $tempLeft
                Write-FlickFitHost "         左ページ（見開きの左側）としてトリミングし、保存したら Enter で次へ" -ForegroundColor Gray
                $null = Read-HostWithEsc "         [フォトで保存後 Enter]"
                if ((Test-Path -LiteralPath $tempRight) -and (Test-Path -LiteralPath $tempLeft)) {
                    if ($RightBinding) {
                        Copy-Item -LiteralPath $tempRight -Destination $dest1 -Force
                        Copy-Item -LiteralPath $tempLeft -Destination $dest2 -Force
                    } else {
                        Copy-Item -LiteralPath $tempLeft -Destination $dest1 -Force
                        Copy-Item -LiteralPath $tempRight -Destination $dest2 -Force
                    }
                    Write-FlickFitHost "         ✅ 手動トリムで右ページ・左ページを保存しました" -ForegroundColor Green
                    Write-FlickFitHost "         [1] 採用  [2] 再度やり直し" -ForegroundColor Cyan
                    $ans2 = Read-HostWithEsc "         [確認]"
                    if ($ans2 -match '^[2]$') {
                        foreach ($sp in @($dest1, $dest2, $tempRight, $tempLeft)) {
                            if (Test-Path -LiteralPath $sp) { Remove-Item -LiteralPath $sp -Force -ErrorAction SilentlyContinue }
                        }
                        $manualTrimRedo = $true
                        continue
                    }
                    foreach ($sp in @($tempRight, $tempLeft)) {
                        if (Test-Path -LiteralPath $sp) { Remove-Item -LiteralPath $sp -Force -ErrorAction SilentlyContinue }
                    }
                    return (Invoke-FlickFitSplitWidthDecision -Route OutcomeRetry -ImgName $ImgName -GutterCacheFolderKey $GutterCacheFolderKey)
                }
            } catch {
                Write-FlickFitHost "         [エラー]: $($_.Exception.Message)" -ForegroundColor Red
            }
            return (Invoke-FlickFitSplitWidthDecision -Route DeletePaths -ImgName $ImgName -GutterCacheFolderKey $GutterCacheFolderKey -PathsForDelete @($tempRight, $tempLeft))
        }
        $manualTrimRedo = $false
    } while ($manualTrimRedo)
    return (Complete-FlickFitSplitWidthValidation -Code 'adopt' -ImgName $ImgName -GutterCacheFolderKey $GutterCacheFolderKey)
}
#endregion

# ===========================================================================
# 処理ログ（JSON）: 成功/失敗記録・リトライ対応
# ===========================================================================
#region Persistence & resume
# 役割:
#   処理ログ JSON・再開スナップショット・中断時メタデータ・リトライプロンプト。
# 主役:
#   Load-ProcessLog / Save-ProcessLog / Invoke-FlickFitResumePrompt
# 注意:
#   _process_log.json はタイトルフォルダ基準。lastSuccessfulStep と clixml の整合を単独では保証しない。
function Get-ProcessLogPath {
    $base = if ($script:TitleFolder) { $script:TitleFolder.FullName } else { (Get-Location).Path }
    return Join-Path $base "_process_log.json"
}
function Load-ProcessLog {
    $path = Get-ProcessLogPath
    if (-not (Test-Path -LiteralPath $path)) { return $null }
    try {
        $json = Get-Content -LiteralPath $path -Raw -Encoding UTF8
        return $json | ConvertFrom-Json
    } catch { return $null }
}
function Save-ProcessLog {
    param($LogObj)
    $path = Get-ProcessLogPath
    try {
        if ($null -ne $LogObj) {
            if (-not ($LogObj.PSObject.Properties.Name -contains 'runId') -or [string]::IsNullOrWhiteSpace([string]$LogObj.runId)) {
                $LogObj | Add-Member -NotePropertyName 'runId' -NotePropertyValue ([Guid]::NewGuid().ToString('N')) -Force
            }
            if (-not ($LogObj.PSObject.Properties.Name -contains 'logSchema') -or [string]::IsNullOrWhiteSpace([string]$LogObj.logSchema)) {
                $LogObj | Add-Member -NotePropertyName 'logSchema' -NotePropertyValue '1' -Force
            }
            if (-not ($LogObj.PSObject.Properties.Name -contains 'startedAt') -or [string]::IsNullOrWhiteSpace([string]$LogObj.startedAt)) {
                $LogObj | Add-Member -NotePropertyName 'startedAt' -NotePropertyValue (Get-Date).ToString("yyyy-MM-ddTHH:mm:ss") -Force
            }
        }
        $LogObj | ConvertTo-Json -Depth 10 | Set-Content -LiteralPath $path -Encoding UTF8
    } catch { Write-FlickFitHost "  [警告]: 処理ログの保存に失敗: $_" -ForegroundColor Yellow }
}
function Update-ProcessLogStep {
    param([int]$StepNum, [string]$Status, [string]$ErrorMsg = $null)
    if (-not $script:ProcessLog) { return }
    if (-not $script:ProcessLog.steps) { $script:ProcessLog | Add-Member -NotePropertyName steps -NotePropertyValue ([PSCustomObject]@{}) -Force }
    $key = "step$StepNum"
    $script:ProcessLog.steps | Add-Member -NotePropertyName $key -NotePropertyValue $Status -Force
    $script:ProcessLog.updatedAt = (Get-Date).ToString("yyyy-MM-ddTHH:mm:ss")
    if ($ErrorMsg) { $script:ProcessLog.lastError = $ErrorMsg }
    if ($Status -eq 'failed') { $script:ProcessLog.status = 'failed' }
    if ($Status -eq 'success') {
        $script:ProcessLog | Add-Member -NotePropertyName 'lastSuccessfulStep' -NotePropertyValue $StepNum -Force
    }
    Save-ProcessLog $script:ProcessLog
}

function Add-FlickFitGuiSplitTrustOutputs {
    # HashSet[string] を型付き param にすると環境によっては「Parameter set cannot be resolved」になるため object で受ける
    param(
        [object]$GuiSplitTrustSet,
        [string]$SplitBasePath
    )
    if ($null -eq $GuiSplitTrustSet -or [string]::IsNullOrWhiteSpace($SplitBasePath)) { return }
    # Python 分割後は元見開きを削除するため、ベースファイルの有無は見ない（_1/_2 のみ登録）
    # Split-Path -LiteralPath は環境によって Parameter set エラーになるため .NET のみ使用
    $par = [System.IO.Path]::GetDirectoryName($SplitBasePath)
    if ([string]::IsNullOrWhiteSpace($par)) { return }
    $stem = [System.IO.Path]::GetFileNameWithoutExtension($SplitBasePath)
    $ext = [System.IO.Path]::GetExtension($SplitBasePath)
    foreach ($suf in @('_1', '_2')) {
        $p = Join-Path $par ($stem + $suf + $ext)
        if (-not (Test-Path -LiteralPath $p)) { continue }
        try {
            $full = [System.IO.Path]::GetFullPath($p).TrimEnd('\')
            [void]$GuiSplitTrustSet.Add($full)
        } catch {
            try { [void]$GuiSplitTrustSet.Add($p.TrimEnd('\')) } catch {}
        }
    }
}

function Save-FlickFitProcessCheckpoint {
    param(
        [System.Collections.Generic.List[string]]$FinalDirs,
        $UnpackRoot,
        [bool]$RunPhaseA,
        [bool]$RunPhaseB,
        [string]$CombinedBase
    )
    if (-not $script:ProcessLog) { return }
    $fd = @($FinalDirs | ForEach-Object { try { [System.IO.Path]::GetFullPath($_) } catch { "$_" } })
    $cp = [PSCustomObject]@{
        finalDirs           = $fd
        unpackRoot          = if ($UnpackRoot -and $UnpackRoot.FullName) { $UnpackRoot.FullName } elseif ($UnpackRoot -is [string] -and $UnpackRoot) { $UnpackRoot } else { $null }
        runPhaseA           = $RunPhaseA
        runPhaseB           = $RunPhaseB
        combinedBase        = $CombinedBase
        titleName           = $script:TitleName
        titleFolder         = if ($script:TitleFolder) { $script:TitleFolder.FullName } else { $null }
        compressionFormat   = $CompressionFormat
        outputSubfolder     = $OutputSubfolder
        hasArchives         = [bool]($script:selectedArchives -and $script:selectedArchives.Count -gt 0)
        hasExistingFolders  = [bool]($script:selectedExistingFolders -and $script:selectedExistingFolders.Count -gt 0)
    }
    $archP = [System.Collections.Generic.List[string]]::new()
    if ($script:selectedArchives) {
        foreach ($a in @($script:selectedArchives)) {
            if ($null -eq $a) { continue }
            $p = if ($a -is [string]) { $a } else { $a.FullName }
            if ($p) { [void]$archP.Add($p) }
        }
    }
    $existP = [System.Collections.Generic.List[string]]::new()
    if ($script:selectedExistingFolders) {
        foreach ($e in @($script:selectedExistingFolders)) {
            if ($null -eq $e) { continue }
            $p = if ($e -is [string]) { $e } else { $e.FullName }
            if ($p) { [void]$existP.Add($p) }
        }
    }
    $subP = [System.Collections.Generic.List[string]]::new()
    if ($script:subfolderArchivesToProcess) {
        foreach ($s in @($script:subfolderArchivesToProcess)) {
            if ($null -eq $s) { continue }
            $p = if ($s -is [string]) { $s } else { $s.FullName }
            if ($p) { [void]$subP.Add($p) }
        }
    }
    $cp | Add-Member -NotePropertyName 'selectedArchivePaths' -NotePropertyValue @($archP) -Force
    $cp | Add-Member -NotePropertyName 'selectedExistingFolderPaths' -NotePropertyValue @($existP) -Force
    $cp | Add-Member -NotePropertyName 'subfolderArchivePaths' -NotePropertyValue @($subP) -Force
    $delSrcP = [System.Collections.Generic.List[string]]::new()
    if (Get-Variable -Name SourceArchivePathsForStep7Delete -Scope Script -ErrorAction SilentlyContinue) {
        foreach ($x in @($script:SourceArchivePathsForStep7Delete)) { if ($x) { [void]$delSrcP.Add([string]$x) } }
    }
    $cp | Add-Member -NotePropertyName 'sourceArchivePathsForDeletion' -NotePropertyValue @($delSrcP) -Force
    $script:ProcessLog | Add-Member -NotePropertyName 'checkpoint' -NotePropertyValue $cp -Force
    $script:ProcessLog | Add-Member -NotePropertyName 'step5CompletedDirs' -NotePropertyValue @() -Force
    Save-ProcessLog $script:ProcessLog
}

function Get-FlickFitResumeSnapshotDir {
    if ($script:TitleFolder) { return $script:TitleFolder.FullName }
    return (Get-Location).Path
}

function Save-FlickFitAfterStep1Snapshot {
    if (-not $script:ProcessLog) { return }
    try {
        $ur = if ($unpackRoot -and $unpackRoot.FullName) { $unpackRoot.FullName } elseif ($unpackRoot -is [string]) { $unpackRoot } else { $null }
        $arch = [System.Collections.Generic.List[string]]::new()
        if ($script:selectedArchives) {
            foreach ($a in @($script:selectedArchives)) {
                if ($null -eq $a) { continue }
                $p = if ($a -is [string]) { $a } else { $a.FullName }
                if ($p) { [void]$arch.Add($p) }
            }
        }
        $exist = [System.Collections.Generic.List[string]]::new()
        if ($script:selectedExistingFolders) {
            foreach ($e in @($script:selectedExistingFolders)) {
                if ($null -eq $e) { continue }
                $p = if ($e -is [string]) { $e } else { $e.FullName }
                if ($p) { [void]$exist.Add($p) }
            }
        }
        $sub = [System.Collections.Generic.List[string]]::new()
        if ($script:subfolderArchivesToProcess) {
            foreach ($s in @($script:subfolderArchivesToProcess)) {
                if ($null -eq $s) { continue }
                $p = if ($s -is [string]) { $s } else { $s.FullName }
                if ($p) { [void]$sub.Add($p) }
            }
        }
        $delStep7 = @()
        if (Get-Variable -Name SourceArchivePathsForStep7Delete -Scope Script -ErrorAction SilentlyContinue) { $delStep7 = @($script:SourceArchivePathsForStep7Delete) }
        $after1 = [PSCustomObject]@{
            unpackRoot              = $ur
            targetRoots             = @($targetRoots)
            selectedArchives        = @($arch)
            selectedExistingFolders = @($exist)
            subfolderArchives       = @($sub)
            sourceArchivePathsForStep7Delete = $delStep7
            epubFolderVolMap        = $script:epubFolderVolMap
            epubCoverMap            = $script:epubCoverMap
            epubMainFolderMap       = $script:epubMainFolderMap
            epubTitleMap            = $script:epubTitleMap
            epubCreatorMap          = $script:epubCreatorMap
            epubSpineImageMap       = $script:epubSpineImageMap
        }
        $p1 = Join-Path (Get-FlickFitResumeSnapshotDir) '_flickfit_after_step1.clixml'
        $after1 | Export-Clixml -Path $p1 -Force
        $script:ProcessLog | Add-Member -NotePropertyName 'afterStep1File' -NotePropertyValue $p1 -Force
        Save-ProcessLog $script:ProcessLog
    } catch {
        Write-FlickFitHost "  [警告] STEP 1 スナップショット保存に失敗: $_" -ForegroundColor Yellow
    }
}

function Restore-FlickFitAfterStep1Snapshot {
    $log = $script:ProcessLog
    $path = $null
    if ($log -and $log.PSObject.Properties['afterStep1File'] -and $log.afterStep1File) { $path = [string]$log.afterStep1File }
    if (-not $path -or -not (Test-Path -LiteralPath $path)) {
        $path = Join-Path (Get-FlickFitResumeSnapshotDir) '_flickfit_after_step1.clixml'
    }
    if (-not (Test-Path -LiteralPath $path)) {
        throw "エラー: STEP 1 完了時のスナップショットがありません。`-ForceRetry` で最初から実行してください。"
    }
    $s = Import-Clixml -Path $path
    if ($s.unpackRoot -and (Test-Path -LiteralPath $s.unpackRoot)) {
        try { Set-Variable -Name unpackRoot -Value (Get-Item -LiteralPath $s.unpackRoot) -Scope Script } catch { Set-Variable -Name unpackRoot -Value $null -Scope Script }
    } else { Set-Variable -Name unpackRoot -Value $null -Scope Script }
    Set-Variable -Name targetRoots -Value @($s.targetRoots) -Scope Script
    $script:selectedArchives = @($s.selectedArchives)
    $script:selectedExistingFolders = @($s.selectedExistingFolders)
    $script:subfolderArchivesToProcess = @($s.subfolderArchives)
    if ($s.PSObject.Properties['sourceArchivePathsForStep7Delete'] -and $s.sourceArchivePathsForStep7Delete) {
        $script:SourceArchivePathsForStep7Delete = @($s.sourceArchivePathsForStep7Delete)
    } else {
        Set-FlickFitSourceArchivePathsForDeletion -FromArchives $script:selectedArchives -FromSubfolder $script:subfolderArchivesToProcess
    }
    if ($s.PSObject.Properties['epubFolderVolMap']) { $script:epubFolderVolMap = $s.epubFolderVolMap }
    if ($s.PSObject.Properties['epubCoverMap']) { $script:epubCoverMap = $s.epubCoverMap }
    if ($s.PSObject.Properties['epubMainFolderMap']) { $script:epubMainFolderMap = $s.epubMainFolderMap }
    # EPUB OPF 由来（STEP1 でのみ設定。旧スナップショットには無い → 空ハッシュで再開可能にする）
    if ($s.PSObject.Properties['epubTitleMap'] -and $s.epubTitleMap) {
        $script:epubTitleMap = $s.epubTitleMap
    } else { $script:epubTitleMap = @{} }
    if ($s.PSObject.Properties['epubCreatorMap'] -and $s.epubCreatorMap) {
        $script:epubCreatorMap = $s.epubCreatorMap
    } else { $script:epubCreatorMap = @{} }
    if ($s.PSObject.Properties['epubSpineImageMap'] -and $s.epubSpineImageMap) {
        $script:epubSpineImageMap = $s.epubSpineImageMap
    } else { $script:epubSpineImageMap = @{} }
}

function Remove-FlickFitStep2ProgressSnapshot {
    try {
        $path = Join-Path (Get-FlickFitResumeSnapshotDir) '_flickfit_step2_progress.clixml'
        if (Test-Path -LiteralPath $path) { Remove-Item -LiteralPath $path -Force -ErrorAction SilentlyContinue }
    } catch { }
}

function Reset-FlickFitStep2ResumeState {
    param(
        # ログを作り直す・ForceRetry 時: STEP1 完了扱いにせず、表紙の仮状態だけ消す
        [switch]$FullRestart
    )
    # STEP1の成果は保持し、STEP2以降の再開用状態だけ初期化
    # （_flickfit_step2_progress.clixml に残った coverMap を読むと「表紙は確定済み」だけが出るため、
    #  -ForceRetry や「最初から」再開時に必ず呼ぶ）
    try {
        $dir = Get-FlickFitResumeSnapshotDir
        foreach ($name in @('_flickfit_step2_progress.clixml', '_flickfit_after_step2.clixml', '_flickfit_after_step3.clixml')) {
            $p = Join-Path $dir $name
            if (Test-Path -LiteralPath $p) { Remove-Item -LiteralPath $p -Force -ErrorAction SilentlyContinue }
        }
    } catch { }

    # 実行中メモリ側もSTEP2開始時相当に戻す
    $script:coverMap = @{}
    $script:detectedCoverFolders = [System.Collections.Generic.List[PSObject]]::new()

    if ($script:ProcessLog) {
        try {
            foreach ($pn in @('afterStep2File','afterStep3File','checkpoint','step5InterruptedDir','exitResumeFromStep')) {
                if ($script:ProcessLog.PSObject.Properties[$pn]) {
                    $script:ProcessLog.PSObject.Properties.Remove($pn)
                }
            }
            if ($script:ProcessLog.PSObject.Properties['steps'] -and $script:ProcessLog.steps) {
                foreach ($sk in @('step2','step3','step4','step5','step6','step7')) {
                    if ($script:ProcessLog.steps.PSObject.Properties[$sk]) {
                        $script:ProcessLog.steps.PSObject.Properties.Remove($sk)
                    }
                }
            }
            if ($FullRestart) {
                if ($script:ProcessLog.PSObject.Properties['lastSuccessfulStep']) {
                    $script:ProcessLog.PSObject.Properties.Remove('lastSuccessfulStep')
                }
            } else {
                $script:ProcessLog | Add-Member -NotePropertyName 'lastSuccessfulStep' -NotePropertyValue 1 -Force
            }
            $script:ProcessLog.status = 'in_progress'
            $script:ProcessLog.updatedAt = (Get-Date).ToString("yyyy-MM-ddTHH:mm:ss")
            Save-ProcessLog $script:ProcessLog
        } catch { }
    }
}

function Save-FlickFitAfterStep2Snapshot {
    param($VolMap, $SpecialItems, $AllLeaves)
    $dir = Get-FlickFitResumeSnapshotDir
    $path = Join-Path $dir '_flickfit_after_step2.clixml'
    try {
        $vm = @{}
        foreach ($k in $VolMap.Keys) {
            $vm["$k"] = @($VolMap[$k])
        }
        $sp = @($SpecialItems | ForEach-Object {
                [PSCustomObject]@{ Suffix = $_.Suffix; Path = $_.Path }
            })
        $bundle = [PSCustomObject]@{
            VolMapSerial     = $vm
            SpecialItems     = $sp
            AllLeafPaths     = @($AllLeaves | ForEach-Object { $_.Path })
            CoverMap         = $script:coverMap
            BestRawName      = $script:BestRawName
            TitleCandidates  = @($script:TitleCandidates)
        }
        $bundle | Export-Clixml -Path $path -Force
        Remove-FlickFitStep2ProgressSnapshot
        if ($script:ProcessLog) {
            $script:ProcessLog | Add-Member -NotePropertyName 'afterStep2File' -NotePropertyValue $path -Force
            Save-ProcessLog $script:ProcessLog
        }
        return $true
    } catch {
        Write-FlickFitHost "  [警告] STEP 2 スナップショット保存に失敗: $_" -ForegroundColor Yellow
        return $false
    }
}

function Restore-FlickFitAfterStep2Snapshot {
    $log = $script:ProcessLog
    $path = $null
    if ($log -and $log.PSObject.Properties['afterStep2File'] -and $log.afterStep2File) { $path = [string]$log.afterStep2File }
    if (-not $path -or -not (Test-Path -LiteralPath $path)) {
        $path = Join-Path (Get-FlickFitResumeSnapshotDir) '_flickfit_after_step2.clixml'
    }
    if (-not (Test-Path -LiteralPath $path)) {
        throw "エラー: STEP 2 完了時のスナップショットがありません。`-ForceRetry` で最初から実行してください。"
    }
    $bundle = Import-Clixml -Path $path
    $volMap = @{}
    foreach ($k in $bundle.VolMapSerial.Keys) {
        $vn = [int]$k
        $lst = [System.Collections.Generic.List[string]]::new()
        foreach ($p in @($bundle.VolMapSerial[$k])) { [void]$lst.Add($p) }
        $volMap[$vn] = $lst
    }
    $script:coverMap = $bundle.CoverMap
    $script:BestRawName = $bundle.BestRawName
    $script:TitleCandidates = @($bundle.TitleCandidates)
    $specialItems = [System.Collections.Generic.List[PSObject]]::new()
    foreach ($row in @($bundle.SpecialItems)) {
        $specialItems.Add([PSCustomObject]@{ Suffix = $row.Suffix; Path = $row.Path })
    }
    $allLeaves = [System.Collections.Generic.List[PSObject]]::new()
    foreach ($lp in @($bundle.AllLeafPaths)) {
        if ([string]::IsNullOrWhiteSpace($lp)) { continue }
        $nm = Split-Path $lp -Leaf
        $allLeaves.Add([PSCustomObject]@{ Name = $nm; Path = $lp })
    }
    Set-Variable -Name volMap -Value $volMap -Scope Script
    Set-Variable -Name specialItems -Value $specialItems -Scope Script
    Set-Variable -Name allLeaves -Value $allLeaves -Scope Script
}

