function Save-FlickFitExitInterruptMetadata {
    if (-not $script:ProcessLog) { return }
    $n = 1
    if ($null -ne $script:CurrentProcessStepNumber) {
        try { $n = [int]$script:CurrentProcessStepNumber } catch { $n = 1 }
    }
    $script:ProcessLog | Add-Member -NotePropertyName 'interruptKind' -NotePropertyValue 'exit' -Force
    $script:ProcessLog | Add-Member -NotePropertyName 'exitResumeFromStep' -NotePropertyValue $n -Force
    Save-ProcessLog $script:ProcessLog
}

function Add-ProcessLogStep5CompletedDir {
    param([string]$DirFullPath)
    if (-not $script:ProcessLog -or [string]::IsNullOrWhiteSpace($DirFullPath)) { return }
    try { $norm = [System.IO.Path]::GetFullPath($DirFullPath).TrimEnd('\') } catch { $norm = $DirFullPath.TrimEnd('\') }
    $arr = [System.Collections.Generic.List[string]]::new()
    if ($script:ProcessLog.PSObject.Properties['step5CompletedDirs'] -and $script:ProcessLog.step5CompletedDirs) {
        foreach ($x in @($script:ProcessLog.step5CompletedDirs)) {
            try { $arr.Add([System.IO.Path]::GetFullPath("$x").TrimEnd('\')) } catch { $arr.Add("$x".TrimEnd('\')) }
        }
    }
    if (-not $arr.Contains($norm)) { [void]$arr.Add($norm) }
    $script:ProcessLog | Add-Member -NotePropertyName 'step5CompletedDirs' -NotePropertyValue @($arr) -Force
    $script:ProcessLog.updatedAt = (Get-Date).ToString("yyyy-MM-ddTHH:mm:ss")
    Save-ProcessLog $script:ProcessLog
}

function Restore-FlickFitVolumeFolderFromBackup {
    param([string]$DestinationDir, [string]$BackupRoot)
    if (-not (Test-Path -LiteralPath $BackupRoot -PathType Container)) {
        Write-FlickFitHost "  [復元スキップ] バックアップが見つかりません: $BackupRoot" -ForegroundColor Yellow
        return
    }
    $subs = @(Get-ChildItem -LiteralPath $BackupRoot -Directory -ErrorAction SilentlyContinue)
    if ($subs.Count -eq 0) {
        Write-FlickFitHost "  [復元スキップ] バックアップ内にフォルダがありません" -ForegroundColor Yellow
        return
    }
    $destLeaf = Split-Path $DestinationDir -Leaf
    $byName = @($subs | Where-Object { $_.Name -eq $destLeaf })
    # 名前が一致するバックアップフォルダがない場合は復元をスキップ
    # （バックアップが元ダウンロードフォルダ丸ごとの場合、誤った中身を書き込んでしまうため）
    if ($byName.Count -eq 0) {
        Write-FlickFitHost "  [復元スキップ] バックアップに「$destLeaf」と一致するフォルダがありません。" -ForegroundColor Yellow
        Write-FlickFitHost "  [復元スキップ] 現在のフォルダ内容をそのまま使って処理を再開します。" -ForegroundColor DarkGray
        return
    }
    $pick = if ($byName.Count -eq 1) { $byName[0] } else { $byName[0] }
    if ($byName.Count -gt 1) {
        Write-FlickFitHost "`n  バックアップ内のフォルダを選んでください（コピー元）:" -ForegroundColor Cyan
        for ($i = 0; $i -lt $byName.Count; $i++) {
            Write-FlickFitHost ("    [{0}] {1}" -f ($i + 1), $byName[$i].Name) -ForegroundColor Gray
        }
        $ans = (Read-HostWithEsc "  番号 (Enter=1)").Trim()
        $idx = 0
        if ($ans -match '^\d+$') { $idx = [int]$ans - 1 }
        if ($idx -lt 0 -or $idx -ge $byName.Count) { $idx = 0 }
        $pick = $byName[$idx]
    }
    Write-FlickFitHost "  [復元] $($pick.FullName) → $DestinationDir" -ForegroundColor Yellow
    if (-not (Test-Path -LiteralPath $DestinationDir)) {
        New-Item -ItemType Directory -Path $DestinationDir -Force | Out-Null
    } else {
        Remove-Item -LiteralPath (Join-Path $DestinationDir '*') -Recurse -Force -ErrorAction SilentlyContinue
        Get-ChildItem -LiteralPath $DestinationDir -Force -ErrorAction SilentlyContinue | Remove-Item -Recurse -Force -ErrorAction SilentlyContinue
    }
    Get-ChildItem -LiteralPath $pick.FullName -Force -ErrorAction Stop | ForEach-Object {
        Copy-Item -LiteralPath $_.FullName -Destination $DestinationDir -Recurse -Force -ErrorAction Stop
    }
    Write-FlickFitHost "  ✓ 復元しました" -ForegroundColor Green
}

function Invoke-FlickFitResumePrompt {
    $log = $script:ProcessLog
    if (-not $log) { return 'continue' }
    $st = $log.status
    if ($st -eq 'success') { return 'continue' }
    $last = 0
    if ($log.PSObject.Properties['lastSuccessfulStep'] -and $null -ne $log.lastSuccessfulStep) {
        try { $last = [int]$log.lastSuccessfulStep } catch { $last = 0 }
    }
    # 旧版では「STEP2 成功ログ」がスナップショットより先に書かれ、snap2 無しで last=2 になることがあった
    $snap2PathResume = $null
    try { $snap2PathResume = Join-Path (Get-FlickFitResumeSnapshotDir) '_flickfit_after_step2.clixml' } catch { $snap2PathResume = $null }
    $snap2Ok = $snap2PathResume -and (Test-Path -LiteralPath $snap2PathResume)
    $snap3PathResume = $null
    try { $snap3PathResume = Join-Path (Get-FlickFitResumeSnapshotDir) '_flickfit_after_step3.clixml' } catch { $snap3PathResume = $null }
    $snap3Ok = $snap3PathResume -and (Test-Path -LiteralPath $snap3PathResume)
    $displayLast = $last
    if ($last -ge 2 -and -not $snap2Ok) { $displayLast = 1 }
    # snap2 が存在する = STEP2 データ保存済み → 表示は「完了した STEP: 2」にする
    if ($snap2Ok -and $last -lt 2) { $displayLast = 2 }
    # lastSuccessfulStep=3 だが snap3 が無い（旧バグで STEP3 成功だけ先に書かれた等）→ 実質 STEP2 まで
    if ($last -ge 3 -and -not $snap3Ok) { $displayLast = 2 }
    $cp = $null
    if ($log.PSObject.Properties['checkpoint']) { $cp = $log.checkpoint }
    $fdCount = 0
    if ($cp -and $cp.PSObject.Properties['finalDirs'] -and $cp.finalDirs) { $fdCount = @($cp.finalDirs).Count }
    $s5done = 0
    if ($log.PSObject.Properties['step5CompletedDirs'] -and $log.step5CompletedDirs) { $s5done = @($log.step5CompletedDirs).Count }
    Write-FlickFitHost "`n  ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━" -ForegroundColor Yellow
    Write-FlickFitHost "  中断記録があります（更新: $($log.updatedAt)）" -ForegroundColor Yellow
    Write-FlickFitHost "  状態: $st ／ 再開の目安・完了した STEP: $displayLast（※スナップショットと整合した番号です）" -ForegroundColor Yellow
    if ($last -ge 2 -and -not $snap2Ok) {
        Write-FlickFitHost "  ※ 処理ログには完了STEP $last と出ていますが、STEP2 の保存ファイル（_flickfit_after_step2.clixml）が無いため、実質は STEP1 まで完了・STEP2 は未完了扱いです" -ForegroundColor Magenta
    }
    if ($last -ge 3 -and -not $snap3Ok) {
        Write-FlickFitHost "  ※ 処理ログに完了STEP $last がありますが、STEP3 の保存ファイル（_flickfit_after_step3.clixml）が無いため、実質は STEP2 まで完了・STEP3 は未完了扱いです" -ForegroundColor Magenta
    }
    if ($displayLast -ge 2) {
        Write-FlickFitHost "  ※ 上記が 2 で STEP2 保存ファイルがあるなら STEP1〜2 済みで次は STEP3 です（STEP2 のやり直しではありません）" -ForegroundColor DarkGray
    }
    $step5Done = ($log.steps -and $log.steps.PSObject.Properties['step5'] -and $log.steps.step5 -eq 'success')
    if ($fdCount -gt 0) {
        Write-FlickFitHost "  STEP 5 用チェックポイント: 巻フォルダ $fdCount 個（処理済 $s5done 個）" -ForegroundColor DarkGray
    }
    if ($log.PSObject.Properties['step5InterruptedDir'] -and $log.step5InterruptedDir) {
        $ileaf = Split-Path $log.step5InterruptedDir -Leaf
        Write-FlickFitHost "  前回の中断位置: 巻フォルダ「$ileaf」付近" -ForegroundColor Magenta
    }
    $exitKind = $null
    if ($log.PSObject.Properties['interruptKind']) { $exitKind = [string]$log.interruptKind }
    $exitStep = 0
    if ($log.PSObject.Properties['exitResumeFromStep'] -and $null -ne $log.exitResumeFromStep) {
        try { $exitStep = [int]$log.exitResumeFromStep } catch { $exitStep = 0 }
    }
    if ($exitKind -eq 'exit' -and $exitStep -ge 2) {
        Write-FlickFitHost "  前回の中断: 入力で exit（当時の STEP $exitStep 付近）※同一 STEP 内は先頭からやり直しになります" -ForegroundColor Magenta
    }
    if ($exitStep -ge 2 -and $exitStep -le 4) {
        Write-FlickFitHost "  中断記録の作業段階: STEP $exitStep（[Enter] 続行時、ログの完了STEPよりこちらが手前ならここから再開します）" -ForegroundColor DarkGray
    }
    $canExitResume = $false
    if ($exitKind -eq 'exit' -and $exitStep -ge 2 -and $exitStep -le 4) {
        $td = Get-FlickFitResumeSnapshotDir
        $p1 = Join-Path $td '_flickfit_after_step1.clixml'
        if ($exitStep -eq 2) {
            $canExitResume = (Test-Path -LiteralPath $p1)
        } elseif ($exitStep -eq 3) {
            $canExitResume = (Test-Path -LiteralPath $p1) -and (Test-Path -LiteralPath (Join-Path $td '_flickfit_after_step2.clixml'))
        } elseif ($exitStep -eq 4) {
            $canExitResume = (Test-Path -LiteralPath (Join-Path $td '_flickfit_after_step3.clixml'))
        }
    }
    if ($canExitResume) {
        Write-FlickFitHost "  [E]     exit で中断した段階から再開（STEP $exitStep 相当のスナップショット）" -ForegroundColor Cyan
    } elseif ($exitKind -eq 'exit' -and $exitStep -ge 2 -and $exitStep -le 4) {
        Write-FlickFitHost "  （exit 再開はスナップショットが揃っている場合のみ [E] が使えます）" -ForegroundColor DarkGray
    }
    Write-FlickFitHost "  [Enter] 続行（ログの完了STEPとスナップショットから次の位置へ。STEP4 済みでチェックポイントがあれば [Enter] でも STEP5 から入ります）" -ForegroundColor Cyan
    if (-not $step5Done -and $last -ge 4 -and $fdCount -gt 0) {
        Write-FlickFitHost "  [Y]     STEP 5（表紙・見開き分割）から再開（[Enter] と同じチェックポイント経路。明示したいとき用）" -ForegroundColor Cyan
    } else {
        Write-FlickFitHost "  （STEP 5 からの再開は、STEP 5 未完了かつチェックポイントがある場合のみ利用できます）" -ForegroundColor DarkGray
    }
    Write-FlickFitHost "  [R]     処理ログを消して完全に最初から（-ForceRetry と同じ）" -ForegroundColor Cyan
    Write-FlickFitHost "  [Q]     終了" -ForegroundColor Cyan
    Write-FlickFitHost "  ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━" -ForegroundColor Yellow
    $ans = (Read-HostWithEsc "  選択").Trim()
    if ($ans -match '^[qQ]$') { return 'quit' }
    if ($ans -match '^[rR]$') { return 'restart' }
    if (-not $step5Done -and $last -ge 4 -and $fdCount -gt 0 -and ($ans -eq 'Y' -or $ans -eq 'y')) { return 'step5' }
    if ($canExitResume -and ($ans -eq 'E' -or $ans -eq 'e')) { return 'exitResume' }
    return 'continue'
}
function Test-ProcessLogAllSuccess {
    if (-not $script:ProcessLog -or -not $script:ProcessLog.steps) { return $false }
    $steps = $script:ProcessLog.steps
    foreach ($n in 1..7) {
        $prop = $steps.PSObject.Properties["step$n"]
        $v = if ($prop) { $prop.Value } else { $null }
        if ($v -ne 'success') { return $false }
    }
    return $true
}
#endregion

# ===========================================================================
# 4. メイン処理
# ===========================================================================
#region Main pipeline
# 役割:
#   環境チェックから全 STEP 完了・エラー・クリーンアップまでの本番実行本体。
# 主役:
#   メイン try / catch / finally ブロック
# 注意:
#   早期 exit・ネストした function 定義・埋め込み Python 生成を含む。finally で一時ファイルとログ掃除。
$tmpCropPy = $null; $tmpSplitPy = $null; $tmpView = $null; $unpackRoot = $null
$script:WorkTrimSplitPyPath = $null
try {
    # finally ブロックで参照するため、早期 exit 経路の前に必ず初期化
    $script:ProcessingCompletedSuccessfully = $false
    Write-FlickFitHost "`n=================================================" -ForegroundColor Cyan
    Write-FlickFitHost "  FlickFit v1.0.0 - 画像をフリックに最適化する自動処理エンジン" -ForegroundColor Cyan
    Write-FlickFitHost "=================================================" -ForegroundColor Cyan
    if ($DryRun) { Write-FlickFitHost "  ★ DRY RUN モード" -ForegroundColor Yellow }
    if ($ProfileTiming) { Write-FlickFitHost "  ★ ボトルネック計測モード（処理後に内訳を表示）" -ForegroundColor DarkCyan }
    
    # Python環境チェック（初回起動PC: パス未設定・Python 実行失敗時はエラー instead of 例外で落ちるよう try-catch）
    if ($script:PythonExe) {
        $pyVer = ""
        try {
            $pyVer = (& $script:PythonExe --version 2>&1) -join ''
            if (-not ($pyVer -match 'Python\s+\d')) { $script:PythonExe = $null }
        } catch {
            Write-FlickFitHost "  [警告]: Python を実行できません（パス未設定の可能性）: $($_.Exception.Message)" -ForegroundColor Yellow
            $script:PythonExe = $null
        }
        if ($script:PythonExe) {
            Write-FlickFitHost "  Python: $pyVer ($($script:PythonExe))" -ForegroundColor DarkGray
        }
        if ($script:PythonExe) {
        # 必要パッケージのチェック（PythonExe と実行時で同一環境を使用）
        $checkScript = @"
import sys
missing = []
versions = {}
def pkg_ver(pkg_name):
    try:
        from importlib.metadata import version
        return version(pkg_name)
    except Exception:
        return None
try:
    from PIL import Image
    versions['pillow'] = pkg_ver('Pillow') or getattr(Image, '__version__', None) or '?'
except ImportError:
    missing.append('pillow')
try:
    import cv2
    versions['opencv-python'] = pkg_ver('opencv-python') or getattr(cv2, '__version__', None) or '?'
except ImportError:
    missing.append('opencv-python')
try:
    import numpy
    versions['numpy'] = pkg_ver('numpy') or getattr(numpy, '__version__', None) or '?'
except ImportError:
    missing.append('numpy')
vparts = [k + '=' + str(v).strip() for k, v in versions.items() if v]
ver_line = ','.join(vparts) if vparts else ''
if missing:
    print('MISSING:' + ','.join(missing))
else:
    print('OK' + ('|' + ver_line if ver_line else ''))
"@
        try {
            $checkResult = (& $script:PythonExe -c $checkScript 2>&1) -join ''
        } catch {
            $checkResult = "MISSING:pillow,opencv-python,numpy"
            Write-FlickFitHost "  [警告]: Python パッケージ確認中にエラー（パス・実行環境を確認してください）: $($_.Exception.Message)" -ForegroundColor Yellow
        }
        $missingBasePkgs = $null
        if ($checkResult -match 'MISSING:(.+)') { $missingBasePkgs = $Matches[1] }
        $baseOk = (-not $missingBasePkgs)
        if ($baseOk) {
            $verStr = ""
            if ($checkResult -match 'OK\|([^\r\n]+)') { $verStr = " " + ($Matches[1].Trim() -replace ',', ' ') }
            if ($verStr) { Write-FlickFitHost "  パッケージ: OK (pillow, opencv-python, numpy)$verStr" -ForegroundColor DarkGray }
            else { Write-FlickFitHost "  パッケージ: OK (pillow, opencv-python, numpy)" -ForegroundColor DarkGray }
        }

        # OCR用パッケージ / Tesseract のチェック（目次検出に使用）
        $ocrCheckScript = @"
import sys, shutil, subprocess
results = []
try:
    import pytesseract
    pytesseract_ok = True
except ImportError:
    pytesseract_ok = False
    results.append('PYTESSERACT_MISSING')
path = shutil.which('tesseract')
if not path:
    results.append('TESSERACT_MISSING')
elif pytesseract_ok:
    try:
        out = subprocess.run([path, '--version'], stdout=subprocess.PIPE, stderr=subprocess.PIPE, text=True, timeout=5)
        line = (out.stdout or out.stderr).splitlines()[0] if (out.stdout or out.stderr) else ''
        results.append('OK:' + line.strip())
    except Exception:
        results.append('OK')
elif not results:
    results.append('OK')
print('|'.join(results))
"@
        try {
            $ocrCheckResult = (& $script:PythonExe -c $ocrCheckScript 2>&1) -join ''
        } catch {
            $ocrCheckResult = "PYTESSERACT_MISSING"
        }
        $missingPytesseract = ($ocrCheckResult -match 'PYTESSERACT_MISSING')
        $missingTesseract   = ($ocrCheckResult -match 'TESSERACT_MISSING')
        if ($ocrCheckResult -match '^OK' -and -not $missingPytesseract -and -not $missingTesseract) {
            Write-FlickFitHost "  OCR: OK (pytesseract / Tesseract 利用可能)" -ForegroundColor DarkGray
        }

        # JXLプラグイン: UserConfig またはキャッシュがあればスキップ（起動時間短縮）
        $jxlAvailable = $null
        $jxlCachePath = Join-Path (Split-Path $MyInvocation.MyCommand.Path -Parent) "Modules\.jxl-plugin-cache.json"
        $jxlConfigVal = if ($script:UserConfig -and $script:UserConfig.PSObject.Properties['JxlPluginAvailable']) { $script:UserConfig.JxlPluginAvailable } else { $null }
        if ($null -ne $jxlConfigVal) {
            $jxlAvailable = [bool]$jxlConfigVal
        } elseif (Test-Path -LiteralPath $jxlCachePath) {
            try {
                $jxlCache = Get-Content -LiteralPath $jxlCachePath -Raw -Encoding UTF8 | ConvertFrom-Json
                if ($jxlCache.PythonExe -eq $script:PythonExe) { $jxlAvailable = [bool]$jxlCache.Available }
            } catch {}
        }
        if ($null -eq $jxlAvailable) {
            $jxlCheckScript = @"
try:
    import pillow_jxl
    print('OK')
except Exception:
    print('MISSING')
"@
            try {
                $jxlCheckResult = (& $script:PythonExe -c $jxlCheckScript 2>&1) -join ''
                $jxlAvailable = ($jxlCheckResult -match '^OK')
            } catch {
                $jxlAvailable = $false
            }
            try {
                @{ Available = $jxlAvailable; PythonExe = $script:PythonExe } | ConvertTo-Json | Set-Content -LiteralPath $jxlCachePath -Encoding UTF8
            } catch {}
        }
        $missingJxl = (-not $jxlAvailable)
        if ($jxlAvailable) {
            Write-FlickFitHost "  JXL: OK (pillow-jxl-plugin 利用可能)" -ForegroundColor DarkGray
        }

        # 不足分を順に案内し、PowerShellで実行するか確認
        $hasAnyMissing = $missingBasePkgs -or $missingPytesseract -or $missingTesseract -or $missingJxl
        if ($hasAnyMissing) {
            Write-FlickFitHost ""
            Write-FlickFitHost "  ========== 不足パッケージのインストール（順に実行できます） ==========" -ForegroundColor Cyan
            $pipExe = $script:PythonExe
            if ($missingBasePkgs) {
                $pkgs = @('pillow', 'opencv-python', 'numpy')
                $missList = @(($missingBasePkgs -split ',') | ForEach-Object { $_.Trim() })
                foreach ($p in $pkgs) {
                    if ($missList -contains $p) {
                        Write-FlickFitHost ""
                        Write-FlickFitHost "  [必須] $p をインストール" -ForegroundColor Yellow
                        Write-FlickFitHost "    コマンド: $pipExe -m pip install $p" -ForegroundColor White
                        $run = Read-HostWithEsc "    このコマンドを今すぐ実行しますか？ (Y/n)"
                        if ($run -notmatch '^[nN]') {
                            try {
                                & $pipExe -m pip install $p 2>&1 | ForEach-Object { Write-FlickFitHost "      $_" -ForegroundColor Gray }
                                Write-FlickFitHost "      -> 完了" -ForegroundColor Green
                            } catch { Write-FlickFitHost "      [エラー]: $_" -ForegroundColor Red }
                        }
                    }
                }
            }
            if ($missingPytesseract) {
                Write-FlickFitHost ""
                Write-FlickFitHost "  [任意] pytesseract をインストール（目次検出用）" -ForegroundColor Yellow
                Write-FlickFitHost "    コマンド: $pipExe -m pip install pytesseract" -ForegroundColor White
                $run = Read-HostWithEsc "    このコマンドを今すぐ実行しますか？ (Y/n)"
                if ($run -notmatch '^[nN]') {
                    try { & $pipExe -m pip install pytesseract 2>&1 | ForEach-Object { Write-FlickFitHost "      $_" -ForegroundColor Gray }; Write-FlickFitHost "      -> 完了" -ForegroundColor Green } catch { Write-FlickFitHost "      [エラー]: $_" -ForegroundColor Red }
                }
            }
            if ($missingTesseract) {
                Write-FlickFitHost ""
                Write-FlickFitHost "  [任意] Tesseract（別途インストール・Pythonパッケージではない）" -ForegroundColor Yellow
                Write-FlickFitHost "    1. 検索「UB Mannheim Tesseract」→ tesseract-ocr-w64-* をDL" -ForegroundColor White
                Write-FlickFitHost "    2. インストール後、PATH に追加: C:\Program Files\Tesseract-OCR" -ForegroundColor White
                Write-FlickFitHost "    3. ターミナル再起動後 tesseract --version で確認" -ForegroundColor White
                $run = Read-HostWithEsc "    ダウンロードページを開きますか？ (Y/n)"
                if ($run -notmatch '^[nN]') { try { Start-Process "https://github.com/UB-Mannheim/tesseract/wiki" } catch {} }
            }
            if ($missingJxl) {
                Write-FlickFitHost ""
                Write-FlickFitHost "  [任意] pillow-jxl-plugin をインストール（JXL画像対応）" -ForegroundColor Yellow
                Write-FlickFitHost "    コマンド: $pipExe -m pip install pillow-jxl-plugin" -ForegroundColor White
                $run = Read-HostWithEsc "    このコマンドを今すぐ実行しますか？ (Y/n)"
                if ($run -notmatch '^[nN]') {
                    try { & $pipExe -m pip install pillow-jxl-plugin 2>&1 | ForEach-Object { Write-FlickFitHost "      $_" -ForegroundColor Gray }; Write-FlickFitHost "      -> 完了" -ForegroundColor Green } catch { Write-FlickFitHost "      [エラー]: $_" -ForegroundColor Red }
                }
            }
            Write-FlickFitHost ""
            Write-FlickFitHost "  ================================================================" -ForegroundColor Cyan
            Write-FlickFitHost ""
            $continueAns = Read-HostWithEsc "  インストール後はスクリプト再起動で反映されます。いま続行しますか？ (y/N)"
            if ($continueAns -notmatch '^[yY]') {
                throw "中断: 不足パッケージをインストールしてから再実行してください"
            }
            if ($missingBasePkgs) {
                Write-FlickFitHost "  [注意]: 画像処理に必須のパッケージが未導入の可能性があります。再起動後に確認されます" -ForegroundColor Yellow
            }
        }
    } else {
        Write-FlickFitHost "  [警告]: Python が見つかりません（未インストール または PATH 未設定）" -ForegroundColor Yellow
        Write-FlickFitHost ""
        $cands = if (Get-Variable -Name 'PythonCandidatesForHelp' -Scope Script -ErrorAction SilentlyContinue) { $script:PythonCandidatesForHelp } else { @() }
        if ($cands -and $cands.Count -gt 0) {
            Write-FlickFitHost "  ※ 以下は見つかりましたが実行できませんでした（PATH 未設定の可能性）:" -ForegroundColor Gray
            foreach ($c in $cands) {
                Write-FlickFitHost "    $c" -ForegroundColor White
            }
            Write-FlickFitHost ""
            Write-FlickFitHost "  【PATH に追加する値】コピーして環境変数 Path に追加してください（.exe まで含む）:" -ForegroundColor Cyan
            $dirToAdd = Split-Path $cands[0] -Parent
            Write-FlickFitHost "    $dirToAdd" -ForegroundColor White
            Write-FlickFitHost ""
            Write-FlickFitHost "  【UserConfig.json で直接指定する場合】Modules\UserConfig.json に追記:" -ForegroundColor Cyan
            Write-FlickFitHost "    `"PythonExe`": `"$($cands[0])`"" -ForegroundColor White
        } else {
            Write-FlickFitHost "  Python のインストール方法:" -ForegroundColor Cyan
            Write-FlickFitHost "    1. https://www.python.org/downloads/ からダウンロード" -ForegroundColor White
            Write-FlickFitHost "    2. インストール時「Add Python to PATH」にチェック" -ForegroundColor White
            Write-FlickFitHost "    3. ターミナル（PowerShell）を再起動" -ForegroundColor White
            Write-FlickFitHost "    推奨: Python 3.10 〜 3.12" -ForegroundColor DarkGray
        }
        Write-FlickFitHost ""
        $openPy = Read-HostWithEsc "  Python のダウンロードページを開きますか？ (y/N)"
        if ($openPy -match '^[yY]$') {
            try { Start-Process "https://www.python.org/downloads/" } catch {}
        }
        Write-FlickFitHost ""
        $continueAns = Read-HostWithEsc "  Python 未設定のまま続行しますか？ (y/N)"
        if ($continueAns -notmatch '^[yY]') {
            throw "中断: Python をインストール・PATH設定してから再実行してください"
        }
        Write-FlickFitHost "  [注意]: 画像処理機能は利用できません" -ForegroundColor Yellow
    }
    }
    
    if (-not $script:WinRAR) {
        Write-FlickFitHost "  [警告]: WinRAR が見つかりません（RAR 出力時に必要）。" -ForegroundColor Yellow
        Write-FlickFitHost "    → 標準インストール、または Modules\UserConfig.json の `"WinRAR`" に WinRAR.exe のフルパスを指定してください。" -ForegroundColor DarkGray
    }

    # 作品名フォルダの決定
    $baseWorkDir = (Get-Location).Path
    $scriptPath = $MyInvocation.MyCommand.Path
    
    # TargetFolderパラメータが指定されている場合はそれを使用
    if ($TargetFolder -and (Test-Path -LiteralPath $TargetFolder -PathType Container)) {
        $script:TitleFolder = Get-Item -LiteralPath $TargetFolder
        $script:TitleName = $script:TitleFolder.Name
    } else {
        # 作品名フォルダの検出（作業フォルダ直下のサブフォルダ）
        # docs / python_pass はツール同梱用で作品ではないため除外
        $excludeToolFolders = '^_|^Modules$|^tools$|^docs$|^python_pass$|^\.(git|cursor|vscode)$'
        $titleFolders = @(Get-ChildItem -Path $baseWorkDir -Directory -ErrorAction SilentlyContinue | 
            Where-Object { $_.Name -notmatch $excludeToolFolders })
        
        if ($titleFolders.Count -eq 0) {
            throw "エラー: 作業フォルダ直下に作品名フォルダが見つかりません。`n作品名のフォルダを作成し、その中に圧縮ファイルを配置してください。"
        }
        
        # 複数フォルダがある場合、各フォルダに対して別プロセスを起動
        if ($titleFolders.Count -gt 1) {
            Write-FlickFitHost "`n複数の作品フォルダが見つかりました:" -ForegroundColor Yellow
            $titleFolders | ForEach-Object { Write-FlickFitHost "  - $($_.Name)" -ForegroundColor Cyan }
            Write-FlickFitHost "`n各作品に対してスクリプトを起動します..." -ForegroundColor Green
            
            $launcher = Get-FlickFitPowerShellLauncher
            if ($launcher -match 'powershell\.exe$' -and $PSVersionTable.PSEdition -eq 'Core') {
                Write-FlickFitHost "  [注意] pwsh が見つからないため Windows PowerShell 5.1 で起動します。PowerShell 7 を PATH に入れると通常起動と同じ環境になります。" -ForegroundColor Yellow
            }
            
            $extraArgs = @()
            if ($RenumberOnly) { $extraArgs += '-RenumberOnly' }
            if ($ProfileTiming) { $extraArgs += '-ProfileTiming' }
            if ($DryRun) { $extraArgs += '-DryRun' }
            if ($ForceRetry) { $extraArgs += '-ForceRetry' }
            if ($PhotosBgAiOnly) { $extraArgs += '-PhotosBgAiOnly' }
            foreach ($folder in $titleFolders) {
                $folderPath = $folder.FullName
                $folderName = $folder.Name
                Write-FlickFitHost "  → 起動: $folderName" -ForegroundColor Gray
                
                $argsList = @('-ExecutionPolicy', 'Bypass', '-File', $scriptPath, '-TargetFolder', $folderPath)
                if ($extraArgs.Count -gt 0) { $argsList = $argsList + $extraArgs }
                Start-Process -FilePath $launcher -ArgumentList $argsList -WorkingDirectory $baseWorkDir
                Start-Sleep -Milliseconds 500
            }
            
            Write-FlickFitHost "`n✅ $($titleFolders.Count) 個のスクリプトを起動しました。" -ForegroundColor Green
            Write-FlickFitHost "   各ウィンドウで処理が進行します。" -ForegroundColor DarkGray
            $null = Read-Host "`nEnterで終了"
            exit 0
        }
        
        $script:TitleFolder = $titleFolders[0]
        $script:TitleName = $script:TitleFolder.Name
    }
    
    # ウィンドウタイトルに作品名を設定
    $Host.UI.RawUI.WindowTitle = "処理中: $($script:TitleName)"
    
    Write-FlickFitHost ""
    Write-FlickFitHost "═══════════════════════════════════════════════════════════" -ForegroundColor Cyan
    Write-FlickFitHost "  「$($script:TitleName)」の作業を開始します" -ForegroundColor Green
    Write-FlickFitHost "═══════════════════════════════════════════════════════════" -ForegroundColor Cyan
    Write-FlickFitHost "  中断は各ステップの確認項目時に行えます" -ForegroundColor DarkGray
    Write-FlickFitHost ""
    
    # キャンセル用フラグ（GUI実装時、キャンセルボタンから $script:CancelRequested = $true を設定）
    $script:CancelRequested = $false
    
    # 作品名フォルダに移動して作業
    Set-Location -LiteralPath $script:TitleFolder.FullName
    
    # ===== 連番のみふり直しモード =====
    if ($RenumberOnly) {
        Write-FlickFitHost "`n  [連番のみふり直し] 画像の連番を振り直します" -ForegroundColor Cyan
        $leaves = Get-LeafFolders (Get-Location).Path
        $renumberCount = 0
        foreach ($leaf in $leaves) {
            $imgs = @(Get-ChildItem -LiteralPath $leaf.Path -File -ErrorAction SilentlyContinue | Where-Object { $script:ImageExtensions -contains $_.Extension.ToLower() })
            if ($imgs.Count -gt 0) {
                Write-FlickFitHost "    📁 $($leaf.Name) ($($imgs.Count) 枚) ..." -ForegroundColor Gray
                Renumber-Images $leaf.Path
                $renumberCount++
            }
        }
        Write-FlickFitHost "`n  ✓ $renumberCount フォルダの連番を振り直しました" -ForegroundColor Green
        $null = Read-Host "`nDone. Enterで終了"
        exit 0
    }
    
    # ===== 処理ログ（リトライ対応） =====
    $script:ProcessingCompletedSuccessfully = $false
    $script:FlickFitRetrimCandidates = [System.Collections.Generic.List[hashtable]]::new()
    $script:ProcessLogPath = Get-ProcessLogPath
    if ($ForceRetry -and (Test-Path -LiteralPath $script:ProcessLogPath)) {
        Remove-Item -LiteralPath $script:ProcessLogPath -Force -ErrorAction SilentlyContinue
        Write-FlickFitHost "  [リトライ] 処理ログをリセットしました" -ForegroundColor DarkGray
    }
    $script:ProcessLog = Load-ProcessLog
    if ($script:ProcessLog -and $script:ProcessLog.status -eq 'success') {
        Write-FlickFitHost "`n  ※ 処理は完了済みです。再実行するには -ForceRetry を指定してください" -ForegroundColor Green
        $null = Read-Host "`nEnterで終了"
        exit 0
    }
    $script:ProcessLogJustCreated = $false
    if (-not $script:ProcessLog) {
        $script:ProcessLog = [PSCustomObject]@{
            version      = 1
            targetFolder = $script:TitleFolder.FullName
            startedAt    = (Get-Date).ToString("yyyy-MM-ddTHH:mm:ss")
            updatedAt    = (Get-Date).ToString("yyyy-MM-ddTHH:mm:ss")
            status       = "in_progress"
            steps        = [PSCustomObject]@{}
            lastError    = $null
        }
        Save-ProcessLog $script:ProcessLog
        $script:ProcessLogJustCreated = $true
    }
    if ($ForceRetry) {
        Reset-FlickFitStep2ResumeState -FullRestart
        Write-FlickFitHost "  [リトライ] STEP2 途中の進捗（_flickfit_step2_progress.clixml）と表紙の仮状態をクリアしました" -ForegroundColor DarkGray
        Write-FlickFitHost "  [リトライ] 次の開始位置: STEP1（解凍・バックアップ）の先頭から" -ForegroundColor Cyan
    }
    $script:ResumeFromStep = 1
    $script:CurrentProcessPhase = 'idle'
    $script:CurrentStep5Dir = $null
    $script:CurrentProcessStepNumber = 1
    if (-not $ForceRetry -and -not $script:ProcessLogJustCreated -and $script:ProcessLog -and $script:ProcessLog.status -ne 'success') {
        $resumeChoice = Invoke-FlickFitResumePrompt
        if ($resumeChoice -eq 'quit') {
            return
        }
        if ($resumeChoice -eq 'restart') {
            if ($script:ProcessLogPath -and (Test-Path -LiteralPath $script:ProcessLogPath)) {
                Remove-Item -LiteralPath $script:ProcessLogPath -Force -ErrorAction SilentlyContinue
            }
            $script:ProcessLog = [PSCustomObject]@{
                version      = 1
                targetFolder = $script:TitleFolder.FullName
                startedAt    = (Get-Date).ToString("yyyy-MM-ddTHH:mm:ss")
                updatedAt    = (Get-Date).ToString("yyyy-MM-ddTHH:mm:ss")
                status       = "in_progress"
                steps        = [PSCustomObject]@{}
                lastError    = $null
            }
            Save-ProcessLog $script:ProcessLog
            $script:ProcessLogJustCreated = $true
            $script:ResumeFromStep = 1
            Reset-FlickFitStep2ResumeState -FullRestart
            Write-FlickFitHost "  [再開] STEP2 途中の進捗スナップショットと表紙の仮状態をクリアしました（最初から）" -ForegroundColor DarkGray
            Write-FlickFitHost "  [再開] 次の開始位置: STEP1（解凍・バックアップ）の先頭から" -ForegroundColor Cyan
        }
        elseif ($resumeChoice -eq 'step5') {
            $script:ResumeFromStep = 5
        }
        elseif ($resumeChoice -eq 'exitResume') {
            $n = 2
            if ($script:ProcessLog.PSObject.Properties['exitResumeFromStep'] -and $null -ne $script:ProcessLog.exitResumeFromStep) {
                try { $n = [int]$script:ProcessLog.exitResumeFromStep } catch { $n = 2 }
            }
            if ($n -lt 2) { $n = 2 }
            if ($n -gt 5) { $n = 5 }
            $script:ResumeFromStep = $n
        }
    }
    # [Enter] 続行時: ログの lastSuccessfulStep から「次の STEP」を推定し、スナップショットが揃っていればそこへ。
    # 加えて exit で中断したときは exitResumeFromStep を優先（STEP2 途中なのに完了STEPだけ 2 になって STEP3 と出るのを防ぐ）
    if (-not $ForceRetry -and $script:ResumeFromStep -eq 1 -and $script:ProcessLog -and -not $script:ProcessLogJustCreated) {
        $lastOk = 0
        if ($script:ProcessLog.PSObject.Properties['lastSuccessfulStep'] -and $null -ne $script:ProcessLog.lastSuccessfulStep) {
            try { $lastOk = [int]$script:ProcessLog.lastSuccessfulStep } catch { $lastOk = 0 }
        }
        $td = Get-FlickFitResumeSnapshotDir
        $snap1 = Join-Path $td '_flickfit_after_step1.clixml'
        $snap2 = Join-Path $td '_flickfit_after_step2.clixml'
        $snap3 = Join-Path $td '_flickfit_after_step3.clixml'
        $computedResume = 1
        $hasStep5Cp = $false
        # ログだけ STEP3 完了になっていても snap3 が無ければ巻は未確定 → 再開推定を STEP2 までに戻す
        if ($lastOk -ge 3 -and -not (Test-Path -LiteralPath $snap3)) {
            $lastOk = 2
        }
        if ($script:ProcessLog.PSObject.Properties['checkpoint'] -and $script:ProcessLog.checkpoint -and $script:ProcessLog.checkpoint.PSObject.Properties['finalDirs'] -and $script:ProcessLog.checkpoint.finalDirs) {
            $hasStep5Cp = @($script:ProcessLog.checkpoint.finalDirs).Count -gt 0
        }
        $step5LoggedSuccess = ($script:ProcessLog.steps -and $script:ProcessLog.steps.PSObject.Properties['step5'] -and $script:ProcessLog.steps.step5 -eq 'success')
        $step6LoggedSuccess = ($script:ProcessLog.steps -and $script:ProcessLog.steps.PSObject.Properties['step6'] -and $script:ProcessLog.steps.step6 -eq 'success')
        # 再開推定: STEP5 完了・STEP6 未なら 6（旧ロジックでは step5 success 後に snap3 へ落ち STEP4 扱い→volMap 空の重複確認になり得た）
        # lastSuccessfulStep=4 は次が STEP5。従来 snap3 のみで 4 固定だったため STEP5 途中中断→[Enter] で STEP4 やり直し→第○巻だけ残り同様の不整合があった。
        if ($step5LoggedSuccess -and -not $step6LoggedSuccess -and $hasStep5Cp) {
            $computedResume = 6
        } elseif ($lastOk -ge 4 -and $hasStep5Cp -and -not $step5LoggedSuccess) {
            $computedResume = 5
        } elseif ($lastOk -ge 3 -and (Test-Path -LiteralPath $snap3)) {
            $computedResume = 4
        } elseif (Test-Path -LiteralPath $snap2) {
            # snap2 が存在 = STEP2 データ保存済み。lastSuccessfulStep の値に関わらず STEP3 から再開。
            # （STEP2完了ログは STEP3 移行時に書かれるため、snap2 存在が「STEP2データ準備完了」の唯一の証拠）
            $computedResume = 3
        } elseif ($lastOk -ge 1 -and (Test-Path -LiteralPath $snap1)) {
            # STEP1 済みで STEP2 未完了（snap2 無し）→ STEP2 先頭から
            $computedResume = 2
        }
        $script:ResumeFromStep = $computedResume
        $exitStep = 0
        if ($script:ProcessLog.PSObject.Properties['exitResumeFromStep'] -and $null -ne $script:ProcessLog.exitResumeFromStep) {
            try { $exitStep = [int]$script:ProcessLog.exitResumeFromStep } catch { $exitStep = 0 }
        }
        $exitKindForResume = $null
        if ($script:ProcessLog.PSObject.Properties['interruptKind']) { $exitKindForResume = [string]$script:ProcessLog.interruptKind }
        # 中断時点が「ログから推定した次の STEP」より手前なら、exitResumeFromStep を採用
        # ただし exitStep=2 かつ snap2 が存在する場合は「STEP2 データ保存済み」なので STEP3 維持（STEP2 に戻さない）
        # STEP5 チェックポイントで続行すべきときは、古い exit 記録で 5 へ行くのを潰さない（interruptKind=exit のときだけ exit 上書きを評価）
        $allowExitStepOverride = ($exitKindForResume -eq 'exit') -and -not (
            ($lastOk -ge 4 -and $hasStep5Cp -and -not $step5LoggedSuccess -and $computedResume -eq 5) -or
            ($step5LoggedSuccess -and -not $step6LoggedSuccess -and $hasStep5Cp -and $computedResume -eq 6)
        )
        if ($allowExitStepOverride -and $exitStep -ge 2 -and $exitStep -le 4 -and $exitStep -lt $computedResume) {
            $snapOk = $false
            if ($exitStep -eq 2) {
                # snap2 がある = STEP2 完了データ保存済み。STEP2 に戻すと Reset でデータ消失するため STEP3 を維持する
                if (-not (Test-Path -LiteralPath $snap2)) {
                    $snapOk = (Test-Path -LiteralPath $snap1)
                }
            }
            elseif ($exitStep -eq 3) { $snapOk = (Test-Path -LiteralPath $snap1) -and (Test-Path -LiteralPath $snap2) }
            elseif ($exitStep -eq 4) { $snapOk = (Test-Path -LiteralPath $snap3) }
            if ($snapOk) { $script:ResumeFromStep = $exitStep }
        }
    }
    # 初回作成ログ（今回が初実行）では「再開」表示を出さない
    if (-not $ForceRetry -and -not $script:ProcessLogJustCreated) {
        $startHint = switch ([int]$script:ResumeFromStep) {
            1 { 'STEP1（解凍・バックアップ）の先頭から' }
            2 { 'STEP2（構造解析・振り分け）の先頭から ※前回の途中選択は復元しません' }
            3 { 'STEP3（作品名・作者名）の先頭から' }
            4 { 'STEP4 以降の先頭から' }
            5 { 'STEP5 の先頭から' }
            6 { 'STEP6（圧縮）の先頭から' }
            default { "STEP $($script:ResumeFromStep) から" }
        }
        Write-FlickFitHost "  [再開] 次の開始位置: $startHint" -ForegroundColor Cyan
    }
    
    # 自動で「全部実行」モード
    $choice = '1'
    $runPhaseA = $true
    $runPhaseB = $true

    # 埋め込み Python 用: TEMP/AppData は AV でブロックされやすい → スクリプト親フォルダの tools\flickfit_worker に固定名（tools にまとめて許可しやすい）
    $scriptRootForWorker = $null
    try { $scriptRootForWorker = Split-Path -Parent $script:MyInvocation.MyCommand.Path } catch {}
    if ([string]::IsNullOrWhiteSpace($scriptRootForWorker)) { $scriptRootForWorker = (Get-Location).Path }
    $script:FlickFitWorkerDir = Join-Path (Join-Path $scriptRootForWorker "tools") "flickfit_worker"
    if (-not (Test-Path -LiteralPath $script:FlickFitWorkerDir)) { New-Item -ItemType Directory -Path $script:FlickFitWorkerDir -Force | Out-Null }
    $pyWorkDir = $script:FlickFitWorkerDir
    $tmpCropPy = Join-Path $pyWorkDir "_vcrop_work.py"
    $tmpSplitPy = Join-Path $pyWorkDir "_vsplit_work.py"
    Set-Content -LiteralPath $tmpCropPy -Value $script:PythonCropCode -Encoding UTF8
    Set-Content -LiteralPath $tmpSplitPy -Value $script:PythonSplitCode -Encoding UTF8

    # 再開5/6 時は必ず入る必要あり。旧 lt 5 だと本文（STEP5〜7 含む）が飛ばされ try が空→finally のみになっていた
    if ($script:ResumeFromStep -le 6) {
    if ($script:ResumeFromStep -lt 2) {
    $script:CurrentProcessStepNumber = 1
    # ===== STEP 1: 解凍 =====
    $cancelRef = [ref]$script:CancelRequested
    $extractResult = Invoke-FlickFitExtract `
        -WorkDir (Get-Location).Path `
        -ArchiveExtensions $script:ArchiveExtensions `
        -ImageExtensions $script:ImageExtensions `
        -ConvertExtensions $script:ConvertExtensions `
        -WinRAR $script:WinRAR `
        -PythonExe $script:PythonExe `
        -DryRun $DryRun `
        -RunPhaseA $runPhaseA `
        -CancelRequested $cancelRef
    $unpackRoot = $extractResult.UnpackRoot
    $targetRoots = $extractResult.TargetRoots
    $script:epubFolderVolMap      = $extractResult.EpubFolderVolMap
    $script:epubCoverMap          = $extractResult.EpubCoverMap
    $script:epubMainFolderMap     = $extractResult.EpubMainFolderMap
    $script:epubTitleMap          = if ($extractResult.EpubTitleMap)      { $extractResult.EpubTitleMap }      else { @{} }
    $script:epubCreatorMap        = if ($extractResult.EpubCreatorMap)    { $extractResult.EpubCreatorMap }    else { @{} }
    $script:epubSpineImageMap     = if ($extractResult.EpubSpineImageMap) { $extractResult.EpubSpineImageMap } else { @{} }
    $script:selectedExistingFolders    = $extractResult.SelectedExistingFolders
    $script:selectedArchives           = $extractResult.SelectedArchives
    $script:subfolderArchivesToProcess = $extractResult.SubfolderArchivesToProcess
    Set-FlickFitSourceArchivePathsForDeletion -FromArchives $script:selectedArchives -FromSubfolder $script:subfolderArchivesToProcess

    # ===== 画像フォルダのみの場合: 処理前にバックアップ =====
    $hasArchives = $script:selectedArchives -and $script:selectedArchives.Count -gt 0
    $hasExistingOnly = $script:selectedExistingFolders -and $script:selectedExistingFolders.Count -gt 0 -and -not $hasArchives
    if ($hasExistingOnly -and -not $DryRun) {
        $ts = Get-Date -Format "yyyyMMdd_HHmmss"
        $sep = [char][System.IO.Path]::DirectorySeparatorChar
        # バックアップ先がコピー元フォルダの「内側」だと、Copy-Item -Recurse が _backup を再帰コピーして無限に近いループになる
        $candRoot = Join-Path $pyWorkDir ("_backup_$ts")
        $backupParent = $pyWorkDir
        foreach ($folderPath in $script:selectedExistingFolders) {
            if (-not (Test-Path -LiteralPath $folderPath -PathType Container)) { continue }
            try {
                $fullFolder = [System.IO.Path]::GetFullPath($folderPath).TrimEnd('\')
                $fullCand = [System.IO.Path]::GetFullPath($candRoot).TrimEnd('\')
                if ($fullCand.StartsWith($fullFolder + $sep, [StringComparison]::OrdinalIgnoreCase)) {
                    $backupParent = Split-Path $fullFolder -Parent
                    break
                }
            } catch {}
        }
        if ($backupParent -eq $pyWorkDir) {
            $backupRoot = $candRoot
        } else {
            $leaf = Split-Path $pyWorkDir -Leaf
            $safeLeaf = ($leaf -replace '[<>:"/\\|?*]', '_').Trim()
            if (-not $safeLeaf) { $safeLeaf = 'work' }
            $backupRoot = Join-Path $backupParent ("_backup_${safeLeaf}_$ts")
        }
        New-Item -ItemType Directory -Path $backupRoot -Force | Out-Null
        Write-FlickFitHost "`n  [バックアップ]: 既存フォルダを処理開始前にバックアップします" -ForegroundColor Cyan
        foreach ($folderPath in $script:selectedExistingFolders) {
            if (-not (Test-Path -LiteralPath $folderPath -PathType Container)) { continue }
            $folderName = Split-Path $folderPath -Leaf
            $destPath = Join-Path $backupRoot $folderName
            Write-FlickFitHost "    📁 $folderName → $backupRoot" -ForegroundColor Gray
            Copy-Item -LiteralPath $folderPath -Destination $destPath -Recurse -Force -ErrorAction SilentlyContinue
        }
        Write-FlickFitHost "  ✓ バックアップ完了: $backupRoot`n" -ForegroundColor DarkGray
        if ($script:ProcessLog) {
            $script:ProcessLog | Add-Member -NotePropertyName 'backupRoot' -NotePropertyValue $backupRoot -Force
            $bleaves = @($script:selectedExistingFolders | ForEach-Object { Split-Path $_ -Leaf })
            $script:ProcessLog | Add-Member -NotePropertyName 'backupEntryLeaves' -NotePropertyValue @($bleaves) -Force
            Save-ProcessLog $script:ProcessLog
        }
    }

    # ===== 解凍後の画像形式変換（TIF/PNG等→JPG） =====
    if ($targetRoots.Count -gt 0 -and $script:PythonExe) {
        # 変換対象ファイルがあるか事前チェック
        $convertibleFiles = @()
        foreach ($targetDir in $targetRoots) {
            $convertibleFiles += @(Get-ChildItem -LiteralPath $targetDir -Recurse -File -ErrorAction SilentlyContinue | 
                Where-Object { $script:ConvertExtensions -contains $_.Extension.ToLower() })
        }
        
        if ($convertibleFiles.Count -gt 0) {
            Write-FlickFitHost "`n  [画像形式変換]: $($convertibleFiles.Count) 個の変換対象ファイルを検出" -ForegroundColor Cyan
            
            # フォルダごとにグループ化して変換
            $folderGroups = $convertibleFiles | Group-Object { Split-Path $_.FullName -Parent }
            foreach ($group in $folderGroups) {
                $folderPath = $group.Name
                $folderName = Split-Path $folderPath -Leaf
                Write-FlickFitHost "    📁 $folderName ($($group.Count) 個)" -ForegroundColor Gray
                Convert-ToJpg -Path $folderPath
            }
            Write-FlickFitHost ""
        }
    }
    Update-ProcessLogStep -StepNum 1 -Status "success"
    Save-FlickFitAfterStep1Snapshot
    } elseif ($script:ResumeFromStep -eq 2) {
        Write-FlickFitHost "`n  [再開] STEP 1（解凍・バックアップ）をスキップ（スナップショットから復元）" -ForegroundColor Cyan
        Write-FlickFitHost "  [再開] STEP2 は未完了のときは常に「振り分け・表紙」の対話を最初から行います" -ForegroundColor DarkGray
        Restore-FlickFitAfterStep1Snapshot
    } else {
        Write-FlickFitHost "`n  [再開] STEP 1 をスキップ" -ForegroundColor DarkGray
    }

    # StrictMode: STEP1 を通らずに再開した場合、EPUB 由来マップが未束縛のまま参照されるのを防ぐ
    if (-not (Get-Variable -Name 'epubTitleMap' -Scope Script -ErrorAction SilentlyContinue)) { $script:epubTitleMap = @{} }
    if (-not (Get-Variable -Name 'epubCreatorMap' -Scope Script -ErrorAction SilentlyContinue)) { $script:epubCreatorMap = @{} }
    if (-not (Get-Variable -Name 'epubSpineImageMap' -Scope Script -ErrorAction SilentlyContinue)) { $script:epubSpineImageMap = @{} }

    if ($script:ResumeFromStep -lt 3) {
    $script:CurrentProcessStepNumber = 2
    # ===== STEP 2: 構造解析 =====
    Write-Step "STEP 2: 構造解析・巻数判定"
    # STEP2 へ入った時点で「STEP2 完了扱い」を必ず無効化する。
    # （中断時に old after_step2/success が残っていると、次回の再開表示が STEP3 先頭になってしまうため）
    Reset-FlickFitStep2ResumeState
    if (Get-Command Ensure-FlickFitVolumePatternRegexes -ErrorAction SilentlyContinue) { Ensure-FlickFitVolumePatternRegexes }
    $allLeaves = [System.Collections.Generic.List[PSObject]]::new()
    foreach ($targetDir in $targetRoots) {
        $realRoot = Get-RealRoot $targetDir
        foreach ($leaf in (Get-LeafFolders $realRoot)) { $allLeaves.Add($leaf) }
    }
    if ($allLeaves.Count -eq 0) {
        Write-FlickFitHost ("  [Step2Debug] ResumeFromStep={0}  targetRoots={1}  （リーフ列挙は EPUB 解凍先 _unpacked を含む。再開用の _unpacked 除外は別スイッチのみ）" -f $script:ResumeFromStep, $targetRoots.Count) -ForegroundColor DarkGray
        Write-FlickFitHost "`n  [情報]: 対象画像がありません。作業を終了します。" -ForegroundColor Yellow
        $bpgLeft = 0
        foreach ($td in $targetRoots) {
            $bpgLeft += @(Get-ChildItem -LiteralPath $td -Recurse -File -ErrorAction SilentlyContinue | Where-Object { $_.Extension.ToLower() -eq '.bpg' }).Count
        }
        if ($bpgLeft -gt 0) {
            Write-FlickFitHost "  （.bpg が $bpgLeft 件残っています。デコード失敗・ファイル破損・拡張子だけ BPG の別形式の可能性があります）" -ForegroundColor DarkGray
        }
        # 失敗扱いの処理ログを残さない（次回起動でリトライ扱いにならないよう削除）
        if ($script:ProcessLogPath -and (Test-Path -LiteralPath $script:ProcessLogPath)) {
            try { Remove-Item -LiteralPath $script:ProcessLogPath -Force -ErrorAction SilentlyContinue } catch {}
        }
        $script:ProcessingCompletedSuccessfully = $true
        try { $Host.UI.RawUI.WindowTitle = 'FlickFit' } catch {}
        return
    }
    # パス階層から作者名・日本語作品名を含むフォルダ名を優先して取得（解凍対象フォルダ内のみ、親のワークスペース等は除外）
    $script:CandidateNames = [System.Collections.Generic.HashSet[string]]::new([System.StringComparer]::OrdinalIgnoreCase)
    $candidateNames = $script:CandidateNames
    $targetRootsNorm = @($targetRoots | ForEach-Object { $p = $_; $resolved = try { (Resolve-Path -LiteralPath $p -ErrorAction Stop).Path } catch { $p }; $resolved.TrimEnd('\') })
    foreach ($leaf in $allLeaves) {
        $leafPath = $leaf.Path.TrimEnd('\')
        $containingRoot = $targetRootsNorm | Where-Object { $leafPath.StartsWith($_.TrimEnd('\') + '\') -or $leafPath -eq $_.TrimEnd('\') } | Select-Object -First 1
        $stopAt = if ($containingRoot) { (Split-Path $containingRoot -Parent) } else { $null }
        $p = $leaf.Path
        while ($p) {
            $seg = Split-Path $p -Leaf
            if ($seg) { [void]$candidateNames.Add($seg) }
            $parent = Split-Path $p -Parent
            if (-not $parent -or $parent -eq $p) { break }
            if ($stopAt -and ($parent -eq $stopAt -or $parent.TrimEnd('\') -eq $stopAt.TrimEnd('\'))) { break }
            $p = $parent
        }
    }
    $bestScore = -1; $script:BestRawName = ""
    # 作品名候補を収集（日本語を含むもの、スコア順）
    $script:TitleCandidates = [System.Collections.Generic.List[PSObject]]::new()
    foreach ($name in $candidateNames) {
        $score = 0
        # 作者名を含む[xxx]形式があれば高スコア（作品名フォルダの可能性大）
        if ($name -match '\[[^\]]*[ぁ-んァ-ヶ一-龯][^\]]*\]') { $score += 10 }
        # 日本語で始まる
        if ($name -match '^[ぁ-んァ-ヶ一-龯]') { $score += 4 }
        # 日本語を含む
        if ($name -match '[ぁ-んァ-ヶ一-龯]') { $score += 2 }
        # 「第XX巻」形式を含む（作品名フォルダの可能性大）
        if ($name -match '第\s*\d+\s*巻') { $score += 5 }
        # 「第XX話」形式は話数フォルダなのでスコア大幅減点（小数点付き対応）
        if ($name -match '第\s*\d+(?:\.\d+)?\s*話') { $score -= 20 }
        # 「chapterXX」形式も話数フォルダなのでスコア減点（小数点付き対応）
        if ($name -match '(?i)chapter\s*\d+(?:\.\d+)?') { $score -= 20 }
        # 「前編」「後編」を含む場合も話数フォルダ
        if ($name -match '[（\(]?[前後]編[）\)]?') { $score -= 10 }
        if ($score -gt $bestScore) { $bestScore = $score; $script:BestRawName = $name }
        # 日本語を含み、話数パターンを含まないもののみ候補に追加（小数点付き対応）
        $isChapterFolder = $name -match '第\s*\d+(?:\.\d+)?\s*話' -or $name -match '(?i)chapter\s*\d+(?:\.\d+)?' -or $name -match '[（\(]?[前後]編[）\)]?'
        if ($name -match '[ぁ-んァ-ヶ一-龯]' -and -not $isChapterFolder) {
            $script:TitleCandidates.Add([PSCustomObject]@{ Name=$name; Score=$score })
        }
    }
    # スコア順にソート、重複除去（Name文字列の配列として保存）
    $script:TitleCandidates = @($script:TitleCandidates | Sort-Object -Property Score -Descending | ForEach-Object { $_.Name } | Select-Object -Unique)
    # EPUBのOPFメタデータからタイトルを先頭候補として追加
    if ($script:epubTitleMap -and $script:epubTitleMap.Count -gt 0) {
        $epubTitles = @($script:epubTitleMap.Values | Where-Object { $_ } | Select-Object -Unique)
        if ($epubTitles.Count -gt 0) {
            $epubTitleCleaned = @($epubTitles | ForEach-Object { Extract-TitleFromName $_ } | Where-Object { $_ } | Select-Object -Unique)
            # 先頭に追加（OPFタイトルが最優先）
            $script:TitleCandidates = @($epubTitleCleaned) + @($script:TitleCandidates | Where-Object { $_ -notin $epubTitleCleaned })
            if ($epubTitleCleaned.Count -gt 0 -and -not $script:BestRawName) {
                $script:BestRawName = $epubTitleCleaned[0]
            }
            Write-FlickFitHost "  [EPUB] OPFタイトルを作品名候補に追加: $($epubTitleCleaned -join ', ')" -ForegroundColor DarkCyan
        }
    }
    if (-not $script:BestRawName) {
        $jpLeaf = $allLeaves | Where-Object { (Split-Path $_.Path -Leaf) -match "[ぁ-んァ-ヶ亜-熙]" } | Select-Object -First 1
        if ($jpLeaf) { $script:BestRawName = Split-Path $jpLeaf.Path -Leaf } else { $script:BestRawName = Split-Path $allLeaves[0].Path -Leaf }
    }
    # 同一親内の「話っぽい」兄弟比率（ローカル多数決用）
    $byParentForVote = @{}
    foreach ($leaf in $allLeaves) {
        $pp = Split-Path $leaf.Path -Parent
        if (-not $byParentForVote.ContainsKey($pp)) { $byParentForVote[$pp] = [System.Collections.ArrayList]::new() }
        [void]$byParentForVote[$pp].Add((Split-Path $leaf.Path -Leaf))
    }
    $chRatioByParent = @{}
    foreach ($pp in $byParentForVote.Keys) {
        $names = @($byParentForVote[$pp])
        $clearCh = 0; $nonCover = 0
        foreach ($n0 in $names) {
            $n = Convert-ZenToHan $n0
            if ($n -match $script:FlickFitRegexCoverLeafOrZero -or $n -match '(?i)^[^\-_]+[-_](#?cover|0)$') { continue }
            $nonCover++
            if ($n -match '(?i)chapter\s*\d|第\s*\d+\s*話|raw\s*chapter|chap\s*\d|(?i)c\d{2,4}\s*[-~]|^\d+_files|[-_]\d+_files') { $clearCh++ }
        }
        $chRatioByParent[$pp] = if ($nonCover -gt 0) { [double]$clearCh / [double]$nonCover } else { 0.0 }
    }
    $leafContexts = [System.Collections.Generic.List[PSObject]]::new()
    foreach ($leaf in $allLeaves) {
        $pp = Split-Path $leaf.Path -Parent
        $ratio = if ($chRatioByParent.ContainsKey($pp)) { $chRatioByParent[$pp] } else { 0.0 }
        $ctx = Get-VolContext $leaf.Path -SiblingChapterRatio $ratio
        # Get-VolContext の Single で Vol=0 / 欠落 かつ 親 or 自フォルダ名に巻が取れるとき上書き（汎用括弧で GVF=30 なのに ctx=0 になった不整合の救済）
        if ($ctx.Type -eq 'Single') {
            $cv0 = if ($ctx.PSObject.Properties['Vol']) { $ctx.Vol } else { $null }
            $vBad = ($null -eq $cv0)
            if (-not $vBad) { $vBad = [int]$cv0 -le 0 }
            if ($vBad) {
                $___pmName = Split-Path (Split-Path $leaf.Path -Parent) -Leaf
                $___pvFromParent = Get-VolFromParentName $___pmName
                $___nFromParent = if ($___pvFromParent -is [hashtable] -and $null -ne $___pvFromParent['Vol']) { [int]$___pvFromParent['Vol'] } else { $null }
                $___nUse = if ($null -ne $___nFromParent -and $___nFromParent -ge 1) { $___nFromParent } else { $null }
                if ($null -eq $___nUse) {
                    $___snSelf = Split-Path $leaf.Path -Leaf
                    $___pvFromSelf = Get-VolFromParentName $___snSelf
                    $___nFromSelf = if ($___pvFromSelf -is [hashtable] -and $null -ne $___pvFromSelf['Vol']) { [int]$___pvFromSelf['Vol'] } else { $null }
                    if ($null -ne $___nFromSelf -and $___nFromSelf -ge 1) { $___nUse = $___nFromSelf }
                }
                if ($null -ne $___nUse) {
                    $ctx | Add-Member -NotePropertyName 'Vol' -NotePropertyValue $___nUse -Force
                }
            }
        }
        $___sn0 = Split-Path $leaf.Path -Leaf
        $___pn0 = Split-Path (Split-Path $leaf.Path -Parent) -Leaf
        $___pvs = Get-VolFromParentName $___sn0
        $___pvp = Get-VolFromParentName $___pn0
        $___sCand = if ($___pvs -is [hashtable] -and $null -ne $___pvs['Vol']) { [string]$___pvs['Vol'] } else { 'null' }
        $___pCand = if ($___pvp -is [hashtable] -and $null -ne $___pvp['Vol']) { [string]$___pvp['Vol'] } else { 'null' }
        $___ctxV = if ($ctx.PSObject.Properties['Vol'] -and $null -ne $ctx.Vol) { $ctx.Vol } else { 'n/a' }
        $___fin = if ($ctx.Type -eq 'Single' -and $ctx.PSObject.Properties['Vol'] -and $null -ne $ctx.Vol) { $ctx.Vol } else { 'n/a' }
        Write-Verbose "[FlickFit-Tokuto] step2ctx parentCand=$___pCand contextVol=$___ctxV finalFromCtx=$___fin type=$($ctx.Type) selfLeaf='$___sn0' selfPvcand=$___sCand parentName='$___pn0'"
        if ($true -eq $script:FlickFitDebugVolumeContext) {
            Write-FlickFitHost "[FlickFit-Tokuto] step2ctx parentCand=$___pCand contextVol=$___ctxV finalFromCtx=$___fin type=$($ctx.Type) selfLeaf='$___sn0' selfPvcand=$___sCand parentName='$___pn0'" -ForegroundColor DarkGray
        }
        # EPUB由来フォルダの処理: サマリ表示用ルート名付加 + 巻番号不明時の補完
        if ($script:epubFolderVolMap -and $script:epubFolderVolMap.Count -gt 0) {
            $___epubCmp = [System.StringComparison]::OrdinalIgnoreCase
            foreach ($epubRoot in $script:epubFolderVolMap.Keys) {
                $normLeaf = $leaf.Path.TrimEnd('\')
                $normRoot = $epubRoot.TrimEnd('\')
                $___underEpub = $normLeaf.StartsWith($normRoot + '\', $___epubCmp) -or
                    [string]::Equals($normLeaf, $normRoot, $___epubCmp)
                if ($___underEpub) {
                    # EPUB由来フォルダは常にルート名をサマリ表示用に付加
                    $leaf | Add-Member -NotePropertyName 'EpubRootName' -NotePropertyValue (Split-Path $epubRoot -Leaf) -Force
                    # 巻番号が判定不明の場合のみ EPUB マップで補完
                    if ($ctx.Type -eq 'Unknown') {
                        $epubVolNum = [int]$script:epubFolderVolMap[$epubRoot]
                        $ctx = [PSCustomObject]@{ Type='Single'; Vol=$epubVolNum; Name=(Split-Path $leaf.Path -Leaf) }
                    }
                    break
                }
            }
        }
        $leafContexts.Add([PSCustomObject]@{ Leaf=$leaf; Ctx=$ctx })
    }
    Write-FlickFitHost "`n[構造解析結果]:" -ForegroundColor Cyan
    # 親フォルダでグループ化（親1回表示・その下に子を並べる）
    $naturalSort = { [regex]::Replace($_.Leaf.Name, '\d+', { $args[0].Value.PadLeft(10,'0') }) }
    $byParent = @{}
    foreach ($lc in $leafContexts) {
        $parentPath = Split-Path $lc.Leaf.Path -Parent
        if (-not $byParent.ContainsKey($parentPath)) { $byParent[$parentPath] = [System.Collections.ArrayList]::new() }
        [void]$byParent[$parentPath].Add($lc)
    }
    # 親をソート（親フォルダ名の自然順）、各親の子は巻→話の順・自然順でソート
    $parentNames = @($byParent.Keys | ForEach-Object { [PSCustomObject]@{ Path=$_; Name=(Split-Path $_ -Leaf) } } | Sort-Object { [regex]::Replace($_.Name, '\d+', { $args[0].Value.PadLeft(10,'0') }) } | ForEach-Object { $_.Path })
    $script:Step2ParentOrder = @{}
    for ($pi = 0; $pi -lt $parentNames.Count; $pi++) { $script:Step2ParentOrder[$parentNames[$pi]] = $pi }
    foreach ($parentPath in $parentNames) {
        $parentName = Split-Path $parentPath -Leaf
        $items = @($byParent[$parentPath] | Sort-Object $naturalSort)
        Write-FlickFitHost "  ${parentName}:" -ForegroundColor Cyan
        foreach ($lc in $items) {
            $leafName = Split-Path $lc.Leaf.Path -Leaf
            $leafImgs = @(Get-ChildItem -LiteralPath $lc.Leaf.Path -File -ErrorAction SilentlyContinue | Where-Object { $script:ImageExtensions -contains $_.Extension.ToLower() })
            $imgCntStr = if ($leafImgs.Count -gt 0) { " (画像 $($leafImgs.Count)枚)" } else { "" }
            $volStr = switch ($lc.Ctx.Type) {
                'Single' {
                    if ($leafName -match '(?i)chapter\s*0*(\d+(?:\.\d+)?)') { "第 $($Matches[1]) 話" }
                    elseif ($leafName -match '第\s*0*(\d+(?:\.\d+)?)\s*話') { "第 $($Matches[1]) 話" }
                    elseif ($leafName -match '(?i)\bv0*(\d{1,3})[sSwWbB]?\s*$') { "第 $([int]$Matches[1]) 巻" }
                    else { "第 $($lc.Ctx.Vol) 巻" }
                }
                'Chapter' {
                    $vp = Get-Step2VolLabelPrefix $lc.Ctx
                    if ($vp) { "${vp}第 $($lc.Ctx.ChNum) 話" } else { "第 $($lc.Ctx.ChNum) 話" }
                }
                'ChapterRange' {
                    $vp = Get-Step2VolLabelPrefix $lc.Ctx
                    $vs = if ($vp) { "${vp}第 $($lc.Ctx.ChStart)-$($lc.Ctx.ChEnd) 話" } else { "第 $($lc.Ctx.ChStart)-$($lc.Ctx.ChEnd) 話" }
                    if ($lc.Ctx.PSObject.Properties['RangeOrderInvalid'] -and $lc.Ctx.RangeOrderInvalid) { $vs += " (範囲逆順・要確認)" }
                    if ($lc.Ctx.PSObject.Properties['OutsideAncestorSpan'] -and $lc.Ctx.OutsideAncestorSpan) { $vs += " (祖先スパン外・要確認)" }
                    $vs
                }
                'Cover' { 
                    if ($leafName -match '(?i)(cover|表紙|カバー)(\d+)') { "表紙フォルダ (第$($Matches[2])巻)" }
                    else { "表紙フォルダ" }
                }
                'Range' { "範囲: $($lc.Ctx.Name)" }
                'Special' { "特別: $($lc.Ctx.Suffix)" }
                default { "判定不明" }
            }
            $lineText = "    - $leafName$imgCntStr  ->  [" + $volStr + "]"
            $lineColor = if ($lc.Ctx.Type -eq 'Cover') { 'DarkCyan' } elseif ($lc.Ctx.Type -eq 'Special') { 'Magenta' } else { 'White' }
            Write-FlickFitHost $lineText -ForegroundColor $lineColor
        }
    }

    Invoke-Step2StructureManualReview -LeafContexts $leafContexts
    # 巻数モード候補・話数振り分け列挙を「構造解析サマリ確定後の leafContexts 順」に揃える（直後の Sort で潰さない）
    $script:Step2LeafPathOrder = @{}
    for ($__s2 = 0; $__s2 -lt $leafContexts.Count; $__s2++) {
        $pth0 = $leafContexts[$__s2].Leaf.Path
        $k0 = $null
        try { $k0 = [System.IO.Path]::GetFullPath($pth0).TrimEnd('\') } catch { $k0 = $pth0.TrimEnd('\') }
        $script:Step2LeafPathOrder[$k0] = [int]$__s2
    }

    $volMap = @{}; $rangeMap = @{}; $unknowns = [System.Collections.Generic.List[PSObject]]::new(); $tempVolMap = @{}
    # STEP2 再開時は「途中の表紙・振り分け」を復元しない（毎回このブロックからやり直し）。
    # 完了済みの状態は _flickfit_after_step2.clixml のみ（STEP3 以降の再開で使用）。
    $step2ProgPath = Join-Path (Get-FlickFitResumeSnapshotDir) '_flickfit_step2_progress.clixml'
    if (Test-Path -LiteralPath $step2ProgPath) {
        Remove-Item -LiteralPath $step2ProgPath -Force -ErrorAction SilentlyContinue
    }
    $script:coverMap = @{}  # 各巻の表紙画像パスを記録
    $script:detectedCoverFolders = [System.Collections.Generic.List[PSObject]]::new()  # 検出されたcoverフォルダ
    $specialItems = [System.Collections.Generic.List[PSObject]]::new()  # 特別短編: 作品名+特別名で分けて保存
    
    foreach ($lc in $leafContexts) {
        if ($lc.PSObject.Properties['Step2ManualExclude'] -and $lc.Step2ManualExclude) { continue }
        $ctx = $lc.Ctx
        if ($ctx.Type -eq 'Single') {
            $leafName = $lc.Leaf.Name
            # Chapter XX / 第X話: 親フォルダが巻を示す場合（単一巻v01s等 or 範囲v01-04等）、話数→巻にマッピング（小数点付き対応）
            if ($leafName -match '(?i)chapter\s*0*(\d+(?:\.\d+)?)' -or $leafName -match '第\s*0*(\d+(?:\.\d+)?)\s*話') {
                $chNum = $Matches[1]  # 小数点付きの場合もあるため文字列として保持
                $parentPath = Split-Path $lc.Leaf.Path -Parent
                $parentName = (Split-Path $parentPath -Leaf)
                $pv = Get-VolFromParentName $parentName
                $pvVol   = if ($pv -is [hashtable] -and $pv.ContainsKey('Vol'))   { $pv['Vol'] }   else { $null }
                $pvStart = if ($pv -is [hashtable] -and $pv.ContainsKey('Start')) { $pv['Start'] } else { $null }
                $pvEnd   = if ($pv -is [hashtable] -and $pv.ContainsKey('End'))   { $pv['End'] }   else { $null }
                $vol = $null
                if ($null -ne $pvStart -and $null -ne $pvEnd) {
                    $vol = [Math]::Min([Math]::Max($chNum, $pvStart), $pvEnd)
                } elseif ($null -ne $pvVol) {
                    $vol = $pvVol
                }
                if ($null -ne $vol) {
                    if ($VerbosePreference -ne 'SilentlyContinue') {
                        Write-Verbose "[FlickFit-Tokuto] step2final where=chMap parentVol=$pvVol range=$pvStart-$pvEnd contextVol=$($ctx.Vol) finalVol=$vol leaf=$leafName"
                    }
                    if (-not $tempVolMap.ContainsKey($vol)) { $tempVolMap[$vol] = [System.Collections.Generic.List[PSObject]]::new() }
                    $tempVolMap[$vol].Add($lc.Leaf)
                } else {
                    if ($VerbosePreference -ne 'SilentlyContinue') {
                        Write-Verbose "[FlickFit-Tokuto] step2final where=chUnknown parentCand=($pvVol/$pvStart-$pvEnd) contextVol=$($ctx.Vol) finalVol=null leaf=$leafName"
                    }
                    $unknowns.Add($lc.Leaf)
                }
            } elseif ($leafName -match '(?i)\bv0*(\d{1,3})[sSwWbB]?\s*$') {
                $vol = [int]$Matches[1]
                if ($VerbosePreference -ne 'SilentlyContinue') {
                    Write-Verbose "[FlickFit-Tokuto] step2final where=vEndPat parentCand=n/a contextVol=$($ctx.Vol) finalVol=$vol leaf=$leafName"
                }
                if (-not $tempVolMap.ContainsKey($vol)) { $tempVolMap[$vol] = [System.Collections.Generic.List[PSObject]]::new() }
                $tempVolMap[$vol].Add($lc.Leaf)
            } else {
                $___pm = Split-Path (Split-Path $lc.Leaf.Path -Parent) -Leaf
                $___pvh = Get-VolFromParentName $___pm
                $___pc2 = if ($___pvh -is [hashtable] -and $null -ne $___pvh['Vol']) { $___pvh['Vol'] } else { 'null' }
                $mapKey = $ctx.Vol
                if (($null -eq $mapKey -or [int]$mapKey -le 0) -and $___pc2 -ne 'null' -and [int]$___pc2 -ge 1) {
                    $mapKey = [int]$___pc2
                }
                Write-Verbose "[FlickFit-Tokuto] step2final ctxOnly parentCand=$___pc2 contextVol=$($ctx.Vol) finalKey=$mapKey leaf=$leafName"
                if ($true -eq $script:FlickFitDebugVolumeContext) {
                    Write-FlickFitHost "[FlickFit-Tokuto] step2final ctxOnly parentCand=$___pc2 contextVol=$($ctx.Vol) finalKey=$mapKey leaf=$leafName" -ForegroundColor DarkGray
                }
                if (-not $tempVolMap.ContainsKey($mapKey)) { $tempVolMap[$mapKey] = [System.Collections.Generic.List[PSObject]]::new() }
                $tempVolMap[$mapKey].Add($lc.Leaf)
            }
        } elseif ($ctx.Type -eq 'Range') {
            if (-not $rangeMap.ContainsKey($ctx.Name)) { $rangeMap[$ctx.Name] = [PSCustomObject]@{ Start=$ctx.Start; End=$ctx.End; Leaves=[System.Collections.Generic.List[string]]::new() } }
            $rangeMap[$ctx.Name].Leaves.Add($lc.Leaf.Path)
        } elseif ($ctx.Type -eq 'Cover') {
            # coverフォルダを別途記録
            $script:detectedCoverFolders.Add($lc.Leaf)
        } elseif ($ctx.Type -eq 'Chapter' -or $ctx.Type -eq 'ChapterRange') {
            # 話数フォルダ: Get-VolContext で先祖から付いた Vol / VolStart-VolEnd を優先（深い ch フォルダ配下でも巻へ載せる）
            $pv = $null
            $pvVol = $null
            $pvStart = $null
            $pvEnd = $null
            if ($ctx.PSObject.Properties['Vol'] -and $null -ne $ctx.Vol) {
                $pvVol = $ctx.Vol
            }
            elseif ($ctx.PSObject.Properties['VolStart'] -and $ctx.PSObject.Properties['VolEnd'] -and $null -ne $ctx.VolStart -and $null -ne $ctx.VolEnd) {
                $pvStart = $ctx.VolStart
                $pvEnd = $ctx.VolEnd
            }
            else {
                $parentPath = Split-Path $lc.Leaf.Path -Parent
                $parentName = (Split-Path $parentPath -Leaf)
                $pv = Get-VolFromParentName $parentName
                if (-not $pv -and $parentPath) {
                    $grandParentPath = Split-Path $parentPath -Parent
                    if ($grandParentPath) {
                        $grandParentName = Split-Path $grandParentPath -Leaf
                        $pv = Get-VolFromParentName $grandParentName
                    }
                }
                $pvVol   = if ($pv -is [hashtable] -and $pv.ContainsKey('Vol'))   { $pv['Vol'] }   else { $null }
                $pvStart = if ($pv -is [hashtable] -and $pv.ContainsKey('Start')) { $pv['Start'] } else { $null }
                $pvEnd   = if ($pv -is [hashtable] -and $pv.ContainsKey('End'))   { $pv['End'] }   else { $null }
            }
            
            if ($null -ne $pvVol) {
                if (-not $tempVolMap.ContainsKey($pvVol)) { $tempVolMap[$pvVol] = [System.Collections.Generic.List[PSObject]]::new() }
                $tempVolMap[$pvVol].Add($lc.Leaf)
            } elseif ($null -ne $pvStart -and $null -ne $pvEnd) {
                # 範囲親（v10-12s等）の場合は全巻に同じフォルダを登録し、表紙未設定で10・11・12巻それぞれ選べるようにする
                for ($v = $pvStart; $v -le $pvEnd; $v++) {
                    if (-not $tempVolMap.ContainsKey($v)) { $tempVolMap[$v] = [System.Collections.Generic.List[PSObject]]::new() }
                    $tempVolMap[$v].Add($lc.Leaf)
                }
            } else {
                $unknowns.Add($lc.Leaf)
            }
        } elseif ($ctx.Type -eq 'Special') {
            $specialItems.Add([PSCustomObject]@{ Suffix=$ctx.Suffix; Path=$lc.Leaf.Path })
        } else { 
            $unknowns.Add($lc.Leaf) 
        }
    }

    # [BUG FIX #5] スキップ時の確認 + 表紙フォルダ選択（若い巻数から優先）
    $script:volDirectOnlyPaths = [System.Collections.Generic.List[string]]::new()
    $script:excludedSubfolderPaths = [System.Collections.Generic.List[string]]::new()  # 除外するサブフォルダ
    $script:processedChapterParentPaths = @{}  # チャプター親パス -> 処理済み
    $script:volMapFilledByChapterSplit = @{}   # 振り分けで決定した巻 → スキップ用
    $script:volMapPreserveChapterOrder = [System.Collections.Generic.HashSet[int]]::new()  # 話数（話数番号）で振り分けた巻は STEP4 で volMap の登録順を維持（例: 11-16,2 → 11-16 側を先にコピー）
    $script:ForceVolumeMode = $false   # Mで巻数モードに切り替えた場合、以降の巻にも反映
    $script:ForceChapterMode = $false  # Yで話数モードに切り替えた場合、以降の巻にも反映
    # 同一 cover フォルダを複数巻で使うとき、既に割り当てた画像は次巻以降の一覧から除外（再開時は coverMap から復元）
    $chapterSharedCoverUsedPaths = [System.Collections.Generic.HashSet[string]]::new([System.StringComparer]::OrdinalIgnoreCase)
    $chapterSelectedCoverDirByParent = @{}  # 親パス -> 選択済みカバーフォルダ（話数モードで再利用）
    $chapterRangeCoverState = @{}  # "start-end-parentPath" -> { Start, End, CoveredVols(HashSet[int]) }
    $chapterRangeCoverResetDone = @{}  # "start-end-parentPath" -> $true（既存表紙キャッシュを初期化済み）
    if ($script:coverMap) {
        foreach ($cmk in $script:coverMap.Keys) {
            foreach ($p in @($script:coverMap[$cmk])) { if ($p) { [void]$chapterSharedCoverUsedPaths.Add($p) } }
        }
    }
    # STEP2 対話の表記を揃える（表紙＝画像フォルダ／話数＝話数番号 or 一覧番号）
    $step2HintChapterNums = '話数番号: 範囲（例: 300-309）・列挙（例: 300,301,9.5）・範囲フォルダは開始番号のみ  カンマ区切りは左から順が連番コピー順  空Enter: スキップ'
    $step2HintFolderIdx = '一覧の番号: 範囲（例: 3-11）・列挙（例: 3,4,5）  [A] すべて  [S] スキップ'
    $step2HintCoverImg = '    [A] すべて  [番号] 範囲・列挙（例: 1-8 / 1,2,3）  [N] 表紙なし  [空Enter] 変更なし'
    # 巻ごと表紙: 第1巻では [R] なし（前巻が存在しない）
    $step2HintCoverImgFirstVol = '    [A] すべて  [番号] 範囲・列挙  [N] 表紙なし  [空Enter] スキップ'
    $step2HintCoverImgR = '    [A] すべて  [番号] 範囲・列挙  [N] 表紙なし  [R] 前の巻へ  [空Enter] スキップ'
    foreach ($vn in ($tempVolMap.Keys | Sort-Object)) {
        if ($script:volMapFilledByChapterSplit.ContainsKey($vn)) { continue }
        # 候補: 親の順 → 話数 → **構造解析サマリ確定後の leaf 順(Step2LeafPathOrder: <>入替含む)** → 名前
        $candidates = @($tempVolMap[$vn] | Sort-Object `
            @{ Expression = {
                $pp = Split-Path $_.Path -Parent
                if ($script:Step2ParentOrder -and $script:Step2ParentOrder.ContainsKey($pp)) { $script:Step2ParentOrder[$pp] } else { [int]::MaxValue }
            } }, `
            @{ Expression = { Get-ChapterNumber $_.Name } }, `
            @{ Expression = { Get-Step2LeafPathOrderRank -Path $_.Path } }, `
            @{ Expression = { [regex]::Replace($_.Name, '\d+(?:\.\d+)?', { $args[0].Value.PadLeft(10,'0') }) } })
        if ($candidates.Count -eq 1) {
            $volMap[$vn] = [System.Collections.Generic.List[string]]::new()
            $volMap[$vn].Add($candidates[0].Path)
        } else {
            $parentPath = Split-Path $candidates[0].Path -Parent
            $uniqueParents = @($candidates | ForEach-Object { (Split-Path $_.Path -Parent) } | Select-Object -Unique)
            $allSameParent = $uniqueParents.Count -eq 1
            
            # coverフォルダを除外して話数フォルダかどうかを判定
            $nonCoverCandidates = @($candidates | Where-Object {
                $n = Split-Path $_.Path -Leaf
                -not ($n -match $script:FlickFitRegexCoverHashPref)
            })
            $nonChapterCount = @($nonCoverCandidates | ForEach-Object { 
                $n = Split-Path $_.Path -Leaf
                # 話数パターン: Chapter XX, 第XX話, 第XX-YY話, 360-367 のような純粋な数値範囲, XX_files, 277 のような3〜4桁の話数フォルダ 等
                $n -match '(?i)chapter\s*0*\d+(?:\.\d+)?(?:\s*[-~]\s*0*\d+(?:\.\d+)?)?' -or 
                $n -match '第\s*0*\d+(?:\.\d+)?(?:\s*[-~]\s*0*\d+(?:\.\d+)?)?\s*話' -or
                $n -match '^\s*\d+(?:\.\d+)?\s*[-~]\s*\d+(?:\.\d+)?\s*$' -or
                $n -match '^\d+(?:\.\d+)?_files$' -or $n -match '[-_]\d+(?:\.\d+)?_files$' -or
                $n -match '^\d{3,4}$'
            } | Where-Object { -not $_ })
            $allChapters = ($nonCoverCandidates.Count -gt 0 -and $nonChapterCount.Count -eq 0)

            # 以前: 表紙未設定かつ「同一親・全話数」以外で continue していたが、候補が複数ある巻では volMap に一度も入らず、
            # 後段の「選択されなかった巻のみ tempVolMap を反映」で全候補が同一巻に積まれる → [表紙が未設定] で第X巻が2フォルダ扱いになり、
            # かつ「配下がすべて第X巻フォルダ名」分岐で表紙UIがスキップされ続ける不具合があった。
            # 複数候補（別親の同一巻など）は必ずこの後の「巻数選択モード」等で採用を決める。
            $pv = Get-VolFromParentName (Split-Path $parentPath -Leaf)
            $pvVol   = if ($pv -is [hashtable] -and $pv.ContainsKey('Vol'))   { $pv['Vol'] }   else { $null }
            $pvStart = if ($pv -is [hashtable] -and $pv.ContainsKey('Start')) { $pv['Start'] } else { $null }
            $pvEnd   = if ($pv -is [hashtable] -and $pv.ContainsKey('End'))   { $pv['End'] }   else { $null }
            if ($null -ne $pvVol -and ($null -eq $pvStart -or $null -eq $pvEnd)) { $pvStart = $pvVol; $pvEnd = $pvVol }

            # 話数フォルダがある場合は話数振り分けモードに移行（親ごとに表紙選択→振り分け）
            if ($allSameParent -and $allChapters) {
                $normParent = [System.IO.Path]::GetFullPath($parentPath)
                # pvStart/pvEndが取得できない場合は現在の巻番号のみを使用
                if ($null -eq $pvStart -or $null -eq $pvEnd) {
                    $pvStart = $vn
                    $pvEnd = $vn
                }
                if (-not $script:processedChapterParentPaths.ContainsKey($normParent)) {
                    $parentName = Split-Path $parentPath -Leaf
                    if (Test-FlickFitChapterParentFullyAssigned -ParentNameLeaf $parentName -VolMap $volMap) {
                        $script:processedChapterParentPaths[$normParent] = $true
                        continue
                    }
                    $script:processedChapterParentPaths[$normParent] = $true
                    $chapterFolders = @(Get-ChildItem -LiteralPath $parentPath -Directory -ErrorAction SilentlyContinue | Where-Object { 
                        $n = $_.Name
                        $n -match '(?i)chapter\s*0*\d+(?:\.\d+)?(?:\s*[-~]\s*0*\d+(?:\.\d+)?)?' -or 
                        $n -match '第\s*0*\d+(?:\.\d+)?(?:\s*[-~]\s*0*\d+(?:\.\d+)?)?\s*話' -or
                        $n -match '^\s*\d+(?:\.\d+)?\s*[-~]\s*\d+(?:\.\d+)?\s*$' -or
                        $n -match '^\d+(?:\.\d+)?_files$' -or $n -match '[-_](\d+(?:\.\d+)?)_files$' -or
                        $n -match '^\d{3,4}$'
                    } | Sort-Object { [regex]::Replace($_.Name, '\d+(?:\.\d+)?', { $args[0].Value.PadLeft(10,'0') }) })
                    $chNumToPath = @{}
                    $chNumDisplay = @{}  # 表示用（範囲の場合は "10-15" など）
                    foreach ($cf in $chapterFolders) {
                        # 話数範囲パターン: 第10-15話, Chapter 10-15
                        if ($cf.Name -match '第\s*0*(\d+(?:\.\d+)?)\s*[-~]\s*0*(\d+(?:\.\d+)?)\s*話') {
                            $chKey = $Matches[1]
                            $chNumToPath[$chKey] = $cf.FullName
                            $chNumDisplay[$chKey] = "$($Matches[1])-$($Matches[2])"
                        } elseif ($cf.Name -match '(?i)chapter\s*0*(\d+(?:\.\d+)?)\s*[-~]\s*0*(\d+(?:\.\d+)?)') {
                            $chKey = $Matches[1]
                            $chNumToPath[$chKey] = $cf.FullName
                            $chNumDisplay[$chKey] = "$($Matches[1])-$($Matches[2])"
                        } elseif ($cf.Name -match '(?i)chapter\s*0*(\d+(?:\.\d+)?)') { 
                            $chNumToPath[$Matches[1]] = $cf.FullName
                            $chNumDisplay[$Matches[1]] = $Matches[1]
                        } elseif ($cf.Name -match '第\s*0*(\d+(?:\.\d+)?)\s*話') { 
                            $chNumToPath[$Matches[1]] = $cf.FullName 
                            $chNumDisplay[$Matches[1]] = $Matches[1]
                        } elseif ($cf.Name -match '^(\d+(?:\.\d+)?)_files$' -or $cf.Name -match '[-_](\d+(?:\.\d+)?)_files$') {
                            $chNumToPath[$Matches[1]] = $cf.FullName
                            $chNumDisplay[$Matches[1]] = $Matches[1]
                        } elseif ($cf.Name -match '^\s*(\d+(?:\.\d+)?)\s*[-~]\s*(\d+(?:\.\d+)?)\s*$') {
                            $chKey = $Matches[1]
                            $chNumToPath[$chKey] = $cf.FullName
                            $chNumDisplay[$chKey] = "$($Matches[1])-$($Matches[2])"
                        } elseif ($cf.Name -match '^(\d{3,4})$') {
                            $chNumToPath[$Matches[1]] = $cf.FullName
                            $chNumDisplay[$Matches[1]] = $Matches[1]
                        }
                    }
                    $chNums = @($chNumToPath.Keys | Sort-Object { [double]$_ })
                    if ($chNums.Count -gt 0) {
                        $chRangeStr = "$($chNums[0])-$($chNums[-1])"
                        $coverVolMap = @{}
                        $genericCovers = @()
                        # 複数のcoverフォルダを検出（cover1, cover2 など＋数字の無いフォルダも表紙候補）
                        $coverCandidates = @(Get-ChildItem -LiteralPath $parentPath -Directory -ErrorAction SilentlyContinue | Where-Object { 
                            $_.Name -match $script:FlickFitRegexCoverUnionOrPad -or
                            $_.Name -notmatch '\d'  # 数字の無いフォルダも表紙候補
                        })
                        if ($coverCandidates.Count -eq 0 -and $script:detectedCoverFolders.Count -gt 0) {
                            $coverCandidates = @($script:detectedCoverFolders | Where-Object { [System.IO.Path]::GetFullPath((Split-Path $_.Path -Parent)) -eq $normParent } | ForEach-Object { Get-Item -LiteralPath $_.Path -ErrorAction SilentlyContinue })
                        }
                        # バンドル直下(ch360-391等)のとき cover は一つ上の階層に並ぶことがある
                        $gpForCover = Split-Path $parentPath -Parent
                        $normPPc = try { [System.IO.Path]::GetFullPath($parentPath).TrimEnd('\') } catch { $parentPath.TrimEnd('\') }
                        $normGPc = if ($gpForCover -and (Test-Path -LiteralPath $gpForCover)) { try { [System.IO.Path]::GetFullPath($gpForCover).TrimEnd('\') } catch { $null } } else { $null }
                        if ($normGPc -and $normGPc -ne $normPPc) {
                            $gpCoverOnly = @(Get-ChildItem -LiteralPath $gpForCover -Directory -ErrorAction SilentlyContinue | Where-Object {
                                $dn = $_.Name
                                $dn -match $script:FlickFitRegexCoverBareTokensOnly -or $dn -match '^[^\-_]+[-_](0|cover)$' -or $dn -match '^0+$'
                            })
                            $coverByPath = @{}
                            foreach ($x in @($coverCandidates) + $gpCoverOnly) {
                                if (-not $x) { continue }
                                try { $ck = [System.IO.Path]::GetFullPath($x.FullName).TrimEnd('\') } catch { $ck = $x.FullName }
                                $coverByPath[$ck] = $x
                            }
                            $coverCandidates = @($coverByPath.Values)
                        }
                        if ($coverCandidates.Count -gt 0) {
                            # フォルダ名から巻数を推測して紐付け（cover1→1巻, cover2→2巻）
                            $coverVolMap = @{}  # 巻番号 -> フォルダパス
                            $genericCovers = @()  # 巻番号なしのcoverフォルダ
                            foreach ($cDir in $coverCandidates) {
                                if ($cDir.Name -match '(?i)(?:cover|表紙|カバー)(\d+)') {
                                    $coverVol = [int]$Matches[1]
                                    $coverVolMap[$coverVol] = $cDir
                                } else {
                                    $genericCovers += $cDir
                                }
                            }
                            
                            Write-FlickFitHost "`n  [STEP2] 表紙（画像）: $parentName" -ForegroundColor Cyan
                            Write-FlickFitHost "    ※ 各巻の表紙画像を選び、そのあと [STEP2] 話数の振り分けで話数フォルダを割り当てます" -ForegroundColor DarkGray
                            if ($coverVolMap.Count -gt 0) {
                                foreach ($cv in ($coverVolMap.Keys | Sort-Object)) {
                                    $cvDir = $coverVolMap[$cv]
                                    $cvImgCnt = @(Get-ChildItem -LiteralPath $cvDir.FullName -File -ErrorAction SilentlyContinue | Where-Object { $script:ImageExtensions -contains $_.Extension.ToLower() }).Count
                                    Write-FlickFitHost "    - $($cvDir.Name) -> 第${cv}巻 ($cvImgCnt 枚)" -ForegroundColor Gray
                                }
                            }
                            if ($genericCovers.Count -gt 0) {
                                foreach ($gcDir in $genericCovers) {
                                    $gcImgCnt = @(Get-ChildItem -LiteralPath $gcDir.FullName -File -ErrorAction SilentlyContinue | Where-Object { $script:ImageExtensions -contains $_.Extension.ToLower() }).Count
                                    Write-FlickFitHost "    - $($gcDir.Name) -> 全巻共通 ($gcImgCnt 枚)" -ForegroundColor Gray
                                }
                            }
                            
                            Write-FlickFitHost "`n  [STEP2] 表紙画像を選んでください（巻ごと）" -ForegroundColor Cyan
                            $volList = @($pvStart..$pvEnd)
                            $volIdx = 0
                            $usedCoverPaths = [System.Collections.Generic.HashSet[string]]::new()  # 選択済み画像追跡
                            while ($volIdx -lt $volList.Count) {
                                $v = $volList[$volIdx]
                                
                                # この巻に対応するcoverフォルダを決定
                                $currentCoverDir = $null
                                if ($coverVolMap.ContainsKey($v)) {
                                    $currentCoverDir = $coverVolMap[$v]
                                } elseif ($genericCovers.Count -gt 0) {
                                    $currentCoverDir = $genericCovers[0]
                                }
                                
                                if (-not $currentCoverDir) {
                                    Write-FlickFitHost "    第 $v 巻: 対応する表紙フォルダがありません" -ForegroundColor Yellow
                                    $volIdx++
                                    continue
                                }
                                
                                # 全画像リストを取得（番号は元のまま表示、選択済みはスキップ）
                                $allCoverImgs = @(Get-ChildItem -LiteralPath $currentCoverDir.FullName -File -ErrorAction SilentlyContinue | Where-Object { $script:ImageExtensions -contains $_.Extension.ToLower() } | Sort-Object { [regex]::Replace($_.Name, '\d+', { $args[0].Value.PadLeft(10,'0') }) })
                                $availableCount = @($allCoverImgs | Where-Object { -not $usedCoverPaths.Contains($_.FullName) }).Count
                                
                                if ($availableCount -eq 0) {
                                    Write-FlickFitHost "    第 $v 巻: 表紙画像がありません ($($currentCoverDir.Name))" -ForegroundColor Yellow
                                    $volIdx++
                                    continue
                                }
                                
                                Write-FlickFitHost "`n    第 $v 巻の表紙 [$($currentCoverDir.Name)] ($availableCount 枚):" -ForegroundColor Cyan
                                try { Start-Process "explorer.exe" -ArgumentList $currentCoverDir.FullName } catch {}
                                
                                # 番号は元のまま表示、選択済みはスキップ
                                for ($i = 0; $i -lt $allCoverImgs.Count; $i++) {
                                    if (-not $usedCoverPaths.Contains($allCoverImgs[$i].FullName)) {
                                        Write-FlickFitHost "      [$($i+1)] $($allCoverImgs[$i].Name)" -ForegroundColor White
                                    }
                                }
                                Write-FlickFitHost $(if ($volIdx -gt 0) { $step2HintCoverImgR } else { $step2HintCoverImgFirstVol }) -ForegroundColor DarkGray
                                
                                $idxAns = (Read-HostWithEsc "    表紙画像").Trim().ToUpper()
                                
                                if ($idxAns -eq 'R') {
                                    if ($volIdx -le 0) {
                                        Write-FlickFitHost "    -> これより前の巻はありません" -ForegroundColor Yellow
                                        continue
                                    }
                                    $prevV = $volList[$volIdx - 1]
                                    # 前巻の選択を解除してusedCoverPathsからも削除
                                    if ($script:coverMap.ContainsKey($prevV)) {
                                        foreach ($cp in $script:coverMap[$prevV]) { $usedCoverPaths.Remove($cp) | Out-Null }
                                        $script:coverMap.Remove($prevV)
                                    }
                                    Write-FlickFitHost "    -> 第 $prevV 巻に戻ります" -ForegroundColor Yellow
                                    $volIdx--
                                    continue
                                }
                                
                                if ($idxAns -eq 'N') {
                                    if ($script:coverMap.ContainsKey($v)) {
                                        foreach ($cp in @($script:coverMap[$v])) { if ($cp) { [void]$usedCoverPaths.Remove($cp) } }
                                        $script:coverMap.Remove($v)
                                    }
                                    Write-FlickFitHost "    -> 第 $v 巻: 表紙なし" -ForegroundColor Yellow
                                }
                                elseif ($idxAns -eq 'A') {
                                    $covPaths = @($allCoverImgs | Where-Object { -not $usedCoverPaths.Contains($_.FullName) } | ForEach-Object { $_.FullName })
                                    foreach ($p in $covPaths) { [void]$usedCoverPaths.Add($p) }
                                    $script:coverMap[$v] = $covPaths
                                    Write-FlickFitHost "    -> 第 $v 巻: 全採用 ($($covPaths.Count) 枚)" -ForegroundColor Green
                                }
                                elseif ($idxAns) {
                                    # 元の番号で入力を受け付け（選択済みは無視）
                                    $parsedIndices = @(Parse-RangeInput $idxAns $allCoverImgs.Count)
                                    $validIndices = @($parsedIndices | Where-Object { -not $usedCoverPaths.Contains($allCoverImgs[$_].FullName) })
                                    if ($validIndices.Count -gt 0) {
                                        $covPaths = @($validIndices | ForEach-Object { $allCoverImgs[$_].FullName })
                                        foreach ($idx in $validIndices) {
                                            Write-FlickFitHost "      選択: $($allCoverImgs[$idx].Name)" -ForegroundColor Green
                                            $usedCoverPaths.Add($allCoverImgs[$idx].FullName) | Out-Null
                                        }
                                        $script:coverMap[$v] = $covPaths
                                        Write-FlickFitHost "    -> 第 $v 巻: $($covPaths.Count) 枚選択" -ForegroundColor Green
                                    } else {
                                        Write-FlickFitHost "      無効な入力または選択済みです" -ForegroundColor Red
                                        continue
                                    }
                                } else {
                                    Write-FlickFitHost "    -> 第 $v 巻: スキップ" -ForegroundColor Gray
                                }
                                $volIdx++
                            }
                        }
                        # 表紙に割り当てたディレクトリを chNum から外す（名称が第○話等と重なる再掲示防止）
                        if ($coverVolMap.Count -gt 0 -or $genericCovers.Count -gt 0) {
                            $coverDirNorm = [System.Collections.Generic.HashSet[string]]::new([System.StringComparer]::OrdinalIgnoreCase)
                            foreach ($d in $coverVolMap.Values) {
                                if (-not $d) { continue }
                                try { [void]$coverDirNorm.Add([System.IO.Path]::GetFullPath($d.FullName).TrimEnd('\')) } catch { [void]$coverDirNorm.Add($d.FullName.TrimEnd('\')) }
                            }
                            foreach ($d in $genericCovers) {
                                if (-not $d) { continue }
                                try { [void]$coverDirNorm.Add([System.IO.Path]::GetFullPath($d.FullName).TrimEnd('\')) } catch { [void]$coverDirNorm.Add($d.FullName.TrimEnd('\')) }
                            }
                            $rm = [System.Collections.Generic.List[string]]::new()
                            foreach ($ck in $chNumToPath.Keys) {
                                $p = $chNumToPath[$ck]; if (-not $p) { continue }
                                $np = $null; try { $np = [System.IO.Path]::GetFullPath($p).TrimEnd('\') } catch { $np = $p.TrimEnd('\') }
                                if ($coverDirNorm.Contains($np)) { $rm.Add($ck) }
                            }
                            foreach ($rk in $rm) { [void]$chNumToPath.Remove($rk) }
                            $chNums = @($chNumToPath.Keys | Sort-Object { [double]$_ })
                        }
                        Write-FlickFitHost "`n  [STEP2] 話数の振り分け: $parentName" -ForegroundColor Cyan
                        $chNumToIndex = @{}
                        for ($i = 0; $i -lt $chNums.Count; $i++) {
                            $chNumToIndex[$chNums[$i].ToString()] = $i
                            # 整数の場合のみ整数キーも追加
                            if ($chNums[$i] -notmatch '\.') {
                                $chNumToIndex[[int]$chNums[$i]] = $i
                            }
                        }
                        # 全話数フォルダを個別にリスト表示（範囲フォルダは "10-15" のように表示）
                        Write-FlickFitHost "    話数フォルダ一覧 ($($chNums.Count) 件):" -ForegroundColor White
                        foreach ($chNum in $chNums) {
                            $chPath = $chNumToPath[$chNum.ToString()]
                            $chName = Split-Path $chPath -Leaf
                            $dispNum = if ($chNumDisplay.ContainsKey($chNum.ToString())) { $chNumDisplay[$chNum.ToString()] } else { $chNum }
                            Write-FlickFitHost "      [$dispNum] $chName" -ForegroundColor Gray
                        }
                        
                        $usedChapterIndices = [System.Collections.Generic.HashSet[int]]::new()
                        foreach ($v in ($pvStart..$pvEnd)) {
                            $remainingChNums = @($chNums | Where-Object { -not $usedChapterIndices.Contains($chNumToIndex[$_.ToString()]) })
                            if ($remainingChNums.Count -eq 0) {
                                Write-FlickFitHost "`n    第 $v 巻: 振り分け可能な話数がありません" -ForegroundColor Yellow
                                continue
                            }
                            
                            # この巻に対応する表紙フォルダの画像を表示
                            if ($coverVolMap.ContainsKey($v)) {
                                $vCoverDir = $coverVolMap[$v]
                                $vCoverImgs = @(Get-ChildItem -LiteralPath $vCoverDir.FullName -File -ErrorAction SilentlyContinue | Where-Object { $script:ImageExtensions -contains $_.Extension.ToLower() } | Sort-Object { [regex]::Replace($_.Name, '\d+', { $args[0].Value.PadLeft(10,'0') }) })
                                if ($vCoverImgs.Count -gt 0) {
                                    Write-FlickFitHost "`n    [第 $v 巻の表紙フォルダ: $($vCoverDir.Name)]" -ForegroundColor Magenta
                                    foreach ($img in $vCoverImgs) {
                                        Write-FlickFitHost "      - $($img.Name)" -ForegroundColor DarkMagenta
                                    }
                                }
                            } elseif ($genericCovers.Count -gt 0) {
                                $vCoverDir = $genericCovers[0]
                                $vCoverImgs = @(Get-ChildItem -LiteralPath $vCoverDir.FullName -File -ErrorAction SilentlyContinue | Where-Object { $script:ImageExtensions -contains $_.Extension.ToLower() } | Sort-Object { [regex]::Replace($_.Name, '\d+', { $args[0].Value.PadLeft(10,'0') }) })
                                if ($vCoverImgs.Count -gt 0) {
                                    Write-FlickFitHost "`n    [表紙フォルダ: $($vCoverDir.Name)] (共通)" -ForegroundColor Magenta
                                    foreach ($img in $vCoverImgs) {
                                        Write-FlickFitHost "      - $($img.Name)" -ForegroundColor DarkMagenta
                                    }
                                }
                            }
                            
                            # 残りの話数を個別表示（範囲フォルダは "10-15" のように表示）
                            Write-FlickFitHost "`n    第 $v 巻に入れる話数（左の番号で指定）" -ForegroundColor Cyan
                            foreach ($chNum in $remainingChNums) {
                                $chPath = $chNumToPath[$chNum.ToString()]
                                $chName = Split-Path $chPath -Leaf
                                $dispNum = if ($chNumDisplay.ContainsKey($chNum.ToString())) { $chNumDisplay[$chNum.ToString()] } else { $chNum }
                                Write-FlickFitHost "      [$dispNum] $chName" -ForegroundColor White
                            }
                            Write-FlickFitHost "    $step2HintChapterNums" -ForegroundColor DarkGray
                            $rangeAns = Read-HostWithEsc "    話数（話数番号）"
                            if (-not [string]::IsNullOrWhiteSpace($rangeAns)) {
                                $indices = Parse-ChapterInput $rangeAns $chNumToIndex
                                if ($null -ne $indices -and @($indices).Count -gt 0) {
                                    $volMap[$v] = [System.Collections.Generic.List[string]]::new()
                                    foreach ($idx in $indices) {
                                        if (-not $usedChapterIndices.Contains($idx)) {
                                            $volMap[$v].Add($chNumToPath[$chNums[$idx].ToString()])
                                            [void]$usedChapterIndices.Add($idx)
                                        }
                                    }
                                    $script:volMapFilledByChapterSplit[$v] = $true
                                    [void]$script:volMapPreserveChapterOrder.Add([int]$v)
                                    Write-FlickFitHost "    -> 第 $v 巻: $($volMap[$v].Count) 話を採用" -ForegroundColor Green
                                }
                            } else {
                                Write-FlickFitHost "    -> 第 $v 巻: スキップ" -ForegroundColor Gray
                                # スキップ時も「このフローで処理対象となった」ことを記録し、後段で再エントリーさせない
                                $script:volMapFilledByChapterSplit[$v] = $true
                            }
                        }
                        continue
                    }
                    # processedChapterParentPaths に既に登録済み = 同一親の別巻が先に統合フローを走らせた。
                    # ここでフォールスルーすると isChapterMode=true → 話数選択モードに再エントリーして二重プロンプトになる。
                    # → この vn は「処理済み」として必ずスキップする。
                    $script:volMapFilledByChapterSplit[$vn] = $true
                    continue
                } else {
                    # 範囲親（v01-03 等）: 先に処理した vn で表紙→全巻の話数振り分けまで済んでいる。残りの巻キーはここで打ち切る。
                    $script:volMapFilledByChapterSplit[$vn] = $true
                    continue
                }
            }

            # 候補が話数フォルダかどうかを判定
            # パターン: Chapter XX, 第XX話, XX_files 等
            $chapterCandidates = @($candidates | Where-Object { 
                $name = Split-Path $_.Path -Leaf
                $name -match '(?i)chapter\s*0*\d+(?:\.\d+)?' -or 
                $name -match '第\s*0*\d+(?:\.\d+)?\s*話' -or
                $name -match '^\d+[_\-]' -or
                $name -match '[_\-]\d+[_\-]files$' -or
                $name -match '^\d{3,4}$'
            })
            # 巻フォルダ候補（話数・表紙以外＝v01, _jp_v01, 第08巻 等）
            $volumeCandidates = @($candidates | Where-Object {
                $name = Split-Path $_.Path -Leaf
                $isCh = $name -match '(?i)chapter\s*0*\d' -or $name -match '^\d+[_\-]' -or $name -match '[_\-]\d+[_\-]files$' -or $name -match '^\d{3,4}$'
                $isCover = $name -match $script:FlickFitRegexCoverHashPref
                -not $isCh -and -not $isCover
            })
            # ユーザー指定モード優先 → 巻・話数が両方ある場合は巻を優先 → 従来ロジック
            $isChapterMode = if ($script:ForceVolumeMode) { $false }
                elseif ($script:ForceChapterMode) { $true }
                elseif ($volumeCandidates.Count -gt 0 -and $chapterCandidates.Count -gt 0) { $false }
                else { ($chapterCandidates.Count -gt 0 -and $chapterCandidates.Count -ge ($candidates.Count / 2)) }

            $modeSwitchRetry = $true
            while ($modeSwitchRetry) {
                $modeSwitchRetry = $false
                if (-not $isChapterMode) {
                    # ========== 巻フォルダ選択モード（同じ巻の複数ソース） ==========
                    Write-FlickFitHost "`n  現在のモード「巻数選択モード」" -ForegroundColor Cyan
                # 表示用: 親フォルダ直下の表紙候補（cover/cover29 など）を追加表示
                $candPathSet = @{}
                foreach ($c0 in $candidates) {
                    try { $candPathSet[[System.IO.Path]::GetFullPath($c0.Path).TrimEnd('\')] = $true } catch {}
                }
                $displayCandidates = [System.Collections.Generic.List[PSObject]]::new()
                foreach ($c0 in $candidates) { [void]$displayCandidates.Add($c0) }
                foreach ($d0 in @(Get-ChildItem -LiteralPath $parentPath -Directory -ErrorAction SilentlyContinue)) {
                    $dn0 = $d0.Name
                    $isCoverLike0 = $dn0 -match $script:CoverFolderNameLikeRegex
                    if (-not $isCoverLike0) { continue }
                    try { $k0 = [System.IO.Path]::GetFullPath($d0.FullName).TrimEnd('\') } catch { $k0 = $d0.FullName.TrimEnd('\') }
                    if ($candPathSet.ContainsKey($k0)) { continue }
                    [void]$displayCandidates.Add([PSCustomObject]@{ Path = $d0.FullName })
                }
                $coverLikeCount = @($displayCandidates | Where-Object {
                    $n = Split-Path $_.Path -Leaf
                    $n -match $script:CoverFolderNameLikeRegex
                }).Count
                if ($coverLikeCount -gt 0) {
                    Write-FlickFitHost "  第 $vn 巻の表紙フォルダを選んでください（★は表紙候補）。話数フォルダへの割り当ては、表紙画像を選んだあとのステップです。" -ForegroundColor Green
                } else {
                    Write-FlickFitHost "  第 $vn 巻の処理対象フォルダを選んでください。" -ForegroundColor Green
                }
                # フォルダ一覧を表示
                for ($i = 0; $i -lt $displayCandidates.Count; $i++) {
                    $folderPath = $displayCandidates[$i].Path
                    $folderName = Split-Path $folderPath -Leaf
                    $imgs = @(Get-ChildItem -LiteralPath $folderPath -File -ErrorAction SilentlyContinue | Where-Object { $script:ImageExtensions -contains $_.Extension.ToLower() })
                    $subDirs = @(Get-ChildItem -LiteralPath $folderPath -Directory -ErrorAction SilentlyContinue)
                    $imgCnt = $imgs.Count
                    $isCoverCandidate = $folderName -match $script:CoverFolderNameLikeRegex
                    if ($subDirs.Count -gt 0) {
                        $subNames = @($subDirs | Sort-Object { [regex]::Replace($_.Name, '\d+', { $args[0].Value.PadLeft(10,'0') }) } | ForEach-Object { $_.Name })
                        $subStr = if ($subNames.Count -le 5) { $subNames -join ", " } else { ($subNames[0..4] -join ", ") + " ...他$($subNames.Count - 5)件" }
                        $suffix = if ($isCoverCandidate) { " ★表紙候補" } else { "" }
                        Write-FlickFitHost ("    [{0}] {1}  (画像 {2}枚, サブ: {3}){4}" -f ($i+1), $folderName, $imgCnt, $subStr, $suffix) -ForegroundColor $(if ($isCoverCandidate) { 'Green' } else { 'White' })
                    } else {
                        $suffix = if ($isCoverCandidate) { " ★表紙候補" } else { "" }
                        Write-FlickFitHost ("    [{0}] {1}  (画像 {2}枚){3}" -f ($i+1), $folderName, $imgCnt, $suffix) -ForegroundColor $(if ($isCoverCandidate) { 'Green' } else { 'White' })
                    }
                }
                if ($coverLikeCount -gt 0) {
                    Write-FlickFitHost "    [番号] そのフォルダを表紙に指定 → 表紙画像 → 話数フォルダ" -ForegroundColor DarkGray
                    Write-FlickFitHost "    [A] 表紙候補をすべて経由して話数選択モードへ（この巻の表紙仮設定をやり直す・以降の巻も話数モード）" -ForegroundColor DarkGray
                    Write-FlickFitHost "    [Y] 話数選択モードへ（以降の巻にも適用・表紙の仮設定は消さない）  [S] スキップ" -ForegroundColor DarkGray
                } else {
                    Write-FlickFitHost "    [番号] 採用するフォルダ  [A] 全部採用  [Y] 話数選択モードへ切り替え（以降の巻にも適用）  [S] スキップ" -ForegroundColor DarkGray
                }
                $volFolderPrompt = if ($coverLikeCount -gt 0) { "  第${vn}巻（番号 / A / Y / S）" } else { "  第${vn}巻フォルダ" }
                $volFolderAns = (Read-HostWithEsc $volFolderPrompt).Trim().ToUpper()
                if ($volFolderAns -eq 'Y') {
                    $script:ForceChapterMode = $true
                    $script:ForceVolumeMode = $false
                    $isChapterMode = $true
                    $modeSwitchRetry = $true
                    Write-FlickFitHost "    -> 話数選択モードに切り替え（以降の巻にも適用）" -ForegroundColor Cyan
                    continue
                }
                if ($volFolderAns -eq 'S' -or $volFolderAns -eq '') {
                    Write-FlickFitHost "    -> スキップしました (この巻は処理されません)" -ForegroundColor Yellow
                    continue
                }
                if ($volFolderAns -eq 'A') {
                    if ($coverLikeCount -gt 0) {
                        if ($script:coverMap.ContainsKey($vn)) {
                            foreach ($cp in @($script:coverMap[$vn])) {
                                if ($cp) { [void]$chapterSharedCoverUsedPaths.Remove($cp) }
                            }
                            [void]$script:coverMap.Remove($vn)
                        }
                        $normP = try { [System.IO.Path]::GetFullPath($parentPath).TrimEnd('\') } catch { $parentPath.TrimEnd('\') }
                        if ($chapterSelectedCoverDirByParent.ContainsKey($normP)) { [void]$chapterSelectedCoverDirByParent.Remove($normP) }
                        $script:ForceChapterMode = $true
                        $script:ForceVolumeMode = $false
                        Write-FlickFitHost "    -> 話数選択モードに移ります（表紙フォルダ→表紙画像→話数フォルダ）。以降の巻も話数選択モードで進みます。" -ForegroundColor Green
                        $isChapterMode = $true
                        $modeSwitchRetry = $true
                        continue
                    }
                    # 表紙候補が無い場合のみ、従来どおり全部採用して確定
                    if (-not $volMap.ContainsKey($vn)) { $volMap[$vn] = [System.Collections.Generic.List[string]]::new() }
                    foreach ($c in $candidates) { $volMap[$vn].Add($c.Path) }
                    Write-FlickFitHost "    -> 全部採用 ($($candidates.Count) フォルダ)" -ForegroundColor Green
                    continue
                }
                
                # 選択を処理（番号で1フォルダのみ採用）
                if ($volFolderAns -match '^\d+$') {
                    $volIdx = [int]$volFolderAns - 1
                    if ($volIdx -ge 0 -and $volIdx -lt $displayCandidates.Count) {
                        $selectedFolder = $displayCandidates[$volIdx]
                        $selectedFolderName = Split-Path $selectedFolder.Path -Leaf
                        Write-FlickFitHost "    -> 採用: $selectedFolderName" -ForegroundColor Green
                        $isSelectedCoverFolder = $selectedFolderName -match $script:CoverFolderNameLikeRegex
                        if ($isSelectedCoverFolder) {
                            # 巻数選択で表紙フォルダが直接選ばれた場合は、表紙画像選択フローへ遷移
                            $normParentPathForCover = try { [System.IO.Path]::GetFullPath($parentPath).TrimEnd('\') } catch { $parentPath.TrimEnd('\') }
                            $chapterSelectedCoverDirByParent[$normParentPathForCover] = $selectedFolder.Path
                            Write-FlickFitHost "    -> 表紙フォルダを選択しました。続けて表紙画像を選択します。" -ForegroundColor DarkCyan
                            $isChapterMode = $true
                            $modeSwitchRetry = $true
                            continue
                        }
                        
                        # volMap: 巻数選択で1フォルダ確定＝この巻は常に1パスだけ（既存 List へ Add すると二重登録し、[表紙が未設定] が「チャプター複数」と誤判定する）
                        $volMap[$vn] = [System.Collections.Generic.List[string]]::new()
                        [void]$volMap[$vn].Add($selectedFolder.Path)
                        # tempVolMap も採用1件に絞る（マージや内部整合で未採用候補が残った扱いにならないようにする）
                        $normSel = $null
                        try { $normSel = [System.IO.Path]::GetFullPath($selectedFolder.Path).TrimEnd('\') } catch { $normSel = $selectedFolder.Path.TrimEnd('\') }
                        if ($tempVolMap.ContainsKey($vn) -and $null -ne $tempVolMap[$vn]) {
                            $pruned = [System.Collections.Generic.List[PSObject]]::new()
                            foreach ($lobj in @($tempVolMap[$vn])) {
                                $sp = $lobj.Path
                                if (-not $sp -and $lobj.PSObject.Properties['FullName'] -and $lobj.FullName) { $sp = $lobj.FullName }
                                if (-not $sp) { continue }
                                try { $nsp = [System.IO.Path]::GetFullPath($sp).TrimEnd('\') } catch { $nsp = $sp.TrimEnd('\') }
                                if ($nsp -eq $normSel) { [void]$pruned.Add($lobj); break }
                            }
                            if ($pruned.Count -eq 1) {
                                $tempVolMap[$vn] = $pruned
                            } elseif ($pruned.Count -eq 0) {
                                $pruned2 = [System.Collections.Generic.List[PSObject]]::new()
                                [void]$pruned2.Add($selectedFolder)
                                $tempVolMap[$vn] = $pruned2
                            }
                        }
                        if (-not $script:volDirectOnlyPaths.Contains($selectedFolder.Path)) { [void]$script:volDirectOnlyPaths.Add($selectedFolder.Path) }
                        
                        # 巻数選択モード: 1フォルダ＝1巻丸ごとの前提のため表紙選択は不要（フォルダ内に含まれる）
                        $selectedFolderPath = $selectedFolder.Path
                        $coverDir = $null
                        
                        # サブフォルダの選択（含めるかどうか）
                        $allSubDirs = @(Get-ChildItem -LiteralPath $selectedFolderPath -Directory -ErrorAction SilentlyContinue)
                        if ($allSubDirs.Count -gt 0) {
                            # 自動除外パターン（単ページ、おまけ、omake、bonus、extra）
                            $autoExcludePattern = '^(?i)(単ページ|おまけ|omake|bonus|extra)$'
                            
                            # 自動除外されるフォルダ
                            $autoExcluded = @($allSubDirs | Where-Object { $_.Name -match $autoExcludePattern })
                            
                            # 表紙フォルダのパス
                            $coverDirPath = if ($coverDir) { $coverDir.FullName } else { $null }
                            
                            # 選択対象フォルダ（表紙フォルダと自動除外を除く）
                            $selectableSubDirs = @($allSubDirs | Where-Object { 
                                $_.FullName -ne $coverDirPath -and 
                                $_.Name -notmatch $autoExcludePattern -and
                                $_.Name -notmatch $script:CoverFolderNameLikeRegex
                            } | Sort-Object { [regex]::Replace($_.Name, '\d+', { $args[0].Value.PadLeft(10,'0') }) })
                            
                            # 自動除外を登録
                            foreach ($exDir in $autoExcluded) {
                                if (-not $script:excludedSubfolderPaths.Contains($exDir.FullName)) {
                                    $script:excludedSubfolderPaths.Add($exDir.FullName)
                                }
                            }
                            
                            if ($autoExcluded.Count -gt 0) {
                                Write-FlickFitHost "`n    [自動除外] $($autoExcluded.Name -join ', ')" -ForegroundColor DarkGray
                            }
                            
                            if ($selectableSubDirs.Count -gt 0) {
                                Write-FlickFitHost "`n    [サブフォルダの選択] 含めるサブフォルダを選んでください" -ForegroundColor Cyan
                                for ($k = 0; $k -lt $selectableSubDirs.Count; $k++) {
                                    $subDir = $selectableSubDirs[$k]
                                    $subImgs = @(Get-ChildItem -LiteralPath $subDir.FullName -File -Recurse -ErrorAction SilentlyContinue | 
                                        Where-Object { $script:ImageExtensions -contains $_.Extension.ToLower() })
                                    Write-FlickFitHost ("      [{0}] {1}  (画像 {2}枚)" -f ($k+1), $subDir.Name, $subImgs.Count) -ForegroundColor White
                                }
                                Write-FlickFitHost "    [Enter] 全て含める  [番号] 選択 (例: 1,2)  [N] 全て除外" -ForegroundColor DarkGray
                                
                                $subAns = (Read-HostWithEsc "    サブフォルダ").Trim().ToUpper()
                                
                                if ($subAns -eq 'N') {
                                    # 全て除外
                                    foreach ($subDir in $selectableSubDirs) {
                                        if (-not $script:excludedSubfolderPaths.Contains($subDir.FullName)) {
                                            $script:excludedSubfolderPaths.Add($subDir.FullName)
                                        }
                                    }
                                    Write-FlickFitHost "    -> 全てのサブフォルダを除外" -ForegroundColor Yellow
                                } elseif ($subAns -ne '' -and $subAns -ne 'A') {
                                    # 選択されたもの以外を除外
                                    $parsedSubIdx = @(Parse-RangeInput $subAns $selectableSubDirs.Count)
                                    if ($parsedSubIdx.Count -gt 0) {
                                        for ($k = 0; $k -lt $selectableSubDirs.Count; $k++) {
                                            if ($parsedSubIdx -notcontains $k) {
                                                $exPath = $selectableSubDirs[$k].FullName
                                                if (-not $script:excludedSubfolderPaths.Contains($exPath)) {
                                                    $script:excludedSubfolderPaths.Add($exPath)
                                                }
                                            }
                                        }
                                        $includedNames = @($parsedSubIdx | ForEach-Object { $selectableSubDirs[$_].Name })
                                        Write-FlickFitHost "    -> 含める: $($includedNames -join ', ')" -ForegroundColor Green
                                    }
                                } else {
                                    Write-FlickFitHost "    -> 全てのサブフォルダを含める" -ForegroundColor Green
                                }
                            }
                        }
                    } else {
                        Write-FlickFitHost "    -> 無効な番号です。この巻はスキップします。" -ForegroundColor Yellow
                    }
                } else {
                    Write-FlickFitHost "    -> 無効な入力です。この巻はスキップします。" -ForegroundColor Yellow
                }
                continue
            }

                if ($isChapterMode) {
                # ========== 話数フォルダ選択モード（Chapter XX / 第XX話） ==========
                $modeRangeLabel = $null
                foreach ($pp in @($candidates | ForEach-Object { Split-Path $_.Path -Parent } | Select-Object -Unique)) {
                    $pvHint = Get-VolFromParentName (Split-Path $pp -Leaf)
                    $pvS = if ($pvHint -is [hashtable] -and $pvHint.ContainsKey('Start')) { $pvHint['Start'] } else { $null }
                    $pvE = if ($pvHint -is [hashtable] -and $pvHint.ContainsKey('End')) { $pvHint['End'] } else { $null }
                    if ($null -ne $pvS -and $null -ne $pvE -and $pvS -lt $pvE) { $modeRangeLabel = "$pvS-$pvE"; break }
                }
                Write-FlickFitHost "`n  現在のモード「話数選択モード」" -ForegroundColor Cyan
                if ($modeRangeLabel) {
                    Write-FlickFitHost "  第 $modeRangeLabel 巻の振り分けをします。" -ForegroundColor Green
                } else {
                    Write-FlickFitHost "  第 $vn 巻に複数のフォルダ候補があります。" -ForegroundColor Green
                }
            # 話数フォルダの親（例: ch360-391）の一つ上に cover が並ぶことが多い → 表紙検索・表示用に親階層も使う
            $chapterParentOneUp = Split-Path $parentPath -Parent
            $normParentPath = try { [System.IO.Path]::GetFullPath($parentPath).TrimEnd('\') } catch { $parentPath.TrimEnd('\') }
            $selectedCoverDir = $null
            $hasCachedCoverDir = $chapterSelectedCoverDirByParent.ContainsKey($normParentPath)
            $forceCoverReselect = $false
            $normOneUp = if ($chapterParentOneUp -and (Test-Path -LiteralPath $chapterParentOneUp)) {
                try { [System.IO.Path]::GetFullPath($chapterParentOneUp).TrimEnd('\') } catch { $chapterParentOneUp.TrimEnd('\') }
            } else { $null }
            $coverScanRoots = [System.Collections.Generic.List[string]]::new()
            [void]$coverScanRoots.Add($parentPath)
            if ($normOneUp -and $normOneUp -ne $normParentPath) { [void]$coverScanRoots.Add($chapterParentOneUp) }
            # エクスプローラー: 同階層に cover/表紙等があるときはその階層を開く（候補フォルダの内側だけだと表紙が見えない）
            $explorerOpenPath = $parentPath
            if ($normOneUp -and $normOneUp -ne $normParentPath) {
                $siblingCoverLike = @(Get-ChildItem -LiteralPath $chapterParentOneUp -Directory -ErrorAction SilentlyContinue | Where-Object {
                    $_.Name -match $script:FlickFitRegexCoverNameDigitsOnly
                })
                if ($siblingCoverLike.Count -gt 0) { $explorerOpenPath = $chapterParentOneUp }
            }
            $skipChapterCoverStep1 = $false
            $hasCoverLikeCandidate = @($candidates | Where-Object {
                $n = Split-Path $_.Path -Leaf
                $n -match $script:CoverFolderNameLikeRegex
            }).Count -gt 0
            # 範囲親（例: v37-42s）は、新規振り分け開始時に過去の表紙キャッシュを一度だけ破棄
            $ppNameForRange = Split-Path $parentPath -Leaf
            $pvRange = Get-VolFromParentName $ppNameForRange
            $pvRangeStart = if ($pvRange -is [hashtable] -and $pvRange.ContainsKey('Start')) { [int]$pvRange['Start'] } else { $null }
            $pvRangeEnd   = if ($pvRange -is [hashtable] -and $pvRange.ContainsKey('End'))   { [int]$pvRange['End'] }   else { $null }
            if ($null -ne $pvRangeStart -and $null -ne $pvRangeEnd -and $pvRangeStart -lt $pvRangeEnd) {
                $rangeResetKey = "$pvRangeStart-$pvRangeEnd-$normParentPath"
                if (-not $chapterRangeCoverResetDone.ContainsKey($rangeResetKey) -and $vn -eq $pvRangeStart) {
                    foreach ($rv in ($pvRangeStart..$pvRangeEnd)) {
                        if ($script:coverMap.ContainsKey($rv)) {
                            foreach ($cp in @($script:coverMap[$rv])) {
                                if ($cp) { [void]$chapterSharedCoverUsedPaths.Remove($cp) }
                            }
                            [void]$script:coverMap.Remove($rv)
                        }
                    }
                    if ($chapterSelectedCoverDirByParent.ContainsKey($normParentPath)) { [void]$chapterSelectedCoverDirByParent.Remove($normParentPath) }
                    $chapterRangeCoverResetDone[$rangeResetKey] = $true
                    Write-FlickFitHost "    [初期化] 第 $pvRangeStart-$pvRangeEnd 巻の過去表紙キャッシュをクリアしました。ここから再割り当てします。" -ForegroundColor DarkGray
                }
            }
            $existingCoverCount = if ($script:coverMap.ContainsKey($vn)) { @($script:coverMap[$vn]).Count } else { 0 }
            if ($existingCoverCount -le 1 -and $hasCoverLikeCandidate) { $forceCoverReselect = $true }
            if ($script:coverMap.ContainsKey($vn)) {
                if ($forceCoverReselect) {
                    Write-FlickFitHost "    [確認] 第 $vn 巻の表紙は仮設定の可能性があります。表紙指定をやり直します。" -ForegroundColor Yellow
                    foreach ($cp in @($script:coverMap[$vn])) {
                        if ($cp) { [void]$chapterSharedCoverUsedPaths.Remove($cp) }
                    }
                    [void]$script:coverMap.Remove($vn)
                    $skipChapterCoverStep1 = $false
                } else {
                    Write-FlickFitHost "    [再開] 第 $vn 巻の表紙はすでに確定済みです。[Enter] で話数フォルダへ  [R] で表紙からやり直し" -ForegroundColor Cyan
                    $resumeCh = (Read-HostWithEsc "  続行").Trim().ToUpper()
                    if ($resumeCh -ne 'R') { $skipChapterCoverStep1 = $true }
                    else {
                        foreach ($cp in @($script:coverMap[$vn])) {
                            if ($cp) { [void]$chapterSharedCoverUsedPaths.Remove($cp) }
                        }
                        [void]$script:coverMap.Remove($vn)
                    }
                }
            }
            if ($forceCoverReselect) { $hasCachedCoverDir = $false }
            if (-not $skipChapterCoverStep1 -and -not $hasCachedCoverDir) {
            $openPath = if ((Get-Variable -Name 'explorerOpenPath' -ErrorAction SilentlyContinue) -and $explorerOpenPath) { $explorerOpenPath } else { $parentPath }
            Write-FlickFitHost "    [フォルダを開いています: $(Split-Path $openPath -Leaf)]" -ForegroundColor Gray
            try { Start-Process "explorer.exe" -ArgumentList $openPath } catch {}
            
            # STEP2（構造解析）内: 表紙フォルダの選択
            Write-FlickFitHost "    [STEP2] 表紙フォルダ: 表紙画像が入っているフォルダを選んでください" -ForegroundColor Cyan
            
            # 表紙フォルダ候補を検出（各ルートを順に。特殊優先→一般 cover→0…→数字無し）
            $coverDir = $null
            foreach ($cr in $coverScanRoots) {
                $coverDir = Get-ChildItem -LiteralPath $cr -Directory -ErrorAction SilentlyContinue |
                    Where-Object { $_.Name -match $script:FlickFitRegexCoverSpecialPriorityToken } | Select-Object -First 1
                if ($coverDir) { break }
            }
            if (-not $coverDir) {
                foreach ($cr in $coverScanRoots) {
                    $coverDir = Get-ChildItem -LiteralPath $cr -Directory -ErrorAction SilentlyContinue |
                        Where-Object { $_.Name -match $script:FlickFitRegexCoverGeneralTokenNoSpecial } | Select-Object -First 1
                    if ($coverDir) { break }
                }
            }
            if (-not $coverDir) {
                foreach ($cr in $coverScanRoots) {
                    $coverDir = Get-ChildItem -LiteralPath $cr -Directory -ErrorAction SilentlyContinue |
                        Where-Object { $_.Name -match '^0+$' } | Select-Object -First 1
                    if ($coverDir) { break }
                }
            }
            if (-not $coverDir) {
                foreach ($cr in $coverScanRoots) {
                    $coverDir = Get-ChildItem -LiteralPath $cr -Directory -ErrorAction SilentlyContinue |
                        Where-Object { $_.Name -notmatch '\d' } | Select-Object -First 1
                    if ($coverDir) { break }
                }
            }
            
            if ($coverDir) {
                $coverImgs = @(Get-ChildItem -LiteralPath $coverDir.FullName -File -ErrorAction SilentlyContinue | Where-Object { $script:ImageExtensions -contains $_.Extension.ToLower() })
                Write-FlickFitHost ("    [表紙フォルダ] {0}  (画像 {1}枚)" -f $coverDir.Name, $coverImgs.Count) -ForegroundColor Cyan
                Write-FlickFitHost "    このフォルダでよければ Enter。変える場合は下の一覧の番号" -ForegroundColor DarkGray
            } else {
                Write-FlickFitHost "    [表紙フォルダ] 自動では検出できませんでした（下の一覧から番号で指定してください）" -ForegroundColor Yellow
            }
            # 親の親にある cover 等は候補一覧に無いことがあるため、番号指定用リストの末尾に追加
            $candPathNorm = @{}
            foreach ($c in $candidates) {
                try { $candPathNorm[[System.IO.Path]::GetFullPath($c.Path).TrimEnd('\')] = $true } catch {}
            }
            $coverPickerExtras = [System.Collections.Generic.List[PSObject]]::new()
            if ($normOneUp -and $normOneUp -ne $normParentPath) {
                foreach ($dir in @(Get-ChildItem -LiteralPath $chapterParentOneUp -Directory -ErrorAction SilentlyContinue)) {
                    $dn = $dir.Name
                    $isExtraCover = $dn -match $script:CoverFolderNameLikeRegex
                    if (-not $isExtraCover) { continue }
                    try { $dfp = [System.IO.Path]::GetFullPath($dir.FullName).TrimEnd('\') } catch { $dfp = $dir.FullName.TrimEnd('\') }
                    if ($candPathNorm.ContainsKey($dfp)) { continue }
                    $coverPickerExtras.Add([PSCustomObject]@{ Path = $dir.FullName })
                }
            }
            $coverPickerList = [System.Collections.Generic.List[PSObject]]::new()
            foreach ($c in $candidates) { [void]$coverPickerList.Add($c) }
            foreach ($ex in $coverPickerExtras) { [void]$coverPickerList.Add($ex) }
            if ($coverPickerExtras.Count -gt 0) {
                Write-FlickFitHost "    [注] 親フォルダ内の表紙フォルダを一覧の $($candidates.Count + 1) 番以降に追加しました" -ForegroundColor DarkGray
            }
            
            # フォルダ一覧を表示（話数モード: 2列表示、表紙候補は色付き）
            $chLines = @(); $chIsCoverCandidate = @()
            for ($i = 0; $i -lt $coverPickerList.Count; $i++) {
                $folderPath = $coverPickerList[$i].Path
                $folderName = Split-Path $folderPath -Leaf
                $imgs = @(Get-ChildItem -LiteralPath $folderPath -File -ErrorAction SilentlyContinue | Where-Object { $script:ImageExtensions -contains $_.Extension.ToLower() })
                $subDirs = @(Get-ChildItem -LiteralPath $folderPath -Directory -ErrorAction SilentlyContinue)
                $imgCnt = $imgs.Count
                $isCoverCandidate = $folderName -match $script:FlickFitRegexCoverUnionLooseNoAnchor -or $folderName -notmatch '\d'
                $chIsCoverCandidate += $isCoverCandidate
                $txt = if ($subDirs.Count -gt 0) {
                    $subNames = @($subDirs | Sort-Object { [regex]::Replace($_.Name, '\d+', { $args[0].Value.PadLeft(10,'0') }) } | ForEach-Object { $_.Name })
                    $subStr = if ($subNames.Count -le 5) { $subNames -join ", " } else { ($subNames[0..4] -join ", ") + " ...他$($subNames.Count - 5)件" }
                    $suffix = if ($isCoverCandidate) { " ★表紙候補" } else { "" }
                    ("    [{0}] {1}  (画像 {2}枚, サブ: {3}){4}" -f ($i+1), $folderName, $imgCnt, $subStr, $suffix)
                } else {
                    $suffix = if ($isCoverCandidate) { " ★表紙候補" } else { "" }
                    ("    [{0}] {1}  (画像 {2}枚){3}" -f ($i+1), $folderName, $imgCnt, $suffix)
                }
                $chLines += $txt
            }
            $chColW = 58
            $chN = $chLines.Count; $chMid = [Math]::Ceiling($chN / 2)
            for ($i = 0; $i -lt $chMid; $i++) {
                $left = $chLines[$i].PadRight($chColW)
                $leftClr = if ($chIsCoverCandidate[$i]) { 'Green' } else { 'White' }
                $right = if ($i + $chMid -lt $chN) { $chLines[$i + $chMid] } else { "" }
                $rightClr = if ($i + $chMid -lt $chN -and $chIsCoverCandidate[$i + $chMid]) { 'Green' } else { 'White' }
                Write-FlickFitHost -NoNewline $left -ForegroundColor $leftClr
                if ($right) { Write-FlickFitHost "  $right" -ForegroundColor $rightClr } else { Write-FlickFitHost "" }
            }
            Write-FlickFitHost "    [Enter] 上記の表紙フォルダでOK  [番号] 一覧の別フォルダを指定  [N] 表紙なし  [S] この巻をスキップ  [M] 巻数選択モードへ（以降の巻にも適用）" -ForegroundColor DarkGray
            
            $coverAns = (Read-HostWithEsc "  表紙フォルダ").Trim().ToUpper()
            if ($coverAns -eq 'S') { Write-FlickFitHost "    -> スキップしました (この巻は処理されません)" -ForegroundColor Yellow; continue }
            if ($coverAns -eq 'M') {
                $script:ForceVolumeMode = $true
                $script:ForceChapterMode = $false
                $isChapterMode = $false
                $modeSwitchRetry = $true
                Write-FlickFitHost "    -> 巻数選択モードに切り替え（以降の巻にも適用・この巻の「どれを採用」を表示）" -ForegroundColor Yellow
                continue
            }
            
            # 表紙フォルダを決定
            if ($coverAns -eq '' -and $coverDir) {
                $selectedCoverDir = $coverDir
                Write-FlickFitHost "    -> 表紙フォルダ: $($selectedCoverDir.Name)" -ForegroundColor Green
            } elseif ($coverAns -eq 'N' -or $coverAns -eq '') {
                Write-FlickFitHost "    -> 表紙フォルダなし" -ForegroundColor Yellow
            } elseif ($coverAns -match '^\d+$') {
                $coverIdx = [int]$coverAns - 1
                if ($coverIdx -ge 0 -and $coverIdx -lt $coverPickerList.Count) {
                    $selectedCoverDir = Get-Item -LiteralPath $coverPickerList[$coverIdx].Path -ErrorAction SilentlyContinue
                    if ($selectedCoverDir) { Write-FlickFitHost "    -> 表紙フォルダ: $($selectedCoverDir.Name)" -ForegroundColor Green }
                }
            }
            if ($selectedCoverDir) {
                $chapterSelectedCoverDirByParent[$normParentPath] = $selectedCoverDir.FullName
            }
            } elseif ($hasCachedCoverDir) {
                $cachedCoverPath = $chapterSelectedCoverDirByParent[$normParentPath]
                if ($cachedCoverPath -and (Test-Path -LiteralPath $cachedCoverPath)) {
                    $selectedCoverDir = Get-Item -LiteralPath $cachedCoverPath -ErrorAction SilentlyContinue
                    if ($selectedCoverDir) {
                        Write-FlickFitHost "    -> 前巻で選んだ表紙フォルダを再利用: $($selectedCoverDir.Name)" -ForegroundColor DarkCyan
                    }
                }
            }
            
            # 表紙フォルダ確定後は常に表紙画像を選ぶ（巻数モードでフォルダだけ選んだ直後もここへ来る）
            # 表紙フォルダを coverMap に登録（画像選択あり）※他巻で使った画像は一覧から除外
            if (-not $skipChapterCoverStep1 -and $selectedCoverDir) {
                $coverImgFilesAll = @(Get-ChildItem -LiteralPath $selectedCoverDir.FullName -File -ErrorAction SilentlyContinue | 
                    Where-Object { $script:ImageExtensions -contains $_.Extension.ToLower() } |
                    Sort-Object { [regex]::Replace($_.Name, '\d+', { $args[0].Value.PadLeft(10,'0') }) })
                $coverImgFiles = @($coverImgFilesAll | Where-Object { -not $chapterSharedCoverUsedPaths.Contains($_.FullName) })
                if ($coverImgFiles.Count -eq 0 -and $coverImgFilesAll.Count -gt 0) {
                    Write-FlickFitHost "`n    [警告] この表紙フォルダの画像は、いずれも他巻に割り当て済みです（表紙なしとして続行）" -ForegroundColor Yellow
                } elseif ($coverImgFiles.Count -gt 0) {
                    # フォルダを開いて画像を確認できるようにする
                    $remainNote = if ($coverImgFilesAll.Count -gt $coverImgFiles.Count) {
                        "（未割り当て $($coverImgFiles.Count) / 全 $($coverImgFilesAll.Count) 枚）"
                    } else { "($($coverImgFiles.Count) 枚)" }
                    Write-FlickFitHost "`n    [表紙画像の選択] $($selectedCoverDir.Name) $remainNote" -ForegroundColor Cyan
                    if ($coverImgFilesAll.Count -gt $coverImgFiles.Count) {
                        Write-FlickFitHost "    [注] 他巻で既に選んだ画像は番号一覧から除外しています" -ForegroundColor DarkGray
                    }
                    Write-FlickFitHost "    [フォルダを開いています...]" -ForegroundColor Gray
                    try { Start-Process "explorer.exe" -ArgumentList $selectedCoverDir.FullName } catch {}
                    
                    # 画像一覧（未割り当てのみ表示、番号は元の連番のまま維持）
                    for ($j = 0; $j -lt $coverImgFilesAll.Count; $j++) {
                        if (-not $chapterSharedCoverUsedPaths.Contains($coverImgFilesAll[$j].FullName)) {
                            Write-FlickFitHost ("      [{0}] {1}" -f ($j+1), $coverImgFilesAll[$j].Name) -ForegroundColor White
                        }
                    }
                    Write-FlickFitHost $step2HintCoverImg -ForegroundColor DarkGray
                    
                    $selectedCoverPaths = @()
                    while ($true) {
                        $imgSelectAns = (Read-HostWithEsc "    表紙画像").Trim().ToUpper()
                        if ($imgSelectAns -eq 'A') {
                            $selectedCoverPaths = @($coverImgFiles | ForEach-Object { $_.FullName })
                            Write-FlickFitHost "    -> 全採用 ($($coverImgFiles.Count) 枚)" -ForegroundColor Green
                            break
                        }
                        if ($imgSelectAns -eq '') {
                            Write-FlickFitHost "    -> 変更なし（この巻の表紙選択は維持）" -ForegroundColor Gray
                            break
                        }
                        if ($imgSelectAns -eq 'N') {
                            Write-FlickFitHost "    -> 表紙なし" -ForegroundColor Yellow
                            break
                        }
                        # 範囲指定やカンマ区切りに対応（番号は上記の未割り当てリストに対応）
                        $parsedIdx = @(Parse-RangeInput $imgSelectAns $coverImgFilesAll.Count)
                        $validIdx = @($parsedIdx | Where-Object { -not $chapterSharedCoverUsedPaths.Contains($coverImgFilesAll[$_].FullName) })
                        if ($validIdx.Count -gt 0) {
                            $selectedCoverPaths = @($validIdx | ForEach-Object { $coverImgFilesAll[$_].FullName })
                            Write-FlickFitHost "    -> 選択: $($validIdx.Count) 枚" -ForegroundColor Green
                            break
                        }
                        Write-FlickFitHost "    -> 入力が無効です。表示中の番号で再入力してください（例: 1-3 / 1,2,3 / A / N）" -ForegroundColor Yellow
                    }
                    
                    if ($selectedCoverPaths.Count -gt 0) {
                        if (-not $script:coverMap.ContainsKey($vn)) { $script:coverMap[$vn] = @() }
                        $script:coverMap[$vn] = $selectedCoverPaths
                        foreach ($scp in $selectedCoverPaths) { [void]$chapterSharedCoverUsedPaths.Add($scp) }
                    }
                }
            }
            if (-not $script:coverMap.ContainsKey($vn)) { $script:coverMap[$vn] = @() }
            if ($skipChapterCoverStep1) {
            $openPath = $parentPath
            Write-FlickFitHost "    [フォルダを開いています: $(Split-Path $openPath -Leaf)]" -ForegroundColor Gray
            try { Start-Process "explorer.exe" -ArgumentList $openPath } catch {}
            $selectedCoverDir = $null
            $cvPaths = @($script:coverMap[$vn])
            if ($cvPaths.Count -gt 0 -and $cvPaths[0]) {
                $coverParentDir = Split-Path $cvPaths[0] -Parent
                $selectedCoverDir = Get-Item -LiteralPath $coverParentDir -ErrorAction SilentlyContinue
            }
            if ($cvPaths.Count -eq 1 -and $cvPaths[0]) {
                $pickedCoverName = Split-Path $cvPaths[0] -Leaf
                Write-FlickFitHost "    -> 表紙画像が1枚のため「$pickedCoverName」を表紙に採用済みです。話数フォルダの選択へ進みます。" -ForegroundColor Green
            } elseif ($cvPaths.Count -gt 1) {
                Write-FlickFitHost "    -> 表紙画像 $($cvPaths.Count) 枚は採用済みです。話数フォルダの選択へ進みます。" -ForegroundColor Green
            } else {
                Write-FlickFitHost "    -> 表紙画像は未設定のまま、話数フォルダの選択へ進みます。" -ForegroundColor Yellow
            }
            }
            
            # STEP2（構造解析）内: 話数フォルダの選択（2列表示）
            $normSelCoverPath = $null
            if ($selectedCoverDir) {
                try { $normSelCoverPath = [System.IO.Path]::GetFullPath($selectedCoverDir.FullName).TrimEnd('\') } catch { $normSelCoverPath = $selectedCoverDir.FullName.TrimEnd('\') }
            }
            $chapterCandidates = @($candidates | Where-Object {
                $leaf = Split-Path $_.Path -Leaf
                $normC = $null; try { $normC = [System.IO.Path]::GetFullPath($_.Path).TrimEnd('\') } catch { $normC = $_.Path.TrimEnd('\') }
                if ($normSelCoverPath -and $normC -eq $normSelCoverPath) { return $false }
                if ($leaf -match $script:CoverFolderNameLikeRegex) { return $false }
                $true
            })
            if ($chapterCandidates.Count -eq 0 -and $normSelCoverPath) {
                $chapterCandidates = @($candidates | Where-Object {
                    $n2 = $null; try { $n2 = [System.IO.Path]::GetFullPath($_.Path).TrimEnd('\') } catch { $n2 = $_.Path.TrimEnd('\') }
                    $n2 -ne $normSelCoverPath
                })
            }
            if ($chapterCandidates.Count -eq 0) {
                Write-FlickFitHost "    話数として選べるフォルダがありません（表紙のみ等）。この巻はスキップします。" -ForegroundColor Yellow
                continue
            }

            # 同一範囲巻（例: 37-42）では、先に全巻の表紙を割り当ててから話数を一括で割り振る
            $rangeInfo = $null
            if ($selectedCoverDir) {
                $coverParentPath = Split-Path $selectedCoverDir.FullName -Parent
                $r = Get-VolFromParentName (Split-Path $coverParentPath -Leaf)
                $rs = if ($r -is [hashtable] -and $r.ContainsKey('Start')) { $r['Start'] } else { $null }
                $re = if ($r -is [hashtable] -and $r.ContainsKey('End')) { $r['End'] } else { $null }
                if ($null -ne $rs -and $null -ne $re -and $rs -lt $re) {
                    $rangeInfo = [PSCustomObject]@{ Start = [int]$rs; End = [int]$re; Parent = $coverParentPath }
                }
            }
            if ($rangeInfo) {
                $rangeKey = "$($rangeInfo.Start)-$($rangeInfo.End)-$($rangeInfo.Parent)"
                if (-not $chapterRangeCoverState.ContainsKey($rangeKey)) {
                    $chapterRangeCoverState[$rangeKey] = [PSCustomObject]@{
                        Start = $rangeInfo.Start
                        End = $rangeInfo.End
                        CoveredVols = [System.Collections.Generic.HashSet[int]]::new()
                    }
                }
                $state = $chapterRangeCoverState[$rangeKey]
                if ($script:coverMap.ContainsKey($vn) -and @($script:coverMap[$vn]).Count -gt 0) { [void]$state.CoveredVols.Add([int]$vn) }
                $spanCount = $state.End - $state.Start + 1
                if ($state.CoveredVols.Count -lt $spanCount) {
                    Write-FlickFitHost "    -> 第 $($state.Start)-$($state.End) 巻は、先に全巻の表紙を割り当てます（現在 $($state.CoveredVols.Count)/$spanCount）。" -ForegroundColor DarkCyan
                    continue
                }
                if ($vn -eq $state.End) {
                    # 最後の巻に到達したら、話数割り振りを一括で実行
                    $chNumToPath = @{}
                    foreach ($cc in $chapterCandidates) {
                        $leaf = Split-Path $cc.Path -Leaf
                        $k = (Get-ChapterNumber $leaf).ToString()
                        if (-not $chNumToPath.ContainsKey($k)) { $chNumToPath[$k] = $cc.Path }
                    }
                    $chNums = @($chNumToPath.Keys | Sort-Object { [double]$_ })
                    $chNumToIndex = @{}
                    for ($i = 0; $i -lt $chNums.Count; $i++) { $chNumToIndex[$chNums[$i]] = $i }
                    $usedChapterIndices = [System.Collections.Generic.HashSet[int]]::new()
                    Write-FlickFitHost "`n    [STEP2] 話数の振り分け（複数巻まとめて）: 第 $($state.Start)-$($state.End) 巻" -ForegroundColor Cyan
                    foreach ($v in ($state.Start..$state.End)) {
                        $remaining = @($chNums | Where-Object { -not $usedChapterIndices.Contains($chNumToIndex[$_]) })
                        if ($remaining.Count -eq 0) { Write-FlickFitHost "    第 $v 巻: 残り話数なし" -ForegroundColor Yellow; continue }
                        Write-FlickFitHost "`n    第 $v 巻に入れる話数（左の番号で指定）" -ForegroundColor Cyan
                        foreach ($ch in $remaining) {
                            Write-FlickFitHost "      [$ch] $(Split-Path $chNumToPath[$ch] -Leaf)" -ForegroundColor White
                        }
                        Write-FlickFitHost "    $step2HintChapterNums" -ForegroundColor DarkGray
                        $ans = (Read-HostWithEsc "    話数（話数番号）").Trim()
                        if ([string]::IsNullOrWhiteSpace($ans)) { continue }
                        $indices = @(Parse-ChapterInput $ans $chNumToIndex)
                        if ($indices.Count -gt 0) {
                            if (-not $volMap.ContainsKey($v)) { $volMap[$v] = [System.Collections.Generic.List[string]]::new() } else { $volMap[$v].Clear() }
                            foreach ($idx in $indices) {
                                if (-not $usedChapterIndices.Contains([int]$idx)) {
                                    $volMap[$v].Add($chNumToPath[$chNums[$idx]])
                                    [void]$usedChapterIndices.Add([int]$idx)
                                }
                            }
                            $script:volMapFilledByChapterSplit[$v] = $true
                            [void]$script:volMapPreserveChapterOrder.Add([int]$v)
                            Write-FlickFitHost "    -> 第 $v 巻: $($volMap[$v].Count) 話を採用" -ForegroundColor Green
                        }
                    }
                    continue
                } else {
                    continue
                }
            }
            Write-FlickFitHost "`n    [STEP2] 話数フォルダ: この巻に含めるフォルダを選んでください" -ForegroundColor Cyan
            $ch2Lines = @()
            for ($i = 0; $i -lt $chapterCandidates.Count; $i++) {
                $folderPath = $chapterCandidates[$i].Path
                $folderName = Split-Path $folderPath -Leaf
                $imgs = @(Get-ChildItem -LiteralPath $folderPath -File -ErrorAction SilentlyContinue | Where-Object { $script:ImageExtensions -contains $_.Extension.ToLower() })
                $subDirs = @(Get-ChildItem -LiteralPath $folderPath -Directory -ErrorAction SilentlyContinue)
                $imgCnt = $imgs.Count
                $isCover = $selectedCoverDir -and ($folderPath -eq $selectedCoverDir.FullName)
                $txt = if ($isCover) {
                    ("    [{0}] {1}  (画像 {2}枚) [表紙]" -f ($i+1), $folderName, $imgCnt)
                } elseif ($subDirs.Count -gt 0) {
                    $subNames = @($subDirs | Sort-Object { [regex]::Replace($_.Name, '\d+', { $args[0].Value.PadLeft(10,'0') }) } | ForEach-Object { $_.Name })
                    $subStr = if ($subNames.Count -le 5) { $subNames -join ", " } else { ($subNames[0..4] -join ", ") + " ...他$($subNames.Count - 5)件" }
                    ("    [{0}] {1}  (画像 {2}枚, サブ: {3})" -f ($i+1), $folderName, $imgCnt, $subStr)
                } else {
                    ("    [{0}] {1}  (画像 {2}枚)" -f ($i+1), $folderName, $imgCnt)
                }
                $ch2Lines += [PSCustomObject]@{ Text = $txt; IsCover = $isCover }
            }
            $ch2ColW = 52
            $ch2N = $ch2Lines.Count; $ch2Mid = [Math]::Ceiling($ch2N / 2)
            for ($i = 0; $i -lt $ch2Mid; $i++) {
                $left = $ch2Lines[$i].Text.PadRight($ch2ColW)
                $leftClr = if ($ch2Lines[$i].IsCover) { 'DarkCyan' } else { 'White' }
                $right = if ($i + $ch2Mid -lt $ch2N) { $ch2Lines[$i + $ch2Mid].Text } else { "" }
                $rightClr = if ($i + $ch2Mid -lt $ch2N -and $ch2Lines[$i + $ch2Mid].IsCover) { 'DarkCyan' } else { 'White' }
                Write-FlickFitHost -NoNewline $left -ForegroundColor $leftClr
                if ($right) { Write-FlickFitHost "  $right" -ForegroundColor $rightClr } else { Write-FlickFitHost "" }
            }
            Write-FlickFitHost "    $step2HintFolderIdx" -ForegroundColor DarkGray
            $firstAns = (Read-HostWithEsc "  話数（一覧の番号）").Trim().ToUpper()
            if ($firstAns -eq 'S' -or $firstAns -eq '') { 
                Write-FlickFitHost "    -> スキップしました (この巻は処理されません)" -ForegroundColor Yellow
                continue 
            }
            $selectedCandidates = [System.Collections.ArrayList]::new()
            $wasAllSelected = $false
            if ($firstAns -eq 'A') {
                foreach ($c in $chapterCandidates) { [void]$selectedCandidates.Add($c) }
                Write-FlickFitHost "    -> 全採用 ($($chapterCandidates.Count) フォルダ)" -ForegroundColor Green
                $wasAllSelected = $true
            } else {
                # 範囲指定（例: 3-6）やカンマ区切り（例: 3,4,5）に対応
                $parsedIndices = @(Parse-RangeInput $firstAns $chapterCandidates.Count)
                if ($parsedIndices.Count -gt 0) {
                    foreach ($idx in $parsedIndices) { [void]$selectedCandidates.Add($chapterCandidates[$idx]) }
                    if ($parsedIndices.Count -eq 1) {
                        Write-FlickFitHost "    -> 採用: [$($parsedIndices[0]+1)] $(Split-Path $chapterCandidates[$parsedIndices[0]].Path -Leaf)" -ForegroundColor Green
                    } else {
                        Write-FlickFitHost "    -> 採用: $($parsedIndices.Count) フォルダ" -ForegroundColor Green
                    }
                } else {
                    Write-FlickFitHost "    -> 無効な入力です。この巻はスキップします。" -ForegroundColor Yellow
                    continue
                }
            }
            if ($selectedCandidates.Count -eq 0) { continue }

            # チャプター選択時: その場でカバー確認 + 話数振り分け
            # ただし、番号で1つだけ選択した場合は話数振り分けをスキップ（選択したフォルダのみ採用）
            $chapterParents = @($selectedCandidates | Where-Object { 
                $name = Split-Path $_.Path -Leaf
                $name -match '(?i)chapter\s*0*\d+(?:\.\d+)?' -or $name -match '第\s*0*\d+(?:\.\d+)?\s*話'
            } | ForEach-Object { (Split-Path $_.Path -Parent) } | Select-Object -Unique)
            if ($chapterParents.Count -gt 0 -and $wasAllSelected) {
                foreach ($parentPath in $chapterParents) {
                    $normParent = [System.IO.Path]::GetFullPath($parentPath)
                    if ($script:processedChapterParentPaths.ContainsKey($normParent)) { continue }
                    $parentName = Split-Path $parentPath -Leaf
                    if (Test-FlickFitChapterParentFullyAssigned -ParentNameLeaf $parentName -VolMap $volMap) {
                        $script:processedChapterParentPaths[$normParent] = $true
                        continue
                    }
                    $script:processedChapterParentPaths[$normParent] = $true
                    $pv = Get-VolFromParentName $parentName
                    $pvVol   = if ($pv -is [hashtable] -and $pv.ContainsKey('Vol'))   { $pv['Vol'] }   else { $null }
                    $pvStart = if ($pv -is [hashtable] -and $pv.ContainsKey('Start')) { $pv['Start'] } else { $null }
                    $pvEnd   = if ($pv -is [hashtable] -and $pv.ContainsKey('End'))   { $pv['End'] }   else { $null }
                    if ($null -ne $pvVol -and ($null -eq $pvStart -or $null -eq $pvEnd)) { $pvStart = $pvVol; $pvEnd = $pvVol }
                    if ($null -eq $pvStart -or $null -eq $pvEnd) { continue }

                    # 表紙フォルダを先に表示 → 表紙選択 → 話数振り分け（表紙を見ながら1巻に何話入るか把握できる）
                    $coverVolMap = @{}
                    $genericCovers = @()
                    # 複数のcoverフォルダを検出（cover1, cover2 など＋数字の無いフォルダも表紙候補）
                    $coverCandidates = @(Get-ChildItem -LiteralPath $parentPath -Directory -ErrorAction SilentlyContinue | Where-Object { 
                        $_.Name -match $script:FlickFitRegexCoverUnionOrPad -or $_.Name -notmatch '\d'
                    })
                    if ($coverCandidates.Count -eq 0 -and $script:detectedCoverFolders.Count -gt 0) {
                        $coverCandidates = @($script:detectedCoverFolders | Where-Object { [System.IO.Path]::GetFullPath((Split-Path $_.Path -Parent)) -eq $normParent } | ForEach-Object { Get-Item -LiteralPath $_.Path -ErrorAction SilentlyContinue })
                    }
                    $gpForCover2 = Split-Path $parentPath -Parent
                    $normPPc2 = try { [System.IO.Path]::GetFullPath($parentPath).TrimEnd('\') } catch { $parentPath.TrimEnd('\') }
                    $normGPc2 = if ($gpForCover2 -and (Test-Path -LiteralPath $gpForCover2)) { try { [System.IO.Path]::GetFullPath($gpForCover2).TrimEnd('\') } catch { $null } } else { $null }
                    if ($normGPc2 -and $normGPc2 -ne $normPPc2) {
                        $gpCoverOnly2 = @(Get-ChildItem -LiteralPath $gpForCover2 -Directory -ErrorAction SilentlyContinue | Where-Object {
                            $dn = $_.Name
                            $dn -match $script:FlickFitRegexCoverBareTokensOnly -or $dn -match '^[^\-_]+[-_](0|cover)$' -or $dn -match '^0+$'
                        })
                        $coverByPath2 = @{}
                        foreach ($x in @($coverCandidates) + $gpCoverOnly2) {
                            if (-not $x) { continue }
                            try { $ck = [System.IO.Path]::GetFullPath($x.FullName).TrimEnd('\') } catch { $ck = $x.FullName }
                            $coverByPath2[$ck] = $x
                        }
                        $coverCandidates = @($coverByPath2.Values)
                    }
                    if ($coverCandidates.Count -gt 0) {
                        # フォルダ名から巻数を推測して紐付け（cover1→1巻, cover2→2巻）
                        $coverVolMap = @{}  # 巻番号 -> フォルダパス
                        $genericCovers = @()  # 巻番号なしのcoverフォルダ
                        foreach ($cDir in $coverCandidates) {
                            if ($cDir.Name -match '(?i)(?:cover|表紙|カバー)(\d+)') {
                                $coverVol = [int]$Matches[1]
                                $coverVolMap[$coverVol] = $cDir
                            } else {
                                $genericCovers += $cDir
                            }
                        }
                        
                        Write-FlickFitHost "`n  [STEP2] 表紙（画像）: $parentName" -ForegroundColor Cyan
                        Write-FlickFitHost "    ※ 各巻の表紙画像を選び、そのあと [STEP2] 話数の振り分けで話数フォルダを割り当てます" -ForegroundColor DarkGray
                        if ($coverVolMap.Count -gt 0) {
                            foreach ($cv in ($coverVolMap.Keys | Sort-Object)) {
                                $cvDir = $coverVolMap[$cv]
                                $cvImgCnt = @(Get-ChildItem -LiteralPath $cvDir.FullName -File -ErrorAction SilentlyContinue | Where-Object { $script:ImageExtensions -contains $_.Extension.ToLower() }).Count
                                Write-FlickFitHost "    - $($cvDir.Name) -> 第${cv}巻 ($cvImgCnt 枚)" -ForegroundColor Gray
                            }
                        }
                        if ($genericCovers.Count -gt 0) {
                            foreach ($gcDir in $genericCovers) {
                                $gcImgCnt = @(Get-ChildItem -LiteralPath $gcDir.FullName -File -ErrorAction SilentlyContinue | Where-Object { $script:ImageExtensions -contains $_.Extension.ToLower() }).Count
                                Write-FlickFitHost "    - $($gcDir.Name) -> 全巻共通 ($gcImgCnt 枚)" -ForegroundColor Gray
                            }
                        }
                        
                        Write-FlickFitHost "`n  [STEP2] 表紙画像を選んでください（巻ごと）" -ForegroundColor Cyan
                        $volList = @($pvStart..$pvEnd)
                        $volIdx = 0
                        $usedCoverPaths = [System.Collections.Generic.HashSet[string]]::new()  # 選択済み画像追跡
                        while ($volIdx -lt $volList.Count) {
                            $v = $volList[$volIdx]
                            
                            # この巻に対応するcoverフォルダを決定
                            $currentCoverDir = $null
                            if ($coverVolMap.ContainsKey($v)) {
                                $currentCoverDir = $coverVolMap[$v]
                            } elseif ($genericCovers.Count -gt 0) {
                                $currentCoverDir = $genericCovers[0]
                            }
                            
                            if (-not $currentCoverDir) {
                                Write-FlickFitHost "    第 $v 巻: 対応する表紙フォルダがありません" -ForegroundColor Yellow
                                $volIdx++
                                continue
                            }
                            
                            # 全画像リストを取得（番号は元のまま表示、選択済みはスキップ）
                            $allCoverImgs = @(Get-ChildItem -LiteralPath $currentCoverDir.FullName -File -ErrorAction SilentlyContinue | Where-Object { $script:ImageExtensions -contains $_.Extension.ToLower() } | Sort-Object { [regex]::Replace($_.Name, '\d+', { $args[0].Value.PadLeft(10,'0') }) })
                            $availableCount = @($allCoverImgs | Where-Object { -not $usedCoverPaths.Contains($_.FullName) }).Count
                            
                            if ($availableCount -eq 0) {
                                Write-FlickFitHost "    第 $v 巻: 表紙画像がありません ($($currentCoverDir.Name))" -ForegroundColor Yellow
                                $volIdx++
                                continue
                            }
                            
                            Write-FlickFitHost "`n    第 $v 巻の表紙 [$($currentCoverDir.Name)] ($availableCount 枚):" -ForegroundColor Cyan
                            try { Start-Process "explorer.exe" -ArgumentList $currentCoverDir.FullName } catch {}
                            
                            # 番号は元のまま表示、選択済みはスキップ
                            for ($i = 0; $i -lt $allCoverImgs.Count; $i++) {
                                if (-not $usedCoverPaths.Contains($allCoverImgs[$i].FullName)) {
                                    Write-FlickFitHost "      [$($i+1)] $($allCoverImgs[$i].Name)" -ForegroundColor White
                                }
                            }
                            Write-FlickFitHost $(if ($volIdx -gt 0) { $step2HintCoverImgR } else { $step2HintCoverImgFirstVol }) -ForegroundColor DarkGray
                            
                            $idxAns = (Read-HostWithEsc "    表紙画像").Trim().ToUpper()
                            
                            if ($idxAns -eq 'R') {
                                if ($volIdx -le 0) {
                                    Write-FlickFitHost "    -> これより前の巻はありません" -ForegroundColor Yellow
                                    continue
                                }
                                $prevV = $volList[$volIdx - 1]
                                # 前巻の選択を解除してusedCoverPathsからも削除
                                if ($script:coverMap.ContainsKey($prevV)) {
                                    foreach ($cp in $script:coverMap[$prevV]) { $usedCoverPaths.Remove($cp) | Out-Null }
                                    $script:coverMap.Remove($prevV)
                                }
                                Write-FlickFitHost "    -> 第 $prevV 巻に戻ります" -ForegroundColor Yellow
                                $volIdx--
                                continue
                            }
                            
                            if ($idxAns -eq 'N') {
                                if ($script:coverMap.ContainsKey($v)) {
                                    foreach ($cp in @($script:coverMap[$v])) { if ($cp) { [void]$usedCoverPaths.Remove($cp) } }
                                    $script:coverMap.Remove($v)
                                }
                                Write-FlickFitHost "    -> 第 $v 巻: 表紙なし" -ForegroundColor Yellow
                            }
                            elseif ($idxAns -eq 'A') {
                                $covPaths = @($allCoverImgs | Where-Object { -not $usedCoverPaths.Contains($_.FullName) } | ForEach-Object { $_.FullName })
                                foreach ($p in $covPaths) { [void]$usedCoverPaths.Add($p) }
                                $script:coverMap[$v] = $covPaths
                                Write-FlickFitHost "    -> 第 $v 巻: 全採用 ($($covPaths.Count) 枚)" -ForegroundColor Green
                            }
                            elseif ($idxAns) {
                                # 元の番号で入力を受け付け（選択済みは無視）
                                $parsedIndices = @(Parse-RangeInput $idxAns $allCoverImgs.Count)
                                $validIndices = @($parsedIndices | Where-Object { -not $usedCoverPaths.Contains($allCoverImgs[$_].FullName) })
                                if ($validIndices.Count -gt 0) {
                                    $covPaths = @($validIndices | ForEach-Object { $allCoverImgs[$_].FullName })
                                    foreach ($idx in $validIndices) {
                                        Write-FlickFitHost "      選択: $($allCoverImgs[$idx].Name)" -ForegroundColor Green
                                        $usedCoverPaths.Add($allCoverImgs[$idx].FullName) | Out-Null
                                    }
                                    $script:coverMap[$v] = $covPaths
                                    Write-FlickFitHost "    -> 第 $v 巻: $($covPaths.Count) 枚選択" -ForegroundColor Green
                                } else {
                                    Write-FlickFitHost "      無効な入力または選択済みです" -ForegroundColor Red
                                    continue
                                }
                            } else {
                                Write-FlickFitHost "    -> 第 $v 巻: スキップ" -ForegroundColor Gray
                            }
                            $volIdx++
                        }
                        Write-FlickFitHost ""
                    }

                    # 話数フォルダの振り分け（表紙確認後）- 小数点付き話数・話数範囲対応
                    $chapterFolders = @(Get-ChildItem -LiteralPath $parentPath -Directory -ErrorAction SilentlyContinue | Where-Object { 
                        $n = $_.Name
                        $n -match '(?i)chapter\s*0*\d+(?:\.\d+)?(?:\s*[-~]\s*0*\d+(?:\.\d+)?)?' -or 
                        $n -match '第\s*0*\d+(?:\.\d+)?(?:\s*[-~]\s*0*\d+(?:\.\d+)?)?\s*話' -or
                        $n -match '^\s*\d+(?:\.\d+)?\s*[-~]\s*\d+(?:\.\d+)?\s*$' -or
                        $n -match '^\d+(?:\.\d+)?_files$' -or $n -match '[-_](\d+(?:\.\d+)?)_files$' -or
                        $n -match '^\d{3,4}$'
                    } | Sort-Object { [regex]::Replace($_.Name, '\d+(?:\.\d+)?', { $args[0].Value.PadLeft(10,'0') }) })
                    # 同じ話数に複数フォルダ（前編・後編など）がある場合に対応するため配列で保持
                    $chNumToPaths = @{}
                    $chNumDisplay2 = @{}  # 表示用（範囲の場合は "10-15" など）
                    foreach ($cf in $chapterFolders) {
                        $chNum = $null
                        $dispNum = $null
                        # 話数範囲パターンを先にチェック
                        if ($cf.Name -match '第\s*0*(\d+(?:\.\d+)?)\s*[-~]\s*0*(\d+(?:\.\d+)?)\s*話') {
                            $chNum = $Matches[1]
                            $dispNum = "$($Matches[1])-$($Matches[2])"
                        } elseif ($cf.Name -match '(?i)chapter\s*0*(\d+(?:\.\d+)?)\s*[-~]\s*0*(\d+(?:\.\d+)?)') {
                            $chNum = $Matches[1]
                            $dispNum = "$($Matches[1])-$($Matches[2])"
                        } elseif ($cf.Name -match '(?i)chapter\s*0*(\d+(?:\.\d+)?)') { 
                            $chNum = $Matches[1]
                            $dispNum = $Matches[1]
                        } elseif ($cf.Name -match '第\s*0*(\d+(?:\.\d+)?)\s*話') { 
                            $chNum = $Matches[1]
                            $dispNum = $Matches[1]
                        } elseif ($cf.Name -match '^(\d+(?:\.\d+)?)_files$' -or $cf.Name -match '[-_](\d+(?:\.\d+)?)_files$') {
                            $chNum = $Matches[1]
                            $dispNum = $Matches[1]
                        } elseif ($cf.Name -match '^\s*(\d+(?:\.\d+)?)\s*[-~]\s*(\d+(?:\.\d+)?)\s*$') {
                            $chNum = $Matches[1]
                            $dispNum = "$($Matches[1])-$($Matches[2])"
                        } elseif ($cf.Name -match '^(\d{3,4})$') {
                            $chNum = $Matches[1]
                            $dispNum = $Matches[1]
                        }
                        if ($chNum) {
                            if (-not $chNumToPaths.ContainsKey($chNum)) { $chNumToPaths[$chNum] = @() }
                            $chNumToPaths[$chNum] += @($cf.FullName)
                            $chNumDisplay2[$chNum] = $dispNum
                        }
                    }
                    $chNums = @($chNumToPaths.Keys | Sort-Object { [double]$_ })
                    if ($chNums.Count -eq 0) { continue }
                    $chRangeStr = "$($chNums[0])-$($chNums[-1])"
                    Write-FlickFitHost "`n  [STEP2] 話数の振り分け: $parentName" -ForegroundColor Cyan
                    
                    # 全話数フォルダを個別にリスト表示（範囲フォルダは "10-15" のように表示）
                    Write-FlickFitHost "    話数フォルダ一覧 ($($chNums.Count) 件):" -ForegroundColor White
                    foreach ($chNum in $chNums) {
                        $paths = $chNumToPaths[$chNum]
                        $dispNum = if ($chNumDisplay2.ContainsKey($chNum)) { $chNumDisplay2[$chNum] } else { $chNum }
                        if ($paths.Count -eq 1) {
                            Write-FlickFitHost "      [$dispNum] $(Split-Path $paths[0] -Leaf)" -ForegroundColor Gray
                        } else {
                            $names = @($paths | ForEach-Object { Split-Path $_ -Leaf }) -join ", "
                            Write-FlickFitHost "      [$dispNum] $names ($($paths.Count)件)" -ForegroundColor Gray
                        }
                    }
                    
                    $chNumToIndex = @{}
                    for ($i = 0; $i -lt $chNums.Count; $i++) {
                        $chNumToIndex[$chNums[$i].ToString()] = $i
                        # 整数の場合のみ整数キーも追加
                        if ($chNums[$i] -notmatch '\.') {
                            $chNumToIndex[[int]$chNums[$i]] = $i
                        }
                    }
                    $usedChapterIndices2 = [System.Collections.Generic.HashSet[int]]::new()
                    foreach ($v in ($pvStart..$pvEnd)) {
                        $remainingChNums = @($chNums | Where-Object { -not $usedChapterIndices2.Contains($chNumToIndex[$_.ToString()]) })
                        if ($remainingChNums.Count -eq 0) {
                            Write-FlickFitHost "`n    第 $v 巻: 振り分け可能な話数がありません" -ForegroundColor Yellow
                            continue
                        }
                        
                        # この巻に対応する表紙フォルダの画像を表示
                        if ($coverVolMap.ContainsKey($v)) {
                            $vCoverDir = $coverVolMap[$v]
                            $vCoverImgs = @(Get-ChildItem -LiteralPath $vCoverDir.FullName -File -ErrorAction SilentlyContinue | Where-Object { $script:ImageExtensions -contains $_.Extension.ToLower() } | Sort-Object { [regex]::Replace($_.Name, '\d+', { $args[0].Value.PadLeft(10,'0') }) })
                            if ($vCoverImgs.Count -gt 0) {
                                Write-FlickFitHost "`n    [第 $v 巻の表紙フォルダ: $($vCoverDir.Name)]" -ForegroundColor Magenta
                                foreach ($img in $vCoverImgs) {
                                    Write-FlickFitHost "      - $($img.Name)" -ForegroundColor DarkMagenta
                                }
                            }
                        } elseif ($genericCovers.Count -gt 0) {
                            $vCoverDir = $genericCovers[0]
                            $vCoverImgs = @(Get-ChildItem -LiteralPath $vCoverDir.FullName -File -ErrorAction SilentlyContinue | Where-Object { $script:ImageExtensions -contains $_.Extension.ToLower() } | Sort-Object { [regex]::Replace($_.Name, '\d+', { $args[0].Value.PadLeft(10,'0') }) })
                            if ($vCoverImgs.Count -gt 0) {
                                Write-FlickFitHost "`n    [表紙フォルダ: $($vCoverDir.Name)] (共通)" -ForegroundColor Magenta
                                foreach ($img in $vCoverImgs) {
                                    Write-FlickFitHost "      - $($img.Name)" -ForegroundColor DarkMagenta
                                }
                            }
                        }
                        
                        # 残りの話数を個別表示（範囲フォルダは "10-15" のように表示）
                        Write-FlickFitHost "`n    第 $v 巻に入れる話数（左の番号で指定）" -ForegroundColor Cyan
                        foreach ($chNum in $remainingChNums) {
                            $paths = $chNumToPaths[$chNum]
                            $dispNum = if ($chNumDisplay2.ContainsKey($chNum)) { $chNumDisplay2[$chNum] } else { $chNum }
                            if ($paths.Count -eq 1) {
                                Write-FlickFitHost "      [$dispNum] $(Split-Path $paths[0] -Leaf)" -ForegroundColor White
                            } else {
                                $names = @($paths | ForEach-Object { Split-Path $_ -Leaf }) -join ", "
                                Write-FlickFitHost "      [$dispNum] $names" -ForegroundColor White
                            }
                        }
                        Write-FlickFitHost "    $step2HintChapterNums" -ForegroundColor DarkGray
                        $rangeAns = Read-HostWithEsc "    話数（話数番号）"
                        if ([string]::IsNullOrWhiteSpace($rangeAns)) { continue }
                        $indices = Parse-ChapterInput $rangeAns $chNumToIndex
                        if ($indices.Count -eq 0) { continue }
                        $volMap[$v] = [System.Collections.Generic.List[string]]::new()
                        foreach ($idx in $indices) {
                            if (-not $usedChapterIndices2.Contains($idx)) {
                                $paths = $chNumToPaths[$chNums[$idx].ToString()]
                                foreach ($p in $paths) { $volMap[$v].Add($p) }
                                [void]$usedChapterIndices2.Add($idx)
                            }
                        }
                        $script:volMapFilledByChapterSplit[$v] = $true
                        [void]$script:volMapPreserveChapterOrder.Add([int]$v)
                        Write-FlickFitHost "    -> 第 $v 巻: $($volMap[$v].Count) フォルダ" -ForegroundColor Green
                    }
                }
                continue
            }

            # 第2段階: 採用したフォルダが1つで、かつそのフォルダ内に子フォルダがある場合
            $singlePath = $selectedCandidates[0].Path
            $hasSubDirs = @(Get-ChildItem -LiteralPath $singlePath -Directory -ErrorAction SilentlyContinue).Count -gt 0
            if ($selectedCandidates.Count -eq 1 -and $hasSubDirs) {
                Write-FlickFitHost "    このフォルダ内に子フォルダがあります。" -ForegroundColor Cyan
                Write-FlickFitHost "    [1] 親フォルダの画像のみ  [2] 子フォルダを含む（すべて使用）" -ForegroundColor DarkGray
                $subAns = (Read-HostWithEsc "  選択").Trim()
                if ($subAns -eq '1') {
                    $script:volDirectOnlyPaths.Add($singlePath)
                    Write-FlickFitHost "    -> 親フォルダの画像のみで採用" -ForegroundColor Green
                } else {
                    Write-FlickFitHost "    -> 子フォルダを含めて採用" -ForegroundColor Green
                }
                $volMap[$vn] = [System.Collections.Generic.List[string]]::new()
                $volMap[$vn].Add($singlePath)
                continue
            }

            # 第2段階: 複数フォルダ採用時（話数+カバー型）→ 話数で範囲指定できる
            # ただし「A」で全採用済みの場合は冗長な確認をスキップ
            if ($selectedCandidates.Count -ge 2 -and -not $wasAllSelected) {
                Write-FlickFitHost "    いま選んだ話数フォルダを、このまますべて第 $vn 巻に登録しますか？ それとも一覧番号でさらに絞りますか？" -ForegroundColor Cyan
                Write-FlickFitHost "    [1] すべて登録  [2] 番号で絞る（例: 1-$($selectedCandidates.Count) の連続範囲）" -ForegroundColor DarkGray
                $rangeAns = (Read-HostWithEsc "  話数（絞り込み）").Trim()
                if ($rangeAns -eq '2') {
                    Write-FlickFitHost "`n    [フォルダリスト] (番号順):" -ForegroundColor Cyan
                    for ($i = 0; $i -lt $selectedCandidates.Count; $i++) { Write-FlickFitHost ("      [{0}] {1}" -f ($i+1), (Split-Path $selectedCandidates[$i].Path -Leaf)) -ForegroundColor White }
                    $startAns = Read-HostWithEsc "    先頭番号 (1-$($selectedCandidates.Count))"
                    $endAns = Read-HostWithEsc "    最終番号 (1-$($selectedCandidates.Count))"
                    $s = 0; $e = 0
                    if ([int]::TryParse($startAns, [ref]$s) -and [int]::TryParse($endAns, [ref]$e) -and $s -ge 1 -and $s -le $selectedCandidates.Count -and $e -ge 1 -and $e -le $selectedCandidates.Count) {
                        $lo = [Math]::Min($s, $e); $hi = [Math]::Max($s, $e)
                        $volMap[$vn] = [System.Collections.Generic.List[string]]::new()
                        for ($i = $lo - 1; $i -lt $hi; $i++) { $volMap[$vn].Add($selectedCandidates[$i].Path) }
                        Write-FlickFitHost "    -> 番号 $lo-$hi を採用 ($($volMap[$vn].Count) フォルダ)" -ForegroundColor Green
                    } else {
                        Write-FlickFitHost "    -> 無効な入力のため全採用します。" -ForegroundColor Yellow
                        $volMap[$vn] = [System.Collections.Generic.List[string]]::new()
                        foreach ($c in $selectedCandidates) { $volMap[$vn].Add($c.Path) }
                    }
                } else {
                    $volMap[$vn] = [System.Collections.Generic.List[string]]::new()
                    foreach ($c in $selectedCandidates) { $volMap[$vn].Add($c.Path) }
                    Write-FlickFitHost "    -> 全採用 ($($selectedCandidates.Count) フォルダ)" -ForegroundColor Green
                }
            } elseif ($selectedCandidates.Count -ge 2 -and $wasAllSelected) {
                # 「A」で全採用済みの場合はそのまま採用
                $volMap[$vn] = [System.Collections.Generic.List[string]]::new()
                foreach ($c in $selectedCandidates) { $volMap[$vn].Add($c.Path) }
            } else {
                $volMap[$vn] = [System.Collections.Generic.List[string]]::new()
                foreach ($c in $selectedCandidates) { $volMap[$vn].Add($c.Path) }
            }
        }
        }
    }
    
    # 再開経路でも未初期化参照を起こさないようガード
    if (-not (Get-Variable -Name 'volMap' -ErrorAction SilentlyContinue) -or $null -eq $volMap) {
        if ((Get-Variable -Name 'volMap' -Scope Script -ErrorAction SilentlyContinue) -and $null -ne $script:volMap) {
            $volMap = $script:volMap
        } else {
            $volMap = @{}
        }
    }
    if (-not (Get-Variable -Name 'coverMap' -Scope Script -ErrorAction SilentlyContinue) -or $null -eq $script:coverMap) { $script:coverMap = @{} }
    if (-not (Get-Variable -Name 'detectedCoverFolders' -Scope Script -ErrorAction SilentlyContinue) -or $null -eq $script:detectedCoverFolders) { $script:detectedCoverFolders = [System.Collections.Generic.List[PSObject]]::new() }
    if (-not (Get-Variable -Name 'specialItems' -ErrorAction SilentlyContinue) -or $null -eq $specialItems) { $specialItems = [System.Collections.Generic.List[PSObject]]::new() }
    if (-not (Get-Variable -Name 'allLeaves' -ErrorAction SilentlyContinue) -or $null -eq $allLeaves) { $allLeaves = [System.Collections.Generic.List[PSObject]]::new() }
    if (-not (Get-Variable -Name 'TitleCandidates' -Scope Script -ErrorAction SilentlyContinue) -or $null -eq $script:TitleCandidates) { $script:TitleCandidates = @() }
    if (-not (Get-Variable -Name 'BestRawName' -Scope Script -ErrorAction SilentlyContinue) -or $null -eq $script:BestRawName) { $script:BestRawName = '' }
    if (-not (Get-Variable -Name 'CandidateNames' -Scope Script -ErrorAction SilentlyContinue) -or $null -eq $script:CandidateNames) { $script:CandidateNames = [System.Collections.Generic.HashSet[string]]::new([System.StringComparer]::OrdinalIgnoreCase) }
    if (-not (Get-Variable -Name 'tempVolMap' -ErrorAction SilentlyContinue) -or $null -eq $tempVolMap) { $tempVolMap = @{} }
    if (-not (Get-Variable -Name 'rangeMap' -ErrorAction SilentlyContinue) -or $null -eq $rangeMap) { $rangeMap = @{} }
    if (-not (Get-Variable -Name 'unknowns' -ErrorAction SilentlyContinue) -or $null -eq $unknowns) { $unknowns = [System.Collections.Generic.List[PSObject]]::new() }

    # 選択されなかった巻のみ tempVolMap を volMap に反映（選択済みは上書きしない）
    foreach ($vn in ($tempVolMap.Keys | Sort-Object)) {
        if (-not $volMap.ContainsKey($vn)) {
            $volMap[$vn] = [System.Collections.Generic.List[string]]::new()
            foreach ($item in $tempVolMap[$vn]) { $volMap[$vn].Add($item.Path) }
        }
    }
    if (-not (Get-Variable -Name 'volDirectOnlyPaths' -Scope Script -ErrorAction SilentlyContinue)) {
        $script:volDirectOnlyPaths = [System.Collections.Generic.List[string]]::new()
    }
    if (-not (Get-Variable -Name 'excludedSubfolderPaths' -Scope Script -ErrorAction SilentlyContinue)) {
        $script:excludedSubfolderPaths = [System.Collections.Generic.List[string]]::new()
    }
    if (-not (Get-Variable -Name 'processedChapterParentPaths' -Scope Script -ErrorAction SilentlyContinue)) {
        $script:processedChapterParentPaths = @{}
    }
    
    # 2. 明示的なcoverフォルダがない巻について、ユーザーに聞く
    # coverMapに登録されていない巻で、チャプター構造（複数フォルダ）を持つ巻を探す
    $volsNeedingCover = [System.Collections.Generic.List[int]]::new()
    foreach ($vn in ($volMap.Keys | Sort-Object)) {
        if (-not (Test-FlickFitCoverMapHasVol $script:coverMap $vn)) {
            # この巻が複数フォルダから構成されているか確認（チャプター構造）
            if ($volMap[$vn].Count -gt 1) {
                # 話数振り分け用の表紙フローは「チャプター相当の複数フォルダ」向け。候補がすべて第X巻等の巻フォルダ名だけなら同一巻の別ソース併記であり、ここでは扱わない（巻数選択と矛盾する誤案内防止）
                $allVolumeNamedLeaves = $true
                foreach ($pp in $volMap[$vn]) {
                    $leaf = Split-Path $pp -Leaf
                    $ok = $leaf -match '第\s*0*\d{1,3}\s*巻' -or $leaf -match '(?i)(?:^|[\s\-_])(?:v|vol\.?)\s*0*\d{1,3}[sSwWbBfF]?\s*$'
                    if (-not $ok) { $allVolumeNamedLeaves = $false; break }
                }
                if (-not $allVolumeNamedLeaves) { $volsNeedingCover.Add($vn) }
            }
        }
    }
    
    if ($volsNeedingCover.Count -gt 0) {
        Write-FlickFitHost "`n[表紙が未設定の巻があります]:" -ForegroundColor Yellow
        foreach ($vn in ($volsNeedingCover | Sort-Object)) {
            Write-FlickFitHost "  - 第 $vn 巻 (チャプター構成: $($volMap[$vn].Count) フォルダ)" -ForegroundColor White
        }
        
        # 対象巻の親フォルダを収集
        $parentPaths = [System.Collections.Generic.List[string]]::new()
        foreach ($vn in $volsNeedingCover) {
            foreach ($p in $volMap[$vn]) {
                $parent = Split-Path $p -Parent
                if (-not $parentPaths.Contains($parent)) { $parentPaths.Add($parent) }
            }
        }
        
        foreach ($parentPath in $parentPaths) {
            # 親に cover がある場合は表紙・話数の一覧を親直下全体に合わせる（ch360-391 内だけに閉じない）
            $fullListingAtGp = $false
            # 話数フォルダは 277 のような名前も 300_files 形式もあり得る → _files を除外しない（表紙確認は一覧で選ばせる）
            $subDirs = @(Get-ChildItem -LiteralPath $parentPath -Directory -ErrorAction SilentlyContinue | 
                Where-Object { $_.Name -ne '単ページ' })
            # 表紙候補を先に（cover29 等が話数フォルダ番号のあとに埋もれないように）
            $subDirs = @($subDirs | Sort-Object @{ Expression = { if ($_.Name -match $script:CoverFolderNameLikeRegex) { 0 } else { 1 } }; Ascending = $true }, @{ Expression = { [regex]::Replace($_.Name, '\d+', { $args[0].Value.PadLeft(10,'0') }) }; Ascending = $true })
            # バンドル直下(ch360-391等)のとき cover は一つ上の階層に並ぶことがある（STEP2 のチャプター選択時と同様に親をマージ）
            $subDirFromOneUp = [System.Collections.Generic.HashSet[string]]::new([System.StringComparer]::OrdinalIgnoreCase)
            $normPPc = try { [System.IO.Path]::GetFullPath($parentPath).TrimEnd('\') } catch { $parentPath.TrimEnd('\') }
            $gpForCover = Split-Path $parentPath -Parent
            $normGPc = if ($gpForCover -and (Test-Path -LiteralPath $gpForCover)) { try { [System.IO.Path]::GetFullPath($gpForCover).TrimEnd('\') } catch { $null } } else { $null }
            if ($normGPc -and $normGPc -ne $normPPc) {
                $gpCoverOnly = @(Get-ChildItem -LiteralPath $gpForCover -Directory -ErrorAction SilentlyContinue | Where-Object {
                    $_.Name -ne '単ページ' -and $_.Name -match $script:CoverFolderNameLikeRegex
                })
                if ($script:detectedCoverFolders.Count -gt 0) {
                    foreach ($dcf in $script:detectedCoverFolders) {
                        $dp = Split-Path $dcf.Path -Parent
                        try { $ndp = [System.IO.Path]::GetFullPath($dp).TrimEnd('\') } catch { $ndp = $null }
                        if ($ndp -ne $normGPc) { continue }
                        $it = Get-Item -LiteralPath $dcf.Path -ErrorAction SilentlyContinue
                        if ($it -and $it.PSIsContainer) { $gpCoverOnly += $it }
                    }
                }
                $coverByPath = @{}
                foreach ($x in $subDirs) {
                    if (-not $x) { continue }
                    try { $ck = [System.IO.Path]::GetFullPath($x.FullName).TrimEnd('\') } catch { continue }
                    $coverByPath[$ck] = $x
                }
                foreach ($x in $gpCoverOnly) {
                    if (-not $x) { continue }
                    try { $ck = [System.IO.Path]::GetFullPath($x.FullName).TrimEnd('\') } catch { continue }
                    if (-not $coverByPath.ContainsKey($ck)) {
                        $coverByPath[$ck] = $x
                        [void]$subDirFromOneUp.Add($ck)
                    }
                }
                $subDirs = @($coverByPath.Values)
                $subDirs = @($subDirs | Sort-Object @{ Expression = { if ($_.Name -match $script:CoverFolderNameLikeRegex) { 0 } else { 1 } }; Ascending = $true }, @{ Expression = { [regex]::Replace($_.Name, '\d+', { $args[0].Value.PadLeft(10,'0') }) }; Ascending = $true })
                if ($subDirFromOneUp.Count -gt 0) {
                    $fullListingAtGp = $true
                    $subDirs = @(Get-ChildItem -LiteralPath $gpForCover -Directory -ErrorAction SilentlyContinue | Where-Object { $_.Name -ne '単ページ' })
                    $subDirs = @($subDirs | Sort-Object @{ Expression = { if ($_.Name -match $script:CoverFolderNameLikeRegex) { 0 } else { 1 } }; Ascending = $true }, @{ Expression = { [regex]::Replace($_.Name, '\d+', { $args[0].Value.PadLeft(10,'0') }) }; Ascending = $true })
                    [void]$subDirFromOneUp.Clear()
                }
            }
            
            # この親に属する巻（範囲の場合は複数になる）
            $targetVolsForParent = @($volsNeedingCover | Where-Object { 
                $volMap[$_] | Where-Object { (Split-Path $_ -Parent) -eq $parentPath }
            } | Sort-Object)
            if ($targetVolsForParent.Count -eq 0) { continue }
            # 同一バンドルで親が二つ（例: ch360-391 配下と v37-42s 直下）に分かれると parentPaths が二重になり、
            # 1周目で表紙・STEP2 済みでも 2周目が [表紙画像フォルダの確認] だけ再走する。全巻表紙済みならこの親はスキップ。
            $allTargetVolsAlreadyHaveCover = $true
            foreach ($tv in $targetVolsForParent) {
                if (-not (Test-FlickFitCoverMapHasVol $script:coverMap $tv)) { $allTargetVolsAlreadyHaveCover = $false; break }
            }
            if ($allTargetVolsAlreadyHaveCover) { continue }
            
            # 巻数振り分けモード：候補がすべて「第X巻」等の巻フォルダの場合は表紙確認をスキップ（表紙は巻フォルダ内にある想定）
            $pathsUnderParent = @($targetVolsForParent | ForEach-Object { $volMap[$_] } | Where-Object { (Split-Path $_ -Parent) -eq $parentPath } | ForEach-Object { Split-Path $_ -Leaf })
            $allVolumeNamed = @($pathsUnderParent | ForEach-Object { $_ -match '第\s*0*\d{1,3}\s*巻' -or $_ -match '(?i)(?:^|[\s\-_])(?:v|vol\.?)\s*0*\d{1,3}[sSwWbBfF]?\s*$' } | Where-Object { -not $_ }).Count -eq 0
            if ($allVolumeNamed -and $pathsUnderParent.Count -gt 0) { continue }
            
            if ($subDirs.Count -gt 0) {
                if ($fullListingAtGp) {
                    $volsNeedingCoverHdr = "$(Split-Path $gpForCover -Leaf) 直下（表紙・話数・同階層の全フォルダ）"
                } else {
                    $volsNeedingCoverHdr = "$(Split-Path $parentPath -Leaf) 内"
                    if ($subDirFromOneUp.Count -gt 0) {
                        $volsNeedingCoverHdr = "$(Split-Path $parentPath -Leaf) 内 + 親フォルダ ($(Split-Path $gpForCover -Leaf)) の表紙候補"
                    }
                }
                $volHdrForCover = if ($targetVolsForParent.Count -eq 1) {
                    "第 $($targetVolsForParent[0]) 巻 "
                } elseif ($targetVolsForParent.Count -gt 1) {
                    "第 $($targetVolsForParent -join '・') 巻 "
                } else { '' }
                if ($volHdrForCover) {
                    Write-FlickFitHost "`n[表紙画像フォルダの確認] $volHdrForCover($volsNeedingCoverHdr):" -ForegroundColor Cyan
                } else {
                    Write-FlickFitHost "`n[表紙画像フォルダの確認] ($volsNeedingCoverHdr):" -ForegroundColor Cyan
                }
                Write-FlickFitHost "    表紙画像が含まれているフォルダはありますか？" -ForegroundColor Yellow
                if ($fullListingAtGp) {
                    Write-FlickFitHost "    ※ 親フォルダ直下の一覧です（ch360-391 内だけでなく Chapter 等の同階層も含みます）" -ForegroundColor DarkGray
                } elseif ($subDirFromOneUp.Count -gt 0) {
                    Write-FlickFitHost "    ※ (1階層上) は親フォルダ直下のフォルダです（cover 等が同階層にあるとき）" -ForegroundColor DarkGray
                }
                
                # 各フォルダの情報を表示（表紙フォルダ候補には★マーク）
                for ($i = 0; $i -lt $subDirs.Count; $i++) {
                    $dirName = $subDirs[$i].Name
                    $imgCount = @(Get-ChildItem -LiteralPath $subDirs[$i].FullName -File -ErrorAction SilentlyContinue | 
                        Where-Object { $script:ImageExtensions -contains $_.Extension.ToLower() }).Count
                    $isCoverCandidate = $dirName -match $script:CoverFolderNameLikeRegex
                    $fpOneUp = $null
                    try { $fpOneUp = [System.IO.Path]::GetFullPath($subDirs[$i].FullName).TrimEnd('\') } catch { }
                    $oneUpSuffix = if ($fpOneUp -and $subDirFromOneUp.Contains($fpOneUp)) { ' (1階層上)' } else { '' }
                    if ($isCoverCandidate) {
                        Write-FlickFitHost ("    [{0}] {1}  (画像 {2}枚) ★表紙候補{3}" -f ($i+1), $dirName, $imgCount, $oneUpSuffix) -ForegroundColor Green
                    } else {
                        Write-FlickFitHost ("    [{0}] {1}  (画像 {2}枚){3}" -f ($i+1), $dirName, $imgCount, $oneUpSuffix) -ForegroundColor White
                    }
                }
                Write-FlickFitHost "    [F] フォルダを開いて確認（F+番号）  [空Enter] 先頭の★表紙候補を自動選択（無いときはスキップ）" -ForegroundColor DarkGray
                Write-FlickFitHost "    ※ 複数枚のフォルダは、選択後に「フォルダ全体を表紙」か「番号で選ぶ」かを選べます" -ForegroundColor DarkGray
                
                $coverFolderAns = Read-HostWithEsc "  選択（番号 または F+番号で開く）"
                
                # 「0」だけの入力は数字のゼロなので注意を促して再入力
                while ($coverFolderAns -eq '0') {
                    Write-FlickFitHost "    [注意] フォルダ番号は 1 からです。スキップするにはそのまま Enter を押してください。" -ForegroundColor Yellow
                    $coverFolderAns = Read-HostWithEsc "  選択（番号 または F+番号で開く）"
                }
                # 空Enter: 一覧は表紙候補優先ソート済み → 先頭が★なら [1] 相当として自動選択
                if ([string]::IsNullOrWhiteSpace($coverFolderAns)) {
                    if ($subDirs.Count -gt 0 -and ($subDirs[0].Name -match $script:CoverFolderNameLikeRegex)) {
                        Write-FlickFitHost "    -> 空Enter: 表紙候補「$($subDirs[0].Name)」を自動選択します" -ForegroundColor DarkCyan
                        $coverFolderAns = '1'
                    }
                }
                # 「F」で始まる場合はフォルダを開く（英字エフ。数字の0ではない）
                if ($coverFolderAns -match '^[Ff]\s*(\d+)$') {
                    $openIdx = [int]$Matches[1] - 1
                    if ($openIdx -ge 0 -and $openIdx -lt $subDirs.Count) {
                        Write-FlickFitHost "    [フォルダを開いています: $($subDirs[$openIdx].Name)]" -ForegroundColor Gray
                        try { Start-Process "explorer.exe" -ArgumentList $subDirs[$openIdx].FullName } catch {}
                        $coverFolderAns = Read-HostWithEsc "  表紙フォルダの番号（空Enterでスキップ）"
                    }
                }
                if ($coverFolderAns -match '^\d+$') {
                    $coverFolderIdx = [int]$coverFolderAns - 1
                    if ($coverFolderIdx -ge 0 -and $coverFolderIdx -lt $subDirs.Count) {
                        $selectedCoverFolder = $subDirs[$coverFolderIdx].FullName
                        $imgs = @(Get-ChildItem -LiteralPath $selectedCoverFolder -File -ErrorAction SilentlyContinue | 
                            Where-Object { $script:ImageExtensions -contains $_.Extension.ToLower() } |
                            Sort-Object { [regex]::Replace($_.Name, '\d+', { $args[0].Value.PadLeft(10,'0') }) })
                        Write-FlickFitHost "    -> 選択: $($subDirs[$coverFolderIdx].Name) ($($imgs.Count) 枚)" -ForegroundColor DarkCyan
                        
                        # 選択したフォルダをエクスプローラーで開く
                        Write-FlickFitHost "    [フォルダを開いています...]" -ForegroundColor Gray
                        try { Start-Process "explorer.exe" -ArgumentList $selectedCoverFolder } catch {}
                        
                        # 表紙候補を表示
                        Write-FlickFitHost "`n  [表紙候補]:" -ForegroundColor Yellow
                        for ($i = 0; $i -lt $imgs.Count; $i++) { 
                            Write-FlickFitHost ("    [{0}] {1}" -f ($i+1), $imgs[$i].Name) -ForegroundColor DarkCyan 
                        }
                        
                        # 複数枚のときは「フォルダ丸ごと表紙」を表紙フローとして明示（話数側だけフォルダ単位になる裏技に寄せない）
                        $coverUseWholeFolder = $false
                        if ($imgs.Count -gt 1) {
                            Write-FlickFitHost "`n  このフォルダの表紙の扱い:" -ForegroundColor Yellow
                            Write-FlickFitHost "    [1] 番号で選ぶ（次の段で 1-3 や 1,2,5 / A など）" -ForegroundColor DarkGray
                            Write-FlickFitHost "    [2] フォルダ内の画像をすべて表紙とする（全 $($imgs.Count) 枚）" -ForegroundColor DarkGray
                            do {
                                $coverModeAns = (Read-HostWithEsc "  選択（1=番号で選ぶ / 2=全採用 / 空Enter=1）").Trim()
                                if ($coverModeAns -in @('', '1', '2')) { break }
                                Write-FlickFitHost "  入力形式が正しくありません。ここでは 1 か 2 か 空Enter のみです（1-3 や A は、直後の「番号で選択」で入れてください）" -ForegroundColor Yellow
                            } while ($true)
                            if ($coverModeAns -eq '2') { $coverUseWholeFolder = $true }
                        }
                        
                        # この親フォルダに属する巻のみ選択
                        $targetVols = @($volsNeedingCover | Where-Object { 
                            $volMap[$_] | Where-Object { (Split-Path $_ -Parent) -eq $parentPath }
                        } | Sort-Object)
                        
                        foreach ($vn in $targetVols) {
                            if ($coverUseWholeFolder) {
                                $selectedPaths = [System.Collections.Generic.List[string]]::new()
                                foreach ($img in $imgs) { $selectedPaths.Add($img.FullName) }
                                $script:coverMap[$vn] = @($selectedPaths)
                                Write-FlickFitHost "`n  -> 第 $vn 巻の表紙: フォルダ全体を採用 ($($imgs.Count) 枚)" -ForegroundColor DarkCyan
                            } else {
                                Write-FlickFitHost "`n  -> 第 $vn 巻の表紙: 番号で選択 (例: 1-3 または 1,2,5 / A で全採用 / 空Enterでスキップ)" -ForegroundColor Cyan
                                $idxAns = (Read-HostWithEsc "  選択").Trim().ToUpper()
                                if ($idxAns) {
                                    $selectedPaths = [System.Collections.Generic.List[string]]::new()
                                    if ($idxAns -eq 'A') {
                                        foreach ($img in $imgs) { $selectedPaths.Add($img.FullName) }
                                        Write-FlickFitHost "       -> 全採用 ($($imgs.Count) 枚)" -ForegroundColor DarkCyan
                                    } else {
                                        $parsedIdx = @(Parse-RangeInput $idxAns $imgs.Count)
                                        if ($parsedIdx.Count -gt 0) {
                                            foreach ($idx in $parsedIdx) { $selectedPaths.Add($imgs[$idx].FullName) }
                                            Write-FlickFitHost "       -> 選択: $($parsedIdx.Count) 枚" -ForegroundColor DarkCyan
                                        }
                                    }
                                    if ($selectedPaths.Count -gt 0) { $script:coverMap[$vn] = @($selectedPaths) }
                                }
                            }
                        }
                    }
                }
                
                # 表紙画像まで終えたら、この親の下で話数振り分け（同一親に1巻だけの v29s でも実施。以前は -gt 1 のため単一巻親では話数が飛び次の親の表紙へ進んでいた）
                # 配下がすべて「第X巻」形式の巻フォルダだけのときは話数振り分け不要のためスキップ
                if ($targetVolsForParent.Count -ge 1) {
                    $chapterPathsList = [System.Collections.Generic.List[string]]::new()
                    foreach ($tv in $targetVolsForParent) {
                        foreach ($p in $volMap[$tv]) {
                            $par = Split-Path $p -Parent
                            if ($par -eq $parentPath -or ($fullListingAtGp -and $gpForCover -and $par -eq $gpForCover)) {
                                $chapterPathsList.Add($p)
                            }
                        }
                    }
                    if ($fullListingAtGp -and $gpForCover) {
                        foreach ($d in @(Get-ChildItem -LiteralPath $gpForCover -Directory -ErrorAction SilentlyContinue)) {
                            if ($d.Name -eq '単ページ') { continue }
                            if ($d.Name -match $script:CoverFolderNameLikeRegex) { continue }
                            if ($d.FullName -eq $parentPath) { continue }
                            try { $dnorm = [System.IO.Path]::GetFullPath($d.FullName).TrimEnd('\') } catch { continue }
                            $inVolMap = $false
                            foreach ($tv in $targetVolsForParent) {
                                foreach ($pp in $volMap[$tv]) {
                                    try { $pn = [System.IO.Path]::GetFullPath($pp).TrimEnd('\') } catch { $pn = $pp }
                                    if ($pn -eq $dnorm -or $pn -like "$dnorm\*") { $inVolMap = $true; break }
                                }
                                if ($inVolMap) { break }
                            }
                            if (-not $inVolMap) {
                                $imgCx = @(Get-ChildItem -LiteralPath $d.FullName -File -ErrorAction SilentlyContinue | Where-Object { $script:ImageExtensions -contains $_.Extension.ToLower() }).Count
                                if ($imgCx -gt 0) { $chapterPathsList.Add($d.FullName) }
                            }
                        }
                    }
                    $chapterPaths = @(
                        $chapterPathsList | Select-Object -Unique | Sort-Object `
                            { Get-ChapterNumber (Split-Path $_ -Leaf) }, `
                            { Get-Step2LeafPathOrderRank -Path $_ }, `
                            { [regex]::Replace((Split-Path $_ -Leaf), '\d+', { $args[0].Value.PadLeft(10,'0') }) }
                    )
                    $chapterPaths = @($chapterPaths | Where-Object { (Split-Path $_ -Leaf) -notmatch $script:CoverFolderNameLikeRegex })
                    # 表紙で1枚以上採用したフォルダは本文・話数振り分け候補から除外（画像パスは coverMap、候補はフォルダ単位のため未連携だった）
                    $coverLeafNormByVol = @{}
                    foreach ($tv in $targetVolsForParent) {
                        $hs = [System.Collections.Generic.HashSet[string]]::new()
                        if (Test-FlickFitCoverMapHasVol $script:coverMap $tv) {
                            foreach ($cp in @($script:coverMap[$tv])) {
                                if (-not $cp) { continue }
                                try {
                                    $leafDir = [System.IO.Path]::GetFullPath((Split-Path $cp -Parent)).TrimEnd('\')
                                    [void]$hs.Add($leafDir)
                                } catch { }
                            }
                        }
                        $coverLeafNormByVol[$tv] = $hs
                    }
                    $allCoverLeafNorms = [System.Collections.Generic.HashSet[string]]::new()
                    foreach ($tv in $targetVolsForParent) {
                        foreach ($x in $coverLeafNormByVol[$tv]) { [void]$allCoverLeafNorms.Add($x) }
                    }
                    $chapterPaths = @($chapterPaths | Where-Object {
                        $leafNorm = $null
                        try { $leafNorm = [System.IO.Path]::GetFullPath($_).TrimEnd('\') } catch { $leafNorm = $_.TrimEnd('\') }
                        -not $allCoverLeafNorms.Contains($leafNorm)
                    })
                    $leavesAreVolumeFolders = @($chapterPaths | ForEach-Object { $leaf = Split-Path $_ -Leaf; $leaf -match '第\s*0*\d{1,3}\s*巻' -or $leaf -match '(?i)(?:^|[\s\-_])(?:v|vol\.?)\s*0*\d{1,3}[sSwWbBfF]?\s*$' } | Where-Object { -not $_ }).Count -eq 0
                    # 話数振り分けが無くても、表紙で使ったフォルダを volMap から外す処理で参照する
                    $assignedByVol = @{}
                    foreach ($v in $targetVolsForParent) { $assignedByVol[$v] = [System.Collections.Generic.List[string]]::new() }
                    if ($chapterPaths.Count -gt 0 -and -not $leavesAreVolumeFolders) {
                        $step2ParentLabel = if ($fullListingAtGp) { "$(Split-Path $gpForCover -Leaf) 直下" } else { "$(Split-Path $parentPath -Leaf)" }
                        Write-FlickFitHost "`n  [STEP2] 話数の振り分け: $step2ParentLabel → 第 $($targetVolsForParent -join '・') 巻" -ForegroundColor Cyan
                        Write-FlickFitHost "    各巻に、まだ割り当てていないフォルダを、一覧の連番 [1]..[N] で指定します。" -ForegroundColor Yellow
                        Write-FlickFitHost "    表示番号（1..N）: 列挙・範囲（例: 1,2  1-3）  空Enter: スキップ確認  [B] 前の巻  [R] この巻の表示をやり直し" -ForegroundColor DarkGray
                        $cpUi = 1
                        foreach ($p in $chapterPaths) {
                            $leaf = Split-Path $p -Leaf
                            $bookParent = Split-Path (Split-Path $p -Parent) -Leaf
                            $imgC = @(Get-ChildItem -LiteralPath $p -File -ErrorAction SilentlyContinue | Where-Object { $script:ImageExtensions -contains $_.Extension.ToLower() }).Count
                            $leafHint = Get-Step2ChapterLeafHint $leaf
                            $fcList = if ($leafHint) { 'DarkYellow' } else { 'White' }
                            Write-FlickFitHost ("    [{0}] {1} / {2}   ({3}枚){4}" -f $cpUi, $bookParent, $leaf, $imgC, $leafHint) -ForegroundColor $fcList
                            $cpUi++
                        }
                        # 同じ話数フォルダが複数巻に重複割り当てされないよう、未割り当ての話数だけを各巻で受け付ける
                        $assignedIndices = [System.Collections.Generic.HashSet[int]]::new()
                        $assignedIndicesByVol = @{}
                        foreach ($v in $targetVolsForParent) { $assignedIndicesByVol[$v] = [System.Collections.Generic.List[int]]::new() }
                        $volListSorted = @($targetVolsForParent | Sort-Object)
                        $vnIdx = 0
                        while ($vnIdx -lt $volListSorted.Count) {
                            $vn = $volListSorted[$vnIdx]
                            $availIdxOrder = [System.Collections.Generic.List[int]]::new()
                            for ($ci = 0; $ci -lt $chapterPaths.Count; $ci++) {
                                if ($assignedIndices.Contains($ci)) { continue }
                                [void]$availIdxOrder.Add($ci)
                            }
                            if ($availIdxOrder.Count -eq 0) {
                                Write-FlickFitHost "  → 第 $vn 巻: 割り当て可能な話数は残っていません" -ForegroundColor DarkGray
                                $vnIdx++
                                continue
                            }
                            $advanceVol = $true
                            $uiToChapterPathIndex = @($availIdxOrder)
                            :inputLoop while ($true) {
                                Write-FlickFitHost ""
                                Write-FlickFitHost "  → 第 $vn 巻に入れるフォルダ（未割り当てのみ）" -ForegroundColor Cyan
                                Write-FlickFitHost "  未割り当て候補:" -ForegroundColor Gray
                                $ui = 1
                                foreach ($ci in $availIdxOrder) {
                                    $pth = $chapterPaths[$ci]
                                    $leaf = Split-Path $pth -Leaf
                                    $bookParent = Split-Path (Split-Path $pth -Parent) -Leaf
                                    $imgC = @(Get-ChildItem -LiteralPath $pth -File -ErrorAction SilentlyContinue | Where-Object { $script:ImageExtensions -contains $_.Extension.ToLower() }).Count
                                    $rowHint = Get-Step2ChapterLeafHint $leaf
                                    $fcRow = if ($rowHint) { 'DarkYellow' } else { 'White' }
                                    Write-FlickFitHost ("    [{0}] {1} / {2}   ({3}枚){4}" -f $ui, $bookParent, $leaf, $imgC, $rowHint) -ForegroundColor $fcRow
                                    $ui++
                                }
                                $bBack = if ($vnIdx -gt 0) { '  [B] 前の巻へ' } else { '' }
                                $numAns = (Read-HostWithEsc "    表示番号（1-$($availIdxOrder.Count)）: 列挙・範囲  空Enter: スキップ確認  [R] やり直し$bBack").Trim()
                                if ($numAns -match '^[Bb]$') {
                                    if ($vnIdx -eq 0) {
                                        Write-FlickFitHost "       -> これより前の巻はありません" -ForegroundColor Yellow
                                        continue inputLoop
                                    }
                                    $prevVn = $volListSorted[$vnIdx - 1]
                                    foreach ($ix in @($assignedIndicesByVol[$prevVn])) {
                                        [void]$assignedIndices.Remove($ix)
                                    }
                                    $assignedIndicesByVol[$prevVn].Clear()
                                    $assignedByVol[$prevVn] = [System.Collections.Generic.List[string]]::new()
                                    $vnIdx--
                                    Write-FlickFitHost "       -> 第 $prevVn 巻の割り当てを取り消しました。もう一度入力してください。" -ForegroundColor Yellow
                                    $advanceVol = $false
                                    break
                                }
                                if ($numAns -match '^[Rr]$') {
                                    continue inputLoop
                                }
                                if ([string]::IsNullOrWhiteSpace($numAns)) {
                                    $c2 = (Read-HostWithEsc "    この巻のフォルダ割り当てをスキップします。 [Enter=確定 / R=この巻を再入力 / B=前の巻へ]").Trim()
                                    if ($c2 -match '^[Rr]$') { continue inputLoop }
                                    if ($c2 -match '^[Bb]$') {
                                        if ($vnIdx -eq 0) {
                                            Write-FlickFitHost "       -> これより前の巻はありません" -ForegroundColor Yellow
                                            continue inputLoop
                                        }
                                        $prevVn = $volListSorted[$vnIdx - 1]
                                        foreach ($ix in @($assignedIndicesByVol[$prevVn])) {
                                            [void]$assignedIndices.Remove($ix)
                                        }
                                        $assignedIndicesByVol[$prevVn].Clear()
                                        $assignedByVol[$prevVn] = [System.Collections.Generic.List[string]]::new()
                                        $vnIdx--
                                        Write-FlickFitHost "       -> 第 $prevVn 巻の割り当てを取り消しました。もう一度入力してください。" -ForegroundColor Yellow
                                        $advanceVol = $false
                                        break
                                    }
                                    if (-not [string]::IsNullOrWhiteSpace($c2)) {
                                        Write-FlickFitHost "       -> [Enter] [R] [B] のみ有効です" -ForegroundColor Yellow
                                        continue inputLoop
                                    }
                                    Write-FlickFitHost "       -> 第 $vn 巻: スキップ（親直下の volMap を維持）" -ForegroundColor DarkGray
                                    break
                                }
                                $indices = @(Parse-Step2UiFolderSelection $numAns $uiToChapterPathIndex)
                                if ($indices.Count -eq 0) {
                                    Write-FlickFitHost "       -> 入力が無効です（1-$($availIdxOrder.Count) の列挙・範囲（例: 1,2  1-3））" -ForegroundColor Yellow
                                    continue inputLoop
                                }
                                foreach ($idx in $indices) {
                                    $assignedByVol[$vn].Add($chapterPaths[$idx])
                                    [void]$assignedIndices.Add([int]$idx)
                                }
                                $assignedIndicesByVol[$vn] = [System.Collections.Generic.List[int]]::new()
                                foreach ($idx in $indices) { $assignedIndicesByVol[$vn].Add([int]$idx) }
                                Write-FlickFitHost "       -> $($indices.Count) フォルダを第 $vn 巻に割り当て" -ForegroundColor DarkCyan
                                break
                            }
                            if ($advanceVol) { $vnIdx++ }
                        }
                    }
                    foreach ($v in $targetVolsForParent) {
                        $rest = [System.Collections.Generic.List[string]]::new()
                        foreach ($p in $volMap[$v]) {
                            $pp = Split-Path $p -Parent
                            $underCh = ($pp -eq $parentPath) -or ($fullListingAtGp -and $gpForCover -and $pp -eq $gpForCover)
                            if (-not $underCh) { $rest.Add($p) }
                        }
                        if ($assignedByVol[$v].Count -gt 0) {
                            foreach ($p in $assignedByVol[$v]) { $rest.Add($p) }
                        } else {
                            # 空Enter／無効入力時は親直下の従来割り当てを維持（volMap から落ちない）
                            # ただし表紙専用にしたフォルダは本文に含めない（coverMap の画像親フォルダと一致するパス）
                            foreach ($p in $volMap[$v]) {
                                $pp = Split-Path $p -Parent
                                $underCh = ($pp -eq $parentPath) -or ($fullListingAtGp -and $gpForCover -and $pp -eq $gpForCover)
                                if (-not $underCh) { continue }
                                $pn = $null
                                try { $pn = [System.IO.Path]::GetFullPath($p).TrimEnd('\') } catch { $pn = $p.TrimEnd('\') }
                                if ($coverLeafNormByVol[$v] -and $coverLeafNormByVol[$v].Contains($pn)) { continue }
                                $rest.Add($p)
                            }
                        }
                        $volMap[$v] = $rest
                        # volsNeedingCover で処理した巻は「処理済み」とマーク（後段の外部ループで再エントリーされないよう）
                        $script:volMapFilledByChapterSplit[$v] = $true
                        if ($assignedByVol[$v].Count -gt 0) { [void]$script:volMapPreserveChapterOrder.Add([int]$v) }
                    }
                }
            }
        }
    }

    foreach ($rangeKey in ($rangeMap.Keys | Sort-Object { $rangeMap[$_].Start })) {
        $r = $rangeMap[$rangeKey]
        $leaves = @($r.Leaves | Sort-Object { [regex]::Replace($_, '\d+', { $args[0].Value.PadLeft(10,'0') }) })
        
        # 親フォルダを特定してcoverフォルダを探す
        $parentFolder = if ($leaves.Count -gt 0) { Split-Path $leaves[0] -Parent } else { $null }
        $coverFolder = $null
        $coverImages = @()
        
        if ($parentFolder) {
            $coverFolder = Get-ChildItem -LiteralPath $parentFolder -Directory -ErrorAction SilentlyContinue | 
                Where-Object { $_.Name -match $script:CoverFolderNameLikeRegex } | Select-Object -First 1
            if ($coverFolder) {
                $coverImages = @(Get-ChildItem -LiteralPath $coverFolder.FullName -File -ErrorAction SilentlyContinue | 
                    Where-Object { $script:ImageExtensions -contains $_.Extension.ToLower() } |
                    Sort-Object { [regex]::Replace($_.Name, '\d+', { $args[0].Value.PadLeft(10,'0') }) })
            }
        }
        
        Write-FlickFitHost "`n[複数巻まとめフォルダ]: $rangeKey" -ForegroundColor Cyan
        
        # coverフォルダの表紙候補を表示
        if ($coverImages.Count -gt 0) {
            Write-FlickFitHost "  [表紙候補] coverフォルダ: $($coverImages.Count) 枚" -ForegroundColor Yellow
            for ($i = 0; $i -lt $coverImages.Count; $i++) { 
                Write-FlickFitHost ("    [{0}] {1}" -f ($i+1), $coverImages[$i].Name) -ForegroundColor DarkCyan 
            }
            
            # coverフォルダをエクスプローラーで開く
            Write-FlickFitHost "  [coverフォルダを開いています...]" -ForegroundColor Gray
            try { Start-Process "explorer.exe" -ArgumentList $coverFolder.FullName } catch {}
            Write-FlickFitHost ""
        }
        
        # チャプターフォルダを表示
        Write-FlickFitHost "  [チャプター]:" -ForegroundColor Gray
        for ($i = 0; $i -lt $leaves.Count; $i++) { Write-FlickFitHost ("    [{0:D2}] {1}" -f ($i+1), (Split-Path $leaves[$i] -Leaf)) -ForegroundColor White }
        
        # 各巻の割り当て
        for ($v = $r.Start; $v -le $r.End; $v++) {
            Write-FlickFitHost ""
            
            # 表紙選択（coverフォルダがある場合）※巻が変わるたびに候補を表示、他巻で使用済みは除外
            if ($coverImages.Count -gt 0) {
                $usedCoverPaths = [System.Collections.Generic.HashSet[string]]::new([System.StringComparer]::OrdinalIgnoreCase)
                for ($prev = $r.Start; $prev -lt $v; $prev++) {
                    if ($script:coverMap.ContainsKey($prev)) {
                        foreach ($p in @($script:coverMap[$prev])) { if ($p) { [void]$usedCoverPaths.Add($p) } }
                    }
                }
                $remainingImgs = @($coverImages | Where-Object { -not $usedCoverPaths.Contains($_.FullName) })
                if ($remainingImgs.Count -eq 0) { Write-FlickFitHost "  [表紙候補] 第 $v 巻: (他巻で使用済みのため候補なし)" -ForegroundColor DarkGray }
                else {
                    # 画像ファイル名から番号を抽出（Screenshot_4.jpg → 4）。無い場合は1-based
                    $imgNumToIndex = @{}
                    $imgNums = [System.Collections.Generic.List[string]]::new()
                    for ($i = 0; $i -lt $remainingImgs.Count; $i++) {
                        $nm = $remainingImgs[$i].Name
                        if ($nm -match '(\d+)(?:\.(?:jpg|jpeg|png|webp|bmp|gif|avif))$') { $num = $Matches[1]; $imgNumToIndex[$num] = $i; $imgNums.Add($num) } else { $imgNumToIndex[($i+1).ToString()] = $i }
                    }
                    Write-FlickFitHost "  [表紙候補] 第 $v 巻:" -ForegroundColor Yellow
                    for ($i = 0; $i -lt $remainingImgs.Count; $i++) {
                        $nm = $remainingImgs[$i].Name
                        $label = if ($nm -match '(\d+)(?:\.(?:jpg|jpeg|png|webp|bmp|gif|avif))$') { $Matches[1] } else { ($i+1).ToString() }
                        Write-FlickFitHost ("    [{0}] {1}" -f $label, $nm) -ForegroundColor DarkCyan
                    }
                    $imgRange = if ($imgNums.Count -gt 0) { "$($imgNums[0])-$($imgNums[-1])" } else { "1-$($remainingImgs.Count)" }
                    Write-FlickFitHost "  表紙を含むフォルダを表示しています。" -ForegroundColor Cyan
                    $selectedPaths = [System.Collections.Generic.List[string]]::new()
                    $numAns = Read-HostWithEsc "  画像選択 (例: 1-3 または 1,2,3 または 1 空Enter:スキップ)"
                    if ($numAns) {
                        $selectedNums = @()
                        if ($numAns -match '^(\d+)\s*[-~]\s*(\d+)$') {
                            $selectedNums = @([int]$Matches[1]..[int]$Matches[2]) | ForEach-Object { $_.ToString() }
                        } elseif ($numAns -match ',') {
                            $selectedNums = @($numAns -split '\s*,\s*')
                        } else {
                            $selectedNums = @($numAns.Trim())
                        }
                        foreach ($num in $selectedNums) {
                            if ($imgNumToIndex.ContainsKey($num)) {
                                $idx = $imgNumToIndex[$num]
                                $selectedPaths.Add($remainingImgs[$idx].FullName)
                                Write-FlickFitHost "       -> $($remainingImgs[$idx].Name)" -ForegroundColor DarkCyan
                            }
                        }
                    }
                    if ($selectedPaths.Count -gt 0) { $script:coverMap[$v] = @($selectedPaths) }
                }
            }
            
            # チャプター選択（話数で入力可能：11 または 11-15）。前段階で選択済みは除外
            $assignedPaths = [System.Collections.Generic.HashSet[string]]::new()
            foreach ($vk in $volMap.Keys) {
                if ($volMap[$vk]) { foreach ($p in $volMap[$vk]) { [void]$assignedPaths.Add($p) } }
            }
            $chapterNumToIndex = @{}
            $chapterNums = [System.Collections.Generic.List[string]]::new()
            $displayIndex = 0
            for ($i = 0; $i -lt $leaves.Count; $i++) {
                if ($assignedPaths.Contains($leaves[$i])) { continue }
                $leafName = Split-Path $leaves[$i] -Leaf
                if ($leafName -match '第\s*0*(\d{1,4})\s*話') { $ch = $Matches[1]; $chapterNumToIndex[$ch] = $i; $chapterNums.Add($ch) } else { $displayIndex++; $chapterNumToIndex[$displayIndex.ToString()] = $i }
            }
            if ($chapterNumToIndex.Count -eq 0) { Write-FlickFitHost "  [チャプター候補] 第 $v 巻: (未割当の候補なし)" -ForegroundColor DarkGray; continue }
            Write-FlickFitHost "  [チャプター候補]:" -ForegroundColor Yellow
            foreach ($ch in ($chapterNumToIndex.Keys | Sort-Object { [int]$_ })) {
                $idx = $chapterNumToIndex[$ch]
                Write-FlickFitHost ("    [{0}] {1}" -f $ch, (Split-Path $leaves[$idx] -Leaf)) -ForegroundColor White
            }
            $chRange = if ($chapterNums.Count -gt 0) { "$($chapterNums[0])-$($chapterNums[-1])" } else { $chapterNumToIndex.Keys -join ',' }
            $ans = Read-HostWithEsc "  -> 第 $v 巻のチャプター (話数で入力: $chRange 例:11 または 11-15, 空Enterでスキップ)"
            if (-not $ans) { continue }
            $anyChAdd = $false
            foreach ($idx in (Parse-ChapterInput $ans $chapterNumToIndex)) {
                if (-not $volMap.ContainsKey($v)) { $volMap[$v] = [System.Collections.Generic.List[string]]::new() }
                if (-not $volMap[$v].Contains($leaves[$idx])) { $volMap[$v].Add($leaves[$idx]); $anyChAdd = $true }
            }
            if ($anyChAdd) { [void]$script:volMapPreserveChapterOrder.Add([int]$v) }
        }
    }

    if ($unknowns.Count -gt 0) {
        # volMapに既に登録されているパスを収集（話数振り分けで採用済み）
        $assignedPaths = [System.Collections.Generic.HashSet[string]]::new()
        foreach ($vKey in $volMap.Keys) {
            foreach ($vPath in $volMap[$vKey]) {
                [void]$assignedPaths.Add([System.IO.Path]::GetFullPath($vPath))
            }
        }
        # coverMapで使用されている表紙画像の親フォルダも除外
        if ($script:coverMap) {
            foreach ($covKey in $script:coverMap.Keys) {
                foreach ($covPath in $script:coverMap[$covKey]) {
                    $covDir = Split-Path $covPath -Parent
                    [void]$assignedPaths.Add([System.IO.Path]::GetFullPath($covDir))
                }
            }
        }
        # 検出されたcoverフォルダも除外
        if ($script:detectedCoverFolders) {
            foreach ($dcf in $script:detectedCoverFolders) {
                [void]$assignedPaths.Add([System.IO.Path]::GetFullPath($dcf.Path))
            }
        }
        
        # 未割り当てのunknownsのみ表示
        $unassignedUnknowns = @($unknowns | Where-Object { 
            $normPath = [System.IO.Path]::GetFullPath($_.Path)
            -not $assignedPaths.Contains($normPath)
        })
        
        if ($unassignedUnknowns.Count -eq 0) {
            Write-FlickFitHost "`n[巻番号不明フォルダ]: なし（すべて話数振り分けで処理済み）" -ForegroundColor DarkGray
        } else {
            Write-FlickFitHost "`n[巻番号不明フォルダ]:" -ForegroundColor Yellow
            $ukLines = @($unassignedUnknowns | ForEach-Object { "  - $(Split-Path $_.Path -Leaf)" })
            $n = $ukLines.Count
            $mid = [Math]::Ceiling($n / 2)
            $colWidth = 48
            for ($i = 0; $i -lt $mid; $i++) {
                $left = $ukLines[$i].PadRight($colWidth)
                $right = if ($i + $mid -lt $n) { $ukLines[$i + $mid] } else { "" }
                Write-FlickFitHost -NoNewline $left -ForegroundColor White
                if ($right) { Write-FlickFitHost "  $right" -ForegroundColor White } else { Write-FlickFitHost "" }
            }
            
            # 先に一括メニュー（P/R）。親名に巻がある場合はここが最短
            if ($unassignedUnknowns.Count -gt 0) {
                Write-FlickFitHost "`n[巻番号不明フォルダの一括処理]" -ForegroundColor Cyan
                Write-FlickFitHost "  [Enter] スキップ → 直下で親名から巻が取れる場合は自動で表紙→話数へ（残りは個別入力）" -ForegroundColor DarkGray
                Write-FlickFitHost "  [P] 親名から巻を解釈 → 表紙→話数の流れで振り分け（余計な話数を除外しやすい）／まとめ親はフォルダが少ないとき案内" -ForegroundColor DarkGray
                Write-FlickFitHost "  [R] 親を並び順で連続巻へ割当（例: 8 親→3-10）／話数パターンの子は P と同様に表紙→話数フロー" -ForegroundColor DarkGray
                $bulkUk = (Read-HostWithEsc "  選択 (Enter / P / R)").Trim().ToUpper()
                if ($bulkUk -eq 'P') {
                Write-FlickFitHost "`n  各親フォルダ: 巻を解釈 → 表紙選択 → 巻ごとに採用する話数フォルダを指定（未採用はこの後も不明のまま残せます）" -ForegroundColor Cyan
                $ukBp = @{}
                foreach ($u in $unassignedUnknowns) {
                    $np = [System.IO.Path]::GetFullPath((Split-Path $u.Path -Parent))
                    if (-not $ukBp.ContainsKey($np)) { $ukBp[$np] = [System.Collections.ArrayList]::new() }
                    [void]$ukBp[$np].Add($u)
                }
                $parKeys = @($ukBp.Keys | Sort-Object { [regex]::Replace((Split-Path $_ -Leaf), '\d+', { $args[0].Value.PadLeft(10,'0') }) })
                # 先に「巻不明だったもの」を親単位で全部見せてから、親名から読んだ巻の処理予定を一覧する
                Write-FlickFitHost "`n  [P] 巻番号が不明だったフォルダ（親ごと・このあと表紙→話数の対象）" -ForegroundColor Cyan
                foreach ($npPr in $parKeys) {
                    $pnPr = Split-Path $npPr -Leaf
                    $lstPr = @($ukBp[$npPr])
                    Write-FlickFitHost "`n  ■ $pnPr  （$($lstPr.Count) 件）" -ForegroundColor White
                    foreach ($upr in $lstPr) { Write-FlickFitHost "      - $(Split-Path $upr.Path -Leaf)" -ForegroundColor Gray }
                }
                Write-FlickFitHost "`n  [P] 親フォルダ名から解釈した「1親あたりの巻」と処理の流れ（上から順に実行）" -ForegroundColor Cyan
                Write-FlickFitHost "  ※ 例: ACE 03（雑誌版）→ 第3巻 とは、「この親の直下の巻不明フォルダを第3巻に振り分ける」という意味です。" -ForegroundColor DarkGray
                $planRow = 1
                foreach ($npPr in $parKeys) {
                    $pnPr = Split-Path $npPr -Leaf
                    $hanPr = Convert-ZenToHan $pnPr
                    $pvPr = Get-VolFromParentName $hanPr
                    $volPr = $null
                    if ($pvPr -is [hashtable] -and $pvPr.ContainsKey('Vol') -and $null -ne $pvPr['Vol']) { $volPr = [int]$pvPr['Vol'] }
                    elseif ($pvPr -is [hashtable] -and $pvPr.ContainsKey('Start') -and $pvPr.ContainsKey('End') -and $null -ne $pvPr['Start'] -and $null -ne $pvPr['End'] -and [int]$pvPr['Start'] -eq [int]$pvPr['End']) {
                        $volPr = [int]$pvPr['Start']
                    }
                    if ($null -eq $volPr) {
                        if ($hanPr -match '0*(\d{1,3})\s*[（\(]') { $volPr = [int]$Matches[1] }
                        elseif ($hanPr -match '(?i)(?:ACE|Vol\.?|v)\s*0*(\d{1,3})(?:\D|$)') { $volPr = [int]$Matches[1] }
                    }
                    $sdPr = @(Get-ChildItem -LiteralPath $npPr -Directory -ErrorAction SilentlyContinue).Count
                    $allPr = @($ukBp[$npPr])
                    $chPr = @($allPr | Where-Object { Test-FlickFitLeafNameChapterLike (Split-Path $_.Path -Leaf) })
                    $nonChPr = $allPr.Count - $chPr.Count
                    if ($null -eq $volPr) {
                        Write-FlickFitHost ("  {0,2}. [×] 「{1}」… 親名から巻を取得できません（この親はスキップ）" -f $planRow, $pnPr) -ForegroundColor Yellow
                    } elseif ($sdPr -ge 2 -and $sdPr -le 5) {
                        Write-FlickFitHost ("  {0,2}. [?] 「{1}」… 直下フォルダ {2} 件 → このあと「1親に複数巻」か確認 → 表紙→話数（単一巻のときは第 {3} 巻）" -f $planRow, $pnPr, $sdPr, $volPr) -ForegroundColor DarkCyan
                    } elseif ($chPr.Count -gt 0) {
                        $xPr = if ($nonChPr -gt 0) { " ＋話数以外 $nonChPr 件" } else { "" }
                        Write-FlickFitHost ("  {0,2}. [→] 「{1}」… 第 {2} 巻（親名）／話数フォルダ {3} 件{4} → 表紙→話数" -f $planRow, $pnPr, $volPr, $chPr.Count, $xPr) -ForegroundColor Green
                    } else {
                        Write-FlickFitHost ("  {0,2}. [→] 「{1}」… 第 {2} 巻へ一括 {3} 件（話数パターン外）" -f $planRow, $pnPr, $volPr, $allPr.Count) -ForegroundColor Green
                    }
                    $planRow++
                }
                $pGo = (Read-HostWithEsc "  この内容で表紙→話数へ進む (Enter) / 中止 (b)").Trim()
                if ($pGo -match '^[Bb]') {
                    Write-FlickFitHost "  -> 親名一括(P) を中止しました（この後は個別入力などで対応できます）" -ForegroundColor Yellow
                } else {
                $didAnyFlow = $false
                $anyDirectAssign = 0
                foreach ($np in $parKeys) {
                    $pname = Split-Path $np -Leaf
                    $han = Convert-ZenToHan $pname
                    $pv = Get-VolFromParentName $han
                    $volN = $null
                    if ($pv -is [hashtable] -and $pv.ContainsKey('Vol') -and $null -ne $pv['Vol']) { $volN = [int]$pv['Vol'] }
                    elseif ($pv -is [hashtable] -and $pv.ContainsKey('Start') -and $pv.ContainsKey('End') -and $null -ne $pv['Start'] -and $null -ne $pv['End'] -and [int]$pv['Start'] -eq [int]$pv['End']) {
                        $volN = [int]$pv['Start']
                    }
                    if ($null -eq $volN) {
                        if ($han -match '0*(\d{1,3})\s*[（\(]') { $volN = [int]$Matches[1] }
                        elseif ($han -match '(?i)(?:ACE|Vol\.?|v)\s*0*(\d{1,3})(?:\D|$)') { $volN = [int]$Matches[1] }
                    }
                    if ($null -eq $volN) {
                        Write-FlickFitHost "  [スキップ] 親「$pname」から巻を取得できませんでした（R や個別入力で対応）" -ForegroundColor Yellow
                        continue
                    }
                    $subDirCount = @(Get-ChildItem -LiteralPath $np -Directory -ErrorAction SilentlyContinue).Count
                    $didPacked = $false
                    # 直下フォルダが少数のときだけ: 1親に複数巻＋話数＋表紙のまとめ構成か確認（雑誌版の9件構成では出さない）
                    if ($subDirCount -ge 2 -and $subDirCount -le 5) {
                        Write-FlickFitHost "`n  ─ 親「$pname」: 直下フォルダ $subDirCount 件" -ForegroundColor DarkCyan
                        $mAns = (Read-HostWithEsc "  1つの親に複数巻分（例: 3-10巻＋話数＋表紙の3フォルダなど）がまとまっていますか？ (y/N)").Trim()
                        if ($mAns -match '^[Yy]') {
                            $volRg = (Read-HostWithEsc "  巻の範囲 (例: 3-10)").Trim()
                            if ($volRg -match '^(\d+)\s*[-~]\s*(\d+)$') {
                                $mvs = [int]$Matches[1]; $mve = [int]$Matches[2]
                                if ($mvs -gt $mve) { $tmpM = $mvs; $mvs = $mve; $mve = $tmpM }
                                $uksPacked = [System.Collections.Generic.List[object]]::new()
                                foreach ($d in (Get-ChildItem -LiteralPath $np -Directory -ErrorAction SilentlyContinue)) {
                                    if (-not (Test-FlickFitLeafNameChapterLike $d.Name)) { continue }
                                    $imgc = @(Get-ChildItem -LiteralPath $d.FullName -File -ErrorAction SilentlyContinue | Where-Object { $script:ImageExtensions -contains $_.Extension.ToLower() }).Count
                                    if ($imgc -le 0) { continue }
                                    $uksPacked.Add([PSCustomObject]@{ Path = $d.FullName })
                                }
                                if ($uksPacked.Count -gt 0) {
                                    Write-FlickFitHost "  -> 話数フォルダ $($uksPacked.Count) 件を第 ${mvs}〜${mve} 巻の表紙→話数フローへ" -ForegroundColor Green
                                    [void](Invoke-FlickFitCoverChapterFlowForParent -NormParent $np -ParentPath $np -ParentName $pname -Uks @($uksPacked) -VolMap $volMap -PresetVolStart $mvs -PresetVolEnd $mve)
                                    $didAnyFlow = $true
                                    $didPacked = $true
                                }
                            }
                        }
                    }
                    if ($didPacked) { continue }
                    $uksAll = @($ukBp[$np])
                    $uksCh = @($uksAll | Where-Object { Test-FlickFitLeafNameChapterLike (Split-Path $_.Path -Leaf) })
                    if ($uksCh.Count -gt 0) {
                        Write-FlickFitHost "`n  ── 処理中: 「$pname」/ 第 $volN 巻（表紙→話数）──" -ForegroundColor DarkCyan
                        [void](Invoke-FlickFitCoverChapterFlowForParent -NormParent $np -ParentPath $np -ParentName $pname -Uks $uksCh -VolMap $volMap -PresetVolStart $volN -PresetVolEnd $volN)
                        $didAnyFlow = $true
                    } else {
                        foreach ($u in $uksAll) {
                            if (-not $volMap.ContainsKey($volN)) { $volMap[$volN] = [System.Collections.Generic.List[string]]::new() }
                            $volMap[$volN].Add($u.Path)
                            $anyDirectAssign++
                        }
                        Write-FlickFitHost "  -> 親「$pname」: $($uksAll.Count) 件 → 第 $volN 巻へ一括（話数パターンとして解釈できない名前）" -ForegroundColor Green
                    }
                }
                if ($didAnyFlow -or $anyDirectAssign -gt 0) {
                    foreach ($vKey in $volMap.Keys) { foreach ($p in $volMap[$vKey]) { [void]$assignedPaths.Add([System.IO.Path]::GetFullPath($p)) } }
                    $unassignedUnknowns = @($unassignedUnknowns | Where-Object { -not $assignedPaths.Contains([System.IO.Path]::GetFullPath($_.Path)) })
                    Write-FlickFitHost "`n  [親名一括(P) 終了時点の volMap]" -ForegroundColor Cyan
                    foreach ($vk in ($volMap.Keys | Sort-Object)) {
                        Write-FlickFitHost ("    第 {0} 巻 … {1} フォルダ" -f $vk, $volMap[$vk].Count) -ForegroundColor Green
                    }
                }
                }
                } elseif ($bulkUk -eq 'R') {
                $parEntries = @{}
                foreach ($u in $unassignedUnknowns) {
                    $np = [System.IO.Path]::GetFullPath((Split-Path $u.Path -Parent))
                    if (-not $parEntries.ContainsKey($np)) { $parEntries[$np] = (Split-Path $np -Leaf) }
                }
                $parSorted = @($parEntries.Keys | Sort-Object { [regex]::Replace($parEntries[$_], '\d+', { $args[0].Value.PadLeft(10,'0') }) })
                Write-FlickFitHost "  親フォルダ（上から順に巻を割り当てます）:" -ForegroundColor White
                for ($idxP = 0; $idxP -lt $parSorted.Count; $idxP++) {
                    $npOne = $parSorted[$idxP]
                    $nUk = @($unassignedUnknowns | Where-Object { [System.IO.Path]::GetFullPath((Split-Path $_.Path -Parent)) -eq $npOne }).Count
                    Write-FlickFitHost ("    {0,2}. {1}  （不明フォルダ {2} 件）" -f ($idxP + 1), $parEntries[$npOne], $nUk) -ForegroundColor Gray
                }
                $rngIn = (Read-HostWithEsc "  開始巻-終了巻 (例: 3-10)").Trim()
                if ($rngIn -match '^(\d+)\s*[-~]\s*(\d+)$') {
                    $a = [int]$Matches[1]; $b = [int]$Matches[2]
                    if ($a -gt $b) { $tmpV = $a; $a = $b; $b = $tmpV }
                    $cntPar = $parSorted.Count
                    $needSpan = $b - $a + 1
                    if ($needSpan -ne $cntPar) {
                        Write-FlickFitHost "  [エラー] 親は $cntPar 件ですが $a 巻〜$b 巻は $needSpan 巻分です。件数が一致しません。" -ForegroundColor Red
                        Write-FlickFitHost "  -> 1 フォルダずつ入力に進みます。" -ForegroundColor Yellow
                    } else {
                        $didAnyFlowR = $false
                        $anyDirectR = 0
                        for ($i = 0; $i -lt $cntPar; $i++) {
                            $volNi = $a + $i
                            $npI = $parSorted[$i]
                            $pnameI = $parEntries[$npI]
                            $uksI = @($unassignedUnknowns | Where-Object { [System.IO.Path]::GetFullPath((Split-Path $_.Path -Parent)) -eq $npI })
                            $uksCh = @($uksI | Where-Object { Test-FlickFitLeafNameChapterLike (Split-Path $_.Path -Leaf) })
                            if ($uksCh.Count -gt 0) {
                                Write-FlickFitHost "`n  -> 「$pnameI」: 第 $volNi 巻（R 割当）／話数 $($uksCh.Count) 件 → 表紙→話数振り分けへ" -ForegroundColor Green
                                [void](Invoke-FlickFitCoverChapterFlowForParent -NormParent $npI -ParentPath $npI -ParentName $pnameI -Uks $uksCh -VolMap $volMap -PresetVolStart $volNi -PresetVolEnd $volNi)
                                $didAnyFlowR = $true
                            } else {
                                foreach ($u in $uksI) {
                                    if (-not $volMap.ContainsKey($volNi)) { $volMap[$volNi] = [System.Collections.Generic.List[string]]::new() }
                                    $volMap[$volNi].Add($u.Path)
                                    $anyDirectR++
                                }
                                Write-FlickFitHost "  -> 「$pnameI」: $($uksI.Count) 件 → 第 $volNi 巻へ一括（話数パターンなし）" -ForegroundColor Green
                            }
                        }
                        if ($didAnyFlowR -or $anyDirectR -gt 0) {
                            foreach ($vKey in $volMap.Keys) { foreach ($p in $volMap[$vKey]) { [void]$assignedPaths.Add([System.IO.Path]::GetFullPath($p)) } }
                            $unassignedUnknowns = @($unassignedUnknowns | Where-Object { -not $assignedPaths.Contains([System.IO.Path]::GetFullPath($_.Path)) })
                        }
                    }
                } else {
                    Write-FlickFitHost "  入力を解釈できませんでした。1 フォルダずつ入力に進みます。" -ForegroundColor Yellow
                }
                }
            }
            # Enter で一括をスキップした場合など: 親名から巻が取れれば Y/n なしで表紙→話数へ（取れないときだけ確認）
            $ukByParent = @{}
            foreach ($uk in $unassignedUnknowns) {
                $normParent = [System.IO.Path]::GetFullPath((Split-Path $uk.Path -Parent))
                if (-not $ukByParent.ContainsKey($normParent)) { $ukByParent[$normParent] = [System.Collections.ArrayList]::new() }
                [void]$ukByParent[$normParent].Add($uk)
            }
            $sortedUkPar = @($ukByParent.Keys | Sort-Object { [regex]::Replace((Split-Path $_ -Leaf), '\d+', { $args[0].Value.PadLeft(10,'0') }) })
            foreach ($normParent in $sortedUkPar) {
                $uks = @($ukByParent[$normParent])
                if ($uks.Count -lt 2) { continue }
                $parentPath = Split-Path $uks[0].Path -Parent
                $parentName = Split-Path $parentPath -Leaf
                $allChapters = $true
                foreach ($uk in $uks) {
                    $nl = Split-Path $uk.Path -Leaf
                    if (-not (Test-FlickFitLeafNameChapterLike $nl)) { $allChapters = $false; break }
                }
                if (-not $allChapters) { continue }
                $hanP = Convert-ZenToHan $parentName
                $pvP = Get-VolFromParentName $hanP
                $volFromParent = $null
                if ($pvP -is [hashtable] -and $pvP.ContainsKey('Vol') -and $null -ne $pvP['Vol']) { $volFromParent = [int]$pvP['Vol'] }
                elseif ($pvP -is [hashtable] -and $pvP.ContainsKey('Start') -and $pvP.ContainsKey('End') -and $null -ne $pvP['Start'] -and $null -ne $pvP['End'] -and [int]$pvP['Start'] -eq [int]$pvP['End']) {
                    $volFromParent = [int]$pvP['Start']
                }
                if ($null -eq $volFromParent) {
                    if ($hanP -match '0*(\d{1,3})\s*[（\(]') { $volFromParent = [int]$Matches[1] }
                    elseif ($hanP -match '(?i)(?:ACE|Vol\.?|v)\s*0*(\d{1,3})(?:\D|$)') { $volFromParent = [int]$Matches[1] }
                }
                if ($null -ne $volFromParent) {
                    Write-FlickFitHost "`n  [$parentName] 親名から第 $volFromParent 巻と判定 → 表紙→話数の振り分けへ（未採用フォルダはこの後も不明のまま残せます）" -ForegroundColor Green
                    [void](Invoke-FlickFitCoverChapterFlowForParent -NormParent $normParent -ParentPath $parentPath -ParentName $parentName -Uks $uks -VolMap $volMap -PresetVolStart $volFromParent -PresetVolEnd $volFromParent)
                    foreach ($vKey in $volMap.Keys) {
                        foreach ($p in $volMap[$vKey]) { [void]$assignedPaths.Add([System.IO.Path]::GetFullPath($p)) }
                    }
                    $unassignedUnknowns = @($unassignedUnknowns | Where-Object { -not $assignedPaths.Contains([System.IO.Path]::GetFullPath($_.Path)) })
                    continue
                }
                Write-FlickFitHost "`n  [$parentName] 親名から巻を特定できません。表紙→話数でまとめて処理しますか？" -ForegroundColor Cyan
                Write-FlickFitHost "    Y/Enter: 実行（巻範囲を聞きます）  /  N: この親はスキップし、後の個別入力へ" -ForegroundColor DarkGray
                $splitAns = (Read-HostWithEsc "  実行しますか？ (Y/n)").Trim()
                if ($splitAns -match '^[Nn]$') { Write-FlickFitHost "    -> スキップしました（個別入力で対応できます）" -ForegroundColor Yellow; continue }
                [void](Invoke-FlickFitCoverChapterFlowForParent -NormParent $normParent -ParentPath $parentPath -ParentName $parentName -Uks $uks -VolMap $volMap)
                foreach ($vKey in $volMap.Keys) {
                    foreach ($p in $volMap[$vKey]) { [void]$assignedPaths.Add([System.IO.Path]::GetFullPath($p)) }
                }
                $unassignedUnknowns = @($unassignedUnknowns | Where-Object { -not $assignedPaths.Contains([System.IO.Path]::GetFullPath($_.Path)) })
            }
        }
        foreach ($uk in $unassignedUnknowns) {
            $ukPath = $uk.Path
            $ukName = Split-Path $ukPath -Leaf
            
            # EPUBフォルダの巻番号を確認（親フォルダがEPUB解凍フォルダの場合）
            $epubVol = $null
            if ($script:epubFolderVolMap) {
                foreach ($epubFolder in $script:epubFolderVolMap.Keys) {
                    if ($ukPath.StartsWith($epubFolder + '\') -or $ukPath -eq $epubFolder) {
                        $epubVol = $script:epubFolderVolMap[$epubFolder]
                        break
                    }
                }
            }
            
            Write-FlickFitHost "`n  フォルダ: $ukName" -ForegroundColor Cyan
            # フォルダをエクスプローラーで開く
            try { Start-Process "explorer.exe" -ArgumentList $ukPath } catch {}
            # フォルダ内の画像数を表示
            $imgCount = @(Get-ChildItem -LiteralPath $ukPath -File -ErrorAction SilentlyContinue | Where-Object { $script:ImageExtensions -contains $_.Extension.ToLower() }).Count
            $subDirs = @(Get-ChildItem -LiteralPath $ukPath -Directory -ErrorAction SilentlyContinue)
            if ($imgCount -gt 0) { Write-FlickFitHost "    画像: $imgCount 枚" -ForegroundColor Gray }
            if ($subDirs.Count -gt 0) {
                Write-FlickFitHost "    サブフォルダ: $($subDirs.Count) 件" -ForegroundColor Gray
                $subDirs | Select-Object -First 5 | ForEach-Object {
                    $subImgCnt = @(Get-ChildItem -LiteralPath $_.FullName -File -Recurse -ErrorAction SilentlyContinue | Where-Object { $script:ImageExtensions -contains $_.Extension.ToLower() }).Count
                    Write-FlickFitHost "      - $($_.Name) ($subImgCnt 枚)" -ForegroundColor DarkGray
                }
                if ($subDirs.Count -gt 5) { Write-FlickFitHost "      ... 他 $($subDirs.Count - 5) 件" -ForegroundColor DarkGray }
            }
            
            # EPUBから巻番号が検出されている場合は自動適用
            if ($epubVol) {
                Write-FlickFitHost "    EPUB巻番号: 第 $epubVol 巻 (自動検出)" -ForegroundColor Green
                $confirmAns = Read-HostWithEsc "  第 $epubVol 巻として処理しますか？ (Y/n/別の番号)"
                if ($confirmAns -match '^[Yy]?$' -or [string]::IsNullOrWhiteSpace($confirmAns)) {
                    if (-not $volMap.ContainsKey($epubVol)) { $volMap[$epubVol] = [System.Collections.Generic.List[string]]::new() }
                    $volMap[$epubVol].Add($ukPath)
                    Write-FlickFitHost "    -> 第 $epubVol 巻として登録" -ForegroundColor Green
                    continue
                } elseif ($confirmAns -match '^\d+$') {
                    $vInt = [int]$confirmAns
                    if (-not $volMap.ContainsKey($vInt)) { $volMap[$vInt] = [System.Collections.Generic.List[string]]::new() }
                    $volMap[$vInt].Add($ukPath)
                    Write-FlickFitHost "    -> 第 $vInt 巻として登録" -ForegroundColor Green
                    continue
                } else {
                    Write-FlickFitHost "    -> スキップ" -ForegroundColor Yellow
                    continue
                }
            }
            
            Write-FlickFitHost "    [半角数字のみ] → 第○巻  /  おまけ・番外など → 題名をそのまま入力（例: おまけ、描き下ろし）" -ForegroundColor DarkGray
            Write-FlickFitHost "    [T:題名] [特:題名] でも可（題名が数字だけのとき用）  /  Enter → スキップ" -ForegroundColor DarkGray
            $vn = (Read-HostWithEsc "  '$ukName'").Trim()
            if ([string]::IsNullOrWhiteSpace($vn)) { continue }
            if ($vn -match '^\d+$') {
                $vInt = [int]$vn
                if (-not $volMap.ContainsKey($vInt)) { $volMap[$vInt] = [System.Collections.Generic.List[string]]::new() }
                $volMap[$vInt].Add($ukPath)
                Write-FlickFitHost "    -> 第 $vInt 巻に登録" -ForegroundColor Green
            } else {
                $ttl = $null
                if ($vn -match '^[TtＴ][\s:：]+(.+)$') { $ttl = $Matches[1].Trim() }
                elseif ($vn -match '^特別?[\s:：]+(.+)$') { $ttl = $Matches[1].Trim() }
                else { $ttl = $vn.Trim() }
                if ([string]::IsNullOrWhiteSpace($ttl)) {
                    $ttl = (Read-HostWithEsc "  題名 (空Enterでフォルダ名を使用)").Trim()
                    if ([string]::IsNullOrWhiteSpace($ttl)) { $ttl = $ukName }
                }
                $ttl = Sanitize-FileName $ttl
                if ([string]::IsNullOrWhiteSpace($ttl)) { $ttl = Sanitize-FileName $ukName }
                $specialItems.Add([PSCustomObject]@{ Suffix = $ttl; Path = $ukPath })
                Write-FlickFitHost "    -> 特別扱い「$ttl」に登録（STEP4で [作品名] $ttl 形式のフォルダになります）" -ForegroundColor Green
            }
        }
    }
    
    # 1. 明示的なcoverフォルダ（自動検出）: 巻番号割り当て完了後に実行（対象巻なしを防ぐ）
    if (-not (Get-Variable -Name 'processedChapterParentPaths' -Scope Script -ErrorAction SilentlyContinue)) {
        $script:processedChapterParentPaths = @{}
    }
    if ($script:detectedCoverFolders.Count -gt 0) {
        # 先に「未設定の巻があるか」だけ判定し、すべて表紙済みならセクション全体を出さない（同一内容の繰り返し表示・二重実行時のスパム防止）
        $needCoverAutoInteractive = $false
        foreach ($coverLeafPre in $script:detectedCoverFolders) {
            $cpp = Split-Path $coverLeafPre.Path -Parent
            $normCp = [System.IO.Path]::GetFullPath($cpp)
            $tvs = [System.Collections.Generic.List[int]]::new()
            foreach ($vk in ($volMap.Keys | Sort-Object)) {
                foreach ($vp in $volMap[$vk]) {
                    $vpn = [System.IO.Path]::GetFullPath((Split-Path $vp -Parent))
                    if ($vpn -eq $normCp -and -not $tvs.Contains($vk)) { $tvs.Add($vk) }
                }
            }
            if ($tvs.Count -eq 0) { continue }
            foreach ($tv in ($tvs | Sort-Object)) {
                if (-not (Test-FlickFitCoverMapHasVol $script:coverMap $tv)) { $needCoverAutoInteractive = $true; break }
            }
            if ($needCoverAutoInteractive) { break }
        }
        if (-not $needCoverAutoInteractive) {
            # 全 cover フォルダについて対象巻が無いか、またはすべて表紙済み
        } else {
        Write-FlickFitHost "`n[表紙フォルダ自動検出]:" -ForegroundColor Cyan
        foreach ($coverLeaf in $script:detectedCoverFolders) {
            $coverParentPath = Split-Path $coverLeaf.Path -Parent
            $normCoverParent = [System.IO.Path]::GetFullPath($coverParentPath)
            $imgs = @(Get-ChildItem -LiteralPath $coverLeaf.Path -File -ErrorAction SilentlyContinue | 
                Where-Object { $script:ImageExtensions -contains $_.Extension.ToLower() } |
                Sort-Object { [regex]::Replace($_.Name, '\d+', { $args[0].Value.PadLeft(10,'0') }) })
            
            # このcoverフォルダと同じ親フォルダに属する巻を特定（パスは正規化して比較）
            $targetVols = [System.Collections.Generic.List[int]]::new()
            foreach ($vn in ($volMap.Keys | Sort-Object)) {
                foreach ($volPath in $volMap[$vn]) {
                    $volParentNorm = [System.IO.Path]::GetFullPath((Split-Path $volPath -Parent))
                    if ($volParentNorm -eq $normCoverParent) {
                        if (-not $targetVols.Contains($vn)) { $targetVols.Add($vn) }
                    }
                }
            }
            
            if ($targetVols.Count -gt 0) {
                # 先に表紙済みか判定し、済みなら行も出さずスキップ（1フォルダでも未設定があると need=true になり他フォルダまで「既に設定済み」が並ぶのを防ぐ）
                $allTargetHaveCover = $true
                foreach ($tv in ($targetVols | Sort-Object)) {
                    if (-not (Test-FlickFitCoverMapHasVol $script:coverMap $tv)) {
                        $allTargetHaveCover = $false
                        break
                    }
                }
                if ($allTargetHaveCover) { continue }
                $targetVolsStr = ($targetVols | Sort-Object | ForEach-Object { "第${_}巻" }) -join ", "
                Write-FlickFitHost "  - $(Split-Path $coverLeaf.Path -Leaf): $($imgs.Count) 枚 -> 対象: $targetVolsStr" -ForegroundColor DarkCyan
                
                # フォルダをエクスプローラーで開く
                Write-FlickFitHost "    [フォルダを開いています...]" -ForegroundColor Gray
                try { Start-Process "explorer.exe" -ArgumentList $coverLeaf.Path } catch {}
                
                # 表紙候補を表示
                Write-FlickFitHost "`n  [表紙候補]:" -ForegroundColor Yellow
                for ($i = 0; $i -lt $imgs.Count; $i++) { 
                    Write-FlickFitHost ("    [{0}] {1}" -f ($i+1), $imgs[$i].Name) -ForegroundColor DarkCyan 
                }
                
                $coverUseWholeFolderAuto = $false
                if ($imgs.Count -gt 1) {
                    Write-FlickFitHost "`n  このフォルダの表紙の扱い:" -ForegroundColor Yellow
                    Write-FlickFitHost "    [1] 番号で選ぶ（次の段で 1-3 や 1,2,5 / A など）" -ForegroundColor DarkGray
                    Write-FlickFitHost "    [2] フォルダ内の画像をすべて表紙とする（全 $($imgs.Count) 枚）" -ForegroundColor DarkGray
                    do {
                        $coverModeAnsAuto = (Read-HostWithEsc "  選択（1=番号で選ぶ / 2=全採用 / 空Enter=1）").Trim()
                        if ($coverModeAnsAuto -in @('', '1', '2')) { break }
                        Write-FlickFitHost "  入力形式が正しくありません。ここでは 1 か 2 か 空Enter のみです（1-3 や A は、直後の「番号で選択」で入れてください）" -ForegroundColor Yellow
                    } while ($true)
                    if ($coverModeAnsAuto -eq '2') { $coverUseWholeFolderAuto = $true }
                }
                
                # 対象巻のみ表紙を選択（すでにcoverMapに登録済みの巻はスキップ）
                foreach ($vn in ($targetVols | Sort-Object)) {
                    if (Test-FlickFitCoverMapHasVol $script:coverMap $vn) {
                        Write-FlickFitHost "`n  -> 第 $vn 巻: 表紙選択済み（スキップ）" -ForegroundColor DarkGray
                        continue
                    }
                    if ($coverUseWholeFolderAuto) {
                        $selectedPaths = [System.Collections.Generic.List[string]]::new()
                        foreach ($img in $imgs) { $selectedPaths.Add($img.FullName) }
                        $script:coverMap[$vn] = @($selectedPaths)
                        Write-FlickFitHost "`n  -> 第 $vn 巻の表紙: フォルダ全体を採用 ($($imgs.Count) 枚)" -ForegroundColor DarkCyan
                    } else {
                        Write-FlickFitHost "`n  -> 第 $vn 巻の表紙: 番号で選択 (例: 1-3 または 1,2,5 / A で全採用 / 空Enterでスキップ)" -ForegroundColor Cyan
                        $idxAns = (Read-HostWithEsc "  選択").Trim().ToUpper()
                        if ($idxAns) {
                            $selectedPaths = [System.Collections.Generic.List[string]]::new()
                            if ($idxAns -eq 'A') {
                                foreach ($img in $imgs) { $selectedPaths.Add($img.FullName) }
                                Write-FlickFitHost "       -> 全採用 ($($imgs.Count) 枚)" -ForegroundColor DarkCyan
                            } else {
                                $parsedIdx = @(Parse-RangeInput $idxAns $imgs.Count)
                                if ($parsedIdx.Count -gt 0) {
                                    foreach ($idx in $parsedIdx) { $selectedPaths.Add($imgs[$idx].FullName) }
                                    Write-FlickFitHost "       -> 選択: $($parsedIdx.Count) 枚" -ForegroundColor DarkCyan
                                }
                            }
                            if ($selectedPaths.Count -gt 0) { $script:coverMap[$vn] = @($selectedPaths) }
                        }
                    }
                }
            } else {
                Write-FlickFitHost "  - $(Split-Path $coverLeaf.Path -Leaf): $($imgs.Count) 枚 (対象巻なし - スキップ)" -ForegroundColor DarkGray
            }
        }
        }
    }
    
    $step2SnapOk = Save-FlickFitAfterStep2Snapshot -VolMap $volMap -SpecialItems $specialItems -AllLeaves $allLeaves
    if ($step2SnapOk) {
        Write-Verbose "STEP2 スナップショット保存成功（STEP3 移行時に完了として記録）"
    } else {
        Write-FlickFitHost "  [警告] STEP2 スナップショットの保存に失敗しました。次回は STEP2 先頭から再開します。" -ForegroundColor Yellow
    }
    }
    # if (lt3) ブロック終了 ↑  ↓ ResumeFromStep>=3 の処理（独立したブロックに分割して } elseif 構文を回避）
    if ($script:ResumeFromStep -eq 3) {
        Write-FlickFitHost "`n  [再開] STEP 2 をスキップ（完了時スナップショットから復元）" -ForegroundColor Cyan
        Write-FlickFitHost "  [再開] STEP3 は対話の先頭から進みます" -ForegroundColor DarkGray
        Restore-FlickFitAfterStep2Snapshot
        # StrictMode: 復元は $script:volMap のみ → スクリプトブロックへ明示束縛
        if ((Get-Variable -Name volMap -Scope Script -ErrorAction SilentlyContinue) -and $null -ne $script:volMap) { $volMap = $script:volMap }
        if ((Get-Variable -Name specialItems -Scope Script -ErrorAction SilentlyContinue) -and $null -ne $script:specialItems) { $specialItems = $script:specialItems }
        if ((Get-Variable -Name allLeaves -Scope Script -ErrorAction SilentlyContinue) -and $null -ne $script:allLeaves) { $allLeaves = $script:allLeaves }
    } elseif ($script:ResumeFromStep -gt 3) {
        # ResumeFromStep >= 4: STEP2 対話不要。STEP3 完了済みなら volMap 等は STEP3 スナップショットから
        if ($script:ResumeFromStep -ge 4) {
            Write-FlickFitHost "`n  [再開] STEP 2 をスキップ（STEP3 完了スナップショットから復元）" -ForegroundColor Cyan
            Restore-FlickFitAfterStep3Snapshot
            if ((Get-Variable -Name volMap -Scope Script -ErrorAction SilentlyContinue) -and $null -ne $script:volMap) { $volMap = $script:volMap }
            if ((Get-Variable -Name specialItems -Scope Script -ErrorAction SilentlyContinue) -and $null -ne $script:specialItems) { $specialItems = $script:specialItems }
            if ((Get-Variable -Name allLeaves -Scope Script -ErrorAction SilentlyContinue) -and $null -ne $script:allLeaves) { $allLeaves = $script:allLeaves }
            if ((Get-Variable -Name combinedBase -Scope Script -ErrorAction SilentlyContinue) -and $null -ne $script:combinedBase) { $combinedBase = $script:combinedBase }
            if ((Get-Variable -Name finalAuthor -Scope Script -ErrorAction SilentlyContinue)) { $finalAuthor = $script:finalAuthor }
            if ((Get-Variable -Name finalTitle -Scope Script -ErrorAction SilentlyContinue)) { $finalTitle = $script:finalTitle }
        } else {
            Write-FlickFitHost "`n  [再開] STEP 2 をスキップ" -ForegroundColor DarkGray
        }
    }

# ===== STEP 3: 作品名・作者名の確認 (ストリームライン版) =====
if ($runPhaseB) {
    if (-not (Get-Variable -Name 'TitleCandidates' -Scope Script -ErrorAction SilentlyContinue) -or $null -eq $script:TitleCandidates) { $script:TitleCandidates = @() }
    if (-not (Get-Variable -Name 'BestRawName' -Scope Script -ErrorAction SilentlyContinue) -or $null -eq $script:BestRawName) { $script:BestRawName = '' }
    if (-not (Get-Variable -Name 'CandidateNames' -Scope Script -ErrorAction SilentlyContinue) -or $null -eq $script:CandidateNames) { $script:CandidateNames = [System.Collections.Generic.HashSet[string]]::new([System.StringComparer]::OrdinalIgnoreCase) }
    if ($script:ResumeFromStep -lt 4) {
    # STEP3 に移行した時点で STEP2 を「完了」として記録する（ユーザー要件: STEP3 移行時のみ STEP2 完了）
    Update-ProcessLogStep -StepNum 2 -Status "success"
    $script:CurrentProcessStepNumber = 3
    Write-Step "STEP 3: 作品名・作者名の確認"

    # フォルダ名から作品名を取得（新方式: 作品名フォルダを優先）
    $rawName = if ($script:TitleName) { $script:TitleName } else { Sanitize-FileName $script:BestRawName }
    $existingAuthor = ""; $pureTitle = ""

    # 作者名: EPUBのOPFメタデータから取得（最優先）
    $epubCreatorFromOPF = $null
    if ($script:epubCreatorMap -and $script:epubCreatorMap.Count -gt 0) {
        $creators = @($script:epubCreatorMap.Values | Where-Object { $_ } | Select-Object -Unique)
        if ($creators.Count -gt 0) { $epubCreatorFromOPF = $creators[0] }
    }

    # 作者名: EPUB形式（作品名 24 - 著者名）から抽出を優先
    # 注: 巻数範囲（01-09巻など）を誤検出しないよう、著者名部分に日本語が含まれていることを確認
    $epubAuthorMatch = $null
    foreach ($tc in $script:TitleCandidates) {
        # TitleCandidatesは文字列配列になったので直接使用
        $tcName = if ($tc -is [string]) { $tc } elseif ($tc.PSObject.Properties['Name']) { $tc.Name } else { $tc.ToString() }
        if ($tcName -match '\s+\d{1,3}\s*[-\-－─—]\s*(.+)$') {
            $potentialAuthor = $Matches[1].Trim()
            # 数字で始まらず（巻数範囲除外）、日本語を含む場合のみ採用
            if ($potentialAuthor -notmatch '^\d' -and $potentialAuthor -match '[ぁ-んァ-ヶ一-龯]') {
                $epubAuthorMatch = $potentialAuthor
                break
            }
        }
    }
    if (-not $epubAuthorMatch -and $rawName -match '\s+\d{1,3}\s*[-\-－─—]\s*(.+)$') {
        $potentialAuthor = $Matches[1].Trim()
        if ($potentialAuthor -notmatch '^\d' -and $potentialAuthor -match '[ぁ-んァ-ヶ一-龯]') {
            $epubAuthorMatch = $potentialAuthor
        }
    }
    
    # 作者名: [xxx]形式から取得（[日付][ジャンル][作者] の3番目を優先、形式名を除外）
    # すべての候補から作者名を収集
    $allAuthorCandidates = @()
    if ($epubAuthorMatch) { $allAuthorCandidates += $epubAuthorMatch }
    
    # 方法1: TitleCandidatesから検索
    foreach ($tc in $script:TitleCandidates) {
        # 型に応じて名前を取得（Select-Object後はPSCustomObjectになる場合がある）
        $tcName = if ($tc -is [string]) { $tc } elseif ($tc.PSObject.Properties['Name']) { $tc.Name } else { $tc.ToString() }
        $bracketMatches = [regex]::Matches($tcName, "\[([^\]]+)\]")
        foreach ($m in $bracketMatches) {
            $b = $m.Groups[1].Value.Trim()
            if ($b -match "^(?:[0-9０-９]+|コミック|General|Manga|Comic)$") { continue }
            if ($b -match "^(?:DL版|AVIF|WEB|DL\s*版|RAW|PDF|EPUB|電子|一般コミック)$") { continue }
            if ($b -match "^(?:[A-Za-z0-9\s\.\-]+)$" -and $b.Length -lt 20) { continue }
            if ($b -match '[ぁ-んァ-ヶ一-龯]') { $allAuthorCandidates += $b }
        }
    }
    
    # 方法2: パス階層候補（CandidateNames）から直接検索（常に実行して候補を追加）
    if ($script:CandidateNames) {
        foreach ($name in $script:CandidateNames) {
            $bracketMatches = [regex]::Matches($name, "\[([^\]]+)\]")
            foreach ($m in $bracketMatches) {
                $b = $m.Groups[1].Value.Trim()
                if ($b -match "^(?:[0-9０-９]+|コミック|General|Manga|Comic)$") { continue }
                if ($b -match "^(?:DL版|AVIF|WEB|DL\s*版|RAW|PDF|EPUB|電子|一般コミック)$") { continue }
                if ($b -match "^(?:[A-Za-z0-9\s\.\-]+)$" -and $b.Length -lt 20) { continue }
                if ($b -match '[ぁ-んァ-ヶ一-龯]') { $allAuthorCandidates += $b }
            }
        }
    }
    
    $allAuthorCandidates = @($allAuthorCandidates | Select-Object -Unique)
    if ($epubCreatorFromOPF) {
        # OPFメタデータの作者名を最優先
        $existingAuthor = $epubCreatorFromOPF
        Write-FlickFitHost "  [EPUB] OPF作者名を採用: $epubCreatorFromOPF" -ForegroundColor DarkCyan
    } elseif ($allAuthorCandidates.Count -gt 0) {
        # EPUB形式の著者名を優先（既に日本語チェック済み）
        if ($epubAuthorMatch) {
            $existingAuthor = $epubAuthorMatch
        } else {
            # 日本語を多く含む候補を優先（作者名らしいもの）
            $mainlyJp = @($allAuthorCandidates | Where-Object {
                $s = $_
                $jpCount = ([regex]::Matches($s, '[ぁ-んァ-ヶ一-龯]')).Count
                $len = [Math]::Max(1, $s.Length)
                $jpCount -ge 2 -and ($jpCount / $len) -ge 0.5
            })
            if ($mainlyJp.Count -gt 0) {
                $existingAuthor = $mainlyJp[0]
            } else {
                # 日本語を含む候補から選択（日本語を含まないものは除外）
                $jpAny = $allAuthorCandidates | Where-Object { $_ -match '[ぁ-んァ-ヶ一-龯]' -and $_ -notmatch '^(DL版|AVIF|WEB)' } | Select-Object -First 1
                if ($jpAny) {
                    $existingAuthor = $jpAny
                }
                # 日本語を含む候補がない場合は空のまま（誤検出を防止）
            }
        }
    }

    # 作品名候補を表示
    Write-FlickFitHost "`n[作品名候補]:" -ForegroundColor Cyan
    $titleOptions = [System.Collections.Generic.List[PSObject]]::new()
    $seenTitles = @{}
    foreach ($tc in $script:TitleCandidates) {
        # TitleCandidatesは文字列配列になったので直接使用
        $tcName = if ($tc -is [string]) { $tc } elseif ($tc.PSObject.Properties['Name']) { $tc.Name } else { $tc.ToString() }
        $extracted = Extract-TitleFromName $tcName
        if ($extracted -and -not $seenTitles.ContainsKey($extracted)) {
            $seenTitles[$extracted] = $true
            $titleOptions.Add([PSCustomObject]@{ Original=$tcName; Extracted=$extracted })
        }
    }
    
    # フォルダ名がある場合はそれを優先、なければ候補から推測
    if ($script:TitleName) {
        $pureTitle = $script:TitleName
        $sourceFolder = "作品名フォルダ"
    } elseif ($titleOptions.Count -gt 0) {
        $pureTitle = $titleOptions[0].Extracted
        $sourceFolder = $titleOptions[0].Original
    } else {
        $pureTitle = Extract-TitleFromName $rawName
        $sourceFolder = $rawName
    }
    
    # 推測結果を表示
    Write-FlickFitHost "`n[作品名]: $pureTitle" -ForegroundColor Yellow
    Write-FlickFitHost "        (取得元: $sourceFolder)" -ForegroundColor DarkGray
    if ($existingAuthor) { 
        Write-FlickFitHost "[推測作者名]: $existingAuthor" -ForegroundColor Yellow 
    }
    
    # 他の候補があれば表示
    if ($titleOptions.Count -gt 1) {
        Write-FlickFitHost "`n[他の候補]:" -ForegroundColor Cyan
        $displayCount = [Math]::Min(5, $titleOptions.Count - 1)
        for ($i = 1; $i -le $displayCount; $i++) {
            $opt = $titleOptions[$i]
            Write-FlickFitHost ("    [{0}] {1}" -f ($i+1), $opt.Extracted) -ForegroundColor White
            Write-FlickFitHost ("        (元: {0})" -f $opt.Original) -ForegroundColor DarkGray
        }
        if ($titleOptions.Count -gt 6) { Write-FlickFitHost "    ... 他 $($titleOptions.Count - 6) 件" -ForegroundColor DarkGray }
    }
    
    Write-FlickFitHost "--------------------------------------------------"
    if ($titleOptions.Count -gt 1) {
        Write-FlickFitHost "    [Enter] 上記を採用  [番号] 他の候補を採用  [直接入力] 任意の作品名" -ForegroundColor DarkGray
    } else {
        Write-FlickFitHost "    [Enter] 上記を採用  [直接入力] 任意の作品名" -ForegroundColor DarkGray
    }

    $inputTitle = Read-HostWithEsc "① 作品名を選択・入力"
    $finalTitle = ""
    if (-not $inputTitle) {
        $finalTitle = $pureTitle
    } elseif ($inputTitle -match '^\d+$') {
        $idx = [int]$inputTitle - 1
        if ($idx -ge 0 -and $idx -lt $titleOptions.Count) {
            $finalTitle = $titleOptions[$idx].Extracted
        } else {
            $finalTitle = $inputTitle
        }
    } else {
        $finalTitle = $inputTitle
    }
    while (-not $finalTitle) { $finalTitle = Read-HostWithEsc "  ※作品名が空です。入力してください" }

    # ========== 表紙画像プレビュー + Google検索 ==========
    Write-FlickFitHost "`n[表紙画像を取得中...]" -ForegroundColor Cyan
    
    $tmpView = $null
    $previewImage = $null
    
    # 優先1: coverMapから第1巻の表紙を取得
    if ($script:coverMap -and $script:coverMap.Count -gt 0) {
        $firstVol = @($script:coverMap.Keys | Sort-Object)[0]
        $coverPaths = $script:coverMap[$firstVol]
        if ($coverPaths -and $coverPaths.Count -gt 0) {
            $previewImage = Get-Item -LiteralPath $coverPaths[0] -ErrorAction SilentlyContinue
        }
    }
    
    # 優先2: detectedCoverFoldersから取得
    if (-not $previewImage -and $script:detectedCoverFolders -and $script:detectedCoverFolders.Count -gt 0) {
        $coverFolder = $script:detectedCoverFolders[0]
        $previewImage = Get-ChildItem -LiteralPath $coverFolder.Path -File -ErrorAction SilentlyContinue |
            Where-Object { $script:ImageExtensions -contains $_.Extension.ToLower() } |
            Sort-Object Name | Select-Object -First 1
    }
    
    # 優先3: 画像が最も多いフォルダの1番最初の画像（サブフォルダではなく本編フォルダの表紙想定）
    if (-not $previewImage -and $null -ne $allLeaves -and $allLeaves.Count -gt 0) {
        try {
            $foldersWithCount = @($allLeaves | ForEach-Object {
                $cnt = @(Get-ChildItem -LiteralPath $_.Path -File -ErrorAction SilentlyContinue |
                    Where-Object { $script:ImageExtensions -contains $_.Extension.ToLower() }).Count
                if ($cnt -gt 0) { [PSCustomObject]@{ Path=$_.Path; ImageCount=$cnt } }
            } | Where-Object { $_ })
            $mainFolder = $foldersWithCount | Sort-Object -Property ImageCount -Descending | Select-Object -First 1
            if ($mainFolder) {
                $previewImage = Get-ChildItem -LiteralPath $mainFolder.Path -File -ErrorAction SilentlyContinue |
                    Where-Object { $script:ImageExtensions -contains $_.Extension.ToLower() } |
                    Sort-Object { [regex]::Replace($_.Name, '\d+', { $args[0].Value.PadLeft(10,'0') }) } | Select-Object -First 1
            }
        } catch {}
    }
    
    if ($null -ne $previewImage) {
        try {
            $tmpView = Join-Path (Get-FlickFitScratchTempDir) ("cover_preview.jpg")
            Copy-Item -LiteralPath $previewImage.FullName -Destination $tmpView -Force
            Write-FlickFitHost "  ✓ 表紙画像を取得しました" -ForegroundColor Green
            
            Write-FlickFitHost "  [表紙を開いています...]" -ForegroundColor Gray
            [void](Open-FlickFitPreviewImage -Path $tmpView)
        } catch {
            if ($_.Exception.Message -match '^中断:') { throw }
            Write-FlickFitHost "  ⚠ 表紙取得エラー: $($_.Exception.Message)" -ForegroundColor Yellow
        }
    } else {
        Write-FlickFitHost "  ⚠ 表紙画像が見つかりませんでした" -ForegroundColor Yellow
    }

    # Google検索を開く（URLエンコードで日本語・特殊文字対応）
    Write-FlickFitHost "`n[Google検索を開いています...]" -ForegroundColor Cyan
    $query = "$finalTitle 作者 漫画"
    $searchUrl = "https://www.google.com/search?q=" + [uri]::EscapeDataString($query)
    try {
        Start-Process $searchUrl -WorkingDirectory $env:TEMP
        Write-FlickFitHost "  ✓ ブラウザを開きました" -ForegroundColor Green
    } catch {
        Write-FlickFitHost "  [警告] ブラウザを開けませんでした" -ForegroundColor Yellow
    }

    # ========== 直接作者名入力（Enterなし） ==========
    Write-FlickFitHost "`n========== 作者名入力 ==========" -ForegroundColor Cyan
    if ($existingAuthor) {
        Write-FlickFitHost "推測作者名: $existingAuthor" -ForegroundColor Yellow
    } else {
        Write-FlickFitHost "推測作者名: (見つかりません)" -ForegroundColor DarkGray
    }
    Write-FlickFitHost "================================" -ForegroundColor Cyan
    Write-FlickFitHost "② 作者名を入力してください" -ForegroundColor Cyan
    Write-FlickFitHost "   [Enter] 採用 / [Ctrl+U] 作者名を空にする" -ForegroundColor DarkGray

    $finalAuthor = Read-HostWithEsc "   "
    $authorExplicitEmpty = (Get-Variable -Name FlickFitReadHostCtrlUCleared -Scope Script -ErrorAction SilentlyContinue) -and $script:FlickFitReadHostCtrlUCleared

    if ([string]::IsNullOrWhiteSpace($finalAuthor)) {
        if ($authorExplicitEmpty) {
            $finalAuthor = ""
            Write-FlickFitHost "  → 作者名を空として確定しました" -ForegroundColor Yellow
        } elseif ($existingAuthor) {
            $finalAuthor = $existingAuthor
            Write-FlickFitHost "  → 採用: $finalAuthor" -ForegroundColor Green
        } else {
            Write-FlickFitHost "  → 作者名なしで処理を続行します" -ForegroundColor Yellow
            $finalAuthor = ""
        }
    } else {
        Write-FlickFitHost "  → 入力: $finalAuthor" -ForegroundColor Green
    }

    # ベース名を確定
    $combinedBase = if ($finalAuthor) { "[$($finalAuthor.Trim())] $($finalTitle.Trim())" } else { $finalTitle.Trim() }
    $combinedBase = Sanitize-FileName $combinedBase
    
    Write-FlickFitHost "`n========== 確定 ==========" -ForegroundColor Cyan
    Write-FlickFitHost "作品名: $finalTitle" -ForegroundColor Yellow
    Write-FlickFitHost "作者名: $finalAuthor" -ForegroundColor Yellow
    Write-FlickFitHost "ベース名: $combinedBase" -ForegroundColor Green
    Write-FlickFitHost "=========================" -ForegroundColor Cyan
    } else {
        Write-FlickFitHost "`n  [再開] STEP3 をスキップ（完了スナップショットから復元）" -ForegroundColor Cyan
        Restore-FlickFitAfterStep3Snapshot
    }
    # StrictMode: Set-Variable -Scope Script だけでは $volMap 等が未束縛扱いになるため同期
    if ((Get-Variable -Name volMap -Scope Script -ErrorAction SilentlyContinue) -and $null -ne $script:volMap) { $volMap = $script:volMap }
    if ((Get-Variable -Name specialItems -Scope Script -ErrorAction SilentlyContinue) -and $null -ne $script:specialItems) { $specialItems = $script:specialItems }
    if ((Get-Variable -Name allLeaves -Scope Script -ErrorAction SilentlyContinue) -and $null -ne $script:allLeaves) { $allLeaves = $script:allLeaves }
    if ($script:ResumeFromStep -ge 4) {
        if ((Get-Variable -Name combinedBase -Scope Script -ErrorAction SilentlyContinue) -and $null -ne $script:combinedBase) { $combinedBase = $script:combinedBase }
        if ((Get-Variable -Name finalAuthor -Scope Script -ErrorAction SilentlyContinue)) { $finalAuthor = $script:finalAuthor }
        if ((Get-Variable -Name finalTitle -Scope Script -ErrorAction SilentlyContinue)) { $finalTitle = $script:finalTitle }
    }
    # （STEP3 成功ログは巻確定後・Save-FlickFitAfterStep3Snapshot 直前にのみ記録。ここでは書かない。）
}

# ===== 変数初期化 (STEP 4の前に必須) =====
# 再開・StrictMode: 復元関数の Set-Variable -Scope Script だけでは $volMap が未束縛のまま残ることがある
if (-not (Get-Variable -Name volMap -ErrorAction SilentlyContinue)) {
    if ((Get-Variable -Name volMap -Scope Script -ErrorAction SilentlyContinue) -and $null -ne $script:volMap) {
        $volMap = $script:volMap
    } else {
        $volMap = @{}
    }
}
if (-not (Get-Variable -Name specialItems -ErrorAction SilentlyContinue)) {
    if ((Get-Variable -Name specialItems -Scope Script -ErrorAction SilentlyContinue) -and $null -ne $script:specialItems) {
        $specialItems = $script:specialItems
    } else {
        $specialItems = [System.Collections.Generic.List[PSObject]]::new()
    }
}
if (-not (Get-Variable -Name allLeaves -ErrorAction SilentlyContinue)) {
    if ((Get-Variable -Name allLeaves -Scope Script -ErrorAction SilentlyContinue) -and $null -ne $script:allLeaves) {
        $allLeaves = $script:allLeaves
    } else {
        $allLeaves = [System.Collections.Generic.List[PSObject]]::new()
    }
}

$extraVolItems = [System.Collections.Generic.List[PSObject]]::new()

if ($volMap.Keys.Count -eq 0) {
    # 特別短編・おまけ系のみ（番号巻なし）→ volMap は空のまま STEP4 で specialItems のみ処理
    if ($specialItems -and $specialItems.Count -gt 0) {
        Write-FlickFitHost "  [注意] 番号付きの巻フォルダはありません。特別扱いフォルダのみ STEP 4 以降を実行します ($($specialItems.Count) 件)。" -ForegroundColor Yellow
    } else {
        $leafFallback = @()
        if ($allLeaves -and $allLeaves.Count -gt 0) {
            $leafFallback = @($allLeaves | Where-Object {
                $_ -and $_.Path -and -not (Test-FlickFitResumeExcludeVolumeOutputLeafName -FolderName (Split-Path $_.Path -Leaf))
            })
        } else {
            $leafFallback = @(Get-LeafFolders -Path (Get-Location).Path -ResumeInputCandidateFilter)
        }
        if ($leafFallback.Count -eq 1) {
            $singleLeaf = $leafFallback[0]
            $isEpubDerived = $false
            if ((Get-Variable -Name epubTitleMap -Scope Script -ErrorAction SilentlyContinue) -and $script:epubTitleMap -and $script:epubTitleMap.Count -gt 0) { $isEpubDerived = $true }
            if (-not $isEpubDerived -and (Get-Variable -Name epubCreatorMap -Scope Script -ErrorAction SilentlyContinue) -and $script:epubCreatorMap -and $script:epubCreatorMap.Count -gt 0) { $isEpubDerived = $true }
            if (-not $isEpubDerived -and (Get-Variable -Name epubFolderVolMap -Scope Script -ErrorAction SilentlyContinue) -and $script:epubFolderVolMap -and $script:epubFolderVolMap.Count -gt 0) { $isEpubDerived = $true }
            if (-not $isEpubDerived -and (Get-Variable -Name epubMainFolderMap -Scope Script -ErrorAction SilentlyContinue) -and $script:epubMainFolderMap -and $script:epubMainFolderMap.Count -gt 0) { $isEpubDerived = $true }
            if (-not $isEpubDerived -and (Get-Variable -Name epubSpineImageMap -Scope Script -ErrorAction SilentlyContinue) -and $script:epubSpineImageMap -and $script:epubSpineImageMap.Count -gt 0) { $isEpubDerived = $true }
            if ($isEpubDerived) {
                $specialItems.Add([PSCustomObject]@{ Suffix = ""; Path = $singleLeaf.Path })
                Write-FlickFitHost "  [注意] EPUB由来の単一画像フォルダを、番号なし単体として処理します: $($singleLeaf.Name)" -ForegroundColor Yellow
            } else {
                $volMap[1] = [System.Collections.Generic.List[string]]::new()
                $volMap[1].Add($singleLeaf.Path)
                Write-FlickFitHost "  [注意] 自動巻判定に失敗したため、単一フォルダを第1巻として処理します: $($singleLeaf.Name)" -ForegroundColor Yellow
            }
        } elseif ($leafFallback.Count -gt 1) {
            # 複数リーフかつ名前がおまけ・特典系のみ → 特別扱いに寄せて続行（未割当 Unknown 対策）
            $extraNamePat = '(?i)おまけ|オマケ|omake|bonus|extra|番外|特典|ペーパー|小冊子|描き下ろし'
            $allExtraLike = $true
            foreach ($lf in $leafFallback) {
                if ($lf.Name -notmatch $extraNamePat) { $allExtraLike = $false; break }
            }
            if ($allExtraLike) {
                foreach ($lf in $leafFallback) {
                    $specialItems.Add([PSCustomObject]@{ Suffix = $lf.Name.Trim(); Path = $lf.Path })
                }
                Write-FlickFitHost "  [注意] 番号巻なし。フォルダ名がおまけ・特典系のため特別扱いで処理します ($($leafFallback.Count) 件)。" -ForegroundColor Yellow
            } else {
                # アンソロジーなど（巻番号なし・複数フォルダ）は元フォルダ名をサフィックスとして使用する
                $nameRows = @()
                foreach ($lf in $leafFallback) {
                    if (Test-FlickFitResumeExcludeVolumeOutputLeafName -FolderName $lf.Name) { continue }
                    $orig = $lf.Name.Trim()
                    if ([string]::IsNullOrWhiteSpace($orig)) { $orig = Split-Path $lf.Path -Leaf }
                    if ([string]::IsNullOrWhiteSpace($orig)) { $orig = "無題" }

                    # 元フォルダ名のノイズを落として「[作者] 作品名」形式へ寄せる
                    $normTitle = Extract-TitleFromName $orig
                    $candAuthor = $null
                    $bracketMatches = [regex]::Matches($orig, "\[([^\]]+)\]")
                    foreach ($m in $bracketMatches) {
                        $b = $m.Groups[1].Value.Trim()
                        if ($b -match "^(?:[0-9０-９]+|コミック|General|Manga|Comic)$") { continue }
                        if ($b -match "^(?:DL版|AVIF|WEB|DL\s*版|RAW|PDF|EPUB|電子|一般コミック)$") { continue }
                        if ($b -match "^(?:[A-Za-z0-9\s\.\-]+)$" -and $b.Length -lt 20) { continue }
                        if ($b -match '[ぁ-んァ-ヶ一-龯]') { $candAuthor = $b; break }
                    }
                    if ([string]::IsNullOrWhiteSpace($candAuthor) -and $orig -match '^\[([^\]]+)\]\s*') {
                        $head = $Matches[1].Trim()
                        if ($head -and $head -notmatch "^(?:DL版|AVIF|WEB|RAW|PDF|EPUB|電子|一般コミック)$" -and $head -match '[ぁ-んァ-ヶ一-龯]') {
                            $candAuthor = $head
                        }
                    }

                    $label = if ($candAuthor -and $normTitle) { "[$candAuthor] $normTitle" } elseif ($normTitle) { $normTitle } else { $orig }
                    $san = Sanitize-FileName $label
                    if ([string]::IsNullOrWhiteSpace($san)) { $san = "無題" }
                    $nameRows += [PSCustomObject]@{ Path = $lf.Path; Original = $orig; Label = $label; Sanitized = $san }
                }
                :dupResolve while ($true) {
                    $dupGroups = @($nameRows | Group-Object -Property Sanitized | Where-Object { $_.Count -gt 1 })
                    if ($dupGroups.Count -eq 0) {
                        foreach ($row in $nameRows) {
                            $specialItems.Add([PSCustomObject]@{ Suffix = $row.Label; Path = $row.Path })
                        }
                        Write-FlickFitHost "  [注意] 番号巻なし。複数フォルダを特別扱いで続行します ($($nameRows.Count) 件)。出力名は「ベース名 + [作者]作品名」です。" -ForegroundColor Yellow
                        break
                    }
                    Write-FlickFitHost "  [確認] フォルダ名が重複します（使用可能文字へ正規化後）。" -ForegroundColor Yellow
                    :dupMenu while ($true) {
                        Write-FlickFitHost "    1: そのまま実行（1つのフォルダにまとめる）" -ForegroundColor DarkGray
                        Write-FlickFitHost "    2: 個別に名前を付ける" -ForegroundColor DarkGray
                        Write-FlickFitHost "    3: リスト表示" -ForegroundColor DarkGray
                        Write-FlickFitHost "    4: 重複キーを選んで、その候補群を今回の処理対象から除外する" -ForegroundColor DarkGray
                        $dupChoice = (Read-HostWithEsc "  選択してください (1/2/3/4)").Trim()
                        if ($dupChoice -eq '3') {
                            Write-FlickFitHost "`n  [重複リスト]" -ForegroundColor Cyan
                            foreach ($g in $dupGroups) {
                                Write-FlickFitHost "    - $($g.Name)" -ForegroundColor Yellow
                                foreach ($it in $g.Group) {
                                    Write-FlickFitHost "        候補: $($it.Label)" -ForegroundColor Gray
                                    Write-FlickFitHost "        元名: $($it.Original)" -ForegroundColor DarkGray
                                    Write-FlickFitHost "        パス: $($it.Path)" -ForegroundColor DarkGray
                                }
                            }
                            continue dupMenu
                        }
                        if ($dupChoice -eq '1') {
                            # 1つの巻に集約して続行（STEP4 の通常巻フローで連番統合）
                            if (-not $volMap.ContainsKey(1)) { $volMap[1] = [System.Collections.Generic.List[string]]::new() }
                            foreach ($row in $nameRows) { $volMap[1].Add($row.Path) }
                            Write-FlickFitHost "  [注意] 1つのフォルダにまとめて処理します（第1巻扱い）。" -ForegroundColor Yellow
                            break dupResolve
                        }
                        if ($dupChoice -eq '2') {
                            $i = 1
                            foreach ($row in $nameRows) {
                                $defaultName = $row.Label
                                $inputName = Read-HostWithEsc ("  名前を入力 [{0}] (Enterで '{1}')" -f $i, $defaultName)
                                $useName = if ([string]::IsNullOrWhiteSpace($inputName)) { $defaultName } else { $inputName.Trim() }
                                if ([string]::IsNullOrWhiteSpace($useName)) { $useName = "短編{0:D2}" -f $i }
                                $specialItems.Add([PSCustomObject]@{ Suffix = $useName; Path = $row.Path })
                                $i++
                            }
                            Write-FlickFitHost "  [注意] 個別指定の名前で特別扱い処理を続行します。" -ForegroundColor Yellow
                            break dupResolve
                        }
                        if ($dupChoice -eq '4') {
                            $gi = 1
                            foreach ($g in $dupGroups) {
                                Write-FlickFitHost "    [$gi] $($g.Name) ($($g.Group.Count) 件)" -ForegroundColor Yellow
                                $gi++
                            }
                            $exAns = (Read-HostWithEsc "  除外する重複キーの番号（1-$($dupGroups.Count)）").Trim()
                            if ($exAns -match '^\d+$') {
                                $exNum = [int]$exAns
                                if ($exNum -ge 1 -and $exNum -le $dupGroups.Count) {
                                    $idx = $exNum - 1
                                    $removeSet = [System.Collections.Generic.HashSet[string]]::new([StringComparer]::OrdinalIgnoreCase)
                                    foreach ($it in $dupGroups[$idx].Group) { [void]$removeSet.Add($it.Path) }
                                    $nameRows = @($nameRows | Where-Object { -not $removeSet.Contains($_.Path) })
                                    Write-FlickFitHost "  [除外] 選択したキーに属するフォルダを処理対象から外しました。" -ForegroundColor DarkGray
                                    if ($nameRows.Count -eq 0) {
                                        throw "除外の結果、処理対象のフォルダがなくなりました。`-ForceRetry` でやり直すか、フォルダ構成を確認してください。"
                                    }
                                    break dupMenu
                                }
                            }
                            Write-FlickFitHost "  [入力エラー] 1 ～ $($dupGroups.Count) の番号を入力してください。" -ForegroundColor Yellow
                            continue dupMenu
                        }
                        Write-FlickFitHost "  [入力エラー] 1 / 2 / 3 / 4 のいずれかを入力してください。" -ForegroundColor Yellow
                    }
                }
            }
        } else {
            throw "処理対象となる巻が見つかりませんでした"
        }
    }
}

if ($runPhaseB) {
    try {
        Save-FlickFitAfterStep3Snapshot -VolMap $volMap -SpecialItems $specialItems -CombinedBase $combinedBase -FinalAuthor $finalAuthor -FinalTitle $finalTitle
        $snap3Post = Join-Path (Get-FlickFitResumeSnapshotDir) '_flickfit_after_step3.clixml'
        if (Test-Path -LiteralPath $snap3Post) {
            Update-ProcessLogStep -StepNum 3 -Status "success"
        } else {
            Write-FlickFitHost "  [警告] STEP3 完了をログに記録しません（_flickfit_after_step3.clixml が無い）。次回は STEP3 から再開します。" -ForegroundColor Yellow
        }
    } catch {
        Write-FlickFitHost "  [警告] STEP 3 後スナップショット保存に失敗: $_" -ForegroundColor Yellow
    }
}

# coverフォルダから画像を収集する関数（表紙を先頭に）
function Get-ImagesWithCoverFirst {
    param([string]$SourcePath, [switch]$DirectOnly)
    $allImages = [System.Collections.Generic.List[System.IO.FileInfo]]::new()
    
    # サブフォルダと直接の画像を確認（除外リストを適用）
    $allSubDirs = @(Get-ChildItem -LiteralPath $SourcePath -Directory -ErrorAction SilentlyContinue)
    $subDirs = @($allSubDirs | Where-Object { 
        -not ($script:excludedSubfolderPaths -and $script:excludedSubfolderPaths.Contains($_.FullName))
    })
    $excludedCount = $allSubDirs.Count - $subDirs.Count
    
    $directImgs = @(Get-ChildItem -LiteralPath $SourcePath -File -ErrorAction SilentlyContinue | 
        Where-Object { $script:ImageExtensions -contains $_.Extension.ToLower() })
    
    # 親フォルダの画像のみ（子フォルダは使わない）
    if ($DirectOnly) {
        if ($directImgs.Count -gt 0) {
            Write-FlickFitHost "      [直接画像のみ]: $($directImgs.Count) 枚" -ForegroundColor Gray
        }
        foreach ($img in ($directImgs | Sort-Object { [regex]::Replace($_.Name, '\d+', { $args[0].Value.PadLeft(10,'0') }) })) { $allImages.Add($img) }
        return $allImages
    }
    
    # 直接の画像がある場合 = リーフフォルダ → フォルダ内の画像をそのまま使用
    if ($directImgs.Count -gt 0) {
        Write-FlickFitHost "      [リーフフォルダ]: 直接の画像 $($directImgs.Count) 枚" -ForegroundColor Gray
        foreach ($img in ($directImgs | Sort-Object { [regex]::Replace($_.Name, '\d+', { $args[0].Value.PadLeft(10,'0') }) })) {
            $allImages.Add($img)
        }
    }
    # 直接の画像がなくサブフォルダがある場合 = チャプター構造 → サブフォルダを処理
    elseif ($subDirs.Count -gt 0) {
        $subMsg = "サブフォルダ $($subDirs.Count) 個"
        if ($excludedCount -gt 0) { $subMsg += " (除外: $excludedCount 個)" }
        Write-FlickFitHost "      [チャプター構造]: $subMsg" -ForegroundColor Gray
        
        # coverフォルダを探す（$script:CoverFolderNameLikeRegex と同一基準）
        $coverDir = $subDirs | Where-Object { $_.Name -match $script:CoverFolderNameLikeRegex } | Select-Object -First 1
        $otherDirs = $subDirs | Where-Object { $_.Name -notmatch $script:CoverFolderNameLikeRegex } | 
            Sort-Object { [regex]::Replace($_.Name, '\d+', { $args[0].Value.PadLeft(10,'0') }) }
        
        # coverフォルダの画像を先頭に追加（最初の1枚のみ表紙として）
        if ($coverDir) {
            $coverImgs = @(Get-ChildItem -LiteralPath $coverDir.FullName -File -ErrorAction SilentlyContinue | 
                Where-Object { $script:ImageExtensions -contains $_.Extension.ToLower() } |
                Sort-Object { [regex]::Replace($_.Name, '\d+', { $args[0].Value.PadLeft(10,'0') }) })
            if ($coverImgs.Count -gt 0) {
                Write-FlickFitHost "      [cover検出]: $($coverDir.Name) から $($coverImgs.Count) 枚" -ForegroundColor Yellow
                $allImages.Add($coverImgs[0])
                Write-FlickFitHost "        -> 表紙: $($coverImgs[0].Name)" -ForegroundColor DarkCyan
            }
        }
        
        # その他のサブフォルダを番号順に処理
        foreach ($dir in $otherDirs) {
            $imgs = @(Get-ChildItem -LiteralPath $dir.FullName -File -ErrorAction SilentlyContinue | 
                Where-Object { $script:ImageExtensions -contains $_.Extension.ToLower() } |
                Sort-Object { [regex]::Replace($_.Name, '\d+', { $args[0].Value.PadLeft(10,'0') }) })
            foreach ($img in $imgs) { $allImages.Add($img) }
        }
    }
    else {
        # 直接の画像もサブフォルダもない場合
        Write-FlickFitHost "      [警告]: 画像が見つかりません" -ForegroundColor Yellow
    }
    
    return $allImages
    }

    # ===== STEP 4: フォルダ整理 =====
    $script:CurrentProcessStepNumber = 4
    Write-Step "STEP 4: フォルダ整理・連番コピー"
    $finalDirs = [System.Collections.Generic.List[string]]::new()
    $outputRootPath = (Get-Location).Path
    foreach ($vNum in ($volMap.Keys | Sort-Object)) {
        $extraItem = $extraVolItems | Where-Object { $_.Vol -eq $vNum } | Select-Object -First 1
        $finalVolName = if ($extraItem) { if ($combinedBase) { "$combinedBase $($extraItem.Suffix)" } else { "番外編_$($extraItem.Suffix)" } } elseif ($runPhaseB) { "$combinedBase 第{0:D2}巻" -f $vNum } else { "第{0:D2}巻" -f $vNum }
        $destDirPath = Join-Path $outputRootPath $finalVolName
        $preserveChOrder = (Get-Variable -Name 'volMapPreserveChapterOrder' -Scope Script -ErrorAction SilentlyContinue) -and $script:volMapPreserveChapterOrder.Contains([int]$vNum)
        $orderedVolLeafPaths = if ($preserveChOrder) {
            @($volMap[$vNum])
        } else {
            @($volMap[$vNum] | Sort-Object { Get-ChapterNumber (Split-Path $_ -Leaf) }, { [regex]::Replace((Split-Path $_ -Leaf), '\d+', { $args[0].Value.PadLeft(10,'0') }) })
        }
        if ($runPhaseB -and $runPhaseA) {
            Write-FlickFitHost "  [整理中]: $finalVolName" -ForegroundColor Cyan
            $destDir = New-Item -ItemType Directory -Path $destDirPath -Force
            $normDest = [System.IO.Path]::GetFullPath($destDir.FullName)
            $destIsSource = $false
            foreach ($sp in $volMap[$vNum]) {
                if ([System.IO.Path]::GetFullPath($sp) -eq $normDest) { $destIsSource = $true; break }
            }
            # コピー先がソースに含まれない場合、既存画像をクリア（元の01巻が残る重複を防止）
            if (-not $destIsSource -and (Test-Path -LiteralPath $destDirPath)) {
                $existingImgs = @(Get-ChildItem -LiteralPath $destDirPath -File -ErrorAction SilentlyContinue | Where-Object { $script:ImageExtensions -contains $_.Extension.ToLower() })
                if ($existingImgs.Count -gt 0 -and -not $DryRun) {
                    Write-FlickFitHost "      [クリア]: 既存の画像 $($existingImgs.Count) 枚を削除（重複防止）" -ForegroundColor Yellow
                    foreach ($ei in $existingImgs) {
                        try { Remove-Item -LiteralPath $ei.FullName -Force -ErrorAction SilentlyContinue } catch {}
                    }
                }
            }
            $imgIdx = 1
            
            # coverMapで選択された表紙があれば先頭にコピー（複数枚対応）
            if ($script:coverMap -and $script:coverMap.ContainsKey($vNum)) {
                $coverPaths = @($script:coverMap[$vNum])
                foreach ($coverPath in $coverPaths) {
                    if ($coverPath -and (Test-Path -LiteralPath $coverPath)) {
                        $coverExt = [System.IO.Path]::GetExtension($coverPath).ToLower()
                        $newName = "{0:D3}{1}" -f $imgIdx++, $coverExt
                        $destFile = Join-Path $destDir.FullName $newName
                        if (-not $DryRun) { Copy-Item -LiteralPath $coverPath -Destination $destFile -Force }
                        Write-FlickFitHost "      [表紙]: $(Split-Path $coverPath -Leaf) -> $newName" -ForegroundColor DarkCyan
                    }
                }
            }
            
            # チャプターフォルダ: 話数振り分けで入力した巻は登録順を維持、それ以外は話数番号順でソート
            # volDirectOnlyPaths が未設定の場合は空リストで初期化（話数振り分けブロックを通らないフォールバック用）
            if (-not (Get-Variable -Name 'volDirectOnlyPaths' -Scope Script -ErrorAction SilentlyContinue)) {
                $script:volDirectOnlyPaths = [System.Collections.Generic.List[string]]::new()
            }
            foreach ($sourcePath in $orderedVolLeafPaths) {
                # TIFファイルがあればJPGに変換
                Convert-TifToJpg -Path $sourcePath
                $normSource = [System.IO.Path]::GetFullPath($sourcePath)
                $normDest   = [System.IO.Path]::GetFullPath($destDir.FullName)
                $isSameFolder = ($normSource -eq $normDest)
                $directOnly = $script:volDirectOnlyPaths -and $script:volDirectOnlyPaths.Contains($sourcePath)
                $imgs = @(Get-ImagesWithCoverFirst -SourcePath $sourcePath -DirectOnly:$directOnly)
                if ($imgs.Count -eq 0) { continue }
                # 同一フォルダ内でのコピーは上書きで消失するため、一時リネーム→最終リネームの2段階で安全に実施
                if ($isSameFolder -and -not $DryRun) {
                    $pad = [Math]::Max(3, $imgs.Count.ToString().Length)
                    $tmpPrefix = "__step4_$([Guid]::NewGuid().ToString('N').Substring(0,8))_"
                    $orderedImgs = @($imgs | Sort-Object { [regex]::Replace($_.Name, '\d+', { $args[0].Value.PadLeft(10,'0') }) })
                    foreach ($img in $orderedImgs) {
                        $tmpName = $tmpPrefix + $img.Name
                        $tmpPath = Join-Path $destDir.FullName $tmpName
                        if ($img.FullName -ne $tmpPath) { Rename-Item -LiteralPath $img.FullName -NewName $tmpName -ErrorAction Stop }
                    }
                    $idx = 1
                    Get-ChildItem -LiteralPath $destDir.FullName -File -ErrorAction SilentlyContinue | Where-Object { $_.Name.StartsWith($tmpPrefix) } |
                        Sort-Object { [regex]::Replace($_.Name.Substring($tmpPrefix.Length), '\d+', { $args[0].Value.PadLeft(10,'0') }) } |
                        ForEach-Object {
                            $ext = $_.Extension.ToLower()
                            $newName = "{0:D$pad}{1}" -f $idx++, $ext
                            Rename-Item -LiteralPath $_.FullName -NewName $newName -ErrorAction Stop
                        }
                    $imgIdx = $idx
                } else {
                    foreach ($img in $imgs) {
                        $newName = "{0:D3}{1}" -f $imgIdx++, $img.Extension.ToLower()
                        $destFile = Join-Path $destDir.FullName $newName
                        if ($img.FullName -ne $destFile -and -not $DryRun) {
                            Copy-Item -LiteralPath $img.FullName -Destination $destFile -Force
                        }
                    }
                }
            }
            if (-not $finalDirs.Contains($destDir.FullName)) { $finalDirs.Add($destDir.FullName) }
        } elseif ($runPhaseB) {
            foreach ($sourcePath in $orderedVolLeafPaths) {
                Convert-TifToJpg -Path $sourcePath
                Remove-NonImageFiles -Path $sourcePath
                if ($sourcePath -ne $destDirPath) {
                    Write-FlickFitHost "  [リネーム]: $(Split-Path $sourcePath -Leaf)  ->  $finalVolName" -ForegroundColor Yellow
                    if (-not $DryRun) { Rename-Item -LiteralPath $sourcePath -NewName $finalVolName }
                } else { Write-FlickFitHost "  [保持]: $finalVolName" -ForegroundColor Gray }
                if (-not $finalDirs.Contains($destDirPath)) { $finalDirs.Add($destDirPath) }
            }
        } else {
            foreach ($sourcePath in $orderedVolLeafPaths) {
                Convert-TifToJpg -Path $sourcePath
                if (-not $finalDirs.Contains($sourcePath)) { $finalDirs.Add($sourcePath) }
            }
        }
    }

    foreach ($sp in $specialItems) {
        $spSuffix = if ($sp.Suffix) { $sp.Suffix.Trim() } else { "" }
        $finalVolName = if ($combinedBase -and $spSuffix) {
            "$combinedBase $spSuffix"
        } elseif ($combinedBase) {
            $combinedBase
        } else {
            "特別_$spSuffix"
        }
        $destDirPath = Join-Path $outputRootPath $finalVolName
        if ($runPhaseB -and $runPhaseA) {
            Write-FlickFitHost "  [整理中]: $finalVolName (特別短編)" -ForegroundColor Cyan
            $normDest = [System.IO.Path]::GetFullPath($destDirPath)
            $normSource = [System.IO.Path]::GetFullPath($sp.Path)
            if ($normDest -eq $normSource) {
                # コピー先＝ソース同一の場合はスキップ（自身への上書きエラー回避）
                Write-FlickFitHost "      [スキップ]: 既に配置済み" -ForegroundColor DarkGray
                $finalDirs.Add($sp.Path) | Out-Null
            } else {
                $destDir = New-Item -ItemType Directory -Path $destDirPath -Force
                $imgIdx = 1
                Convert-TifToJpg -Path $sp.Path
                $imgs = @(Get-ImagesWithCoverFirst -SourcePath $sp.Path -DirectOnly:$false)
                foreach ($img in $imgs) {
                    $newName = "{0:D3}{1}" -f $imgIdx++, $img.Extension.ToLower()
                    $destFile = Join-Path $destDir.FullName $newName
                    if (-not $DryRun) { Copy-Item -LiteralPath $img.FullName -Destination $destFile -Force }
                }
                $finalDirs.Add($destDir.FullName) | Out-Null
            }
        } elseif ($runPhaseB) {
            Convert-TifToJpg -Path $sp.Path
            Remove-NonImageFiles -Path $sp.Path
            $parentDir = Split-Path $sp.Path -Parent
            $moveDest = Join-Path $parentDir $finalVolName
            if ($sp.Path -ne $moveDest) {
                Write-FlickFitHost "  [リネーム]: $(Split-Path $sp.Path -Leaf)  ->  $finalVolName (特別短編)" -ForegroundColor Yellow
                if (-not $DryRun) { Rename-Item -LiteralPath $sp.Path -NewName $finalVolName }
            }
            $finalDirs.Add($moveDest) | Out-Null
        } else {
            Convert-TifToJpg -Path $sp.Path
            $finalDirs.Add($sp.Path) | Out-Null
        }
    }
    # 巻数検証: 期待される巻数に対してフォルダが不足していないか
    $expectedCount = $volMap.Keys.Count + $specialItems.Count
    if ($finalDirs.Count -lt $expectedCount) {
        $errMsg = "巻が不足しています: 期待 $expectedCount に対して $($finalDirs.Count) 件のみ"
        Update-ProcessLogStep -StepNum 4 -Status "failed" -ErrorMsg $errMsg
        throw $errMsg
    }
    Update-ProcessLogStep -StepNum 4 -Status "success"
    Save-FlickFitProcessCheckpoint -FinalDirs $finalDirs -UnpackRoot $unpackRoot -RunPhaseA $runPhaseA -RunPhaseB $runPhaseB -CombinedBase $combinedBase
    }

    if ($script:ResumeFromStep -ge 5) {
        Write-FlickFitHost "`n  [再開] STEP 1〜4 をスキップし、チェックポイントから再開します" -ForegroundColor Cyan
        $cp = $script:ProcessLog.checkpoint
        if (-not $cp) {
            throw "エラー: STEP 5 再開用のチェックポイントがありません。スクリプトを `-ForceRetry` 付きで最初から実行してください。"
        }
        $fdArr = @()
        if ($cp.PSObject.Properties['finalDirs'] -and $cp.finalDirs) { $fdArr = @($cp.finalDirs) }
        if ($fdArr.Count -eq 0) {
            throw "エラー: チェックポイントに巻フォルダがありません。`-ForceRetry` で最初から実行してください。"
        }
        $runPhaseA = $true
        $runPhaseB = $true
        if ($cp.PSObject.Properties['runPhaseA']) { $runPhaseA = [bool]$cp.runPhaseA }
        if ($cp.PSObject.Properties['runPhaseB']) { $runPhaseB = [bool]$cp.runPhaseB }
        if ($cp.PSObject.Properties['compressionFormat'] -and $cp.compressionFormat) { $CompressionFormat = [string]$cp.compressionFormat }
        if ($cp.PSObject.Properties['outputSubfolder']) { $OutputSubfolder = [string]$cp.outputSubfolder }
        $combinedBase = if ($cp.PSObject.Properties['combinedBase'] -and $null -ne $cp.combinedBase) { [string]$cp.combinedBase } else { '' }
        if ($cp.PSObject.Properties['titleName'] -and $cp.titleName) { $script:TitleName = [string]$cp.titleName }
        $finalDirs = [System.Collections.Generic.List[string]]::new()
        foreach ($p in $fdArr) {
            if ([string]::IsNullOrWhiteSpace($p)) { continue }
            if (-not (Test-Path -LiteralPath $p)) {
                Write-FlickFitHost "  [警告] 存在しないためスキップ: $p" -ForegroundColor Yellow
                continue
            }
            [void]$finalDirs.Add([System.IO.Path]::GetFullPath($p))
        }
        if ($finalDirs.Count -eq 0) {
            throw "エラー: 再開対象の巻フォルダが存在しません。`-ForceRetry` で最初から実行してください。"
        }
        $unpackRoot = $null
        if ($cp.unpackRoot -and (Test-Path -LiteralPath $cp.unpackRoot)) {
            try { $unpackRoot = Get-Item -LiteralPath $cp.unpackRoot } catch { $unpackRoot = $null }
        }
        $script:selectedArchives = @()
        $script:subfolderArchivesToProcess = @()
        if ($cp.PSObject.Properties['selectedArchivePaths'] -and $cp.selectedArchivePaths) {
            $script:selectedArchives = @($cp.selectedArchivePaths | ForEach-Object { $_ })
        }
        if ($cp.PSObject.Properties['subfolderArchivePaths'] -and $cp.subfolderArchivePaths) {
            $script:subfolderArchivesToProcess = @($cp.subfolderArchivePaths | ForEach-Object { $_ })
        }
        $script:selectedExistingFolders = @()
        if ($cp.PSObject.Properties['selectedExistingFolderPaths'] -and $cp.selectedExistingFolderPaths) {
            $script:selectedExistingFolders = @($cp.selectedExistingFolderPaths | ForEach-Object { $_ })
        }
        if ($cp.PSObject.Properties['sourceArchivePathsForDeletion'] -and $cp.sourceArchivePathsForDeletion) {
            $script:SourceArchivePathsForStep7Delete = @($cp.sourceArchivePathsForDeletion | ForEach-Object { [string]$_ })
        } else {
            Set-FlickFitSourceArchivePathsForDeletion -FromArchives $script:selectedArchives -FromSubfolder $script:subfolderArchivesToProcess
        }
    }

    # STEP5: 列挙・処理順を巻番号昇順に固定（チェックポイントの配列順や再開回数に依存しない）
    if ($null -ne $finalDirs -and $finalDirs.Count -gt 1) {
        $sortedFd = Sort-FlickFitStringPathsByVolume -InputPaths @($finalDirs)
        $newFdList = [System.Collections.Generic.List[string]]::new()
        foreach ($p in $sortedFd) { if ($p) { [void]$newFdList.Add([string]$p) } }
        $finalDirs = $newFdList
    }

    # ===== STEP 5: 表紙トリミング → 見開き分割（作業フォルダ版） =====
    if ($runPhaseB) {
        $script:CurrentProcessStepNumber = 5
        Write-Step "STEP 5: 表紙トリミング → 見開き分割"
    
    # 埋め込み trim/split 用 Python: tools\flickfit_worker（TEMP 不使用）。旧仕様のスクリプト横 ts_*.py のみ掃除
    if (-not $script:FlickFitWorkerDir) {
        $srw = $null
        try { $srw = Split-Path -Parent $script:MyInvocation.MyCommand.Path } catch {}
        if ([string]::IsNullOrWhiteSpace($srw)) { $srw = (Get-Location).Path }
        $script:FlickFitWorkerDir = Join-Path (Join-Path $srw "tools") "flickfit_worker"
        if (-not (Test-Path -LiteralPath $script:FlickFitWorkerDir)) { New-Item -ItemType Directory -Path $script:FlickFitWorkerDir -Force | Out-Null }
    }
    $workFolder = $script:FlickFitWorkerDir
    if ($scriptRootForWorker) {
        Get-ChildItem -LiteralPath $scriptRootForWorker -File -ErrorAction SilentlyContinue |
            Where-Object { $_.Name -match '^ts_[0-9a-fA-F]{8}\.py$' } |
            ForEach-Object { Remove-Item -LiteralPath $_.FullName -Force -ErrorAction SilentlyContinue }
    }
    # 日本語パスをPythonへ正しく渡すためUTF-8モードを有効化（Python 3.7+）
    if (-not $env:PYTHONUTF8) { $env:PYTHONUTF8 = "1" }
    
    $totalImages = 0
    foreach ($dir in $finalDirs) {
        $imgCount = @(Get-ChildItem -LiteralPath $dir -File | Where-Object { $script:ImageExtensions -contains $_.Extension.ToLower() }).Count
        $totalImages += $imgCount
    }
    Write-FlickFitHost "`n[開始] 合計画像数: $totalImages 枚`n" -ForegroundColor Cyan
    
    $workTrimSplitPy = Join-Path $workFolder "trim_split_embedded.py"
    $script:WorkTrimSplitPyPath = $workTrimSplitPy
    
    # 余白検出パラメータ（UserConfig.Margin から取得）
    $m = if ($script:UserConfig -and $script:UserConfig.Margin) { $script:UserConfig.Margin } else { $null }
    $marginWhiteMin = if ($m -and $null -ne $m.WhiteMin) { [int]$m.WhiteMin } else { 210 }
    $marginWhiteVariance = if ($m -and $null -ne $m.WhiteVariance) { [int]$m.WhiteVariance } else { 550 }
    $marginLightGrayMin = if ($m -and $null -ne $m.LightGrayMin) { [int]$m.LightGrayMin } else { 140 }
    $marginLightGrayMax = if ($m -and $null -ne $m.LightGrayMax) { [int]$m.LightGrayMax } else { 250 }
    $marginLightGrayVar = if ($m -and $null -ne $m.LightGrayVariance) { [int]$m.LightGrayVariance } else { 800 }
    $marginDarkGrayMin = if ($m -and $null -ne $m.DarkGrayMin) { [int]$m.DarkGrayMin } else { 30 }
    $marginDarkGrayMax = if ($m -and $null -ne $m.DarkGrayMax) { [int]$m.DarkGrayMax } else { 210 }
    $marginDarkGrayVar = if ($m -and $null -ne $m.DarkGrayVariance) { [int]$m.DarkGrayVariance } else { 800 }
    $marginDarkGrayUniform = if ($m -and $null -ne $m.DarkGrayUniformity) { [double]$m.DarkGrayUniformity } else { 0.75 }
    $marginSideEdgeExclude = if ($m -and $null -ne $m.SideSampleEdgeExclude) { [double]$m.SideSampleEdgeExclude } else { 0.12 }
    $aspectMinSkipDarkBorders = if ($m -and $null -ne $m.AspectMinSkipForDarkBorders) { $m.AspectMinSkipForDarkBorders -eq $true } else { $true }
    
    $coverCenterCropEnabled = if ($script:UserConfig -and $null -ne $script:UserConfig.CoverCenterCropEnabled) { $script:UserConfig.CoverCenterCropEnabled -eq $true } else { $true }
    $coverCenterCropDarkThresh = if ($script:UserConfig -and $null -ne $script:UserConfig.CoverCenterCropDarkThresh) { [int]$script:UserConfig.CoverCenterCropDarkThresh } else { 85 }
    
    $cm = if ($m -and $m.ColorMargin) { $m.ColorMargin } else { $null }
    $colorMarginEnabled = if ($cm -and $null -ne $cm.Enabled) { $cm.Enabled -eq $true } else { $false }
    $colorMarginHueMin = if ($cm -and $null -ne $cm.HueMin) { [float]$cm.HueMin } else { 5 }
    $colorMarginHueMax = if ($cm -and $null -ne $cm.HueMax) { [float]$cm.HueMax } else { 45 }
    $colorMarginSatMax = if ($cm -and $null -ne $cm.SaturationMax) { [float]$cm.SaturationMax } else { 85 }
    $colorMarginUniform = if ($cm -and $null -ne $cm.Uniformity) { [float]$cm.Uniformity } else { 0.88 }
    
    #region Embedded Python worker (trim_split)
    # 役割:
    #   トリム・分割・見開き処理を行う埋め込み Python ソースを here-string で組み立てる。
    # 主役:
    #   $trimSplitCode（一時 .py へ Set-Content）
    # 注意:
    #   直前の UserConfig / スクリプト変数が文字列に展開される。Python 側と PS1 の既定を変えるときは両方を確認。
    $trimSplitCode = @"
import sys
from PIL import Image, ImageOps
import os
import time
import json
import colorsys
from concurrent.futures import ProcessPoolExecutor, as_completed

# PermissionError対策: ファイルロック解除待ちでリトライ
def _safe_remove(path, max_retries=5):
    for attempt in range(max_retries):
        try:
            os.remove(path)
            return
        except PermissionError:
            if attempt < max_retries - 1:
                time.sleep(0.3 * (attempt + 1))
            else:
                raise

# 並列処理: コアの半分を使用（他アプリの負荷軽減）
def _max_workers():
    import multiprocessing
    n = getattr(multiprocessing, 'cpu_count', lambda: 4)()
    return max(1, n // 2)

# カラー余白検出（UserConfig.Margin.ColorMargin）
COLOR_MARGIN_ENABLED = $colorMarginEnabled
ASPECT_MIN_SKIP_DARK_BORDERS = $aspectMinSkipDarkBorders
COVER_CENTER_CROP_ENABLED = $coverCenterCropEnabled
COVER_CENTER_CROP_DARK_THRESH = $coverCenterCropDarkThresh
COLOR_MARGIN_HUE_MIN = $colorMarginHueMin
COLOR_MARGIN_HUE_MAX = $colorMarginHueMax
COLOR_MARGIN_SAT_MAX = $colorMarginSatMax / 100.0
COLOR_MARGIN_UNIFORMITY = $colorMarginUniform

# 幾何デバッグ（$script:FlickFitDebugPythonGeometry=True のときだけ stdout に出す。通常運用では抑止）
FLICKFIT_DEBUG_GEOMETRY = $($true -eq $script:FlickFitDebugPythonGeometry)
def _dbg_geom(*args, **kwargs):
    if not FLICKFIT_DEBUG_GEOMETRY:
        return
    if "flush" not in kwargs:
        kwargs["flush"] = True
    print(*args, **kwargs)

def get_gray(pixel):
    if isinstance(pixel, tuple) and len(pixel) >= 3:
        r, g, b = pixel[:3]
    else:
        r = g = b = pixel
    return (int(r) + int(g) + int(b)) // 3

def content_score_band(img, x_start, x_end):
    """左右の領域ごとのコンテンツ量（変化の多さ）をスコア化"""
    w, h = img.size
    if x_end <= x_start:
        return 0.0
    step = max(1, (x_end - x_start) // 40)
    y_step = max(1, h // 30)
    total_diff = 0
    count = 0
    for x in range(x_start, min(x_end, w), step):
        for y in range(0, h, y_step):
            g = get_gray(img.getpixel((x, y)))
            if x + 1 < w:
                g_r = get_gray(img.getpixel((x + 1, y)))
                total_diff += abs(g - g_r)
                count += 1
            if y + 1 < h:
                g_d = get_gray(img.getpixel((x, y + 1)))
                total_diff += abs(g - g_d)
                count += 1
    return total_diff / count if count else 0.0

def get_half_content_score(img, x_start, x_end, h):
    """指定範囲のコンテンツスコアを計算（非背景ピクセルの割合）"""
    w = img.size[0]
    margin_y = h // 12
    
    total_pixels = 0
    content_pixels = 0
    
    step_x = max(1, (x_end - x_start) // 60)
    step_y = max(1, h // 60)
    
    for x in range(x_start, x_end, step_x):
        for y in range(margin_y, h - margin_y, step_y):
            gray = get_gray(img.getpixel((x, y)))
            total_pixels += 1
            # 白〜薄グレー(>=200)でも黒(<10)でもないピクセルをコンテンツとみなす
            # 200以上の明るい色は余白（白・薄グレー）として扱う
            if 10 <= gray < 200:
                content_pixels += 1
    
    return content_pixels / total_pixels if total_pixels > 0 else 0

def get_half_variance(img, x_start, x_end, h):
    """指定範囲の輝度分散を計算（コンテンツがあると分散が大きい）"""
    margin_y = h // 12
    
    values = []
    step_x = max(1, (x_end - x_start) // 40)
    step_y = max(1, h // 40)
    
    for x in range(x_start, x_end, step_x):
        for y in range(margin_y, h - margin_y, step_y):
            gray = get_gray(img.getpixel((x, y)))
            values.append(gray)
    
    if len(values) < 2:
        return 0
    
    mean = sum(values) / len(values)
    variance = sum((v - mean) ** 2 for v in values) / len(values)
    return variance

def get_half_entropy(img, x_start, x_end, h):
    """指定範囲の輝度エントロピーを計算（コンテンツがあるとエントロピーが高い）"""
    import math
    margin_y = h // 12
    hist = [0] * 256
    step_x = max(1, (x_end - x_start) // 40)
    step_y = max(1, h // 40)
    
    for x in range(x_start, x_end, step_x):
        for y in range(margin_y, h - margin_y, step_y):
            gray = get_gray(img.getpixel((x, y)))
            hist[min(255, max(0, int(gray)))] += 1
    
    n = sum(hist)
    if n < 2:
        return 0.0
    entropy = 0.0
    for cnt in hist:
        if cnt > 0:
            p = cnt / n
            entropy -= p * math.log2(p)
    return entropy

def get_bright_ratio(img, x_start, x_end, h):
    """指定範囲の明るいピクセル（白〜薄グレー）の割合を計算"""
    margin_y = h // 12
    total = 0
    bright = 0
    step_x = max(1, (x_end - x_start) // 50)
    step_y = max(1, h // 50)
    
    for x in range(x_start, x_end, step_x):
        for y in range(margin_y, h - margin_y, step_y):
            gray = get_gray(img.getpixel((x, y)))
            total += 1
            if gray >= 200:  # 白〜薄グレー
                bright += 1
    
    return bright / total if total > 0 else 0

def _band_density_score(img_rgb, x_center, band_w, h):
    """縦 band の情報密度スコア（エッジ強度＋テクスチャ＋輝度分散）"""
    w = img_rgb.size[0]
    x0 = max(0, x_center - band_w // 2)
    x1 = min(w, x_center + band_w // 2 + 1)
    if x1 <= x0:
        return 0.0
    margin_y = max(1, h // 12)
    y0, y1 = margin_y, h - margin_y
    step_y = max(1, (y1 - y0) // 25)
    step_x = max(1, (x1 - x0) // 4)
    edges = []
    grays = []
    for x in range(x0, x1, step_x):
        for y in range(y0, y1, step_y):
            g = get_gray(img_rgb.getpixel((x, y)))
            grays.append(g)
            if x + 1 < w:
                g_r = get_gray(img_rgb.getpixel((x + 1, y)))
                edges.append(abs(g - g_r))
            if y + 1 < h:
                g_d = get_gray(img_rgb.getpixel((x, y + 1)))
                edges.append(abs(g - g_d))
    edge_score = sum(edges) / len(edges) if edges else 0
    if len(grays) < 2:
        return edge_score
    mean_g = sum(grays) / len(grays)
    variance = sum((v - mean_g) ** 2 for v in grays) / len(grays)
    return edge_score + variance * 0.02  # 正規化して合成

def _find_safe_bounds_density(img_rgb, w, h, margin_px):
    """端から中央へスキャンし、情報密度が急上昇するポイントを検出。削らない安全領域を返す。"""
    band_w = max(4, w // 120)
    half = w // 2
    scores_left = []
    scores_right = []
    for i in range(0, half, max(1, band_w // 2)):
        s = _band_density_score(img_rgb, i, band_w, h)
        scores_left.append((i, s))
    for i in range(w - 1, half - 1, -max(1, band_w // 2)):
        s = _band_density_score(img_rgb, i, band_w, h)
        scores_right.append((i, s))
    if len(scores_left) < 2 or len(scores_right) < 2:
        return 0, w
    first_slice = len(scores_left) // 4
    last_slice = max(1, len(scores_right) // 4)
    mid_scores = [s for _, s in scores_left[first_slice:]] + [s for _, s in scores_right[:-last_slice]]
    if not mid_scores:
        return 0, w
    thresh = max(sum(mid_scores) / len(mid_scores) * 0.5, 15.0)  # 余白は密度低い
    safe_left = 0
    for i, (x, s) in enumerate(scores_left):
        if i > 0 and s > thresh and (s - scores_left[i - 1][1]) > 2:
            safe_left = max(0, x - margin_px)
            break
        elif s > thresh:
            safe_left = max(0, x - margin_px)
            break
    safe_right = w
    for i, (x, s) in enumerate(scores_right):
        if i > 0 and s > thresh and (s - scores_right[i - 1][1]) > 2:
            safe_right = min(w, x + margin_px + 1)
            break
        elif s > thresh:
            safe_right = min(w, x + margin_px + 1)
            break
    return safe_left, safe_right

def _compute_trim_metrics(img_rgb, left, top, right, bottom):
    """トリミング後のエッジ総量・輝度分散を計算（ロールバック判定用）"""
    w, h = img_rgb.size[0], img_rgb.size[1]
    if right <= left or bottom <= top:
        return 0, 0
    step = max(1, min(right - left, bottom - top) // 30)
    edges = 0
    grays = []
    for x in range(left, right, step):
        for y in range(top, bottom, step):
            if x < w and y < h:
                g = get_gray(img_rgb.getpixel((x, y)))
                grays.append(g)
                if x + 1 < w:
                    g_r = get_gray(img_rgb.getpixel((x + 1, y)))
                    edges += abs(g - g_r)
                if y + 1 < h:
                    g_d = get_gray(img_rgb.getpixel((x, y + 1)))
                    edges += abs(g - g_d)
    var = 0
    if len(grays) >= 2:
        mean_g = sum(grays) / len(grays)
        var = sum((v - mean_g) ** 2 for v in grays) / len(grays)
    return edges, var

def _check_over_trim_rollback(img_rgb, w, h, left, top, right, bottom):
    """削りすぎ検知: トリミング後メトリクスが低下していたら +10px ロールバック"""
    if right - left < 100 or bottom - top < 100:
        return left, top, right, bottom
    edges_trim, var_trim = _compute_trim_metrics(img_rgb, left, top, right, bottom)
    edges_full, var_full = _compute_trim_metrics(img_rgb, 0, 0, w, h)
    if edges_full < 1:
        return left, top, right, bottom
    edge_ratio = edges_trim / edges_full
    var_ratio = var_trim / var_full if var_full > 10 else 1.0
    if edge_ratio < 0.6 or var_ratio < 0.5:
        roll = 10
        left = max(0, left - roll)
        right = min(w, right + roll)
    return left, top, right, bottom

def detect_safe_trim_bounds(img_path, aspect_min=0.0, max_trim_x=None, max_trim_y=None, min_crop_ratio=0.5):
    """【削らない安全領域】情報密度スコアで端から中央へ急上昇ポイントを探し、マージン max(1%幅, 8px) で安全境界を返す。"""
    img = Image.open(img_path)
    img_rgb = img.convert("RGB")
    w, h = img.size
    margin_px = max(int(w * 0.01), 8)
    safe_left, safe_right = _find_safe_bounds_density(img_rgb, w, h, margin_px)
    margin_y = max(int(h * 0.03), 15)
    safe_top = margin_y
    safe_bottom = h - margin_y
    left = safe_left
    right = safe_right
    top = safe_top
    bottom = safe_bottom
    max_tx = max_trim_x if max_trim_x is not None else min(w // 2, 600)
    left = min(left, max_tx)
    right = max(right, w - max_tx)
    if (right - left) < w * min_crop_ratio or (bottom - top) < h * min_crop_ratio:
        img_rgb.close()
        img.close()
        return (0, 0, w, h)
    left, top, right, bottom = _check_over_trim_rollback(img_rgb, w, h, left, top, right, bottom)
    if aspect_min > 0:
        left, top, right, bottom = _apply_aspect_min(left, top, right, bottom, w, h, aspect_min, img_rgb)
    img_rgb.close()
    img.close()
    return (left, top, right, bottom)

# is_one_sided: 全画素の原寸RGBは重い。長辺を縮小してから左右半分のスコア計算
# 環境変数 FLICK_FIT_ANALYZE_MAX_LONG（既定 768、0=縮小なし） / FLICK_FIT_ANALYZE_PROFILE=1 で数件分 stderr に計測
# 縦向き納品の横見開き: FLICK_FIT_TYPICAL_SINGLE_WIDTH が与えられ短辺 w >= 基準×1.25 付近のとき 90 度回転して左右を評価
_one_sided_prof_n = 0

def _one_sided_rotate_resample():
    R = Image
    if hasattr(Image, "Resampling"):
        return Image.Resampling.BICUBIC
    return getattr(R, "BICUBIC", 3)

def _maybe_rotate_portrait_for_rotated_spread(img):
    """縦長で短辺が単ページ比で広い場合は 90 度回転（横見開きが縦 Jpeg に入っている想定）。"""
    w, h = img.size
    if h <= w or w <= 0:
        return img, False
    tsw = 0
    try:
        tsw = int(str(os.environ.get("FLICK_FIT_TYPICAL_SINGLE_WIDTH", "0") or "0").strip() or 0)
    except (ValueError, TypeError):
        tsw = 0
    if tsw > 0:
        need = w >= tsw * 1.25
    else:
        try:
            need = w >= int(os.environ.get("FLICK_FIT_PORTRAIT_MIN_W", "1280"))
        except (ValueError, TypeError):
            need = w >= 1280
    if not need:
        return img, False
    r = img.rotate(90, expand=True, resample=_one_sided_rotate_resample())
    try:
        img.close()
    except Exception:
        pass
    return r.convert("RGB"), True

def _load_rgb_for_one_sided_analyze(img_path):
    t_all0 = time.perf_counter()
    img = Image.open(img_path)
    try:
        try:
            img = ImageOps.exif_transpose(img)
        except Exception:
            pass
        ow, oh = img.size
        t_after_open = time.perf_counter()
        try:
            max_long = int(os.environ.get("FLICK_FIT_ANALYZE_MAX_LONG", "768"))
        except (ValueError, TypeError):
            max_long = 768
        if max_long > 0 and max(ow, oh) > max_long:
            r = max_long / float(max(ow, oh))
            nw = max(1, int(round(ow * r)))
            nh = max(1, int(round(oh * r)))
            img = img.resize((nw, nh), getattr(Image, "Resampling", Image).LANCZOS)
        rgb = img.convert("RGB")
        t_ready = time.perf_counter()
        return rgb, (t_all0, t_after_open, t_ready, ow, oh)
    except Exception:
        try:
            img.close()
        except Exception:
            pass
        raise

def is_one_sided(img_path):
    """片側のみコンテンツがある見開きかどうか判定。コンテンツ密度と分散を組み合わせる。"""
    global _one_sided_prof_n
    prof_e = str(os.environ.get("FLICK_FIT_ANALYZE_PROFILE", "")).lower() in ("1", "true", "yes", "on")
    img, times = _load_rgb_for_one_sided_analyze(img_path)
    t_all0, t_after_open, t_ready, ow, oh = times
    img, _didRot = _maybe_rotate_portrait_for_rotated_spread(img)
    try:
        w, h = img.size
        half = w // 2
        margin_x = w // 20
        # 左半分と右半分のコンテンツスコアを計算
        left_score = get_half_content_score(img, margin_x, half, h)
        right_score = get_half_content_score(img, half, w - margin_x, h)
        # 左半分と右半分の輝度エントロピーを計算（コンテンツがあるとエントロピーが高い）
        left_ent = get_half_entropy(img, margin_x, half, h)
        right_ent = get_half_entropy(img, half, w - margin_x, h)
        # 左半分と右半分の明るい領域（白〜薄グレー）の割合を計算
        left_bright = get_bright_ratio(img, margin_x, half, h)
        right_bright = get_bright_ratio(img, half, w - margin_x, h)
    finally:
        try:
            img.close()
        except Exception:
            pass
    # コンテンツスコア閾値（10%以上の中間色ピクセル）
    score_threshold = 0.10
    # エントロピー閾値（漫画コマがあると通常3.0以上、余白は0〜2程度）
    entropy_threshold = 3.0
    # 明るい領域の閾値（88%以上が白〜薄グレーなら余白とみなす。少女漫画等は明るい背景でも80%超になりやすいため緩和）
    bright_threshold = 0.88
    
    # コンテンツ判定：スコアまたはエントロピーが閾値以上、かつ明るい領域が80%未満
    left_has_content = ((left_score >= score_threshold) or (left_ent >= entropy_threshold)) and (left_bright < bright_threshold)
    right_has_content = ((right_score >= score_threshold) or (right_ent >= entropy_threshold)) and (right_bright < bright_threshold)
    # 淡い色（薄い装飾模様等）: 片側がエントロピー2.5以上かつ明るい時はBALANCED扱い（誤検出防止）
    faint_ent_min, faint_bright_min = 2.5, 0.92
    left_faint = (left_ent >= faint_ent_min) and (left_bright >= faint_bright_min) and (left_score < score_threshold)
    right_faint = (right_ent >= faint_ent_min) and (right_bright >= faint_bright_min) and (right_score < score_threshold)
    if left_faint or right_faint:
        left_has_content = left_has_content or left_faint
        right_has_content = right_has_content or right_faint
    # デバッグ出力
    _dbg_geom(f"DEBUG: L_score={left_score:.2f} R_score={right_score:.2f} L_ent={left_ent:.2f} R_ent={right_ent:.2f} L_bright={left_bright:.2f} R_bright={right_bright:.2f}")
    t_end = time.perf_counter()
    if prof_e and _one_sided_prof_n < 4:
        _one_sided_prof_n += 1
        print(
            "[ANALYZE_PROF] open_ms=%.1f prep_ms=%.1f infer_ms=%.1f orig=%dx%d out=%dx%d rot90_for_spread=%s" % (
                (t_after_open - t_all0) * 1000,
                (t_ready - t_after_open) * 1000,
                (t_end - t_ready) * 1000,
                ow, oh, w, h, str(_didRot),
            ),
            file=sys.stderr,
            flush=True,
        )
    if left_has_content and right_has_content:
        return "BALANCED"
    else:
        return "ONE_SIDED"

def _band_v_edge_strength_rough(img, x0, x1, w, h):
    """縦帯 [x0,x1) 内の左右隣接差分の粗い平均。ノド帯は紙抜きで低く出やすい。"""
    s, n = 0.0, 0
    y_step = max(1, h // 36)
    x0 = max(0, int(x0))
    x1 = min(w, int(x1))
    if x1 - x0 < 2:
        return 0.0
    x_step = max(1, (x1 - x0) // 4)
    for y in range(0, h, y_step):
        for x in range(x0, x1 - 1, x_step):
            g0 = get_gray(img.getpixel((x, y)))
            g1 = get_gray(img.getpixel((x + 1, y)))
            s += abs(g0 - g1)
            n += 1
    return s / n if n else 0.0

def assess_center_split_misread_risk(img_path):
    """
    見開き風解像度だが中央にノドが取れない／片側スカスカ／左右スコアの極端差 → 真ん中2分割で壊しやすい。
    戻り: RISK_OK（通常どおり2分割可）/ RISK_SKIP_CENTER_SPLIT
    無効: 環境変数 FLICK_FIT_DISABLE_CENTER_SPLIT_RISK=1
    """
    if str(os.environ.get("FLICK_FIT_DISABLE_CENTER_SPLIT_RISK", "")).lower() in ("1", "true", "yes", "on"):
        return "RISK_OK"
    img = None
    try:
        img, _t = _load_rgb_for_one_sided_analyze(img_path)
        img, _d = _maybe_rotate_portrait_for_rotated_spread(img)
        w, h = img.size
        if w < 200 or h < 200:
            return "RISK_OK"
        ml = w // 20
        half = w // 2
        lsc = get_half_content_score(img, ml, half, h)
        rsc = get_half_content_score(img, half, w - ml, h)
        lbr = get_bright_ratio(img, ml, half, h)
        rbr = get_bright_ratio(img, half, w - ml, h)
        mx = max(lsc, rsc) + 1e-9
        mn = min(lsc, rsc)
        ratio = mn / mx
        c0, c1 = int(w * 0.45), int(w * 0.55)
        center_e = _band_v_edge_strength_rough(img, c0, c1, w, h)
        lref = _band_v_edge_strength_rough(img, w // 8, max(w // 8 + 1, w // 2 - 2), w, h)
        rref = _band_v_edge_strength_rough(img, min(half + 2, w - 2), w - w // 8, w, h)
        refm = (lref + rref) * 0.5 + 1e-9
        if refm < 1e-6:
            return "RISK_OK"
        # 最左右が明るい大余白＋中央帯に本文：見開き解像度の「中央1枚ページ」を中央で割る誤答対策
        strip = max(8, w // 10)
        edgeL = get_bright_ratio(img, 0, strip, h)
        edgeR = get_bright_ratio(img, w - strip, w, h)
        cx0, cx1 = int(w * 0.32), int(w * 0.68)
        mid_c = get_half_content_score(img, cx0, cx1, h)
        if (
            edgeL > 0.86
            and edgeR > 0.86
            and mid_c > 0.10
            and (lsc > 0.04 and rsc > 0.04)
            and ratio > 0.30
        ):
            _dbg_geom(
                f"center_split_risk: SKIP centered_single eL={edgeL:.2f} eR={edgeR:.2f} mid={mid_c:.3f} ratio={ratio:.2f} L={lsc:.3f} R={rsc:.3f}"
            )
            return "RISK_SKIP_CENTER_SPLIT"
        # 本当のノド: 中央帯のエッジ活動が左右ページ内より著しく低い
        no_gutter = center_e > 0.5 * refm
        # 片側がほぼ紙抜き（BALANCED のすり抜け対策）
        sparse_side = (min(lsc, rsc) < 0.045 and max(lsc, rsc) > 0.1) or (
            min(lbr, rbr) > 0.94 and max(lsc, rsc) > 0.12 and min(lsc, rsc) < 0.08
        )
        extreme_imbal = ratio < 0.16
        if extreme_imbal or sparse_side:
            _dbg_geom(f"center_split_risk: SKIP ext_imbal={extreme_imbal} sparse={sparse_side} L={lsc:.3f} R={rsc:.3f} ce/cref={center_e / refm:.2f}")
            return "RISK_SKIP_CENTER_SPLIT"
        if no_gutter and ratio < 0.42:
            _dbg_geom(f"center_split_risk: SKIP no_gutter ratio={ratio:.3f} L={lsc:.3f} R={rsc:.3f} ce/cref={center_e / refm:.2f}")
            return "RISK_SKIP_CENTER_SPLIT"
        if no_gutter and ratio < 0.55 and (lbr > 0.9 or rbr > 0.9):
            return "RISK_SKIP_CENTER_SPLIT"
    except Exception:
        return "RISK_OK"
    finally:
        try:
            if img is not None:
                img.close()
        except Exception:
            pass
    return "RISK_OK"

def _get_one_sided_content_side(img_path):
    """片側コンテンツ時にコンテンツが左か右かを返す。'left' | 'right'（判定は is_one_sided と同じ縮小・回転経路）"""
    img, _ = _load_rgb_for_one_sided_analyze(img_path)
    img, _ = _maybe_rotate_portrait_for_rotated_spread(img)
    try:
        w, h = img.size
        half = w // 2
        margin_x = w // 20
        left_score = get_half_content_score(img, margin_x, half, h)
        right_score = get_half_content_score(img, half, w - margin_x, h)
        left_ent = get_half_entropy(img, margin_x, half, h)
        right_ent = get_half_entropy(img, half, w - margin_x, h)
        left_bright = get_bright_ratio(img, margin_x, half, h)
        right_bright = get_bright_ratio(img, half, w - margin_x, h)
    finally:
        try:
            img.close()
        except Exception:
            pass
    score_threshold, entropy_threshold, bright_threshold = 0.10, 3.0, 0.80
    faint_ent_min, faint_bright_min = 2.5, 0.92
    left_has_content = ((left_score >= score_threshold) or (left_ent >= entropy_threshold)) and (left_bright < bright_threshold)
    right_has_content = ((right_score >= score_threshold) or (right_ent >= entropy_threshold)) and (right_bright < bright_threshold)
    left_faint = (left_ent >= faint_ent_min) and (left_bright >= faint_bright_min) and (left_score < score_threshold)
    right_faint = (right_ent >= faint_ent_min) and (right_bright >= faint_bright_min) and (right_score < score_threshold)
    if left_faint or right_faint:
        left_has_content = left_has_content or left_faint
        right_has_content = right_has_content or right_faint
    if left_has_content and not right_has_content:
        return 'left'
    if right_has_content and not left_has_content:
        return 'right'
    return 'left'  # fallback

USE_STRICT_WHITE_FOR_COVER = False  # cover_trim 時のみ True にし、白・淡色の誤検出を抑える

def _is_margin_pixels(pixels):
    """白・グレー・濃いグレー余白を検出。均一な領域を余白とする。淡い色（200-255）も余白扱い。
    ウォーターマーク（白地に薄い文字）: 88%以上が明るく暗ピクセル15%以下なら余白扱い。
    表紙モード(USE_STRICT_WHITE_FOR_COVER): 白背景・白い髪・薄い模様を誤って余白にしないよう厳格化。"""
    if len(pixels) < 3:
        return False
    avg = sum(pixels) / len(pixels)
    variance = sum((x - avg) ** 2 for x in pixels) / len(pixels)
    dark_count = sum(1 for x in pixels if x <= 50)
    bright_count = sum(1 for x in pixels if x >= $marginWhiteMin)
    bright_count_200 = sum(1 for x in pixels if x >= 200)
    faint_count = sum(1 for x in pixels if x >= 195) / len(pixels)
    faint_count2 = sum(1 for x in pixels if x >= 185) / len(pixels)
    mid_light_uniform = sum(1 for x in pixels if $marginLightGrayMin <= x <= $marginLightGrayMax) / len(pixels)
    dark_gray_uniform = sum(1 for x in pixels if $marginDarkGrayMin <= x <= $marginDarkGrayMax) / len(pixels)
    is_black = (avg <= 50) or (dark_count / len(pixels) >= 0.80)
    if USE_STRICT_WHITE_FOR_COVER:
        is_white = (avg >= 238) and (variance < 180) and (bright_count / len(pixels) >= 0.92)
        is_faint = ((avg >= 235) and (variance < 250) and (faint_count >= 0.90)) or ((avg >= 232) and (variance < 320) and (faint_count2 >= 0.88))
        is_watermark_white = (avg >= 192) and (bright_count_200 / len(pixels) >= 0.88) and (dark_count / len(pixels) <= 0.15)
    else:
        is_white = (avg >= $marginWhiteMin) and (variance < $marginWhiteVariance) and (bright_count / len(pixels) >= 0.85)
        is_watermark_white = (avg >= 190) and (bright_count_200 / len(pixels) >= 0.85) and (dark_count / len(pixels) <= 0.20)
        is_faint = ((avg >= 200) and (variance < 600) and (faint_count >= 0.80)) or ((avg >= 190) and (variance < 900) and (faint_count2 >= 0.75))
    is_light_gray = ($marginLightGrayMin <= avg <= $marginLightGrayMax) and (variance < $marginLightGrayVar) and (mid_light_uniform >= 0.92)
    is_dark_gray = ($marginDarkGrayMin <= avg <= $marginDarkGrayMax) and (variance < $marginDarkGrayVar) and (dark_gray_uniform >= $marginDarkGrayUniform)
    return is_black or is_white or is_watermark_white or is_faint or is_light_gray or is_dark_gray

def _has_significant_color(pixels_rgb):
    """彩度が高い領域は装飾枠（緑枠等）とみなし、余白トリミングから除外"""
    if len(pixels_rgb) < 3:
        return False
    sats = []
    for p in pixels_rgb:
        r, g, b = p[0] / 255.0, p[1] / 255.0, p[2] / 255.0
        _, s, _ = colorsys.rgb_to_hsv(r, g, b)
        sats.append(s)
    avg_sat = sum(sats) / len(sats)
    return avg_sat > 0.12  # 彩度12%超は色付き装飾とみなす

def _is_color_margin_pixels(pixels_rgb):
    """均一な色相範囲のピクセル群を余白と判定（一部ウォーターマーク対応）"""
    if not COLOR_MARGIN_ENABLED or len(pixels_rgb) < 3:
        return False
    in_range = 0
    hues = []
    for p in pixels_rgb:
        r, g, b = p[0] / 255.0, p[1] / 255.0, p[2] / 255.0
        h, s, v = colorsys.rgb_to_hsv(r, g, b)
        h_deg = h * 360.0
        if COLOR_MARGIN_HUE_MIN <= h_deg <= COLOR_MARGIN_HUE_MAX and s <= COLOR_MARGIN_SAT_MAX:
            in_range += 1
        hues.append((h_deg, s, v))
    if in_range / len(pixels_rgb) < COLOR_MARGIN_UNIFORMITY:
        return False
    avg_h = sum(x[0] for x in hues) / len(hues)
    var_h = sum((x[0] - avg_h) ** 2 for x in hues) / len(hues)
    if var_h > 900:
        return False
    return True

def _check_margin(pixels_gray, pixels_rgb):
    """グレースケール＋カラー余白を統合判定。彩度の高い装飾枠（緑枠等）はトリミングしない"""
    if _has_significant_color(pixels_rgb):
        return False  # 色付き装飾は余白扱いにしない
    if _is_margin_pixels(pixels_gray):
        return True
    if COLOR_MARGIN_ENABLED and _is_color_margin_pixels(pixels_rgb):
        return True
    return False

def _find_dark_bar_edges(img_rgb, w, h, dark_thresh=85, content_thresh=80, run_len=5):
    """左右の濃いグレー帯の内側（コンテンツ開始位置）をスキャンで検出。
    グレー(avg~51)とコンテンツの境界を、content_thresh超の連続列で検出。ウォーターマーク回避で上下25%除外。"""
    y_margin = max(1, int(h * 0.25))
    y_top, y_bottom = y_margin, h - y_margin
    step_y = max(1, (y_bottom - y_top) // 15)
    x_step = max(1, w // 250)

    def col_avg(x):
        total, n = 0, 0
        for y in range(y_top, y_bottom, step_y):
            p = img_rgb.getpixel((x, y))
            total += (p[0] + p[1] + p[2]) // 3
            n += 1
        return total / n if n else 0

    left_edge = 0
    consec = 0
    for x in range(0, min(w, w // 2 + 300), x_step):
        avg = col_avg(x)
        if avg >= content_thresh:
            consec += 1
            if consec >= run_len:
                left_edge = max(0, x - (run_len - 1) * x_step)
                break
        else:
            consec = 0
        left_edge = x + x_step

    right_edge = w
    consec = 0
    for x in range(w - 1, max(0, w // 2 - 300), -x_step):
        avg = col_avg(x)
        if avg >= content_thresh:
            consec += 1
            if consec >= run_len:
                right_edge = min(w, x + run_len * x_step)
                break
        else:
            consec = 0
        right_edge = x
    return left_edge, right_edge

def _side_has_dark_content(img_rgb, w, h, side='right', portion=0.25, dark_thresh=150, sample_ratio=0.015):
    """端付近に暗いピクセル（タイトル・巻数など）が十分あるか。あれば白余白補正をスキップする。
    黒いピラーボックス（全体が暗い領域）は「保護するコンテンツ」とはみなさず False を返す。
    side: 'left' なら左端、'right' なら右端をチェック。"""
    if w < 50 or h < 50:
        return False
    if side == 'left':
        x_start, x_end = 0, min(w, int(w * portion))
    else:
        x_start, x_end = max(0, int(w * (1 - portion))), w
    dark_count, bright_count, total, gray_sum = 0, 0, 0, 0
    step_x = max(2, (x_end - x_start) // 25)
    step_y = max(2, h // 30)
    for x in range(x_start, x_end, step_x):
        for y in range(0, h, step_y):
            p = img_rgb.getpixel((x, y))
            g = (p[0] + p[1] + p[2]) // 3
            gray_sum += g
            if g < dark_thresh:
                dark_count += 1
            if g > 200:
                bright_count += 1
            total += 1
    if total == 0:
        return False
    avg_gray = gray_sum / total
    bright_ratio = bright_count / total
    dark_ratio = dark_count / total
    # 黒ピラーボックス: 全体が暗い（平均<90 かつ 明るいピクセル<15%）→ トリミングしてよい
    if avg_gray < 90 and bright_ratio < 0.15:
        return False
    return dark_ratio >= sample_ratio

def _right_side_has_dark_content(img_rgb, w, h, portion=0.25, dark_thresh=150, sample_ratio=0.015):
    return _side_has_dark_content(img_rgb, w, h, side='right', portion=portion, dark_thresh=dark_thresh, sample_ratio=sample_ratio)

def _left_side_has_dark_content(img_rgb, w, h, portion=0.25, dark_thresh=150, sample_ratio=0.015):
    return _side_has_dark_content(img_rgb, w, h, side='left', portion=portion, dark_thresh=dark_thresh, sample_ratio=sample_ratio)

def _adjust_right_edge_for_white_margin(img_rgb, w, h, left_edge, right_edge, white_thresh=240, min_white_run=25, y_margin_ratio=0.25, safety_margin=80):
    """左寄り表紙＋右側広い白余白のとき、right_edge を白余白の手前まで縮める。
    dark_bar_trim で白領域をコンテンツと誤認した場合の補正。右端から左へスキャンし、
    十分な白連続の後に非白（コンテンツ）が見つかった位置をコンテンツ右端とする。
    右端にタイトル・巻数などの暗いテキストがあれば補正をスキップ（削りすぎ防止）。"""
    if _right_side_has_dark_content(img_rgb, w, h, portion=0.20, dark_thresh=130, sample_ratio=0.03):
        return right_edge
    content_w = right_edge - left_edge
    if content_w < w * 0.5:
        return right_edge
    y_margin = max(1, int(h * y_margin_ratio))
    y_top, y_bottom = y_margin, h - y_margin
    step_y = max(1, (y_bottom - y_top) // 15)
    x_step = max(2, w // 250)

    def col_avg(x):
        total, n = 0, 0
        for y in range(y_top, y_bottom, step_y):
            p = img_rgb.getpixel((x, y))
            total += (p[0] + p[1] + p[2]) // 3
            n += 1
        return total / n if n else 0

    white_count = 0
    for x in range(right_edge - 1, max(left_edge - 1, right_edge - (w * 3 // 4)), -x_step):
        avg = col_avg(x)
        if avg >= white_thresh:
            white_count += 1
        else:
            if white_count >= min_white_run:
                new_right = x + 1
                if (new_right - left_edge) >= int(w * 0.15):
                    # 境界を右に余裕を持たせ、表紙コンテンツの切りすぎを防ぐ
                    return min(new_right + safety_margin, right_edge)
            white_count = 0
    return right_edge

def _adjust_left_edge_for_white_margin(img_rgb, w, h, left_edge, right_edge, white_thresh=240, min_white_run=25, y_margin_ratio=0.25, safety_margin=80):
    """右寄り表紙＋左側広い白余白のとき、left_edge を白余白の直後まで伸ばす。
    dark_bar_trim で白領域をコンテンツと誤認した場合の補正。左端から右へスキャンし、
    十分な白連続の後に非白（コンテンツ）が見つかった位置をコンテンツ左端とする。
    左端にタイトル・巻数などの暗いテキストがあれば補正をスキップ（削りすぎ防止）。
    safety_margin: 境界を左に余裕を持たせ、コンテンツの切りすぎを防ぐ。"""
    if _left_side_has_dark_content(img_rgb, w, h, portion=0.20, dark_thresh=130, sample_ratio=0.03):
        return left_edge
    content_w = right_edge - left_edge
    if content_w < w * 0.5:
        return left_edge
    y_margin = max(1, int(h * y_margin_ratio))
    y_top, y_bottom = y_margin, h - y_margin
    step_y = max(1, (y_bottom - y_top) // 15)
    x_step = max(2, w // 250)

    def col_avg(x):
        total, n = 0, 0
        for y in range(y_top, y_bottom, step_y):
            p = img_rgb.getpixel((x, y))
            total += (p[0] + p[1] + p[2]) // 3
            n += 1
        return total / n if n else 0

    white_count = 0
    for x in range(left_edge, min(w, left_edge + (w * 3 // 4)), x_step):
        avg = col_avg(x)
        if avg >= white_thresh:
            white_count += 1
        else:
            if white_count >= min_white_run:
                new_left = x
                if (right_edge - new_left) >= int(w * 0.15):
                    # 境界を左に余裕を持たせ、表紙コンテンツの切りすぎを防ぐ
                    return max(new_left - safety_margin, left_edge)
            white_count = 0
    return left_edge

def _avg_gray_region(img_rgb, x_start, x_end, y_top, y_bottom):
    """指定範囲の平均輝度（濃い縦棒判定用）"""
    if x_end <= x_start or y_bottom <= y_top:
        return None
    total, n = 0, 0
    step = max(1, (x_end - x_start) * (y_bottom - y_top) // 100)
    for x in range(x_start, x_end, max(1, (x_end - x_start) // 5)):
        for y in range(y_top, y_bottom, max(1, (y_bottom - y_top) // 10)):
            p = img_rgb.getpixel((x, y))
            total += (p[0] + p[1] + p[2]) // 3
            n += 1
            if n >= 50:
                return total / n
    return total / n if n else None

def _apply_aspect_min(left, top, right, bottom, w, h, aspect_min, img_rgb=None):
    """縦横比が aspect_min 未満なら境界を拡張（過剰トリミング防止）。
    濃いグレー縦棒除去時はスキップ（余白検出のアーティファクトは削除したい）"""
    if aspect_min <= 0:
        return left, top, right, bottom
    if ASPECT_MIN_SKIP_DARK_BORDERS and img_rgb is not None and (left > 0 or right < w):
        avg_left = _avg_gray_region(img_rgb, 0, max(1, left), top, bottom) if left > 0 else None
        avg_right = _avg_gray_region(img_rgb, right, w, top, bottom) if right < w else None
        if (avg_left is not None and avg_left < 120) or (avg_right is not None and avg_right < 120):
            return left, top, right, bottom
    crop_w = right - left
    crop_h = bottom - top
    if crop_h <= 0 or crop_w / crop_h >= aspect_min:
        return left, top, right, bottom
    min_w = int(crop_h * aspect_min)
    if min_w <= crop_w:
        return left, top, right, bottom
    center_x = (left + right) // 2
    half = min_w // 2
    left_n = max(0, center_x - half)
    right_n = min(w, left_n + min_w)
    if right_n - left_n < min_w:
        left_n = max(0, right_n - min_w)
    return left_n, top, right_n, bottom

def get_trim_split_aspect(img_path):
    """見開きの場合、トリミング+分割を仮定した1ページ分の縦横比を返す。縦長の場合は生の縦横比。"""
    img = Image.open(img_path)
    w, h = img.size
    img.close()
    if h <= 0:
        return 0.0
    aspect = w / h
    if aspect < ${AspectThreshold}:
        return aspect
    left, top, right, bottom = detect_trim_bounds(img_path, aspect_min=0.0)
    crop_w = right - left
    crop_h = bottom - top
    if crop_h <= 0:
        return aspect / 2.0
    return crop_w / (2.0 * crop_h)

def _ocr_onesided_gutter_hint(img_rgb, w, h, content_on_left, padding=25):
    """片側時専用: OCRでテキストbboxからノド境界のヒントを取得。テキストがない場合はNone。"""
    bbox = _ocr_content_bbox(img_rgb, w, h, padding=padding, padding_y=padding)
    if not bbox:
        return None
    left, top, right, bottom = bbox
    cw = right - left
    if cw < 80 or (bottom - top) < 80:
        return None
    if content_on_left:
        # コンテンツが左: ノドはテキスト右端の右側
        gutter_x = min(w - 1, right + padding)
        _dbg_geom(f"DEBUG_OCR_ONESIDED: content_left, OCR bbox right={right} -> gutter_hint={gutter_x}")
        return gutter_x
    else:
        # コンテンツが右: ノドはテキスト左端の左側
        gutter_x = max(1, left - padding)
        _dbg_geom(f"DEBUG_OCR_ONESIDED: content_right, OCR bbox left={left} -> gutter_hint={gutter_x}")
        return gutter_x

def detect_gutter_x_brightness(pil_img, content_on_left=True, bright_thresh=235, step_y=None):
    """片側コンテンツ用: 明度の区切りでノド（余白とコンテンツの境界）を検出。
    content_on_left=True: 左にコンテンツ・右に白余白 → 右からスキャンして境界を検出
    content_on_left=False: 右にコンテンツ・左に白余白 → 左からスキャンして境界を検出"""
    if pil_img.mode != 'RGB' and pil_img.mode != 'L':
        pil_img = pil_img.convert('RGB')
    w, h = pil_img.size
    if w < 100 or h < 20:
        return w // 2
    def get_gray(px):
        if isinstance(px, (list, tuple)) and len(px) >= 3:
            return (px[0] + px[1] + px[2]) // 3
        return int(px) if isinstance(px, (int, float)) else px
    sy = step_y if step_y is not None else max(1, h // 40)
    y_begin, y_end = max(0, h // 20), h - max(0, h // 20)
    col_bright = []
    for x in range(w):
        total, n = 0, 0
        for y in range(y_begin, y_end, sy):
            total += get_gray(pil_img.getpixel((x, y)))
            n += 1
        avg = total / n if n > 0 else 255
        col_bright.append(avg)
    if content_on_left:
        for x in range(w - 1, -1, -1):
            if col_bright[x] < bright_thresh:
                _dbg_geom(f"DEBUG_GUTTER_BRIGHT: content_left, boundary x={x} bright={col_bright[x]:.0f}")
                return max(1, min(x + 5, w - 1))
    else:
        for x in range(w):
            if col_bright[x] < bright_thresh:
                _dbg_geom(f"DEBUG_GUTTER_BRIGHT: content_right, boundary x={x} bright={col_bright[x]:.0f}")
                return max(1, min(x, w - 1))
    _dbg_geom(f"DEBUG_GUTTER_BRIGHT: no boundary found, fallback center")
    return w // 2

def _detect_gutter_vertical_brightness(pil_img, center_band_ratio=0.3):
    """片側のノドだけ白/黒の場合: 縦方向の明度で暗い領域と明るい領域の分かれ目をノドとする。
    上下GUTTER_EDGE_EXCLUDE%除外（ウォーターマーク回避）。"""
    if pil_img.mode != 'RGB' and pil_img.mode != 'L':
        pil_img = pil_img.convert('RGB')
    w, h = pil_img.size
    if w < 100 or h < 20:
        return w // 2
    y_margin = max(1, int(h * GUTTER_EDGE_EXCLUDE))
    y_start, y_end = y_margin, h - y_margin
    step_y = max(1, (y_end - y_start) // 60)
    step_x = max(1, w // 150)
    def get_gray(px):
        if isinstance(px, (list, tuple)) and len(px) >= 3:
            return (px[0] + px[1] + px[2]) // 3
        return int(px) if isinstance(px, (int, float)) else px
    col_avg = []
    for x in range(0, w, step_x):
        total, n = 0, 0
        for y in range(y_start, y_end, step_y):
            total += get_gray(pil_img.getpixel((x, y)))
            n += 1
        col_avg.append((x, total / n) if n > 0 else (x, 128))
    if len(col_avg) < 10:
        return w // 2
    center = w // 2
    band = max(2, int(w * center_band_ratio))
    x_lo = max(0, center - band)
    x_hi = min(w, center + band)
    best_x, best_diff = center, 0
    for xi, (xp, _) in enumerate(col_avg):
        if x_lo <= xp < x_hi:
            left_vals = [v for x, v in col_avg if x < xp]
            right_vals = [v for x, v in col_avg if x >= xp]
            if left_vals and right_vals:
                avg_left = sum(left_vals) / len(left_vals)
                avg_right = sum(right_vals) / len(right_vals)
                diff = abs(avg_left - avg_right)
                if diff > best_diff and diff > 25:
                    best_diff = diff
                    best_x = xp
    if best_diff > 25:
        _dbg_geom(f"DEBUG_GUTTER_VERT: 縦明度境界 x={best_x} diff={best_diff:.0f}")
        return best_x
    return center

def _detect_content_region_center(pil_img):
    """中央に白余白（ノド）が無い場合: 連続コンテンツ領域を検出し、その中央で区切る。
    左右からスキャン。上下GUTTER_EDGE_EXCLUDE%除外（ウォーターマーク回避）。"""
    if pil_img.mode != 'RGB' and pil_img.mode != 'L':
        pil_img = pil_img.convert('RGB')
    w, h = pil_img.size
    if w < 100 or h < 20:
        return w // 2
    img_rgb = pil_img.convert('RGB')
    y_margin = max(1, int(h * GUTTER_EDGE_EXCLUDE))
    y_start, y_end = y_margin, h - y_margin
    step_y = max(1, (y_end - y_start) // 60)
    step_x = max(1, w // 200)
    def has_content(col):
        pg, prgb = [], []
        for yy in range(y_start, y_end, step_y):
            p = img_rgb.getpixel((col, yy))
            prgb.append(p[:3])
            pg.append((p[0] + p[1] + p[2]) // 3)
        return pg and not _check_margin(pg, prgb)
    left_bound = 0
    consec = 0
    for x in range(0, w, step_x):
        if has_content(x):
            consec += 1
            if consec >= 3:
                left_bound = max(0, x - 2 * step_x)
                break
        else:
            consec = 0
    right_bound = w - 1
    consec = 0
    for x in range(w - 1, -1, -step_x):
        if has_content(x):
            consec += 1
            if consec >= 3:
                right_bound = min(w, x + 2 * step_x)
                break
        else:
            consec = 0
    if right_bound <= left_bound + 10:
        center = w // 2
        _dbg_geom(f"DEBUG_GUTTER_CONTENT: コンテンツ領域が狭い fallback center={center}")
        return center
    mid = (left_bound + right_bound) // 2
    _dbg_geom(f"DEBUG_GUTTER_CONTENT: 連続コンテンツ中央 left={left_bound} right={right_bound} mid={mid}")
    return mid

def _find_content_boundaries_from_center(img_rgb, half, w, h, step_y=None, step_x=3):
    """中央の分割点から左右の外側に向かって、コンテンツ→空白の境界を検出。
    上下GUTTER_EDGE_EXCLUDE%除外（ウォーターマーク回避）。左: half-1から左方向へ、右: halfから右方向へ。"""
    if img_rgb.mode != 'RGB':
        img_rgb = img_rgb.convert('RGB')
    y_margin = max(1, int(h * GUTTER_EDGE_EXCLUDE))
    y_start, y_end = y_margin, h - y_margin
    sy = step_y if step_y is not None else max(1, (y_end - y_start) // 40)
    def is_margin_col(x):
        if x < 0 or x >= w:
            return True
        pg, prgb = [], []
        for yy in range(y_start, y_end, sy):
            p = img_rgb.getpixel((x, yy))
            prgb.append(p[:3])
            pg.append((p[0] + p[1] + p[2]) // 3)
        return bool(pg and _check_margin(pg, prgb))
    TOL = 4
    last_content_x = max(0, half - 1)
    consec = 0
    for x in range(half - 2, -1, -step_x):
        if is_margin_col(x):
            consec += 1
            if consec >= TOL:
                break
        else:
            consec = 0
            last_content_x = x
    left_bound = max(0, last_content_x)
    last_content_x = min(w - 1, half)
    consec = 0
    for x in range(half + 1, w, step_x):
        if is_margin_col(x):
            consec += 1
            if consec >= TOL:
                break
        else:
            consec = 0
            last_content_x = x
    right_bound = min(w - 1, last_content_x)
    if left_bound >= half:
        left_bound = max(0, half - 50)
    if right_bound <= half:
        right_bound = min(w - 1, half + 50)
    # 安全マージン: 境界スキャンで文字切れを防ぐ（コンテンツ境界の外側に余白を確保）
    SAFETY_MARGIN = 30
    left_bound = max(0, left_bound - SAFETY_MARGIN)
    right_bound = min(w - 1, right_bound + SAFETY_MARGIN)
    _dbg_geom(f"DEBUG_ONESIDED_BOUNDS: center→外側スキャン left_bound={left_bound} right_bound={right_bound} half={half} (安全マージン±{SAFETY_MARGIN}px)")
    return (left_bound, right_bound)

def _otsu_threshold(hist):
    """ヒストグラムから大津の閾値を計算。"""
    total = sum(hist)
    if total <= 0:
        return 128
    sum_b = 0
    w_b = 0
    best_var = 0
    best_t = 0
    for t in range(256):
        w_b += hist[t]
        w_f = total - w_b
        if w_b <= 0 or w_f <= 0:
            continue
        sum_b += t * hist[t]
        m_b = sum_b / w_b
        sum_f = sum(i * hist[i] for i in range(256)) - sum_b
        m_f = sum_f / w_f
        var = w_b * w_f * (m_b - m_f) ** 2
        if var > best_var:
            best_var = var
            best_t = t
    return best_t

# ノド検出時の上下除外率（ウォーターマーク回避: 3%→18%、detect_trim_boundsの20%に近づける）
GUTTER_EDGE_EXCLUDE = 0.18

def _detect_gutter_x_binary(pil_img, center_band_ratio=0.12, edge_exclude_ratio=None):
    """2色化（二値化）して縦エッジを検出しノド位置の精度を向上。
    白余白とコンテンツの境界が薄い装飾で曖昧な場合に有効。
    edge_exclude_ratio: 上下何%を除外（ウォーターマーク回避、デフォルト18%）。"""
    if edge_exclude_ratio is None:
        edge_exclude_ratio = GUTTER_EDGE_EXCLUDE
    if pil_img.mode != 'RGB' and pil_img.mode != 'L':
        pil_img = pil_img.convert('RGB')
    w, h = pil_img.size
    if w < 100 or h < 20:
        return w // 2
    gray = pil_img.convert('L')
    _get_pixels = getattr(gray, 'get_flattened_data', None) or gray.getdata
    pixels = list(_get_pixels())
    hist = [0] * 256
    for p in pixels:
        hist[min(255, int(p))] += 1
    thresh = _otsu_threshold(hist)
    binary = [255 if p >= thresh else 0 for p in pixels]
    y_margin = max(1, int(h * edge_exclude_ratio))
    y_begin, y_end = y_margin, h - y_margin
    num_segments = 8
    seg_height = max(1, (y_end - y_begin) // num_segments)
    center = w // 2
    band_half = max(2, int(w * center_band_ratio / 2.0))
    x_start = max(1, center - band_half)
    x_end = min(w - 1, center + band_half)
    column_scores = []
    for x in range(x_start, x_end):
        segment_edges = []
        for seg in range(num_segments):
            sy0 = y_begin + seg * seg_height
            sy1 = min(y_end, sy0 + seg_height)
            edge_total = 0
            n = 0
            for y in range(sy0, sy1, max(1, seg_height // 10)):
                if x - 1 >= 0 and x + 1 < w:
                    idx_c = y * w + x
                    idx_l = y * w + (x - 1)
                    idx_r = y * w + (x + 1)
                    edge_total += abs(binary[idx_c] - binary[idx_l]) + abs(binary[idx_r] - binary[idx_c])
                    n += 1
            if n > 0:
                segment_edges.append(edge_total / n)
        edge_score = max(segment_edges) if segment_edges else 0
        column_scores.append((x, edge_score))
    if not column_scores:
        return center
    min_edge = min(p[1] for p in column_scores)
    thresh_score = min_edge * 1.5 if min_edge > 0 else 50
    band_xs = [x for x, s in column_scores if s <= thresh_score]
    if not band_xs:
        band_xs = [x for x, s in column_scores]
    best_x = int(sum(band_xs) / len(band_xs))
    _dbg_geom(f"DEBUG_GUTTER_BINARY: x={best_x} Otsu_thresh={thresh}")
    return best_x

def detect_gutter_x(pil_img, center_band_ratio=0.12, edge_exclude_ratio=None):
    """中央 band_ratio 幅の帯でエッジ＋明度を組み合わせてノド位置を検出。
    上下18%除外（ウォーターマーク回避）で縦方向検証。edge_exclude_ratio で上書き可。
    ノドなし時（中央に白余白なし）は連続コンテンツ領域の中央で区切る。"""
    if edge_exclude_ratio is None:
        edge_exclude_ratio = GUTTER_EDGE_EXCLUDE
    if pil_img.mode != 'RGB' and pil_img.mode != 'L':
        pil_img = pil_img.convert('RGB')
    w, h = pil_img.size
    if w < 100 or h < 20:
        return w // 2
    center = w // 2
    band_half = max(2, int(w * center_band_ratio / 2.0))
    x_start = max(1, center - band_half)
    x_end = min(w - 1, center + band_half)
    if x_end <= x_start + 2:
        return center
    y_margin = max(1, int(h * edge_exclude_ratio))
    y_begin = y_margin
    y_end = h - y_margin
    if y_end <= y_begin + 2:
        y_begin, y_end = 0, h
    num_segments = 8
    seg_height = max(1, (y_end - y_begin) // num_segments)
    def get_gray(px):
        if isinstance(px, (list, tuple)) and len(px) >= 3:
            return (px[0] + px[1] + px[2]) // 3
        return int(px) if isinstance(px, (int, float)) else px
    center_band = 5
    c0 = max(0, center - center_band)
    c1 = min(w, center + center_band)
    center_sum, center_n = 0, 0
    for x in range(c0, c1):
        for y in range(y_begin, y_end, max(1, seg_height // 5)):
            center_sum += get_gray(pil_img.getpixel((x, y)))
            center_n += 1
    center_dark = center_sum / center_n if center_n > 0 else 255
    if center_dark < 80:
        _dbg_geom(f"DEBUG_GUTTER: center_dark={center_dark:.0f} (<80) -> use center")
        return center
    column_scores = []
    brightnesses = []
    for x in range(x_start, x_end):
        segment_edges = []
        segment_brights = []
        for seg in range(num_segments):
            sy0 = y_begin + seg * seg_height
            sy1 = min(y_end, sy0 + seg_height)
            step_y = max(1, (sy1 - sy0) // 15)
            edge_total = 0
            bright_total = 0
            n = 0
            for y in range(sy0, sy1, step_y):
                if x - 1 >= 0 and x + 1 < w:
                    c = get_gray(pil_img.getpixel((x, y)))
                    l_ = get_gray(pil_img.getpixel((x - 1, y)))
                    r_ = get_gray(pil_img.getpixel((x + 1, y)))
                    edge_total += abs(c - l_) + abs(r_ - c)
                    bright_total += c
                    n += 1
            if n > 0:
                segment_edges.append(edge_total / n)
                segment_brights.append(bright_total / n)
        edge_score = max(segment_edges) if segment_edges else 999
        bright_avg = sum(segment_brights) / len(segment_brights) if segment_brights else 128
        column_scores.append((x, edge_score))
        brightnesses.append((x, bright_avg))
    if not column_scores or not brightnesses:
        return center
    col_vals = [p[1] for p in column_scores]
    max_col = max(col_vals) if col_vals else 1
    min_col = min(col_vals) if col_vals else 0
    col_range = max_col - min_col if max_col > min_col else 1
    best_combined = float('inf')
    combined_list = []
    use_edge_only = center_dark > 200
    if center_dark > 180:
        binary_x = _detect_gutter_x_binary(pil_img, center_band_ratio, edge_exclude_ratio)
        if abs(binary_x - center) <= w * 0.12:
            _dbg_geom(f"DEBUG_GUTTER: binary_x={binary_x} center_dark={center_dark:.0f}")
            return binary_x
    for i, (x, col_score) in enumerate(column_scores):
        if use_edge_only:
            combined = col_score
        else:
            bright = brightnesses[i][1] if i < len(brightnesses) else 128
            col_norm = (col_score - min_col) / col_range if col_range > 0 else 0
            bright_norm = bright / 255.0
            combined = col_norm * 0.7 + bright_norm * 0.3
        combined_list.append((x, combined))
        if combined < best_combined:
            best_combined = combined
    if not use_edge_only and best_combined > 0.7:
        vert_x = _detect_gutter_vertical_brightness(pil_img)
        if abs(vert_x - center) > w * 0.05:
            _dbg_geom(f"DEBUG_GUTTER: 片側ノド白/黒検出 x={vert_x}")
            return vert_x
        _dbg_geom(f"DEBUG_GUTTER: center_dark={center_dark:.0f} best_combined={best_combined:.3f} -> 連続コンテンツ中央で検出")
        return _detect_content_region_center(pil_img)
    # ノドバンドの中央でカットするよう、同程度のスコアの列の平均を採用（偏り軽減）
    thresh = best_combined * 1.15 if best_combined > 0.001 else best_combined + 0.05
    band_xs = [x for x, c in combined_list if c <= thresh]
    best_x = int(sum(band_xs) / len(band_xs)) if band_xs else center
    _dbg_geom(f"DEBUG_GUTTER: center_dark={center_dark:.0f} best_x={best_x} band_len={len(band_xs)} mode={'edge_only' if use_edge_only else 'combined'} (上下全域検証)")
    return best_x

def _ocr_content_bbox(img_rgb, w, h, padding=35, padding_y=40):
    """白余白ページ用: OCRでテキスト領域の外接矩形を取得。コンテンツ境界の推定に使用。"""
    try:
        import pytesseract
        data = pytesseract.image_to_data(img_rgb, lang='jpn+eng', output_type=pytesseract.Output.DICT, config='--psm 6')
    except Exception:
        return None
    boxes = []
    n_boxes = len(data.get('text', []))
    for i in range(n_boxes):
        conf = int(data.get('conf', [0])[i]) if i < len(data.get('conf', [])) else 0
        txt = (data.get('text', []) or [''])[i]
        if conf > 0 or (txt and txt.strip()):
            x = data['left'][i]
            y = data['top'][i]
            bw = data['width'][i]
            bh = data['height'][i]
            if bw > 0 and bh > 0:
                boxes.append((x, y, x + bw, y + bh))
    if len(boxes) < 2:
        return None
    l = max(0, min(b[0] for b in boxes) - padding)
    t = max(0, min(b[1] for b in boxes) - padding_y)
    r = min(w, max(b[2] for b in boxes) + padding)
    b_ = min(h, max(b[3] for b in boxes) + padding_y)
    if r - l >= 80 and b_ - t >= 80:
        return (int(l), int(t), int(r), int(b_))
    return None

def detect_trim_bounds(img_path, aspect_min=0.0, max_trim_x_override=None, max_trim_y_override=None, edge_exclude_override=None, min_crop_ratio=0.5, use_safe_region=False, margin_y_exclude=0.20, top_bottom_min_ratio=0.10):
    """【工程1】見開き画像の余白検知。margin_y_exclude: 上下何%を余白検知から除外（ウォーターマーク回避）。
    top_bottom_min_ratio: 上下カットは余白がこの割合以上の場合のみ（片側余白時はカットしない想定）。"""
    if use_safe_region:
        try:
            result = detect_safe_trim_bounds(
                img_path, aspect_min=aspect_min,
                max_trim_x=max_trim_x_override,
                max_trim_y=max_trim_y_override,
                min_crop_ratio=min_crop_ratio
            )
            if result:
                img = Image.open(img_path)
                w, h = img.size
                img.close()
                if (result[2] - result[0]) >= w * min_crop_ratio and (result[3] - result[1]) >= h * min_crop_ratio:
                    return result
        except Exception:
            pass
    img = Image.open(img_path)
    img_rgb = img.convert("RGB")
    w, h = img.size
    max_trim_x = max_trim_x_override if max_trim_x_override is not None else min(w // 2, 600)
    max_trim_y = max_trim_y_override if max_trim_y_override is not None else min(h // 6, 250)
    step_y = max(2, h // 50)
    step_x = max(2, w // 80)
    left, top, right, bottom = 0, 0, w, h
    edge_excl = edge_exclude_override if edge_exclude_override is not None else 0.12
    y_margin = max(1, int(h * max(edge_excl, margin_y_exclude)))
    y_start, y_end = y_margin, h - y_margin
    x_margin = max(1, int(w * margin_y_exclude))
    x_start_central, x_end_central = x_margin, w - x_margin
    TOL = 4  # 連続N列/行非余白で初めて停止
    consec = 0
    for x in range(max_trim_x):
        pg, prgb = [], []
        for y in range(y_start, y_end, step_y):
            p = img_rgb.getpixel((x, y))
            prgb.append(p[:3])
            pg.append((p[0] + p[1] + p[2]) // 3)
        if pg and _check_margin(pg, prgb):
            left = x + 1
            consec = 0
        else:
            consec += 1
            if consec >= TOL:
                break
    consec = 0
    for x in range(w - 1, w - max_trim_x - 1, -1):
        pg, prgb = [], []
        for y in range(y_start, y_end, step_y):
            p = img_rgb.getpixel((x, y))
            prgb.append(p[:3])
            pg.append((p[0] + p[1] + p[2]) // 3)
        if pg and _check_margin(pg, prgb):
            right = x
            consec = 0
        else:
            consec += 1
            if consec >= TOL:
                break
    consec = 0
    for y in range(max_trim_y):
        pg, prgb = [], []
        for x in range(x_start_central, x_end_central, step_x):
            p = img_rgb.getpixel((x, y))
            prgb.append(p[:3])
            pg.append((p[0] + p[1] + p[2]) // 3)
        if pg and _check_margin(pg, prgb):
            top = y + 1
            consec = 0
        else:
            consec += 1
            if consec >= TOL:
                break
    consec = 0
    for y in range(h - 1, h - max_trim_y - 1, -1):
        pg, prgb = [], []
        for x in range(x_start_central, x_end_central, step_x):
            p = img_rgb.getpixel((x, y))
            prgb.append(p[:3])
            pg.append((p[0] + p[1] + p[2]) // 3)
        if pg and _check_margin(pg, prgb):
            bottom = y
            consec = 0
        else:
            consec += 1
            if consec >= TOL:
                break
    top_thresh = max(50, int(h * top_bottom_min_ratio))
    has_top = top > 0 and top >= top_thresh
    has_bottom = bottom < h and (h - bottom) >= top_thresh
    if has_top != has_bottom:
        top, bottom = 0, h
    elif top > 0 and top < top_thresh:
        top = 0
    elif bottom < h and (h - bottom) < top_thresh:
        bottom = h
    if (right - left) < w * min_crop_ratio or (bottom - top) < h * min_crop_ratio:
        img.close()
        return (0, 0, w, h)
    if USE_STRICT_WHITE_FOR_COVER and right < w:
        if _right_side_has_dark_content(img_rgb, w, h, portion=0.25, dark_thresh=150, sample_ratio=0.015):
            right = w
    if USE_STRICT_WHITE_FOR_COVER and left > 0:
        if _left_side_has_dark_content(img_rgb, w, h, portion=0.25, dark_thresh=150, sample_ratio=0.015):
            left = 0
    if aspect_min > 0:
        left, top, right, bottom = _apply_aspect_min(left, top, right, bottom, w, h, aspect_min, img_rgb)
    img.close()
    return (left, top, right, bottom)

def trim_only(img_path, output_path=None, aspect_min=0.0):
    """トリミングのみ行い保存。output_path指定時はそこに出力（プレビュー用）"""
    left, top, right, bottom = detect_trim_bounds(img_path, aspect_min=aspect_min)
    img = Image.open(img_path)
    w, h = img.size
    out_path = output_path if output_path else img_path
    ext = os.path.splitext(out_path)[1].lower()
    save_kw = {"quality": 95} if ext in (".jpg", ".jpeg") else {}
    # JPEG保存時はRGBA→RGB変換が必要
    if ext in (".jpg", ".jpeg") and img.mode == 'RGBA':
        img = img.convert('RGB')
    if (right - left >= w - 8) and (bottom - top >= h - 8):
        if output_path:
            img.save(out_path, **save_kw)
        img.close()
        return "TRIMMED:1"
    img = img.crop((left, top, right, bottom))
    img.save(out_path, **save_kw)
    img.close()
    return "TRIMMED:1"

def crop_gui_margins_only(img_path, left_trim_px, top_trim_px, right_trim_px, bottom_trim_px):
    """GUIで指定した四辺のトリムのみ（見開き分割なし）。元ファイルを置き換える。"""
    _m = 5
    img = Image.open(img_path)
    w, h = img.size
    lt = max(0, int(left_trim_px))
    tt = max(0, int(top_trim_px))
    rt = max(0, int(right_trim_px))
    bt = max(0, int(bottom_trim_px))
    if lt + rt >= w - _m * 2 or tt + bt >= h - _m * 2:
        img.close()
        return "ERROR:Crop margins too large w=%s h=%s l=%s r=%s t=%s b=%s" % (w, h, lt, rt, tt, bt)
    x1, y1, x2, y2 = lt, tt, w - rt, h - bt
    if x2 - x1 < _m or y2 - y1 < _m:
        img.close()
        return "ERROR:Crop result too small"
    if x1 == 0 and y1 == 0 and x2 == w and y2 == h:
        img.close()
        return "TRIMMED:1"
    cropped = img.crop((x1, y1, x2, y2))
    img.close()
    ext = os.path.splitext(img_path)[1].lower()
    save_kw = {"quality": 95} if ext in (".jpg", ".jpeg") else {}
    if ext in (".jpg", ".jpeg") and cropped.mode == "RGBA":
        cropped = cropped.convert("RGB")
    cropped.save(img_path, **save_kw)
    cropped.close()
    time.sleep(0.1)
    return "TRIMMED:1"

def trim_single_safe(img_path, cover_width=0, aspect_min=0.0):
    """単ページ（縦長）: 左右余白を検知し、トリミング後の幅が表紙幅以上になる場合のみトリミング。"""
    if cover_width <= 0:
        return "SKIP"
    left, top, right, bottom = detect_trim_bounds(img_path, aspect_min=aspect_min)
    result_w = right - left
    if result_w < cover_width:
        return "SKIP"
    img = Image.open(img_path)
    w, h = img.size
    if (right - left >= w - 8) and (bottom - top >= h - 8):
        img.close()
        return "TRIMMED:1"
    ext = os.path.splitext(img_path)[1].lower()
    save_kw = {"quality": 95} if ext in (".jpg", ".jpeg") else {}
    if ext in (".jpg", ".jpeg") and img.mode == 'RGBA':
        img = img.convert('RGB')
    img = img.crop((left, top, right, bottom))
    img.save(img_path, **save_kw)
    img.close()
    return "TRIMMED:1"

def cover_trim(img_path, output_path, max_height=0, aspect_min=0.0, aspect_target=0.0, strength=None, gentle=False):
    """表紙トリミング: 従来のピクセルスキャン + 縦横比制限。表紙のみ 0.55～0.85 に緩和。
    strength: 0.0〜1.0 でトリミング強度を指定（1.0=従来の強さ, 0.0=かなり弱め）。
    gentle=True のときは strength が未指定なら弱め（例: 0.3）として扱う。"""
    global USE_STRICT_WHITE_FOR_COVER
    USE_STRICT_WHITE_FOR_COVER = True
    try:
        return _cover_trim_impl(img_path, output_path, max_height, aspect_min, aspect_target, strength, gentle)
    finally:
        USE_STRICT_WHITE_FOR_COVER = False

def _cover_trim_impl(img_path, output_path, max_height=0, aspect_min=0.0, aspect_target=0.0, strength=None, gentle=False):
    # 表紙専用: 縦横比を 0.55～0.85 の範囲に緩める（他ページより柔軟）
    aspect_target = min(aspect_target, 0.85) if aspect_target > 0 else 0.7
    aspect_min = min(aspect_min, 0.55) if aspect_min > 0 else 0.55
    # トリミング強度を正規化（0.0〜1.0）
    if strength is None:
        strength = 0.3 if gentle else 1.0
    try:
        strength = float(strength)
    except (TypeError, ValueError):
        strength = 1.0
    if strength < 0.0:
        strength = 0.0
    if strength > 1.0:
        strength = 1.0

    img = Image.open(img_path)
    img_rgb = img.convert("RGB")
    w, h = img.size
    aspect = w / h if h > 0 else 0
    ext = os.path.splitext(output_path)[1].lower()
    save_kw = {"quality": 90} if ext in (".jpg", ".jpeg") else {}

    # 段階的余白検知: 横長画像は1段階→アスペクト確認→2段階→まだ横長なら手動確認促す
    if aspect >= 1.0:
        max_trim_x = min(int(w * 0.75 * strength + w * 0.25 * (1 - strength)), 2800)
        _dbg_geom(f"DEBUG: cover_trim staged aspect={aspect:.3f} aspect_target={aspect_target} max_trim_x={max_trim_x}")
        left1, top1, right1, bottom1 = detect_trim_bounds(img_path, aspect_min=0.0, max_trim_x_override=max_trim_x, edge_exclude_override=0.20, use_safe_region=False)
        if (right1 - left1) >= w - 8 and (bottom1 - top1) >= h - 8:
            left1, top1, right1, bottom1 = 0, 0, w, h
        stage1 = img_rgb.crop((left1, top1, right1, bottom1))
        cw1, ch1 = stage1.size
        aspect1 = cw1 / ch1 if ch1 > 0 else 0
        _dbg_geom(f"DEBUG: stage1 left={left1} right={right1} w={cw1} aspect={aspect1:.3f}")
        if aspect1 < 1.0 and aspect1 >= aspect_min:
            img.close()
            img_rgb.close()
            if max_height > 0 and ch1 > max_height:
                resample = getattr(Image, 'Resampling', Image).LANCZOS if hasattr(Image, 'Resampling') else Image.LANCZOS
                stage1 = stage1.resize((int(cw1 * (max_height / ch1)), max_height), resample)
            if stage1.mode == 'RGBA':
                stage1 = stage1.convert('RGB')
            stage1.save(output_path, **save_kw)
            stage1.close()
            return "TRIMMED:1"
        if aspect1 >= 1.0:
            import tempfile
            fd, temp_path = tempfile.mkstemp(suffix=ext)
            os.close(fd)
            try:
                s1_rgb = stage1.convert('RGB') if stage1.mode == 'RGBA' else stage1
                s1_rgb.save(temp_path, **save_kw)
                if s1_rgb is not stage1:
                    s1_rgb.close()
                left2, top2, right2, bottom2 = detect_trim_bounds(temp_path, aspect_min=0.0, max_trim_x_override=min(cw1 // 2, 800), edge_exclude_override=0.15, use_safe_region=False)
                os.remove(temp_path)
            except Exception:
                left2, top2, right2, bottom2 = 0, 0, cw1, ch1
            if (right2 - left2) >= cw1 - 8 and (bottom2 - top2) >= ch1 - 8:
                left2, top2, right2, bottom2 = 0, 0, cw1, ch1
            stage2 = stage1.crop((left2, top2, right2, bottom2))
            stage1.close()
            cw2, ch2 = stage2.size
            aspect2 = cw2 / ch2 if ch2 > 0 else 0
            _dbg_geom(f"DEBUG: stage2 left={left2} right={right2} w={cw2} aspect={aspect2:.3f}")
            # 左右白余白の追加除去: まだ横長なら両端から白余白をスキャンしてさらに縮める
            # 右端にタイトル・巻数などの暗いテキストがあれば右側補正はスキップ（_adjust_*内で判定）
            if aspect2 > 0.85:
                stage2_rgb = stage2.convert("RGB")
                left_adj = 0
                right_adj = cw2
                right_adj_new = _adjust_right_edge_for_white_margin(stage2_rgb, cw2, ch2, 0, cw2, white_thresh=240, min_white_run=20, safety_margin=60)
                if right_adj_new < cw2 - 50:
                    right_adj = right_adj_new
                left_adj_new = _adjust_left_edge_for_white_margin(stage2_rgb, cw2, ch2, 0, cw2, white_thresh=240, min_white_run=20, safety_margin=60)
                if left_adj_new > 50:
                    left_adj = left_adj_new
                stage2_rgb.close()
                if left_adj > 0 or right_adj < cw2:
                    stage2 = stage2.crop((left_adj, 0, right_adj, ch2))
                    cw2, ch2 = stage2.size
                    aspect2 = cw2 / ch2 if ch2 > 0 else 0
                    _dbg_geom(f"DEBUG: stage2+ white_margin_adj left={left_adj} right={right_adj} w={cw2} aspect={aspect2:.3f}")
                if aspect2 >= 1.0:
                    _dbg_geom(f"DEBUG: 2段階後も横長(aspect={aspect2:.3f})のため手動確認を推奨")
            img.close()
            img_rgb.close()
            if max_height > 0 and ch2 > max_height:
                resample = getattr(Image, 'Resampling', Image).LANCZOS if hasattr(Image, 'Resampling') else Image.LANCZOS
                stage2 = stage2.resize((int(cw2 * (max_height / ch2)), max_height), resample)
            if stage2.mode == 'RGBA':
                stage2 = stage2.convert('RGB')
            stage2.save(output_path, **save_kw)
            stage2.close()
            return "TRIMMED:1"
        img.close()
        img_rgb.close()
        if max_height > 0 and ch1 > max_height:
            resample = getattr(Image, 'Resampling', Image).LANCZOS if hasattr(Image, 'Resampling') else Image.LANCZOS
            stage1 = stage1.resize((int(cw1 * (max_height / ch1)), max_height), resample)
        if stage1.mode == 'RGBA':
            stage1 = stage1.convert('RGB')
        stage1.save(output_path, **save_kw)
        stage1.close()
        return "TRIMMED:1"

    use_center_crop = False
    offset_content = False
    avg_left, avg_right = None, None
    # 強度がある程度高いときだけセンタークロップを有効にする（弱いときはマージントリムのみ）
    cond_ok = COVER_CENTER_CROP_ENABLED and aspect >= 1.0 and aspect_target > 0 and aspect_target < 1.0 and strength >= 0.5
    _dbg_geom(f"DEBUG: cover_trim aspect={aspect:.3f} aspect_target={aspect_target} cond_ok={cond_ok} (CROP_ENABLED={COVER_CENTER_CROP_ENABLED})")
    if cond_ok:
        edge_w = max(1, w // 10)
        y_margin = max(1, int(h * 0.12))
        y_top, y_bottom = y_margin, h - y_margin
        avg_left = _avg_gray_region(img_rgb, 0, edge_w, y_top, y_bottom)
        avg_right = _avg_gray_region(img_rgb, w - edge_w, w, y_top, y_bottom)
        c_lo, c_hi = max(0, w // 2 - w // 5), min(w, w // 2 + w // 5)
        avg_center = _avg_gray_region(img_rgb, c_lo, c_hi, y_top, y_bottom)
        dark_ok = (avg_left is not None and avg_left < COVER_CENTER_CROP_DARK_THRESH) or (avg_right is not None and avg_right < COVER_CENTER_CROP_DARK_THRESH)
        center_light = avg_center is not None and avg_center > 230
        edges_white = (avg_left is not None and avg_left > 240) and (avg_right is not None and avg_right > 240)
        offset_content = edges_white and center_light
        _dbg_geom(f"DEBUG: avg_left={avg_left} avg_right={avg_right} avg_center={avg_center} THRESH={COVER_CENTER_CROP_DARK_THRESH} dark_ok={dark_ok} offset_content={offset_content}")
        if dark_ok:
            use_center_crop = True
            _dbg_geom(f"DEBUG: path=dark_bar_trim (dark_ok=True, use detect_trim_bounds with extended range)")
        elif offset_content:
            _dbg_geom(f"DEBUG: path=offset_content (中心ずれ検出: 両端・中央とも白→varianceベース境界検出)")
    if use_center_crop:
        left_edge, right_edge = _find_dark_bar_edges(img_rgb, w, h, dark_thresh=COVER_CENTER_CROP_DARK_THRESH, content_thresh=80)
        content_w = right_edge - left_edge
        # 白余白補正: dark_bar_trim が白領域をコンテンツと誤認するのを防ぐ
        # 右端の薄いグレーバーで avg_right が下がる場合があるため、right_has_dark (>=THRESH) を基準とする
        left_has_dark = avg_left is not None and avg_left < COVER_CENTER_CROP_DARK_THRESH
        right_has_dark = avg_right is not None and avg_right < COVER_CENTER_CROP_DARK_THRESH
        both_have_dark = left_has_dark and right_has_dark  # 両端グレー＋中央表紙＋左右白余白
        left_aligned = left_has_dark and not right_has_dark
        right_aligned = right_has_dark and not left_has_dark
        if content_w > w * 0.5:
            if left_aligned:
                # 左寄り表紙＋右側広い白余白: 左端は_find_dark_bar_edgesの値（グレー余白除去）、右端を白余白手前まで補正
                right_edge_adj = _adjust_right_edge_for_white_margin(img_rgb, w, h, left_edge, right_edge)
                if right_edge_adj < right_edge:
                    right_edge = right_edge_adj
                    content_w = right_edge - left_edge
                    _dbg_geom(f"DEBUG: white_margin_adjust left_aligned right_edge {right_edge} content_w={content_w}")
            elif right_aligned:
                # 右寄り表紙＋左側広い白余白: 右端=w（右がコンテンツ）、左端を補正
                right_edge = w
                left_edge_adj = _adjust_left_edge_for_white_margin(img_rgb, w, h, left_edge, right_edge)
                if left_edge_adj > left_edge:
                    left_edge = left_edge_adj
                    content_w = right_edge - left_edge
                    _dbg_geom(f"DEBUG: white_margin_adjust left_edge {left_edge} content_w={content_w}")
            elif both_have_dark:
                # 中央表紙＋両端グレー＋左右に白余白: 両方の白余白を除去
                changed = False
                right_edge_adj = _adjust_right_edge_for_white_margin(img_rgb, w, h, left_edge, right_edge)
                if right_edge_adj < right_edge:
                    right_edge = right_edge_adj
                    content_w = right_edge - left_edge
                    changed = True
                left_edge_adj = _adjust_left_edge_for_white_margin(img_rgb, w, h, left_edge, right_edge)
                if left_edge_adj > left_edge:
                    left_edge = left_edge_adj
                    content_w = right_edge - left_edge
                    changed = True
                if changed:
                    _dbg_geom(f"DEBUG: white_margin_adjust both (center pattern) left={left_edge} right={right_edge} content_w={content_w}")
        if content_w < 100 or left_edge >= right_edge:
            # 表紙専用: 右寄りスキャンの左余白対応。白背景で削りすぎ防止のため控えめに
            base_ratio = 0.70
            gentle_ratio = 0.50
            trim_ratio = gentle_ratio + (base_ratio - gentle_ratio) * strength
            max_trim_cover = min(int(w * trim_ratio), 3500)
            img_rgb.close()
            img.close()
            left, top, right, bottom = detect_trim_bounds(img_path, aspect_min=0.0, max_trim_x_override=max_trim_cover, edge_exclude_override=0.35, use_safe_region=False)
            if right - left >= 100 and right - left <= w - 50:
                left_edge, right_edge = left, right
                _dbg_geom(f"DEBUG: fallback detect_trim_bounds left={left} right={right}")
            img = Image.open(img_path)
            img_rgb = img.convert("RGB")
            w, h = img.size
        content_w = right_edge - left_edge
        target_w = int(h * aspect_target)
        if strength < 1.0:
            # 強度が弱いときは、トリミング後の幅が元の一定割合より小さくならないようにする
            # strength=1.0 → 約 0.70, strength=0.0 → 約 0.85
            min_ratio_base = 0.70
            min_ratio_soft = 0.85
            min_ratio = min_ratio_base + (min_ratio_soft - min_ratio_base) * (1.0 - strength)
            min_target_w = int(w * min_ratio)
            if target_w < min_target_w:
                target_w = min_target_w
        if content_w < 100 or content_w >= w - 8:
            left_edge, right_edge = 0, w
            content_w = w
        if content_w >= target_w:
            # 左寄り/右寄りは端揃え、中央表紙は従来どおり中央クロップ
            if left_aligned:
                left, right = left_edge, min(left_edge + target_w, right_edge)
                if right - left < target_w:
                    left = max(left_edge, right - target_w)
            elif right_aligned:
                right, left = right_edge, max(right_edge - target_w, left_edge)
                if right - left < target_w:
                    right = min(right_edge, left + target_w)
            else:
                center_x = (left_edge + right_edge) // 2
                left = center_x - target_w // 2
                left = max(left_edge, min(left, right_edge - target_w))
                right = left + target_w
        else:
            left, right = left_edge, right_edge
        # 強度に応じて左右のトリム量を補間（strength=0 → 無加工、1 → 計算結果どおり）
        if strength < 1.0:
            full_left, full_right = 0, w
            trim_left, trim_right = left, right
            new_left = int(full_left + (trim_left - full_left) * strength)
            new_right = int(full_right - (full_right - trim_right) * strength)
            if new_right - new_left >= 10:
                left, right = new_left, new_right
        _dbg_geom(f"DEBUG: trim_bounds left_edge={left_edge} right_edge={right_edge} content_w={content_w} crop left={left} right={right}")
        cropped = img_rgb.crop((left, 0, right, h))
        img.close()
        if cropped.mode == 'RGBA':
            cropped = cropped.convert('RGB')
        cw, ch = cropped.size
        _dbg_geom(f"DEBUG: center_crop result_size w={cw} h={ch} aspect={(cw / ch) if ch > 0 else 0}")
        if max_height > 0 and ch > max_height:
            resample = getattr(Image, 'Resampling', Image).LANCZOS if hasattr(Image, 'Resampling') else Image.LANCZOS
            cropped = cropped.resize((int(cw * (max_height / ch)), max_height), resample)
        ext = os.path.splitext(output_path)[1].lower()
        save_kw = {"quality": 90} if ext in (".jpg", ".jpeg") else {}
        cropped.save(output_path, **save_kw)
        cropped.close()
        img_rgb.close()
        trim_rate = 1.0 - (cw * h) / (w * h) if w * h > 0 else 0.0
        print(f"TRIM_RATE:{trim_rate:.4f}", flush=True)
        _dbg_geom(f"DEBUG: path=center_crop DONE")
        return "TRIMMED:1"
    if img_rgb is not None:
        img_rgb.close()
    img.close()
    path_msg = "offset_content (中心ずれ)" if offset_content else "center_crop skipped"
    _dbg_geom(f"DEBUG: path=detect_trim_bounds ({path_msg})")
    # 表紙専用: 右寄りスキャンの左余白対応。白背景・白い髪で削りすぎ防止のため min_crop を緩和
    base_ratio = 0.70   # 最大トリム割合（従来0.75→控えめに）
    gentle_ratio = 0.50
    trim_ratio = gentle_ratio + (base_ratio - gentle_ratio) * strength
    max_trim_white = min(int(w * trim_ratio), 3500)
    edge_excl = 0.08 if offset_content else None
    base_min_crop = 0.25 if offset_content else 0.35
    soft_min_crop = 0.35 if offset_content else 0.50
    min_crop = soft_min_crop + (base_min_crop - soft_min_crop) * strength
    left, top, right, bottom = detect_trim_bounds(img_path, aspect_min=aspect_min, max_trim_x_override=max_trim_white, edge_exclude_override=edge_excl, min_crop_ratio=min_crop, use_safe_region=False)
    img = Image.open(img_path)
    w, h = img.size
    # 強度に応じて「元画像」と「検出されたトリム境界」を補間する。
    # strength=1.0 → detect_trim_bounds の結果そのまま
    # strength=0.0 → ほぼ無加工（元画像全面）
    if strength < 1.0:
        full_left, full_top, full_right, full_bottom = 0, 0, w, h
        trim_left, trim_top, trim_right, trim_bottom = left, top, right, bottom
        new_left = int(full_left + (trim_left - full_left) * strength)
        new_top = int(full_top + (trim_top - full_top) * strength)
        new_right = int(full_right - (full_right - trim_right) * strength)
        new_bottom = int(full_bottom - (full_bottom - trim_bottom) * strength)
        # 幅・高さが 0 以下にならないようガード
        if new_right - new_left >= 10 and new_bottom - new_top >= 10:
            left, top, right, bottom = new_left, new_top, new_right, new_bottom
    trim_px = (w - (right - left)) + (h - (bottom - top))
    _dbg_geom(f"DEBUG: bounds left={left} top={top} right={right} bottom={bottom} trim_px~={trim_px}")
    if (right - left >= w - 8) and (bottom - top >= h - 8):
        print(f"TRIM_RATE:0.0000", flush=True)
        _dbg_geom(f"DEBUG: path=no_trim (bounds almost full, saved original)")
        if output_path:
            if img.mode == 'RGBA':
                img = img.convert('RGB')
            ext = os.path.splitext(output_path)[1].lower()
            save_kw = {"quality": 90} if ext in (".jpg", ".jpeg") else {}
            img.save(output_path, **save_kw)
        img.close()
        return "TRIMMED:1"
    cropped = img.crop((left, top, right, bottom))
    img.close()
    if cropped.mode == 'RGBA':
        cropped = cropped.convert('RGB')
    cw, ch = cropped.size
    if max_height > 0 and ch > max_height:
        resample = getattr(Image, 'Resampling', Image).LANCZOS if hasattr(Image, 'Resampling') else Image.LANCZOS
        cropped = cropped.resize((int(cw * (max_height / ch)), max_height), resample)
    ext = os.path.splitext(output_path)[1].lower()
    save_kw = {"quality": 90} if ext in (".jpg", ".jpeg") else {}
    cropped.save(output_path, **save_kw)
    cropped.close()
    trim_rate = 1.0 - ((right - left) * (bottom - top)) / (w * h) if w * h > 0 else 0.0
    print(f"TRIM_RATE:{trim_rate:.4f}", flush=True)
    _dbg_geom(f"DEBUG: path=margin_crop DONE")
    return "TRIMMED:1"

def is_mostly_blank(pil_img, bright_thresh=245, ratio_thresh=0.92):
    """トリミング後のページがほぼ白余白か判定。サンプリングで効率化。"""
    if pil_img is None or pil_img.size[0] < 50 or pil_img.size[1] < 50:
        return False
    w, h = pil_img.size
    g = pil_img.convert("L") if pil_img.mode != 'L' else pil_img
    step = max(2, min(w, h) // 25)
    bright = 0
    total = 0
    for y in range(0, h, step):
        for x in range(0, w, step):
            p = g.getpixel((x, y))
            if p >= bright_thresh:
                bright += 1
            total += 1
    if total <= 0:
        return False
    return (bright / total) >= ratio_thresh

def trim_single_page(pil_img, outer_side='both', aspect_min=0.0, ocr_trim_mode=False, min_width_guard=0):
    """【工程3】分割後の1ページのサイド余白チェック。
    必ず外側（ノドの反対側）のみ削る。ノド側から表紙+1%の区間は絶対にトリミングしない。
    min_width_guard>0 のときは表紙+1%未満にトリミングしない（事前検証との整合）。"""
    w, h = pil_img.size
    if w < 100 or h < 100:
        return pil_img
    
    img_rgb = pil_img.convert("RGB")
    
    def is_margin_column(col):
        pg, prgb = [], []
        for yy in range(0, h, max(1, h // 40)):
            p = img_rgb.getpixel((col, yy))
            prgb.append(p[:3])
            pg.append((p[0] + p[1] + p[2]) // 3)
        return _check_margin(pg, prgb)
    
    left = 0
    right = w
    if ocr_trim_mode:
        max_trim = min(w // 2, 800)  # OCRトリミング時: より積極的にスキャン
    else:
        max_trim = min(w // 2, 450)  # 最大50%または450pxまで
    
    # 外側のみトリミング。連続N列非余白で初めて停止（ stray pixel に強くする）
    MARGIN_TOLERANCE = 4
    if outer_side == 'left' or outer_side == 'both':
        consec = 0
        for x in range(max_trim):
            if is_margin_column(x):
                left = x + 1
                consec = 0
            else:
                consec += 1
                if consec >= MARGIN_TOLERANCE:
                    break
    if outer_side == 'right' or outer_side == 'both':
        consec = 0
        for x in range(w - 1, w - max_trim, -1):
            if is_margin_column(x):
                right = x
                consec = 0
            else:
                consec += 1
                if consec >= MARGIN_TOLERANCE:
                    break
    
    # 上下はトリミングしない
    top = 0
    bottom = h
    
    # ocr_trim_mode時: 安全マージン（文字切れ防止のためコンテンツ境界から余白を確保）
    if ocr_trim_mode and (left > 0 or right < w):
        TRIM_SAFETY_PX = 15
        left = max(0, left - TRIM_SAFETY_PX)
        right = min(w, right + TRIM_SAFETY_PX)
    
    # デバッグ出力
    _dbg_geom(f"TRIM_DEBUG: w={w} h={h} left={left} right={right} outer={outer_side}")    
    # 安全チェック: min_width_guard（表紙+1%）未満にはトリミングしない
    if ocr_trim_mode:
        min_width = max(80, h * 0.3) if aspect_min > 0 else 80  # 最低幅のみ
    else:
        min_width = w * 0.70
        if aspect_min > 0:
            min_width = max(min_width, h * aspect_min)
    if min_width_guard > 0:
        min_width = max(min_width, min_width_guard)
    if (right - left) < min_width:
        _dbg_geom(f"TRIM_DEBUG: SKIPPED (size check)")
        return pil_img
    
    # 変化がない場合はそのまま
    if left == 0 and right == w:
        _dbg_geom(f"TRIM_DEBUG: NO_CHANGE")
        return pil_img
    
    _dbg_geom(f"TRIM_DEBUG: CROPPED")
    return pil_img.crop((left, top, right, bottom))

def _trim_outer_to_target_width(pil_img, outer_side, target_width, aspect_min=0.0, ocr_trim_mode=False):
    """外側の余白のみをトリミングして幅を target_width に近づける。
    必ず外側（ノドの反対側）のみ削る。中央・ノド側を削るとコンテンツが欠けるため絶対に行わない。
    outer_side='left': 左端（外側）のみ削る / 'right': 右端（外側）のみ削る。
    ocr_trim_mode 時は余白マージン確保をしない（目次・白余白OCRと同様）。"""
    w, h = pil_img.size
    if w <= target_width or h < 50:
        return pil_img
    min_w = max(100, int(h * aspect_min)) if aspect_min > 0 else 100
    if target_width < min_w:
        target_width = min_w
    to_trim = w - target_width
    if to_trim <= 0:
        return pil_img
    img_rgb = pil_img.convert("RGB")
    edge_excl = 0.35
    y_margin = max(1, int(h * edge_excl))
    y_start, y_end = y_margin, h - y_margin
    step_y = max(2, (y_end - y_start) // 20)
    def is_margin_col(col):
        pg, prgb = [], []
        for yy in range(y_start, y_end, step_y):
            p = img_rgb.getpixel((col, yy))
            prgb.append(p[:3])
            pg.append((p[0] + p[1] + p[2]) // 3)
        return _check_margin(pg, prgb) if pg else False
    left, right = 0, w
    max_trim = min(w - min_w, target_width)
    margin_buffer = 0 if ocr_trim_mode else 6  # OCRトリミング時は余白マージン取らない
    TOL = 4  # 連続N列非余白で初めて停止
    if outer_side == 'left':
        consec = 0
        for x in range(min(to_trim, max_trim)):
            if is_margin_col(x):
                left = x + 1
                consec = 0
            else:
                consec += 1
                if consec >= TOL:
                    break
        left = max(0, left - margin_buffer)
    else:
        stop_at = max(w - to_trim - 1, w - max_trim - 1, -1)
        consec = 0
        for x in range(w - 1, stop_at, -1):
            if is_margin_col(x):
                right = x
                consec = 0
            else:
                consec += 1
                if consec >= TOL:
                    break
        right = min(w, right + margin_buffer)
    crop_w = right - left
    if crop_w < min_w:
        return pil_img
    # 表紙+1%未満にならないよう保証（target_width が表紙+1%のとき）
    if target_width >= 100 and crop_w < target_width:
        return pil_img
    if left > 0 or right < w:
        return pil_img.crop((left, 0, right, h))
    return pil_img

def _ensure_min_width(pil_img, min_width):
    """表紙幅未満のページをリサイズして最小幅を担保。
    拡大（縦伸び）は行わない：表紙+1%未満でもそのまま返し、縦の長さが増えるのを防ぐ。"""
    w, h = pil_img.size
    if w >= min_width or min_width < 50 or h < 10:
        return pil_img
    # 拡大は行わない（縦の長さが増えるのを防ぐ）
    _dbg_geom(f"DEBUG_COVER: w={w} below min {min_width} -> 拡大せずそのまま（縦伸び防止）")
    return pil_img

def _equalize_page_widths(page_1, page_2, outer_1, outer_2, aspect_min=0.0, ocr_trim_mode=False, cover_width=0, skip_resize=False):
    """両ページの横幅を揃える。cover_width>0 のときは表紙幅の+1%を目標に外側余白を検知してカット。
    必ず外側のみ削る（outer_1/outer_2 でノドの反対側を指定）。中央・ノド側を削るとコンテンツが欠けるため絶対に行わない。
    skip_resize=True のときは表紙幅未満でも横リサイズしない（ノドずれ時の変形防止）。
    完全余白時など表紙幅未満になった場合はリサイズして最小幅を担保（強制クロップは行わない）。"""
    w1, w2 = page_1.size[0], page_2.size[0]
    target = min(w1, w2)
    max_target = int(cover_width * 1.01) if cover_width > 0 else 0  # 表紙幅の+1%で外側余白カット
    if cover_width > 0:
        _dbg_geom(f"DEBUG_COVER: w1={w1} w2={w2} cover_width={cover_width} max_target={max_target}")
    if max_target > 0:
        target = min(target, max_target)
        # 狭い方に合わせて広い方をトリムするとき、表紙+1%未満にしない
        if target < max_target:
            target = max_target
    if abs(w1 - w2) <= 15:
        if max_target > 0 and (w1 > max_target or w2 > max_target):
            if w1 > max_target:
                page_1 = _trim_outer_to_target_width(page_1, outer_1, max_target, aspect_min, ocr_trim_mode)
            if page_2.size[0] > max_target:
                page_2 = _trim_outer_to_target_width(page_2, outer_2, max_target, aspect_min, ocr_trim_mode)
    else:
        if w1 > target:
            page_1 = _trim_outer_to_target_width(page_1, outer_1, target, aspect_min, ocr_trim_mode)
        if page_2.size[0] > target:
            page_2 = _trim_outer_to_target_width(page_2, outer_2, target, aspect_min, ocr_trim_mode)
    # 表紙+1%未満のときはリサイズして保証（skip_resize=True のときは行わない）
    min_ok = int(cover_width * 1.01) if cover_width > 0 else 0
    if min_ok > 0 and not skip_resize:
        if page_1.size[0] < min_ok:
            old_p1 = page_1
            page_1 = _ensure_min_width(page_1, min_ok)
            if page_1 is not old_p1:
                old_p1.close()
        if page_2.size[0] < min_ok:
            old_p2 = page_2
            page_2 = _ensure_min_width(page_2, min_ok)
            if page_2 is not old_p2:
                old_p2.close()
    if max_target > 0 or cover_width > 0:
        _dbg_geom(f"DEBUG_COVER: after equalize w1={page_1.size[0]} w2={page_2.size[0]} cover={cover_width}")
    return page_1, page_2

def _crop_pages_center_target(img, half, w, h, target, is_right_binding):
    """中心から外側へ target px（表紙+1%）ずつ確保し、余った分はクロップで除外。
    中心±targetを削らず、外側の余剰のみ除外してから外側トリミング。スキャン等倍前提。
    倍率が異なる場合は拡大・縮小が必要でユーザー判断が妥当。左右共にtarget以上確保できる場合のみ適用。"""
    if target <= 0 or half < target or (w - half) < target:
        return None
    left_crop = max(0, half - target)
    right_crop = min(w, half + target)
    if is_right_binding:
        page_1 = img.crop((half, 0, right_crop, h))
        page_2 = img.crop((left_crop, 0, half, h))
    else:
        page_1 = img.crop((left_crop, 0, half, h))
        page_2 = img.crop((half, 0, right_crop, h))
    _dbg_geom(f"DEBUG_CENTER_TARGET: 中心±{target}pxでクロップ left_crop={left_crop} right_crop={right_crop} half={half}")
    return (page_1, page_2)

def split_preview(img_path, output_prefix, is_right_binding=True, no_trim=False, aspect_min=0.0):
    """分割プレビュー生成（元ファイルを変更せず別名で出力）
    工程: 1)見開き余白検知→削除  2)左右同サイズで分割  3)サイド余白チェック(白・濃いグレー)"""
    img = Image.open(img_path)
    w, h = img.size
    
    aspect = w / h if h > 0 else 0
    if aspect < ${AspectThreshold}:
        img.close()
        return "SKIP"
    
    if no_trim:
        left, top, right, bottom = 0, 0, w, h
    else:
        # 左右で異なる量をトリミングすると分割位置（ノド）がずれるので、
        # 検出された左右トリム量のうち小さい方で左右対称にトリミングする
        left, top, right, bottom = detect_trim_bounds(img_path, aspect_min=aspect_min)
        orig_w = w
        left_trim = max(0, left)
        right_trim = max(0, orig_w - right)
        sym_trim = min(left_trim, right_trim)
        sym_left = sym_trim
        sym_right = orig_w - sym_trim
        img = img.crop((sym_left, top, sym_right, bottom))
        w, h = img.size
    
    half = detect_gutter_x(img, center_band_ratio=0.12)
    
    if is_right_binding:
        # 右綴じ: page_1=右ページ（右端が外側）, page_2=左ページ（左端が外側）
        page_1 = img.crop((half, 0, w, h))
        page_2 = img.crop((0, 0, half, h))
        page_1 = trim_single_page(page_1, outer_side='right', aspect_min=aspect_min)
        page_2 = trim_single_page(page_2, outer_side='left', aspect_min=aspect_min)
        page_1, page_2 = _equalize_page_widths(page_1, page_2, 'right', 'left', aspect_min)
    else:
        # 左綴じ: page_1=左ページ（左端が外側）, page_2=右ページ（右端が外側）
        page_1 = img.crop((0, 0, half, h))
        page_2 = img.crop((half, 0, w, h))
        page_1 = trim_single_page(page_1, outer_side='left', aspect_min=aspect_min)
        page_2 = trim_single_page(page_2, outer_side='right', aspect_min=aspect_min)
        page_1, page_2 = _equalize_page_widths(page_1, page_2, 'left', 'right', aspect_min)
    
    ext = os.path.splitext(img_path)[1].lower()
    page_1_path = f"{output_prefix}_1{ext}"
    page_2_path = f"{output_prefix}_2{ext}"
    
    # JPEG保存時はRGBA→RGB変換が必要
    if ext in (".jpg", ".jpeg"):
        if page_1.mode == 'RGBA':
            page_1 = page_1.convert('RGB')
        if page_2.mode == 'RGBA':
            page_2 = page_2.convert('RGB')
    
    save_kw = {"quality": 95} if ext in (".jpg", ".jpeg") else {}
    page_1.save(page_1_path, **save_kw)
    page_2.save(page_2_path, **save_kw)
    
    img.close()
    page_1.close()
    page_2.close()
    return f"PREVIEW:{page_1_path}|{page_2_path}"

def trim_and_split(img_path, is_right_binding=True, no_trim=False, aspect_min=0.0, cover_width=0):
    """トリミング+分割。工程: 1)余白検知→対称トリム  2)ノドで分割  3)各ページのグレー余白除去。"""
    img = Image.open(img_path)
    w, h = img.size
    
    aspect = w / h if h > 0 else 0
    if aspect < ${AspectThreshold}:
        img.close()
        return "SKIP"
    
    if no_trim:
        left, top, right, bottom = 0, 0, w, h
        _dbg_geom(f"DEBUG_SPLIT: bounds left={left} top={top} right={right} bottom={bottom} (no_trim)")
    else:
        # 左右で異なる量をトリミングすると分割位置がノドをまたいでしまうことがあるため、
        # 検出された左右トリム量のうち小さい方で左右対称にトリミングしてから分割する
        left, top, right, bottom = detect_trim_bounds(img_path, aspect_min=aspect_min)
        orig_w = w
        left_trim = max(0, left)
        right_trim = max(0, orig_w - right)
        sym_trim_raw = min(left_trim, right_trim)
        sym_trim = sym_trim_raw
        min_page_width = 0
        max_allowed_trim = -1
        # 表紙の横ピクセル数を基準に削りすぎ防止（1ページあたりの最小幅を確保）
        if h > 0:
            min_page_width = int(h * aspect_min) if aspect_min > 0 else 0
            if cover_width > 0:
                min_page_width = max(min_page_width, cover_width)
            if min_page_width > 0:
                min_spread_width = min_page_width * 2
                if orig_w > min_spread_width:
                    max_allowed_trim = max(0, (orig_w - min_spread_width) // 2)
                    sym_trim = min(sym_trim, max_allowed_trim)
        _dbg_geom(f"DEBUG_SPLIT: bounds left={left} top={top} right={right} bottom={bottom}")
        _dbg_geom(f"DEBUG_SPLIT: left_trim={left_trim} right_trim={right_trim} sym_trim_raw={sym_trim_raw} sym_trim={sym_trim}")
        _dbg_geom(f"DEBUG_SPLIT: cover_width={cover_width} min_page_width={min_page_width} max_allowed_trim={max_allowed_trim}")
        sym_left = sym_trim
        sym_right = orig_w - sym_trim
        img = img.crop((sym_left, top, sym_right, bottom))
        w, h = img.size
        _dbg_geom(f"DEBUG_SPLIT: cropped w={w} h={h}")    
    half = detect_gutter_x(img, center_band_ratio=0.12)
    _dbg_geom(f"DEBUG_SPLIT: gutter half={half} (w={w})")
    target = int(cover_width * 1.01) if cover_width > 0 else 0
    mw_guard = target
    # 表紙以外は白ページも残すため、1枚にまとめず常に2ページに分割する
    img_rgb = img.convert("RGB")
    img_rgb.close()
    center_crops = _crop_pages_center_target(img, half, w, h, target, is_right_binding) if target > 0 else None
    if center_crops is not None:
        page_1, page_2 = center_crops
        page_1 = trim_single_page(page_1, outer_side=('right' if is_right_binding else 'left'), aspect_min=aspect_min, min_width_guard=mw_guard)
        page_2 = trim_single_page(page_2, outer_side=('left' if is_right_binding else 'right'), aspect_min=aspect_min, min_width_guard=mw_guard)
        page_1, page_2 = _equalize_page_widths(page_1, page_2, 'right' if is_right_binding else 'left', 'left' if is_right_binding else 'right', aspect_min, cover_width=cover_width)
    else:
        if is_right_binding:
            page_1 = img.crop((half, 0, w, h))
            page_2 = img.crop((0, 0, half, h))
            page_1 = trim_single_page(page_1, outer_side='right', aspect_min=aspect_min, min_width_guard=mw_guard)
            page_2 = trim_single_page(page_2, outer_side='left', aspect_min=aspect_min, min_width_guard=mw_guard)
            page_1, page_2 = _equalize_page_widths(page_1, page_2, 'right', 'left', aspect_min, cover_width=cover_width)
        else:
            page_1 = img.crop((0, 0, half, h))
            page_2 = img.crop((half, 0, w, h))
            page_1 = trim_single_page(page_1, outer_side='left', aspect_min=aspect_min, min_width_guard=mw_guard)
            page_2 = trim_single_page(page_2, outer_side='right', aspect_min=aspect_min, min_width_guard=mw_guard)
            page_1, page_2 = _equalize_page_widths(page_1, page_2, 'left', 'right', aspect_min, cover_width=cover_width)
    
    base = os.path.splitext(img_path)[0]
    ext = os.path.splitext(img_path)[1].lower()
    # 空白ページも削除せず両方保存。保存直前に表紙+1%を最終保証
    min_ok = int(cover_width * 1.01) if cover_width > 0 else 0
    if min_ok > 0:
        if page_1.size[0] < min_ok:
            old = page_1
            page_1 = _ensure_min_width(page_1, min_ok)
            if page_1 is not old:
                old.close()
        if page_2.size[0] < min_ok:
            old = page_2
            page_2 = _ensure_min_width(page_2, min_ok)
            if page_2 is not old:
                old.close()
    page_1_path = f"{base}_1{ext}"
    page_2_path = f"{base}_2{ext}"
    if ext in (".jpg", ".jpeg"):
        if page_1.mode == 'RGBA':
            page_1 = page_1.convert('RGB')
        if page_2.mode == 'RGBA':
            page_2 = page_2.convert('RGB')
    save_kw = {"quality": 95} if ext in (".jpg", ".jpeg") else {}
    page_1.save(page_1_path, **save_kw)
    page_2.save(page_2_path, **save_kw)
    
    img.close()
    page_1.close()
    page_2.close()
    
    time.sleep(0.1)
    _safe_remove(img_path)
    
    return "SPLIT:2"

def trim_and_split_one_sided(img_path, is_right_binding=True, no_trim=False, aspect_min=0.0, cover_width=0):
    """片側のみコンテンツ時も通常と同様に中央帯エッジでノド検出→分割。
    表紙幅未満になる場合は、中央から左右外側へコンテンツ→空白の境界をスキャンし、
    その境界で区切って表紙+1%となるようトリミング。"""
    try:
        return _trim_and_split_one_sided_impl(img_path, is_right_binding, no_trim, aspect_min, cover_width)
    except Exception as e:
        import traceback
        _dbg_geom(f"DEBUG_SPLIT_ONESIDED: fallback to trim_and_split (no_trim) due to: {e}")
        traceback.print_exc()
        try:
            # 通常の中央分割にフォールバック（必ず2ページに分割される）
            return trim_and_split(img_path, is_right_binding=is_right_binding, no_trim=True, aspect_min=aspect_min, cover_width=cover_width)
        except Exception as e2:
            import traceback as tb2
            tb2.print_exc()
            print(f"ERROR: one_sided fallback failed: {e2}", flush=True)
            raise

def _trim_and_split_one_sided_impl(img_path, is_right_binding=True, no_trim=False, aspect_min=0.0, cover_width=0):
    img = Image.open(img_path)
    w, h = img.size
    if cover_width <= 0 and w > 0:
        cover_width = w // 2
        _dbg_geom(f"DEBUG_SPLIT_ONESIDED: cover_width not passed, using half={cover_width}")
    aspect = w / h if h > 0 else 0
    if aspect < ${AspectThreshold}:
        img.close()
        return "SKIP"
    if not no_trim:
        left, top, right, bottom = detect_trim_bounds(img_path, aspect_min=aspect_min)
        orig_w = w
        left_trim = max(0, left)
        right_trim = max(0, orig_w - right)
        sym_trim = min(left_trim, right_trim)
        min_page_width = 0
        if h > 0:
            min_page_width = int(h * aspect_min) if aspect_min > 0 else 0
            if cover_width > 0:
                min_page_width = max(min_page_width, cover_width)
            if min_page_width > 0:
                min_spread_width = min_page_width * 2
                if orig_w > min_spread_width:
                    max_allowed_trim = max(0, (orig_w - min_spread_width) // 2)
                    sym_trim = min(sym_trim, max_allowed_trim)
        sym_left = sym_trim
        sym_right = orig_w - sym_trim
        # 横長スプレッドは左右のみトリムし高さは維持（他ページと高さを揃える）
        img = img.crop((sym_left, 0, sym_right, h))
        w, h = img.size
    half = detect_gutter_x(img, center_band_ratio=0.12)
    half = max(1, min(w - 1, half))  # 不正値ガード
    _dbg_geom(f"DEBUG_SPLIT_ONESIDED: half={half} w={w} cover_width={cover_width}")
    target_min = int(cover_width * 1.01) if cover_width > 0 else 0
    # 表紙以外は白ページも残すため、1枚にまとめず常に2ページに分割する
    center_crops = _crop_pages_center_target(img, half, w, h, target_min, is_right_binding) if target_min > 0 else None
    mw_guard = target_min
    if center_crops is not None:
        page_1, page_2 = center_crops
    else:
        if is_right_binding:
            page_1 = img.crop((half, 0, w, h))
            page_2 = img.crop((0, 0, half, h))
        else:
            page_1 = img.crop((0, 0, half, h))
            page_2 = img.crop((half, 0, w, h))
    page_1 = trim_single_page(page_1, outer_side=('right' if is_right_binding else 'left'), aspect_min=aspect_min, ocr_trim_mode=True, min_width_guard=mw_guard)
    page_2 = trim_single_page(page_2, outer_side=('left' if is_right_binding else 'right'), aspect_min=aspect_min, ocr_trim_mode=True, min_width_guard=mw_guard)
    page_1, page_2 = _equalize_page_widths(page_1, page_2,
        'right' if is_right_binding else 'left', 'left' if is_right_binding else 'right',
        aspect_min, ocr_trim_mode=True, cover_width=cover_width)
    need_expand = target_min > 0 and (page_1.size[0] < target_min or page_2.size[0] < target_min)
    if need_expand:
        page_1.close()
        page_2.close()
        img_rgb = img.convert("RGB")
        left_bound, right_bound = _find_content_boundaries_from_center(img_rgb, half, w, h)
        img_rgb.close()
        left_bound = max(0, min(left_bound, half - target_min))
        right_bound = min(w - 1, max(right_bound, half + target_min - 1))
        _dbg_geom(f"DEBUG_SPLIT_ONESIDED: expand outer left={left_bound} right={right_bound} target={target_min}")
        if is_right_binding:
            page_1 = img.crop((half, 0, right_bound + 1, h))
            page_2 = img.crop((left_bound, 0, half, h))
        else:
            page_1 = img.crop((left_bound, 0, half, h))
            page_2 = img.crop((half, 0, right_bound + 1, h))
        page_1 = trim_single_page(page_1, outer_side=('right' if is_right_binding else 'left'), aspect_min=aspect_min, ocr_trim_mode=True, min_width_guard=mw_guard)
        page_2 = trim_single_page(page_2, outer_side=('left' if is_right_binding else 'right'), aspect_min=aspect_min, ocr_trim_mode=True, min_width_guard=mw_guard)
        page_1, page_2 = _equalize_page_widths(page_1, page_2,
            'right' if is_right_binding else 'left', 'left' if is_right_binding else 'right',
            aspect_min, ocr_trim_mode=True, cover_width=cover_width)
        if target_min > 0 and (page_1.size[0] < target_min or page_2.size[0] < target_min):
            old_p1, old_p2 = page_1, page_2
            page_1 = _ensure_min_width(page_1, target_min)
            page_2 = _ensure_min_width(page_2, target_min)
            if page_1 is not old_p1:
                old_p1.close()
            if page_2 is not old_p2:
                old_p2.close()
    base = os.path.splitext(img_path)[0]
    ext = os.path.splitext(img_path)[1].lower()
    # 保存直前に表紙+1%を最終保証（空白多いページ含む）
    if target_min > 0:
        if page_1.size[0] < target_min:
            old = page_1
            page_1 = _ensure_min_width(page_1, target_min)
            if page_1 is not old:
                old.close()
        if page_2.size[0] < target_min:
            old = page_2
            page_2 = _ensure_min_width(page_2, target_min)
            if page_2 is not old:
                old.close()
    save_kw = {"quality": 95} if ext in (".jpg", ".jpeg") else {}
    page_1_path = f"{base}_1{ext}"
    page_2_path = f"{base}_2{ext}"
    if ext in (".jpg", ".jpeg"):
        if page_1.mode == 'RGBA':
            page_1 = page_1.convert('RGB')
        if page_2.mode == 'RGBA':
            page_2 = page_2.convert('RGB')
    w1f, w2f = page_1.size[0], page_2.size[0]
    _dbg_geom(f"DEBUG_SPLIT_ONESIDED: before save w1={w1f} w2={w2f} target_min={target_min}")
    if target_min > 0:
        if w1f < target_min:
            old = page_1
            page_1 = _ensure_min_width(page_1, target_min)
            if page_1 is not old:
                old.close()
            _dbg_geom(f"DEBUG_SPLIT_ONESIDED: page_1 resize {w1f}->{target_min}")
        if page_2.size[0] < target_min:
            old = page_2
            page_2 = _ensure_min_width(page_2, target_min)
            if page_2 is not old:
                old.close()
            _dbg_geom(f"DEBUG_SPLIT_ONESIDED: page_2 resize {w2f}->{target_min}")
    page_1.save(page_1_path, **save_kw)
    page_2.save(page_2_path, **save_kw)
    img.close()
    page_1.close()
    page_2.close()
    time.sleep(0.1)
    _safe_remove(img_path)
    return "SPLIT:2"

def trim_and_split_at_gutter_with_margins(img_path, gutter_x_orig, left_trim_px, right_trim_px, is_right_binding=True, aspect_min=0.0, cover_width=0, top_trim_px=0, bottom_trim_px=0):
    """
    ①（任意）上端・下端から top_trim_px / bottom_trim_px を削る。
    ②元画像上のノド位置(gutter_x、GUIの%%から算出したpx)で左右に分割。
    ③左ページ帯[0,gx)の左端からleft_trim_px、右ページ帯[gx,w)の右端からright_trim_pxを削る。
    """
    _m = 5
    img = Image.open(img_path)
    w, h = img.size
    tt = max(0, int(top_trim_px))
    bt = max(0, int(bottom_trim_px))
    if tt + bt > h - _m * 2:
        tt = min(tt, max(0, h // 2 - _m))
        bt = min(bt, max(0, h - tt - _m * 2))
    if h - tt - bt < _m * 2:
        img.close()
        return "ERROR:Invalid vertical trim top=%s bottom=%s h=%s" % (tt, bt, h)
    if tt > 0 or bt > 0:
        img = img.crop((0, tt, w, h - bt))
        w, h = img.size
    gx = int(float(gutter_x_orig))
    gx = max(_m + 1, min(w - _m - 1, gx))
    lt0 = max(0, int(left_trim_px))
    rt0 = max(0, int(right_trim_px))
    lt = min(lt0, max(0, gx - _m - 1))
    rt = min(rt0, max(0, w - gx - _m - 1))
    if lt0 != lt or rt0 != rt:
        _dbg_geom("DEBUG_SPLIT_GUTTER_MARGINS_CLAMP: requested left=%s right=%s -> effective left=%s right=%s (gutter_x=%s full_w=%s)" % (lt0, rt0, lt, rt, gx, w))
    lw = gx - lt
    rw = (w - gx) - rt
    if lw < _m or rw < _m:
        img.close()
        return "ERROR:Invalid trim gutter=%s lt=%s rt=%s (左幅%s 右幅%s full_w=%s)" % (gx, lt, rt, lw, rw, w)
    _dbg_geom("DEBUG_SPLIT_GUTTER_MARGINS: split_then_trim full_w=%s gutter_x=%s left_trim=%s right_trim=%s -> left_page_w=%s right_page_w=%s" % (w, gx, lt, rt, lw, rw))
    if is_right_binding:
        page_1 = img.crop((gx, 0, w - rt, h))
        page_2 = img.crop((lt, 0, gx, h))
    else:
        page_1 = img.crop((lt, 0, gx, h))
        page_2 = img.crop((gx, 0, w - rt, h))
    img.close()
    base = os.path.splitext(img_path)[0]
    ext = os.path.splitext(img_path)[1].lower()
    save_kw = {"quality": 95} if ext in (".jpg", ".jpeg") else {}
    if ext in (".jpg", ".jpeg"):
        if page_1.mode == 'RGBA': page_1 = page_1.convert('RGB')
        if page_2.mode == 'RGBA': page_2 = page_2.convert('RGB')
    page_1.save(base + "_1" + ext, **save_kw)
    page_2.save(base + "_2" + ext, **save_kw)
    page_1.close()
    page_2.close()
    time.sleep(0.1)
    _safe_remove(img_path)
    return "SPLIT:2"

def split_with_manual_trim(img_path, is_right_binding=True, left_trim_px=0, right_trim_px=0, cover_width=0, aspect_min=0.0):
    """ユーザー指定の左右トリムでスプレッドを分割。左端からleft_trim_px、右端からright_trim_pxを削ってから中央で分割。"""
    img = Image.open(img_path)
    w, h = img.size
    left = max(0, min(left_trim_px, w - 100))
    right = max(left + 100, w - max(0, min(right_trim_px, w - 100)))
    if right <= left:
        img.close()
        return "ERROR:Invalid trim"
    img = img.crop((left, 0, right, h))
    w, h = img.size
    half = w // 2
    mw_guard = int(cover_width * 1.01) if cover_width > 0 else 0
    if is_right_binding:
        page_1 = img.crop((half, 0, w, h))
        page_2 = img.crop((0, 0, half, h))
        page_1 = trim_single_page(page_1, outer_side='right', aspect_min=aspect_min, min_width_guard=mw_guard)
        page_2 = trim_single_page(page_2, outer_side='left', aspect_min=aspect_min, min_width_guard=mw_guard)
        page_1, page_2 = _equalize_page_widths(page_1, page_2, 'right', 'left', aspect_min, cover_width=cover_width)
    else:
        page_1 = img.crop((0, 0, half, h))
        page_2 = img.crop((half, 0, w, h))
        page_1 = trim_single_page(page_1, outer_side='left', aspect_min=aspect_min, min_width_guard=mw_guard)
        page_2 = trim_single_page(page_2, outer_side='right', aspect_min=aspect_min, min_width_guard=mw_guard)
        page_1, page_2 = _equalize_page_widths(page_1, page_2, 'left', 'right', aspect_min, cover_width=cover_width)
    min_ok = int(cover_width * 1.01) if cover_width > 0 else 0
    if min_ok > 0:
        if page_1.size[0] < min_ok:
            old = page_1
            page_1 = _ensure_min_width(page_1, min_ok)
            if page_1 is not old:
                old.close()
        if page_2.size[0] < min_ok:
            old = page_2
            page_2 = _ensure_min_width(page_2, min_ok)
            if page_2 is not old:
                old.close()
    base = os.path.splitext(img_path)[0]
    ext = os.path.splitext(img_path)[1].lower()
    save_kw = {"quality": 95} if ext in (".jpg", ".jpeg") else {}
    if ext in (".jpg", ".jpeg"):
        if page_1.mode == 'RGBA':
            page_1 = page_1.convert('RGB')
        if page_2.mode == 'RGBA':
            page_2 = page_2.convert('RGB')
    page_1.save(base + "_1" + ext, **save_kw)
    page_2.save(base + "_2" + ext, **save_kw)
    img.close()
    page_1.close()
    page_2.close()
    time.sleep(0.1)
    _safe_remove(img_path)
    return "SPLIT:2"

def trim_and_split_at_gutter(img_path, gutter_x_orig, is_right_binding=True, no_trim=False, aspect_min=0.0, cover_width=0, no_vertical_trim=False, gui_exact=False):
    """ユーザー指定のノド位置(gutter_x_orig=元画像のx座標)で分割。trim_and_splitと同様の工程。
    no_vertical_trim=True: 上下トリムを無効化（ノドキャッシュ適用時・縦の削れ防止）
    gui_exact=True: ノド・余白GUIで確定した分割のみ（自動の detect_trim_bounds / 片ページ trim_single_page / 幅均等化を一切しない）"""
    img = Image.open(img_path)
    w, h = img.size
    orig_w = w
    if gutter_x_orig <= 0 or gutter_x_orig >= orig_w:
        gutter_x_orig = orig_w // 2
    aspect = w / h if h > 0 else 0
    if aspect < ${AspectThreshold}:
        img.close()
        return "SKIP"
    if gui_exact:
        no_trim = True
    if no_trim:
        left, top, right, bottom = 0, 0, w, h
        sym_left, sym_right = 0, w
    else:
        max_y = 0 if no_vertical_trim else None
        left, top, right, bottom = detect_trim_bounds(img_path, aspect_min=aspect_min, max_trim_y_override=max_y)
        orig_w = w
        left_trim = max(0, left)
        right_trim = max(0, orig_w - right)
        sym_trim = min(left_trim, right_trim)
        min_page_width = int(h * aspect_min) if (aspect_min > 0 and h > 0) else 0
        if cover_width > 0:
            min_page_width = max(min_page_width, cover_width)
        if min_page_width > 0:
            min_spread_width = min_page_width * 2
            if orig_w > min_spread_width:
                max_allowed_trim = max(0, (orig_w - min_spread_width) // 2)
                sym_trim = min(sym_trim, max_allowed_trim)
        sym_left = sym_trim
        sym_right = orig_w - sym_trim
        img = img.crop((sym_left, top, sym_right, bottom))
        w, h = img.size
    # 元画像座標のgutter_xをクロップ後座標に変換
    half = max(1, min(w - 1, gutter_x_orig - sym_left))
    _dbg_geom(f"DEBUG_SPLIT_GUTTER: gutter_x_orig={gutter_x_orig} sym_left={sym_left} -> half={half} (w={w}) gui_exact={gui_exact}")
    if gui_exact:
        if is_right_binding:
            page_1 = img.crop((half, 0, w, h))
            page_2 = img.crop((0, 0, half, h))
        else:
            page_1 = img.crop((0, 0, half, h))
            page_2 = img.crop((half, 0, w, h))
    else:
        target = int(cover_width * 1.01) if cover_width > 0 else 0
        mw_guard = target
        img_rgb = img.convert("RGB")
        img_rgb.close()
        center_crops = _crop_pages_center_target(img, half, w, h, target, is_right_binding) if target > 0 else None
        if center_crops is not None:
            page_1, page_2 = center_crops
            page_1 = trim_single_page(page_1, outer_side=('right' if is_right_binding else 'left'), aspect_min=aspect_min, min_width_guard=mw_guard)
            page_2 = trim_single_page(page_2, outer_side=('left' if is_right_binding else 'right'), aspect_min=aspect_min, min_width_guard=mw_guard)
            page_1, page_2 = _equalize_page_widths(page_1, page_2, 'right' if is_right_binding else 'left', 'left' if is_right_binding else 'right', aspect_min, cover_width=cover_width, skip_resize=True)
        else:
            if is_right_binding:
                page_1 = img.crop((half, 0, w, h))
                page_2 = img.crop((0, 0, half, h))
            else:
                page_1 = img.crop((0, 0, half, h))
                page_2 = img.crop((half, 0, w, h))
            page_1 = trim_single_page(page_1, outer_side=('right' if is_right_binding else 'left'), aspect_min=aspect_min, min_width_guard=mw_guard)
            page_2 = trim_single_page(page_2, outer_side=('left' if is_right_binding else 'right'), aspect_min=aspect_min, min_width_guard=mw_guard)
            page_1, page_2 = _equalize_page_widths(page_1, page_2, 'right' if is_right_binding else 'left', 'left' if is_right_binding else 'right', aspect_min, cover_width=cover_width, skip_resize=True)
    base = os.path.splitext(img_path)[0]
    ext = os.path.splitext(img_path)[1].lower()
    # 狭くなっても横リサイズは行わない（ユーザー指定ノドのずれ時に変形を防ぐ）
    page_1_path = f"{base}_1{ext}"
    page_2_path = f"{base}_2{ext}"
    if ext in (".jpg", ".jpeg"):
        if page_1.mode == 'RGBA': page_1 = page_1.convert('RGB')
        if page_2.mode == 'RGBA': page_2 = page_2.convert('RGB')
    save_kw = {"quality": 95} if ext in (".jpg", ".jpeg") else {}
    page_1.save(page_1_path, **save_kw)
    page_2.save(page_2_path, **save_kw)
    img.close()
    page_1.close()
    page_2.close()
    time.sleep(0.1)
    _safe_remove(img_path)
    return "SPLIT:2"

def split_at_center_only(img_path, is_right_binding=True):
    """フォト等で手動トリム済みの画像を中央で分割。トリミングは行わず分割のみ。"""
    img = Image.open(img_path)
    w, h = img.size
    half = w // 2
    base = os.path.splitext(img_path)[0]
    ext = os.path.splitext(img_path)[1].lower()
    save_kw = {"quality": 95} if ext in (".jpg", ".jpeg") else {}
    if is_right_binding:
        page_1 = img.crop((half, 0, w, h))
        page_2 = img.crop((0, 0, half, h))
    else:
        page_1 = img.crop((0, 0, half, h))
        page_2 = img.crop((half, 0, w, h))
    if ext in (".jpg", ".jpeg"):
        if page_1.mode == 'RGBA': page_1 = page_1.convert('RGB')
        if page_2.mode == 'RGBA': page_2 = page_2.convert('RGB')
    page_1.save(base + "_1" + ext, **save_kw)
    page_2.save(base + "_2" + ext, **save_kw)
    img.close()
    page_1.close()
    page_2.close()
    time.sleep(0.1)
    _safe_remove(img_path)
    return "SPLIT:2"

def _batch_split_worker(args):
    """ProcessPoolExecutor用: 1枚のtrim_and_split処理。モジュールトップで定義（pickle用）"""
    path, is_rb, no_trim, aspect_min, cover_width, split_mode, aspect_ref = args
    try:
        if split_mode == "one_sided_split":
            return (path, trim_and_split_one_sided(path, is_right_binding=is_rb, no_trim=(str(no_trim).lower() == "true"), aspect_min=aspect_min, cover_width=cover_width))
        elif split_mode == "split":
            return (path, trim_and_split(path, is_right_binding=is_rb, no_trim=(str(no_trim).lower() == "true"), aspect_min=aspect_min, cover_width=cover_width))
        elif split_mode == "trim_toc_split":
            return (path, trim_and_split_toc(path, is_right_binding=is_rb, aspect_min=aspect_min, aspect_target=aspect_ref, cover_width=cover_width))
        elif split_mode == "trim_white_margin_split":
            return (path, trim_and_split_white_margin(path, is_right_binding=is_rb, aspect_min=aspect_min, aspect_target=aspect_ref, cover_width=cover_width))
        else:
            return (path, trim_and_split(path, is_right_binding=is_rb, no_trim=(str(no_trim).lower() == "true"), aspect_min=aspect_min, cover_width=cover_width))
    except Exception as e:
        return (path, f"ERROR:{str(e)}")

def _batch_analyze_worker(path):
    """ProcessPoolExecutor用: is_one_sided 1件。モジュールトップで定義（pickle用）"""
    try:
        return (path, is_one_sided(path))
    except Exception as e:
        return (path, f"ERROR:{str(e)}")

def _batch_aspect_worker(path):
    """ProcessPoolExecutor用: get_trim_split_aspect 1件"""
    try:
        a = get_trim_split_aspect(path)
        return (path, a)
    except Exception as e:
        return (path, 0.0)

def _batch_split_at_gutter_from_json(spec_path, argv_right_binding):
    """1プロセス内で split_at_gutter / split_at_gutter_with_margins を複数件実行。1行1JSONを stdout へ。
    仕様JSONは必ず UTF-8（BOM 可）。Windows ではテキスト open の既定が cp932 になり得るため rb+decode を固定する。
    各行の print は ensure_ascii=True（\\uXXXX）にし、PowerShell が子プロセス stdout を取り込んでもパスが化けないようにする。"""
    with open(spec_path, "rb") as f:
        raw = f.read()
    spec = json.loads(raw.decode("utf-8-sig"))
    rb = bool(spec.get("right_binding", argv_right_binding))
    jobs = spec.get("jobs") or []
    for i, job in enumerate(jobs):
        op = (job.get("op") or "").lower()
        inp = job.get("input") or job.get("path") or ""
        if isinstance(inp, str):
            inp = inp.strip().strip("\ufeff")
        rec = {"index": i, "input": inp, "ok": False, "result": ""}
        if not inp or not os.path.isfile(inp):
            rec["result"] = "ERROR:missing_input"
            print(json.dumps(rec, ensure_ascii=True), flush=True)
            continue
        try:
            if op == "split_at_gutter_with_margins":
                gx = int(float(job.get("gutter_x", 0)))
                lt = int(float(job.get("left_trim", job.get("left", 0))))
                rt = int(float(job.get("right_trim", job.get("right", 0))))
                tt = int(float(job.get("top_trim", job.get("top", 0))))
                bt = int(float(job.get("bottom_trim", job.get("bottom", 0))))
                aspect_min = float(job.get("aspect_min", 0.0))
                cover_width = int(float(job.get("cover_width", 0)))
                res = trim_and_split_at_gutter_with_margins(inp, gx, lt, rt, is_right_binding=rb, aspect_min=aspect_min, cover_width=cover_width, top_trim_px=tt, bottom_trim_px=bt)
            elif op == "split_at_gutter":
                gx = int(float(job.get("gutter_x", 0)))
                no_trim = bool(job.get("no_trim", False))
                aspect_min = float(job.get("aspect_min", 0.0))
                cover_width = int(float(job.get("cover_width", 0)))
                no_vertical_trim = bool(job.get("no_vertical_trim", True))
                gui_exact = bool(job.get("gui_exact", False))
                res = trim_and_split_at_gutter(inp, gx, is_right_binding=rb, no_trim=no_trim, aspect_min=aspect_min, cover_width=cover_width, no_vertical_trim=no_vertical_trim, gui_exact=gui_exact)
            else:
                res = "ERROR:unknown_op:%s" % op
            rec["result"] = str(res)
            rec["ok"] = not str(res).startswith("ERROR")
        except Exception as e:
            rec["result"] = "ERROR:%s" % str(e)
        print(json.dumps(rec, ensure_ascii=True), flush=True)

def _parse_aspect_min(argv, default_idx=5):
    """argv から aspect_min を取得（複数モードで使用）"""
    for i in range(default_idx, min(default_idx + 2, len(argv))):
        try:
            v = float(argv[i])
            if v >= 0:
                return v
        except (ValueError, IndexError):
            pass
    return 0.0

def _toc_ocr_bbox(img_rgb, w, h, invert=False, padding=40, padding_y=None):
    """OCRでテキストbboxを取得し、外接矩形＋パディングを返す。上下は多めに余白を残す。"""
    py = padding_y if padding_y is not None else padding
    try:
        import pytesseract
        ocr_img = img_rgb
        if invert:
            import PIL.ImageOps
            ocr_img = PIL.ImageOps.invert(img_rgb.convert('RGB'))
        data = pytesseract.image_to_data(ocr_img, lang='jpn+eng', output_type=pytesseract.Output.DICT, config='--psm 6')
        if invert:
            ocr_img.close()
    except Exception:
        return None
    boxes = []
    n_boxes = len(data.get('text', []))
    for i in range(n_boxes):
        conf = int(data.get('conf', [0])[i]) if i < len(data.get('conf', [])) else 0
        txt = (data.get('text', []) or [''])[i]
        if conf > 0 or (txt and txt.strip()):
            x = data['left'][i]
            y = data['top'][i]
            bw = data['width'][i]
            bh = data['height'][i]
            if bw > 0 and bh > 0:
                boxes.append((x, y, x + bw, y + bh))
    if len(boxes) < 2:
        return None
    l = max(0, min(b[0] for b in boxes) - padding)
    t = max(0, min(b[1] for b in boxes) - py)
    r = min(w, max(b[2] for b in boxes) + padding)
    b_ = min(h, max(b[3] for b in boxes) + py)
    if r - l >= 50 and b_ - t >= 50:
        return (int(l), int(t), int(r), int(b_))
    return None

def detect_toc_trim_bounds(img_path):
    """【目次専用】OCRで境界を取得し、余白をきちんとトリミング。"""
    img = Image.open(img_path)
    img_rgb = img.convert("RGB")
    w, h = img.size
    if w < 100 or h < 100:
        img.close()
        return (0, 0, w, h)
    corner_size = max(2, min(w, h) // 20)
    samples = []
    for (x0, y0) in [(0, 0), (w - corner_size, 0), (0, h - corner_size), (w - corner_size, h - corner_size)]:
        x1 = min(x0 + corner_size, w)
        y1 = min(y0 + corner_size, h)
        total, n = 0, 0
        for x in range(x0, x1, max(1, (x1 - x0) // 4)):
            for y in range(y0, y1, max(1, (y1 - y0) // 4)):
                p = img_rgb.getpixel((x, y))
                total += (p[0] + p[1] + p[2]) // 3
                n += 1
        if n:
            samples.append(total / n)
    avg_bg = sum(samples) / len(samples) if samples else 128
    is_dark_bg = avg_bg < 100
    is_light_bg = avg_bg > 200
    toc_padding_x = 25
    expand_left = max(int(w * 0.05), 40)
    result = None
    if is_dark_bg:
        bbox = _toc_ocr_bbox(img_rgb, w, h, invert=True, padding=toc_padding_x)
        if bbox:
            ol, ot, or_, ob = bbox
            # 右側は白余白を含めない（bbox は既に padding 済み）。左側は expand で余裕を取る
            result = (max(0, ol - expand_left), 0, min(w, or_), h)
        if not result:
            left, top, right, bottom = detect_trim_bounds(
                img_path, aspect_min=0.0,
                max_trim_x_override=min(w // 2, 1200), max_trim_y_override=min(h // 2, 600),
                edge_exclude_override=0.2, min_crop_ratio=0.15, use_safe_region=False
            )
            result = (left, top, right, bottom)
    elif is_light_bg:
        bbox = _toc_ocr_bbox(img_rgb, w, h, invert=False, padding=toc_padding_x)
        if bbox:
            result = bbox
        if not result:
            result = detect_trim_bounds(
                img_path, aspect_min=0.0,
                max_trim_x_override=min(w // 2, 1500), min_crop_ratio=0.2
            )
    else:
        result = detect_trim_bounds(
            img_path, aspect_min=0.0,
            max_trim_x_override=min(w // 2, 1200), min_crop_ratio=0.2
        )
    img_rgb.close()
    img.close()
    left, _, right, _ = result
    if not is_dark_bg:
        left = max(0, left - 15)
        right = min(w, right + 15)
    return (left, 0, right, h)

def trim_and_split_toc(img_path, is_right_binding=True, aspect_min=0.0, aspect_target=0.0, cover_width=0):
    """目次専用: OCRで余白検出 → 事前トリミング → 中央で分割 → 各ページのグレー余白除去"""
    img = Image.open(img_path)
    w, h = img.size
    aspect = w / h if h > 0 else 0
    if aspect < ${AspectThreshold}:
        img.close()
        return "SKIP"
    left, _, right, _ = detect_toc_trim_bounds(img_path)
    img.close()
    img = Image.open(img_path)
    w, h = img.size
    img = img.crop((left, 0, right, h))
    w, h = img.size
    half = w // 2
    ocr_mode = True
    mw_guard = int(cover_width * 1.01) if cover_width > 0 else 0
    if is_right_binding:
        page_1 = img.crop((half, 0, w, h))
        page_2 = img.crop((0, 0, half, h))
        page_1 = trim_single_page(page_1, outer_side='right', aspect_min=aspect_min, ocr_trim_mode=ocr_mode, min_width_guard=mw_guard)
        page_2 = trim_single_page(page_2, outer_side='left', aspect_min=aspect_min, ocr_trim_mode=ocr_mode, min_width_guard=mw_guard)
        page_1, page_2 = _equalize_page_widths(page_1, page_2, 'right', 'left', aspect_min, ocr_trim_mode=ocr_mode, cover_width=cover_width)
    else:
        page_1 = img.crop((0, 0, half, h))
        page_2 = img.crop((half, 0, w, h))
        page_1 = trim_single_page(page_1, outer_side='left', aspect_min=aspect_min, ocr_trim_mode=ocr_mode, min_width_guard=mw_guard)
        page_2 = trim_single_page(page_2, outer_side='right', aspect_min=aspect_min, ocr_trim_mode=ocr_mode, min_width_guard=mw_guard)
        page_1, page_2 = _equalize_page_widths(page_1, page_2, 'left', 'right', aspect_min, ocr_trim_mode=ocr_mode, cover_width=cover_width)
    if mw_guard > 0:
        if page_1.size[0] < mw_guard:
            old = page_1
            page_1 = _ensure_min_width(page_1, mw_guard)
            if page_1 is not old:
                old.close()
        if page_2.size[0] < mw_guard:
            old = page_2
            page_2 = _ensure_min_width(page_2, mw_guard)
            if page_2 is not old:
                old.close()
    base = os.path.splitext(img_path)[0]
    ext = os.path.splitext(img_path)[1].lower()
    page_1_path = f"{base}_1{ext}"
    page_2_path = f"{base}_2{ext}"
    if ext in (".jpg", ".jpeg"):
        if page_1.mode == 'RGBA':
            page_1 = page_1.convert('RGB')
        if page_2.mode == 'RGBA':
            page_2 = page_2.convert('RGB')
    save_kw = {"quality": 95} if ext in (".jpg", ".jpeg") else {}
    page_1.save(page_1_path, **save_kw)
    page_2.save(page_2_path, **save_kw)
    img.close()
    page_1.close()
    page_2.close()
    time.sleep(0.1)
    _safe_remove(img_path)
    return "SPLIT:2"

def detect_white_margin_trim_bounds(img_path):
    """【白余白ページ専用】目次なら余白をきちんとトリミング。非目次なら余白を少なく積極トリミング。"""
    img = Image.open(img_path)
    img_rgb = img.convert("RGB")
    w, h = img.size
    if w < 400 or h < 400:
        img.close()
        return (0, 0, w, h)
    is_toc = (detect_toc(img_path) == "TOC")
    if is_toc:
        padding_x, padding_y = 40, 45
    else:
        padding_x, padding_y = 18, 22
    bbox = _ocr_content_bbox(img_rgb, w, h, padding=padding_x, padding_y=padding_y)
    img_rgb.close()
    img.close()
    if bbox:
        left, top, right, bottom = bbox
        cw, ch = right - left, bottom - top
        if cw >= w * 0.15 and ch >= h * 0.15 and cw <= w * 0.98 and ch <= h * 0.98:
            return (left, top, right, bottom)
    return (0, 0, w, h)

def trim_and_split_white_margin(img_path, is_right_binding=True, aspect_min=0.0, aspect_target=0.0, cover_width=0):
    """白余白ページ専用: OCR余白検出 → ノドで分割 → 各ページのグレー余白除去。"""
    img = Image.open(img_path)
    w, h = img.size
    aspect = w / h if h > 0 else 0
    if aspect < ${AspectThreshold}:
        img.close()
        return "SKIP"
    left, top, right, bottom = detect_white_margin_trim_bounds(img_path)
    img = Image.open(img_path)
    w, h = img.size
    min_spread_width = 0
    # 表紙の横ピクセル数を基準に、1ページあたり表紙+1%を確保（削りすぎ防止）
    if h > 0:
        min_page_width = int(h * aspect_min) if aspect_min > 0 else 0
        min_ok = int(cover_width * 1.01) if cover_width > 0 else 0
        if min_ok > 0:
            min_page_width = max(min_page_width, min_ok)
        min_spread_width = min_page_width * 2
        cur_w = right - left
        if min_page_width > 0 and cur_w > 0 and w > min_spread_width:
            # OCRの中心は維持しつつ、必要なら左右に広げて最低幅を確保
            need_w = max(cur_w, min_spread_width)
            if need_w > w:
                need_w = w
            extra = (need_w - cur_w) // 2
            left = max(0, left - extra)
            right = min(w, right + extra)
    img = img.crop((left, top, right, bottom))
    w, h = img.size
    # 白余白ページも表紙と同程度の縦横比に揃える。表紙+1%未満にはしない。
    at_raw = aspect_target if aspect_target > 0 else (aspect_min if aspect_min > 0 else 0.7)
    at = min(at_raw, 0.7)
    target_spread = 2.0 * at
    floor_w = min_spread_width if (cover_width > 0 and min_spread_width > 0) else 0
    if at > 0 and h > 0:
        cur = w / h
        if cur > target_spread:
            new_w = int(h * target_spread)
            if floor_w > 0 and new_w < floor_w:
                new_w = floor_w
            dx = (w - new_w) // 2
            img = img.crop((dx, 0, dx + new_w, h))
            w, h = img.size
        elif cur < target_spread and w > 0:
            new_h = int(w / target_spread)
            dy = (h - new_h) // 2
            img = img.crop((0, dy, w, dy + new_h))
            w, h = img.size
    half = detect_gutter_x(img, center_band_ratio=0.12)
    ocr_mode = True
    mw_guard = int(cover_width * 1.01) if cover_width > 0 else 0
    if is_right_binding:
        page_1 = img.crop((half, 0, w, h))
        page_2 = img.crop((0, 0, half, h))
        page_1 = trim_single_page(page_1, outer_side='right', aspect_min=aspect_min, ocr_trim_mode=ocr_mode, min_width_guard=mw_guard)
        page_2 = trim_single_page(page_2, outer_side='left', aspect_min=aspect_min, ocr_trim_mode=ocr_mode, min_width_guard=mw_guard)
        page_1, page_2 = _equalize_page_widths(page_1, page_2, 'right', 'left', aspect_min, ocr_trim_mode=ocr_mode, cover_width=cover_width)
    else:
        page_1 = img.crop((0, 0, half, h))
        page_2 = img.crop((half, 0, w, h))
        page_1 = trim_single_page(page_1, outer_side='left', aspect_min=aspect_min, ocr_trim_mode=ocr_mode, min_width_guard=mw_guard)
        page_2 = trim_single_page(page_2, outer_side='right', aspect_min=aspect_min, ocr_trim_mode=ocr_mode, min_width_guard=mw_guard)
        page_1, page_2 = _equalize_page_widths(page_1, page_2, 'left', 'right', aspect_min, ocr_trim_mode=ocr_mode, cover_width=cover_width)
    if mw_guard > 0:
        if page_1.size[0] < mw_guard:
            old = page_1
            page_1 = _ensure_min_width(page_1, mw_guard)
            if page_1 is not old:
                old.close()
        if page_2.size[0] < mw_guard:
            old = page_2
            page_2 = _ensure_min_width(page_2, mw_guard)
            if page_2 is not old:
                old.close()
    base = os.path.splitext(img_path)[0]
    ext = os.path.splitext(img_path)[1].lower()
    page_1_path = f"{base}_1{ext}"
    page_2_path = f"{base}_2{ext}"
    if ext in (".jpg", ".jpeg"):
        if page_1.mode == 'RGBA':
            page_1 = page_1.convert('RGB')
        if page_2.mode == 'RGBA':
            page_2 = page_2.convert('RGB')
    save_kw = {"quality": 95} if ext in (".jpg", ".jpeg") else {}
    page_1.save(page_1_path, **save_kw)
    page_2.save(page_2_path, **save_kw)
    img.close()
    page_1.close()
    page_2.close()
    time.sleep(0.1)
    _safe_remove(img_path)
    return "SPLIT:2"

def _ocr_toc_keywords(txt):
    """テキストに目次キーワードが含まれるか判定"""
    import re
    txt = (txt or "").replace("\n", " ")
    txt_upper = txt.upper()
    patterns = [
        (r'CONTENTS', True),
        (r'目次', False), (r'カタログ', False), (r'収録', False),
        (r'第\s*[0-9０-９]+\s*話', False), (r'第\s*[0-9０-９]+\s*章', False),
        (r'[0-9０-９]+\s*ページ', False), (r'P\.?\s*[0-9０-９]+', True),
    ]
    for p, use_upper in patterns:
        s = txt_upper if use_upper else txt
        if re.search(p, s):
            return True
    return False

def detect_toc(img_path):
    """巻頭用: OCRで目次ページかどうか判定。黒背景は反転＋PSM調整で認識率向上。"""
    try:
        import pytesseract
    except ImportError:
        return "NOT_TOC"
    try:
        img = Image.open(img_path)
        if img.mode not in ('RGB', 'L'):
            img = img.convert('RGB')
        w, h = img.size
        if w < 100 or h < 100:
            img.close()
            return "NOT_TOC"
        short = min(w, h)
        if short < 800:
            scale = 800.0 / short
            new_w = int(w * scale)
            new_h = int(h * scale)
            img = img.resize((new_w, new_h), getattr(Image, 'Resampling', Image).LANCZOS)
        # 背景判定: 四隅の平均輝度
        corner_size = max(2, min(img.size[0], img.size[1]) // 20)
        samples = []
        for (x0, y0) in [(0, 0), (img.size[0] - corner_size, 0), (0, img.size[1] - corner_size), (img.size[0] - corner_size, img.size[1] - corner_size)]:
            x1 = min(x0 + corner_size, img.size[0])
            y1 = min(y0 + corner_size, img.size[1])
            total, n = 0, 0
            for x in range(x0, x1, max(1, (x1 - x0) // 4)):
                for y in range(y0, y1, max(1, (y1 - y0) // 4)):
                    p = img.getpixel((x, y))
                    g = (p[0] + p[1] + p[2]) // 3 if isinstance(p, (list, tuple)) and len(p) >= 3 else p
                    total += g
                    n += 1
            if n:
                samples.append(total / n)
        avg_bg = sum(samples) / len(samples) if samples else 128
        is_dark_bg = avg_bg < 100
        ocr_config = '--psm 6'
        txt = pytesseract.image_to_string(img, lang='jpn+eng', config=ocr_config)
        if _ocr_toc_keywords(txt):
            img.close()
            return "TOC"
        if is_dark_bg:
            import PIL.ImageOps
            inv = PIL.ImageOps.invert(img.convert('RGB'))
            txt = pytesseract.image_to_string(inv, lang='jpn+eng', config=ocr_config)
            inv.close()
            if _ocr_toc_keywords(txt):
                img.close()
                return "TOC"
        img.close()
        return "NOT_TOC"
    except Exception:
        return "NOT_TOC"

