                aspect_min = _parse_aspect_min(sys.argv, 5)
                left, top, right, bottom = detect_trim_bounds(src_path, aspect_min=aspect_min)
                print(f"MARGIN_BOUNDS:{int(left)},{int(top)},{int(right)},{int(bottom)}", flush=True)
            except Exception as _e_mb:
                print(f"MARGIN_BOUNDS_ERROR:{_e_mb}", flush=True)
        elif mode == "trim_only":
            aspect_min = _parse_aspect_min(sys.argv, 5)
            result = trim_only(src_path, output_path=(arg4 if arg4 else None), aspect_min=aspect_min)
            print(result)
        elif mode == "crop_gui_margins":
            left_trim = int(float(sys.argv[5])) if len(sys.argv) > 5 else 0
            top_trim = int(float(sys.argv[6])) if len(sys.argv) > 6 else 0
            right_trim = int(float(sys.argv[7])) if len(sys.argv) > 7 else 0
            bottom_trim = int(float(sys.argv[8])) if len(sys.argv) > 8 else 0
            result = crop_gui_margins_only(src_path, left_trim, top_trim, right_trim, bottom_trim)
            print(result)
        elif mode == "trim_preview":
            output_path = arg4 if arg4 else src_path + ".trimmed.jpg"
            aspect_min = _parse_aspect_min(sys.argv, 5)
            result = trim_only(src_path, output_path=output_path, aspect_min=aspect_min)
            print(f"PREVIEW:{output_path}")
        elif mode == "cover_trim":
            output_path = arg4 if arg4 else src_path
            try:
                max_height = int(float(sys.argv[5])) if len(sys.argv) > 5 else 0
            except (ValueError, TypeError):
                max_height = 0
            aspect_min = float(sys.argv[6]) if len(sys.argv) > 6 else 0.0
            aspect_target = float(sys.argv[7]) if len(sys.argv) > 7 else 0.0
            strength = 1.0
            if len(sys.argv) > 8:
                raw = sys.argv[8]
                try:
                    strength = float(raw)
                except (ValueError, TypeError):
                    if isinstance(raw, str) and raw.lower() == "gentle":
                        strength = 0.3
            result = cover_trim(src_path, output_path, max_height=max_height, aspect_min=aspect_min, aspect_target=aspect_target, strength=strength)
            print(result)
        elif mode == "split_preview":
            output_prefix = arg4 if arg4 else src_path + "_split"
            no_trim_flag = (len(sys.argv) > 5 and sys.argv[5].lower() == "true")
            aspect_min = _parse_aspect_min(sys.argv, 6)
            result = split_preview(src_path, output_prefix, is_right_binding, no_trim=no_trim_flag, aspect_min=aspect_min)
            print(result)
        elif mode == "trim_single_safe":
            aspect_min = _parse_aspect_min(sys.argv, 5)
            try: cover_width = int(float(sys.argv[6])) if len(sys.argv) > 6 else 0
            except (ValueError, TypeError): cover_width = 0
            result = trim_single_safe(src_path, cover_width=cover_width, aspect_min=aspect_min)
            print(result)
        elif mode == "one_sided_split":
            no_trim = (arg4.lower() == "true") if arg4 else False
            aspect_min = _parse_aspect_min(sys.argv, 5)
            cover_width = 0
            if len(sys.argv) > 6 and sys.argv[6]:
                try:
                    cover_width = int(float(str(sys.argv[6]).strip()))
                except (ValueError, TypeError):
                    pass
            if cover_width <= 0:
                a6 = repr(sys.argv[6]) if len(sys.argv) > 6 else 'N/A'
                _dbg_geom(f"DEBUG_SPLIT_ONESIDED: argv[6]={a6} -> cover_width=0 (not passed)")
            try:
                result = trim_and_split_one_sided(src_path, is_right_binding, no_trim=no_trim, aspect_min=aspect_min, cover_width=cover_width)
                print(result)
            except Exception as e:
                import traceback
                traceback.print_exc()
                print(f"ERROR:{str(e)}", flush=True)
        elif mode == "split_manual_trim":
            left_trim = int(float(sys.argv[5])) if len(sys.argv) > 5 else 0
            right_trim = int(float(sys.argv[6])) if len(sys.argv) > 6 else 0
            try: cover_width = int(float(sys.argv[7])) if len(sys.argv) > 7 else 0
            except (ValueError, TypeError): cover_width = 0
            aspect_min = _parse_aspect_min(sys.argv, 8) if len(sys.argv) > 8 else 0.0
            result = split_with_manual_trim(src_path, is_right_binding, left_trim, right_trim, cover_width, aspect_min)
            print(result)
        elif mode == "split_center_only":
            result = split_at_center_only(src_path, is_right_binding)
            print(result)
        elif mode == "split_at_gutter_with_margins":
            # argv[4] は未使用。Windows では PowerShell からの "" が落ち argv[5] が左余白になる不具合があるため PS1 側は "-" を渡す
            try: gutter_x = int(float(sys.argv[5])) if len(sys.argv) > 5 and str(sys.argv[5]).strip() else 0
            except (ValueError, TypeError): gutter_x = 0
            left_trim = int(float(sys.argv[6])) if len(sys.argv) > 6 else 0
            right_trim = int(float(sys.argv[7])) if len(sys.argv) > 7 else 0
            aspect_min = _parse_aspect_min(sys.argv, 8)
            try: cover_width = int(float(sys.argv[9])) if len(sys.argv) > 9 else 0
            except (ValueError, TypeError): cover_width = 0
            try: top_trim = int(float(sys.argv[10])) if len(sys.argv) > 10 and str(sys.argv[10]).strip() else 0
            except (ValueError, TypeError): top_trim = 0
            try: bottom_trim = int(float(sys.argv[11])) if len(sys.argv) > 11 and str(sys.argv[11]).strip() else 0
            except (ValueError, TypeError): bottom_trim = 0
            result = trim_and_split_at_gutter_with_margins(src_path, gutter_x, left_trim, right_trim, is_right_binding=is_right_binding, aspect_min=aspect_min, cover_width=cover_width, top_trim_px=top_trim, bottom_trim_px=bottom_trim)
            print(result)
        elif mode == "split_at_gutter":
            try: gutter_x = int(float(sys.argv[5])) if len(sys.argv) > 5 and str(sys.argv[5]).strip() else 0
            except (ValueError, TypeError): gutter_x = 0
            no_trim = (arg4.lower() == "true") if arg4 else False
            aspect_min = _parse_aspect_min(sys.argv, 6)
            try: cover_width = int(float(sys.argv[7])) if len(sys.argv) > 7 else 0
            except (ValueError, TypeError): cover_width = 0
            no_vertical_trim = (str(sys.argv[8]).lower() == "true") if len(sys.argv) > 8 and str(sys.argv[8]).strip() else False
            gui_exact = (str(sys.argv[9]).lower() == "true") if len(sys.argv) > 9 and str(sys.argv[9]).strip() else False
            result = trim_and_split_at_gutter(src_path, gutter_x, is_right_binding=is_right_binding, no_trim=no_trim, aspect_min=aspect_min, cover_width=cover_width, no_vertical_trim=no_vertical_trim, gui_exact=gui_exact)
            print(result)
        else:
            no_trim = (arg4.lower() == "true")
            aspect_min = _parse_aspect_min(sys.argv, 5)
            try: cover_width = int(float(sys.argv[6])) if len(sys.argv) > 6 else 0
            except (ValueError, TypeError): cover_width = 0
            result = trim_and_split(src_path, is_right_binding, no_trim=no_trim, aspect_min=aspect_min, cover_width=cover_width)
            print(result)
    except Exception as e:
        import traceback
        traceback.print_exc()
        print(f"ERROR:{str(e)}", flush=True)
"@
    #endregion
    
    Set-Content -LiteralPath $workTrimSplitPy -Value $trimSplitCode -Encoding UTF8
    $script:FlickFitTrimSplitEmbeddedCode = $trimSplitCode

    $processedImages = 0
    $splitImages = 0
    $skippedImages = 0
    $step5SumKeptAsIs = 0
    $step5SumLoadFailed = 0
    $step5SumProblem = 0
    $step5SumRealProcess = 0
    # FolderGutterCache: キー=フォルダパス文字列。値=のど・余白・ImgW/ImgH/Ref* 等。同一フォルダ内の「同サイズ見開き」自動適用に使う。Remove($dir) で明示無効化（縦横比再GUI等）。プロセス終了まで生存（スクリプト再実行で初期化）。
    # FolderMarginMode: キー="$dir|${w}x${h}"。値 'gui'|'auto'。そのサイズキーで余白GUIモードを記憶。同上プロセス寿命。
    # SplitWidthLastConfirmedByFolder: キー=フォルダ。分割幅GUIで「確定した」スナップ＋ImgW。再利用・±Tol 再利用の照合に使う。同上プロセス寿命。
    if (-not (Get-Variable -Name 'FolderGutterCache' -Scope Script -ErrorAction SilentlyContinue)) { $script:FolderGutterCache = @{} }
    if (-not (Get-Variable -Name 'FolderMarginMode'   -Scope Script -ErrorAction SilentlyContinue)) { $script:FolderMarginMode   = @{} }  # key: "$dir|${w}x${h}" -> 'gui' / 'auto'
    if (-not (Get-Variable -Name 'SplitWidthLastConfirmedByFolder' -Scope Script -ErrorAction SilentlyContinue)) { $script:SplitWidthLastConfirmedByFolder = @{} }

    # ===== STEP5 再開時: 処理済み巻の確認と再処理選択 =====
    $s5doneArr = @()
    if ($script:ProcessLog -and $script:ProcessLog.PSObject.Properties['step5CompletedDirs'] -and $script:ProcessLog.step5CompletedDirs) {
        $s5doneArr = @($script:ProcessLog.step5CompletedDirs)
    }
    if ($s5doneArr.Count -gt 0) {
        Write-FlickFitHost ""
        Write-FlickFitHost "  ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━" -ForegroundColor Cyan
        Write-FlickFitHost ("  [STEP5 再開] 前回処理済み: {0} / {1} 巻" -f $s5doneArr.Count, $finalDirs.Count) -ForegroundColor Cyan
        Write-FlickFitHost "  ※ 表示・処理順は巻番号昇順（第01巻→第02巻→…）です。やり直し指定の番号もこの並びの何番目かです。" -ForegroundColor DarkGray
        $s5doneDisplay = @(Sort-FlickFitStringPathsByVolume -InputPaths $s5doneArr)
        for ($s5ri = 0; $s5ri -lt $s5doneDisplay.Count; $s5ri++) {
            Write-FlickFitHost ("    [{0,2}] {1}" -f ($s5ri + 1), (Split-Path $s5doneDisplay[$s5ri] -Leaf)) -ForegroundColor DarkGray
        }
        Write-FlickFitHost "  【済み巻をやり直すときだけ】全体の並び 1〜$($finalDirs.Count) で番号指定（例: 3 / 5,12 / 4-6）。処理済みリストから外してその巻から再実行します。" -ForegroundColor Cyan
        Write-FlickFitHost "  【まだSTEP5を通していない巻】は番号を入れないでください。空Enterのまま進めば、済みはスキップされ未処理から続きます。" -ForegroundColor DarkGray
        Write-FlickFitHost "  やり直し番号は「全 $($finalDirs.Count) 巻を巻番号順に並べたときの何番目」です（上の済み一覧の行番号と同じ並び基準です）。" -ForegroundColor DarkGray
        $s5redoAns = (Read-HostWithEsc "  やり直す巻（番号・済みのみ／不要なら空Enter）").Trim()
        if ($s5redoAns) {
            $s5redoIdx = [System.Collections.Generic.List[int]]::new()
            foreach ($s5part in ($s5redoAns -split '[,，]')) {
                $s5part = $s5part.Trim()
                if ($s5part -match '^(\d+)[－\-](\d+)$') {
                    $s5from = [int]$Matches[1]; $s5to = [int]$Matches[2]
                    if ($s5from -gt $s5to) { $tmp = $s5from; $s5from = $s5to; $s5to = $tmp }
                    for ($s5i = $s5from; $s5i -le $s5to; $s5i++) { if (-not $s5redoIdx.Contains($s5i)) { [void]$s5redoIdx.Add($s5i) } }
                } elseif ($s5part -match '^\d+$') {
                    $s5n = [int]$s5part
                    if (-not $s5redoIdx.Contains($s5n)) { [void]$s5redoIdx.Add($s5n) }
                }
            }
            $s5FinalNorm = [System.Collections.Generic.List[string]]::new()
            foreach ($fd in $finalDirs) {
                try { [void]$s5FinalNorm.Add([System.IO.Path]::GetFullPath($fd).TrimEnd('\')) } catch { [void]$s5FinalNorm.Add("$fd".TrimEnd('\')) }
            }
            $s5doneNormSet = [System.Collections.Generic.HashSet[string]]::new([StringComparer]::OrdinalIgnoreCase)
            foreach ($x in $s5doneArr) {
                try { [void]$s5doneNormSet.Add([System.IO.Path]::GetFullPath($x).TrimEnd('\')) } catch { [void]$s5doneNormSet.Add("$x".TrimEnd('\')) }
            }
            $s5removeNorm = [System.Collections.Generic.HashSet[string]]::new([StringComparer]::OrdinalIgnoreCase)
            $notDoneYetLeaves = [System.Collections.Generic.List[string]]::new()
            $outOfRange = [System.Collections.Generic.List[int]]::new()
            foreach ($s5n in $s5redoIdx) {
                if ($s5n -lt 1) { continue }
                if ($s5n -gt $s5FinalNorm.Count) { [void]$outOfRange.Add($s5n); continue }
                $tNorm = $s5FinalNorm[$s5n - 1]
                if ($s5doneNormSet.Contains($tNorm)) {
                    [void]$s5removeNorm.Add($tNorm)
                } else {
                    [void]$notDoneYetLeaves.Add((Split-Path $tNorm -Leaf))
                }
            }
            foreach ($or in $outOfRange) {
                Write-FlickFitHost ("  [無視] {0} は全 {1} 巻の範囲外です" -f $or, $finalDirs.Count) -ForegroundColor DarkGray
            }
            $s5onlyNotYet = ($notDoneYetLeaves.Count -gt 0 -and $s5removeNorm.Count -eq 0 -and $outOfRange.Count -eq 0)
            if ($notDoneYetLeaves.Count -gt 0 -and -not $s5onlyNotYet) {
                Write-FlickFitHost "  [注] 次はまだSTEP5未完了です。やり直し指定は不要です（このあとそのまま処理されます）:" -ForegroundColor DarkGray
                foreach ($nw in $notDoneYetLeaves) { Write-FlickFitHost ("    - {0}" -f $nw) -ForegroundColor DarkGray }
            }
            if ($s5removeNorm.Count -gt 0) {
                $s5newDone = [System.Collections.Generic.List[string]]::new()
                foreach ($p in $s5doneArr) {
                    $pn = try { [System.IO.Path]::GetFullPath($p).TrimEnd('\') } catch { "$p".TrimEnd('\') }
                    if ($s5removeNorm.Contains($pn)) {
                        Write-FlickFitHost ("    → 再処理対象: {0}" -f (Split-Path $p -Leaf)) -ForegroundColor Yellow
                    } else {
                        [void]$s5newDone.Add($p)
                    }
                }
                $script:ProcessLog | Add-Member -NotePropertyName 'step5CompletedDirs' -NotePropertyValue @($s5newDone) -Force
                Save-ProcessLog $script:ProcessLog
                Write-FlickFitHost ("  {0} 巻を再処理対象にしました（処理済みリストから除外）" -f $s5removeNorm.Count) -ForegroundColor Yellow
            } elseif ($s5redoIdx.Count -gt 0 -and $outOfRange.Count -eq $s5redoIdx.Count) {
                Write-FlickFitHost "  入力がすべて範囲外でした。完了済み巻はスキップして続行します。" -ForegroundColor DarkGray
            } elseif ($s5redoIdx.Count -gt 0 -and $s5onlyNotYet) {
                # 未処理巻の番号だけ＝リストから外す対象なし（エラーではない）
                Write-FlickFitHost "  [再開] 指定はすべて「まだSTEP5未完了」の巻でした。やり直し指定は不要なので、このまま続行します（済みはスキップ→未処理から再開）。" -ForegroundColor DarkGray
            } elseif ($s5redoIdx.Count -gt 0 -and $notDoneYetLeaves.Count -gt 0 -and $outOfRange.Count -gt 0) {
                Write-FlickFitHost "  [再開] 範囲外の番号と未処理巻の番号が混在しています。やり直しは「すでにSTEP5済み」の巻番号だけ指定してください。このまま続行します。" -ForegroundColor DarkGray
            } elseif ($s5redoIdx.Count -gt 0) {
                Write-FlickFitHost "  有効な番号として解釈できませんでした。完了済み巻はスキップして続行します。" -ForegroundColor DarkGray
            }
        }
        Write-FlickFitHost "  ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━" -ForegroundColor Cyan
        Write-FlickFitHost ""
    }

    foreach ($dir in $finalDirs) {
        if ($script:CancelRequested) { throw "中断: 処理がキャンセルされました" }
        try { $normDir = [System.IO.Path]::GetFullPath($dir).TrimEnd('\') } catch { $normDir = "$dir".TrimEnd('\') }
        $doneNorm = @()
        if ($script:ProcessLog -and $script:ProcessLog.PSObject.Properties['step5CompletedDirs'] -and $script:ProcessLog.step5CompletedDirs) {
            $doneNorm = @($script:ProcessLog.step5CompletedDirs | ForEach-Object { try { [System.IO.Path]::GetFullPath("$_").TrimEnd('\') } catch { "$_".TrimEnd('\') } })
        }
        if ($doneNorm -contains $normDir) {
            Write-FlickFitHost "  [再開] 完了済みのためスキップ: $(Get-LiteralPathLeaf $dir)" -ForegroundColor DarkGray
            continue
        }
        $brk = $null
        if ($script:ProcessLog -and $script:ProcessLog.PSObject.Properties['step5InterruptedDir']) { $brk = $script:ProcessLog.step5InterruptedDir }
        if (-not [string]::IsNullOrWhiteSpace($brk)) {
            try { $brkN = [System.IO.Path]::GetFullPath($brk).TrimEnd('\') } catch { $brkN = $brk.TrimEnd('\') }
            if ($brkN -ieq $normDir) {
                $volLabel = Get-LiteralPathLeaf $dir
                $bk = $null
                if ($script:ProcessLog.PSObject.Properties['backupRoot']) { $bk = [string]$script:ProcessLog.backupRoot }
                Write-FlickFitHost ""
                Write-FlickFitHost "  ⚠  前回「$volLabel」の処理中に中断しました。" -ForegroundColor Yellow
                Write-FlickFitHost "     フォルダ内の画像が中途半端な状態の可能性があります。" -ForegroundColor Yellow
                Write-FlickFitHost ""
                if ($bk -and (Test-Path -LiteralPath $bk)) {
                    Write-FlickFitHost "  📁 バックアップの場所:" -ForegroundColor Cyan
                    Write-FlickFitHost "     $bk" -ForegroundColor White
                    Write-FlickFitHost ""
                    Write-FlickFitHost "  ▶ 復元が必要な場合は、バックアップフォルダ内から" -ForegroundColor Cyan
                    Write-FlickFitHost "    「$volLabel」に相当する画像ファイルを" -ForegroundColor Cyan
                    Write-FlickFitHost "     以下のフォルダへ手動でコピーしてください:" -ForegroundColor Cyan
                    Write-FlickFitHost "     $dir" -ForegroundColor White
                    Write-FlickFitHost ""
                }
                $rs = Read-HostWithEsc "  このまま現在のフォルダ内容で処理を続行しますか？ (Y=続行 / n=スキップ)"
                if ($rs.Trim() -eq 'n' -or $rs.Trim() -eq 'N') {
                    Write-FlickFitHost "  [スキップ] 「$volLabel」をスキップします。" -ForegroundColor DarkGray
                    $script:ProcessLog | Add-Member -NotePropertyName 'step5InterruptedDir' -NotePropertyValue $null -Force
                    Save-ProcessLog $script:ProcessLog
                    continue
                }
                $script:ProcessLog | Add-Member -NotePropertyName 'step5InterruptedDir' -NotePropertyValue $null -Force
                Save-ProcessLog $script:ProcessLog
            }
        }
        $script:CurrentProcessPhase = 'step5'
        $script:CurrentStep5Dir = $normDir
        try {
        $envFlickTswPushed = $false
        $envPrevFlickFitTsw = $null
        $script:FolderAutoTimer = @{ Stopwatch = [System.Diagnostics.Stopwatch]::StartNew(); ElapsedMs = 0; Enabled = $true }
        if ($ProfileTiming) { $script:ProfileTimingData = @{} }
        $folderLeaf = Get-LiteralPathLeaf $dir
        $folderAnalyzeDisp = if ($folderLeaf.Length -gt 48) { $folderLeaf.Substring(0, 46) + [char]0x2026 } else { $folderLeaf }
        Write-FlickFitHost "  $folderAnalyzeDisp Analyze 0%   " -NoNewline -ForegroundColor Cyan
        
        # フォルダ内の画像をそのまま取得（Windows自然順、cvr_*のみ除外）
        # 旧スクリプトの cvr_retry_<8桁hex> が残っている場合のみ削除（増殖ゴミの掃除。新形式 cvr_retry_<元名> は処理中に上書きされる）
        foreach ($lr in @(Get-ChildItem -LiteralPath $dir -File -ErrorAction SilentlyContinue | Where-Object {
                $script:ImageExtensions -contains $_.Extension.ToLower() -and $_.Name -match '^(?i)cvr_retry_[0-9a-f]{8}\.'
            })) {
            try { Remove-Item -LiteralPath $lr.FullName -Force -ErrorAction SilentlyContinue } catch {}
        }
        $imgs = @(Get-ProcessableFolderImages -FolderPath $dir)
        Write-FlickFitHost "`r  $folderAnalyzeDisp Analyze 10%   " -NoNewline -ForegroundColor Cyan
        
        if ($imgs.Count -eq 0) { 
            Write-FlickFitHost ""
            Write-FlickFitHost "     ⚠ 画像なし" -ForegroundColor Yellow
            Add-ProcessLogStep5CompletedDir $dir
            $script:CurrentProcessPhase = 'idle'
            $script:CurrentStep5Dir = $null
            continue 
        }
        
        # 縦横比基準（参考画像は表紙・帯・裏表紙・作者近影を避ける）
        # 見開きフォルダの場合: 実際にトリム+分割した縦横比を使用、マージンで開始位置を後ろに
        $refStart = if ($script:UserConfig -and $null -ne $script:UserConfig.CoverAspectReferenceStart) { [int]$script:UserConfig.CoverAspectReferenceStart } else { 10 }
        $refCount = if ($script:UserConfig -and $null -ne $script:UserConfig.CoverAspectReferenceCount) { [int]$script:UserConfig.CoverAspectReferenceCount } else { 10 }
        $spreadMargin = if ($script:UserConfig -and $null -ne $script:UserConfig.CoverAspectSpreadMargin) { [int]$script:UserConfig.CoverAspectSpreadMargin } else { 5 }
        $minFactor = if ($script:UserConfig -and $null -ne $script:UserConfig.CoverAspectMinFactor) { [double]$script:UserConfig.CoverAspectMinFactor } else { 0.95 }
        $contentAspects = @()
        $checkCount = [Math]::Min(20, $imgs.Count)
        $spreadCount = 0
        for ($c = 0; $c -lt $checkCount; $c++) {
            if ($script:SkipAVIF -and $imgs[$c].Extension.ToLower() -eq '.avif') { continue }
            $a = Get-ImageAspect $imgs[$c].FullName
            if ($a -gt 0 -and $a -ge $AspectThreshold) { $spreadCount++ }
            if ($checkCount -gt 0 -and (($c + 1) % 5 -eq 0 -or $c -eq $checkCount - 1)) {
                $pct = 10 + [int](15 * ($c + 1) / [Math]::Max(1, $checkCount))
                Write-FlickFitHost "`r  $folderAnalyzeDisp Analyze $pct%   " -NoNewline -ForegroundColor Cyan
            }
        }
        $isMostlySpreads = ($checkCount -gt 0) -and (($spreadCount / $checkCount) -ge 0.7)
        $startIdx = if ($refStart -ge $imgs.Count) { 0 } else { $refStart }
        if ($isMostlySpreads -and $spreadMargin -gt 0) {
            $startIdx = [Math]::Min($startIdx + $spreadMargin, $imgs.Count - 1)
            $startIdx = [Math]::Max(0, $startIdx)
        }
        $endIdx = [Math]::Min($startIdx + $refCount, $imgs.Count)
        $aspectPaths = @()
        $aspectSpan = [Math]::Max(1, $endIdx - $startIdx)
        for ($i = $startIdx; $i -lt $endIdx; $i++) {
            if ($script:SkipAVIF -and $imgs[$i].Extension.ToLower() -eq '.avif') { continue }
            $a = Get-ImageAspect $imgs[$i].FullName
            if ($a -gt 0) {
                if ($a -ge $AspectThreshold -and $script:PythonExe) {
                    $aspectPaths += $imgs[$i].FullName
                } else {
                    if ($a -ge $AspectThreshold) { $contentAspects += ($a / 2.0) } else { $contentAspects += $a }
                }
            }
            $done = $i - $startIdx + 1
            if ($done % 3 -eq 0 -or $done -eq $aspectSpan) {
                $pct = 25 + [int](25 * $done / $aspectSpan)
                Write-FlickFitHost "`r  $folderAnalyzeDisp Analyze $pct%   " -NoNewline -ForegroundColor Cyan
            }
        }
        Write-FlickFitHost "`r  $folderAnalyzeDisp Analyze 50%   " -NoNewline -ForegroundColor Cyan
        if ($aspectPaths.Count -gt 0) {
            $tmpAspectList = Join-Path (Get-FlickFitScratchTempDir) ("aspect_" + [Guid]::NewGuid().ToString('N').Substring(0,8) + ".txt")
            $aspectPaths | Set-Content -LiteralPath $tmpAspectList -Encoding UTF8
            try {
                $batchOut = Invoke-PythonTimed -Category "PythonAspect" -PythonArgs $workTrimSplitPy, $tmpAspectList, $RightBinding.ToString(), "batch_get_aspect"
                $batchLines = @($batchOut | ForEach-Object { "$_" } | Where-Object { $_ -match '^\S+\t[\d.]+$' })
                foreach ($line in $batchLines) {
                    if ($line -match '\t([\d.]+)$') {
                        $parsed = [double]$Matches[1]
                        if ($parsed -gt 0 -and $parsed -lt 2) { $contentAspects += $parsed }
                    }
                }
                if ($batchLines.Count -eq 0 -and $aspectPaths.Count -gt 0) { throw "no batch results" }
            } catch {
                foreach ($p in $aspectPaths) {
                    try {
                        $out = Invoke-PythonTimed -Category "PythonAspect" -PythonArgs $workTrimSplitPy, $p, $RightBinding.ToString(), "get_trim_split_aspect"
                        $outStr = ($out | ForEach-Object { "$_" }) -join " "
                        if ($outStr -match '(\d+\.?\d*)') {
                            $parsed = [double]$Matches[1]
                            if ($parsed -gt 0 -and $parsed -lt 2) { $contentAspects += $parsed } else { $contentAspects += (Get-ImageAspect $p) / 2.0 }
                        } else { $contentAspects += (Get-ImageAspect $p) / 2.0 }
                    } catch { $contentAspects += (Get-ImageAspect $p) / 2.0 }
                }
            } finally {
                if (Test-Path -LiteralPath $tmpAspectList) { Remove-Item -LiteralPath $tmpAspectList -Force -ErrorAction SilentlyContinue }
            }
        }
        # 要素が1つだけのとき += でスカラー化し .Count が無くなることがある → 常に配列化
        $contentAspects = @($contentAspects)
        Write-FlickFitHost "`r  $folderAnalyzeDisp Analyze 70%   " -NoNewline -ForegroundColor Cyan
        $aspectMin = 0.0
        $aspectRef = 0.0
        if ($contentAspects.Count -ge 1 -and $minFactor -gt 0) {
            $rounded = @($contentAspects | ForEach-Object { [Math]::Round($_, 2) })
            $grouped = @($rounded | Group-Object | Sort-Object -Property Count -Descending)
            $modeAspect = [double]$grouped[0].Name
            $aspectRef = $modeAspect
            $aspectMin = [Math]::Round($modeAspect * $minFactor, 4)
        }
        # フォルダから十分なサンプルが取れない場合でも、表紙1ページ相当の縦横比を基準として使う
        if ($aspectRef -le 0) {
            $aspectRef = 0.7
        }
        if ($aspectMin -le 0 -and $aspectRef -gt 0 -and $minFactor -gt 0) {
            $aspectMin = [Math]::Round($aspectRef * $minFactor, 4)
        }
        $folderSplit = 0
        $folderKeptAsIs = 0   # 縦長通過・元のまま・GUI信頼パスなど（正常に実処理しない枚数）
        $folderPortraitKeptSilentCount = 0
        $folderLoadFailed = 0 # Get-ImageAspect 等で読めなかった枚数
        $folderProblemSkipped = 0 # 分割/トリム失敗・GUI削除・検証delete など
        $folderAvifOmit = 0
        $folderCoverWidth = 0
        
        # フォルダ内のアスペクト・サイズを事前収集（異物検出用、見開きと区別）
        # AVIFはPython処理が遅いのでサンプリング（最大10枚）
        $folderAspects = @(); $folderSizes = @()
        $firstExt = if ($imgs.Count -gt 0) { $imgs[0].Extension.ToLower() } else { '' }
        $isSlowFormat = $firstExt -in @('.avif', '.webp')
        $sampleImgs = @(
            if ($isSlowFormat -and $imgs.Count -gt 10) {
                $step = [Math]::Floor($imgs.Count / 10)
                @(for ($si = 0; $si -lt $imgs.Count; $si += $step) { $imgs[$si] }) | Select-Object -First 10
            } else { $imgs }
        )
        $sampleTotal = $sampleImgs.Count
        $sampleIdx = 0
        foreach ($ci in $sampleImgs) {
            if ($script:SkipAVIF -and $ci.Extension.ToLower() -eq '.avif') { continue }
            $a = Get-ImageAspect $ci.FullName
            if ($a -gt 0) { $folderAspects += $a; $folderSizes += $ci.Length }
            $sampleIdx++
            if ($sampleTotal -gt 0 -and ($sampleIdx % 3 -eq 0 -or $sampleIdx -eq $sampleTotal)) {
                $pct = 70 + [int](30 * $sampleIdx / $sampleTotal)
                Write-FlickFitHost "`r  $folderAnalyzeDisp Analyze $pct%   " -NoNewline -ForegroundColor Cyan
            }
        }
        Write-FlickFitHost "`r  $folderAnalyzeDisp Analyze 100%   " -NoNewline -ForegroundColor Cyan
        Write-FlickFitHost ""
        Write-FlickFitHost "     📊 $($imgs.Count) 枚の画像" -ForegroundColor Gray
        if (($true -eq $script:FlickFitDebugStep5Verbose) -or ($true -eq $script:FlickFitDebugAnalyze)) {
            Write-FlickFitHost "    [DEBUG] contentAspects=$($contentAspects.Count) aspectRef=$aspectRef aspectMin=$aspectMin" -ForegroundColor DarkYellow
        }
        $folderAspects = @($folderAspects)
        $folderSizes = @($folderSizes)
        $medianAspect = if ($folderAspects.Count -gt 0) { $sorted = @($folderAspects | Sort-Object); $sorted[[Math]::Floor($sorted.Count / 2)] } else { 0.7 }
        $medianSize = if ($folderSizes.Count -gt 0) { $sorted = @($folderSizes | Sort-Object); $sorted[[Math]::Floor($sorted.Count / 2)] } else { 0 }
        # 単ページ基準幅: 先頭（表紙候補）を除く本体からランダムに最大5枚（等間隔の先頭寄りだとピクセル不揃いの影響が出やすいため）
        $folderTypicalSingleWidth = 0
        if ($imgs.Count -gt 1) {
            $wsBodyIndices = @(1..($imgs.Count - 1))
            $wsSampleMax = [Math]::Min(5, $wsBodyIndices.Count)
            $wsWidths = [System.Collections.Generic.List[int]]::new()
            foreach ($wsi in ($wsBodyIndices | Sort-Object { Get-Random })) {
                if ($wsWidths.Count -ge $wsSampleMax) { break }
                if ($script:SkipAVIF -and $imgs[$wsi].Extension.ToLower() -eq '.avif') { continue }
                $wsDims = Get-ImageDimensionsFast -Path $imgs[$wsi].FullName
                if ($wsDims.Width -gt 0 -and $wsDims.Height -gt 0) {
                    $wsAsp = $wsDims.Width / $wsDims.Height
                    if ($aspectRef -le 0 -or [Math]::Abs($wsAsp - $aspectRef) / $aspectRef -le 0.35) {
                        [void]$wsWidths.Add([int]$wsDims.Width)
                    }
                }
            }
            if ($wsWidths.Count -gt 0) {
                $wsSorted = @($wsWidths | Sort-Object)
                $folderTypicalSingleWidth = $wsSorted[[Math]::Floor($wsSorted.Count / 2)]
                Write-FlickFitHost "     [単ページ基準幅] $folderTypicalSingleWidth px ($($wsSorted.Count) 枚サンプル・表紙除く本体からランダム)" -ForegroundColor DarkGray
            }
        }
        $aspectDiffThreshold = 0.2
        $sizeSmallRatio = 0.5
        $sizeSmallAbs = 150 * 1024
        
        # is_one_sided: 回転納品横見開き判定の閾値（短辺 ≧ 基準幅×1.25 等）— Python 読み取り
        if ($folderTypicalSingleWidth -gt 0) {
            $envPrevFlickFitTsw = $env:FLICK_FIT_TYPICAL_SINGLE_WIDTH
            $env:FLICK_FIT_TYPICAL_SINGLE_WIDTH = [string]$folderTypicalSingleWidth
            $envFlickTswPushed = $true
        }
        
        # 片側画像の選択履歴と自動適用設定
        $folderOneSidedChoices = @()
        $folderAutoChoice = $null
        # 「以降同じ処理を自動選択」はフォルダ毎にリセット（スキャン精度がフォルダで異なるため）
        $script:OneSidedSplitWidthAutoAdopt = $false
        # 異物削除: 2回連続削除で自動削除モード
        $folderConsecutiveOutlierDeletes = 0
        $folderAutoDeleteOutlier = $false
        
        # 目次判定: 巻頭OCRチェックは省略（遅延のため）。片側黒背景のとき専用トリミングを適用
        $folderTocPaths = @{}
        # GUI（またはキャッシュのGUI設定）で見開き分割した直後の _1/_2 は縦長になりやすく、異物判定や単ページ自動トリムの対象にしない
        $guiSplitTrustNorm = [System.Collections.Generic.HashSet[string]]::new([StringComparer]::OrdinalIgnoreCase)
        $script:FlickFitCorruptPathsThisFolder = [System.Collections.Generic.HashSet[string]]::new([StringComparer]::OrdinalIgnoreCase)
        $script:FlickFitCachedBalBatchResultByPath = @{}
        $script:FlickFitFatalBatchSplitAbort = $false
        $ffQueueApplySilent = 0
        
        $imgIdx = 0
        $Step5OneSidedAnalyze = @{}
        # ループ毎に Sync すると $imgs へ 1 枚でも追加のたび未キャッシュが大量になり、毎回全件 batch_analyze_seq が走り破綻する。開始時1回だけ。
        Sync-FlickFitStep5OneSidedAnalyzeMap -ByPath $Step5OneSidedAnalyze -Imgs $imgs -WorkTrimSplitPy $workTrimSplitPy -RightBinding $RightBinding -TypicalSingleWidth $folderTypicalSingleWidth
        if ($true -eq $script:FlickFitDebugCachedBalBatch) {
            Write-FlickFitHost ("     [STEP5] CachedBalBatch enable={0} debug={1} (UserConfig / env FLICK_FIT_ENABLE_CACHED_BAL_BATCH)" -f $script:FlickFitEnableCachedBalBatch, $script:FlickFitDebugCachedBalBatch) -ForegroundColor DarkGray
        }
        :FlickFitStep5ImgLoop while ($imgIdx -lt $imgs.Count) {
            if ($script:CancelRequested) { throw "中断: 処理がキャンセルされました" }
            $ci = $imgs[$imgIdx]
            
            # 一時ファイル (cvr_*) はスキップ
            if ($ci.Name -like "cvr_*") {
                Remove-Item -LiteralPath $ci.FullName -Force -ErrorAction SilentlyContinue
                $imgs = @($imgs | Where-Object { $_.FullName -ne $ci.FullName })
                continue
            }
            
            $imgName = $ci.Name
            $ciExt = $ci.Extension.ToLower()
            
            # batch_split_at_gutter: 先読み一括ですでに分割/トリム済みだが $imgs は更新前のまま。元ファイルが無いと Get-ImageAspect で失敗するため、存在確認より前にキューを消費する。
            if ($script:FlickFitCachedBalBatchResultByPath -and $script:FlickFitCachedBalBatchResultByPath.Count -gt 0) {
                $curKeyBalQ = Get-FlickFitStep5PathKey $ci.FullName
                if (-not $curKeyBalQ) {
                    try { $curKeyBalQ = [System.IO.Path]::GetFullPath($ci.FullName) } catch { $curKeyBalQ = $ci.FullName }
                }
                $pickBalQ = $null
                if ($curKeyBalQ -and $script:FlickFitCachedBalBatchResultByPath.ContainsKey($curKeyBalQ)) {
                    $pickBalQ = $curKeyBalQ
                } elseif ($curKeyBalQ) {
                    foreach ($mkBal in $script:FlickFitCachedBalBatchResultByPath.Keys) {
                        if ([string]::Equals([string]$mkBal, $curKeyBalQ, [StringComparison]::OrdinalIgnoreCase)) { $pickBalQ = [string]$mkBal; break }
                    }
                }
                if ($pickBalQ) {
                    $lnBalQ = [string]$script:FlickFitCachedBalBatchResultByPath[$pickBalQ]
                    [void]$script:FlickFitCachedBalBatchResultByPath.Remove($pickBalQ)
                    if ($lnBalQ -match 'SPLIT:2') {
                        try { Add-FlickFitGuiSplitTrustOutputs -GuiSplitTrustSet $guiSplitTrustNorm -SplitBasePath $ci.FullName } catch { }
                        $folderSplit += 2
                        $splitImages += 2
                    } elseif ($lnBalQ -match 'TRIMMED:1') {
                        $folderSplit += 1
                        $splitImages += 1
                    } else {
                        $folderSplit += 1
                        $splitImages += 1
                    }
                    if (($true -eq $script:FlickFitEnableCachedBalBatch) -and -not ($true -eq $script:FlickFitDebugCachedBalBatch)) {
                        $ffQueueApplySilent++
                    } else {
                        Write-FlickFitHost "      ✓ $imgName （batch_split_at_gutter 済みを反映・キュー消費）" -ForegroundColor Green
                    }
                    $processedImages++
                    $imgIdx++
                    continue
                }
            }
            
            # AVIF 高速パス: 縦横比取得・見開き処理を省略（folderAvifOmit／サマリーの「そのまま保持」とは別扱い）
            if ($script:SkipAVIF -and $ciExt -eq '.avif') {
                $label = if ($imgIdx -eq 0) { "AVIF表紙・高速パス" } else { "AVIF・高速パス" }
                Write-FlickFitHost "      ⏭ $imgName ($label)" -ForegroundColor DarkGray
                $folderAvifOmit++
                $folderSplit += 1
                $splitImages += 1
                $processedImages++
                $imgIdx++
                continue
            }
            
            $aspect = Get-ImageAspect $ci.FullName
            if ($aspect -le 0) {
                Register-FlickFitCorruptImageForStep5 -Path $ci.FullName
                Write-FlickFitHost "      ⏭ $imgName (読み込み失敗・スキップ)" -ForegroundColor Yellow
                $folderLoadFailed++
                $skippedImages++
                $processedImages++
                $imgIdx++
                continue
            }
            
            # 先頭画像は縦長でも表紙としてトリミング確認する（表紙スルー防止）
            # 類似画像（帯付き/帯なし等）がある場合は連続確認可能
            if ($imgIdx -eq 0) {
                $coverCheckIdx = 0  # 表紙確認用インデックス
                $coverLoopImgsRefreshed = $false  # 2ページ目分割で$imgsを再取得した場合、次インデックスを補正する
                $coverWhileExitImgIdxOverride = $null  # GUI内削除など: 表紙ループを抜けたあと main の imgIdx を明示指定
                $skippedPrevImages = [System.Collections.Generic.List[string]]::new()  # 「次へ」でスキップした画像
                while ($coverCheckIdx -lt $imgs.Count) {
                    $script:coverPhotosEditPathGui = $null
                    $coverImg = $imgs[$coverCheckIdx]
                    $coverName = $coverImg.Name
                    $coverExt = $coverImg.Extension.ToLower()
                    
                    # AVIF 高速パス（表紙ループ）
                    if ($script:SkipAVIF -and $coverExt -eq '.avif') {
                        Write-FlickFitHost "      ⏭ $coverName (AVIF表紙・高速パス)" -ForegroundColor DarkGray
                        $folderAvifOmit++
                        $folderSplit += 1
                        $splitImages += 1
                        $processedImages++
                        break
                    }
                    
                    $coverAspect = Get-ImageAspect $coverImg.FullName
                    $coverLabel = if ($coverCheckIdx -eq 0) { "表紙" } else { "表紙候補 #$($coverCheckIdx + 1)" }
                    Write-FlickFitHost "      ⏳ $coverName ($coverLabel・縦長でも処理)" -ForegroundColor Gray
                    
                    if ($DryRun) {
                        Write-FlickFitHost "         [DRY RUN]" -ForegroundColor Yellow
                        $processedImages++
                        break
                    }
                    
                    try {
                        $ext = $coverExt
                        $origPath = $coverImg.FullName
                        
                        # AVIF: 縦長なら確認スキップ
                        if ($ext -eq '.avif') {
                            if ($coverAspect -lt 1.0) {
                                Write-FlickFitHost "         ✅ AVIF表紙（縦長: 確認スキップ）" -ForegroundColor Green
                                $folderSplit += 1
                                $splitImages += 1
                                $processedImages++
                                break
                            }
                            Write-FlickFitHost "         ⚠ AVIF横長表紙: 表示まで時間がかかります..." -ForegroundColor Yellow
                        }
                        
                        Write-FlickFitHost "         📍 表紙トリミング（Margin基準・縦横比制限）..." -ForegroundColor Gray
                        Write-FlickFitDebugStep5VerboseHost -Text "[DEBUG] cover_trim 呼び出し: aspectRef=$aspectRef aspectMin=$aspectMin" -ForegroundColor DarkYellow
                        $tmpCoverPreview = Join-Path $dir ("cvr_" + [Guid]::NewGuid().ToString('N').Substring(0,8) + $ext)
                        $cropRes = ""
                        if ($script:PythonExe) {
                            $strengthStr = "1.0"
                            # 日本語パス対策: 環境変数経由で渡す（PowerShell→Pythonのargvが破損するため）
                            $prevCovSrc = $env:COVER_TRIM_SRC
                            $prevCovOut = $env:COVER_TRIM_OUT
                            $prevCovRight = $env:COVER_TRIM_RIGHT
                            $prevCovMaxH = $env:COVER_TRIM_MAX_H
                            $prevCovAMin = $env:COVER_TRIM_ASPECT_MIN
                            $prevCovATgt = $env:COVER_TRIM_ASPECT_TGT
                            $prevCovStr = $env:COVER_TRIM_STRENGTH
                            $env:COVER_TRIM_SRC = $origPath
                            $env:COVER_TRIM_OUT = $tmpCoverPreview
                            $env:COVER_TRIM_RIGHT = $RightBinding.ToString()
                            $env:COVER_TRIM_MAX_H = "0"
                            $env:COVER_TRIM_ASPECT_MIN = [string]$aspectMin
                            $env:COVER_TRIM_ASPECT_TGT = [string]$aspectRef
                            $env:COVER_TRIM_STRENGTH = $strengthStr
                            try {
                                $prevErrPref = $ErrorActionPreference
                                $ErrorActionPreference = 'Continue'
                                $cropOut = Invoke-PythonWithProcess -Category "PythonCover" -PythonArgs @($workTrimSplitPy)
                                $cropRes = ($cropOut | ForEach-Object { "$_" }) -join "`n"
                            } finally {
                                $ErrorActionPreference = $prevErrPref
                                $env:COVER_TRIM_SRC = $prevCovSrc
                                $env:COVER_TRIM_OUT = $prevCovOut
                                $env:COVER_TRIM_RIGHT = $prevCovRight
                                $env:COVER_TRIM_MAX_H = $prevCovMaxH
                                $env:COVER_TRIM_ASPECT_MIN = $prevCovAMin
                                $env:COVER_TRIM_ASPECT_TGT = $prevCovATgt
                                $env:COVER_TRIM_STRENGTH = $prevCovStr
                            }
                            if ($cropRes -match 'Traceback|Error:|SyntaxError|NameError') {
                                Write-FlickFitHost "         [Python出力]:" -ForegroundColor Red
                                ($cropRes -split "`r?`n" | Where-Object { $_ }) | ForEach-Object { Write-FlickFitHost "           $_" -ForegroundColor Red }
                            } elseif ($cropRes -match 'DEBUG:') {
                                if ($true -eq $script:FlickFitDebugPythonGeometry) {
                                    ($cropRes -split "`r?`n" | Where-Object { $_ -match 'DEBUG:' }) | ForEach-Object { Write-FlickFitHost "         $_" -ForegroundColor DarkYellow }
                                }
                            }
                        }
                        $usedFallback = $false
                        if (-not (Test-Path -LiteralPath $tmpCoverPreview)) {
                            Copy-Item -LiteralPath $origPath -Destination $tmpCoverPreview -Force
                            $usedFallback = $true
                            Write-FlickFitHost "         [検証] Pythonがファイルを作成していませんでした → 元画像をコピーしました" -ForegroundColor Red
                        }
                        # 表紙: スコア判定（縦向き格納の横見開き: 短辺が単ページ基準より大きいと減点 / RotatedSpreadSuspect）
                        $covDimsForScore = Get-ImageDimensionsFast -Path $origPath
                        $siCv = Get-CoverTrimScore -CropRes $cropRes -CoverAspect $coverAspect `
                            -PixelWidth $covDimsForScore.Width -PixelHeight $covDimsForScore.Height `
                            -TypicalSinglePageWidth $folderTypicalSingleWidth `
                            -WideWidthFactor $script:FlickFitCoverWideWidthFactor `
                            -WidePortraitPenalty $script:FlickFitCoverWidePortraitPenalty `
                            -SkipWidePortraitScorePenalty $true `
                            -PreviewPath $tmpCoverPreview
                        $coverScoreCv = $siCv.Score
                        $needCoverGutterGui = $false
                        $confirm = $null
                        if ($cropRes -match 'TRIMMED:1') {
                            Write-CoverTrimVerify -OrigPath $origPath -PreviewPath $tmpCoverPreview -UsedFallback $usedFallback
                            Write-FlickFitHost "         [表紙スコア: $coverScoreCv / 100]" -ForegroundColor Gray
                            if ($coverScoreCv -ge 90) {
                                Write-FlickFitHost "         ✓ 自動トリミング（スコア90以上・自動採用）" -ForegroundColor Green
                                $confirm = '1'
                            } else {
                                Write-FlickFitHost "         ✓ 自動トリミング完了（要確認）" -ForegroundColor Green
                                $needCoverGutterGui = $true
                            }
                        } elseif ($siCv.IsPortrait) {
                            Write-FlickFitHost "         [表紙スコア: $coverScoreCv / 100]" -ForegroundColor Gray
                            if ($true -eq $siCv.RotatedSpreadSuspect) {
                                Write-FlickFitHost "         ⚠ 短辺が本体の単ページ幅より大きい（横見開きを 90 度入稿した疑い。自動表紙にしない）" -ForegroundColor Yellow
                            }
                            if ($true -eq $siCv.RotatedSpreadSuspect -or $coverScoreCv -lt 90) {
                                Write-FlickFitHost "         ✓ 要確認: ノド・余白の GUI" -ForegroundColor Green
                                $needCoverGutterGui = $true
                            } else {
                                Write-FlickFitHost "         ✓ トリミング不要（縦長・自動採用）" -ForegroundColor Green
                                $confirm = '1'
                            }
                        } else {
                            Write-FlickFitHost "         [表紙スコア: $coverScoreCv / 100]" -ForegroundColor Gray
                            if ($coverScoreCv -ge 90) {
                                Write-FlickFitHost "         ✓ トリミング不要（スコア90以上・自動採用）" -ForegroundColor Green
                                $confirm = '1'
                            } else {
                                Write-FlickFitHost "         ✓ トリミング不要（横長・確認）" -ForegroundColor Green
                                $needCoverGutterGui = $true
                            }
                        }
                        if ($needCoverGutterGui) {
                            Write-FlickFitHost "         （ノド・余白のGUIで確認してください）" -ForegroundColor DarkGray
                            $allPathsCover = @(foreach ($cim in $imgs) { $cim.FullName })
                            try { $tmpR = (Resolve-Path -LiteralPath $tmpCoverPreview -ErrorAction Stop).Path } catch { $tmpR = $tmpCoverPreview }
                            try { $origR = (Resolve-Path -LiteralPath $origPath -ErrorAction Stop).Path } catch { $origR = $origPath }
                            $navCov = [System.Collections.Generic.List[string]]::new()
                            $insertedTmp = $false
                            for ($ni = 0; $ni -lt $allPathsCover.Count; $ni++) {
                                $pOne = $allPathsCover[$ni]
                                $prOne = $null
                                try { $prOne = (Resolve-Path -LiteralPath $pOne -ErrorAction Stop).Path } catch { $prOne = $pOne }
                                if ($ni -eq $coverCheckIdx -and $prOne -and $origR -and [string]::Equals($prOne, $origR, [System.StringComparison]::OrdinalIgnoreCase)) {
                                    [void]$navCov.Add($tmpR)
                                    # 次へ1回で元画像へ進める → 「削除」は面倒な切替なしで cvr_* / 001.jpg をそのまま消せる
                                    $tmpCmp = try { (Resolve-Path -LiteralPath $tmpR -ErrorAction Stop).Path } catch { $tmpR }
                                    if ($prOne -and -not [string]::Equals($prOne, $tmpCmp, [System.StringComparison]::OrdinalIgnoreCase)) {
                                        [void]$navCov.Add($pOne)
                                    }
                                    $insertedTmp = $true
                                } else {
                                    [void]$navCov.Add($pOne)
                                }
                            }
                            if (-not $insertedTmp) {
                                $navCov = [System.Collections.Generic.List[string]]::new()
                                [void]$navCov.Add($tmpR)
                                foreach ($pOne in $allPathsCover) { [void]$navCov.Add($pOne) }
                            }
                            $coverNavArr = [string[]]($navCov.ToArray())
                            $coverGuiSplat = @{
                                ImagePath         = $tmpCoverPreview
                                Title             = '表紙: ノドと余白（自動トリム結果）'
                                AllImagePaths     = $coverNavArr
                                OriginalImagePath = $origPath
                            }
                            try {
                                $gmCv = Show-GutterMarginSetGui @coverGuiSplat -CoverConfirmMode -OkAppliesToCurrentView
                                if ($gmCv -is [System.Collections.IDictionary]) { $gmCv = Normalize-GutterGuiResult -GuiResult $gmCv }
                            } catch {
                                $posMsg = $_.InvocationInfo.PositionMessage
                                if ($posMsg) { Write-FlickFitHost "         $posMsg" -ForegroundColor DarkGray }
                                throw
                            }
                            $imgs = Update-ImgsAfterMarginGui -Imgs $imgs -GuiResult $gmCv
                            if ($null -eq $gmCv -or $gmCv -isnot [System.Collections.IDictionary]) {
                                $confirm = 'N'
                            } elseif (Test-GuiMarginFlagTrue -Tbl $gmCv -Key 'PhotosEdit') {
                                try { $script:coverPhotosEditPathGui = [string]$gmCv['ImagePath'] } catch { $script:coverPhotosEditPathGui = $null }
                                $confirm = 'm'
                            } elseif ($gmCv.ContainsKey('CoverAction')) {
                                $caGm = [string]$gmCv['CoverAction']
                                if ($caGm -eq 'S' -or $caGm -eq '2' -or $caGm -eq 'N' -or $caGm -eq 'D') {
                                    $confirm = $caGm
                                } elseif ($caGm -eq '1') {
                                    $mtGm = Get-HashtableBool -Tbl $gmCv -Key 'MarginTrimWithoutSplit'
                                    if (-not $mtGm) {
                                        [void][System.Windows.Forms.MessageBox]::Show(
                                            "表紙では「ノド（見開き分割）」がオンのまま確定できません。チェックをオフにするか「見開きで通常分割 (S)」を使用してください。",
                                            "表紙確認",
                                            [System.Windows.Forms.MessageBoxButtons]::OK,
                                            [System.Windows.Forms.MessageBoxIcon]::Information)
                                        $confirm = 'N'
                                    } else {
                                        $apPathGm = Get-HashtableTrimmedString -Tbl $gmCv -Key 'ApplyImagePath'
                                        if ($apPathGm -and -not (Test-Path -LiteralPath $apPathGm)) { $apPathGm = $null }
                                        # GUI 内で一時プレビュー(cvr_*)を削除した場合、tmpCoverPreview へのフォールバックは必ず失敗する → 更新済み $imgs / 元ループ画像へ
                                        if (-not $apPathGm -and (Test-Path -LiteralPath $tmpCoverPreview)) { $apPathGm = $tmpCoverPreview }
                                        if (-not $apPathGm -and $imgs.Count -gt $coverCheckIdx -and (Test-Path -LiteralPath $imgs[$coverCheckIdx].FullName)) {
                                            $apPathGm = $imgs[$coverCheckIdx].FullName
                                        }
                                        if (-not $apPathGm) {
                                            foreach ($itCv in $imgs) {
                                                if ($itCv.FullName -and (Test-Path -LiteralPath $itCv.FullName)) { $apPathGm = $itCv.FullName; break }
                                            }
                                        }
                                        if (-not $apPathGm -and (Test-Path -LiteralPath $origPath)) { $apPathGm = $origPath }
                                        if (-not $apPathGm -or -not (Test-Path -LiteralPath $apPathGm)) {
                                            throw "表紙・余白トリムの入力画像が見つかりません（一時プレビューや削除済みパスを参照している可能性があります）。"
                                        }
                                        if ($gmCv.ContainsKey('RotationDegrees')) {
                                            try {
                                                $rdCv = [double]$gmCv['RotationDegrees']
                                                if ([Math]::Abs($rdCv) -gt 0.01) {
                                                    Write-FlickFitHost "         [表紙] 回転 ${rdCv}° を適用（$(Get-LiteralPathLeaf $apPathGm)）" -ForegroundColor DarkCyan
                                                }
                                            } catch { }
                                        }
                                        $dApGm = Get-ImageDimensions -Path $apPathGm
                                        $apH = $dApGm.Height
                                        $ltGm = Get-HashtableInt -Tbl $gmCv -Key 'LeftTrimPx'
                                        $rtGm = Get-HashtableInt -Tbl $gmCv -Key 'RightTrimPx'
                                        $ttGm = Get-HashtableInt -Tbl $gmCv -Key 'TopTrimPx'
                                        $btGm = Get-HashtableInt -Tbl $gmCv -Key 'BottomTrimPx'
                                        if ($apH -gt 0) {
                                            $vGm = Repair-GutterVerticalMargins -ImgH $apH -TopTrim $ttGm -BottomTrim $btGm
                                            $ttGm = $vGm.TopTrimPx
                                            $btGm = $vGm.BottomTrimPx
                                        }
                                        try {
                                            $pyCropCv = Invoke-PythonCropGuiMargins -WorkTrimSplitPy $workTrimSplitPy -ImagePath $apPathGm -RightBinding $RightBinding -LeftTrim $ltGm -TopTrim $ttGm -RightTrim $rtGm -BottomTrim $btGm
                                            if ($pyCropCv -notmatch 'TRIMMED:1|OK') {
                                                Write-FlickFitHost "         [警告] 表紙・余白トリム: $pyCropCv" -ForegroundColor Yellow
                                            }
                                        } catch {
                                            Write-FlickFitHost "         [警告] 表紙・余白トリムでエラー: $($_.Exception.Message)" -ForegroundColor Yellow
                                        }
                                        # cvr_* は連番リストに入らず後で削除される。トリム結果が一時ファイルにだけ残っていると未トリムの origPath が残るため、ここで正規の表紙ファイルへ書き戻す（別ファイル採用時は apPathGm が 001 で一致しコピーしない）
                                        $apNormWb = try { (Resolve-Path -LiteralPath $apPathGm -ErrorAction Stop).Path } catch { $apPathGm }
                                        $origNormWb = try { (Resolve-Path -LiteralPath $origPath -ErrorAction Stop).Path } catch { $origPath }
                                        if ($apNormWb -and $origNormWb -and -not [string]::Equals($apNormWb, $origNormWb, [StringComparison]::OrdinalIgnoreCase) -and (Test-Path -LiteralPath $apPathGm) -and (Test-Path -LiteralPath $origPath)) {
                                            if ([System.IO.Path]::GetFileName($apPathGm) -like 'cvr_*') {
                                                Copy-Item -LiteralPath $apPathGm -Destination $origPath -Force
                                                Write-FlickFitHost "         [表紙] 余白トリム済みを $(Get-LiteralPathLeaf $origPath) に反映（一時プレビューは後続で削除）" -ForegroundColor DarkCyan
                                            }
                                        }
                                        # 自動採用の else 分岐が tmp→origPath の Copy-Item をするため、GUI余白採用時はフラグでスキップ（cvr_* をGUIで削除した場合の例外防止）
                                        $script:CoverGuiMarginAdoptDone = $true
                                        $confirm = '1'
                                    }
                                } else {
                                    if ($caGm) { $confirm = [string]$caGm } else { $confirm = 'N' }
                                }
                            } elseif (Test-GuiMarginFlagTrue -Tbl $gmCv -Key 'DeleteImage') {
                                $confirm = 'D'
                            } else {
                                $confirm = 'N'
                            }
                        }
                        
                        if ($confirm -match '^[sS]$') {
                            # 通常の見開き分割（表紙由来のため分割前トリミングをスキップ＝削りすぎ防止）
                            if (Test-Path -LiteralPath $tmpCoverPreview) {
                                [System.GC]::Collect()
                                [System.GC]::WaitForPendingFinalizers()
                                Start-Sleep -Milliseconds 300
                                Remove-Item -LiteralPath $tmpCoverPreview -Force -ErrorAction SilentlyContinue
                            }
                            if ($true -eq $script:FlickFitDebugStep5Verbose) { Write-FlickFitHost "         📍 通常分割..." -ForegroundColor Cyan }
                            $cw = $folderCoverWidth
                            if ($cw -le 0) {
                                $d = Get-ImageDimensions -Path $origPath
                                if ($d.Width -gt 0) { $cw = [Math]::Floor($d.Width / 2); Write-FlickFitDebugStep5VerboseHost -Text "[DEBUG] 表紙幅未設定→元画像半分 $cw px をフォールバック" }
                            }
                            try {
                                $output = Invoke-PythonTimed -Category "PythonSplit" -PythonArgs $workTrimSplitPy, $origPath, $RightBinding.ToString(), "split", "true", $aspectMin, $cw
                                $result = ($output | ForEach-Object { "$_" }) -join ""
                            } catch {
                                $result = "ERROR:$($_.Exception.Message)"
                            }
                            if ($result -match "SPLIT:2") {
                                Write-FlickFitHost "         ✅ 余白を除去して2ページに分割" -ForegroundColor DarkGreen
                                $folderSplit += 2
                                $splitImages += 2
                                $splitOut1 = Join-Path (Get-LiteralPathParent $origPath) ([System.IO.Path]::GetFileNameWithoutExtension($origPath) + "_1" + [System.IO.Path]::GetExtension($origPath))
                                if (Test-Path -LiteralPath $splitOut1) {
                                    $d = Get-ImageDimensions -Path $splitOut1
                                    if ($d.Width -gt 0) {
                                        $folderCoverWidth = $d.Width
                                        Write-FlickFitDebugStep5VerboseHost -Text "[DEBUG] 表紙幅=$folderCoverWidth px（分割結果）→ 以降の最小幅基準に使用"
                                    }
                                }
                            } elseif ($result -match "SPLIT:1") {
                                Write-FlickFitHost "         ✅ 余白除去のみ（分割なし）" -ForegroundColor DarkGreen
                                $folderSplit += 1
                                $splitImages += 1
                                $splitOut1 = Join-Path (Get-LiteralPathParent $origPath) ([System.IO.Path]::GetFileNameWithoutExtension($origPath) + "_1" + [System.IO.Path]::GetExtension($origPath))
                                if (Test-Path -LiteralPath $splitOut1) {
                                    $d = Get-ImageDimensions -Path $splitOut1
                                    if ($d.Width -gt 0) {
                                        $folderCoverWidth = $d.Width
                                        Write-FlickFitDebugStep5VerboseHost -Text "[DEBUG] 表紙幅=$folderCoverWidth px（SPLIT:1結果）→ 以降の最小幅基準に使用"
                                    }
                                }
                            } elseif ($result -match "ERROR") {
                                Write-FlickFitHost "         ⚠ 処理エラー: $result" -ForegroundColor Yellow
                            } else {
                                Write-FlickFitHost "         ✅ 処理完了" -ForegroundColor DarkGreen
                                $folderSplit += 1
                                $splitImages += 1
                            }
                            $processedImages++
                            # 残っている一時ファイルをすべて削除
                            Get-ChildItem -LiteralPath $dir -File -ErrorAction SilentlyContinue | 
                                Where-Object { $_.Name -like "cvr_*" } | 
                                ForEach-Object { Remove-Item -LiteralPath $_.FullName -Force -ErrorAction SilentlyContinue }
                            # 画像リストを更新（分割で新しいファイルが作成された可能性、一時ファイルを除外）
                            $imgs = @(Get-ProcessableFolderImages -FolderPath $dir)
                            break
                        } elseif ($confirm -match '^[mM]$') {
                            # 手動調整: 通常は元画像。表紙GUIからフォトを開いた場合はそのパス（tmp または別ファイル）を優先
                            $openCoverPhotos = $origPath
                            if ($script:coverPhotosEditPathGui -and (Test-Path -LiteralPath $script:coverPhotosEditPathGui)) {
                                $openCoverPhotos = $script:coverPhotosEditPathGui
                            }
                            $script:coverPhotosEditPathGui = $null
                            Invoke-PhotosOpen -ImagePath $openCoverPhotos
                            Write-FlickFitHost "         ※ フォトで編集・保存したら Enter で続行（編集不要ならそのまま Enter）" -ForegroundColor Yellow
                            Read-HostWithEsc "         [確認]"
                            try { $tmpR2 = (Resolve-Path -LiteralPath $tmpCoverPreview -ErrorAction Stop).Path } catch { $tmpR2 = $tmpCoverPreview }
                            try { $origR2 = (Resolve-Path -LiteralPath $origPath -ErrorAction Stop).Path } catch { $origR2 = $origPath }
                            try { $openR2 = (Resolve-Path -LiteralPath $openCoverPhotos -ErrorAction Stop).Path } catch { $openR2 = $openCoverPhotos }
                            if ($openR2 -and $tmpR2 -and [string]::Equals($openR2, $tmpR2, [System.StringComparison]::OrdinalIgnoreCase)) {
                                Copy-Item -LiteralPath $tmpCoverPreview -Destination $origPath -Force
                                if (Test-Path -LiteralPath $tmpCoverPreview) { Remove-Item -LiteralPath $tmpCoverPreview -Force -ErrorAction SilentlyContinue }
                                $dims = Get-ImageDimensions -Path $origPath
                            } else {
                                if (Test-Path -LiteralPath $tmpCoverPreview) { Remove-Item -LiteralPath $tmpCoverPreview -Force -ErrorAction SilentlyContinue }
                                $dims = Get-ImageDimensions -Path $origPath
                            }
                            if ($dims.Width -gt 0) { $folderCoverWidth = $dims.Width }
                            Write-FlickFitHost "         ✅ 採用しました" -ForegroundColor Green
                        } elseif ($confirm -match '^[nN]$') {
                            Write-FlickFitHost "         ⏮ キャンセル（元のまま）" -ForegroundColor Yellow
                        } elseif ($confirm -match '^[dD]$') {
                            if (Test-Path -LiteralPath $tmpCoverPreview) { Remove-Item -LiteralPath $tmpCoverPreview -Force -ErrorAction SilentlyContinue }
                            # 画像ビューアがロックしている可能性があるため、リトライ
                            $deleteSuccess = $false
                            for ($retry = 0; $retry -lt 5; $retry++) {
                                try {
                                    [System.GC]::Collect()
                                    [System.GC]::WaitForPendingFinalizers()
                                    Start-Sleep -Milliseconds 500
                                    if (Test-Path -LiteralPath $origPath) {
                                        Remove-Item -LiteralPath $origPath -Force -ErrorAction Stop
                                    }
                                    # 削除後に本当に消えたか確認
                                    if (-not (Test-Path -LiteralPath $origPath)) {
                                        $deleteSuccess = $true
                                        break
                                    }
                                } catch {
                                    if ($retry -lt 4) { Start-Sleep -Milliseconds 500 }
                                }
                            }
                            # それでも残っている場合はごみ箱へ移動を試みる
                            if (-not $deleteSuccess -and (Test-Path -LiteralPath $origPath)) {
                                try {
                                    Add-Type -AssemblyName Microsoft.VisualBasic -ErrorAction SilentlyContinue
                                    [Microsoft.VisualBasic.FileIO.FileSystem]::DeleteFile(
                                        $origPath,
                                        [Microsoft.VisualBasic.FileIO.UIOption]::OnlyErrorDialogs,
                                        [Microsoft.VisualBasic.FileIO.RecycleOption]::SendToRecycleBin
                                    )
                                    Start-Sleep -Milliseconds 300
                                    if (-not (Test-Path -LiteralPath $origPath)) {
                                        $deleteSuccess = $true
                                    }
                                } catch { }
                            }
                            if ($deleteSuccess) {
                                Write-FlickFitHost "         🗑 削除しました: $coverName" -ForegroundColor Yellow
                            } else {
                                Write-FlickFitHost "         ⚠ 削除失敗（ファイル使用中?）: $coverName" -ForegroundColor Red
                                Write-FlickFitHost "           パス: $origPath" -ForegroundColor Gray
                                Write-FlickFitHost "         ※ 画像ビューアを閉じてから再試行してください" -ForegroundColor Yellow
                            }
                            # 画像リストを更新（削除された画像を除外）
                            $imgs = @($imgs | Where-Object { $_.FullName -ne $origPath })
                            # 削除後は次の画像を処理（同じインデックスに新しい画像が来る）
                            continue
                        } elseif ($confirm -eq '2') {
                            if (Test-Path -LiteralPath $tmpCoverPreview) { Remove-Item -LiteralPath $tmpCoverPreview -Force -ErrorAction SilentlyContinue }
                            Write-FlickFitHost "         ⏭ 次の画像へ" -ForegroundColor Cyan
                            $skippedPrevImages.Add($origPath)  # スキップした画像を記録
                        } elseif ((Get-Variable -Name CoverGuiMarginAdoptDone -Scope Script -ErrorAction SilentlyContinue) -and $script:CoverGuiMarginAdoptDone) {
                            $script:CoverGuiMarginAdoptDone = $false
                            $imgs = @(Get-ProcessableFolderImages -FolderPath $dir)
                            $cwPickGm = $null
                            if (Test-Path -LiteralPath $origPath) { $cwPickGm = $origPath }
                            elseif ($imgs.Count -gt $coverCheckIdx -and (Test-Path -LiteralPath $imgs[$coverCheckIdx].FullName)) { $cwPickGm = $imgs[$coverCheckIdx].FullName }
                            elseif ($imgs.Count -gt 0) {
                                foreach ($itGm in $imgs) { if ($itGm.FullName -and (Test-Path -LiteralPath $itGm.FullName)) { $cwPickGm = $itGm.FullName; break } }
                            }
                            if ($cwPickGm) {
                                $dCovGm = Get-ImageDimensions -Path $cwPickGm
                                if ($dCovGm.Width -gt 0) {
                                    $folderCoverWidth = $dCovGm.Width
                                    Write-FlickFitDebugStep5VerboseHost -Text "[DEBUG] 表紙幅=$folderCoverWidth px → 分割時の最小幅基準に使用"
                                }
                            }
                            Write-FlickFitHost "         ✅ 採用しました（GUIの余白トリム反映済み）" -ForegroundColor Green
                            # スキップした前の画像があれば削除確認
                            if ($skippedPrevImages.Count -gt 0) {
                                $skippedNames = ($skippedPrevImages | ForEach-Object { Split-Path $_ -Leaf }) -join ", "
                                Write-FlickFitHost "         📎 スキップした画像: $skippedNames" -ForegroundColor Yellow
                                Write-FlickFitHost "         [D] 削除  [Enter] 残す" -ForegroundColor DarkGray
                                $delPrev = Read-HostWithEsc "         [前の画像]"
                                if ($delPrev -match '^[dD]$') {
                                    foreach ($sp in $skippedPrevImages) {
                                        $spDeleted = $false
                                        for ($spRetry = 0; $spRetry -lt 5; $spRetry++) {
                                            try {
                                                [System.GC]::Collect()
                                                [System.GC]::WaitForPendingFinalizers()
                                                Start-Sleep -Milliseconds 300
                                                if (Test-Path -LiteralPath $sp) {
                                                    Remove-Item -LiteralPath $sp -Force -ErrorAction Stop
                                                }
                                                if (-not (Test-Path -LiteralPath $sp)) {
                                                    $spDeleted = $true
                                                    break
                                                }
                                            } catch {
                                                if ($spRetry -lt 4) { Start-Sleep -Milliseconds 500 }
                                            }
                                        }
                                        if ($spDeleted) {
                                            Write-FlickFitHost "         🗑 削除: $(Get-LiteralPathLeaf $sp)" -ForegroundColor Yellow
                                        } else {
                                            Write-FlickFitHost "         ⚠ 削除失敗: $(Get-LiteralPathLeaf $sp)" -ForegroundColor Red
                                        }
                                        $imgs = @($imgs | Where-Object { $_.FullName -ne $sp })
                                    }
                                }
                                $skippedPrevImages.Clear()
                            }
                        } else {
                            $dims = Get-ImageDimensions -Path $tmpCoverPreview
                            if ($dims.Width -gt 0) {
                                $folderCoverWidth = $dims.Width
                                Write-FlickFitDebugStep5VerboseHost -Text "[DEBUG] 表紙幅=$folderCoverWidth px → 分割時の最小幅基準に使用"
                            }
                            if (Test-Path -LiteralPath $tmpCoverPreview) {
                                Copy-Item -LiteralPath $tmpCoverPreview -Destination $origPath -Force
                            } else {
                                Write-FlickFitHost "         [警告] 一時プレビューが見つかりません（既に削除済みの可能性）。元画像のまま続行します。" -ForegroundColor Yellow
                            }
                            Write-FlickFitHost "         ✅ 採用しました" -ForegroundColor Green
                            # スキップした前の画像があれば削除確認
                            if ($skippedPrevImages.Count -gt 0) {
                                $skippedNames = ($skippedPrevImages | ForEach-Object { Split-Path $_ -Leaf }) -join ", "
                                Write-FlickFitHost "         📎 スキップした画像: $skippedNames" -ForegroundColor Yellow
                                Write-FlickFitHost "         [D] 削除  [Enter] 残す" -ForegroundColor DarkGray
                                $delPrev = Read-HostWithEsc "         [前の画像]"
                                if ($delPrev -match '^[dD]$') {
                                    foreach ($sp in $skippedPrevImages) {
                                        $spDeleted = $false
                                        for ($spRetry = 0; $spRetry -lt 5; $spRetry++) {
                                            try {
                                                [System.GC]::Collect()
                                                [System.GC]::WaitForPendingFinalizers()
                                                Start-Sleep -Milliseconds 300
                                                if (Test-Path -LiteralPath $sp) {
                                                    Remove-Item -LiteralPath $sp -Force -ErrorAction Stop
                                                }
                                                if (-not (Test-Path -LiteralPath $sp)) {
                                                    $spDeleted = $true
                                                    break
                                                }
                                            } catch {
                                                if ($spRetry -lt 4) { Start-Sleep -Milliseconds 500 }
                                            }
                                        }
                                        if ($spDeleted) {
                                            Write-FlickFitHost "         🗑 削除: $(Get-LiteralPathLeaf $sp)" -ForegroundColor Yellow
                                        } else {
                                            Write-FlickFitHost "         ⚠ 削除失敗: $(Get-LiteralPathLeaf $sp)" -ForegroundColor Red
                                        }
                                        $imgs = @($imgs | Where-Object { $_.FullName -ne $sp })
                                    }
                                }
                                $skippedPrevImages.Clear()
                            }
                        }
                        if (Test-Path -LiteralPath $tmpCoverPreview) { Start-Sleep -Milliseconds 500; Remove-Item -LiteralPath $tmpCoverPreview -Force -ErrorAction SilentlyContinue }
                        $folderSplit += 1
                        $splitImages += 1
                        $processedImages++
                        
                        # 次の画像確認へ進むか判定
                        if ($confirm -eq '2') {
                            $coverCheckIdx++
                            continue
                        }
                        # 表紙が確定した（表紙候補ループを抜けた後、次の見開きで1回だけGUIを出すためのフラグ）
                        if (-not (Get-Variable -Name PostCoverConfirmed -Scope Script -ErrorAction SilentlyContinue)) { $script:PostCoverConfirmed = @{} }
                        try { $script:PostCoverConfirmed[$dir] = $true } catch { }
                        
                        # 次の画像が横長（見開き等）かチェック - 縦長は自動スキップ
                        $nextIdx = $coverCheckIdx + 1
                        if ($nextIdx -lt $imgs.Count) {
                            $nextImg = $imgs[$nextIdx]
                            $nextAspect = Get-ImageAspect $nextImg.FullName
                            $nextSize = $nextImg.Length
                            $dNext = Get-ImageDimensions -Path $nextImg.FullName
                            
                            # 次の画像が横長（見開き）候補の場合。aspect が不安定でも実寸 W>=H を優先して拾う
                            $nextW = $dNext.Width
                            $nextH = $dNext.Height
                            $isNextLandscape = (($nextW -gt 0 -and $nextH -gt 0 -and $nextW -ge $nextH) -or (Test-IsLandscapeAspectForSpread -Aspect $nextAspect -Threshold $AspectThreshold))
                            if ($isNextLandscape) {
                                $cache = $script:FolderGutterCache[$dir]
                                $cacheMtFlag = if ($cache) { Get-HashtableBool -Tbl $cache -Key 'MarginTrimWithoutSplit' } else { $false }
                                $useCachedGutter = ($cache -and $cache.ImgW -eq $nextW -and $cache.ImgH -eq $nextH -and (($cache.GutterX -gt 0) -or $cacheMtFlag))
                                # 表紙確定後の横長は「最初の1枚だけGUIで決定」→以降はキャッシュで自動適用
                                if (-not (Get-Variable -Name PostCoverSpreadGuiDone -Scope Script -ErrorAction SilentlyContinue)) { $script:PostCoverSpreadGuiDone = @{} }
                                $needGuiOnce = $true
                                try {
                                    if ($script:PostCoverSpreadGuiDone.ContainsKey($dir) -and $script:PostCoverSpreadGuiDone[$dir]) { $needGuiOnce = $false }
                                } catch { $needGuiOnce = $true }
                                if ($needGuiOnce) {
                                    Write-FlickFitHost "`n         📎 2ページ目も横長（見開き）: $($nextImg.Name) → 1回だけGUIでノド/余白を決めます（以降は自動）" -ForegroundColor Cyan
                                    $useCachedGutter = $false
                                }
                                if ($useCachedGutter) {
                                    Write-FlickFitHost "$(if ($cacheMtFlag) { "`n         📎 2ページ目も横長: $($nextImg.Name)（前回の余白トリムのみを自動適用・分割なし）" } else { "`n         📎 2ページ目も横長: $($nextImg.Name)（のど位置を前回設定で自動適用）" })" -ForegroundColor Cyan
                                    $nextPath = $nextImg.FullName
                                    $cw2 = $folderCoverWidth
                                    if ($cw2 -le 0) { $d2 = Get-ImageDimensions -Path $nextPath; if ($d2.Width -gt 0) { $cw2 = [Math]::Floor($d2.Width / 2) } }
                                    try {
                                        $ltCached = Get-HashtableInt -Tbl $cache -Key 'LeftTrimPx'
                                        $rtCached = Get-HashtableInt -Tbl $cache -Key 'RightTrimPx'
                                        $ttCached = Get-HashtableInt -Tbl $cache -Key 'TopTrimPx'
                                        $btCached = Get-HashtableInt -Tbl $cache -Key 'BottomTrimPx'
                                        $cacheMtOnlyC = Get-HashtableBool -Tbl $cache -Key 'MarginTrimWithoutSplit'
                                        $output = @()
                                        if ($cacheMtOnlyC) {
                                            $vertCMt = Repair-GutterVerticalMargins -ImgH $nextH -TopTrim $ttCached -BottomTrim $btCached
                                            Write-FlickFitHost "         [キャッシュ] 同サイズ: 余白のみトリム 左=${ltCached}px 右=${rtCached}px 上=$($vertCMt.TopTrimPx)px 下=$($vertCMt.BottomTrimPx)px（分割なし）" -ForegroundColor DarkCyan
                                            $result = Invoke-PythonCropGuiMargins -WorkTrimSplitPy $workTrimSplitPy -ImagePath $nextPath -RightBinding $RightBinding -LeftTrim $ltCached -TopTrim $vertCMt.TopTrimPx -RightTrim $rtCached -BottomTrim $vertCMt.BottomTrimPx
                                        } else {
                                            $gPctC = 50.0
                                            $hasPctKey = $false
                                            foreach ($ck in @($cache.Keys)) {
                                                if ([string]::Equals([string]$ck, 'GutterPct', [StringComparison]::OrdinalIgnoreCase)) {
                                                    try { $gPctC = [Math]::Max(1, [Math]::Min(99, [double]$cache[$ck])); $hasPctKey = $true; break } catch {}
                                                }
                                            }
                                            if (-not $hasPctKey) {
                                                $gxOldC = Get-HashtableInt -Tbl $cache -Key 'GutterX'
                                                $iwOld = if ($cache.ImgW -gt 0) { [int]$cache.ImgW } else { $nextW }
                                                if ($iwOld -gt 0 -and $gxOldC -gt 0) { $gPctC = [Math]::Max(1, [Math]::Min(99, 100.0 * $gxOldC / [double]$iwOld)) }
                                            }
                                            $gxEffC = [int]([Math]::Round($nextW * $gPctC / 100.0))
                                            $gxEffC = [Math]::Max(7, [Math]::Min($nextW - 8, $gxEffC))
                                            $cohC = Repair-GutterMarginGeometry -ImgW $nextW -GutterX $gxEffC -LeftTrim $ltCached -RightTrim $rtCached
                                            $vertC = Repair-GutterVerticalMargins -ImgH $nextH -TopTrim $ttCached -BottomTrim $btCached
                                            Write-FlickFitHost "         [キャッシュ] 同サイズ見開き: ノド=${cohC.GutterX}px 左=${cohC.LeftTrimPx}px 右=${cohC.RightTrimPx}px 上=${vertC.TopTrimPx}px 下=${vertC.BottomTrimPx}px" -ForegroundColor DarkCyan
                                            $output = @(& $script:PythonExe $workTrimSplitPy $nextPath $RightBinding.ToString() "split_at_gutter_with_margins" "-" $cohC.GutterX $cohC.LeftTrimPx $cohC.RightTrimPx $aspectMin $cw2 $vertC.TopTrimPx $vertC.BottomTrimPx 2>&1 | ForEach-Object { "$_" })
                                            $result = $output -join ""
                                        }
                                        Write-FlickFitPythonDebugLines -Lines @($output)
                                    } catch { $result = "ERROR:$($_.Exception.Message)" }
                                    if ($result -match "TRIMMED:1" -and $cacheMtFlag) {
                                        Write-FlickFitHost "         ✅ 前回どおり余白のみトリミングしました（1枚のまま）" -ForegroundColor DarkGreen
                                        $folderSplit += 1
                                        $splitImages += 1
                                        $processedImages++
                                        $imgs = @(Get-ProcessableFolderImages -FolderPath $dir)
                                        $coverLoopImgsRefreshed = $true
                                        $resolvedCcMt = Get-FlickFitNextCoverLoopIndexAfterSpreadOp -Images $imgs -ProcessedSourcePath $nextPath -PythonResult $result
                                        if ($null -ne $resolvedCcMt) {
                                            $coverCheckIdx = $resolvedCcMt
                                        } else {
                                            $coverCheckIdx = $nextIdx + 1
                                        }
                                        $script:PostCoverSpreadGuiDone[$dir] = $true
                                        break
                                    }
                                    if ($result -match "SPLIT:2") {
                                        Write-FlickFitHost "         ✅ のど位置を自動適用して2ページに分割" -ForegroundColor DarkGreen
                                        $folderSplit += 2
                                        $splitImages += 2
                                        try {
                                            Add-FlickFitGuiSplitTrustOutputs -GuiSplitTrustSet $guiSplitTrustNorm -SplitBasePath $nextPath
                                        } catch {
                                            Write-FlickFitHost "         [警告] 分割片の信頼リスト登録に失敗（処理は続行）: $($_.Exception.Message)" -ForegroundColor DarkYellow
                                        }
                                        $processedImages++
                                        $imgs = @(Get-ProcessableFolderImages -FolderPath $dir)
                                        $coverLoopImgsRefreshed = $true
                                        $resolvedCcSp = Get-FlickFitNextCoverLoopIndexAfterSpreadOp -Images $imgs -ProcessedSourcePath $nextPath -PythonResult $result
                                        if ($null -ne $resolvedCcSp) {
                                            $coverCheckIdx = $resolvedCcSp
                                        } else {
                                            # 1 見開き→2 枚に置換で net +1 枚（旧ロジック）
                                            $coverCheckIdx = $nextIdx + 2
                                        }
                                        $script:PostCoverSpreadGuiDone[$dir] = $true
                                        break
                                    }
                                    Write-FlickFitHost "         ⚠ キャッシュ自動適用に失敗しました: $result" -ForegroundColor Yellow
                                    Write-FlickFitHost "         → GUI でノド/余白を設定してください。" -ForegroundColor DarkCyan
                                    $useCachedGutter = $false
                                }
                                if (-not $useCachedGutter) {
                                # GUI で別ページに適用した場合に備え、最初に開いたファイルを記録（OK が別ページだけだと開始側が未処理のまま）
                                $spreadGuiEntryPath = $nextImg.FullName
                                Write-FlickFitHost "`n         📎 2ページ目も横長（見開き）: $($nextImg.Name) - ここで分割します" -ForegroundColor Cyan
                                $allPaths = @($imgs | ForEach-Object { $_.FullName })
                                $guiResult2 = Show-GutterMarginSetGui -ImagePath $nextImg.FullName -Title "ノドと左右余白の設定 - ここで分割します" -AllImagePaths $allPaths -OkAppliesToCurrentView -ShowApplyThisPageOnlyButton
                                if ($guiResult2 -is [System.Collections.IDictionary]) { $guiResult2 = Normalize-GutterGuiResult -GuiResult $guiResult2 }
                                $imgs = Update-ImgsAfterMarginGui -Imgs $imgs -GuiResult $guiResult2
                                if (Test-GuiMarginFlagTrue -Tbl $guiResult2 -Key 'ApplyOnlyThisSpread') {
                                    $script:SplitWidthApplyGutterOnlyThisPage = $true
                                }
                                $gui2DeletedPaths = [System.Collections.Generic.List[string]]::new()
                                if ($null -ne $guiResult2 -and $guiResult2 -is [System.Collections.IDictionary] -and $guiResult2.ContainsKey('DeletedImagePaths')) {
                                    foreach ($gd in @($guiResult2['DeletedImagePaths'])) {
                                        $gs = [string]$gd
                                        if (-not [string]::IsNullOrWhiteSpace($gs)) { [void]$gui2DeletedPaths.Add($gs) }
                                    }
                                }
                                $hadGui2SessionDeletes = ($gui2DeletedPaths.Count -gt 0)
                                if (Test-GuiMarginFlagTrue -Tbl $guiResult2 -Key 'DeleteImage') {
                                    Write-FlickFitHost "         ↩ GUI削除を反映しました。一覧を更新し、次の画像から再評価します" -ForegroundColor DarkGray
                                    $imgs = @(Get-ProcessableFolderImages -FolderPath $dir)
                                    $coverLoopImgsRefreshed = $true
                                    $ixR = $nextIdx
                                    if ($ixR -lt 0) { $ixR = 0 }
                                    if ($imgs.Count -gt 0 -and $ixR -ge $imgs.Count) { $ixR = $imgs.Count - 1 }
                                    $coverWhileExitImgIdxOverride = $ixR
                                    break
                                }
                                if ($hadGui2SessionDeletes) {
                                    Write-FlickFitHost "         ↩ GUIで画像を削除したため、このセッションの余白・分割結果は適用せず、一覧を更新して次の画像から再評価します" -ForegroundColor DarkGray
                                    $imgs = @(Get-ProcessableFolderImages -FolderPath $dir)
                                    $coverLoopImgsRefreshed = $true
                                    $ixR = $nextIdx
                                    if ($ixR -lt 0) { $ixR = 0 }
                                    if ($imgs.Count -gt 0 -and $ixR -ge $imgs.Count) { $ixR = $imgs.Count - 1 }
                                    $coverWhileExitImgIdxOverride = $ixR
                                    break
                                }
                                if ($null -ne $guiResult2 -and $guiResult2 -is [System.Collections.IDictionary] -and (Get-HashtableInt -Tbl $guiResult2 -Key 'GutterX' -Default (-1)) -ge 0) {
                                    $script:PostCoverSpreadGuiDone[$dir] = $true
                                }
                                $splitPath2 = $nextImg.FullName
                                $apSp2 = Get-HashtableTrimmedString -Tbl $guiResult2 -Key 'ApplyImagePath'
                                if ($apSp2 -and (Test-Path -LiteralPath $apSp2)) { $splitPath2 = $apSp2 }
                                $dSp2 = Get-ImageDimensions -Path $splitPath2
                                if ($dSp2.Width -gt 0 -and $dSp2.Height -gt 0) { $nextW = $dSp2.Width; $nextH = $dSp2.Height }
                                $gutterX = $null
                                $lt2 = 0; $rt2 = 0
                                if (Test-GuiMarginFlagTrue -Tbl $guiResult2 -Key 'PhotosEdit') {
                                    if (Test-Path -LiteralPath $tmpCoverPreview) { Remove-Item -LiteralPath $tmpCoverPreview -Force -ErrorAction SilentlyContinue }
                                    $photoPath = $guiResult2.ImagePath
                                    $dPhoto = Get-ImageDimensions -Path $photoPath
                                    if ($dPhoto.Width -gt 0) { $folderCoverWidth = $dPhoto.Width }
                                    Write-FlickFitHost "         ✅ フォトで編集した画像を採用（以降のトリミング基準に使用）" -ForegroundColor Green
                                    $folderSplit += 1
                                    $splitImages += 1
                                    $processedImages++
                                    $imgs = @(Get-ProcessableFolderImages -FolderPath $dir)
                                    $coverLoopImgsRefreshed = $true
                                    $coverCheckIdx = $nextIdx + 1
                                    break
                                }
                                $lt2 = 0; $rt2 = 0; $tt2 = 0; $bt2 = 0
                                if ($null -ne $guiResult2) {
                                    $gx2 = Get-HashtableInt -Tbl $guiResult2 -Key 'GutterX' -Default (-1)
                                    if ($gx2 -ge 0) {
                                        $gutterX = $gx2
                                        $lt2 = Get-HashtableInt -Tbl $guiResult2 -Key 'LeftTrimPx'
                                        $rt2 = Get-HashtableInt -Tbl $guiResult2 -Key 'RightTrimPx'
                                        $tt2 = Get-HashtableInt -Tbl $guiResult2 -Key 'TopTrimPx'
                                        $bt2 = Get-HashtableInt -Tbl $guiResult2 -Key 'BottomTrimPx'
                                    }
                                }
                                # キャンセル時は2回目のGUIを出さず直接メニューへ（1回のキャンセルで受け付ける）
                                if ($null -ne $gutterX -and $gutterX -ge 0) {
                                    if (Test-Path -LiteralPath $tmpCoverPreview) { Remove-Item -LiteralPath $tmpCoverPreview -Force -ErrorAction SilentlyContinue }
                                    $cw2 = $folderCoverWidth
                                    if ($cw2 -le 0) { $d2 = Get-ImageDimensions -Path $splitPath2; if ($d2.Width -gt 0) { $cw2 = [Math]::Floor($d2.Width / 2) } }
                                    try {
                                        $mtOnly2 = Get-HashtableBool -Tbl $guiResult2 -Key 'MarginTrimWithoutSplit'
                                        $output = @()
                                        if ($mtOnly2) {
                                            Write-FlickFitHost "         [余白のみ・分割なし] 左=${lt2}px 右=${rt2}px 上=${tt2}px 下=${bt2}px (2p目GUI→Python)" -ForegroundColor DarkCyan
                                            $vertMt2 = Repair-GutterVerticalMargins -ImgH $nextH -TopTrim $tt2 -BottomTrim $bt2
                                            $result = Invoke-PythonCropGuiMargins -WorkTrimSplitPy $workTrimSplitPy -ImagePath $splitPath2 -RightBinding $RightBinding -LeftTrim $lt2 -TopTrim $vertMt2.TopTrimPx -RightTrim $rt2 -BottomTrim $vertMt2.BottomTrimPx
                                        } elseif ($null -ne $guiResult2 -and ($lt2 -gt 0 -or $rt2 -gt 0 -or $tt2 -gt 0 -or $bt2 -gt 0)) {
                                            Write-FlickFitHost "         [余白・ノド] のど=${gutterX}px 左=${lt2}px 右=${rt2}px 上=${tt2}px 下=${bt2}px (2p目GUI→Python)" -ForegroundColor DarkCyan
                                            $coh2 = Repair-GutterMarginGeometry -ImgW $nextW -GutterX $gutterX -LeftTrim $lt2 -RightTrim $rt2
                                            $gutterX = $coh2.GutterX; $lt2 = $coh2.LeftTrimPx; $rt2 = $coh2.RightTrimPx
                                            $vert2 = Repair-GutterVerticalMargins -ImgH $nextH -TopTrim $tt2 -BottomTrim $bt2
                                            $tt2 = $vert2.TopTrimPx; $bt2 = $vert2.BottomTrimPx
                                            $output = @(& $script:PythonExe $workTrimSplitPy $splitPath2 $RightBinding.ToString() "split_at_gutter_with_margins" "-" $gutterX $lt2 $rt2 $aspectMin $cw2 $tt2 $bt2 2>&1 | ForEach-Object { "$_" })
                                            $result = $output -join ""
                                        } else {
                                            $output = @(& $script:PythonExe $workTrimSplitPy $splitPath2 $RightBinding.ToString() "split_at_gutter" "false" $gutterX $aspectMin $cw2 "false" "true" 2>&1 | ForEach-Object { "$_" })
                                            $result = $output -join ""
                                        }
                                        Write-FlickFitPythonDebugLines -Lines @($output)
                                    } catch { $result = "ERROR:$($_.Exception.Message)" }
                                        if ($result -match "TRIMMED:1" -and (Get-HashtableBool -Tbl $guiResult2 -Key 'MarginTrimWithoutSplit')) {
                                        Write-FlickFitHost "         ✅ 余白のみトリミングしました（1枚のまま、以降同サイズは自動適用）" -ForegroundColor DarkGreen
                                        $folderSplit += 1
                                        $splitImages += 1
                                        if ($null -ne $vertMt2) { $tt2 = $vertMt2.TopTrimPx; $bt2 = $vertMt2.BottomTrimPx }
                                        $refAsp = 0
                                        $refW = 0
                                        if (Test-Path -LiteralPath $splitPath2) {
                                            $dRefT = Get-ImageDimensions -Path $splitPath2
                                            if ($dRefT.Width -gt 0 -and $dRefT.Height -gt 0) { $refAsp = $dRefT.Width / $dRefT.Height; $refW = $dRefT.Width }
                                        }
                                        $ucsC2 = $true
                                        $skipCacheC2a = (Get-Variable -Name SplitWidthApplyGutterOnlyThisPage -Scope Script -ErrorAction SilentlyContinue) -and $script:SplitWidthApplyGutterOnlyThisPage
                                        if ($skipCacheC2a) { $script:SplitWidthApplyGutterOnlyThisPage = $false } else {
                                            $script:FolderGutterCache[$dir] = New-FlickFitFolderGutterCacheEntry -GutterX $gutterX -GutterPct 50.0 -LeftTrimPx $lt2 -RightTrimPx $rt2 -TopTrimPx $tt2 -BottomTrimPx $bt2 -ImgW $nextW -ImgH $nextH -RefAspect $refAsp -RefWidth $refW -MarginTrimWithoutSplit $ucsC2
                                        }
                                    } elseif ($result -match "SPLIT:2") {
                                        Write-FlickFitHost "         ✅ のど位置を手動設定して2ページに分割（以降、同サイズ画像は自動適用）" -ForegroundColor DarkGreen
                                        $folderSplit += 2
                                        $splitImages += 2
                                        $so1 = Join-Path (Get-LiteralPathParent $splitPath2) ([System.IO.Path]::GetFileNameWithoutExtension($splitPath2) + "_1" + [System.IO.Path]::GetExtension($splitPath2))
                                        try {
                                            Add-FlickFitGuiSplitTrustOutputs -GuiSplitTrustSet $guiSplitTrustNorm -SplitBasePath $splitPath2
                                        } catch {
                                            Write-FlickFitHost "         [警告] 分割片の信頼リスト登録に失敗（処理は続行）: $($_.Exception.Message)" -ForegroundColor DarkYellow
                                        }
                                        if ($folderCoverWidth -le 0 -and (Test-Path -LiteralPath $so1)) {
                                            $dd = Get-ImageDimensions -Path $so1
                                            if ($dd.Width -gt 0) { $folderCoverWidth = $dd.Width }
                                        }
                                        $refAsp = 0
                                        $refW = 0
                                        if (Test-Path -LiteralPath $so1) {
                                            $dRef = Get-ImageDimensions -Path $so1
                                        if ($dRef.Width -gt 0 -and $dRef.Height -gt 0) { $refAsp = $dRef.Width / $dRef.Height; $refW = $dRef.Width }
                                        }
                                        $gp2 = 50.0
                                        if ($null -ne $guiResult2 -and $guiResult2 -is [System.Collections.IDictionary]) {
                                            foreach ($gk in @($guiResult2.Keys)) {
                                                if ([string]::Equals([string]$gk, 'GutterPct', [StringComparison]::OrdinalIgnoreCase)) {
                                                    try { $gp2 = [Math]::Max(1, [Math]::Min(99, [double]$guiResult2[$gk])); break } catch {}
                                                }
                                            }
                                        }
                                        if ($gp2 -eq 50.0 -and $nextW -gt 0) { $gp2 = [Math]::Round(100.0 * $gutterX / $nextW, 2) }
                                        $ucsC2 = Get-HashtableBool -Tbl $guiResult2 -Key 'MarginTrimWithoutSplit'
                                        $skipCacheC2b = (Get-Variable -Name SplitWidthApplyGutterOnlyThisPage -Scope Script -ErrorAction SilentlyContinue) -and $script:SplitWidthApplyGutterOnlyThisPage
                                        if ($skipCacheC2b) { $script:SplitWidthApplyGutterOnlyThisPage = $false } else {
                                            $script:FolderGutterCache[$dir] = New-FlickFitFolderGutterCacheEntry -GutterX $gutterX -GutterPct $gp2 -LeftTrimPx $lt2 -RightTrimPx $rt2 -TopTrimPx $tt2 -BottomTrimPx $bt2 -ImgW $nextW -ImgH $nextH -RefAspect $refAsp -RefWidth $refW -MarginTrimWithoutSplit $ucsC2
                                        }
                                        # 同じフォルダ＋同じサイズの見開きには GUI で決めた余白＋ノドをそのまま適用（対話なし・従来 [1] 相当）
                                        $sizeKey = "$($dir)|${nextW}x${nextH}"
                                        if (-not $script:FolderMarginMode.ContainsKey($sizeKey)) {
                                            $script:FolderMarginMode[$sizeKey] = 'gui'
                                        }
                                    } else {
                                        Write-FlickFitHost "         ⚠ 分割/トリム処理: $result" -ForegroundColor Yellow
                                    }
                                    $processedImages++
                                    $imgs = @(Get-ProcessableFolderImages -FolderPath $dir)
                                    $coverLoopImgsRefreshed = $true
                                    $coverResumeAfter2pGui = 1
                                    if ($result -match "SPLIT:2") { $coverResumeAfter2pGui = 2 }
                                    $guiEntryKey2 = $null
                                    $actualSplitKey2 = $null
                                    try { $guiEntryKey2 = Get-FlickFitStep5PathKey $spreadGuiEntryPath } catch { }
                                    try { $actualSplitKey2 = Get-FlickFitStep5PathKey $splitPath2 } catch { }
                                    if ($guiEntryKey2 -and $actualSplitKey2 -and ($guiEntryKey2 -ne $actualSplitKey2)) {
                                        $idxResume2 = Get-FlickFitCoverLoopIndexForPath -Images $imgs -FullPath $spreadGuiEntryPath
                                        if ($idxResume2 -ge 0) {
                                            $coverCheckIdx = $idxResume2
                                            if ($true -eq $script:FlickFitDebugStep5Verbose) {
                                                Write-FlickFitHost "         [IDX-DBG] 2pGui entry=$(Split-Path -Leaf $spreadGuiEntryPath) actual=$(Split-Path -Leaf $splitPath2) → coverCheckIdx=$coverCheckIdx (resume entry; altページのみ処理済み)" -ForegroundColor DarkGray
                                            }
                                        } else {
                                            $resolvedCcGui = Get-FlickFitNextCoverLoopIndexAfterSpreadOp -Images $imgs -ProcessedSourcePath $splitPath2 -PythonResult $result
                                            if ($null -ne $resolvedCcGui) {
                                                $coverCheckIdx = $resolvedCcGui
                                            } else {
                                                $coverCheckIdx = $nextIdx + $coverResumeAfter2pGui
                                            }
                                            if ($true -eq $script:FlickFitDebugStep5Verbose) {
                                                Write-FlickFitHost "         [IDX-DBG] entry path missing in list after split; used resolver coverCheckIdx=$coverCheckIdx" -ForegroundColor DarkYellow
                                            }
                                        }
                                    } else {
                                        $resolvedCcGui = Get-FlickFitNextCoverLoopIndexAfterSpreadOp -Images $imgs -ProcessedSourcePath $splitPath2 -PythonResult $result
                                        if ($null -ne $resolvedCcGui) {
                                            $coverCheckIdx = $resolvedCcGui
                                            if ($true -eq $script:FlickFitDebugStep5Verbose) {
                                                Write-FlickFitHost "         [IDX-DBG] staleNextIdx=$nextIdx splitSource=$(Split-Path -Leaf $splitPath2) resolvedCoverCheckIdx=$coverCheckIdx fallback=$($nextIdx + $coverResumeAfter2pGui)" -ForegroundColor DarkGray
                                            }
                                        } else {
                                            $coverCheckIdx = $nextIdx + $coverResumeAfter2pGui
                                            if ($true -eq $script:FlickFitDebugStep5Verbose) {
                                                Write-FlickFitHost "         [IDX-DBG] staleNextIdx=$nextIdx splitSource=$(Split-Path -Leaf $splitPath2) fallbackCoverCheckIdx=$coverCheckIdx (resolver missed _2/_1 leaf)" -ForegroundColor DarkYellow
                                            }
                                        }
                                    }
                                    break
                                } else {
                                    Write-FlickFitHost "         （GUIキャンセル）メニューから選択してください" -ForegroundColor Gray
                                    try { if (Test-Path -LiteralPath $splitPath2) { Start-Process $splitPath2 } } catch { Write-FlickFitHost "         ⚠ 画像表示エラー" -ForegroundColor Yellow }
                                    Write-FlickFitHost "         [1/Enter] 通常分割  [2] 表紙トリミング  [3] スキップ  [4] のど・左右余白（GUI）  [D] 削除" -ForegroundColor DarkGray
                                    $nextConfirm = Read-HostWithEsc "         [2ページ目処理]"
                                }
                                if ($nextConfirm -match '^[dD]$') {
                                    if (Test-Path -LiteralPath $tmpCoverPreview) { Remove-Item -LiteralPath $tmpCoverPreview -Force -ErrorAction SilentlyContinue }
                                    $nextPath = $nextImg.FullName
                                    $deleteSuccess = $false
                                    for ($retry = 0; $retry -lt 5; $retry++) {
                                        try {
                                            [System.GC]::Collect()
                                            [System.GC]::WaitForPendingFinalizers()
                                            Start-Sleep -Milliseconds 300
                                            if (Test-Path -LiteralPath $nextPath) { Remove-Item -LiteralPath $nextPath -Force -ErrorAction Stop }
                                            if (-not (Test-Path -LiteralPath $nextPath)) { $deleteSuccess = $true; break }
                                        } catch { if ($retry -lt 4) { Start-Sleep -Milliseconds 500 } }
                                    }
                                    if ($deleteSuccess) {
                                        Write-FlickFitHost "         🗑 削除しました: $($nextImg.Name)" -ForegroundColor Yellow
                                    } else {
                                        Write-FlickFitHost "         ⚠ 削除失敗（ファイル使用中?）: $($nextImg.Name)" -ForegroundColor Red
                                    }
                                    $imgs = @($imgs | Where-Object { $_.FullName -ne $nextPath })
                                    # 削除時は coverCheckIdx を進めない（次の画像 003.jpg が coverCheckIdx+1 の位置に詰まるため）
                                    break
                                } elseif ($nextConfirm -eq '' -or $nextConfirm -match '^1$') {
                                    if (Test-Path -LiteralPath $tmpCoverPreview) { Remove-Item -LiteralPath $tmpCoverPreview -Force -ErrorAction SilentlyContinue }
                                    $nextPath = $nextImg.FullName
                                    if ($folderCoverWidth -le 0 -and (Test-Path -LiteralPath $coverImg.FullName)) {
                                        $dCv = Get-ImageDimensions -Path $coverImg.FullName
                                        if ($dCv.Width -gt 0) {
                                            $folderCoverWidth = $dCv.Width
                                            Write-FlickFitDebugStep5VerboseHost -Text "[DEBUG] 2p目分割: 採用表紙から幅=$folderCoverWidth px を取得"
                                        }
                                    }
                                    if ($script:SkipAVIF -and $nextImg.Extension.ToLower() -eq '.avif') {
                                        Write-FlickFitHost "         ✅ AVIF（高速パス: 処理省略）" -ForegroundColor Green
                                        $folderAvifOmit++
                                        $folderSplit += 1
                                        $splitImages += 1
                                        $menu2pResumeDelta = 1
                                    } else {
                                        $menu2pResumeDelta = 1
                                        if ($true -eq $script:FlickFitDebugStep5Verbose) { Write-FlickFitHost "         📍 通常分割..." -ForegroundColor Cyan }
                                        $cw2 = $folderCoverWidth
                                        if ($cw2 -le 0) {
                                            $d2 = Get-ImageDimensions -Path $nextPath
                                            if ($d2.Width -gt 0) { $cw2 = [Math]::Floor($d2.Width / 2); Write-FlickFitDebugStep5VerboseHost -Text "[DEBUG] 2p目: 表紙幅未設定→元画像半分 $cw2 px をフォールバック" }
                                        } else {
                                            Write-FlickFitDebugStep5VerboseHost -Text "[DEBUG] 2p目: 表紙幅=$folderCoverWidth px で分割・表紙+1%を適用" -ForegroundColor DarkYellow
                                        }
                                        try {
                                            $output = & $script:PythonExe $workTrimSplitPy $nextPath $RightBinding.ToString() "split" "true" $aspectMin $cw2 2>&1
                                            $result = ($output | ForEach-Object { "$_" }) -join ""
                                        } catch { $result = "ERROR:$($_.Exception.Message)" }
                                        if ($result -match "SPLIT:2") {
                                            Write-FlickFitHost "         ✅ 余白を除去して2ページに分割" -ForegroundColor DarkGreen
                                            $folderSplit += 2
                                            $splitImages += 2
                                            $menu2pResumeDelta = 2
                                            if ($folderCoverWidth -le 0) {
                                                $so1 = Join-Path (Split-Path $nextPath -Parent) ([System.IO.Path]::GetFileNameWithoutExtension($nextPath) + "_1" + [System.IO.Path]::GetExtension($nextPath))
                                                if (Test-Path -LiteralPath $so1) {
                                                    $dd = Get-ImageDimensions -Path $so1
                                                    if ($dd.Width -gt 0) { $folderCoverWidth = $dd.Width; Write-FlickFitDebugStep5VerboseHost -Text "[DEBUG] 表紙幅=$folderCoverWidth px（2p目分割結果）" }
                                                }
                                            }
                                        } elseif ($result -match "SPLIT:1") {
                                            Write-FlickFitHost "         ✅ 余白除去のみ（分割なし）" -ForegroundColor DarkGreen
                                            $folderSplit += 1
                                            $splitImages += 1
                                            if ($folderCoverWidth -le 0) {
                                                $so1 = Join-Path (Split-Path $nextPath -Parent) ([System.IO.Path]::GetFileNameWithoutExtension($nextPath) + "_1" + [System.IO.Path]::GetExtension($nextPath))
                                                if (Test-Path -LiteralPath $so1) {
                                                    $dd = Get-ImageDimensions -Path $so1
                                                    if ($dd.Width -gt 0) { $folderCoverWidth = $dd.Width; Write-FlickFitDebugStep5VerboseHost -Text "[DEBUG] 表紙幅=$folderCoverWidth px（2p目SPLIT:1結果）" }
                                                }
                                            }
                                        } else {
                                            Write-FlickFitHost "         ✅ 処理完了" -ForegroundColor DarkGreen
                                            $folderSplit += 1
                                            $splitImages += 1
                                        }
                                    }
                                    $processedImages++
                                    $imgs = @(Get-ProcessableFolderImages -FolderPath $dir)
                                    $coverLoopImgsRefreshed = $true
                                    $resolvedCcMn = Get-FlickFitNextCoverLoopIndexAfterSpreadOp -Images $imgs -ProcessedSourcePath $nextPath -PythonResult $result
                                    if ($null -ne $resolvedCcMn) {
                                        $coverCheckIdx = $resolvedCcMn
                                    } else {
                                        $coverCheckIdx = $nextIdx + $menu2pResumeDelta
                                    }
                                    break
                                } elseif ($nextConfirm -match '^2$') {
                                    # 表紙トリミングUIへ進む
                                    if (Test-Path -LiteralPath $tmpCoverPreview) { Remove-Item -LiteralPath $tmpCoverPreview -Force -ErrorAction SilentlyContinue }
                                    $coverCheckIdx++
                                    continue
                                } elseif ($nextConfirm -match '^4$') {
                                    # のど・左右余白: 統一GUI（2ページ目メニュー [4]）
                                    if (Test-Path -LiteralPath $tmpCoverPreview) { Remove-Item -LiteralPath $tmpCoverPreview -Force -ErrorAction SilentlyContinue }
                                    $spreadGuiEntryPathM4 = $nextImg.FullName
                                    $allPathsM4 = @($imgs | ForEach-Object { $_.FullName })
                                    $guiM4 = Show-GutterMarginSetGui -ImagePath $nextImg.FullName -Title "ノドと左右余白の設定 - ここで分割します" -AllImagePaths $allPathsM4 -OkAppliesToCurrentView -ShowApplyThisPageOnlyButton
                                    if ($guiM4 -is [System.Collections.IDictionary]) { $guiM4 = Normalize-GutterGuiResult -GuiResult $guiM4 }
                                    $imgs = Update-ImgsAfterMarginGui -Imgs $imgs -GuiResult $guiM4
                                    if (Test-GuiMarginFlagTrue -Tbl $guiM4 -Key 'ApplyOnlyThisSpread') {
                                        $script:SplitWidthApplyGutterOnlyThisPage = $true
                                    }
                                    $m4DeletedPaths = [System.Collections.Generic.List[string]]::new()
                                    if ($null -ne $guiM4 -and $guiM4 -is [System.Collections.IDictionary] -and $guiM4.ContainsKey('DeletedImagePaths')) {
                                        foreach ($gd in @($guiM4['DeletedImagePaths'])) {
                                            $gs = [string]$gd
                                            if (-not [string]::IsNullOrWhiteSpace($gs)) { [void]$m4DeletedPaths.Add($gs) }
                                        }
                                    }
                                    $hadM4SessionDeletes = ($m4DeletedPaths.Count -gt 0)
                                    if (Test-GuiMarginFlagTrue -Tbl $guiM4 -Key 'DeleteImage') {
                                        Write-FlickFitHost "         ↩ GUI削除を反映しました。一覧を更新し、次の画像から再評価します" -ForegroundColor DarkGray
                                        $imgs = @(Get-ProcessableFolderImages -FolderPath $dir)
                                        $coverLoopImgsRefreshed = $true
                                        $ixR = $nextIdx
                                        if ($ixR -lt 0) { $ixR = 0 }
                                        if ($imgs.Count -gt 0 -and $ixR -ge $imgs.Count) { $ixR = $imgs.Count - 1 }
                                        $coverWhileExitImgIdxOverride = $ixR
                                        break
                                    }
                                    if ($hadM4SessionDeletes) {
                                        Write-FlickFitHost "         ↩ GUIで画像を削除したため、このセッションの余白・分割結果は適用せず、一覧を更新して次の画像から再評価します" -ForegroundColor DarkGray
                                        $imgs = @(Get-ProcessableFolderImages -FolderPath $dir)
                                        $coverLoopImgsRefreshed = $true
                                        $ixR = $nextIdx
                                        if ($ixR -lt 0) { $ixR = 0 }
                                        if ($imgs.Count -gt 0 -and $ixR -ge $imgs.Count) { $ixR = $imgs.Count - 1 }
                                        $coverWhileExitImgIdxOverride = $ixR
                                        break
                                    }
                                    $splitPathM4 = $nextImg.FullName
                                    $apM4 = Get-HashtableTrimmedString -Tbl $guiM4 -Key 'ApplyImagePath'
                                    if ($apM4 -and (Test-Path -LiteralPath $apM4)) { $splitPathM4 = $apM4 }
                                    $dApplyM4 = Get-ImageDimensions -Path $splitPathM4
                                    if ($dApplyM4.Width -gt 0 -and $dApplyM4.Height -gt 0) { $nextW = $dApplyM4.Width; $nextH = $dApplyM4.Height }
                                    if (Test-GuiMarginFlagTrue -Tbl $guiM4 -Key 'PhotosEdit') {
                                        if (Test-Path -LiteralPath $tmpCoverPreview) { Remove-Item -LiteralPath $tmpCoverPreview -Force -ErrorAction SilentlyContinue }
                                        $photoM4 = $guiM4.ImagePath
                                        $dPhM4 = Get-ImageDimensions -Path $photoM4
                                        if ($dPhM4.Width -gt 0) { $folderCoverWidth = $dPhM4.Width }
                                        Write-FlickFitHost "         ✅ フォトで編集した画像を採用（以降のトリミング基準に使用）" -ForegroundColor Green
                                        $folderSplit += 1
                                        $splitImages += 1
                                        $processedImages++
                                        $imgs = @(Get-ProcessableFolderImages -FolderPath $dir)
                                        $coverLoopImgsRefreshed = $true
                                        $coverCheckIdx = $nextIdx + 1
                                        break
                                    }
                                    $gutterX = $null
                                    $ltM4 = 0; $rtM4 = 0; $ttM4 = 0; $btM4 = 0
                                    if ($null -ne $guiM4) {
                                        $gxM4 = Get-HashtableInt -Tbl $guiM4 -Key 'GutterX' -Default (-1)
                                        if ($gxM4 -ge 0) {
                                            $gutterX = $gxM4
                                            $ltM4 = Get-HashtableInt -Tbl $guiM4 -Key 'LeftTrimPx'
                                            $rtM4 = Get-HashtableInt -Tbl $guiM4 -Key 'RightTrimPx'
                                            $ttM4 = Get-HashtableInt -Tbl $guiM4 -Key 'TopTrimPx'
                                            $btM4 = Get-HashtableInt -Tbl $guiM4 -Key 'BottomTrimPx'
                                        }
                                    }
                                    if ($null -ne $gutterX -and $gutterX -ge 0) {
                                        $cw2Manual = $folderCoverWidth
                                        if ($cw2Manual -le 0) {
                                            $d2m = Get-ImageDimensions -Path $splitPathM4
                                            if ($d2m.Width -gt 0) { $cw2Manual = [Math]::Floor($d2m.Width / 2) }
                                        }
                                        try {
                                            $mtOnlyM4 = Get-HashtableBool -Tbl $guiM4 -Key 'MarginTrimWithoutSplit'
                                            $output = @()
                                            if ($mtOnlyM4) {
                                                Write-FlickFitHost "         [余白のみ・分割なし] 左=${ltM4}px 右=${rtM4}px 上=${ttM4}px 下=${btM4}px (メニュー[4]→Python)" -ForegroundColor DarkCyan
                                                $vertMtM4 = Repair-GutterVerticalMargins -ImgH $nextH -TopTrim $ttM4 -BottomTrim $btM4
                                                $result = Invoke-PythonCropGuiMargins -WorkTrimSplitPy $workTrimSplitPy -ImagePath $splitPathM4 -RightBinding $RightBinding -LeftTrim $ltM4 -TopTrim $vertMtM4.TopTrimPx -RightTrim $rtM4 -BottomTrim $vertMtM4.BottomTrimPx
                                            } elseif ($ltM4 -gt 0 -or $rtM4 -gt 0 -or $ttM4 -gt 0 -or $btM4 -gt 0) {
                                                Write-FlickFitHost "         [余白・ノド] のど=${gutterX}px 左=${ltM4}px 右=${rtM4}px 上=${ttM4}px 下=${btM4}px (メニュー[4]→Python)" -ForegroundColor DarkCyan
                                                $cohM4 = Repair-GutterMarginGeometry -ImgW $nextW -GutterX $gutterX -LeftTrim $ltM4 -RightTrim $rtM4
                                                $gutterX = $cohM4.GutterX; $ltM4 = $cohM4.LeftTrimPx; $rtM4 = $cohM4.RightTrimPx
                                                $vertM4 = Repair-GutterVerticalMargins -ImgH $nextH -TopTrim $ttM4 -BottomTrim $btM4
                                                $ttM4 = $vertM4.TopTrimPx; $btM4 = $vertM4.BottomTrimPx
                                                $output = @(& $script:PythonExe $workTrimSplitPy $splitPathM4 $RightBinding.ToString() "split_at_gutter_with_margins" "-" $gutterX $ltM4 $rtM4 $aspectMin $cw2Manual $ttM4 $btM4 2>&1 | ForEach-Object { "$_" })
                                                $result = $output -join ""
                                            } else {
                                                $output = @(& $script:PythonExe $workTrimSplitPy $splitPathM4 $RightBinding.ToString() "split_at_gutter" "false" $gutterX $aspectMin $cw2Manual "false" "true" 2>&1 | ForEach-Object { "$_" })
                                                $result = $output -join ""
                                            }
                                            Write-FlickFitPythonDebugLines -Lines @($output)
                                        } catch { $result = "ERROR:$($_.Exception.Message)" }
                                        if ($result -match "TRIMMED:1" -and (Get-HashtableBool -Tbl $guiM4 -Key 'MarginTrimWithoutSplit')) {
                                            Write-FlickFitHost "         ✅ 余白のみトリミングしました（1枚のまま、以降同サイズは自動適用）" -ForegroundColor DarkGreen
                                            $folderSplit += 1
                                            $splitImages += 1
                                            if ($null -ne $vertMtM4) { $ttM4 = $vertMtM4.TopTrimPx; $btM4 = $vertMtM4.BottomTrimPx }
                                            $refAsp = 0
                                            $refW = 0
                                            if (Test-Path -LiteralPath $splitPathM4) {
                                                $dRefTM4 = Get-ImageDimensions -Path $splitPathM4
                                                if ($dRefTM4.Width -gt 0 -and $dRefTM4.Height -gt 0) { $refAsp = $dRefTM4.Width / $dRefTM4.Height; $refW = $dRefTM4.Width }
                                            }
                                            $ucsM4 = $true
                                            $skipCacheM4a = (Get-Variable -Name SplitWidthApplyGutterOnlyThisPage -Scope Script -ErrorAction SilentlyContinue) -and $script:SplitWidthApplyGutterOnlyThisPage
                                            if ($skipCacheM4a) { $script:SplitWidthApplyGutterOnlyThisPage = $false } else {
                                                $script:FolderGutterCache[$dir] = New-FlickFitFolderGutterCacheEntry -GutterX $gutterX -GutterPct 50.0 -LeftTrimPx $ltM4 -RightTrimPx $rtM4 -TopTrimPx $ttM4 -BottomTrimPx $btM4 -ImgW $nextW -ImgH $nextH -RefAspect $refAsp -RefWidth $refW -MarginTrimWithoutSplit $ucsM4
                                            }
                                        } elseif ($result -match "SPLIT:2") {
                                            Write-FlickFitHost "         ✅ のど位置を手動設定して2ページに分割（以降、同サイズ画像は自動適用）" -ForegroundColor DarkGreen
                                            $folderSplit += 2
                                            $splitImages += 2
                                            $so1 = Join-Path (Get-LiteralPathParent $splitPathM4) ([System.IO.Path]::GetFileNameWithoutExtension($splitPathM4) + "_1" + [System.IO.Path]::GetExtension($splitPathM4))
                                            try {
                                                Add-FlickFitGuiSplitTrustOutputs -GuiSplitTrustSet $guiSplitTrustNorm -SplitBasePath $splitPathM4
                                            } catch {
                                                Write-FlickFitHost "         [警告] 分割片の信頼リスト登録に失敗（処理は続行）: $($_.Exception.Message)" -ForegroundColor DarkYellow
                                            }
                                            if ($folderCoverWidth -le 0 -and (Test-Path -LiteralPath $so1)) {
                                                $dd = Get-ImageDimensions -Path $so1
                                                if ($dd.Width -gt 0) { $folderCoverWidth = $dd.Width }
                                            }
                                            $refAsp = 0
                                            $refW = 0
                                            if (Test-Path -LiteralPath $so1) {
                                                $dRef = Get-ImageDimensions -Path $so1
                                                if ($dRef.Width -gt 0 -and $dRef.Height -gt 0) { $refAsp = $dRef.Width / $dRef.Height; $refW = $dRef.Width }
                                            }
                                            $gp8318 = 50.0
                                            if ($null -ne $guiM4 -and $guiM4 -is [System.Collections.IDictionary]) {
                                                foreach ($gk in @($guiM4.Keys)) {
                                                    if ([string]::Equals([string]$gk, 'GutterPct', [StringComparison]::OrdinalIgnoreCase)) {
                                                        try { $gp8318 = [Math]::Max(1, [Math]::Min(99, [double]$guiM4[$gk])); break } catch {}
                                                    }
                                                }
                                            }
                                            if ($gp8318 -eq 50.0 -and $nextW -gt 0) { $gp8318 = [Math]::Round(100.0 * $gutterX / $nextW, 2) }
                                            $ucsM4 = Get-HashtableBool -Tbl $guiM4 -Key 'MarginTrimWithoutSplit'
                                            $skipCacheM4b = (Get-Variable -Name SplitWidthApplyGutterOnlyThisPage -Scope Script -ErrorAction SilentlyContinue) -and $script:SplitWidthApplyGutterOnlyThisPage
                                            if ($skipCacheM4b) { $script:SplitWidthApplyGutterOnlyThisPage = $false } else {
                                                $script:FolderGutterCache[$dir] = New-FlickFitFolderGutterCacheEntry -GutterX $gutterX -GutterPct $gp8318 -LeftTrimPx $ltM4 -RightTrimPx $rtM4 -TopTrimPx $ttM4 -BottomTrimPx $btM4 -ImgW $nextW -ImgH $nextH -RefAspect $refAsp -RefWidth $refW -MarginTrimWithoutSplit $ucsM4
                                            }
                                            $sizeKeyM4 = "$($dir)|${nextW}x${nextH}"
                                            if (($ltM4 -gt 0 -or $rtM4 -gt 0 -or $ttM4 -gt 0 -or $btM4 -gt 0) -and -not $ucsM4 -and -not $script:FolderMarginMode.ContainsKey($sizeKeyM4)) {
                                                $script:FolderMarginMode[$sizeKeyM4] = 'gui'
                                            }
                                        } else {
                                            Write-FlickFitHost "         ⚠ 分割/トリム処理: $result" -ForegroundColor Yellow
                                        }
                                        $processedImages++
                                        $imgs = @(Get-ProcessableFolderImages -FolderPath $dir)
                                        $coverLoopImgsRefreshed = $true
                                        $coverResumeAfterM4 = 1
                                        if ($result -match "SPLIT:2") { $coverResumeAfterM4 = 2 }
                                        $guiEntryKeyM4 = $null
                                        $actualSplitKeyM4 = $null
                                        try { $guiEntryKeyM4 = Get-FlickFitStep5PathKey $spreadGuiEntryPathM4 } catch { }
                                        try { $actualSplitKeyM4 = Get-FlickFitStep5PathKey $splitPathM4 } catch { }
                                        if ($guiEntryKeyM4 -and $actualSplitKeyM4 -and ($guiEntryKeyM4 -ne $actualSplitKeyM4)) {
                                            $idxResumeM4 = Get-FlickFitCoverLoopIndexForPath -Images $imgs -FullPath $spreadGuiEntryPathM4
                                            if ($idxResumeM4 -ge 0) {
                                                $coverCheckIdx = $idxResumeM4
                                                if ($true -eq $script:FlickFitDebugStep5Verbose) {
                                                    Write-FlickFitHost "         [IDX-DBG] menu[4] entry=$(Split-Path -Leaf $spreadGuiEntryPathM4) actual=$(Split-Path -Leaf $splitPathM4) → coverCheckIdx=$coverCheckIdx (resume entry)" -ForegroundColor DarkGray
                                                }
                                            } else {
                                                $resolvedCcM4 = Get-FlickFitNextCoverLoopIndexAfterSpreadOp -Images $imgs -ProcessedSourcePath $splitPathM4 -PythonResult $result
                                                if ($null -ne $resolvedCcM4) { $coverCheckIdx = $resolvedCcM4 } else { $coverCheckIdx = $nextIdx + $coverResumeAfterM4 }
                                            }
                                        } else {
                                            $resolvedCcM4 = Get-FlickFitNextCoverLoopIndexAfterSpreadOp -Images $imgs -ProcessedSourcePath $splitPathM4 -PythonResult $result
                                            if ($null -ne $resolvedCcM4) {
                                                $coverCheckIdx = $resolvedCcM4
                                            } else {
                                                $coverCheckIdx = $nextIdx + $coverResumeAfterM4
                                            }
                                        }
                                        break
                                    } else {
                                        Write-FlickFitHost "         （キャンセル）" -ForegroundColor Gray
                                    }
                                }
                                }
                                # 3: スキップ（何もしない、breakでループ抜け）
                            }
                        }
                        # ループ終了前に一時ファイルを削除
                        if (Test-Path -LiteralPath $tmpCoverPreview) { Remove-Item -LiteralPath $tmpCoverPreview -Force -ErrorAction SilentlyContinue }
                        break
                        
                    } catch {
                        if ($_.Exception.Message -match '^中断:') { throw }
                        Write-FlickFitHost "         ❌ エラー: $($_.Exception.Message)" -ForegroundColor Red
                        $processedImages++
                        break
                    }
                }
                # ループ終了後、スキップした画像が残っていれば削除確認
                if ($skippedPrevImages.Count -gt 0) {
                    $skippedNames = ($skippedPrevImages | ForEach-Object { Split-Path $_ -Leaf }) -join ", "
                    Write-FlickFitHost "`n         📎 確認せずにスキップした画像: $skippedNames" -ForegroundColor Yellow
                    Write-FlickFitHost "         [D] 削除  [Enter] 残す" -ForegroundColor DarkGray
                    $delPrev = Read-HostWithEsc "         [スキップ画像]"
                    if ($delPrev -match '^[dD]$') {
                        foreach ($sp in $skippedPrevImages) {
                            $spDeleted = $false
                            for ($spRetry = 0; $spRetry -lt 5; $spRetry++) {
                                try {
                                    [System.GC]::Collect()
                                    [System.GC]::WaitForPendingFinalizers()
                                    Start-Sleep -Milliseconds 300
                                    if (Test-Path -LiteralPath $sp) {
                                        Remove-Item -LiteralPath $sp -Force -ErrorAction Stop
                                    }
                                    if (-not (Test-Path -LiteralPath $sp)) {
                                        $spDeleted = $true
                                        break
                                    }
                                } catch {
                                    if ($spRetry -lt 4) { Start-Sleep -Milliseconds 500 }
                                }
                            }
                            if ($spDeleted) {
                                Write-FlickFitHost "         🗑 削除: $(Get-LiteralPathLeaf $sp)" -ForegroundColor Yellow
                            } else {
                                Write-FlickFitHost "         ⚠ 削除失敗: $(Get-LiteralPathLeaf $sp)" -ForegroundColor Red
                            }
                            $imgs = @($imgs | Where-Object { $_.FullName -ne $sp })
                        }
                    }
                    $skippedPrevImages.Clear()
                }
                # 処理済み画像をスキップ（coverCheckIdx の次から再開）
                # 2ページ目分割で$imgsを再取得した場合、リストから削除分が詰まるため imgIdx=coverCheckIdx（+1しない）
                if ($null -ne $coverWhileExitImgIdxOverride) {
                    $imgs = @(Get-ProcessableFolderImages -FolderPath $dir)
                    $ixExit = [int]$coverWhileExitImgIdxOverride
                    if ($ixExit -lt 0) { $ixExit = 0 }
                    if ($imgs.Count -gt 0 -and $ixExit -ge $imgs.Count) { $ixExit = $imgs.Count - 1 }
                    $imgIdx = $ixExit
                    $coverWhileExitImgIdxOverride = $null
                } elseif ($coverLoopImgsRefreshed) {
                    $imgIdx = $coverCheckIdx
                } else {
                    $imgIdx = $coverCheckIdx + 1
                }
                continue
            }
            
            if (-not (Test-IsLandscapeAspectForSpread -Aspect $aspect -Threshold $AspectThreshold)) {
                $ciTrustNorm = $null
                try { $ciTrustNorm = [System.IO.Path]::GetFullPath($ci.FullName).TrimEnd('\') } catch { $ciTrustNorm = $ci.FullName.TrimEnd('\') }
                if ($guiSplitTrustNorm.Contains($ciTrustNorm)) {
                    Write-FlickFitHost "      ✓ $imgName （GUI／キャッシュ分割の片ページ・異物判定・自動トリムをスキップ）" -ForegroundColor DarkGray
                    $folderConsecutiveOutlierDeletes = 0
                    $folderKeptAsIs++
                    $processedImages++
                    $imgIdx++
                    continue
                }
                $isOutlier = $false
                # 1ページ想定の縦横比以上（aspectMin以上）の縦長ページは正規ページとして扱い、異物判定しない
                if (-not ($aspectMin -gt 0 -and $aspect -ge $aspectMin)) {
                    if ($medianAspect -gt 0) {
                        $aspectDiff = [Math]::Abs($aspect - $medianAspect)
                        $isSmall = ($medianSize -gt 0 -and $ci.Length -lt [Math]::Max($medianSize * $sizeSmallRatio, $sizeSmallAbs))
                        if ($aspectDiff -gt $aspectDiffThreshold -and $isSmall) { $isOutlier = $true }
                    }
                }
                if ($isOutlier) {
                    if ($folderAutoDeleteOutlier) {
                        Write-FlickFitHost "      🗑 $imgName (異物・自動削除: 縦長 $([math]::Round($aspect, 2)), 他と相違)" -ForegroundColor Yellow
                        if (-not $DryRun) { Remove-Item -LiteralPath $ci.FullName -Force -ErrorAction SilentlyContinue }
                        $folderProblemSkipped++
                        $skippedImages++
                        $processedImages++
                    } else {
                        Write-FlickFitHost "      ⚠ $imgName (異物候補: 縦長 $([math]::Round($aspect, 2)), 他と相違・小サイズ)" -ForegroundColor Yellow
                        Write-FlickFitHost "         [画像を表示しています...]" -ForegroundColor Gray
                        try {
                            Invoke-PhotosOpen -ImagePath $ci.FullName
                        } catch {
                            try { Start-Process $ci.FullName } catch { Write-FlickFitHost "         ⚠ 画像表示エラー" -ForegroundColor Yellow }
                        }
                        $ans = Read-HostWithEsc "         [D] 削除  [S] スキップ (空Enter=スキップ)"
                        if (($ans -eq 'D' -or $ans -eq 'd')) {
                            if (-not $DryRun) { Remove-Item -LiteralPath $ci.FullName -Force -ErrorAction SilentlyContinue }
                            $folderConsecutiveOutlierDeletes++
                            if ($folderConsecutiveOutlierDeletes -ge 2) { $folderAutoDeleteOutlier = $true; Write-FlickFitHost "         → 以降は自動削除します" -ForegroundColor DarkCyan }
                            Write-FlickFitHost "         🗑 削除しました" -ForegroundColor Yellow
                            $folderProblemSkipped++
                        } else {
                            $folderConsecutiveOutlierDeletes = 0
                            Write-FlickFitHost "         ⏭ スキップ" -ForegroundColor DarkGray
                            $folderKeptAsIs++
                        }
                        $skippedImages++
                        $processedImages++
                    }
                } else {
                    # 表紙アスペクトとの差が大きい縦長のみ余白トリミングを試行（差が小さい場合はスキップで高速化）
                    $aspectDiffFromRef = [Math]::Abs($aspect - $aspectRef)
                    # 単ページトリムの基準幅を決定（表紙幅が単ページ基準より著しく小さい場合は補正）
                    $effectiveCoverWidth = $folderCoverWidth
                    if ($folderTypicalSingleWidth -gt 0) {
                        if ($folderCoverWidth -le 0) {
                            $effectiveCoverWidth = $folderTypicalSingleWidth
                        } elseif ($folderCoverWidth -lt [int]($folderTypicalSingleWidth * 0.75)) {
                            Write-FlickFitHost "         [幅補正] 表紙幅 ${folderCoverWidth}px < 単ページ基準幅 ${folderTypicalSingleWidth}px の75% → 単ページ基準幅を採用" -ForegroundColor Yellow
                            $effectiveCoverWidth = $folderTypicalSingleWidth
                        }
                    }
                    $doSingleTrim = ($aspectDiffFromRef -gt 0.05) -and ($effectiveCoverWidth -gt 0) -and $script:PythonExe -and (-not $DryRun)
                    if ($doSingleTrim) {
                        try {
                            $trimRes = (Invoke-PythonTimed -Category "PythonTrim" -PythonArgs $workTrimSplitPy, $ci.FullName, $RightBinding.ToString(), "trim_single_safe", "", $aspectMin, $effectiveCoverWidth) -join ""
                            if ($trimRes -match "TRIMMED:1") {
                                Write-FlickFitHost "      ✂ $imgName (縦長・余白トリミング)" -ForegroundColor DarkCyan
                                $folderSplit++
                                $splitImages++
                            } else {
                                if ($true -eq $script:FlickFitDebugStep5Verbose) {
                                    Write-FlickFitHost "      ⏭ $imgName (縦長: $([math]::Round($aspect, 2)))" -ForegroundColor DarkGray
                                } else { $folderPortraitKeptSilentCount++ }
                                $folderKeptAsIs++
                                $skippedImages++
                            }
                        } catch {
                            if ($true -eq $script:FlickFitDebugStep5Verbose) {
                                Write-FlickFitHost "      ⏭ $imgName (縦長: $([math]::Round($aspect, 2)))" -ForegroundColor DarkGray
                            } else { $folderPortraitKeptSilentCount++ }
                            $folderKeptAsIs++
                            $skippedImages++
                        }
                    } else {
                        if ($true -eq $script:FlickFitDebugStep5Verbose) {
                            Write-FlickFitHost "      ⏭ $imgName (縦長: $([math]::Round($aspect, 2)))" -ForegroundColor DarkGray
                        } else { $folderPortraitKeptSilentCount++ }
                        $folderKeptAsIs++
                        $skippedImages++
                    }
                    $folderConsecutiveOutlierDeletes = 0
                    $processedImages++
                }
                $imgIdx++
                continue 
            }
            
            Write-FlickFitHost "      ⏳ $imgName (横長: $([math]::Round($aspect, 2)))" -ForegroundColor Gray
            
            if ($DryRun) {
                Write-FlickFitHost "         [DRY RUN]" -ForegroundColor Yellow
                $processedImages++
                $imgIdx++
                continue
            }
            
            try {
                $ext = $ci.Extension.ToLower()
                $origPath = $ci.FullName
                $entryPathStep5 = [string]$origPath
                $entryNameStep5 = $imgName
                # GUI 後の Python/幾何が ERROR のとき、同じ $imgIdx を再試行する（飛ばし防止）
                $Step5SkipIdxInc = $false
                Write-FlickFitStep5EntryDebug -Label 'horiz-iter' -EntryPath $entryPathStep5 -PreviewPath $entryPathStep5 -ApplyPath $origPath -ImgIdx $imgIdx -ImgsCount $imgs.Count
                
                # AVIF 高速パス: 処理を省略して1枚としてカウント
                if ($script:SkipAVIF -and $ext -eq '.avif') {
                    Write-FlickFitHost "         ✅ AVIF（高速パス: 処理省略）" -ForegroundColor Green
                    $folderAvifOmit++
                    $folderSplit += 1
                    $splitImages += 1
                    $processedImages++
                    $imgIdx++
                    continue
                }
                
                # 2枚目以降の横長＝見開き処理（表紙は先頭で処理済み）
                # 表紙確定後、最初に出てくる見開き（横長）で1回だけGUIを出す（2ページ目が縦長でも取りこぼさないため）
                if (-not (Get-Variable -Name PostCoverSpreadGuiDone -Scope Script -ErrorAction SilentlyContinue)) { $script:PostCoverSpreadGuiDone = @{} }
                $needGuiOnceHere = $false
                try {
                    if ((Get-Variable -Name PostCoverConfirmed -Scope Script -ErrorAction SilentlyContinue) -and $script:PostCoverConfirmed.ContainsKey($dir) -and $script:PostCoverConfirmed[$dir]) {
                        if (-not ($script:PostCoverSpreadGuiDone.ContainsKey($dir) -and $script:PostCoverSpreadGuiDone[$dir])) { $needGuiOnceHere = $true }
                    }
                } catch { $needGuiOnceHere = $false }
                if ($needGuiOnceHere) {
                    Write-FlickFitHost "`n         📎 表紙確定後の最初の見開き: $imgName → 1回だけGUIでノド/余白を決めます（以降は自動）" -ForegroundColor Cyan
                    try {
                        $gutterEntryPc = [string]$entryPathStep5
                        $allPathsPc = @($imgs | ForEach-Object { $_.FullName })
                        Write-FlickFitStep5EntryDebug -Label 'pc-before' -EntryPath $entryPathStep5 -PreviewPath $entryPathStep5 -ApplyPath $origPath -ImgIdx $imgIdx -ImgsCount $imgs.Count
                        $guiPc = Show-GutterMarginSetGui -ImagePath $entryPathStep5 -Title "表紙後の最初の見開き: ノドと左右余白の設定 - ここで分割します" -AllImagePaths $allPathsPc -OkAppliesToCurrentView -ShowApplyThisPageOnlyButton
                        if ($guiPc -is [System.Collections.IDictionary]) { $guiPc = Normalize-GutterGuiResult -GuiResult $guiPc }
                        $imgs = Update-ImgsAfterMarginGui -Imgs $imgs -GuiResult $guiPc
                        if (Test-GuiMarginFlagTrue -Tbl $guiPc -Key 'ApplyOnlyThisSpread') {
                            $script:SplitWidthApplyGutterOnlyThisPage = $true
                        }
                        $pcDeletedPaths = [System.Collections.Generic.List[string]]::new()
                        if ($null -ne $guiPc -and $guiPc -is [System.Collections.IDictionary] -and $guiPc.ContainsKey('DeletedImagePaths')) {
                            foreach ($gd in @($guiPc['DeletedImagePaths'])) {
                                $gs = [string]$gd
                                if (-not [string]::IsNullOrWhiteSpace($gs)) { [void]$pcDeletedPaths.Add($gs) }
                            }
                        }
                        $hadPcSessionDeletes = ($pcDeletedPaths.Count -gt 0)
                        if (Test-GuiMarginFlagTrue -Tbl $guiPc -Key 'DeleteImage') {
                            Write-FlickFitHost "         ↩ GUI削除を反映しました。一覧を更新し、次の画像から再評価します" -ForegroundColor DarkGray
                            $imgs = @(Get-ProcessableFolderImages -FolderPath $dir)
                            if ($imgIdx -ge $imgs.Count) { $imgIdx = $imgs.Count; continue }
                            continue
                        }
                        if ($hadPcSessionDeletes) {
                            Write-FlickFitHost "         ↩ GUIで画像を削除したため、このセッションの余白・分割結果は適用せず、一覧を更新して次の画像から再評価します" -ForegroundColor DarkGray
                            $imgs = @(Get-ProcessableFolderImages -FolderPath $dir)
                            if ($imgIdx -ge $imgs.Count) { $imgIdx = $imgs.Count; continue }
                            continue
                        }
                        $navPc = Get-FlickFitGutterEntryAfterNavGui -EntryPath $entryPathStep5 -EntryName $entryNameStep5 -GuiResult $guiPc
                        if ($null -ne $navPc) { $origPath = $navPc.OrigPath; $imgName = $navPc.ImgName; $ext = $navPc.Ext }
                        Write-FlickFitStep5EntryDebug -Label 'pc-after' -EntryPath $entryPathStep5 -GuiResult $guiPc -ApplyPath $origPath -ImgIdx $imgIdx -ImgsCount $imgs.Count
                        if (Test-GuiMarginFlagTrue -Tbl $guiPc -Key 'PhotosEdit') {
                            $dPhPc = Get-ImageDimensions -Path $origPath
                            if ($dPhPc.Width -gt 0) { $folderCoverWidth = $dPhPc.Width }
                            Write-FlickFitHost "         ✅ フォトで編集した画像を採用（以降のトリミング基準に使用）" -ForegroundColor Green
                            $folderSplit += 1
                            $splitImages += 1
                            $processedImages++
                            $imgs = @(Get-ProcessableFolderImages -FolderPath $dir)
                            $script:PostCoverSpreadGuiDone[$dir] = $true
                            $imgIdx++
                            continue
                        }
                        $lockPc = Get-FlickFitGutterGuiSplitPathLockedToEntry -EntryPath $gutterEntryPc -GuiResult $guiPc
                        if ($lockPc.Scaled) { $guiPc = $lockPc.GuiTweak }
                        $splitPathPc = $lockPc.Path
                        if ($null -ne $gutterEntryPc -and -not [string]::Equals($origPath, $splitPathPc, [StringComparison]::OrdinalIgnoreCase)) {
                            $origPath = $splitPathPc
                            $imgName = [System.IO.Path]::GetFileName($origPath)
                            $ext = [System.IO.Path]::GetExtension($origPath).ToLower()
                        }
                        $dPc = Get-ImageDimensions -Path $splitPathPc
                        if ($dPc.Width -gt 0 -and $dPc.Height -gt 0) { $origWpc = $dPc.Width; $origHpc = $dPc.Height } else { $origWpc = 0; $origHpc = 0 }
                        $gutterXPc = $null
                        $ltPc = 0; $rtPc = 0; $ttPc = 0; $btPc = 0
                        if ($null -ne $guiPc) {
                            $gxPc = Get-HashtableInt -Tbl $guiPc -Key 'GutterX' -Default (-1)
                            if ($gxPc -ge 0) {
                                $gutterXPc = $gxPc
                                $ltPc = Get-HashtableInt -Tbl $guiPc -Key 'LeftTrimPx'
                                $rtPc = Get-HashtableInt -Tbl $guiPc -Key 'RightTrimPx'
                                $ttPc = Get-HashtableInt -Tbl $guiPc -Key 'TopTrimPx'
                                $btPc = Get-HashtableInt -Tbl $guiPc -Key 'BottomTrimPx'
                            }
                        }
                        if ($null -ne $gutterXPc -and $gutterXPc -ge 0) {
                            $cwPc = $folderCoverWidth
                            if ($cwPc -le 0) {
                                $dCw = Get-ImageDimensions -Path $splitPathPc
                                if ($dCw.Width -gt 0) { $cwPc = [Math]::Floor($dCw.Width / 2) }
                            }
                            try {
                                $mtOnlyPc = Get-HashtableBool -Tbl $guiPc -Key 'MarginTrimWithoutSplit'
                                $outputPc = @()
                                if ($mtOnlyPc) {
                                    Write-FlickFitHost "         [余白のみ・分割なし] 左=${ltPc}px 右=${rtPc}px 上=${ttPc}px 下=${btPc}px (表紙後初回GUI→Python)" -ForegroundColor DarkCyan
                                    $vertMtPc = Repair-GutterVerticalMargins -ImgH $origHpc -TopTrim $ttPc -BottomTrim $btPc
                                    $resultPc = Invoke-PythonCropGuiMargins -WorkTrimSplitPy $workTrimSplitPy -ImagePath $splitPathPc -RightBinding $RightBinding -LeftTrim $ltPc -TopTrim $vertMtPc.TopTrimPx -RightTrim $rtPc -BottomTrim $vertMtPc.BottomTrimPx
                                } elseif ($ltPc -gt 0 -or $rtPc -gt 0 -or $ttPc -gt 0 -or $btPc -gt 0) {
                                    Write-FlickFitHost "         [余白・ノド] のど=${gutterXPc}px 左=${ltPc}px 右=${rtPc}px 上=${ttPc}px 下=${btPc}px (表紙後初回GUI→Python)" -ForegroundColor DarkCyan
                                    $cohPc = Repair-GutterMarginGeometry -ImgW $origWpc -GutterX $gutterXPc -LeftTrim $ltPc -RightTrim $rtPc
                                    $gutterXPc = $cohPc.GutterX; $ltPc = $cohPc.LeftTrimPx; $rtPc = $cohPc.RightTrimPx
                                    $vertPc = Repair-GutterVerticalMargins -ImgH $origHpc -TopTrim $ttPc -BottomTrim $btPc
                                    $ttPc = $vertPc.TopTrimPx; $btPc = $vertPc.BottomTrimPx
                                    $outputPc = @(& $script:PythonExe $workTrimSplitPy $splitPathPc $RightBinding.ToString() "split_at_gutter_with_margins" "-" $gutterXPc $ltPc $rtPc $aspectMin $cwPc $ttPc $btPc 2>&1 | ForEach-Object { "$_" })
                                    $resultPc = $outputPc -join ""
                                } else {
                                    $outputPc = @(& $script:PythonExe $workTrimSplitPy $splitPathPc $RightBinding.ToString() "split_at_gutter" "false" $gutterXPc $aspectMin $cwPc "false" "true" 2>&1 | ForEach-Object { "$_" })
                                    $resultPc = $outputPc -join ""
                                }
                                Write-FlickFitPythonDebugLines -Lines @($outputPc)
                            } catch { $resultPc = "ERROR:$($_.Exception.Message)" }
                            if ($resultPc -match "TRIMMED:1" -and (Get-HashtableBool -Tbl $guiPc -Key 'MarginTrimWithoutSplit')) {
                                Write-FlickFitHost "         ✅ 余白のみトリミングしました（1枚のまま、以降同サイズは自動適用）" -ForegroundColor DarkGreen
                                $folderSplit += 1; $splitImages += 1
                                if ($null -ne $vertMtPc) { $ttPc = $vertMtPc.TopTrimPx; $btPc = $vertMtPc.BottomTrimPx }
                                $skipCachePcA = (Get-Variable -Name SplitWidthApplyGutterOnlyThisPage -Scope Script -ErrorAction SilentlyContinue) -and $script:SplitWidthApplyGutterOnlyThisPage
                                if ($skipCachePcA) { $script:SplitWidthApplyGutterOnlyThisPage = $false } else {
                                    $script:FolderGutterCache[$dir] = New-FlickFitFolderGutterCacheEntry -GutterX $gutterXPc -GutterPct 50.0 -LeftTrimPx $ltPc -RightTrimPx $rtPc -TopTrimPx $ttPc -BottomTrimPx $btPc -ImgW $origWpc -ImgH $origHpc -RefAspect 0 -RefWidth 0 -MarginTrimWithoutSplit $true
                                }
                            } elseif ($resultPc -match "SPLIT:2") {
                                Write-FlickFitHost "         ✅ のど位置を手動設定して2ページに分割（以降、同サイズ画像は自動適用）" -ForegroundColor DarkGreen
                                $folderSplit += 2; $splitImages += 2
                                try {
                                    Add-FlickFitGuiSplitTrustOutputs -GuiSplitTrustSet $guiSplitTrustNorm -SplitBasePath $splitPathPc
                                } catch {
                                    Write-FlickFitHost "         [警告] 分割片の信頼リスト登録に失敗（処理は続行）: $($_.Exception.Message)" -ForegroundColor DarkYellow
                                }
                                $gpPc = 50.0
                                if ($null -ne $guiPc -and $guiPc -is [System.Collections.IDictionary]) {
                                    foreach ($gk in @($guiPc.Keys)) {
                                        if ([string]::Equals([string]$gk, 'GutterPct', [StringComparison]::OrdinalIgnoreCase)) {
                                            try { $gpPc = [Math]::Max(1, [Math]::Min(99, [double]$guiPc[$gk])); break } catch {}
                                        }
                                    }
                                }
                                if ($gpPc -eq 50.0 -and $origWpc -gt 0) { $gpPc = [Math]::Round(100.0 * $gutterXPc / $origWpc, 2) }
                                $ucsPc = Get-HashtableBool -Tbl $guiPc -Key 'MarginTrimWithoutSplit'
                                $skipCachePcB = (Get-Variable -Name SplitWidthApplyGutterOnlyThisPage -Scope Script -ErrorAction SilentlyContinue) -and $script:SplitWidthApplyGutterOnlyThisPage
                                if ($skipCachePcB) { $script:SplitWidthApplyGutterOnlyThisPage = $false } else {
                                    $script:FolderGutterCache[$dir] = New-FlickFitFolderGutterCacheEntry -GutterX $gutterXPc -GutterPct $gpPc -LeftTrimPx $ltPc -RightTrimPx $rtPc -TopTrimPx $ttPc -BottomTrimPx $btPc -ImgW $origWpc -ImgH $origHpc -RefAspect 0 -RefWidth 0 -MarginTrimWithoutSplit $ucsPc
                                }
                            } else {
                                Write-FlickFitHost "         ⚠ 分割/トリム処理: $resultPc" -ForegroundColor Yellow
                            }
                            $processedImages++
                            $imgs = @(Get-ProcessableFolderImages -FolderPath $dir)
                            $script:PostCoverSpreadGuiDone[$dir] = $true
                            if ($resultPc -match "SPLIT:2") {
                                $imgIdx += 2
                            } else {
                                $imgIdx++
                            }
                            continue
                        } else {
                            Write-FlickFitHost "         （GUIキャンセル）通常の自動処理で続行します" -ForegroundColor Gray
                            $script:PostCoverSpreadGuiDone[$dir] = $true
                            # GUI内で削除された場合はスキップ（FileNotFoundError 防止）
                            if (-not (Test-Path -LiteralPath $origPath)) {
                                Write-FlickFitHost "         ↩ 削除済みのためスキップします: $imgName" -ForegroundColor DarkGray
                                $processedImages++
                                continue
                            }
                        }
                    } catch {
                        Write-FlickFitHost "         ⚠ 表紙後初回GUIでエラー: $($_.Exception.Message)" -ForegroundColor Yellow
                        $script:PostCoverSpreadGuiDone[$dir] = $true
                    }
                }
                    $useTocTrim = $folderTocPaths.ContainsKey($origPath)
                    $splitMode = if ($useTocTrim) { "trim_toc_split" } else { "split" }
                    if ($useTocTrim) {
                        Write-FlickFitHost "         📋 目次専用トリミング + 分割..." -ForegroundColor DarkCyan
                    }
                    # 片側のみコンテンツの見開きかどうかを先に判定（batch_analyze_seq で蓄積済みなら再起動しない）
                    $analyzeResult = ""
                    $normAn = $null
                    try { $normAn = [System.IO.Path]::GetFullPath($origPath) } catch { $normAn = $origPath }
                    if ($Step5OneSidedAnalyze -and $normAn -and $Step5OneSidedAnalyze.ContainsKey($normAn)) {
                        $analyzeResult = [string]$Step5OneSidedAnalyze[$normAn]
                    } else {
                        try {
                            $analyzeOut = Invoke-PythonTimed -Category "PythonAnalyze" -PythonArgs $workTrimSplitPy, $origPath, $RightBinding.ToString(), "analyze"
                            $analyzeResult = ($analyzeOut | ForEach-Object { "$_" }) -join "`n"
                            if ($normAn) { $Step5OneSidedAnalyze[$normAn] = $analyzeResult }
                            Write-FlickFitPythonDebugLines -Lines @($analyzeOut)
                        } catch {
                            $analyzeResult = "BALANCED"
                        }
                    }
                    
                    if ($analyzeResult -match "ONE_SIDED") {
                        $baseNoExt = [System.IO.Path]::GetFileNameWithoutExtension($origPath)
                        $previewDir = [System.IO.Path]::GetDirectoryName($origPath)
                        if ($folderAutoChoice) {
                            $choiceNames = @{ '1' = 'トリミング版'; '2' = '分割版'; '3' = '元のまま' }
                            Write-FlickFitHost "         ⚠ 片側コンテンツと検出 → 自動適用: $($choiceNames[$folderAutoChoice])" -ForegroundColor Yellow
                            if ($folderAutoChoice -eq '1') {
                                try {
                                    $trimOut = Invoke-PythonTimed -Category "PythonTrim" -PythonArgs $workTrimSplitPy, $origPath, $RightBinding.ToString(), "trim_only", "", $aspectMin
                                    Write-FlickFitHost "         ✅ トリミング版を採用しました（1枚）" -ForegroundColor DarkGreen
                                    Add-FlickFitRetrimCandidate -VolFolder $dir -FilePath $origPath -Reason 'trim_weak' -PageLabel $imgName
                                    $folderSplit += 1; $splitImages += 1
                                } catch {
                                    Write-FlickFitHost "         ⚠ トリミングエラー: $($_.Exception.Message)" -ForegroundColor Yellow
                                    $folderProblemSkipped++; $skippedImages++
                                }
                                $imgIdx++; continue
                            }
                            if ($folderAutoChoice -eq '3') {
                                Write-FlickFitHost "         ⏭ 元のまま保持しました" -ForegroundColor DarkGray
                                $folderKeptAsIs++; $skippedImages++; $imgIdx++; continue
                            }
                        }
                        $dOrigOs = Get-ImageDimensions -Path $origPath
                        $origW = $dOrigOs.Width
                        $origH = $dOrigOs.Height
                        <#
                          --- tempBackupOs 対応表（片側 ONE_SIDED）---
                          意味: このループ中に $origPath が上書き・削除されうるため、その直前の元画像コピー。
                                失敗時の復元元と、Invoke-SplitWidthValidation -BackupPath（見開き参照）に使う。

                          | 操作     | いつ・どこで |
                          |----------|--------------|
                          | 作る     | 直下 Join-Path + Copy-Item（cvr_retry_{元名}{ext}。cvr_* は走査対象外） |
                          | 持ち越す | 初回 Python 後もファイルとして残し、SPLIT:2 かつ条件成立時は検証へ BackupPath として渡す。gutter_reselect では orig を復元した後も再分割完了まで分岐内で温存し得る |
                          | 戻す     | Copy → $origPath … 余白のみトリム失敗、trim_only（分割片削除後→trim）、gutter_reselect 入口・再GUIキャンセル・再分割失敗など |
                          | 消す     | 初回GUI DeleteImage/PhotosEdit、余白のみ成功で continue、検証 delete、各成功経路・elseif フォールスルー、WinError32 リトライ後 等 |
                          最終網: フォルダ単位の cvr_* 一括削除（本スクリプト後段）。ここを頼りにしないよう分岐では基本 Remove する。
                        #>
                        # 旧: GUID 名だと再開のたびに新ファイルが増え、表紙などで目立つ。元名ベースで常に上書き（cvr_* は処理対象外）
                        $tempBackupOs = Join-Path (Get-LiteralPathParent $origPath) ("cvr_retry_" + $baseNoExt + $ext)
                        Copy-Item -LiteralPath $origPath -Destination $tempBackupOs -Force -ErrorAction SilentlyContinue
                        $cacheOs = $script:FolderGutterCache[$dir]
                        $cacheOsMt = if ($cacheOs) { Get-HashtableBool -Tbl $cacheOs -Key 'MarginTrimWithoutSplit' } else { $false }
                        $useCachedGutterOs = ($cacheOs -and $cacheOs.ImgW -eq $origW -and $cacheOs.ImgH -eq $origH -and (($cacheOs.GutterX -gt 0) -or $cacheOsMt))
                        if (-not $folderAutoChoice) {
                            if ($useCachedGutterOs) {
                                Write-FlickFitHost "         ⚠ 片側コンテンツと検出（他見開きと同じサイズ→同じ余白・のどで分割）" -ForegroundColor Yellow
                            } else {
                                Write-FlickFitHost "         ⚠ 片側コンテンツと検出（のど・余白を設定して分割）" -ForegroundColor Yellow
                            }
                        }
                        $cwOs = $folderCoverWidth
                        if ($cwOs -le 0 -and $imgs.Count -gt 0) {
                            $dOsC = Get-ImageDimensions -Path $imgs[0].FullName
                            if ($dOsC.Width -gt 0) {
                                $aFirst = Get-ImageAspect $imgs[0].FullName
                                $cwOs = if ($aFirst -lt 1) { $dOsC.Width } else { [Math]::Floor($dOsC.Width / 2) }
                                if ($folderCoverWidth -le 0) { $folderCoverWidth = $cwOs }
                                Write-FlickFitDebugStep5VerboseHost -Text "[DEBUG] 表紙幅未設定→先頭画像から $cwOs px を取得"
                            }
                        }
                        if ($cwOs -le 0) {
                            $dOs = Get-ImageDimensions -Path $origPath
                            if ($dOs.Width -gt 0) { $cwOs = [Math]::Floor($dOs.Width / 2); Write-FlickFitDebugStep5VerboseHost -Text "[DEBUG] 表紙幅未設定→元画像半分 $cwOs px をフォールバック" }
                        } else { Write-FlickFitDebugStep5VerboseHost -Text "[DEBUG] 表紙幅=$([int]$cwOs) px で分割・表紙比較を適用" -ForegroundColor DarkYellow }
                        if ($cwOs -le 0 -and $imgs.Count -gt 0) {
                            $dF = Get-ImageDimensions -Path $imgs[0].FullName
                            if ($dF.Width -gt 0) { $aF = Get-ImageAspect $imgs[0].FullName; $cwOs = if ($aF -lt 1) { $dF.Width } else { [Math]::Floor($dF.Width / 2) } }
                        }
                        $so1 = Join-Path (Get-LiteralPathParent $origPath) ($baseNoExt + "_1" + $ext)
                        $so2 = Join-Path (Get-LiteralPathParent $origPath) ($baseNoExt + "_2" + $ext)
                        $guiOs = $null
                        $gutterXOs = $null
                        $ltOs = 0
                        $rtOs = 0
                        $ttOs = 0
                        $btOs = 0
                        $gutterPctOsSav = $null
                        $ucsOsSave = $false
                        $osFreshGutterGuiUsed = $false
                        $gutterEntryOs = $null
                        if ($useCachedGutterOs) {
                            $ltOs = if ($cacheOs.ContainsKey('LeftTrimPx')) { [int]$cacheOs['LeftTrimPx'] } else { 0 }
                            $rtOs = if ($cacheOs.ContainsKey('RightTrimPx')) { [int]$cacheOs['RightTrimPx'] } else { 0 }
                            $ttOs = Get-HashtableInt -Tbl $cacheOs -Key 'TopTrimPx'
                            $btOs = Get-HashtableInt -Tbl $cacheOs -Key 'BottomTrimPx'
                            $cacheUcO = Get-HashtableBool -Tbl $cacheOs -Key 'MarginTrimWithoutSplit'
                            if ($cacheUcO) {
                                $gutterXOs = [Math]::Max(1, [Math]::Min($origW - 1, [int]($origW / 2)))
                                $gutterPctOsSav = 50.0
                                if ($ltOs -gt 0 -or $rtOs -gt 0 -or $ttOs -gt 0 -or $btOs -gt 0) {
                                    Write-FlickFitHost "         [キャッシュ] 片側: 余白のみトリム 左=${ltOs}px 右=${rtOs}px 上=${ttOs}px 下=${btOs}px（分割なし）" -ForegroundColor DarkCyan
                                }
                            } else {
                                $gxOldO = Get-HashtableInt -Tbl $cacheOs -Key 'GutterX'
                                $iwOldO = if ($cacheOs.ImgW -gt 0) { [int]$cacheOs.ImgW } else { $origW }
                                $gPctO = 50.0
                                $hasPctO = $false
                                foreach ($ck in @($cacheOs.Keys)) {
                                    if ([string]::Equals([string]$ck, 'GutterPct', [StringComparison]::OrdinalIgnoreCase)) {
                                        try { $gPctO = [Math]::Max(1, [Math]::Min(99, [double]$cacheOs[$ck])); $hasPctO = $true; break } catch {}
                                    }
                                }
                                if (-not $hasPctO) {
                                    if (($ltOs -gt 0 -or $rtOs -gt 0) -and $gxOldO -le ($ltOs + 8)) {
                                        $gPctO = 50.0
                                        Write-FlickFitHost "         [キャッシュ] 片側: 保存のど(${gxOldO}px)が左余白付近→50%で再計算" -ForegroundColor Yellow
                                    } else {
                                        $gPctO = [Math]::Max(1, [Math]::Min(99, 100.0 * $gxOldO / [double]$iwOldO))
                                    }
                                }
                                $gutterXOs = [int]([Math]::Round($origW * $gPctO / 100.0))
                                $gutterXOs = [Math]::Max(7, [Math]::Min($origW - 8, $gutterXOs))
                                $gutterPctOsSav = $gPctO
                                if ($ltOs -gt 0 -or $rtOs -gt 0 -or $ttOs -gt 0 -or $btOs -gt 0) {
                                    Write-FlickFitHost "         [キャッシュ] 片側: のど=${gutterXOs}px (${gPctO}%) 左=${ltOs}px 右=${rtOs}px 上=${ttOs}px 下=${btOs}px" -ForegroundColor DarkCyan
                                }
                            }
                        } else {
                            if (-not $folderAutoChoice) {
                                try {
                                    $gutterEntryOs = [string]$entryPathStep5
                                    $allPathsOs = @($imgs | ForEach-Object { $_.FullName })
                                    Write-FlickFitStep5EntryDebug -Label 'os-before' -EntryPath $entryPathStep5 -PreviewPath $entryPathStep5 -ApplyPath $origPath -ImgIdx $imgIdx -ImgsCount $imgs.Count
                                    $guiOs = Show-GutterMarginSetGui -ImagePath $entryPathStep5 -Title "片側コンテンツ: ノドと左右余白の設定 - ここで分割します" -AllImagePaths $allPathsOs -OkAppliesToCurrentView -ShowApplyThisPageOnlyButton
                                    if ($guiOs -is [System.Collections.IDictionary]) { $guiOs = Normalize-GutterGuiResult -GuiResult $guiOs }
                                    $imgs = Update-ImgsAfterMarginGui -Imgs $imgs -GuiResult $guiOs
                                    if (Test-GuiMarginFlagTrue -Tbl $guiOs -Key 'ApplyOnlyThisSpread') {
                                        $script:SplitWidthApplyGutterOnlyThisPage = $true
                                    }
                                    $navOs = Get-FlickFitGutterEntryAfterNavGui -EntryPath $entryPathStep5 -EntryName $entryNameStep5 -GuiResult $guiOs
                                    if ($null -ne $navOs) { $origPath = $navOs.OrigPath; $imgName = $navOs.ImgName; $ext = $navOs.Ext }
                                    Write-FlickFitStep5EntryDebug -Label 'os-after' -EntryPath $entryPathStep5 -GuiResult $guiOs -ApplyPath $origPath -ImgIdx $imgIdx -ImgsCount $imgs.Count
                                    if (Test-GuiMarginFlagTrue -Tbl $guiOs -Key 'DeleteImage') {
                                        if (Test-Path -LiteralPath $tempBackupOs) { Remove-Item -LiteralPath $tempBackupOs -Force -ErrorAction SilentlyContinue }
                                        if (Test-Path -LiteralPath $so1) { Remove-Item -LiteralPath $so1 -Force -ErrorAction SilentlyContinue }
                                        if (Test-Path -LiteralPath $so2) { Remove-Item -LiteralPath $so2 -Force -ErrorAction SilentlyContinue }
                                        $folderProblemSkipped++; $skippedImages++; $processedImages++; $imgIdx++; continue
                                    }
                                    if (Test-GuiMarginFlagTrue -Tbl $guiOs -Key 'PhotosEdit') {
                                        if (Test-Path -LiteralPath $tempBackupOs) { Remove-Item -LiteralPath $tempBackupOs -Force -ErrorAction SilentlyContinue }
                                        $dPhotoOs = Get-ImageDimensions -Path $origPath
                                        if ($dPhotoOs.Width -gt 0) { $folderCoverWidth = $dPhotoOs.Width }
                                        Write-FlickFitHost "         ✅ フォトで編集した画像を採用（以降のトリミング基準に使用）" -ForegroundColor Green
                                        $folderSplit += 1
                                        $splitImages += 1
                                        $processedImages++
                                        $imgIdx++
                                        continue
                                    }
                                    if ($null -ne $guiOs) {
                                        $ucsOsSave = Get-HashtableBool -Tbl $guiOs -Key 'MarginTrimWithoutSplit'
                                        $gxOsGui = Get-HashtableInt -Tbl $guiOs -Key 'GutterX' -Default (-1)
                                        if ($gxOsGui -ge 0) {
                                            $osFreshGutterGuiUsed = $true
                                            $gutterXOs = $gxOsGui
                                            $ltOs = Get-HashtableInt -Tbl $guiOs -Key 'LeftTrimPx'
                                            $rtOs = Get-HashtableInt -Tbl $guiOs -Key 'RightTrimPx'
                                            $ttOs = Get-HashtableInt -Tbl $guiOs -Key 'TopTrimPx'
                                            $btOs = Get-HashtableInt -Tbl $guiOs -Key 'BottomTrimPx'
                                            foreach ($gk in @($guiOs.Keys)) {
                                                if ([string]::Equals([string]$gk, 'GutterPct', [StringComparison]::OrdinalIgnoreCase)) {
                                                    try { $gutterPctOsSav = [Math]::Max(1, [Math]::Min(99, [double]$guiOs[$gk])); break } catch {}
                                                }
                                            }
                                        }
                                    }
                                } catch {
                                    Write-FlickFitHost "         （GUI未表示／キャンセル）" -ForegroundColor DarkGray
                                }
                            }
                            if ($null -eq $gutterXOs -or $gutterXOs -lt 0) {
                                $gutterXOs = [Math]::Floor($origW / 2)
                                $gutterPctOsSav = 50.0
                                Write-FlickFitDebugStep5VerboseHost -Text "[DEBUG] のど未設定→中央 $gutterXOs px で分割"
                            } elseif ($null -eq $gutterPctOsSav -and $origW -gt 0) {
                                $gutterPctOsSav = [Math]::Round(100.0 * $gutterXOs / $origW, 2)
                            }
                        }
                        $entOs = if ($null -ne $gutterEntryOs) { $gutterEntryOs } else { $entryPathStep5 }
                        $lockOsGui = Get-FlickFitGutterGuiSplitPathLockedToEntry -EntryPath $entOs -GuiResult $guiOs
                        if ($lockOsGui.Scaled -and $null -ne $lockOsGui.GuiTweak) {
                            $guiOs = $lockOsGui.GuiTweak
                            $ucsOsSave = Get-HashtableBool -Tbl $guiOs -Key 'MarginTrimWithoutSplit'
                            $gxOsGui2 = Get-HashtableInt -Tbl $guiOs -Key 'GutterX' -Default (-1)
                            if ($gxOsGui2 -ge 0) {
                                $gutterXOs = $gxOsGui2
                                $ltOs = Get-HashtableInt -Tbl $guiOs -Key 'LeftTrimPx'
                                $rtOs = Get-HashtableInt -Tbl $guiOs -Key 'RightTrimPx'
                                $ttOs = Get-HashtableInt -Tbl $guiOs -Key 'TopTrimPx'
                                $btOs = Get-HashtableInt -Tbl $guiOs -Key 'BottomTrimPx'
                                foreach ($gk in @($guiOs.Keys)) {
                                    if ([string]::Equals([string]$gk, 'GutterPct', [StringComparison]::OrdinalIgnoreCase)) {
                                        try { $gutterPctOsSav = [Math]::Max(1, [Math]::Min(99, [double]$guiOs[$gk])); break } catch {}
                                    }
                                }
                            }
                        }
                        $splitOrigOs = $lockOsGui.Path
                        if ($null -ne $entOs -and -not [string]::Equals($origPath, $splitOrigOs, [StringComparison]::OrdinalIgnoreCase)) {
                            $origPath = $splitOrigOs
                            $imgName = [System.IO.Path]::GetFileName($origPath)
                            $ext = [System.IO.Path]::GetExtension($origPath).ToLower()
                            $baseNoExt = [System.IO.Path]::GetFileNameWithoutExtension($origPath)
                            $dFixOs = Get-ImageDimensions -Path $origPath
                            if ($dFixOs.Width -gt 0 -and $dFixOs.Height -gt 0) { $origW = $dFixOs.Width; $origH = $dFixOs.Height }
                            $so1 = Join-Path (Get-LiteralPathParent $origPath) ($baseNoExt + "_1" + $ext)
                            $so2 = Join-Path (Get-LiteralPathParent $origPath) ($baseNoExt + "_2" + $ext)
                        }
                        $osMarginTrimOnly = ($useCachedGutterOs -and (Get-HashtableBool -Tbl $cacheOs -Key 'MarginTrimWithoutSplit')) -or $ucsOsSave
                        # 片側 ONE_SIDED: 実入力パスと寸法参照をこの try ブロック内で一致（Python 引数・ref 全幅・観測ログの基準）。ノド再選択サブブロックでは下で再同期する。
                        $iszEffOs = Get-FlickFitEffectiveInputSizePx -LiteralPath $splitOrigOs
                        $effectiveInputPathOs = [string]$splitOrigOs
                        $effectiveInputWidthOs = $iszEffOs.Width
                        $effectiveInputHeightOs = $iszEffOs.Height
                        try {
                            $env:PYTHONIOENCODING = "utf-8"
                            if ($osMarginTrimOnly) {
                                $vertOsMt = Repair-GutterVerticalMargins -ImgH $effectiveInputHeightOs -TopTrim $ttOs -BottomTrim $btOs
                                $ltCrop = [Math]::Max(0, [int]$ltOs)
                                $rtCrop = [Math]::Max(0, [int]$rtOs)
                                $resultStr = Invoke-PythonCropGuiMargins -WorkTrimSplitPy $workTrimSplitPy -ImagePath $effectiveInputPathOs -RightBinding $RightBinding -LeftTrim $ltCrop -TopTrim $vertOsMt.TopTrimPx -RightTrim $rtCrop -BottomTrim $vertOsMt.BottomTrimPx
                                $ttOs = $vertOsMt.TopTrimPx
                                $btOs = $vertOsMt.BottomTrimPx
                                $ltOs = $ltCrop
                                $rtOs = $rtCrop
                                if ($resultStr -match "TRIMMED:1") {
                                    Write-FlickFitHost "         ✅ 片側: 余白のみトリミングしました（1枚のまま）" -ForegroundColor DarkGreen
                                    $folderSplit += 1
                                    $splitImages += 1
                                    if ($useCachedGutterOs -eq $false -and (Test-Path -LiteralPath $effectiveInputPathOs)) {
                                        $iszRefOsT = Get-FlickFitEffectiveInputSizePx -LiteralPath $effectiveInputPathOs
                                        $refAspOsT = 0; $refWOsT = 0
                                        if ($iszRefOsT.Width -gt 0 -and $iszRefOsT.Height -gt 0) { $refAspOsT = $iszRefOsT.Width / $iszRefOsT.Height; $refWOsT = $iszRefOsT.Width }
                                        $gpOsT = if ($null -ne $gutterPctOsSav) { [Math]::Round([double]$gutterPctOsSav, 2) } else { 50.0 }
                                        $skipCacheOsMt0 = (Get-Variable -Name SplitWidthApplyGutterOnlyThisPage -Scope Script -ErrorAction SilentlyContinue) -and $script:SplitWidthApplyGutterOnlyThisPage
                                        if ($skipCacheOsMt0) { $script:SplitWidthApplyGutterOnlyThisPage = $false } else {
                                            $script:FolderGutterCache[$dir] = New-FlickFitFolderGutterCacheEntry -GutterX $gutterXOs -GutterPct $gpOsT -LeftTrimPx $ltOs -RightTrimPx $rtOs -TopTrimPx $ttOs -BottomTrimPx $btOs -ImgW $effectiveInputWidthOs -ImgH $effectiveInputHeightOs -RefAspect $refAspOsT -RefWidth $refWOsT -MarginTrimWithoutSplit $true
                                        }
                                    }
                                    if (Test-Path -LiteralPath $tempBackupOs) { Remove-Item -LiteralPath $tempBackupOs -Force -ErrorAction SilentlyContinue }
                                    $processedImages++
                                    $imgIdx++
                                    continue
                                }
                                Write-FlickFitHost "         ⚠ 余白トリム処理: $resultStr" -ForegroundColor Yellow
                                if (Test-Path -LiteralPath $tempBackupOs) {
                                    Copy-Item -LiteralPath $tempBackupOs -Destination $origPath -Force -ErrorAction SilentlyContinue
                                    Remove-Item -LiteralPath $tempBackupOs -Force -ErrorAction SilentlyContinue
                                }
                                $folderProblemSkipped++
                                $skippedImages++
                                $processedImages++
                                $imgIdx++
                                continue
                            }
                            if ($ltOs -gt 0 -or $rtOs -gt 0 -or $ttOs -gt 0 -or $btOs -gt 0) {
                                $cohOs = Repair-GutterMarginGeometry -ImgW $effectiveInputWidthOs -GutterX $gutterXOs -LeftTrim $ltOs -RightTrim $rtOs
                                $gutterXOs = $cohOs.GutterX; $ltOs = $cohOs.LeftTrimPx; $rtOs = $cohOs.RightTrimPx
                                $vertOs = Repair-GutterVerticalMargins -ImgH $effectiveInputHeightOs -TopTrim $ttOs -BottomTrim $btOs
                                $ttOs = $vertOs.TopTrimPx; $btOs = $vertOs.BottomTrimPx
                                $pyArgsOs = @($workTrimSplitPy, $effectiveInputPathOs, $RightBinding.ToString(), "split_at_gutter_with_margins", "-", [string]$gutterXOs, [string]$ltOs, [string]$rtOs, [string]$aspectMin, [string][int]$cwOs, [string]$ttOs, [string]$btOs)
                            } else {
                                # キャッシュ自動適用は従来どおり（gui_exact なし）。今回ノドGUIで確定したときだけ gui_exact で表紙幅による再クロップ・片ページトリムを抑止
                                $pyArgsOs = @($workTrimSplitPy, $effectiveInputPathOs, $RightBinding.ToString(), "split_at_gutter", "true", [string]$gutterXOs, [string]$aspectMin, [string][int]$cwOs, "true")
                                if ($osFreshGutterGuiUsed) { $pyArgsOs += "true" }
                            }
                            $splitOut = Invoke-PythonWithProcess -Category "PythonSplit" -PythonArgs $pyArgsOs
                            foreach ($ln in $splitOut) {
                                if ($ln -match "DEBUG") { Write-FlickFitHost "         $ln" -ForegroundColor DarkGray }
                            }
                            $resultStr = ($splitOut -join "")
                            if ($resultStr -match "SPLIT:2" -and (Test-Path -LiteralPath $so1) -and (Test-Path -LiteralPath $so2) -and $folderCoverWidth -gt 0 -and (Test-Path -LiteralPath $tempBackupOs)) {
                                # 期待ページ幅を RefWidthFromGutter に渡す（余白0のみでも 0 にならないよう純粋関数で統一）
                                $refWOs = Get-FlickFitReferencePageWidthFromGutter -ImgW $effectiveInputWidthOs -GutterX $gutterXOs -LeftTrimPx $ltOs -RightTrimPx $rtOs
                                $refAspOs = if ($cacheOs -and $cacheOs.RefAspect -gt 0) { $cacheOs.RefAspect } else { 0 }
                                $val = Invoke-SplitWidthValidation -SplitPath1 $so1 -SplitPath2 $so2 -CoverWidth $folderCoverWidth -BackupPath $tempBackupOs -OrigPath $origPath -WorkTrimSplitPy $workTrimSplitPy -RightBinding $RightBinding -AspectMin $aspectMin -ImgName $imgName -OneSidedContent -RefWidthFromGutter $refWOs -AllowGutterReselect $useCachedGutterOs -RefAspect $refAspOs -AllImagePaths @($imgs | ForEach-Object { $_.FullName }) -GutterCacheFolderKey $dir -AssumeInitialGutterGuiPrecedesSplit:$osFreshGutterGuiUsed
                                if ($val -eq "delete") {
                                    if (Test-Path -LiteralPath $tempBackupOs) { Remove-Item -LiteralPath $tempBackupOs -Force -ErrorAction SilentlyContinue }
                                    $folderProblemSkipped++; $skippedImages++; $processedImages++; $imgIdx++; continue
                                }
                                if ($val -eq "trim_only") {
                                    if (Test-Path -LiteralPath $so1) { Remove-Item -LiteralPath $so1 -Force -ErrorAction SilentlyContinue }
                                    if (Test-Path -LiteralPath $so2) { Remove-Item -LiteralPath $so2 -Force -ErrorAction SilentlyContinue }
                                    if (Test-Path -LiteralPath $tempBackupOs) {
                                        Copy-Item -LiteralPath $tempBackupOs -Destination $origPath -Force -ErrorAction SilentlyContinue
                                        $null = Invoke-PythonTimed -Category "PythonTrim" -PythonArgs $workTrimSplitPy, $origPath, $RightBinding.ToString(), "trim_only", "", $aspectMin
                                        Remove-Item -LiteralPath $tempBackupOs -Force -ErrorAction SilentlyContinue
                                    }
                                    Write-FlickFitHost "         ✅ 余白のみトリミング（分割なし・1枚）" -ForegroundColor DarkGreen
                                    $folderSplit += 1; $splitImages += 1; $processedImages++; $imgIdx++; continue
                                }
                                if ($val -eq "set_new_cover" -and (Get-Variable -Name SplitWidthNewCoverCandidate -Scope Script -ErrorAction SilentlyContinue)) {
                                    if ($script:SplitWidthNewCoverCandidate -gt 0) {
                                        $folderCoverWidth = [int]$script:SplitWidthNewCoverCandidate
                                        Write-FlickFitHost "         → このページ幅 $folderCoverWidth px を新しい基準値として採用しました" -ForegroundColor DarkCyan
                                    }
                                    $script:SplitWidthNewCoverCandidate = $null
                                }
                                if ($val -eq "gutter_reselect" -and (Test-Path -LiteralPath $tempBackupOs)) {
                                    # 片側コンテンツ用: ノド位置をGUIで再選択してから再分割（左右トリムなし）
                                    if (Test-Path -LiteralPath $so1) { Remove-Item -LiteralPath $so1 -Force -ErrorAction SilentlyContinue }
                                    Write-FlickFitObsFileOp -Op 'gutter_reselect_os_Remove_so1' -Path $so1
                                    if (Test-Path -LiteralPath $so2) { Remove-Item -LiteralPath $so2 -Force -ErrorAction SilentlyContinue }
                                    Write-FlickFitObsFileOp -Op 'gutter_reselect_os_Remove_so2' -Path $so2
                                    Copy-Item -LiteralPath $tempBackupOs -Destination $origPath -Force -ErrorAction SilentlyContinue
                                    Write-FlickFitObsFileOp -Op 'gutter_reselect_os_CopyBackupToOrig' -Path $origPath
                                    Write-FlickFitObsFileOp -Op 'gutter_reselect_os_tempBackup' -Path $tempBackupOs
                                    $guiResultOs = $null
                                    $gxOs = $null
                                    $presetOsFromVal = $script:SplitWidthGuiPresetResult
                                    if ($presetOsFromVal) { $script:SplitWidthGuiPresetResult = $null }
                                    if ($null -ne $presetOsFromVal -and $presetOsFromVal -is [System.Collections.IDictionary]) {
                                        $gxPre = Get-HashtableInt -Tbl $presetOsFromVal -Key 'GutterX' -Default (-1)
                                        if ($gxPre -ge 0) {
                                            $gxOs = $presetOsFromVal
                                            $guiResultOs = @{
                                                GutterX      = $gxPre
                                                LeftTrimPx   = (Get-HashtableInt -Tbl $presetOsFromVal -Key 'LeftTrimPx')
                                                RightTrimPx  = (Get-HashtableInt -Tbl $presetOsFromVal -Key 'RightTrimPx')
                                                TopTrimPx    = (Get-HashtableInt -Tbl $presetOsFromVal -Key 'TopTrimPx')
                                                BottomTrimPx = (Get-HashtableInt -Tbl $presetOsFromVal -Key 'BottomTrimPx')
                                                MarginTrimWithoutSplit = (Get-HashtableBool -Tbl $presetOsFromVal -Key 'MarginTrimWithoutSplit')
                                            }
                                        }
                                    }
                                    if ($null -eq $guiResultOs -or $guiResultOs.GutterX -lt 0) {
                                    try {
                                        $gutterReselectEntryOs = [string]$origPath
                                        $allPathsRsOs = @($imgs | ForEach-Object { $_.FullName })
                                        Write-FlickFitStep5EntryDebug -Label 'rsos-before' -EntryPath $entryPathStep5 -PreviewPath $gutterReselectEntryOs -ApplyPath $origPath -ImgIdx $imgIdx -ImgsCount $imgs.Count
                                        $gxOs = Show-GutterMarginSetGui -ImagePath $origPath -Title "片側コンテンツ: ノドと左右余白の再設定" -AllImagePaths $allPathsRsOs -OkAppliesToCurrentView -ShowApplyThisPageOnlyButton
                                        if ($gxOs -is [System.Collections.IDictionary]) { $gxOs = Normalize-GutterGuiResult -GuiResult $gxOs }
                                        $imgs = Update-ImgsAfterMarginGui -Imgs $imgs -GuiResult $gxOs
                                        $navRsOs = Get-FlickFitGutterEntryAfterNavGui -EntryPath $gutterReselectEntryOs -EntryName $imgName -GuiResult $gxOs
                                        if ($null -ne $navRsOs) { $origPath = $navRsOs.OrigPath; $imgName = $navRsOs.ImgName; $ext = $navRsOs.Ext }
                                        Write-FlickFitStep5EntryDebug -Label 'rsos-after' -EntryPath $entryPathStep5 -GuiResult $gxOs -ApplyPath $origPath -ImgIdx $imgIdx -ImgsCount $imgs.Count
                                        if (Test-GuiMarginFlagTrue -Tbl $gxOs -Key 'DeleteImage') {
                                            if (Test-Path -LiteralPath $tempBackupOs) { Remove-Item -LiteralPath $tempBackupOs -Force -ErrorAction SilentlyContinue }
                                            if (Test-Path -LiteralPath $so1) { Remove-Item -LiteralPath $so1 -Force -ErrorAction SilentlyContinue }
                                            if (Test-Path -LiteralPath $so2) { Remove-Item -LiteralPath $so2 -Force -ErrorAction SilentlyContinue }
                                            $folderProblemSkipped++; $skippedImages++; $processedImages++; $imgIdx++; continue
                                        }
                                        if (Test-GuiMarginFlagTrue -Tbl $gxOs -Key 'PhotosEdit') {
                                            if (Test-Path -LiteralPath $tempBackupOs) { Remove-Item -LiteralPath $tempBackupOs -Force -ErrorAction SilentlyContinue }
                                            if (Test-Path -LiteralPath $so1) { Remove-Item -LiteralPath $so1 -Force -ErrorAction SilentlyContinue }
                                            if (Test-Path -LiteralPath $so2) { Remove-Item -LiteralPath $so2 -Force -ErrorAction SilentlyContinue }
                                            $dPhRs = Get-ImageDimensions -Path $origPath
                                            if ($dPhRs.Width -gt 0) { $folderCoverWidth = $dPhRs.Width }
                                            Write-FlickFitHost "         ✅ フォトで編集した画像を採用（以降のトリミング基準に使用）" -ForegroundColor Green
                                            $folderSplit += 1; $splitImages += 1; $processedImages++; $imgIdx++; continue
                                        }
                                        $gxPickOs = Get-HashtableInt -Tbl $gxOs -Key 'GutterX' -Default (-1)
                                        if ($gxPickOs -ge 0) {
                                            $guiResultOs = @{
                                                GutterX     = $gxPickOs
                                                LeftTrimPx  = (Get-HashtableInt -Tbl $gxOs -Key 'LeftTrimPx')
                                                RightTrimPx = (Get-HashtableInt -Tbl $gxOs -Key 'RightTrimPx')
                                                TopTrimPx   = (Get-HashtableInt -Tbl $gxOs -Key 'TopTrimPx')
                                                BottomTrimPx = (Get-HashtableInt -Tbl $gxOs -Key 'BottomTrimPx')
                                                MarginTrimWithoutSplit = (Get-HashtableBool -Tbl $gxOs -Key 'MarginTrimWithoutSplit')
                                            }
                                        }
                                        if (Test-GuiMarginFlagTrue -Tbl $gxOs -Key 'ApplyOnlyThisSpread') {
                                            $script:SplitWidthApplyGutterOnlyThisPage = $true
                                        }
                                    } catch {
                                        Write-FlickFitHost "         （ノド再選択GUIが開けませんでした）" -ForegroundColor DarkGray
                                    }
                                    }
                                    if ($null -eq $guiResultOs -or $guiResultOs.GutterX -lt 0) {
                                        # キャンセル扱い: 元画像を復元してスキップ
                                        if (Test-Path -LiteralPath $tempBackupOs) { Copy-Item -LiteralPath $tempBackupOs -Destination $origPath -Force -ErrorAction SilentlyContinue }
                                        if (Test-Path -LiteralPath $tempBackupOs) { Remove-Item -LiteralPath $tempBackupOs -Force -ErrorAction SilentlyContinue }
                                        $folderKeptAsIs++; $skippedImages++; $processedImages++; $imgIdx++; continue
                                    }
                                    $apOne = Get-HashtableTrimmedString -Tbl $gxOs -Key 'ApplyImagePath'
                                    $splitOrigRs = Resolve-FlickFitEffectiveInputPath -OrigPath $origPath -GuiResult $gxOs
                                    $srSrc = if ($null -ne $presetOsFromVal) { 'preset' } else { 'gui' }
                                    $srLastW = 0
                                    if ($script:SplitWidthLastConfirmedByFolder -and $script:SplitWidthLastConfirmedByFolder.ContainsKey($dir)) {
                                        $srLastW = Get-HashtableInt -Tbl $script:SplitWidthLastConfirmedByFolder[$dir] -Key 'ImgW' -Default 0
                                    }
                                    if (-not [string]::Equals($splitOrigRs, $origPath, [StringComparison]::OrdinalIgnoreCase)) {
                                        $extRs = [System.IO.Path]::GetExtension($splitOrigRs).ToLower()
                                        $baseRs = [System.IO.Path]::GetFileNameWithoutExtension($splitOrigRs)
                                        $so1 = Join-Path (Get-LiteralPathParent $splitOrigRs) ($baseRs + "_1" + $extRs)
                                        $so2 = Join-Path (Get-LiteralPathParent $splitOrigRs) ($baseRs + "_2" + $extRs)
                                        $dRs = Get-ImageDimensions -Path $splitOrigRs
                                        if ($dRs.Width -gt 0 -and $dRs.Height -gt 0) { $origW = $dRs.Width; $origH = $dRs.Height }
                                    }
                                    # ノド再選択サブブロック: 実入力を再同期（以降の Python・幾何・ログ imgW はここ基準）
                                    $effectiveInputPathOs = [string]$splitOrigRs
                                    $iszEffOsRs = Get-FlickFitEffectiveInputSizePx -LiteralPath $effectiveInputPathOs
                                    $effectiveInputWidthOs = $iszEffOsRs.Width
                                    $effectiveInputHeightOs = $iszEffOsRs.Height
                                    $srHasApply = ($null -ne $apOne)
                                    Write-FlickFitHost ("[SplitReuse] mode=one_sided source={0} orig={1} input={2} hasApply={3} imgW={4} lastImgW={5} eff={6}" -f $srSrc, $origPath, $splitOrigRs, $srHasApply, $effectiveInputWidthOs, $srLastW, $effectiveInputPathOs) -ForegroundColor DarkYellow
                                    $gxVal = [int]$guiResultOs.GutterX
                                    $ltOs2 = [int]$guiResultOs.LeftTrimPx
                                    $rtOs2 = [int]$guiResultOs.RightTrimPx
                                    $ttOs2 = [int]$guiResultOs.TopTrimPx
                                    $btOs2 = [int]$guiResultOs.BottomTrimPx
                                    $rsOsMt = Get-HashtableBool -Tbl $guiResultOs -Key 'MarginTrimWithoutSplit'
                                    if ($rsOsMt) {
                                        $vertRsMt = Repair-GutterVerticalMargins -ImgH $effectiveInputHeightOs -TopTrim $ttOs2 -BottomTrim $btOs2
                                        $ltOs2 = [Math]::Max(0, $ltOs2)
                                        $rtOs2 = [Math]::Max(0, $rtOs2)
                                        $resultStr2 = Invoke-PythonCropGuiMargins -WorkTrimSplitPy $workTrimSplitPy -ImagePath $effectiveInputPathOs -RightBinding $RightBinding -LeftTrim $ltOs2 -TopTrim $vertRsMt.TopTrimPx -RightTrim $rtOs2 -BottomTrim $vertRsMt.BottomTrimPx
                                        $ttOs2 = $vertRsMt.TopTrimPx
                                        $btOs2 = $vertRsMt.BottomTrimPx
                                        if ($resultStr2 -match "TRIMMED:1") {
                                            Write-FlickFitHost "         ✅ 再設定: 余白のみトリミング（1枚）" -ForegroundColor DarkGreen
                                            $folderSplit += 1
                                            $splitImages += 1
                                            $iszRefOs2Mt = Get-FlickFitEffectiveInputSizePx -LiteralPath $effectiveInputPathOs
                                            $refAspOs2 = 0; $refWOs2 = 0
                                            if ($iszRefOs2Mt.Width -gt 0 -and $iszRefOs2Mt.Height -gt 0) { $refAspOs2 = $iszRefOs2Mt.Width / $iszRefOs2Mt.Height; $refWOs2 = $iszRefOs2Mt.Width }
                                            $skipCacheOsMt = (Get-Variable -Name SplitWidthApplyGutterOnlyThisPage -Scope Script -ErrorAction SilentlyContinue) -and $script:SplitWidthApplyGutterOnlyThisPage
                                            if ($skipCacheOsMt) { $script:SplitWidthApplyGutterOnlyThisPage = $false } else {
                                                $script:FolderGutterCache[$dir] = New-FlickFitFolderGutterCacheEntry -GutterX $gxVal -GutterPct 50.0 -LeftTrimPx $ltOs2 -RightTrimPx $rtOs2 -TopTrimPx $ttOs2 -BottomTrimPx $btOs2 -ImgW $effectiveInputWidthOs -ImgH $effectiveInputHeightOs -RefAspect $refAspOs2 -RefWidth $refWOs2 -MarginTrimWithoutSplit $true
                                            }
                                            if (Test-Path -LiteralPath $tempBackupOs) { Remove-Item -LiteralPath $tempBackupOs -Force -ErrorAction SilentlyContinue }
                                            $processedImages++
                                            $imgIdx++
                                            continue
                                        }
                                        if (Test-Path -LiteralPath $tempBackupOs) {
                                            Copy-Item -LiteralPath $tempBackupOs -Destination $origPath -Force -ErrorAction SilentlyContinue
                                            Remove-Item -LiteralPath $tempBackupOs -Force -ErrorAction SilentlyContinue
                                        }
                                        $folderProblemSkipped++; $skippedImages++; $processedImages++; $imgIdx++; continue
                                    }
                                    if ($ltOs2 -gt 0 -or $rtOs2 -gt 0 -or $ttOs2 -gt 0 -or $btOs2 -gt 0) {
                                        $cohOs2 = Repair-GutterMarginGeometry -ImgW $effectiveInputWidthOs -GutterX $gxVal -LeftTrim $ltOs2 -RightTrim $rtOs2
                                        $gxVal = $cohOs2.GutterX; $ltOs2 = $cohOs2.LeftTrimPx; $rtOs2 = $cohOs2.RightTrimPx
                                        $vertOs2 = Repair-GutterVerticalMargins -ImgH $effectiveInputHeightOs -TopTrim $ttOs2 -BottomTrim $btOs2
                                        $ttOs2 = $vertOs2.TopTrimPx; $btOs2 = $vertOs2.BottomTrimPx
                                        $pyArgsOs2 = @($workTrimSplitPy, $effectiveInputPathOs, $RightBinding.ToString(), "split_at_gutter_with_margins", "-", [string]$gxVal, [string]$ltOs2, [string]$rtOs2, [string]$aspectMin, [string][int]$folderCoverWidth, [string]$ttOs2, [string]$btOs2)
                                    } else {
                                        $pyArgsOs2 = @($workTrimSplitPy, $effectiveInputPathOs, $RightBinding.ToString(), "split_at_gutter", "true", [string]$gxVal, [string]$aspectMin, [string][int]$folderCoverWidth, "true", "true")
                                    }
                                    $splitOut2 = Invoke-PythonWithProcess -Category "PythonSplit" -PythonArgs $pyArgsOs2
                                    foreach ($ln2 in $splitOut2) {
                                        if ($ln2 -match "DEBUG") { Write-FlickFitHost "         $ln2" -ForegroundColor DarkGray }
                                    }
                                    $resultStr2 = ($splitOut2 -join "")
                                    if ($resultStr2 -match "SPLIT:2" -and (Test-Path -LiteralPath $so1) -and (Test-Path -LiteralPath $so2)) {
                                        Write-FlickFitHost "         ✅ ノド再選択の分割結果を採用しました（2枚）" -ForegroundColor DarkGreen
                                        $folderSplit += 2
                                        $splitImages += 2
                                        $processedImages++
                                        $imgIdx++
                                        # 新しいノド位置をキャッシュ
                                        $dRefOs2 = Get-ImageDimensions -Path $so1
                                        $refAspOs2 = 0; $refWOs2 = 0
                                        if ($dRefOs2.Width -gt 0 -and $dRefOs2.Height -gt 0) { $refAspOs2 = $dRefOs2.Width / $dRefOs2.Height; $refWOs2 = $dRefOs2.Width }
                                        $gpOs2 = if ($effectiveInputWidthOs -gt 0) { [Math]::Round(100.0 * $gxVal / $effectiveInputWidthOs, 2) } else { 50.0 }
                                        $ucsRsOs = if ($null -ne $gxOs) { Get-HashtableBool -Tbl $gxOs -Key 'MarginTrimWithoutSplit' } else { $false }
                                        $skipCacheOsSp = (Get-Variable -Name SplitWidthApplyGutterOnlyThisPage -Scope Script -ErrorAction SilentlyContinue) -and $script:SplitWidthApplyGutterOnlyThisPage
                                        if ($skipCacheOsSp) { $script:SplitWidthApplyGutterOnlyThisPage = $false } else {
                                            $script:FolderGutterCache[$dir] = New-FlickFitFolderGutterCacheEntry -GutterX $gxVal -GutterPct $gpOs2 -LeftTrimPx $ltOs2 -RightTrimPx $rtOs2 -TopTrimPx $ttOs2 -BottomTrimPx $btOs2 -ImgW $effectiveInputWidthOs -ImgH $effectiveInputHeightOs -RefAspect $refAspOs2 -RefWidth $refWOs2 -MarginTrimWithoutSplit $ucsRsOs
                                        }
                                        if (Test-Path -LiteralPath $tempBackupOs) { Remove-Item -LiteralPath $tempBackupOs -Force -ErrorAction SilentlyContinue }
                                        continue
                                    } else {
                                        # 再分割失敗時は元画像を復元してスキップ
                                        if (Test-Path -LiteralPath $tempBackupOs) {
                                            Copy-Item -LiteralPath $tempBackupOs -Destination $origPath -Force -ErrorAction SilentlyContinue
                                            Remove-Item -LiteralPath $tempBackupOs -Force -ErrorAction SilentlyContinue
                                        }
                                        $folderProblemSkipped++; $skippedImages++; $processedImages++; $imgIdx++; continue
                                    }
                                }
                                if ($val -eq "retry" -and $folderCoverWidth -le 0 -and (Test-Path -LiteralPath $so1)) {
                                    $dd = Get-ImageDimensions -Path $so1
                                    if ($dd.Width -gt 0) { $folderCoverWidth = $dd.Width }
                                }
                                if (Test-Path -LiteralPath $tempBackupOs) { Remove-Item -LiteralPath $tempBackupOs -Force -ErrorAction SilentlyContinue }
                            } elseif (Test-Path -LiteralPath $tempBackupOs) { Remove-Item -LiteralPath $tempBackupOs -Force -ErrorAction SilentlyContinue }
                            if ($resultStr -match "SPLIT:2") {
                                Write-FlickFitHost "         ✅ 分割版を採用しました（2枚）" -ForegroundColor DarkGreen
                                $folderSplit += 2
                                $splitImages += 2
                                if ($osFreshGutterGuiUsed) {
                                    try {
                                        # SplitBasePath は「初回ノドGUIで確定した分割のベースファイル」用。$effectiveInputPathOs（ApplyImagePath 等の実入力）とは別。将来ここを再利用判定に使う場合はズレ源になり得る。
                                        Add-FlickFitGuiSplitTrustOutputs -GuiSplitTrustSet $guiSplitTrustNorm -SplitBasePath $splitOrigOs
                                    } catch {
                                        Write-FlickFitHost "         [警告] 分割片の信頼リスト登録に失敗（処理は続行）: $($_.Exception.Message)" -ForegroundColor DarkYellow
                                    }
                                }
                                $processedImages++
                                $imgIdx++
                                if ($folderCoverWidth -le 0 -and (Test-Path -LiteralPath $so1)) {
                                    $dd = Get-ImageDimensions -Path $so1
                                    if ($dd.Width -gt 0) { $folderCoverWidth = $dd.Width; Write-FlickFitDebugStep5VerboseHost -Text "[DEBUG] 表紙幅=$folderCoverWidth px（片側分割結果）" }
                                }
                                if ($useCachedGutterOs -eq $false -and $gutterXOs -ge 0) {
                                    $dRefOs = Get-ImageDimensions -Path $so1
                                    $refAspOs = 0; $refWOs = 0
                                    if ($dRefOs.Width -gt 0 -and $dRefOs.Height -gt 0) { $refAspOs = $dRefOs.Width / $dRefOs.Height; $refWOs = $dRefOs.Width }
                                    $gpOsSave = if ($null -ne $gutterPctOsSav) { [Math]::Round([double]$gutterPctOsSav, 2) } elseif ($effectiveInputWidthOs -gt 0) { [Math]::Round(100.0 * $gutterXOs / $effectiveInputWidthOs, 2) } else { 50.0 }
                                    $skipCacheOsSp0 = (Get-Variable -Name SplitWidthApplyGutterOnlyThisPage -Scope Script -ErrorAction SilentlyContinue) -and $script:SplitWidthApplyGutterOnlyThisPage
                                    if ($skipCacheOsSp0) { $script:SplitWidthApplyGutterOnlyThisPage = $false } else {
                                        $script:FolderGutterCache[$dir] = New-FlickFitFolderGutterCacheEntry -GutterX $gutterXOs -GutterPct $gpOsSave -LeftTrimPx $ltOs -RightTrimPx $rtOs -TopTrimPx $ttOs -BottomTrimPx $btOs -ImgW $effectiveInputWidthOs -ImgH $effectiveInputHeightOs -RefAspect $refAspOs -RefWidth $refWOs -MarginTrimWithoutSplit $ucsOsSave
                                    }
                                }
                                continue
                            } elseif ($resultStr -match "ERROR" -and $resultStr -match "PermissionError|WinError 32|アクセスできません" -and (Test-Path -LiteralPath $so1) -and (Test-Path -LiteralPath $so2)) {
                                Write-FlickFitHost "         ⚠ 分割は成功しましたが元画像の削除に失敗。PowerShell側でリトライ..." -ForegroundColor Yellow
                                $delOkOs = $false
                                for ($ro = 0; $ro -lt 8; $ro++) {
                                    [System.GC]::Collect(); [System.GC]::WaitForPendingFinalizers()
                                    Start-Sleep -Milliseconds (200 + $ro * 150)
                                    try {
                                        if (Test-Path -LiteralPath $origPath) { Remove-Item -LiteralPath $origPath -Force -ErrorAction Stop }
                                        if (-not (Test-Path -LiteralPath $origPath)) { $delOkOs = $true; break }
                                    } catch {}
                                }
                                if ($delOkOs) {
                                    Write-FlickFitHost "         ✅ 元画像を削除し、2ページに分割完了" -ForegroundColor DarkGreen
                                    $folderSplit += 2; $splitImages += 2; $processedImages++; $imgIdx++
                                    if ($folderCoverWidth -le 0) { $dd = Get-ImageDimensions -Path $so1; if ($dd.Width -gt 0) { $folderCoverWidth = $dd.Width } }
                                } else {
                                    Write-FlickFitHost "         ⚠ 削除リトライも失敗: $imgName（分割結果は作成済み・元画像は手動削除してください）" -ForegroundColor Red
                                    $folderProblemSkipped++; $skippedImages++
                                }
                                if (Test-Path -LiteralPath $tempBackupOs) { Remove-Item -LiteralPath $tempBackupOs -Force -ErrorAction SilentlyContinue }
                                if (-not $delOkOs) { $processedImages++; $imgIdx++ }
                                continue
                            } else {
                                Write-FlickFitHost "         ⚠ 分割エラー: $($resultStr.Trim())" -ForegroundColor Yellow
                                $folderProblemSkipped++; $skippedImages++
                            }
                        } catch {
                            Write-FlickFitHost "         ⚠ 分割エラー: $($_.Exception.Message)" -ForegroundColor Yellow
                            $folderProblemSkipped++; $skippedImages++
                        }
                        # 片側分割エラー時: GUI 削除直後などで $origPath が欠落のままだと imgIdx++ で 1 枚飛ばす。一覧を再同期し、欠落→復旧なら同じインデックスで再試行
                        $origMissingBeforeSync = -not (Test-Path -LiteralPath $origPath)
                        $imgs = @(Get-ProcessableFolderImages -FolderPath $dir)
                        if (Test-Path -LiteralPath $entryPathStep5) {
                            $origPath = $entryPathStep5
                            $imgName = [System.IO.Path]::GetFileName($entryPathStep5)
                            $ext = [System.IO.Path]::GetExtension($entryPathStep5).ToLower()
                        } elseif ($imgIdx -lt $imgs.Count) {
                            $ci = $imgs[$imgIdx]
                            $origPath = $ci.FullName
                            $imgName = $ci.Name
                            $ext = $ci.Extension.ToLower()
                        }
                        if (-not (Test-Path -LiteralPath $origPath)) {
                            Write-FlickFitHost "         ↩ 元画像が無いためこの枠をスキップします（削除済みなど）" -ForegroundColor DarkGray
                            $processedImages++
                            $imgIdx++
                            continue
                        }
                        if ($origMissingBeforeSync) {
                            Write-FlickFitHost "         ↻ ファイル一覧を同期しました。この位置の画像でもう一度処理します" -ForegroundColor DarkGray
                            continue
                        }
                        
                    } else {
                        # BALANCED: 分割 + 各ページ余白除去（前トリミングなし＝2枚目と同様）
                        # 同フォルダ×同解像度のノドキャッシュが使える場合は先に確定。center_split_risk は未確定画像向けの保険とし、キャッシュありでは実行しない
                        $dOrigB = Get-ImageDimensions -Path $origPath
                        $origW = $dOrigB.Width
                        $origH = $dOrigB.Height
                        $cacheB = $script:FolderGutterCache[$dir]
                        $cacheBMt = if ($cacheB) { Get-HashtableBool -Tbl $cacheB -Key 'MarginTrimWithoutSplit' } else { $false }
                        $useCachedGutterB = ($cacheB -and $cacheB.ImgW -eq $origW -and $cacheB.ImgH -eq $origH -and (($cacheB.GutterX -gt 0) -or $cacheBMt) -and $splitMode -eq "split")
                        if ($true -eq $script:FlickFitDebugStep5Verbose -and $useCachedGutterB) {
                            Write-FlickFitHost "         [CenterSplitRisk] 同サイズ（${origW}x${origH}）のノドキャッシュあり → center_split_risk をスキップ" -ForegroundColor DarkCyan
                        }
                        if (-not $script:FlickFitDisableCenterSplitRisk -and $splitMode -eq "split" -and -not $useTocTrim -and -not $useCachedGutterB) {
                            $csrP = "RISK_OK"
                            try {
                                $csrOut = @(Invoke-PythonTimed -Category "PythonAnalyze" -PythonArgs $workTrimSplitPy, $entryPathStep5, $RightBinding.ToString(), "center_split_risk")
                                foreach ($ln in $csrOut) { if ($ln -match "RISK_SKIP_CENTER_SPLIT") { $csrP = "SKIP" } }
                            } catch { $csrP = "RISK_OK" }
