                                Write-FlickFitHost "         ⚠ 中央1ページ風: 真ん中にノドが取れない／片側すき／左右差が大きいため 中央2分割を避けます" -ForegroundColor Yellow
                                $dCst0 = Get-ImageDimensions -Path $entryPathStep5
                                $cstKey0 = Get-FlickFitCenteredSingleTrimCacheKey -DirPath $dir -W $dCst0.Width -H $dCst0.Height
                                $cstProfileDone = $false
                                if (-not $script:FlickFitDisableCenteredSingleTrimProfile -and $script:FolderCenteredSingleTrimCache.ContainsKey($cstKey0)) {
                                    $prC = $script:FolderCenteredSingleTrimCache[$cstKey0]
