                                        $ltCp = [int]$prC.LeftTrimPx; $rtCp = [int]$prC.RightTrimPx; $ttCp = [int]$prC.TopTrimPx; $btCp = [int]$prC.BottomTrimPx
                                        $vertCp = Repair-GutterVerticalMargins -ImgH $dCst0.Height -TopTrim $ttCp -BottomTrim $btCp
                                        try {
                                            $outCp = Invoke-PythonCropGuiMargins -WorkTrimSplitPy $workTrimSplitPy -ImagePath $entryPathStep5 -RightBinding $RightBinding -LeftTrim $ltCp -TopTrim $vertCp.TopTrimPx -RightTrim $rtCp -BottomTrim $vertCp.BottomTrimPx
                                            if ($outCp -match "TRIMMED:1") {
