                                                $cstProfileDone = $true
                                                $folderSplit += 1; $splitImages += 1
                                            }
                                        } catch { }
                                    }
                                }
                                if ($cstProfileDone) { $processedImages++; $imgIdx++; continue }
                                if ($script:FlickFitDisableCenteredSingleTrimProfile) {
                                    try {
                                        $null = Invoke-PythonTimed -Category "PythonTrim" -PythonArgs $workTrimSplitPy, $entryPathStep5, $RightBinding.ToString(), "trim_only", "", $aspectMin
                                        Write-FlickFitHost "         ✅ 余白トリムのみ（1枚・分割なし）" -ForegroundColor DarkGreen
                                        Add-FlickFitRetrimCandidate -VolFolder $dir -FilePath $entryPathStep5 -Reason 'centered_single_fallback' -PageLabel $imgName
                                        $folderSplit += 1; $splitImages += 1
                                    } catch {
