                                    $allPathsCst = @($imgs | ForEach-Object { $_.FullName })
                                    Write-FlickFitStep5EntryDebug -Label 'cst-before' -EntryPath $entryPathStep5 -PreviewPath $entryPathStep5 -ApplyPath $origPath -ImgIdx $imgIdx -ImgsCount $imgs.Count
                                    $guiCst = Show-GutterMarginSetGui -ImagePath $entryPathStep5 -Title "中央1枚型: 四辺余白（「ノドを指定する」はオフ＝余白のみ推奨）" -AllImagePaths $allPathsCst -OkAppliesToCurrentView -ShowApplyThisPageOnlyButton
                                    if ($null -eq $guiCst) {
                                        Write-FlickFitHost "         （中央1枚型GUI: キャンセル）従来の trim_only" -ForegroundColor DarkGray
                                        $null = Invoke-PythonTimed -Category "PythonTrim" -PythonArgs $workTrimSplitPy, $entryPathStep5, $RightBinding.ToString(), "trim_only", "", $aspectMin
                                        Write-FlickFitHost "         ✅ 余白トリムのみ（1枚・分割なし）" -ForegroundColor DarkGreen
                                        Add-FlickFitRetrimCandidate -VolFolder $dir -FilePath $entryPathStep5 -Reason 'trim_weak' -PageLabel $imgName
                                        $folderSplit += 1; $splitImages += 1; $processedImages++; $imgIdx++; continue
                                    }
                                    if ($guiCst -is [System.Collections.IDictionary]) { $guiCst = Normalize-GutterGuiResult -GuiResult $guiCst }
                                    $imgs = Update-ImgsAfterMarginGui -Imgs $imgs -GuiResult $guiCst
                                    if (Test-GuiMarginFlagTrue -Tbl $guiCst -Key 'ApplyOnlyThisSpread') { $script:SplitWidthApplyGutterOnlyThisPage = $true }
                                    $navCst = Get-FlickFitGutterEntryAfterNavGui -EntryPath $entryPathStep5 -EntryName $entryNameStep5 -GuiResult $guiCst
                                    if ($null -ne $navCst) { $origPath = $navCst.OrigPath; $imgName = $navCst.ImgName; $ext = $navCst.Ext }
