                                    if (-not [string]::Equals($origPath, $pathCst, [StringComparison]::OrdinalIgnoreCase)) {
                                        $origPath = $pathCst
                                        $imgName = [System.IO.Path]::GetFileName($origPath)
                                        $ext = [System.IO.Path]::GetExtension($origPath).ToLower()
                                    }
                                    $dPathCst = Get-ImageDimensions -Path $pathCst
                                    # MarginTrimWithoutSplit: GUI「ノド位置を指定する」がオフ=四辺のみ・1枚。オン=分割（で MarginTrimWithoutSplit=$false）→ split_at_gutter 系
                                    $mtCstUserMarginOnly = Get-HashtableBool -Tbl $guiCst -Key 'MarginTrimWithoutSplit'
                                    $gxCstGui = Get-HashtableInt -Tbl $guiCst -Key 'GutterX' -Default (-1)
                                    if (-not $mtCstUserMarginOnly -and $gxCstGui -ge 0) {
