                                        Copy-Item -LiteralPath $pathCst -Destination $cstBackupG -Force -ErrorAction SilentlyContinue
                                        $ltG = Get-HashtableInt -Tbl $guiCst -Key 'LeftTrimPx'
                                        $rtG = Get-HashtableInt -Tbl $guiCst -Key 'RightTrimPx'
                                        $ttG = Get-HashtableInt -Tbl $guiCst -Key 'TopTrimPx'
                                        $btG = Get-HashtableInt -Tbl $guiCst -Key 'BottomTrimPx'
                                        $dGCst = $dPathCst
                                        $cwGCst = $folderCoverWidth
