                                        $gXuse = $cohGCst.GutterX; $ltG = $cohGCst.LeftTrimPx; $rtG = $cohGCst.RightTrimPx
                                        $vertGCst = Repair-GutterVerticalMargins -ImgH $dGCst.Height -TopTrim $ttG -BottomTrim $btG
                                        if ($ltG -gt 0 -or $rtG -gt 0 -or $vertGCst.TopTrimPx -gt 0 -or $vertGCst.BottomTrimPx -gt 0) {
