                                        } else {
                                            $outGstC = @(& $script:PythonExe $workTrimSplitPy $pathCst $RightBinding.ToString() "split_at_gutter" "false" $gXuse $aspectMin $cwGCst "false" "true" 2>&1)
                                        }
                                        Write-FlickFitPythonDebugLines -Lines @($outGstC)
                                        $joinedGstC = ($outGstC | ForEach-Object { "$_" }) -join ""
                                        $pGst1 = Join-Path (Get-LiteralPathParent $pathCst) ([System.IO.Path]::GetFileNameWithoutExtension($pathCst) + "_1" + $ext)
                                        $pGst2 = Join-Path (Get-LiteralPathParent $pathCst) ([System.IO.Path]::GetFileNameWithoutExtension($pathCst) + "_2" + $ext)
                                        if ($joinedGstC -match "SPLIT:2" -and (Test-Path -LiteralPath $pGst1) -and (Test-Path -LiteralPath $pGst2)) {
                                            try { if (Test-Path -LiteralPath $pathCst) { Remove-Item -LiteralPath $pathCst -Force -ErrorAction Stop } } catch { }
                                            if (Test-Path -LiteralPath $cstBackupG) { Remove-Item -LiteralPath $cstBackupG -Force -ErrorAction SilentlyContinue }
                                            Write-FlickFitHost "         ✅ ノド指定で2分割しました（中央1ページ風RISKの手動上書き）" -ForegroundColor DarkGreen
                                            $refAC = 0.0; $refWC2 = 0.0
                                            if (Test-Path -LiteralPath $pGst1) { $dR1g = Get-ImageDimensions -Path $pGst1; if ($dR1g.Width -gt 0) { $refAC = $dR1g.Width / $dR1g.Height; $refWC2 = $dR1g.Width } }
                                            $gpCst2 = if ($dGCst.Width -gt 0) { [Math]::Round(100.0 * $gXuse / $dGCst.Width, 2) } else { 50.0 }
                                            if ($gpCst2 -lt 1) { $gpCst2 = 1.0 } elseif ($gpCst2 -gt 99) { $gpCst2 = 99.0 }
                                            $skGst = (Get-Variable -Name SplitWidthApplyGutterOnlyThisPage -Scope Script -ErrorAction SilentlyContinue) -and $script:SplitWidthApplyGutterOnlyThisPage
                                            if ($skGst) { $script:SplitWidthApplyGutterOnlyThisPage = $false } else {
                                                $script:FolderGutterCache[$dir] = New-FlickFitFolderGutterCacheEntry -GutterX $gXuse -GutterPct $gpCst2 -LeftTrimPx $ltG -RightTrimPx $rtG -TopTrimPx $vertGCst.TopTrimPx -BottomTrimPx $vertGCst.BottomTrimPx -ImgW $dGCst.Width -ImgH $dGCst.Height -RefAspect $refAC -RefWidth $refWC2 -MarginTrimWithoutSplit $false
                                            }
                                            $szKCst = "$($dir)|$($dGCst.Width)x$($dGCst.Height)"
                                            if (-not $script:FolderMarginMode.ContainsKey($szKCst)) { $script:FolderMarginMode[$szKCst] = 'gui' }
                                            $folderSplit += 2; $splitImages += 2; $processedImages++; $imgIdx++
                                            if ($folderCoverWidth -le 0 -and (Test-Path -LiteralPath $pGst1)) { $dPc2 = Get-ImageDimensions -Path $pGst1; if ($dPc2.Width -gt 0) { $folderCoverWidth = $dPc2.Width } }
                                            continue
                                        }
                                        Write-FlickFitHost "         ⚠ ノド指定2分割に失敗: $joinedGstC — 1枚余白にフォールバック" -ForegroundColor Yellow
                                        if (Test-Path -LiteralPath $cstBackupG) { Copy-Item -LiteralPath $cstBackupG -Destination $pathCst -Force -ErrorAction SilentlyContinue }
                                        if (Test-Path -LiteralPath $cstBackupG) { Remove-Item -LiteralPath $cstBackupG -Force -ErrorAction SilentlyContinue }
                                        try { $ftGst = (Invoke-PythonTimed -Category "PythonTrim" -PythonArgs $workTrimSplitPy, $pathCst, $RightBinding.ToString(), "trim_only", "", $aspectMin) -join "" } catch { $ftGst = '' }
                                        if ($ftGst -match "TRIMMED:1") { Write-FlickFitHost "         ✅ 余白トリムのみ（1枚・分割なし）" -ForegroundColor DarkGreen } else { Write-FlickFitHost "         ⚠ trim_only: $ftGst" -ForegroundColor Yellow }
                                        Add-FlickFitRetrimCandidate -VolFolder $dir -FilePath $pathCst -Reason 'cst_risk_gutter_split_fail' -PageLabel $imgName
                                        $folderSplit += 1; $splitImages += 1; $processedImages++; $imgIdx++
                                        continue
                                    }
                                    $ltCst = Get-HashtableInt -Tbl $guiCst -Key 'LeftTrimPx'
                                    $rtCst = Get-HashtableInt -Tbl $guiCst -Key 'RightTrimPx'
                                    $ttCst = Get-HashtableInt -Tbl $guiCst -Key 'TopTrimPx'
                                    $btCst = Get-HashtableInt -Tbl $guiCst -Key 'BottomTrimPx'
                                    $vertCst = Repair-GutterVerticalMargins -ImgH $dPathCst.Height -TopTrim $ttCst -BottomTrim $btCst
                                    $outCst1 = Invoke-PythonCropGuiMargins -WorkTrimSplitPy $workTrimSplitPy -ImagePath $pathCst -RightBinding $RightBinding -LeftTrim $ltCst -TopTrim $vertCst.TopTrimPx -RightTrim $rtCst -BottomTrim $vertCst.BottomTrimPx
                                    if ($outCst1 -match "TRIMMED:1") {
                                        Write-FlickFitHost "         ✅ 中央1枚型: 四辺を適用（1枚）" -ForegroundColor DarkGreen
                                        $cstKeySave = Get-FlickFitCenteredSingleTrimCacheKey -DirPath $dir -W $dPathCst.Width -H $dPathCst.Height
                                        $skipCstPr = (Get-Variable -Name SplitWidthApplyGutterOnlyThisPage -Scope Script -ErrorAction SilentlyContinue) -and $script:SplitWidthApplyGutterOnlyThisPage
                                        if ($skipCstPr) { $script:SplitWidthApplyGutterOnlyThisPage = $false }
                                        if (-not $skipCstPr -and -not (Test-GuiMarginFlagTrue -Tbl $guiCst -Key 'ApplyOnlyThisSpread')) {
                                            $script:FolderCenteredSingleTrimCache[$cstKeySave] = [PSCustomObject]@{
                                                LeftTrimPx   = $ltCst; RightTrimPx  = $rtCst; TopTrimPx    = $vertCst.TopTrimPx; BottomTrimPx = $vertCst.BottomTrimPx
                                                ImgW = $dPathCst.Width; ImgH = $dPathCst.Height
                                            }
                                            Write-FlickFitHost "         📌 以降 同解像度（$($dPathCst.Width)x$($dPathCst.Height)）で同じ四辺pxを継承します" -ForegroundColor DarkGray
                                        } else {
                                            Write-FlickFitHost "         （このページのみ採用: 四辺プロファイルは保存しません）" -ForegroundColor DarkGray
                                        }
                                    } else {
                                        Write-FlickFitHost "         ⚠ 四辺crop失敗。従来 trim_only: $outCst1" -ForegroundColor Yellow
                                        $null = Invoke-PythonTimed -Category "PythonTrim" -PythonArgs $workTrimSplitPy, $pathCst, $RightBinding.ToString(), "trim_only", "", $aspectMin
                                        Write-FlickFitHost "         ✅ 余白トリムのみ（1枚・分割なし）" -ForegroundColor DarkGreen
                                        Add-FlickFitRetrimCandidate -VolFolder $dir -FilePath $pathCst -Reason 'trim_weak' -PageLabel $imgName
                                    }
                                    $folderSplit += 1; $splitImages += 1
                                } catch {
                                    Write-FlickFitHost "         ⚠ 中央1枚型: $($_.Exception.Message)" -ForegroundColor Yellow
                                    $folderProblemSkipped++; $skippedImages++
                                }
                                $processedImages++
                                $imgIdx++
                                continue
                            }
                        }
                        $baseNoExtBal = [System.IO.Path]::GetFileNameWithoutExtension($origPath)
                        <#
                          --- tempBackupB 対応表（バランス型 BALANCED）---
                          意味: バランス経路でも $origPath / 分割結果の変化に備えた元画像コピー。tempBackupOs と対称だが分岐集合が異なる。

                          | 操作     | いつ・どこで |
                          |----------|--------------|
                          | 作る     | 直下 Join-Path + Copy-Item（cvr_retry_{元名}{ext}） |
                          | 持ち越す | キャッシュ分割・GUI ループ・縦横比警告後の再分割など長い区間。SPLIT:2 かつ条件成立時は Invoke-SplitWidthValidation -BackupPath に渡す |
                          | 戻す     | trim_only、gutter_reselect 入口（分割片削除後）、縦横比再設定でキャッシュ解除時、Aspect GUI キャンセル「このまま採用」など Copy → $origPath |
                          | 消す     | バランスGUI DeleteImage/PhotosEdit、余白のみ成功、検証 delete、再分割成功、SKIP/ERROR 系、検証ブロック外の elseif 等 |
                          注意: 縦横比 GUI の「このまま採用」分岐は復元後に temp を即 Remove しない（continue）。残りは後段 cvr_* 一括削除に依存し得る。
                          最終網: フォルダ単位の cvr_* 一括削除（tempBackupOs と同じ後段）。
                        #>
                        $tempBackupB = Join-Path (Get-LiteralPathParent $origPath) ("cvr_retry_" + $baseNoExtBal + $ext)
                        Copy-Item -LiteralPath $origPath -Destination $tempBackupB -Force -ErrorAction SilentlyContinue
                        if (-not $useTocTrim) {
                            if ($useCachedGutterB) {
                                if ($true -eq $script:FlickFitDebugStep5Verbose) { Write-FlickFitHost "         📍 通常分割（のど位置を前回設定で自動適用）..." -ForegroundColor Gray }
                            } elseif ($splitMode -ne "split") {
                                # split 以外（例: trim_toc）では従来どおり案内
                                if ($true -eq $script:FlickFitDebugStep5Verbose) { Write-FlickFitHost "         📍 通常分割..." -ForegroundColor Gray }
                            }
                            # split かつキャッシュなし: のど・余白GUIが先に出るため「通常分割」とは書かない（誤解防止）
                        }
                        $cwM = $folderCoverWidth
                        if ($cwM -le 0) {
                            $dM = Get-ImageDimensions -Path $origPath
                            if ($dM.Width -gt 0) { $cwM = [Math]::Floor($dM.Width / 2); Write-FlickFitDebugStep5VerboseHost -Text "[DEBUG] 表紙幅未設定→元画像半分 $cwM px をフォールバック" }
                        } elseif ($folderCoverWidth -gt 0) { Write-FlickFitDebugStep5VerboseHost -Text "[DEBUG] 表紙幅=$folderCoverWidth px で分割・表紙比較を適用" -ForegroundColor DarkYellow }
                        try {
                            $bBalancedMarginTrimResultDone = $false
                            $balancedFreshGutterGuiUsed = $false
                            # BALANCED: 実入力パスと寸法（キャッシュ経路・GUI while・try 外の検証まで引き回し。GUI 内で $origPath / Apply 先が変わるたび再同期する）
                            $effectiveInputPathBal = [string]$origPath
                            $iszBalEntry = Get-FlickFitEffectiveInputSizePx -LiteralPath $effectiveInputPathBal
                            $effectiveInputWidthBal = $iszBalEntry.Width
                            $effectiveInputHeightBal = $iszBalEntry.Height
                            if ($useCachedGutterB) {
                                $lt = Get-HashtableInt -Tbl $cacheB -Key 'LeftTrimPx'
                                $rt = Get-HashtableInt -Tbl $cacheB -Key 'RightTrimPx'
                                $ttB = Get-HashtableInt -Tbl $cacheB -Key 'TopTrimPx'
                                $btB = Get-HashtableInt -Tbl $cacheB -Key 'BottomTrimPx'
                                $cacheUcB = Get-HashtableBool -Tbl $cacheB -Key 'MarginTrimWithoutSplit'
                                if ($cacheUcB) {
                                    if ($true -eq $script:FlickFitDebugStep5Verbose) { Write-FlickFitHost "         [キャッシュ] 余白のみトリム（分割なし）左=${lt}px 右=${rt}px 上=${ttB}px 下=${btB}px" -ForegroundColor DarkCyan }
                                    $vertBCrop = Repair-GutterVerticalMargins -ImgH $effectiveInputHeightBal -TopTrim $ttB -BottomTrim $btB
                                    $ltCropB = [Math]::Max(0, [int]$lt)
                                    $rtCropB = [Math]::Max(0, [int]$rt)
                                    $result = Invoke-PythonCropGuiMargins -WorkTrimSplitPy $workTrimSplitPy -ImagePath $effectiveInputPathBal -RightBinding $RightBinding -LeftTrim $ltCropB -TopTrim $vertBCrop.TopTrimPx -RightTrim $rtCropB -BottomTrim $vertBCrop.BottomTrimPx
                                    $bBalancedMarginTrimResultDone = $true
                                } else {
                                    $gxOldB = Get-HashtableInt -Tbl $cacheB -Key 'GutterX'
                                    $iwOldB = if ($cacheB.ImgW -gt 0) { [int]$cacheB.ImgW } else { $origW }
                                    $gPctB = 50.0
                                    $hasPctB = $false
                                    foreach ($ck in @($cacheB.Keys)) {
                                        if ([string]::Equals([string]$ck, 'GutterPct', [StringComparison]::OrdinalIgnoreCase)) {
                                            try { $gPctB = [Math]::Max(1, [Math]::Min(99, [double]$cacheB[$ck])); $hasPctB = $true; break } catch {}
                                        }
                                    }
                                    if (-not $hasPctB) {
                                        if (($lt -gt 0 -or $rt -gt 0) -and $gxOldB -le ($lt + 8)) {
                                            $gPctB = 50.0
                                            if ($true -eq $script:FlickFitDebugStep5Verbose) { Write-FlickFitHost "         [キャッシュ] 通常分割: のど${gxOldB}px が左余白付近→50%で再計算" -ForegroundColor Yellow }
                                        } else {
                                            $gPctB = [Math]::Max(1, [Math]::Min(99, 100.0 * $gxOldB / [double]$iwOldB))
                                        }
                                    }
                                    $gxEffB = [int]([Math]::Round($effectiveInputWidthBal * $gPctB / 100.0))
                                    $gxEffB = [Math]::Max(7, [Math]::Min($effectiveInputWidthBal - 8, $gxEffB))
                                }
                                if (-not $cacheUcB) {
                                    if ($true -eq $script:FlickFitDebugCachedBalBatch) {
                                        Write-FlickFitHost ("         [BATCH-DBG] balanced+cache split entry img={0} idx={1} enableBatch={2} marginTrimOnlyB={3}" -f $imgName, $imgIdx, $script:FlickFitEnableCachedBalBatch, $cacheUcB) -ForegroundColor DarkGray
                                    }
                                    $sizeKey = "$($dir)|${effectiveInputWidthBal}x${effectiveInputHeightBal}"
                                    $mm = if ($script:FolderMarginMode.ContainsKey($sizeKey)) { $script:FolderMarginMode[$sizeKey] } else { 'auto' }
                                    $useMarginsCachedOp = ($mm -eq 'gui' -and ($lt -gt 0 -or $rt -gt 0 -or $ttB -gt 0 -or $btB -gt 0))
                                    $cohB = $null
                                    if ($useMarginsCachedOp) {
                                        if ($true -eq $script:FlickFitDebugStep5Verbose) { Write-FlickFitHost "         [キャッシュ] 通常分割: のど=${gxEffB}px (${gPctB}%) 左=${lt}px 右=${rt}px 上=${ttB}px 下=${btB}px" -ForegroundColor DarkCyan }
                                        $cohB = Repair-GutterMarginGeometry -ImgW $effectiveInputWidthBal -GutterX $gxEffB -LeftTrim $lt -RightTrim $rt
                                        $vertB = Repair-GutterVerticalMargins -ImgH $effectiveInputHeightBal -TopTrim $ttB -BottomTrim $btB
                                        $ttB = $vertB.TopTrimPx; $btB = $vertB.BottomTrimPx
                                    }
                                    try { $normBalInp = [System.IO.Path]::GetFullPath($effectiveInputPathBal) } catch { $normBalInp = $effectiveInputPathBal }
                                    $normBalKeyEarly = Get-FlickFitStep5PathKey $normBalInp
                                    if (-not $normBalKeyEarly) { $normBalKeyEarly = $normBalInp }
                                    $output = $null
                                    $cachedBalUsedPython = $false
                                    $bfPaths = [string[]]@()
                                    if ($script:FlickFitCachedBalBatchResultByPath -and $script:FlickFitCachedBalBatchResultByPath.ContainsKey($normBalKeyEarly)) {
                                        $cachedBalLineQ = [string]$script:FlickFitCachedBalBatchResultByPath[$normBalKeyEarly]
                                        [void]$script:FlickFitCachedBalBatchResultByPath.Remove($normBalKeyEarly)
                                        $output = @($cachedBalLineQ)
                                        $cachedBalUsedPython = $true
                                    } elseif ($true -eq $script:FlickFitEnableCachedBalBatch -or $true -eq $script:FlickFitDebugCachedBalBatch) {
                                        $balScanCtx = Get-FlickFitCachedBalBatchScanContext -DirPath $dir -CurrentFileFullPath $effectiveInputPathBal -LoopImgs $imgs -LoopImgIdx $imgIdx
                                        if ($true -eq $script:FlickFitDebugCachedBalBatch) {
                                            Write-FlickFitHost ("         [BATCH-DBG] scanCtx source={0} imgsCount={1} startIdx={2}" -f $balScanCtx.Source, @($balScanCtx.Imgs).Count, $balScanCtx.StartIdx) -ForegroundColor DarkGray
                                        }
                                        if ($true -eq $script:FlickFitDebugCachedBalBatch) {
                                            Write-FlickFitHost ("         [BATCH-DBG] probe batch_split_at_gutter forward-scan loopIdx={0} file={1}" -f $imgIdx, $imgName) -ForegroundColor DarkGray
                                        }
                                        $scanBalForward = @($balScanCtx.Imgs)
                                        for ($fi = $balScanCtx.StartIdx; $fi -lt $scanBalForward.Count; $fi++) {
                                            $fillIm = $scanBalForward[$fi]
                                            if (-not $fillIm -or -not $fillIm.FullName) { continue }
                                            if ($null -ne (Resolve-FlickFitStep5AnalyzeForPath -ByPath $Step5OneSidedAnalyze -FullPath $fillIm.FullName)) { continue }
                                            $kf = Get-FlickFitStep5PathKey $fillIm.FullName
                                            if ($kf) { $Step5OneSidedAnalyze[$kf] = 'BALANCED' }
                                        }
                                        $bfPaths = @(Get-FlickFitCachedBalBatchForwardPaths -StartIdx $balScanCtx.StartIdx -Imgs $balScanCtx.Imgs -ExpectW $effectiveInputWidthBal -ExpectH $effectiveInputHeightBal -CacheB $cacheB -Step5OneSidedByPath $Step5OneSidedAnalyze -FolderTocPaths $folderTocPaths -SkipAvif:$script:SkipAVIF)
                                        if ($true -eq $script:FlickFitDebugCachedBalBatch) {
                                            $ct = if ($bfPaths.Count -gt 0) { $bfPaths[0].GetType().FullName } else { 'n/a' }
                                            Write-FlickFitHost ("         [BATCH-DBG] caller bfPaths count={0} idx0Type={1}" -f $bfPaths.Count, $ct) -ForegroundColor DarkGray
                                        }
                                        if ($true -eq $script:FlickFitDebugCachedBalBatch) {
                                            Write-FlickFitHost ("         [BATCH-DBG] forwardPaths={0} img={1} marginsGui={2} effWH={3}x{4}" -f $bfPaths.Count, $imgName, $useMarginsCachedOp, $effectiveInputWidthBal, $effectiveInputHeightBal) -ForegroundColor DarkGray
                                        }
                                        if ($bfPaths.Count -ge 2 -and ($true -eq $script:FlickFitEnableCachedBalBatch)) {
                                            $jobsArr = [System.Collections.Generic.List[hashtable]]::new()
                                            foreach ($bp in $bfPaths) {
                                                if ($useMarginsCachedOp -and $null -ne $cohB) {
                                                    [void]$jobsArr.Add(@{
                                                        op          = 'split_at_gutter_with_margins'
                                                        input       = $bp
                                                        gutter_x    = [int]$cohB.GutterX
                                                        left_trim   = [int]$cohB.LeftTrimPx
                                                        right_trim  = [int]$cohB.RightTrimPx
                                                        top_trim    = [int]$ttB
                                                        bottom_trim = [int]$btB
                                                        aspect_min  = [double]$aspectMin
                                                        cover_width = [int]$cwM
                                                    })
                                                } else {
                                                    [void]$jobsArr.Add(@{
                                                        op               = 'split_at_gutter'
                                                        input            = $bp
                                                        gutter_x         = [int]$gxEffB
                                                        no_trim          = $false
                                                        aspect_min       = [double]$aspectMin
                                                        cover_width      = [int]$cwM
                                                        no_vertical_trim = $true
                                                        gui_exact        = $false
                                                    })
                                                }
                                            }
                                            $specObj = [ordered]@{ right_binding = [bool]$RightBinding; jobs = @($jobsArr.ToArray()) }
                                            $jsonBatch = $specObj | ConvertTo-Json -Depth 14 -Compress
                                            $jsonPathFb = $null
                                            try {
                                                $jsonPathFb = Join-Path (Get-FlickFitScratchTempDir) ('ff_batch_split_' + [Guid]::NewGuid().ToString('N').Substring(0, 8) + '.json')
                                                $utf8n = New-Object System.Text.UTF8Encoding($false)
                                                [System.IO.File]::WriteAllText($jsonPathFb, $jsonBatch, $utf8n)
                                                Write-FlickFitHost ("         [STEP5] キャッシュ分割を batch_split_at_gutter にまとめます: {0} 件" -f $bfPaths.Count) -ForegroundColor Cyan
                                                $rawBatchPyOut = @(Invoke-FlickFitBatchSplitAtGutterJson -WorkTrimSplitPy $workTrimSplitPy -RightBinding $RightBinding -JsonPath $jsonPathFb)
                                                $batchLineList = [System.Collections.Generic.List[string]]::new()
                                                foreach ($ro in $rawBatchPyOut) {
                                                    $chunk = "$ro"
                                                    if ([string]::IsNullOrWhiteSpace($chunk)) { continue }
                                                    foreach ($line in $chunk -split "`r?`n") {
                                                        $lt = $line.Trim()
                                                        if ($lt.Length -ge 2 -and $lt[0] -eq '{') { [void]$batchLineList.Add($lt) }
                                                    }
                                                }
                                                try {
                                                    $rbLog = Join-Path (Get-FlickFitScratchTempDir) ('ff_batch_split_raw_' + [Guid]::NewGuid().ToString('N').Substring(0, 8) + '.log')
                                                    $u8rb = New-Object System.Text.UTF8Encoding($false)
                                                    [System.IO.File]::WriteAllText($rbLog, (($rawBatchPyOut | ForEach-Object { "$_" }) -join [Environment]::NewLine), $u8rb)
                                                    if ($true -eq $script:FlickFitDebugCachedBalBatch) {
                                                        Write-FlickFitHost ("         [BATCH-DBG] batch 生 stdout: {0} （チャンク数={1} JSON行={2}）" -f $rbLog, $rawBatchPyOut.Count, $batchLineList.Count) -ForegroundColor DarkGray
                                                    }
                                                } catch { }
                                                $okAllFb = $true
                                                $resMapFb = @{}
                                                foreach ($lb in $batchLineList) {
                                                    $lnT = "$lb".Trim()
                                                    if (-not $lnT) { continue }
                                                    try {
                                                        $rec = $lnT | ConvertFrom-Json
                                                        $ipRaw = [string]$rec.input
                                                        $ipK = Get-FlickFitStep5PathKey $ipRaw
                                                        if (-not $ipK) { $ipK = try { [System.IO.Path]::GetFullPath($ipRaw) } catch { $ipRaw } }
                                                        $rsRaw = $rec.result
                                                        $rs = if ($null -eq $rsRaw) { '' } elseif ($rsRaw -is [string]) { $rsRaw } else { [string]$rsRaw }
                                                        $okRec = $true
                                                        foreach ($propOk in $rec.PSObject.Properties) {
                                                            if ($propOk.Name -ceq 'ok') { $okRec = [bool]$propOk.Value; break }
                                                        }
                                                        if (-not $okRec) { $okAllFb = $false; break }
                                                        if ($rs.StartsWith('ERROR')) { $okAllFb = $false; break }
                                                        $resMapFb[$ipK] = $rs
                                                    } catch {
                                                        $okAllFb = $false
                                                        break
                                                    }
                                                }
                                                $normBalKeyFb = Get-FlickFitStep5PathKey $normBalInp
                                                if (-not $normBalKeyFb) { $normBalKeyFb = $normBalInp }
                                                $batchFirstKey = $null
                                                if ($bfPaths.Count -gt 0) {
                                                    $batchFirstKey = Get-FlickFitStep5PathKey ([string]$bfPaths[0])
                                                    if (-not $batchFirstKey) { $batchFirstKey = try { [System.IO.Path]::GetFullPath([string]$bfPaths[0]) } catch { [string]$bfPaths[0] } }
                                                }
                                                $pickCurKey = $null
                                                foreach ($cand in @($batchFirstKey, $normBalKeyFb)) {
                                                    if (-not $cand) { continue }
                                                    if ($resMapFb.ContainsKey($cand)) { $pickCurKey = $cand; break }
                                                }
                                                if (-not $pickCurKey) {
                                                    foreach ($cand in @($batchFirstKey, $normBalKeyFb)) {
                                                        if (-not $cand) { continue }
                                                        foreach ($mk in $resMapFb.Keys) {
                                                            if ([string]::Equals([string]$mk, $cand, [StringComparison]::OrdinalIgnoreCase)) { $pickCurKey = [string]$mk; break }
                                                        }
                                                        if ($pickCurKey) { break }
                                                    }
                                                }
                                                $wantBatchMapDbg = ($true -eq $script:FlickFitDebugCachedBalBatch)
                                                if ($wantBatchMapDbg) {
                                                    Write-FlickFitHost ("         [BATCH-DBG] resultMap count={0} hasNormKey={1} hasFirstKey={2} pickCurKeySet={3}" -f $resMapFb.Count, $resMapFb.ContainsKey($normBalKeyFb), ($batchFirstKey -and $resMapFb.ContainsKey($batchFirstKey)), [bool]$pickCurKey) -ForegroundColor DarkGray
                                                    Write-FlickFitHost ("         [BATCH-DBG] lookup normBalKeyFb={0} batchFirstKey={1} effPath={2} origPath={3}" -f $normBalKeyFb, $batchFirstKey, $effectiveInputPathBal, $origPath) -ForegroundColor DarkGray
                                                    $sampK = @($resMapFb.Keys | Select-Object -First 3)
                                                    foreach ($sk in $sampK) {
                                                        Write-FlickFitHost "         [BATCH-DBG] resultMap sampleKey=$sk" -ForegroundColor DarkGray
                                                    }
                                                }
                                                if ($okAllFb -and $resMapFb.Count -eq $bfPaths.Count -and $pickCurKey) {
                                                    if (-not $script:FlickFitCachedBalBatchResultByPath) { $script:FlickFitCachedBalBatchResultByPath = @{} }
                                                    foreach ($rk in $resMapFb.Keys) {
                                                        $script:FlickFitCachedBalBatchResultByPath[$rk] = $resMapFb[$rk]
                                                    }
                                                    $cachedBalLine0 = [string]$script:FlickFitCachedBalBatchResultByPath[$pickCurKey]
                                                    [void]$script:FlickFitCachedBalBatchResultByPath.Remove($pickCurKey)
                                                    $script:FlickFitFatalBatchSplitAbort = $false
                                                    $output = @($cachedBalLine0)
                                                    $cachedBalUsedPython = $true
                                                }
                                            } catch {
                                                Write-FlickFitHost ("         [致命的] batch_split_at_gutter 呼び出し例外: {0}" -f $_.Exception.Message) -ForegroundColor Red
                                                $script:FlickFitFatalBatchSplitAbort = $true
                                                throw
                                            } finally {
                                                if ($jsonPathFb -and (Test-Path -LiteralPath $jsonPathFb)) { Remove-Item -LiteralPath $jsonPathFb -Force -ErrorAction SilentlyContinue }
                                            }
                                        }
                                        if (($true -eq $script:FlickFitEnableCachedBalBatch) -and ($bfPaths.Count -ge 2) -and (-not $cachedBalUsedPython)) {
                                            Write-FlickFitHost "         [致命的] batch_split_at_gutter をまとめ実行したが成功結果を反映できません（Python が部分処理した可能性）。1枚フォールバックは日本語パス等で二次被害の恐れがあるため中断します。" -ForegroundColor Red
                                            $script:FlickFitFatalBatchSplitAbort = $true
                                            throw [System.InvalidOperationException]::new('FlickFit: batch_split_at_gutter が不完全です。フォルダを確認のうえ、この巻を最初からやり直してください。')
                                        }
                                        if ($bfPaths.Count -lt 2) {
                                            $br = $script:FlickFitCachedBalBatchLastBreak
                                            if ([string]::IsNullOrWhiteSpace($br)) {
                                                $br = if ($bfPaths.Count -eq 0) { 'no_paths' } else { 'only_one_forward' }
                                            }
                                            if ($true -eq $script:FlickFitDebugCachedBalBatch) {
                                                Write-FlickFitHost ("         [BATCH-DBG] batch_split skip: paths={0} break={1} scanStartIdx={2} loopIdx={3} file={4}" -f $bfPaths.Count, $br, $balScanCtx.StartIdx, $imgIdx, $imgName) -ForegroundColor DarkGray
                                            }
                                        }
                                    }
                                    if (-not $cachedBalUsedPython) {
                                        if ($useMarginsCachedOp) {
                                            $output = & $script:PythonExe $workTrimSplitPy $effectiveInputPathBal $RightBinding.ToString() "split_at_gutter_with_margins" "-" $cohB.GutterX $cohB.LeftTrimPx $cohB.RightTrimPx $aspectMin $cwM $ttB $btB 2>&1
                                        } else {
                                            # AUTOモード: ノド位置のみ再利用し、左右余白は通常の自動トリム
                                            $output = & $script:PythonExe $workTrimSplitPy $effectiveInputPathBal $RightBinding.ToString() "split_at_gutter" "false" $gxEffB $aspectMin $cwM "true" 2>&1
                                        }
                                    }
                                    Write-FlickFitPythonDebugLines -Lines @($output)
                                }
                            } elseif ($splitMode -eq "split") {
                                # キャッシュなしのバランス型: いきなり Python 自動分割しない。先にノド・余白GUI（キャンセル時のみ [1]自動/[4]再GUI/[S]スキップ）
                                $balGuiLoop = $true
                                while ($balGuiLoop) {
                                    $gutterEntryBal = [string]$entryPathStep5
                                    $effectiveInputPathBal = [string]$entryPathStep5
                                    $iszBalLoop = Get-FlickFitEffectiveInputSizePx -LiteralPath $effectiveInputPathBal
                                    $effectiveInputWidthBal = $iszBalLoop.Width
                                    $effectiveInputHeightBal = $iszBalLoop.Height
                                    $cacheSnapBalAuto = $null
                                    if ($script:FolderGutterCache -and $script:FolderGutterCache.ContainsKey($dir)) {
                                        $cacheSnapBalAuto = $script:FolderGutterCache[$dir]
                                    }
                                    $balAutoDec = Get-FlickFitBalancedAutoGutterDecision -FolderCacheSnap $cacheSnapBalAuto -EffectiveW $effectiveInputWidthBal -EffectiveH $effectiveInputHeightBal
                                    $allPathsBal = @($imgs | ForEach-Object { $_.FullName })
                                    if ($balAutoDec.ShouldSkipGui) {
                                        if ($true -eq $script:FlickFitDebugStep5Verbose) {
                                            Write-FlickFitHost "[AutoGutter] balanced skip_gui=True reason=$($balAutoDec.Reason) gutter=$($balAutoDec.SuggestedGutterX) img=${effectiveInputWidthBal}x${effectiveInputHeightBal} file=$imgName" -ForegroundColor DarkCyan
                                        }
                                        $guiBal = New-FlickFitAutoGutterGuiResult -GutterX $balAutoDec.SuggestedGutterX
                                    } else {
                                        if ($null -ne $cacheSnapBalAuto -and ($true -eq $script:FlickFitDebugStep5Verbose)) {
                                            Write-FlickFitHost "[AutoGutter] balanced skip_gui=False reason=$($balAutoDec.Reason) file=$imgName" -ForegroundColor DarkGray
                                        }
                                        $balReasonJa = Get-FlickFitBalancedAutoGutterReasonJa -Reason ([string]$balAutoDec.Reason)
                                        if ($balReasonJa -and ($true -eq $script:FlickFitDebugStep5Verbose)) { Write-FlickFitHost "         $balReasonJa" -ForegroundColor Yellow }
                                        Write-FlickFitHost "`n         📎 バランス型見開き: $imgName → ノド/余白をGUIで設定してください（キャンセルでメニュー）" -ForegroundColor Cyan
                                        Write-FlickFitStep5EntryDebug -Label 'bal-before' -EntryPath $entryPathStep5 -PreviewPath $gutterEntryBal -ApplyPath $origPath -ImgIdx $imgIdx -ImgsCount $imgs.Count
                                        $guiBal = Show-GutterMarginSetGui -ImagePath $gutterEntryBal -Title "見開き（バランス型）: ノドと左右余白の設定 - ここで分割します" -AllImagePaths $allPathsBal -OkAppliesToCurrentView -ShowApplyThisPageOnlyButton
                                    }
                                    if ($guiBal -is [System.Collections.IDictionary]) { $guiBal = Normalize-GutterGuiResult -GuiResult $guiBal }
                                    $imgs = Update-ImgsAfterMarginGui -Imgs $imgs -GuiResult $guiBal
                                    if (Test-GuiMarginFlagTrue -Tbl $guiBal -Key 'ApplyOnlyThisSpread') {
                                        $script:SplitWidthApplyGutterOnlyThisPage = $true
                                    }
                                    $navBal = Get-FlickFitGutterEntryAfterNavGui -EntryPath $gutterEntryBal -EntryName ([System.IO.Path]::GetFileName($gutterEntryBal)) -GuiResult $guiBal
                                    if ($null -ne $navBal) { $origPath = $navBal.OrigPath; $imgName = $navBal.ImgName; $ext = $navBal.Ext }
                                    Write-FlickFitStep5EntryDebug -Label 'bal-after' -EntryPath $entryPathStep5 -GuiResult $guiBal -ApplyPath $origPath -ImgIdx $imgIdx -ImgsCount $imgs.Count
                                    if (Test-GuiMarginFlagTrue -Tbl $guiBal -Key 'DeleteImage') {
                                        $imgs = @(Get-ProcessableFolderImages -FolderPath $dir)
                                        if (Test-Path -LiteralPath $tempBackupB) { Remove-Item -LiteralPath $tempBackupB -Force -ErrorAction SilentlyContinue }
                                        $processedImages++
                                        $imgIdx++
                                        $balGuiLoop = $false
                                        $output = @('BAL_DELETE_CONTINUE')
                                        break
                                    }
                                    if (Test-GuiMarginFlagTrue -Tbl $guiBal -Key 'PhotosEdit') {
                                        $dPhBal = Get-ImageDimensions -Path $origPath
                                        if ($dPhBal.Width -gt 0) { $folderCoverWidth = $dPhBal.Width }
                                        Write-FlickFitHost "         ✅ フォトで編集した画像を採用（以降のトリミング基準に使用）" -ForegroundColor Green
                                        $folderSplit += 1
                                        $splitImages += 1
                                        if (Test-Path -LiteralPath $tempBackupB) { Remove-Item -LiteralPath $tempBackupB -Force -ErrorAction SilentlyContinue }
                                        $processedImages++
                                        $imgIdx++
                                        $balGuiLoop = $false
                                        $output = @('BAL_PHOTOS_CONTINUE')
                                        break
                                    }
                                    $gxBal = if ($null -ne $guiBal) { Get-HashtableInt -Tbl $guiBal -Key 'GutterX' -Default (-1) } else { -1 }
                                    if ($gxBal -ge 0) {
                                        $lockBal = Get-FlickFitGutterGuiSplitPathLockedToEntry -EntryPath $gutterEntryBal -GuiResult $guiBal
                                        if ($lockBal.Scaled) { $guiBal = $lockBal.GuiTweak; $gxBal = Get-HashtableInt -Tbl $guiBal -Key 'GutterX' -Default (-1) }
                                        $splitPathB = $lockBal.Path
                                        if (-not [string]::Equals($origPath, $splitPathB, [StringComparison]::OrdinalIgnoreCase)) {
                                            $origPath = $splitPathB
                                            $imgName = [System.IO.Path]::GetFileName($origPath)
                                            $ext = [System.IO.Path]::GetExtension($origPath).ToLower()
                                        }
                                        $iszBalGui = Get-FlickFitEffectiveInputSizePx -LiteralPath $splitPathB
                                        if ($iszBalGui.Width -gt 0 -and $iszBalGui.Height -gt 0) { $origW = $iszBalGui.Width; $origH = $iszBalGui.Height } else { $origW = 0; $origH = 0 }
                                        $effectiveInputPathBal = [string]$splitPathB
                                        $effectiveInputWidthBal = $iszBalGui.Width
                                        $effectiveInputHeightBal = $iszBalGui.Height
                                        $ltB = Get-HashtableInt -Tbl $guiBal -Key 'LeftTrimPx'
                                        $rtB = Get-HashtableInt -Tbl $guiBal -Key 'RightTrimPx'
                                        $ttB = Get-HashtableInt -Tbl $guiBal -Key 'TopTrimPx'
                                        $btB = Get-HashtableInt -Tbl $guiBal -Key 'BottomTrimPx'
                                        $gutterXB = $gxBal
                                        $cwBal = $folderCoverWidth
                                        if ($cwBal -le 0 -and $iszBalGui.Width -gt 0) { $cwBal = [Math]::Floor($iszBalGui.Width / 2) }
                                        $mtOnlyB = Get-HashtableBool -Tbl $guiBal -Key 'MarginTrimWithoutSplit'
                                        if ($true -eq $script:FlickFitDebugStep5Entry) {
                                            $apGuiBal = if ($null -ne $guiBal -and $guiBal -is [System.Collections.IDictionary]) { Get-HashtableTrimmedString -Tbl $guiBal -Key 'ApplyImagePath' } else { '' }
                                            if (-not $apGuiBal) { $apGuiBal = '-' }
                                            $brB = if ($mtOnlyB) { 'trim_only_margins' } elseif ($ltB -gt 0 -or $rtB -gt 0 -or $ttB -gt 0 -or $btB -gt 0) { 'split_at_gutter_with_margins' } else { 'split_at_gutter' }
                                            Write-FlickFitHost ("[STEP5GuiApply] entry={0} lockSplitPath={1} origPath={2} apGui={3} eff={4}x{5} lockScaled={6} gx={7} mtOnly={8} branch={9} LTRB={10}/{11}/{12}/{13}" -f $entryPathStep5, $splitPathB, $origPath, $apGuiBal, $effectiveInputWidthBal, $effectiveInputHeightBal, $lockBal.Scaled, $gxBal, $mtOnlyB, $brB, $ltB, $rtB, $ttB, $btB) -ForegroundColor Cyan
                                        }
                                        try {
                                            if ($mtOnlyB) {
                                                if ($true -eq $script:FlickFitDebugStep5Verbose) { Write-FlickFitHost "         [余白のみ・分割なし] 左=${ltB}px 右=${rtB}px 上=${ttB}px 下=${btB}px (バランス型GUI→Python)" -ForegroundColor DarkCyan }
                                                $vertBal = Repair-GutterVerticalMargins -ImgH $effectiveInputHeightBal -TopTrim $ttB -BottomTrim $btB
                                                $cropBal = Invoke-PythonCropGuiMargins -WorkTrimSplitPy $workTrimSplitPy -ImagePath $effectiveInputPathBal -RightBinding $RightBinding -LeftTrim $ltB -TopTrim $vertBal.TopTrimPx -RightTrim $rtB -BottomTrim $vertBal.BottomTrimPx
                                                $ttB = $vertBal.TopTrimPx
                                                $btB = $vertBal.BottomTrimPx
                                                $output = @($cropBal)
                                            } elseif ($ltB -gt 0 -or $rtB -gt 0 -or $ttB -gt 0 -or $btB -gt 0) {
                                                if ($true -eq $script:FlickFitDebugStep5Verbose) { Write-FlickFitHost "         [余白・ノド] のど=${gutterXB}px 左=${ltB}px 右=${rtB}px 上=${ttB}px 下=${btB}px (バランス型GUI→Python)" -ForegroundColor DarkCyan }
                                                $cohBal = Repair-GutterMarginGeometry -ImgW $effectiveInputWidthBal -GutterX $gutterXB -LeftTrim $ltB -RightTrim $rtB
                                                $gutterXB = $cohBal.GutterX; $ltB = $cohBal.LeftTrimPx; $rtB = $cohBal.RightTrimPx
                                                $vertBal2 = Repair-GutterVerticalMargins -ImgH $effectiveInputHeightBal -TopTrim $ttB -BottomTrim $btB
                                                $ttB = $vertBal2.TopTrimPx; $btB = $vertBal2.BottomTrimPx
                                                $output = @(& $script:PythonExe $workTrimSplitPy $effectiveInputPathBal $RightBinding.ToString() "split_at_gutter_with_margins" "-" $gutterXB $ltB $rtB $aspectMin $cwBal $ttB $btB 2>&1 | ForEach-Object { "$_" })
                                            } else {
                                                $output = @(& $script:PythonExe $workTrimSplitPy $effectiveInputPathBal $RightBinding.ToString() "split_at_gutter" "false" $gutterXB $aspectMin $cwBal "false" "true" 2>&1 | ForEach-Object { "$_" })
                                            }
                                            if (-not $mtOnlyB) {
                                                Write-FlickFitPythonDebugLines -Lines @($output)
                                            }
                                        } catch {
                                            $output = @("ERROR:$($_.Exception.Message)")
                                        }
                                        $joinedBal = ($output | ForEach-Object { "$_" }) -join ""
                                        if (Test-FlickFitStep5StringLooksLikeResultError -S ([string]$joinedBal)) {
                                            $actInner = Get-FlickFitStep5RetryAction -Path $entryPathStep5 -MaxRetryBeforeFallback 2
                                            # 1〜2 回目: 再GUI。3 回目: 無限ループ防止の trim_only
                                            if ($actInner -eq 'fallback') {
                                                Write-FlickFitWarning "同一画像で ERROR が3回連続したため trim_only にフォールバックします ($imgName)"
                                                if (Test-Path -LiteralPath $tempBackupB) { Copy-Item -LiteralPath $tempBackupB -Destination $entryPathStep5 -Force -ErrorAction SilentlyContinue }
                                                $origPath = $entryPathStep5
                                                $imgName = $entryNameStep5
                                                if (Test-Path -LiteralPath $entryPathStep5) { $ext = [System.IO.Path]::GetExtension($entryPathStep5).ToLower() }
                                                try {
                                                    $ftFall = (Invoke-PythonTimed -Category "PythonTrim" -PythonArgs $workTrimSplitPy, $entryPathStep5, $RightBinding.ToString(), "trim_only", "", $aspectMin) -join ""
                                                    if ($ftFall -match "TRIMMED:1") {
                                                        Write-FlickFitHost "         ✅ trim_only フォールバック成功（1枚）" -ForegroundColor DarkCyan
                                                    } else {
                                                        Write-FlickFitHost "         ⚠ trim_only フォールバック: $ftFall" -ForegroundColor Yellow
                                                    }
                                                } catch { Write-FlickFitHost "         ⚠ trim_only フォールバック失敗: $($_.Exception.Message)" -ForegroundColor Yellow }
                                                Add-FlickFitRetrimCandidate -VolFolder $dir -FilePath $entryPathStep5 -Reason 'bal_trim_err_fallback' -PageLabel $imgName
                                                if (Test-Path -LiteralPath $tempBackupB) { Remove-Item -LiteralPath $tempBackupB -Force -ErrorAction SilentlyContinue }
                                                $folderSplit += 1
                                                $splitImages += 1
                                                $processedImages++
                                                $imgIdx++
                                                $balGuiLoop = $false
                                                $output = @('BAL_TRIM_ERR_FALLBACK')
                                                break
                                            }
                                            Write-FlickFitHost "         ⚠ GUI後の適用に失敗しました。元画像を復元し、ノド/余白を再設定してください" -ForegroundColor Yellow
                                            if (Test-Path -LiteralPath $tempBackupB) {
                                                Copy-Item -LiteralPath $tempBackupB -Destination $entryPathStep5 -Force -ErrorAction SilentlyContinue
                                            }
                                            $origPath = $entryPathStep5
                                            $imgName = $entryNameStep5
                                            if (Test-Path -LiteralPath $entryPathStep5) { $ext = [System.IO.Path]::GetExtension($entryPathStep5).ToLower() }
                                            continue
                                        }
                                        if ($mtOnlyB -and $joinedBal -match "TRIMMED:1") {
                                            $iszRefBalMt = Get-FlickFitEffectiveInputSizePx -LiteralPath $effectiveInputPathBal
                                            $raB = 0; $rwB = 0
                                            if ($iszRefBalMt.Width -gt 0 -and $iszRefBalMt.Height -gt 0) { $raB = $iszRefBalMt.Width / $iszRefBalMt.Height; $rwB = $iszRefBalMt.Width }
                                            $skB1 = (Get-Variable -Name SplitWidthApplyGutterOnlyThisPage -Scope Script -ErrorAction SilentlyContinue) -and $script:SplitWidthApplyGutterOnlyThisPage
                                            if ($skB1) { $script:SplitWidthApplyGutterOnlyThisPage = $false } else {
                                                $script:FolderGutterCache[$dir] = New-FlickFitFolderGutterCacheEntry -GutterX $gutterXB -GutterPct 50.0 -LeftTrimPx $ltB -RightTrimPx $rtB -TopTrimPx $ttB -BottomTrimPx $btB -ImgW $effectiveInputWidthBal -ImgH $effectiveInputHeightBal -RefAspect $raB -RefWidth $rwB -MarginTrimWithoutSplit $true
                                            }
                                            $szKB = "$($dir)|${effectiveInputWidthBal}x${effectiveInputHeightBal}"
                                            if (-not $script:FolderMarginMode.ContainsKey($szKB)) { $script:FolderMarginMode[$szKB] = 'gui' }
                                            Write-FlickFitHost "         ✅ 余白のみトリミングしました（1枚のまま、以降同サイズは自動適用）" -ForegroundColor DarkGreen
                                            $folderSplit += 1
                                            $splitImages += 1
                                            if (Test-Path -LiteralPath $tempBackupB) { Remove-Item -LiteralPath $tempBackupB -Force -ErrorAction SilentlyContinue }
                                            $processedImages++
                                            $imgIdx++
                                            $balGuiLoop = $false
                                            $output = @('BAL_MARGIN_DONE')
                                            break
                                        }
                                        if ($joinedBal -match "SPLIT:2") {
                                            $extSb = [System.IO.Path]::GetExtension($splitPathB).ToLower()
                                            $baseSb = [System.IO.Path]::GetFileNameWithoutExtension($splitPathB)
                                            $so1chk = Join-Path (Get-LiteralPathParent $splitPathB) ($baseSb + "_1" + $extSb)
                                            $refAspBal = 0; $refWBal = 0
                                            if (Test-Path -LiteralPath $so1chk) {
                                                $drb = Get-ImageDimensions -Path $so1chk
                                                if ($drb.Width -gt 0 -and $drb.Height -gt 0) { $refAspBal = $drb.Width / $drb.Height; $refWBal = $drb.Width }
                                            }
                                            $gpBal = 50.0
                                            if ($null -ne $guiBal -and $guiBal -is [System.Collections.IDictionary]) {
                                                foreach ($gk in @($guiBal.Keys)) {
                                                    if ([string]::Equals([string]$gk, 'GutterPct', [StringComparison]::OrdinalIgnoreCase)) {
                                                        try { $gpBal = [Math]::Max(1, [Math]::Min(99, [double]$guiBal[$gk])); break } catch {}
                                                    }
                                                }
                                            }
                                            if ($gpBal -eq 50.0 -and $effectiveInputWidthBal -gt 0) { $gpBal = [Math]::Round(100.0 * $gutterXB / $effectiveInputWidthBal, 2) }
                                            $ucsBal = Get-HashtableBool -Tbl $guiBal -Key 'MarginTrimWithoutSplit'
                                            $skB2 = (Get-Variable -Name SplitWidthApplyGutterOnlyThisPage -Scope Script -ErrorAction SilentlyContinue) -and $script:SplitWidthApplyGutterOnlyThisPage
                                            if ($skB2) {
                                                $script:SplitWidthApplyGutterOnlyThisPage = $false
                                                $script:SplitWidthSkipRepeatGuiApplyOnlyThisPage = $true
                                            } else {
                                                $script:FolderGutterCache[$dir] = New-FlickFitFolderGutterCacheEntry -GutterX $gutterXB -GutterPct $gpBal -LeftTrimPx $ltB -RightTrimPx $rtB -TopTrimPx $ttB -BottomTrimPx $btB -ImgW $effectiveInputWidthBal -ImgH $effectiveInputHeightBal -RefAspect $refAspBal -RefWidth $refWBal -MarginTrimWithoutSplit $ucsBal
                                            }
                                            $szKB2 = "$($dir)|${effectiveInputWidthBal}x${effectiveInputHeightBal}"
                                            if (-not $script:FolderMarginMode.ContainsKey($szKB2)) { $script:FolderMarginMode[$szKB2] = 'gui' }
                                        }
                                        if (-not [string]::Equals($splitPathB, $origPath, [StringComparison]::OrdinalIgnoreCase)) {
                                            $origPath = $splitPathB
                                            $ext = [System.IO.Path]::GetExtension($splitPathB).ToLower()
                                            $imgName = [System.IO.Path]::GetFileName($splitPathB)
                                        }
                                        $balancedFreshGutterGuiUsed = $true
                                        $balGuiLoop = $false
                                        break
                                    }
                                    Write-FlickFitHost "         （キャンセルまたは無効） [1] Python自動分割（従来）  [4] GUIを再度開く  [S] この画像をスキップ" -ForegroundColor DarkGray
                                    $chBal = Read-HostWithEsc "         [バランス型見開き]"
                                    if ($chBal -match '^[sS]$') {
                                        $output = @("SKIP:balanced_user")
                                        $balGuiLoop = $false
                                        break
                                    }
                                    if ($chBal -eq '1') {
                                        $output = @(& $script:PythonExe $workTrimSplitPy $effectiveInputPathBal $RightBinding.ToString() $splitMode "true" $aspectMin $cwM 2>&1)
                                        $balGuiLoop = $false
                                        break
                                    }
                                    # 4 または空: GUI を再表示
                                }
                                if (($output.Count -eq 1) -and ($output[0] -eq 'BAL_DELETE_CONTINUE')) {
                                    continue
                                }
                                if (($output.Count -eq 1) -and ($output[0] -eq 'BAL_PHOTOS_CONTINUE')) {
                                    continue
                                }
                                if (($output.Count -eq 1) -and ($output[0] -eq 'BAL_MARGIN_DONE')) {
                                    continue
                                }
                                if (($output.Count -eq 1) -and ($output[0] -eq 'BAL_TRIM_ERR_FALLBACK')) {
                                    continue
                                }
                            } else {
                                $output = & $script:PythonExe $workTrimSplitPy $effectiveInputPathBal $RightBinding.ToString() $splitMode "" $aspectMin $aspectRef $cwM 2>&1
                            }
                            if (-not $bBalancedMarginTrimResultDone) {
                                $result = ($output | ForEach-Object { "$_" }) -join ""
                            }
                        } catch {
                            if ($true -eq $script:FlickFitFatalBatchSplitAbort) { throw }
                            $result = "ERROR:$($_.Exception.Message)"
                        }
                        $effectiveInputPathBal = [string]$origPath
                        $iszBalPostTry = Get-FlickFitEffectiveInputSizePx -LiteralPath $effectiveInputPathBal
                        $effectiveInputWidthBal = $iszBalPostTry.Width
                        $effectiveInputHeightBal = $iszBalPostTry.Height
                        Ensure-FlickFitStep5ErrorRetryCount
                        $ek5 = Get-FlickFitStep5ErrorRetryKey -Path $entryPathStep5
                        if ($result -and -not (Test-FlickFitStep5StringLooksLikeResultError -S ([string]$result)) -and -not [string]::IsNullOrWhiteSpace($ek5) -and $script:Step5ErrorRetryCount.ContainsKey($ek5)) { [void]$script:Step5ErrorRetryCount.Remove($ek5) }
                        if ($result -match "TRIMMED:1" -and $useCachedGutterB -and (Get-HashtableBool -Tbl $cacheB -Key 'MarginTrimWithoutSplit')) {
                            Write-FlickFitHost "         ✅ キャッシュどおり余白のみトリミングしました（1枚のまま）" -ForegroundColor DarkGreen
                            $folderSplit += 1
                            $splitImages += 1
                            if (Test-Path -LiteralPath $tempBackupB) { Remove-Item -LiteralPath $tempBackupB -Force -ErrorAction SilentlyContinue }
                            $processedImages++
                            $imgIdx++
                            continue
                        }
                        if ($result -match "SPLIT:2") {
                            $so1b = Join-Path (Get-LiteralPathParent $origPath) ([System.IO.Path]::GetFileNameWithoutExtension($origPath) + "_1" + $ext)
                            $so2b = Join-Path (Get-LiteralPathParent $origPath) ([System.IO.Path]::GetFileNameWithoutExtension($origPath) + "_2" + $ext)
                            # 縦横比警告〜その後の再分割では、FolderGutterCache 等がまだ $origW/$origH 更新に寄っている箇所がある（effectiveInput* とは未統一）。検証直前の再同期で後段は揃えているが、ログと実処理の解釈ズレが残るならここを第一候補に。
                            if ($useCachedGutterB -and (Test-Path -LiteralPath $so1b) -and $cacheB.RefAspect -gt 0) {
                                $dSo1b = Get-ImageDimensions -Path $so1b
                                if ($dSo1b.Width -gt 0 -and $dSo1b.Height -gt 0) {
                                    $curAspB = $dSo1b.Width / $dSo1b.Height
                                    $diffB = [Math]::Abs($curAspB - $cacheB.RefAspect) / $cacheB.RefAspect
                                    if ($diffB -gt 0.10) {
                                        Write-FlickFitHost "         （フォルダ参照との縦横比差が大きい → 分割幅チェックへ。参照=$([Math]::Round($cacheB.RefAspect,3)) 今回=$([Math]::Round($curAspB,3))）" -ForegroundColor DarkGray
                                        $origPathAtAspectWarn = $origPath
                                        $so1bAtAspect = $so1b
                                        $so2bAtAspect = $so2b
                                        $linesAspB = [System.Collections.Generic.List[string]]::new()
                                        [void]$linesAspB.Add("⚠ 分割後の縦横比がフォルダ基準と大きく異なります（約10%超）")
                                        [void]$linesAspB.Add("参照: $([Math]::Round($cacheB.RefAspect,3)) ／ 今回1ページ目: $([Math]::Round($curAspB,3))")
                                        [void]$linesAspB.Add("")
                                        [void]$linesAspB.Add("キャンセル ＝ この分割のまま続行します")
                                        [void]$linesAspB.Add("OK ＝ のど・余白を選び直して再分割（自動適用キャッシュは解除）")
                                        [void]$linesAspB.Add("削除 ＝ この見開きを削除（GUIの削除ボタン）")
                                        $sumAspectB = [string]::Join("`r`n", $linesAspB)
                                        $gutterEntryRedoB = [string]$origPath
                                        $allPathsRedoB = @($imgs | ForEach-Object { $_.FullName })
                                        Write-FlickFitStep5EntryDebug -Label 'redob-before' -EntryPath $entryPathStep5 -PreviewPath $gutterEntryRedoB -ApplyPath $origPath -ImgIdx $imgIdx -ImgsCount $imgs.Count
                                        $guiRedoB = Show-GutterMarginSetGui -ImagePath $origPath -Title "縦横比のずれ — $imgName" -AllImagePaths $allPathsRedoB -ValidationSummaryText $sumAspectB -OkAppliesToCurrentView -ShowApplyThisPageOnlyButton
                                        if ($guiRedoB -is [System.Collections.IDictionary]) { $guiRedoB = Normalize-GutterGuiResult -GuiResult $guiRedoB }
                                        $imgs = Update-ImgsAfterMarginGui -Imgs $imgs -GuiResult $guiRedoB
                                        if ($null -ne $guiRedoB) {
                                            if (Test-GuiMarginFlagTrue -Tbl $guiRedoB -Key 'ApplyOnlyThisSpread') {
                                                $script:SplitWidthApplyGutterOnlyThisPage = $true
                                            }
                                            $navRedoB = Get-FlickFitGutterEntryAfterNavGui -EntryPath $gutterEntryRedoB -EntryName $imgName -GuiResult $guiRedoB
                                            if ($null -ne $navRedoB) { $origPath = $navRedoB.OrigPath; $imgName = $navRedoB.ImgName; $ext = $navRedoB.Ext }
                                            Write-FlickFitStep5EntryDebug -Label 'redob-after' -EntryPath $entryPathStep5 -GuiResult $guiRedoB -ApplyPath $origPath -ImgIdx $imgIdx -ImgsCount $imgs.Count
                                            if (Test-GuiMarginFlagTrue -Tbl $guiRedoB -Key 'DeleteImage') {
                                                foreach ($pDel in @($origPathAtAspectWarn, $so1bAtAspect, $so2bAtAspect)) {
                                                    if (Test-Path -LiteralPath $pDel) { Remove-Item -LiteralPath $pDel -Force -ErrorAction SilentlyContinue }
                                                }
                                                if (Test-Path -LiteralPath $tempBackupB) { Remove-Item -LiteralPath $tempBackupB -Force -ErrorAction SilentlyContinue }
                                                $folderProblemSkipped++; $skippedImages++; $processedImages++; $imgIdx++; continue
                                            }
                                            if (Test-GuiMarginFlagTrue -Tbl $guiRedoB -Key 'PhotosEdit') {
                                                if (Test-Path -LiteralPath $tempBackupB) { Remove-Item -LiteralPath $tempBackupB -Force -ErrorAction SilentlyContinue }
                                                $dPhRb = Get-ImageDimensions -Path $origPath
                                                if ($dPhRb.Width -gt 0) { $folderCoverWidth = $dPhRb.Width }
                                                Write-FlickFitHost "         ✅ フォトで編集した画像を採用（以降のトリミング基準に使用）" -ForegroundColor Green
                                                $folderSplit += 1; $splitImages += 1; $processedImages++; $imgIdx++; continue
                                            }
                                            $aspectRedoProceed = $false
                                            if ($guiRedoB -is [System.Collections.IDictionary]) {
                                                $gxAspChk = Get-HashtableInt -Tbl $guiRedoB -Key 'GutterX' -Default (-1)
                                                if ($gxAspChk -ge 0) { $aspectRedoProceed = $true }
                                            }
                                            if ($aspectRedoProceed) {
                                                $script:FolderGutterCache.Remove($dir)
                                                if (Test-Path -LiteralPath $tempBackupB) {
                                                    Copy-Item -LiteralPath $tempBackupB -Destination $origPath -Force -ErrorAction SilentlyContinue
                                                }
                                                if (Test-Path -LiteralPath $so1bAtAspect) { Remove-Item -LiteralPath $so1bAtAspect -Force -ErrorAction SilentlyContinue }
                                                if (Test-Path -LiteralPath $so2bAtAspect) { Remove-Item -LiteralPath $so2bAtAspect -Force -ErrorAction SilentlyContinue }
                                                $so1b = Join-Path (Get-LiteralPathParent $origPath) ([System.IO.Path]::GetFileNameWithoutExtension($origPath) + "_1" + $ext)
                                                $so2b = Join-Path (Get-LiteralPathParent $origPath) ([System.IO.Path]::GetFileNameWithoutExtension($origPath) + "_2" + $ext)
                                                $dAspRestore = Get-ImageDimensions -Path $origPath
                                                if ($dAspRestore.Width -gt 0 -and $dAspRestore.Height -gt 0) { $origW = $dAspRestore.Width; $origH = $dAspRestore.Height }
                                            }
                                            $gutterXNew = $null
                                            $ltRb = 0; $rtRb = 0; $ttRb = 0; $btRb = 0
                                            if ($null -ne $guiRedoB) {
                                                $gxRb = Get-HashtableInt -Tbl $guiRedoB -Key 'GutterX' -Default (-1)
                                                if ($gxRb -ge 0) {
                                                    $gutterXNew = $gxRb
                                                    $ltRb = Get-HashtableInt -Tbl $guiRedoB -Key 'LeftTrimPx'
                                                    $rtRb = Get-HashtableInt -Tbl $guiRedoB -Key 'RightTrimPx'
                                                    $ttRb = Get-HashtableInt -Tbl $guiRedoB -Key 'TopTrimPx'
                                                    $btRb = Get-HashtableInt -Tbl $guiRedoB -Key 'BottomTrimPx'
                                                }
                                            }
                                            $splitPathRedoB = $origPath
                                            $apRb = Get-HashtableTrimmedString -Tbl $guiRedoB -Key 'ApplyImagePath'
                                            if ($apRb -and (Test-Path -LiteralPath $apRb)) { $splitPathRedoB = $apRb }
                                            if (-not [string]::Equals($splitPathRedoB, $origPath, [StringComparison]::OrdinalIgnoreCase)) {
                                                $extRb = [System.IO.Path]::GetExtension($splitPathRedoB).ToLower()
                                                $baseRb = [System.IO.Path]::GetFileNameWithoutExtension($splitPathRedoB)
                                                $so1b = Join-Path (Get-LiteralPathParent $splitPathRedoB) ($baseRb + "_1" + $extRb)
                                                $so2b = Join-Path (Get-LiteralPathParent $splitPathRedoB) ($baseRb + "_2" + $extRb)
                                                $dRbSp = Get-ImageDimensions -Path $splitPathRedoB
                                                if ($dRbSp.Width -gt 0 -and $dRbSp.Height -gt 0) { $origW = $dRbSp.Width; $origH = $dRbSp.Height }
                                            }
                                            if ($null -ne $gutterXNew -and $gutterXNew -ge 0) {
                                                $cwG = $folderCoverWidth
                                                if ($cwG -le 0) { $dG = Get-ImageDimensions -Path $splitPathRedoB; if ($dG.Width -gt 0) { $cwG = [Math]::Floor($dG.Width / 2) } }
                                                try {
                                                    $rbMt = Get-HashtableBool -Tbl $guiRedoB -Key 'MarginTrimWithoutSplit'
                                                    if ($rbMt) {
                                                        $vertRbMt = Repair-GutterVerticalMargins -ImgH $origH -TopTrim $ttRb -BottomTrim $btRb
                                                        $ltRb = [Math]::Max(0, [int]$ltRb)
                                                        $rtRb = [Math]::Max(0, [int]$rtRb)
                                                        $resultG = Invoke-PythonCropGuiMargins -WorkTrimSplitPy $workTrimSplitPy -ImagePath $splitPathRedoB -RightBinding $RightBinding -LeftTrim $ltRb -TopTrim $vertRbMt.TopTrimPx -RightTrim $rtRb -BottomTrim $vertRbMt.BottomTrimPx
                                                        $ttRb = $vertRbMt.TopTrimPx
                                                        $btRb = $vertRbMt.BottomTrimPx
                                                        if ($resultG -match "TRIMMED:1") {
                                                            $iszRefRb = Get-FlickFitEffectiveInputSizePx -LiteralPath $splitPathRedoB
                                                            $refAspNew = 0; $refWNew = 0
                                                            if ($iszRefRb.Width -gt 0 -and $iszRefRb.Height -gt 0) { $refAspNew = $iszRefRb.Width / $iszRefRb.Height; $refWNew = $iszRefRb.Width }
                                                            $skipCacheRbMt = (Get-Variable -Name SplitWidthApplyGutterOnlyThisPage -Scope Script -ErrorAction SilentlyContinue) -and $script:SplitWidthApplyGutterOnlyThisPage
                                                            if ($skipCacheRbMt) { $script:SplitWidthApplyGutterOnlyThisPage = $false } else {
                                                                $script:FolderGutterCache[$dir] = New-FlickFitFolderGutterCacheEntry -GutterX $gutterXNew -GutterPct 50.0 -LeftTrimPx $ltRb -RightTrimPx $rtRb -TopTrimPx $ttRb -BottomTrimPx $btRb -ImgW $origW -ImgH $origH -RefAspect $refAspNew -RefWidth $refWNew -MarginTrimWithoutSplit $true
                                                            }
                                                            Write-FlickFitHost "         ✅ 再設定: 余白のみトリミング（1枚）" -ForegroundColor DarkGreen
                                                            $folderSplit += 1; $splitImages += 1; $processedImages++; $imgIdx++
                                                            if (Test-Path -LiteralPath $tempBackupB) { Remove-Item -LiteralPath $tempBackupB -Force -ErrorAction SilentlyContinue }
                                                            continue
                                                        }
                                                        Write-FlickFitHost "         ⚠ 余白トリム: $resultG" -ForegroundColor Yellow
                                                    } elseif ($ltRb -gt 0 -or $rtRb -gt 0 -or $ttRb -gt 0 -or $btRb -gt 0) {
                                                        $cohRb = Repair-GutterMarginGeometry -ImgW $origW -GutterX $gutterXNew -LeftTrim $ltRb -RightTrim $rtRb
                                                        $gutterXNew = $cohRb.GutterX; $ltRb = $cohRb.LeftTrimPx; $rtRb = $cohRb.RightTrimPx
                                                        $vertRb = Repair-GutterVerticalMargins -ImgH $origH -TopTrim $ttRb -BottomTrim $btRb
                                                        $ttRb = $vertRb.TopTrimPx; $btRb = $vertRb.BottomTrimPx
                                                        $outputG = & $script:PythonExe $workTrimSplitPy $splitPathRedoB $RightBinding.ToString() "split_at_gutter_with_margins" "-" $gutterXNew $ltRb $rtRb $aspectMin $cwG $ttRb $btRb 2>&1
                                                        $resultG = ($outputG | ForEach-Object { "$_" }) -join ""
                                                    } else {
                                                        $outputG = & $script:PythonExe $workTrimSplitPy $splitPathRedoB $RightBinding.ToString() "split_at_gutter" "false" $gutterXNew $aspectMin $cwG "true" "true" 2>&1
                                                        $resultG = ($outputG | ForEach-Object { "$_" }) -join ""
                                                    }
                                                    if (-not $rbMt -and $resultG -match "SPLIT:2" -and (Test-Path -LiteralPath $so1b) -and (Test-Path -LiteralPath $so2b)) {
                                                        $dRefNew = Get-ImageDimensions -Path $so1b
                                                        $refAspNew = 0; $refWNew = 0
                                                        if ($dRefNew.Width -gt 0 -and $dRefNew.Height -gt 0) { $refAspNew = $dRefNew.Width / $dRefNew.Height; $refWNew = $dRefNew.Width }
                                                        $gpNew = 50.0
                                                        if ($null -ne $guiRedoB -and $guiRedoB -is [System.Collections.IDictionary]) {
                                                            foreach ($gk in @($guiRedoB.Keys)) {
                                                                if ([string]::Equals([string]$gk, 'GutterPct', [StringComparison]::OrdinalIgnoreCase)) {
                                                                    try { $gpNew = [Math]::Max(1, [Math]::Min(99, [double]$guiRedoB[$gk])); break } catch {}
                                                                }
                                                            }
                                                        }
                                                        if ($gpNew -eq 50.0 -and $origW -gt 0) { $gpNew = [Math]::Round(100.0 * $gutterXNew / $origW, 2) }
                                                        $ucsRb = Get-HashtableBool -Tbl $guiRedoB -Key 'MarginTrimWithoutSplit'
                                                        $skipCacheRbSp = (Get-Variable -Name SplitWidthApplyGutterOnlyThisPage -Scope Script -ErrorAction SilentlyContinue) -and $script:SplitWidthApplyGutterOnlyThisPage
                                                        if ($skipCacheRbSp) { $script:SplitWidthApplyGutterOnlyThisPage = $false } else {
                                                            $script:FolderGutterCache[$dir] = New-FlickFitFolderGutterCacheEntry -GutterX $gutterXNew -GutterPct $gpNew -LeftTrimPx $ltRb -RightTrimPx $rtRb -TopTrimPx $ttRb -BottomTrimPx $btRb -ImgW $origW -ImgH $origH -RefAspect $refAspNew -RefWidth $refWNew -MarginTrimWithoutSplit $ucsRb
                                                        }
                                                        Write-FlickFitHost "         ✅ ノド位置を再設定して2ページに分割しました" -ForegroundColor DarkGreen
                                                        $folderSplit += 2; $splitImages += 2; $processedImages++; $imgIdx++
                                                        if ($folderCoverWidth -le 0 -and (Test-Path -LiteralPath $so1b)) {
                                                            $dd = Get-ImageDimensions -Path $so1b
                                                            if ($dd.Width -gt 0) { $folderCoverWidth = $dd.Width }
                                                        }
                                                        if (Test-Path -LiteralPath $tempBackupB) { Remove-Item -LiteralPath $tempBackupB -Force -ErrorAction SilentlyContinue }
                                                        continue
                                                    } elseif (-not $rbMt) {
                                                        Write-FlickFitHost "         ⚠ 分割処理: $resultG" -ForegroundColor Yellow
                                                    }
                                                } catch { Write-FlickFitHost "         ⚠ 分割エラー: $($_.Exception.Message)" -ForegroundColor Red }
                                            } else {
                                                Write-FlickFitHost "         （GUIキャンセル）このまま採用します" -ForegroundColor Gray
                                                if (Test-Path -LiteralPath $tempBackupB) {
                                                    Copy-Item -LiteralPath $tempBackupB -Destination $origPath -Force -ErrorAction SilentlyContinue
                                                }
                                                $imgs = @(Get-ProcessableFolderImages -FolderPath $dir)
                                                continue
                                            }
                                        }
                                    }
                                }
                            }
                            # 分割幅検証直前: $origPath（縦横比再GUI 等の後）と寸法を再同期
                            $effectiveInputPathBal = [string]$origPath
                            $iszBalPreVal = Get-FlickFitEffectiveInputSizePx -LiteralPath $effectiveInputPathBal
                            $effectiveInputWidthBal = $iszBalPreVal.Width
                            $effectiveInputHeightBal = $iszBalPreVal.Height
                            if ((Test-Path -LiteralPath $so1b) -and (Test-Path -LiteralPath $so2b) -and $folderCoverWidth -gt 0 -and (Test-Path -LiteralPath $tempBackupB)) {
                                $refWb = if ($useCachedGutterB -and $cacheB.RefWidth -gt 0) { $cacheB.RefWidth } else { 0 }
                                $refAspB = if ($useCachedGutterB -and $cacheB.RefAspect -gt 0) { $cacheB.RefAspect } else { 0 }
                                $val = Invoke-SplitWidthValidation -SplitPath1 $so1b -SplitPath2 $so2b -CoverWidth $folderCoverWidth -BackupPath $tempBackupB -OrigPath $origPath -WorkTrimSplitPy $workTrimSplitPy -RightBinding $RightBinding -AspectMin $aspectMin -ImgName $imgName -RefWidthFromGutter $refWb -AllowGutterReselect $useCachedGutterB -RefAspect $refAspB -AllImagePaths @($imgs | ForEach-Object { $_.FullName }) -GutterCacheFolderKey $dir -AssumeInitialGutterGuiPrecedesSplit:$balancedFreshGutterGuiUsed
                                if ($val -eq "delete") {
                                    if (Test-Path -LiteralPath $tempBackupB) { Remove-Item -LiteralPath $tempBackupB -Force -ErrorAction SilentlyContinue }
                                    $folderProblemSkipped++; $skippedImages++
                                    $processedImages++
                                    # リフレッシュせずimgIdxを進める（リフレッシュすると032_1～等を再走査してしまう）
                                    $imgIdx++
                                    continue
                                }
                                if ($val -eq "trim_only") {
                                    if (Test-Path -LiteralPath $so1b) { Remove-Item -LiteralPath $so1b -Force -ErrorAction SilentlyContinue }
                                    if (Test-Path -LiteralPath $so2b) { Remove-Item -LiteralPath $so2b -Force -ErrorAction SilentlyContinue }
                                    if (Test-Path -LiteralPath $tempBackupB) {
                                        Copy-Item -LiteralPath $tempBackupB -Destination $origPath -Force -ErrorAction SilentlyContinue
                                        $trimOnlyOut = & $script:PythonExe $workTrimSplitPy $origPath $RightBinding.ToString() "trim_only" "" $aspectMin 2>&1
                                        Remove-Item -LiteralPath $tempBackupB -Force -ErrorAction SilentlyContinue
                                    }
                                    Write-FlickFitHost "         ✅ 余白のみトリミング（分割なし・1枚）" -ForegroundColor DarkGreen
                                    $folderSplit += 1
                                    $splitImages += 1
                                    $processedImages++; $imgIdx++; continue
                                }
                                if ($val -eq "set_new_cover" -and (Get-Variable -Name SplitWidthNewCoverCandidate -Scope Script -ErrorAction SilentlyContinue)) {
                                    if ($script:SplitWidthNewCoverCandidate -gt 0) {
                                        $folderCoverWidth = [int]$script:SplitWidthNewCoverCandidate
                                        Write-FlickFitHost "         → このページ幅 $folderCoverWidth px を新しい基準値として採用しました" -ForegroundColor DarkCyan
                                    }
                                    $script:SplitWidthNewCoverCandidate = $null
                                }
                                if ($val -eq "gutter_reselect" -and (Test-Path -LiteralPath $tempBackupB)) {
                                    $script:FolderGutterCache.Remove($dir)
                                    if (Test-Path -LiteralPath $so1b) { Remove-Item -LiteralPath $so1b -Force -ErrorAction SilentlyContinue }
                                    Write-FlickFitObsFileOp -Op 'gutter_reselect_bal_Remove_so1' -Path $so1b
                                    if (Test-Path -LiteralPath $so2b) { Remove-Item -LiteralPath $so2b -Force -ErrorAction SilentlyContinue }
                                    Write-FlickFitObsFileOp -Op 'gutter_reselect_bal_Remove_so2' -Path $so2b
                                    Copy-Item -LiteralPath $tempBackupB -Destination $origPath -Force -ErrorAction SilentlyContinue
                                    Write-FlickFitObsFileOp -Op 'gutter_reselect_bal_CopyBackupToOrig' -Path $origPath
                                    Write-FlickFitObsFileOp -Op 'gutter_reselect_bal_tempBackup' -Path $tempBackupB
                                    $guiResult = $null
                                    $gxGuiVal = $null
                                    $presetBFromVal = $script:SplitWidthGuiPresetResult
                                    if ($presetBFromVal) { $script:SplitWidthGuiPresetResult = $null }
                                    if ($null -ne $presetBFromVal -and $presetBFromVal -is [System.Collections.IDictionary]) {
                                        $gxPb = Get-HashtableInt -Tbl $presetBFromVal -Key 'GutterX' -Default (-1)
                                        if ($gxPb -ge 0) {
                                            $gxGuiVal = $presetBFromVal
                                            $guiResult = @{
                                                GutterX      = $gxPb
                                                LeftTrimPx   = (Get-HashtableInt -Tbl $presetBFromVal -Key 'LeftTrimPx')
                                                RightTrimPx  = (Get-HashtableInt -Tbl $presetBFromVal -Key 'RightTrimPx')
                                                TopTrimPx    = (Get-HashtableInt -Tbl $presetBFromVal -Key 'TopTrimPx')
                                                BottomTrimPx = (Get-HashtableInt -Tbl $presetBFromVal -Key 'BottomTrimPx')
                                                MarginTrimWithoutSplit = (Get-HashtableBool -Tbl $presetBFromVal -Key 'MarginTrimWithoutSplit')
                                            }
                                        }
                                    }
                                    if ($null -eq $guiResult -or $guiResult.GutterX -lt 0) {
                                    $gutterReGr = [string]$origPath
                                    $allPathsGr = @($imgs | ForEach-Object { $_.FullName })
                                    Write-FlickFitStep5EntryDebug -Label 'regr-before' -EntryPath $entryPathStep5 -PreviewPath $gutterReGr -ApplyPath $origPath -ImgIdx $imgIdx -ImgsCount $imgs.Count
                                    $gxGuiVal = Show-GutterMarginSetGui -ImagePath $origPath -Title "ノドと左右余白の再選択" -AllImagePaths $allPathsGr -OkAppliesToCurrentView -ShowApplyThisPageOnlyButton
                                    if ($gxGuiVal -is [System.Collections.IDictionary]) { $gxGuiVal = Normalize-GutterGuiResult -GuiResult $gxGuiVal }
                                    $imgs = Update-ImgsAfterMarginGui -Imgs $imgs -GuiResult $gxGuiVal
                                    $navReGr = Get-FlickFitGutterEntryAfterNavGui -EntryPath $gutterReGr -EntryName $imgName -GuiResult $gxGuiVal
                                    if ($null -ne $navReGr) { $origPath = $navReGr.OrigPath; $imgName = $navReGr.ImgName; $ext = $navReGr.Ext }
                                    Write-FlickFitStep5EntryDebug -Label 'regr-after' -EntryPath $entryPathStep5 -GuiResult $gxGuiVal -ApplyPath $origPath -ImgIdx $imgIdx -ImgsCount $imgs.Count
                                    if (Test-GuiMarginFlagTrue -Tbl $gxGuiVal -Key 'DeleteImage') {
                                        if (Test-Path -LiteralPath $tempBackupB) { Remove-Item -LiteralPath $tempBackupB -Force -ErrorAction SilentlyContinue }
                                        if (Test-Path -LiteralPath $so1b) { Remove-Item -LiteralPath $so1b -Force -ErrorAction SilentlyContinue }
                                        if (Test-Path -LiteralPath $so2b) { Remove-Item -LiteralPath $so2b -Force -ErrorAction SilentlyContinue }
                                        $folderProblemSkipped++; $skippedImages++; $processedImages++; $imgIdx++; continue
                                    }
                                    if (Test-GuiMarginFlagTrue -Tbl $gxGuiVal -Key 'PhotosEdit') {
                                        if (Test-Path -LiteralPath $tempBackupB) { Remove-Item -LiteralPath $tempBackupB -Force -ErrorAction SilentlyContinue }
                                        $dPhGr = Get-ImageDimensions -Path $origPath
                                        if ($dPhGr.Width -gt 0) { $folderCoverWidth = $dPhGr.Width }
                                        Write-FlickFitHost "         ✅ フォトで編集した画像を採用（以降のトリミング基準に使用）" -ForegroundColor Green
                                        $folderSplit += 1; $splitImages += 1; $processedImages++; $imgIdx++; continue
                                    }
                                    $gxPickGr = Get-HashtableInt -Tbl $gxGuiVal -Key 'GutterX' -Default (-1)
                                    if ($gxPickGr -ge 0) {
                                        $guiResult = @{
                                            GutterX      = $gxPickGr
                                            LeftTrimPx   = (Get-HashtableInt -Tbl $gxGuiVal -Key 'LeftTrimPx')
                                            RightTrimPx  = (Get-HashtableInt -Tbl $gxGuiVal -Key 'RightTrimPx')
                                            TopTrimPx    = (Get-HashtableInt -Tbl $gxGuiVal -Key 'TopTrimPx')
                                            BottomTrimPx = (Get-HashtableInt -Tbl $gxGuiVal -Key 'BottomTrimPx')
                                            MarginTrimWithoutSplit = (Get-HashtableBool -Tbl $gxGuiVal -Key 'MarginTrimWithoutSplit')
                                        }
                                    }
                                    if (Test-GuiMarginFlagTrue -Tbl $gxGuiVal -Key 'ApplyOnlyThisSpread') {
                                        $script:SplitWidthApplyGutterOnlyThisPage = $true
                                    }
                                    }
                                    $apBal = Get-HashtableTrimmedString -Tbl $gxGuiVal -Key 'ApplyImagePath'
                                    $splitPathGr = Resolve-FlickFitEffectiveInputPath -OrigPath $origPath -GuiResult $gxGuiVal
                                    $sbSrc = if ($null -ne $presetBFromVal) { 'preset' } else { 'gui' }
                                    $sbLastW = 0
                                    if ($script:SplitWidthLastConfirmedByFolder -and $script:SplitWidthLastConfirmedByFolder.ContainsKey($dir)) {
                                        $sbLastW = Get-HashtableInt -Tbl $script:SplitWidthLastConfirmedByFolder[$dir] -Key 'ImgW' -Default 0
                                    }
                                    if (-not [string]::Equals($splitPathGr, $origPath, [StringComparison]::OrdinalIgnoreCase)) {
                                        $extGr = [System.IO.Path]::GetExtension($splitPathGr).ToLower()
                                        $baseGr = [System.IO.Path]::GetFileNameWithoutExtension($splitPathGr)
                                        $so1b = Join-Path (Get-LiteralPathParent $splitPathGr) ($baseGr + "_1" + $extGr)
                                        $so2b = Join-Path (Get-LiteralPathParent $splitPathGr) ($baseGr + "_2" + $extGr)
                                        $dGrSp = Get-ImageDimensions -Path $splitPathGr
                                        if ($dGrSp.Width -gt 0 -and $dGrSp.Height -gt 0) { $origW = $dGrSp.Width; $origH = $dGrSp.Height }
                                    }
                                    $effectiveInputPathBal = [string]$splitPathGr
                                    $iszBalGr = Get-FlickFitEffectiveInputSizePx -LiteralPath $effectiveInputPathBal
                                    $effectiveInputWidthBal = $iszBalGr.Width
                                    $effectiveInputHeightBal = $iszBalGr.Height
                                    $sbHasApply = ($null -ne $apBal)
                                    Write-FlickFitHost ("[SplitReuse] mode=balanced source={0} orig={1} input={2} hasApply={3} imgW={4} lastImgW={5} eff={6}" -f $sbSrc, $origPath, $splitPathGr, $sbHasApply, $effectiveInputWidthBal, $sbLastW, $effectiveInputPathBal) -ForegroundColor DarkYellow
                                    $cwValReselect = 0
                                    if ($null -ne $guiResult -and $guiResult.GutterX -ge 0) {
                                        try {
                                            $gxV = [int]$guiResult.GutterX
                                            $ltGr = [int]$guiResult.LeftTrimPx
                                            $rtGr = [int]$guiResult.RightTrimPx
                                            $ttGr = [int]$guiResult.TopTrimPx
                                            $btGr = [int]$guiResult.BottomTrimPx
                                            $grMt = Get-HashtableBool -Tbl $gxGuiVal -Key 'MarginTrimWithoutSplit'
                                            if ($grMt) {
                                                $vertGrMt = Repair-GutterVerticalMargins -ImgH $effectiveInputHeightBal -TopTrim $ttGr -BottomTrim $btGr
                                                $ltGr = [Math]::Max(0, $ltGr)
                                                $rtGr = [Math]::Max(0, $rtGr)
                                                $resVal = Invoke-PythonCropGuiMargins -WorkTrimSplitPy $workTrimSplitPy -ImagePath $effectiveInputPathBal -RightBinding $RightBinding -LeftTrim $ltGr -TopTrim $vertGrMt.TopTrimPx -RightTrim $rtGr -BottomTrim $vertGrMt.BottomTrimPx
                                                $ttGr = $vertGrMt.TopTrimPx
                                                $btGr = $vertGrMt.BottomTrimPx
                                                if ($resVal -match "TRIMMED:1") {
                                                    $iszRefGrMt = Get-FlickFitEffectiveInputSizePx -LiteralPath $effectiveInputPathBal
                                                    $refA = 0; $refW = 0
                                                    if ($iszRefGrMt.Width -gt 0 -and $iszRefGrMt.Height -gt 0) { $refA = $iszRefGrMt.Width / $iszRefGrMt.Height; $refW = $iszRefGrMt.Width }
                                                    $skipCacheGrMt = (Get-Variable -Name SplitWidthApplyGutterOnlyThisPage -Scope Script -ErrorAction SilentlyContinue) -and $script:SplitWidthApplyGutterOnlyThisPage
                                                    if ($skipCacheGrMt) { $script:SplitWidthApplyGutterOnlyThisPage = $false } else {
                                                        $script:FolderGutterCache[$dir] = New-FlickFitFolderGutterCacheEntry -GutterX $gxV -GutterPct 50.0 -LeftTrimPx $ltGr -RightTrimPx $rtGr -TopTrimPx $ttGr -BottomTrimPx $btGr -ImgW $effectiveInputWidthBal -ImgH $effectiveInputHeightBal -RefAspect $refA -RefWidth $refW -MarginTrimWithoutSplit $true
                                                    }
                                                    Write-FlickFitHost "         ✅ 再選択: 余白のみトリミング（1枚）" -ForegroundColor DarkGreen
                                                    $folderSplit += 1
                                                    $splitImages += 1
                                                    $processedImages++
                                                    if (Test-Path -LiteralPath $tempBackupB) { Remove-Item -LiteralPath $tempBackupB -Force -ErrorAction SilentlyContinue }
                                                    $imgIdx++
                                                    continue
                                                }
                                                Write-FlickFitHost "         ⚠ 余白トリム: $resVal" -ForegroundColor Yellow
                                            } elseif ($ltGr -gt 0 -or $rtGr -gt 0 -or $ttGr -gt 0 -or $btGr -gt 0) {
                                                $cohGrBal = Repair-GutterMarginGeometry -ImgW $effectiveInputWidthBal -GutterX $gxV -LeftTrim $ltGr -RightTrim $rtGr
                                                $gxV = $cohGrBal.GutterX; $ltGr = $cohGrBal.LeftTrimPx; $rtGr = $cohGrBal.RightTrimPx
                                                $vertGr = Repair-GutterVerticalMargins -ImgH $effectiveInputHeightBal -TopTrim $ttGr -BottomTrim $btGr
                                                $ttGr = $vertGr.TopTrimPx; $btGr = $vertGr.BottomTrimPx
                                                $outVal = & $script:PythonExe $workTrimSplitPy $effectiveInputPathBal $RightBinding.ToString() "split_at_gutter_with_margins" "-" $gxV $ltGr $rtGr $aspectMin $cwValReselect $ttGr $btGr 2>&1
                                                $resVal = ($outVal | ForEach-Object { "$_" }) -join ""
                                            } else {
                                                $outVal = & $script:PythonExe $workTrimSplitPy $effectiveInputPathBal $RightBinding.ToString() "split_at_gutter" "false" $gxV $aspectMin $cwValReselect "true" "true" 2>&1
                                                $resVal = ($outVal | ForEach-Object { "$_" }) -join ""
                                            }
                                            if (-not $grMt -and $resVal -match "SPLIT:2" -and (Test-Path -LiteralPath $so1b) -and (Test-Path -LiteralPath $so2b)) {
                                                $dRefVal = Get-ImageDimensions -Path $so1b
                                                $refA = 0; $refW = 0
                                                if ($dRefVal.Width -gt 0 -and $dRefVal.Height -gt 0) { $refA = $dRefVal.Width / $dRefVal.Height; $refW = $dRefVal.Width }
                                                $gp8858 = 50.0
                                                if ($null -ne $gxGuiVal -and $gxGuiVal -is [System.Collections.IDictionary]) {
                                                    foreach ($gk in @($gxGuiVal.Keys)) {
                                                        if ([string]::Equals([string]$gk, 'GutterPct', [StringComparison]::OrdinalIgnoreCase)) {
                                                            try { $gp8858 = [Math]::Max(1, [Math]::Min(99, [double]$gxGuiVal[$gk])); break } catch {}
                                                        }
                                                    }
                                                }
                                                if ($gp8858 -eq 50.0 -and $effectiveInputWidthBal -gt 0) { $gp8858 = [Math]::Round(100.0 * $gxV / $effectiveInputWidthBal, 2) }
                                                $ucsGr = Get-HashtableBool -Tbl $gxGuiVal -Key 'MarginTrimWithoutSplit'
                                                $skipCacheGrSp = (Get-Variable -Name SplitWidthApplyGutterOnlyThisPage -Scope Script -ErrorAction SilentlyContinue) -and $script:SplitWidthApplyGutterOnlyThisPage
                                                if ($skipCacheGrSp) { $script:SplitWidthApplyGutterOnlyThisPage = $false } else {
                                                    $script:FolderGutterCache[$dir] = New-FlickFitFolderGutterCacheEntry -GutterX $gxV -GutterPct $gp8858 -LeftTrimPx $ltGr -RightTrimPx $rtGr -TopTrimPx $ttGr -BottomTrimPx $btGr -ImgW $effectiveInputWidthBal -ImgH $effectiveInputHeightBal -RefAspect $refA -RefWidth $refW -MarginTrimWithoutSplit $ucsGr
                                                }
                                                Write-FlickFitHost "         ✅ ノド位置を再選択して2ページに分割しました" -ForegroundColor DarkGreen
                                            }
                                        } catch { Write-FlickFitHost "         ⚠ 分割エラー: $($_.Exception.Message)" -ForegroundColor Red }
                                    } else {
                                        Write-FlickFitHost "         （GUIキャンセル）通常分割で再処理します" -ForegroundColor Gray
                                        $cwFall = $folderCoverWidth
                                        if ($cwFall -le 0) { $dF = Get-ImageDimensions -Path $origPath; if ($dF.Width -gt 0) { $cwFall = [Math]::Floor($dF.Width / 2) } }
                                        try {
                                            $outFall = & $script:PythonExe $workTrimSplitPy $origPath $RightBinding.ToString() "split" "true" $aspectMin $cwFall 2>&1
                                            if (($outFall -join "") -match "SPLIT:2" -and (Test-Path -LiteralPath $so1b) -and (Test-Path -LiteralPath $so2b)) {
                                                Write-FlickFitHost "         ✅ 通常分割で2ページに分割しました" -ForegroundColor DarkGreen
                                            }
                                        } catch {}
                                    }
                                }
                                if ($val -eq "retry" -and $folderCoverWidth -le 0 -and (Test-Path -LiteralPath $so1b)) { $dd = Get-ImageDimensions -Path $so1b; if ($dd.Width -gt 0) { $folderCoverWidth = $dd.Width } }
                                if (Test-Path -LiteralPath $tempBackupB) { Remove-Item -LiteralPath $tempBackupB -Force -ErrorAction SilentlyContinue }
                            } elseif (Test-Path -LiteralPath $tempBackupB) { Remove-Item -LiteralPath $tempBackupB -Force -ErrorAction SilentlyContinue }
                            Write-FlickFitHost "         ✅ 余白を除去して2ページに分割" -ForegroundColor DarkGreen
                            $folderSplit += 2
                            $splitImages += 2
                            if ($folderCoverWidth -le 0 -and (Test-Path -LiteralPath $so1b)) {
                                $dd = Get-ImageDimensions -Path $so1b
                                if ($dd.Width -gt 0) { $folderCoverWidth = $dd.Width; Write-FlickFitDebugStep5VerboseHost -Text "[DEBUG] 表紙幅=$folderCoverWidth px（分割結果→以降の最小幅基準）" }
                            }
                        } elseif ($result -match "SKIP") {
                            Write-FlickFitHost "         ⏭ スキップ（縦長）" -ForegroundColor DarkGray
                            $folderKeptAsIs++
                            $skippedImages++
                            if (Test-Path -LiteralPath $tempBackupB) { Remove-Item -LiteralPath $tempBackupB -Force -ErrorAction SilentlyContinue }
                        } elseif ($result -match "ERROR" -and $result -match "PermissionError|WinError 32|アクセスできません") {
                            $so1bCheck = Join-Path (Get-LiteralPathParent $origPath) ([System.IO.Path]::GetFileNameWithoutExtension($origPath) + "_1" + $ext)
                            $so2bCheck = Join-Path (Get-LiteralPathParent $origPath) ([System.IO.Path]::GetFileNameWithoutExtension($origPath) + "_2" + $ext)
                            if ((Test-Path -LiteralPath $so1bCheck) -and (Test-Path -LiteralPath $so2bCheck)) {
                                Write-FlickFitHost "         ⚠ 分割は成功しましたが元画像の削除に失敗。PowerShell側でリトライ..." -ForegroundColor Yellow
                                $delOk = $false
                                for ($r = 0; $r -lt 8; $r++) {
                                    [System.GC]::Collect(); [System.GC]::WaitForPendingFinalizers()
                                    Start-Sleep -Milliseconds (200 + $r * 150)
                                    try {
                                        if (Test-Path -LiteralPath $origPath) { Remove-Item -LiteralPath $origPath -Force -ErrorAction Stop }
                                        if (-not (Test-Path -LiteralPath $origPath)) { $delOk = $true; break }
                                    } catch {}
                                }
                                if ($delOk) {
                                    Write-FlickFitHost "         ✅ 元画像を削除し、2ページに分割完了" -ForegroundColor DarkGreen
                                    $folderSplit += 2
                                    $splitImages += 2
                                    if ($folderCoverWidth -le 0) {
                                        $dd = Get-ImageDimensions -Path $so1bCheck
                                        if ($dd.Width -gt 0) { $folderCoverWidth = $dd.Width }
                                    }
                                } else {
                                    Write-FlickFitHost "         ⚠ 削除リトライも失敗: $imgName（分割結果_1, _2 は作成済み・元画像は手動削除してください）" -ForegroundColor Red
                                }
                                if (Test-Path -LiteralPath $tempBackupB) { Remove-Item -LiteralPath $tempBackupB -Force -ErrorAction SilentlyContinue }
                            } else {
                                Write-FlickFitHost "         ⚠ 処理結果: $result" -ForegroundColor Yellow
                                if (Test-Path -LiteralPath $tempBackupB) { Remove-Item -LiteralPath $tempBackupB -Force -ErrorAction SilentlyContinue }
                            }
                        } else {
                            $isErrRes = (Test-FlickFitStep5StringLooksLikeResultError -S ([string]$result))
                            if ($isErrRes -and ([string]$result -match 'batch_split_at_gutter.*不完全')) {
                                Write-FlickFitHost "         [致命的] バッチ分割を再試行せず中断します: $result" -ForegroundColor Red
                                $script:FlickFitFatalBatchSplitAbort = $false
                                $fatMsg = [string]$result
                                if ($fatMsg -match '(?i)^ERROR:\s*(.+)$') { $fatMsg = $Matches[1].Trim() } else { $fatMsg = $fatMsg.Trim() }
                                throw [System.InvalidOperationException]::new($fatMsg)
                            }
                            $actOuter = $null
                            if ($isErrRes) { $actOuter = Get-FlickFitStep5RetryAction -Path $entryPathStep5 -MaxRetryBeforeFallback 2 }
                            Write-FlickFitHost "         ⚠ 処理結果: $result" -ForegroundColor Yellow
                            if ($isErrRes) {
                                if ($actOuter -eq 'fallback') {
                                    Write-FlickFitWarning "同一画像で ERROR が3回連続（結果文字列）したため trim_only にフォールバックします ($imgName)"
                                    if (Test-Path -LiteralPath $tempBackupB) { Copy-Item -LiteralPath $tempBackupB -Destination $entryPathStep5 -Force -ErrorAction SilentlyContinue }
                                    $origPath = $entryPathStep5; $imgName = $entryNameStep5; if (Test-Path -LiteralPath $entryPathStep5) { $ext = [System.IO.Path]::GetExtension($entryPathStep5).ToLower() }
                                    try {
                                        $ftO = (Invoke-PythonTimed -Category "PythonTrim" -PythonArgs $workTrimSplitPy, $entryPathStep5, $RightBinding.ToString(), "trim_only", "", $aspectMin) -join ""
                                        if ($ftO -match "TRIMMED:1") { Write-FlickFitHost "         ✅ trim_only フォールバック成功（1枚）" -ForegroundColor DarkCyan } else { Write-FlickFitHost "         ⚠ trim_only: $ftO" -ForegroundColor Yellow }
                                    } catch { Write-FlickFitHost "         ⚠ trim_only 失敗: $($_.Exception.Message)" -ForegroundColor Yellow }
                                    Add-FlickFitRetrimCandidate -VolFolder $dir -FilePath $entryPathStep5 -Reason 'bal_trim_err_fallback' -PageLabel $imgName
                                    if (Test-Path -LiteralPath $tempBackupB) { Remove-Item -LiteralPath $tempBackupB -Force -ErrorAction SilentlyContinue }
                                    $folderSplit += 1; $splitImages += 1; $processedImages++;
                                    $imgIdx++
                                    continue FlickFitStep5ImgLoop
                                }
                                if (Test-Path -LiteralPath $tempBackupB) {
                                    Copy-Item -LiteralPath $tempBackupB -Destination $entryPathStep5 -Force -ErrorAction SilentlyContinue
                                }
                                $origPath = $entryPathStep5
                                $imgName = $entryNameStep5
                                if (Test-Path -LiteralPath $entryPathStep5) { $ext = [System.IO.Path]::GetExtension($entryPathStep5).ToLower() }
                                Write-FlickFitHost "         ⚠ GUI後の適用に失敗したため、この画像を未処理のまま再試行します（$entryNameStep5）" -ForegroundColor Yellow
                                $Step5SkipIdxInc = $true
                            }
                            if (-not (Test-FlickFitStep5StringLooksLikeResultError -S ([string]$result))) {
                                $folderSplit += 1
                                $splitImages += 1
                            }
                            if (Test-Path -LiteralPath $tempBackupB) { Remove-Item -LiteralPath $tempBackupB -Force -ErrorAction SilentlyContinue }
                        }
                    }
                    
                    Start-Sleep -Milliseconds 250
                    if (-not $Step5SkipIdxInc) { $processedImages++ }
                
            } catch {
                if ($_.Exception.Message -match '^中断:') { throw }
                if ($true -eq $script:FlickFitFatalBatchSplitAbort) {
                    $script:FlickFitFatalBatchSplitAbort = $false
                    throw
                }
                Write-FlickFitHost "         ❌ エラー: $($_.Exception.Message)" -ForegroundColor Red
                $processedImages++
            }
            Write-FlickFitStep5EntryDebug -Label 'idx-before-main-inc' -EntryPath $entryPathStep5 -PreviewPath $origPath -ApplyPath $origPath -ImgIdx $imgIdx -ImgsCount $imgs.Count
            if (-not $Step5SkipIdxInc) { $imgIdx++ }
        }
        if ($folderPortraitKeptSilentCount -gt 0) {
            Write-FlickFitHost ("     [STEP5] 縦長ページをそのまま保持: {0} 枚" -f $folderPortraitKeptSilentCount) -ForegroundColor DarkGray
        }
        $step5SumKeptAsIs += $folderKeptAsIs
        $step5SumLoadFailed += $folderLoadFailed
        $step5SumProblem += $folderProblemSkipped
        $step5SumRealProcess += $folderSplit
        if (($true -eq $script:FlickFitEnableCachedBalBatch) -and -not ($true -eq $script:FlickFitDebugCachedBalBatch) -and ($ffQueueApplySilent -gt 0)) {
            Write-FlickFitHost ("     [STEP5] batch_split_at_gutter 結果を {0} 件反映" -f $ffQueueApplySilent) -ForegroundColor Green
        }
        if ($folderSplit -gt 0) {
            # 一時ファイル (cvr_*) のクリーンアップ（tempBackupOs / tempBackupB の消し漏れや他経路の cvr_* を最終掃除）
            $tmpFiles = @(Get-ChildItem -LiteralPath $dir -File -ErrorAction SilentlyContinue | Where-Object { $_.Name -like "cvr_*" })
            foreach ($tmpF in $tmpFiles) {
                Remove-Item -LiteralPath $tmpF.FullName -Force -ErrorAction SilentlyContinue
            }
            Write-FlickFitHost "     🔢 連番を整えています..." -ForegroundColor Yellow
            Renumber-Images $dir
            Write-FlickFitHost "     ✓ 完了" -ForegroundColor Green
        }
        
        if ($ProfileTiming -and $script:ProfileTimingData -and $script:ProfileTimingData.Count -gt 0) {
            Write-FlickFitHost "     ⏱ [ボトルネック計測] " -ForegroundColor DarkCyan -NoNewline
            $parts = @($script:ProfileTimingData.GetEnumerator() | Sort-Object { -$_.Value } | ForEach-Object { "$($_.Key)=$([math]::Round($_.Value/1000,1))s" })
            Write-FlickFitHost ($parts -join " | ") -ForegroundColor DarkGray
        }
        try {
            Show-FlickFitCorruptImageNotifyForStep5Folder -FolderLabel (Get-LiteralPathLeaf $dir)
        } catch { }
        $s5FolderSummary = "     📈 処理完了: $folderSplit 枚"
        if ($folderAvifOmit -gt 0) { $s5FolderSummary += "（うち AVIF 高速省略 $folderAvifOmit 枚）" }
        $s5FolderSummary += ", そのまま保持 $folderKeptAsIs 枚, 読み込み失敗 $folderLoadFailed 枚"
        if ($folderProblemSkipped -gt 0) { $s5FolderSummary += ", エラー・削除等 $folderProblemSkipped 枚" }
        $s5FolderSummary += "`n"
        Write-FlickFitHost $s5FolderSummary -ForegroundColor Cyan
        } finally {
            if ($envFlickTswPushed) {
                if ($null -ne $envPrevFlickFitTsw) { $env:FLICK_FIT_TYPICAL_SINGLE_WIDTH = $envPrevFlickFitTsw } else { Remove-Item -Path Env:FLICK_FIT_TYPICAL_SINGLE_WIDTH -ErrorAction SilentlyContinue }
            }
            if ($script:FolderAutoTimer) {
                $script:FolderAutoTimer.Stopwatch.Stop()
                $prevMs = $script:FolderAutoTimer.ElapsedMs; if ($null -eq $prevMs) { $prevMs = 0 }
                $totalMs = $prevMs + $script:FolderAutoTimer.Stopwatch.ElapsedMilliseconds
                $sec = [math]::Round($totalMs / 1000, 1)
                Write-FlickFitHost "     ⏱ 自動処理: ${sec}秒（ユーザー確認時間を除く）" -ForegroundColor DarkGray
                $script:FolderAutoTimer = $null
            }
        }
        Add-ProcessLogStep5CompletedDir $dir
        $script:CurrentProcessPhase = 'idle'
        $script:CurrentStep5Dir = $null
    }
    
    # Clean up work script
    if (Test-Path $workTrimSplitPy) {
        Start-Sleep -Milliseconds 100
        Remove-Item -LiteralPath $workTrimSplitPy -Force -ErrorAction SilentlyContinue
        Write-FlickFitHost "  🧹 一時スクリプトを削除しました" -ForegroundColor Gray
    }
    
    Write-FlickFitHost "  📊 ==== 処理サマリー ====" -ForegroundColor Cyan
    Write-FlickFitHost "     合計: $totalImages 枚" -ForegroundColor Gray
    Write-FlickFitHost "     処理済み入力: $processedImages 枚" -ForegroundColor Green
    Write-FlickFitHost "     実処理（分割・トリム等）: $step5SumRealProcess 枚" -ForegroundColor Green
    Write-FlickFitHost "     そのまま保持: $step5SumKeptAsIs 枚" -ForegroundColor DarkGray
    Write-FlickFitHost "     読み込み失敗: $step5SumLoadFailed 枚" -ForegroundColor $(if ($step5SumLoadFailed -gt 0) { 'Yellow' } else { 'DarkGray' })
    Write-FlickFitHost "     削除・除外: $step5SumProblem 枚" -ForegroundColor $(if ($step5SumProblem -gt 0) { 'Yellow' } else { 'DarkGray' })
    $s5GapTotal = $totalImages - $processedImages
    if ($s5GapTotal -ne 0) {
        Write-FlickFitHost "     ※ 合計 − 処理済み入力 = $s5GapTotal 枚（削除や分析時点との枚数差など）" -ForegroundColor DarkGray
    }
    Write-FlickFitHost "  =======================`n" -ForegroundColor Cyan
    }
    Update-ProcessLogStep -StepNum 5 -Status "success"

    # ===== STEP 6: 圧縮（ZIP/RAR） =====
    $script:CurrentProcessStepNumber = 6
    $stepName = if ($CompressionFormat -eq 'CBZ') { "STEP 6: CBZ圧縮" } elseif ($CompressionFormat -eq 'ZIP') { "STEP 6: ZIP圧縮" } else { "STEP 6: RAR圧縮" }
    Write-Step $stepName
    $archivedFolders = [System.Collections.Generic.List[string]]::new()
    $baseOutput = (Get-Location).Path
    $outputFolder = if ($OutputSubfolder) { Join-Path $baseOutput $OutputSubfolder } else { $baseOutput }
    if ($finalDirs.Count -gt 0 -and -not $DryRun) {
        if ($OutputSubfolder) {
            if (-not (Test-Path -LiteralPath $outputFolder)) { New-Item -ItemType Directory -Path $outputFolder -Force | Out-Null }
            Write-FlickFitHost "  出力先: $outputFolder" -ForegroundColor Cyan
        } else {
            Write-FlickFitHost "  出力先: $outputFolder" -ForegroundColor Cyan
        }
    }
    foreach ($dir in $finalDirs) {
        if ($script:CancelRequested) { throw "中断: 処理がキャンセルされました" }
        $doCompress = $true
        if (-not $runPhaseA) { $doCompress = Confirm-YN "  $(Get-LiteralPathLeaf $dir) を圧縮しますか？" -DefaultY $true }
        if (-not $doCompress -or $DryRun) { continue }
        $result = Invoke-CompressFolder -FolderPath $dir -OutputFolder $outputFolder -Format $CompressionFormat -WinRARPath $script:WinRAR
        if ($result) { $archivedFolders.Add($dir) | Out-Null }
    }
    Update-ProcessLogStep -StepNum 6 -Status "success"

    $script:CurrentProcessStepNumber = 7
    # ===== STEP 7: クリーンアップ（確認で削除対象を選択） =====
    $hasArchived = ($archivedFolders.Count -gt 0)
    $hasUnpacked = ($runPhaseA -and $unpackRoot -and (Test-Path -LiteralPath $unpackRoot.FullName))
    $hasSourceFiles = $false
    try {
        # 元ファイル＝解凍元の「アーカイブファイル」のみ。selectedExistingFolders は作業用フォルダのため含めない（誤ると作業ルートを削除する）。
        $hasSourceFiles = ($script:selectedArchives -and $script:selectedArchives.Count -gt 0) -or
            ($script:subfolderArchivesToProcess -and $script:subfolderArchivesToProcess.Count -gt 0)
    } catch {}
    
    if ($hasArchived -or $hasUnpacked -or $hasSourceFiles) {
        Write-FlickFitHost "`n=================================================" -ForegroundColor Cyan
        # STEP7 既定（配布版の安心寄り: 作業フォルダは消しやすい・解凍元は残しやすい）
        $defCleanupWork = $true
        $defKeepSourceArchives = $true
        if ($script:UserConfig) {
            if ($null -ne $script:UserConfig.CleanupWorkingFolders) { $defCleanupWork = [bool]$script:UserConfig.CleanupWorkingFolders }
            if ($null -ne $script:UserConfig.KeepSourceArchives) { $defKeepSourceArchives = [bool]$script:UserConfig.KeepSourceArchives }
        }
        # ランチャー等で UserConfig に両方あるときは方針確定済み→二重確認を省略（キーを消せば従来どおり対話）
        $ucPropNames = if ($script:UserConfig) { @($script:UserConfig.PSObject.Properties | ForEach-Object Name) } else { @() }
        $step7SkipConfirm = ($ucPropNames -contains 'CleanupWorkingFolders') -and ($ucPropNames -contains 'KeepSourceArchives')
        $deleteFoldersAndUnpacked = $false
        $deleteSourceFiles = $false
        if ($hasArchived -or $hasUnpacked) {
            Write-FlickFitHost "  [STEP7-1] 作業フォルダ・一時フォルダ" -ForegroundColor Cyan
            $msg1 = "圧縮済みの作業フォルダと一時フォルダを削除しますか？（フォルダは多くの場合ごみ箱へ）`n"
            if ($hasArchived) { $msg1 += "  - 圧縮済み作業フォルダ: $($archivedFolders.Count) 個`n" }
            if ($hasUnpacked) { $msg1 += "  - 一時: _unpacked`n" }
            if ($step7SkipConfirm) {
                $deleteFoldersAndUnpacked = [bool]$defCleanupWork
                Write-FlickFitHost ("  [UserConfig] 作業フォルダ・一時を削除する: {0}（確認省略・CleanupWorkingFolders）" -f $deleteFoldersAndUnpacked) -ForegroundColor DarkGray
            } else {
                $deleteFoldersAndUnpacked = Confirm-YN $msg1.TrimEnd() -DefaultY $defCleanupWork
            }
        }
        if ($hasSourceFiles) {
            Write-FlickFitHost "  [STEP7-2] 解凍元アーカイブ" -ForegroundColor Cyan
            $msg2 = "解凍元のアーカイブ（CBR/CBZ/ZIP等）をごみ箱へ移動しますか？`n  ※ 新規に出力した圧縮ファイルとは別です。トラブル時の保険として残す人も多いです。`n"
            # KeepSourceArchives=true → 残すのが既定 → 「移動する？」の既定は No
            if ($step7SkipConfirm) {
                $deleteSourceFiles = -not [bool]$defKeepSourceArchives
                Write-FlickFitHost ("  [UserConfig] 解凍元アーカイブをごみ箱へ移動する: {0}（確認省略・KeepSourceArchives={1}）" -f $deleteSourceFiles, $defKeepSourceArchives) -ForegroundColor DarkGray
            } else {
                $deleteSourceFiles = Confirm-YN $msg2.TrimEnd() -DefaultY (-not $defKeepSourceArchives)
            }
        }
        if ($deleteFoldersAndUnpacked -or $deleteSourceFiles) {
            $deleteRetries = 5
            $deleteDelaySec = 2
            
            Write-FlickFitHost "  ※ 削除に失敗する場合は、開いているエクスプローラーを閉じてください" -ForegroundColor DarkGray
            
            # 作業フォルダのサブフォルダのエクスプローラーウィンドウを閉じる試み（ルートは残す）
            try {
                $shell = New-Object -ComObject Shell.Application
                $workPath = (Get-Location).Path.TrimEnd('\')
                $shell.Windows() | ForEach-Object {
                    try {
                        $locUrl = $_.LocationURL
                        if ($locUrl) {
                            $locPath = [Uri]::UnescapeDataString(($locUrl -replace '^file:///', '')) -replace '/', '\'
                            $locPath = $locPath.TrimEnd('\')
                            # ルートフォルダ自体は閉じない（サブフォルダのみ閉じる）
                            if ($locPath -and $locPath.StartsWith($workPath + '\', [StringComparison]::OrdinalIgnoreCase)) {
                                $_.Quit()
                            }
                        }
                    } catch {}
                }
                [System.Runtime.InteropServices.Marshal]::ReleaseComObject($shell) | Out-Null
            } catch {}
            
            # ガベージコレクションでファイルハンドルを解放
            [System.GC]::Collect()
            [System.GC]::WaitForPendingFinalizers()
            Start-Sleep -Milliseconds 1000
            
            if ($deleteSourceFiles -and $hasSourceFiles) {
                # 新規作成した圧縮ファイルのパス（解凍元削除時、同名パスを除外）
                $newArchivePaths = [System.Collections.Generic.HashSet[string]]::new([StringComparer]::OrdinalIgnoreCase)
                foreach ($dir in $archivedFolders) {
                    $baseName = Get-LiteralPathLeaf $dir
                    $ext = if ($CompressionFormat -eq 'CBZ') { '.cbz' } elseif ($CompressionFormat -eq 'ZIP') { '.zip' } else { '.rar' }
                    $joined = Join-Path $outputFolder ($baseName + $ext)
                    try { $joined = [System.IO.Path]::GetFullPath($joined).TrimEnd('\') } catch { }
                    [void]$newArchivePaths.Add($joined)
                }
            } else {
                $newArchivePaths = $null
            }
            
            if ($deleteFoldersAndUnpacked -and $hasArchived) {
                Add-Type -AssemblyName Microsoft.VisualBasic
                foreach ($dir in $archivedFolders) {
                    if (Test-Path -LiteralPath $dir) {
                        $deleted = $false
                        foreach ($attempt in 1..$deleteRetries) {
                            try {
                                [Microsoft.VisualBasic.FileIO.FileSystem]::DeleteDirectory($dir, 'OnlyErrorDialogs', 'SendToRecycleBin')
                                Start-Sleep -Milliseconds 300
                                if (-not (Test-Path -LiteralPath $dir)) {
                                    Write-FlickFitHost "  [完了]: $(Get-LiteralPathLeaf $dir)" -ForegroundColor Gray
                                    $deleted = $true
                                    break
                                }
                            } catch {
                                if ($attempt -lt $deleteRetries) {
                                    Write-FlickFitHost "  [リトライ $attempt/$deleteRetries]: $(Get-LiteralPathLeaf $dir)" -ForegroundColor Yellow
                                    [System.GC]::Collect()
                                    [System.GC]::WaitForPendingFinalizers()
                                    Start-Sleep -Seconds $deleteDelaySec
                                }
                            }
                        }
                        if (-not $deleted -and (Test-Path -LiteralPath $dir)) {
                            Write-FlickFitHost "  [失敗]: $(Get-LiteralPathLeaf $dir) - ファイル使用中" -ForegroundColor Red
                            Write-FlickFitHost "    ※ エクスプローラーや画像ビューアを閉じてから手動で削除してください" -ForegroundColor DarkYellow
                        }
                    }
                }
            }
            if ($deleteFoldersAndUnpacked -and $hasUnpacked) {
                $unpackDeleted = $false
                foreach ($attempt in 1..$deleteRetries) {
                    try {
                        [System.GC]::Collect()
                        [System.GC]::WaitForPendingFinalizers()
                        Remove-Item -LiteralPath $unpackRoot.FullName -Recurse -Force -ErrorAction Stop
                        Start-Sleep -Milliseconds 300
                        if (-not (Test-Path -LiteralPath $unpackRoot.FullName)) {
                            Write-FlickFitHost "  _unpacked を削除しました。" -ForegroundColor DarkGray
                            $unpackDeleted = $true
                            break
                        }
                    } catch {
                        if ($attempt -lt $deleteRetries) {
                            Write-FlickFitHost "  [リトライ $attempt/$deleteRetries]: _unpacked" -ForegroundColor Yellow
                            Start-Sleep -Seconds $deleteDelaySec
                        }
                    }
                }
                if (-not $unpackDeleted -and (Test-Path -LiteralPath $unpackRoot.FullName)) {
                    # ごみ箱への移動を試みる
                    try {
                        Add-Type -AssemblyName Microsoft.VisualBasic -ErrorAction SilentlyContinue
                        [Microsoft.VisualBasic.FileIO.FileSystem]::DeleteDirectory(
                            $unpackRoot.FullName,
                            [Microsoft.VisualBasic.FileIO.UIOption]::OnlyErrorDialogs,
                            [Microsoft.VisualBasic.FileIO.RecycleOption]::SendToRecycleBin
                        )
                        if (-not (Test-Path -LiteralPath $unpackRoot.FullName)) {
                            Write-FlickFitHost "  _unpacked を削除しました（ごみ箱へ）。" -ForegroundColor DarkGray
                            $unpackDeleted = $true
                        }
                    } catch {}
                }
                if (-not $unpackDeleted -and (Test-Path -LiteralPath $unpackRoot.FullName)) {
                    Write-FlickFitHost "  [警告]: _unpacked の削除に失敗 - ファイル使用中" -ForegroundColor Yellow
                    Write-FlickFitHost "    ※ エクスプローラーを閉じてから手動で削除してください" -ForegroundColor DarkYellow
                }
            }
            
            # 元ファイル（解凍元のCBR/CBZ/ZIP等）の削除（STEP1 で固定した絶対パスのみ。当日再解決しない）
            if ($deleteSourceFiles -and $hasSourceFiles) {
                Add-Type -AssemblyName Microsoft.VisualBasic -ErrorAction SilentlyContinue
                $anySourceDeleteSkippedForSafety = $false
                $toDelete = [System.Collections.Generic.List[string]]::new()
                if (Get-Variable -Name SourceArchivePathsForStep7Delete -Scope Script -ErrorAction SilentlyContinue) {
                    foreach ($p0 in @($script:SourceArchivePathsForStep7Delete)) {
                        if ([string]::IsNullOrWhiteSpace($p0)) { continue }
                        $pNorm = $null
                        try { $pNorm = [System.IO.Path]::GetFullPath($p0).TrimEnd('\') } catch { $pNorm = $p0.TrimEnd('\') }
                        if (-not $pNorm) { continue }
                        if ($newArchivePaths.Contains($pNorm)) { continue }
                        [void]$toDelete.Add($pNorm)
                    }
                }
                if ($toDelete.Count -eq 0) {
                    if ($script:selectedArchives -and $script:selectedArchives.Count -gt 0) {
                        foreach ($arc in $script:selectedArchives) {
                            $path = if ($arc -is [System.IO.FileInfo]) { $arc.FullName } elseif ($arc -is [string]) { $arc } else { try { $arc.FullName } catch { $arc.ToString() } }
                            if (-not $path) { continue }
                            try { $path = [System.IO.Path]::GetFullPath($path).TrimEnd('\') } catch { }
                            if ($newArchivePaths.Contains($path)) { continue }
                            [void]$toDelete.Add($path)
                        }
                    }
                    if ($script:subfolderArchivesToProcess -and $script:subfolderArchivesToProcess.Count -gt 0) {
                        foreach ($arc in $script:subfolderArchivesToProcess) {
                            $path = if ($arc -is [System.IO.FileInfo]) { $arc.FullName } elseif ($arc -is [string]) { $arc } else { try { $arc.FullName } catch { $arc.ToString() } }
                            if (-not $path) { continue }
                            try { $path = [System.IO.Path]::GetFullPath($path).TrimEnd('\') } catch { }
                            if ($newArchivePaths.Contains($path)) { continue }
                            [void]$toDelete.Add($path)
                        }
                    }
                }
                foreach ($path in $toDelete) {
                    if ($true -eq $script:FlickFitDebugSourceArchiveDelete) {
                        $ex = Test-Path -LiteralPath $path
                        $isLf = if ($ex) { Test-Path -LiteralPath $path -PathType Leaf } else { $false }
                        $extD = if ($ex) { [System.IO.Path]::GetExtension($path) } else { '(n/a)' }
                        Write-FlickFitHost "  [DeleteDebug] sourceArchiveLiteral=$path exists=$ex PathTypeLeaf=$isLf ext=$extD" -ForegroundColor Magenta
                    }
                    if (-not (Test-Path -LiteralPath $path)) { continue }
                    if (-not (Test-FlickFitPathIsDeletableSourceArchive -LiteralPath $path)) {
                        if (Test-Path -LiteralPath $path) { $anySourceDeleteSkippedForSafety = $true }
                        continue
                    }
                    $name = [System.IO.Path]::GetFileName($path)
                    $deleted = $false
                    foreach ($attempt in 1..$deleteRetries) {
                        try {
                            [Microsoft.VisualBasic.FileIO.FileSystem]::DeleteFile($path, 'OnlyErrorDialogs', 'SendToRecycleBin')
                            Start-Sleep -Milliseconds 300
                            if (-not (Test-Path -LiteralPath $path)) {
                                Write-FlickFitHost "  [元ファイル削除]: $name" -ForegroundColor DarkGray
                                $deleted = $true
                                break
                            }
                        } catch {
                            if ($attempt -lt $deleteRetries) {
                                [System.GC]::Collect()
                                [System.GC]::WaitForPendingFinalizers()
                                Start-Sleep -Seconds $deleteDelaySec
                            }
                        }
                    }
                    if (-not $deleted -and (Test-Path -LiteralPath $path)) {
                        Write-FlickFitHost "  [失敗]: $name - 使用中の可能性" -ForegroundColor Yellow
                    }
                }
                if ($anySourceDeleteSkippedForSafety) {
                    Write-FlickFitHost "  [元ファイル削除] 安全のためスキップ: 同名競合の可能性があります" -ForegroundColor DarkGray
                }
            }
        }
    }

    # ウィンドウタイトルを完了に更新
    $Host.UI.RawUI.WindowTitle = "✓ 完了: $($script:TitleName)"
    
    Update-ProcessLogStep -StepNum 7 -Status "success"
    if ($script:ProcessLog) { $script:ProcessLog.status = 'success'; Save-ProcessLog $script:ProcessLog }
    $script:ProcessingCompletedSuccessfully = $true
    
    Write-Step "全ての処理が完了しました！" "Green"
    Write-FlickFitHost "  残るはRAR等のアーカイブ（または設定した圧縮形式）で出力されたファイルです。" -ForegroundColor Cyan
    if ($true -eq $script:ProcessingCompletedSuccessfully) {
        if ($runPhaseB -and $script:FlickFitRetrimCandidates -and $script:FlickFitRetrimCandidates.Count -gt 0) {
            if ($script:FlickFitTrimSplitEmbeddedCode) {
                if (-not $script:FlickFitWorkerDir) {
                    $srW = $null; try { $srW = Split-Path -Parent $script:MyInvocation.MyCommand.Path } catch {}
                    if ([string]::IsNullOrWhiteSpace($srW)) { $srW = (Get-Location).Path }
                    $script:FlickFitWorkerDir = Join-Path (Join-Path $srW "tools") "flickfit_worker"
                }
                $retrPy = Join-Path $script:FlickFitWorkerDir "trim_split_embedded.py"
                if (-not (Test-Path -LiteralPath $script:FlickFitWorkerDir)) { New-Item -ItemType Directory -Path $script:FlickFitWorkerDir -Force | Out-Null }
                try { Set-Content -LiteralPath $retrPy -Value $script:FlickFitTrimSplitEmbeddedCode -Encoding UTF8 } catch { $retrPy = $null }
                if ($retrPy -and (Test-Path -LiteralPath $retrPy)) {
                    $rbPost = if (Get-Variable -Name RightBinding -ErrorAction SilentlyContinue) { [bool]$RightBinding } else { $true }
                    $amPost = 0.0; if (Get-Variable -Name aspectMin -ErrorAction SilentlyContinue) { $amPost = [double]$aspectMin }
                    Invoke-FlickFitOptionalPostRetrimMenu -WorkTrimSplitPy $retrPy -RightBinding $rbPost -AspectMin $amPost
                } else { $null = Save-FlickFitRetrimCandidatesJson; Write-FlickFitHost "  （再トリミング: 作業用 Python の再展開に失敗。候補は _retrim_candidates.json）" -ForegroundColor DarkGray }
            } else { $null = Save-FlickFitRetrimCandidatesJson; Write-FlickFitHost "  （再トリミング: STEP5 未実行のため手動。候補は _retrim_candidates.json）" -ForegroundColor DarkGray }
        }
    }
    # 上の if (ResumeFromStep -le 6) { … } ブロックの閉じ
    }

} catch {
    if ($_.Exception.Message -eq '中断: exit') {
        try { Save-FlickFitExitInterruptMetadata } catch {}
    }
    if ($script:ProcessLog -and $script:CurrentProcessPhase -eq 'step5' -and $script:CurrentStep5Dir) {
        try {
            $script:ProcessLog | Add-Member -NotePropertyName 'step5InterruptedDir' -NotePropertyValue $script:CurrentStep5Dir -Force
            Save-ProcessLog $script:ProcessLog
        } catch {}
    }
    if ($script:ProcessLog) {
        $script:ProcessLog.lastError = $_.Exception.Message
        $script:ProcessLog.status = 'failed'
        Save-ProcessLog $script:ProcessLog
        Write-FlickFitHost "`n  [処理ログ] _process_log.json に失敗を記録しました（リトライ時に利用）" -ForegroundColor DarkGray
    }
    if ($_.Exception.Message -match '^中断:') { 
        Write-FlickFitHost "`n$($_.Exception.Message)" -ForegroundColor Yellow 
    } else { 
        Write-FlickFitHost "`n[エラー]: $($_.Exception.Message)" -ForegroundColor Red
        Write-FlickFitHost $_.ScriptStackTrace -ForegroundColor DarkGray
    }
} finally {
    Write-FlickFitHost "`n[クリーンアップ]: 一時ファイルを削除しています..." -ForegroundColor DarkGray
    $procOk = (Get-Variable -Name ProcessingCompletedSuccessfully -Scope Script -ErrorAction SilentlyContinue) -and $script:ProcessingCompletedSuccessfully
    
    # [BUG FIX #8] より安全なクリーンアップ
    $tempFiles = @(
        $tmpCropPy,
        $tmpSplitPy,
        $tmpView
    )
    
    foreach ($tmpFile in $tempFiles) {
        if ($tmpFile -and (Test-Path -LiteralPath $tmpFile)) {
            try {
                Remove-Item -LiteralPath $tmpFile -Force -ErrorAction SilentlyContinue
                Write-FlickFitHost "  ✓ $([System.IO.Path]::GetFileName($tmpFile)) を削除" -ForegroundColor DarkGray
            } catch {
                Write-FlickFitHost "  ✗ $([System.IO.Path]::GetFileName($tmpFile)) の削除に失敗" -ForegroundColor Yellow
            }
        }
    }
    if ($script:WorkTrimSplitPyPath -and (Test-Path -LiteralPath $script:WorkTrimSplitPyPath)) {
        try {
            Remove-Item -LiteralPath $script:WorkTrimSplitPyPath -Force -ErrorAction SilentlyContinue
            Write-FlickFitHost "  ✓ $([System.IO.Path]::GetFileName($script:WorkTrimSplitPyPath)) を削除" -ForegroundColor DarkGray
        } catch {
            Write-FlickFitHost "  ✗ 埋め込み trim/split 作業 .py の削除に失敗" -ForegroundColor Yellow
        }
    }
    # tools\flickfit_worker: 作業用 .py は上で削除。再開・中断・やり直しで残りやすい中間物を掃除し、空ならフォルダごと削除
    try {
        $ffWorker = $null
        if ((Get-Variable -Name FlickFitWorkerDir -Scope Script -ErrorAction SilentlyContinue) -and $script:FlickFitWorkerDir) {
            $ffWorker = $script:FlickFitWorkerDir
        } else {
            $srFf = if ($PSScriptRoot) { $PSScriptRoot } else { $null }
            if ([string]::IsNullOrWhiteSpace($srFf)) {
                try { $srFf = Split-Path -Parent $script:MyInvocation.MyCommand.Path } catch { $srFf = $null }
            }
            if ([string]::IsNullOrWhiteSpace($srFf)) { $srFf = (Get-Location).Path }
            $ffWorker = Join-Path (Join-Path $srFf "tools") "flickfit_worker"
        }
        if ($ffWorker -and (Test-Path -LiteralPath $ffWorker)) {
            Get-ChildItem -LiteralPath $ffWorker -Directory -ErrorAction SilentlyContinue |
                Where-Object { $_.Name -like '_backup_*' -or $_.Name -eq '__pycache__' } |
                ForEach-Object {
                    try {
                        Remove-Item -LiteralPath $_.FullName -Recurse -Force -ErrorAction SilentlyContinue
                        Write-FlickFitHost "  ✓ $($_.Name) を削除 (tools\flickfit_worker)" -ForegroundColor DarkGray
                    } catch { }
                }
            Get-ChildItem -LiteralPath $ffWorker -File -ErrorAction SilentlyContinue |
                Where-Object { $_.Extension -eq '.pyc' } |
                ForEach-Object { Remove-Item -LiteralPath $_.FullName -Force -ErrorAction SilentlyContinue }
            $remain = @(Get-ChildItem -LiteralPath $ffWorker -Force -ErrorAction SilentlyContinue)
            if ($remain.Count -eq 0) {
                try {
                    Remove-Item -LiteralPath $ffWorker -Force -ErrorAction SilentlyContinue
                    Write-FlickFitHost "  ✓ tools\flickfit_worker を削除（空のため）" -ForegroundColor DarkGray
                } catch { }
                $toolsDir = Split-Path -LiteralPath $ffWorker -Parent
                if ($toolsDir -and (Test-Path -LiteralPath $toolsDir)) {
                    $toolsRemain = @(Get-ChildItem -LiteralPath $toolsDir -Force -ErrorAction SilentlyContinue)
                    if ($toolsRemain.Count -eq 0) {
                        try {
                            Remove-Item -LiteralPath $toolsDir -Force -ErrorAction SilentlyContinue
                            Write-FlickFitHost "  ✓ tools を削除（空のため）" -ForegroundColor DarkGray
                        } catch { }
                    }
                }
            }
        }
    } catch { }
    
    # 野良一時ファイルのクリーンアップ
    try {
        Get-ChildItem -Path (Get-Location).Path -Filter "_vcrop_*.py" -ErrorAction SilentlyContinue | Remove-Item -Force -ErrorAction SilentlyContinue
        Get-ChildItem -Path (Get-Location).Path -Filter "_vsplit_*.py" -ErrorAction SilentlyContinue | Remove-Item -Force -ErrorAction SilentlyContinue
        try {
            $hadScratchDir = [bool]$script:FlickFitScratchTempDirCache
            Clear-FlickFitScratchTempFiles -SuccessRun:$procOk
            if ($hadScratchDir) {
                Write-FlickFitHost "  ✓ _temp 内の一時ファイルを削除" -ForegroundColor DarkGray
                if (-not $procOk) {
                    Write-FlickFitHost "    ff_batch_split_raw_*.log は保持" -ForegroundColor DarkGray
                }
            }
        } catch { }
        Get-ChildItem -Path $env:TEMP -Filter "preview_crop_*" -ErrorAction SilentlyContinue | Remove-Item -Force -ErrorAction SilentlyContinue
        Get-ChildItem -Path $env:TEMP -Filter "preview_title_*" -ErrorAction SilentlyContinue | Remove-Item -Force -ErrorAction SilentlyContinue
        # 比較プレビュー用一時ファイルのクリーンアップ
        Get-ChildItem -Path (Get-Location).Path -Filter "_preview_trim_*" -Recurse -ErrorAction SilentlyContinue | Remove-Item -Force -ErrorAction SilentlyContinue
        Get-ChildItem -Path (Get-Location).Path -Filter "_preview_split_*" -Recurse -ErrorAction SilentlyContinue | Remove-Item -Force -ErrorAction SilentlyContinue
    } catch {}
    
    # 全STEP成功時は処理ログを削除（いらないファイルとともに）
    $logPath = if (Get-Variable -Name ProcessLogPath -Scope Script -ErrorAction SilentlyContinue) { $script:ProcessLogPath } else { $null }
    if ($procOk) {
        # 処理ログの削除
        if ($logPath -and (Test-Path -LiteralPath $logPath)) {
            try {
                Remove-Item -LiteralPath $logPath -Force -ErrorAction SilentlyContinue
                Write-FlickFitHost "  ✓ _process_log.json を削除" -ForegroundColor DarkGray
            } catch {}
        }
        # 正常終了時のみデバッグログも削除（ノド調整GUIのログ）
        try {
            $debugLogDir = if ($PSScriptRoot) { $PSScriptRoot } else { Get-Location }
            $debugLogPath = Join-Path $debugLogDir 'debug-68e06a.log'
            if (Test-Path -LiteralPath $debugLogPath) {
                Remove-Item -LiteralPath $debugLogPath -Force -ErrorAction SilentlyContinue
                Write-FlickFitHost "  ✓ debug-68e06a.log を削除" -ForegroundColor DarkGray
            }
        } catch {}
        # 再開用スナップショット（clixml）を削除
        try {
            $snapDir = if ((Get-Variable -Name TitleFolder -Scope Script -ErrorAction SilentlyContinue) -and $script:TitleFolder) { $script:TitleFolder.FullName } else { (Get-Location).Path }
            foreach ($snapName in @('_flickfit_after_step1.clixml','_flickfit_after_step2.clixml','_flickfit_after_step3.clixml','_flickfit_step2_progress.clixml')) {
                $snapPath = Join-Path $snapDir $snapName
                if (Test-Path -LiteralPath $snapPath) {
                    Remove-Item -LiteralPath $snapPath -Force -ErrorAction SilentlyContinue
                    Write-FlickFitHost "  ✓ $snapName を削除" -ForegroundColor DarkGray
                }
            }
        } catch {}
        # バックアップフォルダ（_backup_*）を削除
        try {
            $backupBase = if ((Get-Variable -Name TitleFolder -Scope Script -ErrorAction SilentlyContinue) -and $script:TitleFolder) { $script:TitleFolder.FullName } else { (Get-Location).Path }
            $backupFolders = @(Get-ChildItem -LiteralPath $backupBase -Directory -ErrorAction SilentlyContinue | Where-Object { $_.Name -like '_backup_*' })
            foreach ($bf in $backupFolders) {
                Remove-Item -LiteralPath $bf.FullName -Recurse -Force -ErrorAction SilentlyContinue
                Write-FlickFitHost "  ✓ $($bf.Name) を削除" -ForegroundColor DarkGray
            }
        } catch {}
    }
    
    $null = Read-Host "`nDone. Enterで終了"
    exit
}
#endregion